gameforge.collect_quest_lv85._070_say = "Kan du skaffe mig 40 af disse grene? S\248rg for, at[ENTER]at de ikke er for tynd eller kn\230kkede. Jeg kan[ENTER]kun bruge st\230rke, sunde grene til min forskning.[ENTER]Og bring dem til mig personligt, s\229 jeg kan[ENTER]tjekke dem enkeltvis. "
