gameforge.collect_quest_lv94._050_say_title = "Seon-Pyeong: "
gameforge.collect_quest_lv94._060_say = "Hilsner! S\229 du fik mit brev? Godt, s\229 ved du[ENTER]allerede at jeg skal bruge hj\230lp til min[ENTER]v\229benforskning igen. Efter at jeg opdagede[ENTER]grotten, har flere og flere sandheder vist sig.[ENTER]Nu har jeg fundet ud af at monstrene i dette[ENTER]bjerg ogs\229 kradser andre typer juveler ud af[ENTER]stenene. "
gameforge.collect_quest_lv94._070_say = "Det drejer sig om de smukke Visdommens juveler -[ENTER]de er specielt klare og rene diamanter som[ENTER]\229benbart indeholder essensen af den dr\230bte[ENTER]gudinde Bahar-Taraji. Hold dine \248jne \229bne for[ENTER]nogle n\229r du er i grotten. Jeg skal bruge 20[ENTER]perfekte eksemplarer. Held og lykke, og lad mig[ENTER]ikke vente for l\230nge! "
gameforge.collect_quest_lv94._080_say_title = "Juveler til Seon-Pyeong "
gameforge.collect_quest_lv94._090_say = "V\229bensmeden og forskeren Seon-Pyeong beh\248ver 20[ENTER]Visdommens juveler til hans v\229benforskning. Bring[ENTER]dem til ham enkeltvis, s\229 han kan studere dem[ENTER]individuelt. Du kan f\229 dem fra Setaou J\230gerne og[ENTER]Setaou Lederne. "
gameforge.collect_quest_lv94._100_sayReward = "Du har leveret %s juveler hidtil. "
gameforge.collect_quest_lv94._110_say = "Du kan ikke bruge Forskerens eliksir endnu. "
gameforge.collect_quest_lv94._120_say = "Du har allerede brugt en eliksir! "
gameforge.collect_quest_lv94._130_say = "Du kan bruge eliksir s\229 snart du har fundet en[ENTER]juvel. "
gameforge.collect_quest_lv94._140_send_letter = "Fundet juvelen "
gameforge.collect_quest_lv94._150_npcChat = "Visdomens Juvel (94) "
gameforge.collect_quest_lv94._160_say = "Dig igen? Jeg er ked af det, men jeg er ikke[ENTER]f\230rdig med at studere den sidste endnu. Kom[ENTER]tilbage senere! "
gameforge.collect_quest_lv94._170_say = "Du har ikke fundet noget endnu? Jeg er ked af[ENTER]det, men hvorfor er du s\229 her? Kom nu, skynd dig![ENTER]Kom tilbage n\229r du kan bringe mig nogle juveler! "
gameforge.collect_quest_lv94._180_say = "Du har fundet en juvel? Fantastisk! Vent et[ENTER]sekund, Jeg er n\248dt til at v\230re sikker... "
gameforge.collect_quest_lv94._190_say = "\197h, en smuk \230delsten. Kan du f\248le varmen i dit[ENTER]hjerte? Den fred? Det er alt stenene g\248r... Mange[ENTER]tak! "
gameforge.collect_quest_lv94._200_say = "Men som du allerede ved, s\229 skal jeg bruge[ENTER]yderligere %s af dem i denne kvalitet. Giv mig en[ENTER]dag til at unders\248ge denne grundigt. S\229 kan du[ENTER]komme med den n\230ste. "
gameforge.collect_quest_lv94._210_say = "Held og lykke! "
gameforge.collect_quest_lv94._230_1_select = "Livspoint +1100 "
gameforge.collect_quest_lv94._230_2_select = "Forsvar +140 "
gameforge.collect_quest_lv94._230_3_select = "Angreb +60 "
gameforge.collect_quest_lv94._240_say = "Hmm... Det er en smuk diamant, det er der ingen[ENTER]tvivl om. Men den ser ikke ud til at have en[ENTER]gudelig aura. Jeg er bange for at den ikke[ENTER]hj\230lper mig videre. Skaf mig en anden! Og husk at[ENTER]jeg skal bruge noget tid til at unders\248ge denne[ENTER]her. "
gameforge.collect_quest_lv94._250_say = "Du klarede det virkelig! 20 Visdom Juveler ...[ENTER]Jeg er imponeret![ENTER]Men desv\230rre, det er bare ikke nok. Hvad jeg har[ENTER]brug for nu, for virkelig at forst\229 karakteren af[ENTER]kr\230fterne i disse diamanter er en sj\230lesten:[ENTER]Sj\230lesten af Grottens hersker - Dragen[ENTER]Beran-Setaou. "
gameforge.collect_quest_lv94._260_send_letter = "Seon-Pyeong's anmodning "
gameforge.collect_quest_lv94._270_say_title = "Dragen's sj\230lesten "
gameforge.collect_quest_lv94._280_say = "Du har form\229et at f\229 fat i dragen's sj\230lsten.[ENTER]Tag den til Seon-Pyeong ved indgangen til[ENTER]Forbandelsens grotten. "
gameforge.collect_quest_lv94._290_say_title = "Dragen's sj\230lesten "
gameforge.collect_quest_lv94._300_say = "Du tog 20 Visdom Juveler til Seon-Pyeong i[ENTER]Seungryong Dalen. Nu er han bare brug for[ENTER]Dragen's sj\230lesten! "
gameforge.collect_quest_lv94._310_say = "Du kan f\229 den fra Beran-Setaou. "
gameforge.collect_quest_lv94._320_send_letter = "Du har modtaget Dragen's Sj\230lesten. "
gameforge.collect_quest_lv94._330_npcChat = "Jeg har f\229et Dragen's sj\230lesten! "
gameforge.collect_quest_lv94._340_say = "Det er ... utroligt. Dragen sj\230lsten![ENTER]Jeg b\248jer mig i overv\230relse af deres store evner![ENTER]Nu st\229r intet i vejen for min forskning - og jeg[ENTER]vil give dig en gener\248s bel\248nning. V\230lg en! "
gameforge.collect_quest_lv94._350_say = "Du har f\229et sj\230lenstenen? Og hvorfor kan jeg ikke[ENTER]se den s\229?! Fors\248g ikke bevidst at vildlede mig[ENTER]... Jeg ved, at jeg gav dig en vanskelig opgave,[ENTER]men jeg er helt sikker p\229, at du kan g\248re det! "
gameforge.couple_ring = {}
gameforge.couple_ring._100_sendLetter = "Vind over Jin-Hees. "
gameforge.couple_ring._10_npcChat = "Ring-k\248bmandens h\230vn "
gameforge.couple_ring._110_sayReward = "Den gamle Dame har bedt om Deres st\248tte: hendes[ENTER]veninde var Guldsmed blev myrdet af Jin-Hee, Hvid[ENTER]Eid-specialister. H\230vne den d\248de Guldsmed ved at[ENTER]dr\230be 30 Jin-Hee. "
gameforge.couple_ring._120_sayReward = "Antal tilbage blivende Jin-Hees "
gameforge.couple_ring._130_say = "\197h, jeg kan se at du har k\230mpet mod Jin-Hee? Og[ENTER]du kunne naturligvis ikke besejre dem alle. Jeg[ENTER]kender deres styrke og deres f\230rdigheder - det er[ENTER]ikke en let opgave. "
gameforge.couple_ring._140_say = "Guldsmedens familie gik i dyb sorg efter hans[ENTER]d\248d. Det ville v\230re meget \230del af dig, hvis du[ENTER]kunne h\230vne hans d\248d for at hj\230lpe dem med at[ENTER]komme over deres tab. "
gameforge.couple_ring._150_say = "S\248rgeligt, at du ikke vil tage h\230vn for[ENTER]ring-k\248bmandens d\248d. Hmm, naturligvis kan du lide[ENTER]dit liv. Som du \248nsker. Et hvert liv er[ENTER]v\230rdifuld. "
gameforge.couple_ring._160_say = "Du s\229, at den gamle dame holdt noget i h\229nden da[ENTER]hun drejede sig. Det var en funklende genstand.[ENTER](S\229 ud som en v\230rdifuld sten) "
gameforge.couple_ring._170_select = "Jeg forts\230tter med at pr\248ve det "
gameforge.couple_ring._180_say = "Jeg er ikke interesseret i v\230rdifulde sten. Jeg[ENTER]\248nsker kun at der tages h\230vn for d\248den af[ENTER]ring-k\248bsmanden. Godt at du har overvejet din[ENTER]sidste beslutning. "
gameforge.couple_ring._190_say = "Jeg synes det er s\248rgeligt for ring-k\248bmandens[ENTER]familie. Jeg synes det er synd at du ikke tager[ENTER]imod udfordringen. "
gameforge.couple_ring._200_sendLetter = "G\229 tilbage til den gamle dame. "
gameforge.couple_ring._20_sayTitle = "Gammel dame "
gameforge.couple_ring._210_say = "G\229 tilbage til den gamle dame og fort\230l, at du[ENTER]har taget h\230vn for ring-k\248bmandens d\248d, idet du[ENTER]drabte Jin-Hees. "
gameforge.couple_ring._220_npcChat = "Du har vundet over 30 Jin-Hee's! "
gameforge.couple_ring._230_say = "Du har dr\230bt alle Jin-Hees. Godt arbejde![ENTER]Ring-k\248bmanden vil v\230re tilfreds med dig. Her er[ENTER]den ring, som han har givet mig. Du f\229r den. Det[ENTER]er bel\248nningen for at du har taget h\230vn. Jeg er[ENTER]sikker p\229 at det ogs\229 var hans \248nske. "
gameforge.couple_ring._240_sayReward = "Du har f\229et en forlovelsesring. "
gameforge.couple_ring._250_sayItem = "Vielsesring "
gameforge.couple_ring._255_sayItem = "Denne ring symboliserer et forest\229ende bryllup. "
gameforge.couple_ring._30_say = "Du er nu en af krigerne i landsbyen.[ENTER]Hvis bare jeg vidste hvordan vi kunne bruge dine[ENTER]ny-fundne kr\230fter. Har du nogensinde h\248rt om[ENTER]Jin-Hee? De er en gruppe af meget farlige[ENTER]elitekrigere. En af dem dr\230bte vores landsbys[ENTER]ring-s\230lger. S\230lgeren var ikke bare en god ven,[ENTER]men ogs\229 en velset og rimelig mand der solgte[ENTER]smykker til unge par der planlagde at blive gift.[ENTER]Er du klar til at h\230vne hans d\248d? For at g\248re[ENTER]dette skal du dr\230be 30 Jin-Hee... "
gameforge.couple_ring._40_select = "Jeg vil h\230vne Guldsmeden. "
gameforge.couple_ring._50_select = "Nej, Jin-Hee's er for st\230rke for mig. "
gameforge.couple_ring._60_say = "Det er en meget klog og h\230derlig beslutning![ENTER]men husk - du er n\248dt til at dr\230be 30 Jin-Hee.[ENTER]V\230r dog forsigtig, de er snu og meget dygtige til[ENTER]at skjule sig selv! "
gameforge.couple_ring._70_say = "Ja, det er en beklagelig beslutning, men det er[ENTER]op til dig. Efter alt, kan selvtillid v\230re[ENTER]d\248delige. Pas p\229! "
gameforge.couple_ring._75_say = "Antal tilbage blivende Jin-Hees "
gameforge.couple_ring._80_sayTitle = "Du har dr\230bt alle Jin-Hees. "
gameforge.couple_ring._90_say = "Nu da Guldsmedens d\248d er h\230vnet, er din mission[ENTER]fuldf\248rt. "
gameforge.cube = {}
gameforge.cube._060_npcChat = "Producer alle eliksirer "
gameforge.cube._10_say = "hejsa, hvordan har du det?[ENTER]Er du interesseret i fremstilling af diverse[ENTER]eliksirer der kan \248ge din styrke eller har[ENTER]helende virkning? Jeg er l\230ge og har besk\230ftiget[ENTER]mig med eliksirfremstilling.[ENTER]Jeg har fundet ud af adskillige opskrifter. Vil[ENTER]du pr\248ve nogen? "
gameforge.cube._20_say = "Raffinering af ting er et vigtigt h\229ndv\230rk. Er du[ENTER]interesseret i s\229dan nogen f\230rdigheder? Jeg kan[ENTER]vise dig nogle af mine urte opskrifter. De er[ENTER]meget brugbare til at producere st\230rkere[ENTER]variationer af kendte eliksirer. Eller kan jeg[ENTER]l\230re dig hvordan man forvandler et hverdags b\230lte[ENTER]om til et m\230gtigt v\230rkt\248j. "
gameforge.cube._30_npcChat = "Hemmelig opskrift "
gameforge.cube._40_sayTitle = "Huahn-So "
gameforge.cube._50_say = "Jeg har fundet en gammel familie-opskrift.[ENTER]Med denne bliver du n\230sten us\229rlig![ENTER]Hahaha Jeg er nok den eneste her i landet, der[ENTER]kender denne opskrift. Med denne eliksir kan der[ENTER]i grunden ikke ske noget for personen.[ENTER]\216nsker du at afpr\248ve? "
