gameforge.dragon_soul = {}
gameforge.dragon_soul._010_sayTitle = "Delt drage sten?! "
gameforge.dragon_soul._020_say = "I din h\229nd ligger et fragment af en sten. Det[ENTER]skinner, som om det er fuld af hemmelighedder, og[ENTER]du kan m\230rke dets magt, mens det flyder igennem[ENTER]dig.[ENTER]Hvad er det for en slags sten? Tag den med til[ENTER]alkymisten. Han vil v\230re i stand til at hj\230lpe[ENTER]dig videre. "
gameforge.dragon_soul._030_npcChat = "Delt drage sten?! "
gameforge.dragon_soul._040_say = "Det er et fragment af en drage sten - en ekstrem[ENTER]sparsom og v\230rdifuld krystal med en k\230mpe magt.[ENTER]Det bliver dat at en s\229dan sten er sj\230len af en[ENTER]drage. Helt utrolig smuk![ENTER]Kan du m\230rke dens magt, mens den flyder igennem[ENTER]dig s\229 snart du samlede den op og bar den?[ENTER]Bring mig ti af disse delte drage sten mere. Jeg[ENTER]kan lave dem til en komplet sten. "
gameforge.dragon_soul._050_npcChat = "Drage stens forvandling "
gameforge.dragon_soul._060_say = "V\230r ikke s\229 ut\229lmodig. Jeg kan kun forvandle ti[ENTER]dele til en drage sten. Bliv ved med at lede! "
gameforge.dragon_soul._070_say = "Ah, rigtig godt! Du har fundet ti delte drage[ENTER]sten. Vent venligst et \248jeblik.[ENTER]...[ENTER]Jeg gjorde det! Men dog, vi har v\230ret i stand til[ENTER]at lave en Cor Draconis gennem denne proces - et[ENTER]krystallinsk drage hjerte og beskyttelse af drage[ENTER]stenen.[ENTER]Br\230k den op og find ud af, had den indeholder.[ENTER]Den vil blive flyttet direkte til drage stens[ENTER]alkymi inventar.[ENTER]Vidste du, at du ogs\229 kan for\230dle drage stenene[ENTER]yderligere? "
gameforge.dragon_soul._080_say = "Vi du gerne have en anden Cor Draconis? Bah, Jeg[ENTER]er forbi mit bedste allerede og produktionen af[ENTER]en s\229dan kompleks genstand slider p\229 min styrke.[ENTER]Men Jeg vil pr\248ve for dig. Men selv om n\229r jeg er[ENTER]bedst, kan jeg ikke klare mere end ti om dagen! "
gameforge.dragon_soul._090_say = "Det er nok for i dag. Jeg kan simpelthen ikke[ENTER]klare mere en ti om dagen. Jeg har n\230sten ikke[ENTER]flere kr\230fter, og jeg har brug for at hvile mig.[ENTER]Kom igen i morgen. "
gameforge.dragon_soul._100_npcChat = "\197ben butik "
gameforge.dragon_soul._1010_sendLetter = "Ankomsten af delt dage sten "
gameforge.dragon_soul._1020_say = "Den mest kendte mineral alkymist i hele riget[ENTER]leder efter dig. Drag til ham s\229 snart s\229 muligt! "
gameforge.dragon_soul._1030_npcChat = "Delt drage sten?! "
gameforge.dragon_soul._1040_say = "Ah, der er du! Jeg har opdaget noget ganske[ENTER]bem\230rkelsesv\230rdigt: fragmentet af en drage sten![ENTER]En drage sten er en yderst sj\230lden og v\230rdifuld[ENTER]krystal med stor kraft. Det siges, at de engang[ENTER]var sj\230len af en drage. Utrolig smuk! Jeg vil[ENTER]give dig Drage\248jets Styrke, s\229 du ogs\229 kan[ENTER]registrere sk\229rene.[ENTER]Bring mig i alt ti delte drage sten.[ENTER]Jeg vil s\229 v\230re i stand til at forvandle dem til[ENTER]en komplet sten. "
gameforge.dragon_soul._1050_sendLetter = "Saml delte drage sten "
gameforge.dragon_soul._1060_say = "Bring ti delte drage sten til alkymisten. "
gameforge.dragon_soul._1070_say = "Ah, meget god! Du har fundet ti delte drage sten.[ENTER]Vent et \248jeblik.[ENTER]...[ENTER]Fantastisk! Forvandlingen har resulteret i en Cor[ENTER]Draconis - et krystallisk drage hjerte, at[ENTER]beskyttende omgiver drage stenen.[ENTER]N\229r du \229bner det, vil drage stenen inden i[ENTER]derefter g\229 lige ind i drage stens Alkymi[ENTER]opg\248relse.[ENTER]For at finde delte drage sten, skal du bruge[ENTER]Drage\248jets Styrke. Jeg kan l\229ne det til dig -[ENTER]bare komme og se mig hver dag. S\229 vil du ogs\229[ENTER]v\230re i stand til at forvandle drage sten! Jeg har[ENTER]allerede gjort nok for dig i dag, de resterende[ENTER]%d kan du klare p\229 egen h\229nd. "
gameforge.dragon_soul._1080_say = "Hey, spild ikke mere tid! Afsted med dig og led[ENTER]efter flere delte drage sten! "
gameforge.dragon_soul._1090_sendLetter = "Drage\248jets Styrke "
gameforge.dragon_soul._1100_say = "Resterende varighed af Drage\248jets Styrke: %d "
gameforge.dragon_soul._110_say = "V\230lg. "
gameforge.dragon_soul._1110_notice = "Es gibt keine Drachensteinsplitter mehr "
gameforge.dragon_soul._1120_npcChat = "Giv mig Drage\248jets Styrke "
gameforge.dragon_soul._1130_say = "Hallo! Du har allerede modtaget Drage\248jets Styrke[ENTER]i dag. Denne process sv\230kker mig s\229 meget, at jeg[ENTER]kun kan hj\230lpe dig en gang om dagen. Kom igen i[ENTER]morgen! "
gameforge.dragon_soul._1140_say = "Hallo! Jeg vil v\230dde med du er her for styrke af[ENTER]et drage \248je. Korrekt? Godt s\229, v\230rsgo. Held og[ENTER]lykke med din jagt! Jeg h\229ber du vil finde nok[ENTER]delte drage sten til ti drage sten! "
gameforge.dragon_soul._1150_sendLetter = "Drage\248jets Styrke mangler "
gameforge.dragon_soul._1160_say = "Drage\248jets Styrke har forladt dig. "
gameforge.dragon_soul._1170_say = "G\229 tilbage til alkymisten i morgen for endnu en[ENTER]gang at f\229 Drage\248jets Styrke! "
gameforge.dragon_soul._1180_say = "G\229 tilbage til alkymisten og f\229 styrke af et[ENTER]drage \248je! "
