gameforge.dragon_soul_daily_gift._010_npcChat = "Cor Draconis som en gave "
gameforge.dragon_soul_daily_gift._020_say = "Kontrollen af drage \248jet er ikke s\229 nemt, som det[ENTER]ser ud til. Kun erfarne krigere er i stand til[ENTER]det. Tr\230n lidt l\230ngere end i krigs kunsten og s\229[ENTER]returner, n\229r du er noget mindst level 50. "
gameforge.dragon_soul_daily_gift._030_say = "For at v\230re klar til at bruge Cor Draconis, skal[ENTER]du bruge styrken fra en drages \248je. Kom igen, n\229r[ENTER]du tror, du er i stand til det. "
gameforge.dragon_soul_daily_gift._040_say = "Ah, jeg m\230rker styrken fra en drage \248je inden i[ENTER]dig. Som et tegn p\229 min dybe respekt, vil jeg[ENTER]gerne pr\230sentere dig for denne Cor Draconis.[ENTER]En sten om dagen - Jeg er bange for, jeg ikke kan[ENTER]undv\230re flere. "
gameforge.dragon_soul_daily_gift._050_say = "V\230rsgo, din Cor Draconis. Selv tak. "
gameforge.dragon_soul_daily_gift._060_say = "Jeg er meget ked af det. Jeg kan ikke undv\230re[ENTER]mere end en om dagen. Kom igen i morgen.[ENTER]M\229ske vil jeg have en ny Cor Draconis til dig. "
