gameforge.energy_system = {}
gameforge.energy_system._001_npcChat = "En ny teknologi! "
gameforge.energy_system._010_say = "Jeg har gjort det![ENTER]Jeg har endelig klaret at udvikle en helt ny[ENTER]teknologi.[ENTER]Jeg har klaret at processe genstande og udtr\230kke[ENTER]ren energi fra dem. Det er abselout Brilliant! "
gameforge.energy_system._020_say = "Hvis du \248delegger en genstand ved brug af min nye[ENTER]teknologi, vil du modtage en Energi Fragment.[ENTER]Hvis du fusionere 30 af disse fragmenter, vil du[ENTER]modtage en magtfuld Energi Krystal! Ren,[ENTER]ufiltreret energi, bundet med en \230delsten.[ENTER]Effekten vil flyde ind i alt dit udsty.[ENTER]Er du interesseret i det? "
gameforge.energy_system._030_say = "Bring udstyrs genstande s\229 som v\229ben, juveler og[ENTER]t\248j som du finder under jagt til mig. Jeg vil[ENTER]prosesse dem til energi fragmenter. Vores[ENTER]kongeriges fremtid og h\229b afh\230nger af denne[ENTER]teknologi. Vi vil blive uovervindelige! "
gameforge.energy_system._035_npcChat = "Udtr\230k Energi Fragmenter "
gameforge.energy_system._040_say = "Virkede det? Modtog du Energi Fragmenter? Bring[ENTER]mig flere genstande og jeg vil knuse dem ved[ENTER]hj\230lp af alkemi. Min teknologi er ikke helt[ENTER]blevet perfektioneret endnu. Derfor kan jeg[ENTER]aldrig garantere hvor mange fragmenter du vil[ENTER]modtage. "
gameforge.energy_system._050_say = "Der er en betingelse: dit eget level s\229vel som[ENTER]levelet af genstanden skal minimum v\230re level 35.[ENTER]Hm, lad mig se p\229 det... "
gameforge.energy_system._060_say = "Du er ikke st\230rk nok endnu! Kom igen n\229r du har[ENTER]n\229et minimum level 35. "
gameforge.energy_system._070_say = "Ah fremragende! Du er st\230rk og erfaren.[ENTER]Giv mig genstanden som du jeg skal procese. "
gameforge.energy_system._080_say = "Du er ikke st\230rk nok endnu til at kontrollere[ENTER]energien i disse Energi Fragmenter. Kom igen n\229r[ENTER]du er n\229et minimum level 35. "
gameforge.energy_system._090_say = "Denne genstand er ikke egnet til min teknologi.[ENTER]Bring mig noget andet. "
gameforge.energy_system._100_say = "Denne genstand har ikke nok energi. Bring mig et[ENTER]som er minimum level 35 - det er den eneste m\229de[ENTER]jeg er istand til at udtr\230kke energi med min[ENTER]teknologi. "
gameforge.energy_system._110_say = "Skal jeg tilintetg\248re denne genstand? "
gameforge.energy_system._120_select = "Ja "
gameforge.energy_system._130_select = "Nej, ikke enenu! "
gameforge.energy_system._140_say = "Jeg har fejlet - desv\230rre jeg kunne ikke udtr\230kke[ENTER]nogle Energi Fragmenter. M\229ske vil jeg have bedre[ENTER]held n\230ste gang. "
gameforge.energy_system._150_say = "Vidunderligt! Det lykkedes mig at finde %d Energi[ENTER]Fragmenter.[ENTER]V\230rsgo. "
gameforge.energy_system._160_npcChat = "fremstil Energi Krystal "
gameforge.energy_system._170_say = "Har du brugt alle dine energi reserver allerede?[ENTER]Du b\248r ikke arbejde s\229 h\229rdt og bringe dit liv[ENTER]til kanten p\229 s\229dan en ligegyldig m\229de. Jeg vil[ENTER]beh\248ve %d Energi Fragmenter for at producere en[ENTER]Energi Krystal. "
gameforge.energy_system._180_say = "Du har ikke nok Energi Fragmenter.[ENTER]Jeg kan ikke producere en Energi Krystal med det.[ENTER]Kom igen n\229r du har samlet mindst %d fragmenter. "
gameforge.energy_system._190_say = "Meget godt, du har de %d n\248dvendige Energi[ENTER]Fragmenter. Jeg kan producere en Energi Krystal[ENTER]med det. Vent venligst et \248jeblik. Jeg vil pr\248ve[ENTER]men kan ikke garantere at det virker. "
gameforge.energy_system._200_say = "Alt er klart til at smelte Fragmenterne ind i en[ENTER]Energi Krystal. Dog, jeg er n\248d til at leve af[ENTER]noget ogs\229 og v\230rkt\248j falder ikke ned fra himlen.[ENTER]Jeg kr\230ver et lille omkost d\230kning p\229 %d Yang. Er[ENTER]du villig til at betale? "
gameforge.energy_system._210_select = "Naturligvis. "
gameforge.energy_system._220_select = "Nej, ikke lige nu. "
gameforge.energy_system._230_say = "Okay, jeg respektere din beslutning.[ENTER]Kom igen n\229r du har \230ndret din mening og[ENTER]alligevel har brug for Energi Krystallen. "
gameforge.energy_system._240_say = "Undskyld, du er n\248d til at betale f\248rst. Jeg er[ENTER]ikke en velg\248renhedsorganisation.[ENTER]Det er bare en forretning - giv mig pengene og[ENTER]jeg kan udf\248re mit arbejde. "
gameforge.energy_system._250_say = "Her, din Energi Krystal. Men den er kun f\248rste[ENTER]fors\248g der altid er succesfuldt. Alkemi er en[ENTER]uforudsigelig videnskab - en lille fejl leder til[ENTER]fiasko! Der er altid en lille chance for at et[ENTER]eksperiment fejler. "
gameforge.energy_system._260_say = "Desv\230rre, det fors\248g fejlede. Jeg kunne ikke[ENTER]producere en Energi krystal. Min teknologi er[ENTER]genial - men processen er fuld af risicis.[ENTER]Tingene fungere ikke altid if\248lge planen. Jeg er[ENTER]sikker p\229 at n\230ste gang vil blive succesfuld. "
gameforge.energy_system._270_say = "Jeg viste det! Min teknologi er genial![ENTER]Her er din Energi Krystal. Det er helt sikkert et[ENTER]fint eksemplar! Kan du m\230rke energien? "
