gameforge.find_brother_article._110_say = "Selvf\248lgelig vil jeg hj\230lpe dig. Missionen er[ENTER]ikke sv\230r at gennemf\248re og jeg kan forst\229 at du[ENTER]vil have din souvenir tilbage. Ses snart igen! "
