gameforge.find_brother_article._170_select = "Opgive "
gameforge.find_brother_article._180_sayReward = "Det er n\230sten umuligt at n\230gte denne piges \248nske.[ENTER]En kamp mod 100 af Sortvind banden virker meget[ENTER]nemmere til sammenligning. "
gameforge.find_brother_article._190_say = "Jeg beklager. Jeg f\248ler med dig, men Sort-Vind[ENTER]banden er for st\230rke for mig. En anden med mere[ENTER]erfaring vil v\230re bedre til dette job. "
