gameforge.find_brother_article._300_sayReward = "Du har f\229et et \248delagt sv\230rd.[ENTER]G\229 til smeden "
gameforge.find_brother_article._30_say = "Oh beklager, jeg h\248rte dig ikke komme. Jeg t\230nkte[ENTER]p\229 min stakkels bror. Men hvem er du? "
gameforge.find_brother_article._310_sendLetter = "G\229 til Smeden "
