gameforge.find_brother_article._340_npcChat = "Kan du reparere sv\230rdet? "
gameforge.find_brother_article._350_say = "Det er et vidunderligt sv\230rd! Det tilh\248rte Mirine[ENTER]gjorde det ikke? Jeg h\248rte at du hjalp hende.[ENTER]Flot arbejde, du ser ud til at v\230re en retf\230rdig[ENTER]og \230rlig person, s\229 jeg vil ikke kr\230ve betaling[ENTER]for at reparere v\229bnet. Vent et \248jeblik... "
