gameforge.find_brother_article._50_say = "Oh, jeg bem\230rkede ikke at nogen var i n\230rheden...[ENTER]Mit navn er Mirine. M\229ske kunne du hj\230lpe mig?[ENTER]Min \230ldre bror er d\248d. Han var p\229 p\229 vej for at[ENTER]skaffe medicin men s\229...[ENTER]Den eneste ting jeg har tilbage af ham er hans[ENTER]grav og en genstand: Hans sorte uniform. "
gameforge.find_brother_article._60_sayTitle = "Mirine: "
gameforge.find_brother_article._70_say = "P\229 min vej hjem viste Sort-Vind banden sig - en[ENTER]af de mest berygtede grupper af lovl\248se[ENTER]snigmordere. Jeg blev n\248dt til at flygte fra dem[ENTER]og mistede min brors minde-genstand. Jeg er for[ENTER]bange for at g\229 tilbage dertil og lede efter det.[ENTER]Kan du g\248re det for mig? "
gameforge.find_brother_article._80_sayReward = "Ha\180 medlidenhed med den s\248de pige og hj\230lp hende[ENTER]med at finde den gamle sorte uniform fra hendes[ENTER]bror! "
