gameforge.fisher._30_sayTitle = "Fisker: "
gameforge.fisher._40_say = "S\229 du er interesseret i hemmeligheden omkring[ENTER]forbedring af fiskest\230nger? For at v\230re \230rlig er[ENTER]det faktisk ikke nogen stor hemmelighed. Jo mere[ENTER]tid du bruger p\229 at fiske, jo flere point vil din[ENTER]fiskestang samle. N\229r din fiskestang har n\229et[ENTER]dets maksimale level, s\229 bring den til mig.[ENTER]S\229 vil jeg pr\248ve at opgradere den for dig.[ENTER]Ok. V\230lg nu den fiskestang du \248nsker at f\229[ENTER]opgraderet, og giv den til mig. "
gameforge.fisher._50_say = "Hvad skal jeg med det? Jeg kan kun forbedre[ENTER]fiskest\230nger! "
gameforge.fisher._60_say = "Beklager, men denne fiskestang kan ikke forbedres[ENTER]yderligere. "
gameforge.fisher._70_say = "Fiskestangen har ikke samlet point nok endnu. Jeg[ENTER]kan ikke forbedre den endnu. Kom tilbage n\229r din[ENTER]fiskestang har n\229et dens maksimum point. "
gameforge.fisher._80_say = "\216nsker du at forbedre din fiskestang?[ENTER]Lad mig se... "
gameforge.fisher._90_say = "Din fiskestang-level er %s. "
