gameforge.fortune_telling._100_sayTitle = "Gammel dame "
gameforge.fortune_telling._10_npcChat = "Jeg har h\248rt De er en sp\229kone. "
gameforge.fortune_telling._110_say = "Du er for ung til at sukke s\229dan! \216nsker du at se[ENTER]ind i din fremtid? Du b\248r vide at der er nogle[ENTER]kr\230fter der ude som kan give dig svar du mangler[ENTER]for at genfinde noget af dit h\229b. "
gameforge.fortune_telling._120_select = "Lad damen forudsige "
gameforge.fortune_telling._130_select = "Nej tak "
gameforge.fortune_telling._140_say = "Ja. Det vigtigste i livet er at lytte til sin[ENTER]egen vilje. Lev i fred! "
gameforge.fortune_telling._150_select = "Ja, jeg \248nsker en. "
gameforge.fortune_telling._160_select = "Nej tak. "
gameforge.fortune_telling._170_say = "Jeg er venlig, men jeg kan ikke give jer nogen[ENTER]talisman. Hvis i \248nsker at modst\229 uheld, burde i[ENTER]betale en fornunftig pris for denne talisman.[ENTER]Den koster %s Yang. "
gameforge.fortune_telling._180_say = "Du smutter? M\229ske har du ret. Uheld er en del af[ENTER]livet. Pas p\229 dig selv og lev i fred. Kom igen[ENTER]hvis du skulle skifte mening. "
gameforge.fortune_telling._20_say = "Blikket i dine \248jne fort\230ller mig at du er meget[ENTER]ung. Hvorfor \248nsker du at kende din sk\230bne s\229[ENTER]tidlig i livet? Er der en speciel grund til det?[ENTER]Sk\230bnen har stadig meget i vente for dig. Kom[ENTER]tilbage igen senere. "
gameforge.fortune_telling._30_say = "\216nsker du at leve som sp\229konen fort\230ller? Du[ENTER]burde ikke v\230gte forudsigelserne for h\248jt. Det[ENTER]vigtige i et liv er din holdning og din mine.[ENTER]Hvis de begge er positive, kan intet g\229 galt.[ENTER]Hvis du stadig \248nsker at f\229 din sk\230bne af vide,[ENTER]s\229 kom igen i morgen.  "
gameforge.fortune_telling._40_sayTitle = "Gammel dame "
gameforge.fortune_telling._50_say = "Som jeg allerede har fortalt dig er din[ENTER]forudsigelse for i dag som f\248lger: "
gameforge.fortune_telling._60_say = "Du vil have en del uheld, og du har ikke k\248bt[ENTER]talismanen mod det onde.. Er du interesseret i at[ENTER]k\248be min rigdom-talisman? "
gameforge.fortune_telling._70_select = "Ja, jeg k\248ber den. "
gameforge.fortune_telling._80_select = "Nej, den har jeg ikke brug for. "
gameforge.fortune_telling._90_say = "Jeg er venlig, men jeg kan ikke give jer nogen[ENTER]talisman. Hvis i \248nsker at modst\229 uheld, burde i[ENTER]betale en fornunftig pris for denne[ENTER]talisman.  "
