gameforge.ghost_story = {}
gameforge.ghost_story._010_sayTitle = "Sp\248gelse af en Sura: "
gameforge.ghost_story._020_npcChat = "Er du et sp\248gelse? "
gameforge.ghost_story._030_say = "Nej, jeg er dronningen af Saba ... Selvf\248lgelig[ENTER]er jeg et sp\248gelse! Har nogen tabt dig p\229[ENTER]hovedet, som baby? "
gameforge.ghost_story._040_npcChat = "Hj\230lp, et sp\248gelse! "
gameforge.ghost_story._050_say = "Og der kan man bare se, en frygtl\248s kriger! Boo! "
gameforge.ghost_story._060_npcChat = "Hvem er du? "
gameforge.ghost_story._070_say = "Mit navn er Akuma. Jeg var engang en stor kriger,[ENTER]nogle sige, at jeg var den bedste af min tid.[ENTER]Jeg troede det faktisk selv! Men se p\229 mig nu.[ENTER]Kig p\229 hvad der var tilbage af mig, efter jeg[ENTER]fandt grotten... og omkom. "
gameforge.ghost_story._080_npcChat = "Kender du historien om dette sted? "
gameforge.ghost_story._090_say = "\197h jeg ved, hvad der skete dengang. Jeg[ENTER]researchede i lang tid, fors\248gte at finde ud af[ENTER]\229rsagen bag dette og fors\248ger at finde den[ENTER]grotten. Og siden min d\248d jeg har haft en masse[ENTER]tid til at t\230nke over det. Bare sp\248rg mig, hvad[ENTER]\248nsker du at vide! "
gameforge.ghost_story._100_npcChat = "Hvilken slags portal er det? "
gameforge.ghost_story._110_say = "Denne portal f\248rer ind i den m\248rke drages kammer,[ENTER]til den faldne Gud Beran-Setaou. Den kan[ENTER]aktiveres med en magisk n\248gle, som kun[ENTER]Beran-Setaous tropper kan f\229... "
gameforge.ghost_story._120_npcChat = "De tre guder "
gameforge.ghost_story._130_say = "Engang, dannede tre gudelige s\248skende grundlaget[ENTER]for eksistens.[ENTER]Bahar-Taraji, gudinden for skabelse var yngste af[ENTER]de tre. Hendes job var at skabe nye v\230sener -[ENTER]hvor hun gik, blomster blomstrede og liv[ENTER]trivedes. "
gameforge.ghost_story._140_say = "Den \230ldste bror blev kaldt Beran-Setaou. Han var[ENTER]ansvarlig for afslutningen af liv og for[ENTER]opl\248sning. N\229r en livscyklus var p\229 sit sidste,[ENTER]skilte han krop og sj\230l fra hinanden og f\248rte[ENTER]sj\230len ind i efterlivet. Og s\229ledes en konstant[ENTER]cirkel for at v\230re, og dem som g\229r v\230k -[ENTER]grundlaget for alt liv - var sikret. "
gameforge.ghost_story._150_say = "Den mellemste bror var Baljit-Elvedin. Som Gud af[ENTER]bevarelse, han m\230glede mellem hans to s\248skende og[ENTER]aktiverede den evige cirkel af liv for skabninger[ENTER]af jorden. Han var for eksempel ansvarlig for de[ENTER]kommende og g\229ende \229rstider. "
gameforge.ghost_story._160_npcChat = "Striden "
gameforge.ghost_story._170_say = "I d\229rligere tider, bad folk de tre guder om[ENTER]hj\230lp. Men desv\230rre frygtede de og tilsidesatte[ENTER]Beran-Setaou, som de i deres kortsynethed ikke[ENTER]forstod, at ligesom lys og m\248rke findes,[ENTER]eksistere han som et modstykke til skabelsen. "
gameforge.ghost_story._180_say = "I lang tid ignorerede guden det, men i l\248bet af[ENTER]\229rene voksede misundelsen i ham, som langsomt[ENTER]ventes til had og ondsindethed. Som det f\248rste[ENTER]han kanaliserede sin vrede mod menneskerne, ved[ENTER]at give dem krig og sygdom. Som dog kun[ENTER]resulterede i deres yderligere afvisning af ham,[ENTER]og de stigende b\248nner til Bahar-Taraji, gudinde[ENTER]for nyoprettede liv. Og s\229ledes blev det den onde[ENTER]cirkel, der i sidste ende f\248rte til ruin. "
gameforge.ghost_story._190_say = "Den vrede guden f\248lte blev s\229 intens at han ikke[ENTER]kunne kontrollere det l\230ngere, og noget utroligt[ENTER]skete: Han dr\230bte sin s\248ster, nationens k\230reste.[ENTER]Denne gerning var helt uprovokeret, for p\229 denne[ENTER]dag hun behandlede sin bror med den samme[ENTER]k\230rlighed og tillid, som hun gjorde hver dag. Og[ENTER]han kigge ind i disse rare \248jne og tog hendes liv[ENTER]alligevel. "
gameforge.ghost_story._200_npcChat = "Eftervirkningerne "
gameforge.ghost_story._210_say = "Bahar-Taraji d\248d havde forf\230rdelige konsekvenser[ENTER]for verden af guder, samt mennesker: En lang og[ENTER]grusom vinter kom, dr\230bende v\230sener i havet og p\229[ENTER]land. Jorden fr\248s s\229 fast, at sten spr\230kkede og[ENTER]de \230ldste og st\230rkeste tr\230er visnede. "
gameforge.ghost_story._220_say = "Unge mennesker og dyr d\248de, og da det endelig[ENTER]blev varmere, var f\248dselstallet lavere end[ENTER]nogensinde f\248r. Det sv\230kkede land gav ikke[ENTER]udbytte nok til at holde den voksne befolkning i[ENTER]live - og slet ikke nok til at br\248df\248de nyt liv.[ENTER]H\229bet var d\248dt sammen med livet, og begge havde[ENTER]brug for meget lang tid til at komme p\229 fode[ENTER]igen. "
gameforge.ghost_story._230_say = "Selv guderne tog skade, dog, tiden g\229r[ENTER]langsommere for dem end det g\248r for[ENTER]mennesker.Beran-Setaou trak sig tilbage og s\248gte[ENTER]ensomhed, da det v\230ldige omfang af, hvad han[ENTER]havde gjort gik op for ham.[ENTER]\216del\230ggende beklagelse og dyb tilfredshed[ENTER]grublede inden i ham - indtil sidstn\230vnte vandt[ENTER]denne mentale kamp.[ENTER]Hans hjerte forvandlede sig til is og Guden af[ENTER]opl\248sning blev til Guden af Is og kulde, af Had[ENTER]og af frygt. "
gameforge.ghost_story._240_npcChat = "Slaget "
gameforge.ghost_story._250_say = "Baljit-Elvedin, Gud af Bevarelse, s\248rgede over[ENTER]sin s\248ster i lang tid. Og da de stramme kl\248er af[ENTER]smerte endelig l\248snede deres greb omkring hans[ENTER]hjerte, gik han p\229 jagt efter sin bror.[ENTER]Besindighed og visdom dominerede stadig hans Livs[ENTER]vej og han erkendte, trods hans sorg, at livet[ENTER]ikke kunne forts\230tter med at v\230re i ubalance. "
gameforge.ghost_story._260_say = "Han fulgte sin brors spor og efter mange lange \229r[ENTER]fandt han ham endelig i en hule af is, had og[ENTER]ensomhed, fjernt fra enhver anden tegn p\229 liv.[ENTER]Baljit-Elvedin gjorde, hvad han havde at g\248re,[ENTER]selv om det rev endnu et s\229r ihans hjerte: Han[ENTER]udfordrede sin bror til en duel. Beran-Setaou var[ENTER]kommet s\229 langt fra stien til Retf\230rdighed, at[ENTER]han ikke t\248vede et sekund ... "
gameforge.ghost_story._270_say = "Tilsyneladende var slaget forf\230rdeligt og uden[ENTER]for al forstand. Baljit-Elvedin vandt slaget.[ENTER]Og for at v\230re tro mod hans moral, havde han ikke[ENTER]dr\230bt sin bror, men tog hans kr\230fter fra ham og[ENTER]l\229ste ham inde i grotten. Og s\229ledes er[ENTER]Beran-Setaou her stadig med skabninger, han har[ENTER]skabt i de sidste par \229rhundreder ... "
gameforge.ghost_story._280_npcChat = "Jeg har h\248rt nok. "
gameforge.ghost_story._290_say = "M\229 din sk\230bne blive anderledes end min. Held og[ENTER]lykke! "
gameforge.ghost_story._300_sayTitle = "Sp\248gelse af en kriger: "
gameforge.ghost_story._310_npcChat = "Hvorfor er du gennemskinnelige? "
gameforge.ghost_story._320_say = "Hvad mener du?! Jeg er et sp\248gelse og har v\230ret[ENTER]fanget i denne sten i tusind \229r ... "
gameforge.ghost_story._330_say = "Hj\230lp, et sp\248gelse! "
gameforge.ghost_story._340_say = "Ja, et sp\248gelse. L\248b hurtigt v\230k, ellers vil jeg[ENTER]\230de dig op! "
gameforge.ghost_story._350_npcChat = "Hvem er du? "
gameforge.ghost_story._360_say = "Jeg var lejesoldat engang, en simpel mand. Mine[ENTER]for\230ldre var landm\230nd. Men jeg \248nskede ikke at[ENTER]forts\230tte med at arbejde i samme omr\229de resten af[ENTER]mit liv, s\229 jeg kom med i milit\230ret.[ENTER]Det var h\229rdt og blodigt, men det var ikke s\229[ENTER]d\229rligt. Men da jeg endelig blev tr\230t af at blive[ENTER]kommanderet rundt med af god-for-ingenting[ENTER]adelsm\230nd forlod jeg stedet. Og til sidst f\248rte[ENTER]sk\230bne mig til dette m\248rke sted. "
gameforge.ghost_story._370_npcChat = "Kender du historien om den grotte? "
gameforge.ghost_story._380_say = "Nej, jeg ved det ikke, jeg tror, jeg bare var[ENTER]uheldig. Efter jeg havde forladt milit\230ret,[ENTER]\248nskede jeg at gemme mig i bjergene og snublede[ENTER]s\229 over denne grotte. Det virkede en smule[ENTER]m\230rkeligt p\229 mig lige fra starten, men det var[ENTER]praktisk og syntes helt forladt. F\229 dage senere[ENTER]blev jeg vidne og offer for en utroligt kamp.[ENTER]Hvis du vil, kan jeg fort\230lle dig om det. "
gameforge.ghost_story._390_npcChat = "Begyndelsen af Slaget "
gameforge.ghost_story._400_say = "En dag - jeg samlede r\248dder p\229 bjergsiden - en[ENTER]s\248lv drage fremkom p\229 himlene. Jeg troede, han[ENTER]var efter mig, men han kunne ikke engang se mig -[ENTER]han var helt fokuseret p\229 grotten's indgang.[ENTER]Uden at s\230tte farten ned, kom han fejende ind i[ENTER]dalen og slyngede sig selv ind i hulen. "
gameforge.ghost_story._410_say = "Og s\229 var det stille for et stykke tid, og jeg[ENTER]vidste ikke, hvad jeg skulle g\248re. Alt mit udstyr[ENTER]var i hulen, men jeg \248nskede naturligvis ikke at[ENTER]komme p\229 tv\230rs af dragen! S\229 begyndte jorden at[ENTER]buldre og et kedeligt br\248l l\248d inde fra dybet af[ENTER]hulen - men til min r\230dsel var der ikke bare \233n[ENTER]stemme - men to! Kort efter kom to drager skudt[ENTER]ud af hulen - en s\248lv direkte efterfulgt af en[ENTER]bl\229. "
gameforge.ghost_story._420_say = "En n\230sten ubeskrivelig kamp udspandt sig mellem[ENTER]dragerne. De fl\229ede i hinandens kroppe, blev l\229st[ENTER]fast i et stramt greb og hver is\230r satte t\230nderne[ENTER]i hinandens hals ... Det regnede blod ... Men[ENTER]ingen af dem l\248snede deres greb et sekund. "
gameforge.ghost_story._430_npcChat = "Slutningen af slaget "
gameforge.ghost_story._440_say = "Begge drager rullede over bjergene som et[ENTER]tordenvejr - for\229rsager jordskred og kaos alle[ENTER]vejne. Lyn br\230ndte den bl\229 dragens munden,[ENTER]isnende hagl perforerede s\248lv dragens vinger. Den[ENTER]tykke is skorpe, der havde d\230kket jorden i[ENTER]\229revis, smeltede under dette storml\248b og efterlod[ENTER]en mudret rest bag sig. Jeg gemte mig bag en[ENTER]sten, forstenet men ude af stand til at ignorere[ENTER]synet foran mig. "
gameforge.ghost_story._450_say = "Det tog timer, f\248r deres kr\230fter var udt\248mte.[ENTER]Og s\229, s\229 jeg endelig min chance, rev mig v\230k fra[ENTER]scenen og l\248b ind i dalen for at f\229 mit udstyr[ENTER]fra hulen. Og s\229ledes beseglede jeg min sk\230bne.[ENTER]Jeg var allerede p\229 vej tilbage, da begge drager[ENTER]sk\248d ud fra bjerget, den bl\229 forud for den s\248lv.[ENTER]Han havde lidt forf\230rdelige skader. "
gameforge.ghost_story._460_say = "Lige f\248r de forsvinder ind i hulen, indhentede[ENTER]s\248lv dragen ham og noget meget m\230rkeligt skete:[ENTER]Himlen begyndte at flimre, der formede sig en[ENTER]tr\230kvind og en vortex af energi blev skabt som[ENTER]den bl\229 dragen blev fanget i. Han begyndte at[ENTER]br\248le af smerte og raseri ... han begyndte at[ENTER]skrumpe, hans br\248l blev svagere og hans skalaer[ENTER]mistede deres glans, f\248r han bliver sl\248v og[ENTER]farvel\248s ... "
gameforge.ghost_story._470_say = "Endelig frigav s\248lv dragen den anden drage inde i[ENTER]hulen. Med hans sidste smule styrke, sl\230bte[ENTER]taberen sig ind under bjerget. Men s\248lv drage[ENTER]frigav en kraftfuld magi storm, der lukkede hulen[ENTER]med en energi barriere og blev en del af bjerget[ENTER]sammenbrud. Den m\248rke drage og jeg blev fanget.[ENTER]D\248mt til en kummerlig og ulidelig sulted\248d ... "
gameforge.ghost_story._480_npcChat = "Jeg har h\248rt nok. "
gameforge.ghost_story._490_say = "Tak fordi du gad at lytte. De sidste tusind \229r[ENTER]har v\230ret rigtig ensomme ... "
gameforge.goldbar = {}
gameforge.goldbar._100_say = "Inden jeg slap bort fra sort-vind-banden, fandt[ENTER]jeg ud af hvor de har gemt deres guld. De har en[ENTER]k\230mpe bunke guldbarrer! De ville ikke bem\230rke,[ENTER]hvis der ville mangle nogen. Sikke idioter de er.[ENTER]Hvis du er indforst\229et med betalingen kan jeg[ENTER]bringe dig en guldbarre. Men jeg kan ikke b\230re[ENTER]mere end en guldbarre af gangen.  "
gameforge.goldbar._104_say = "Tid "
gameforge.goldbar._108_say = "Minut(ter) "
gameforge.goldbar._10_npcChat = "Offer for sort-vind-banden "
gameforge.goldbar._110_say = "Det tager ca. %s %s, for at bringe en guldbarre[ENTER]tilbage. "
gameforge.goldbar._120_say = "Sig til n\229r du er interesseret. "
gameforge.goldbar._130_say = "Seri\248st? S\229 finder vi nok ud af det! Du skal bare[ENTER]sige til, og jeg bringer dig en! "
gameforge.goldbar._140_npcChat = "Jeg \248nsker at k\248be en Guldbar. "
gameforge.goldbar._150_say = "Hvad siger du? Om det ved jeg intet. "
gameforge.goldbar._160_say = "Hvad? Du \248nsker at k\248be guldbarrer?[ENTER]Nej, ikke nu! Sort-vind-banden ser ud til at v\230re[ENTER]mistroiske. Jeg risikerer at blive fanget! Vi[ENTER]pr\248ver igen, n\229r han er faldet lidt til ro. "
gameforge.goldbar._170_sayReward = "Pt. kan du ikke k\248be guldbarrer. "
gameforge.goldbar._180_say = "Det var endnu ikke muligt for mig at hente en[ENTER]guldbarre. "
gameforge.goldbar._190_say = "Vi bliver n\248d til at vente ca. %s %s. "
gameforge.goldbar._200_say = "Jeg har medbragt en guldbarre. Den koster kun 2,2[ENTER]Millioner Yang. De 200.000 Yang er for[ENTER]bearbejdelsesgebyr. Er du interesseret i at k\248be[ENTER]en? "
gameforge.goldbar._20_sayTitle = "Forr\230deren Balso : "
gameforge.goldbar._210_say = "Der er du, en Guldbar! Du har lavet en klog[ENTER]beslutning. Det er altid en god ide at lave[ENTER]investeringer. "
gameforge.goldbar._220_say = "Du har ikke nok Yang! Den koster 2,2 Millioner[ENTER]Yang. "
gameforge.goldbar._230_say = "Hvorfor er du her, n\229r du slet ikke vil k\248be[ENTER]noget? Du har spildt min tid. "
gameforge.goldbar._240_npcChat = "GM: Tilbages\230t guldbarre-salgs-tid "
gameforge.goldbar._250_say = "Guldbarre-salgstiden blev sat tilbage. "
gameforge.goldbar._260_npcChat = "S\230lg en guldbar. "
gameforge.goldbar._270_say = "Hvad siger du? Om det ved jeg intet. "
gameforge.goldbar._280_say = "Hvad? Du \248nsker at s\230lge din guldbarre? Har du[ENTER]ikke h\248rt, at sort-vind-banden er blevet[ENTER]mistroiske! Hvis du s\230lger en guldbarre vil du[ENTER]ikke v\230re lang tid i live. Det er nok bedst, du[ENTER]lader v\230re med at s\230lge den, og den forbliver[ENTER]hvor den er. Gem den godt!  "
gameforge.goldbar._290_sayReward = "Pt. kan du ikke s\230lge guldbarrer. "
gameforge.goldbar._300_say = "Hvis du \248nsker at bringe en guldbarre tilbage, "
gameforge.goldbar._30_say = "Hvad? Et offer for sort-vind-banden? Ha, ha, ha![ENTER]Du er jo stadig et barn. Hvor har du h\248rt det? G\229[ENTER]ud og leg med vildhundene!  "
gameforge.goldbar._310_say = "bliver du n\248d til at vente %s %s. "
gameforge.goldbar._320_say = "Du har ingen guldbarrer.[ENTER]Hvis du afleverer nogle guldbarrer, vil du f\229[ENTER]Yang for den.  "
gameforge.goldbar._330_say = "Hvad? Du vil aflevere din guldbarre? Hvorfor i[ENTER]alverden har du s\229 overhoved k\248bt den? Hvis du[ENTER]absolut vil bringe den tilbage, s\229 har jeg intet[ENTER]imod det.[ENTER]Sort-vind-banden holder vagt, s\229 jeg kan ikke[ENTER]g\248re det for ofte. \216nsker du stadig at give den[ENTER]tilbage igen? "
gameforge.goldbar._340_select = "Tilbage. "
gameforge.goldbar._350_select = "Behold. "
gameforge.goldbar._360_say = "Her er dine Yang.[ENTER]Well, nu bliver jeg n\248d til at bringe den[ENTER]tilbage!  "
gameforge.goldbar._370_say = "Har du overhoved guldbarrer?[ENTER]Jeg er meget besk\230ftigt! S\229 venlig kun at komme[ENTER]hvis du \248nsker at handle.  "
gameforge.goldbar._40_sayReward = "'Et offer af sort-vind-bande'-opgaven er kun[ENTER]tilg\230ngeligt for karakterer med level 30 eller[ENTER]h\248jere. "
gameforge.goldbar._50_say = "V\230r forsigtigt! Sort-vind-krigerne er blevet[ENTER]mistroiske. Det er bedst, at man forholder sig[ENTER]absolut stille. Lev i fred. "
gameforge.goldbar._60_sayReward = "En 'Et offer af Sort-vind-banden'-opgave er pt.[ENTER]ikke tilg\230ngeligt. "
gameforge.goldbar._70_say = "Psssst![ENTER]Her er der nogle sort-vind-krigerne gemt. Har du[ENTER]h\248rt om dem?[ENTER]Nej? Okay. Det er ikke s\229 vigtigt. Ved du[ENTER]nogenlunde hvad der sker her?  "
gameforge.goldbar._80_select = "Nej, i grunden ikke. "
gameforge.goldbar._90_select = "Ja, jeg ved. "
