gameforge.guild_building_npc._10_sayTitle = "V\229bensmed: "
gameforge.guild_building_npc._20_say = "Oh, du er medlem af min orden! Hvis du \248nsker at[ENTER]opgradere dit v\229ben, s\229 bring dem til mig, og[ENTER]ikke til de nybegyndere inde i byen. Min[ENTER]succesrate er 10% h\248jere. Vores medlemmer f\229r[ENTER]ogs\229 5% rabat. Bare giv mig v\229bnet du \248nsker at[ENTER]opgradere, og jeg vil klare arbejdet. "
gameforge.guild_building_npc._30_say = "Mit navn er Sanley, og jeg er ansvarligt for at[ENTER]forbedre v\229ben.[ENTER]Jeg er meget bedre end landsby-smeden![ENTER]N\229r jeg forbedrer dit v\229ben \248ges sandsynligheden[ENTER]for succes med 10%.[ENTER]Giv mig det v\229ben, der skal[ENTER]forbedres  "
gameforge.guild_building_npc._40_sayTitle = "Rustningssmed: "
gameforge.guild_building_npc._50_say = "Ah, du er medlem af min orden! Det betyder at du[ENTER]kan give mig din rustning, skjold, sko og hjelm[ENTER]til opgradering. Min succesrate er 10% h\248jere end[ENTER]by smedjen! Jeg kan ogs\229 give medlemmer i ordenen[ENTER]5% rabat. Det er simpelt giv mig udstyret du[ENTER]\248nsker at f\229 opgraderet. "
gameforge.guild_building_npc._60_say = "Mit navn er Stanton. Jeg er ansvarlig for[ENTER]opgradering af rustninger. Jeg er meget bedre end[ENTER]bysmedjen: Min succesrate er 10% h\248jre. Giv mig[ENTER]simpelt din rustning som du \248nsker at jeg skal[ENTER]forbedre. "
gameforge.guild_building_npc._70_sayTitle = "Juvel\233r: "
gameforge.guild_building_npc._80_say = "Oh, du er medlem i min Orden![ENTER]Din succes-sandsynlighed \248ges med 10% n\229r du[ENTER]lader dine smykker forbedre hos mig.[ENTER]Yderligere giver jeg vores medlemmer 5% rabat.[ENTER]Jeg kan forbedre armb\229nd, \248rering og k\230der.[ENTER]Giv mig dit smykke, der skal blive[ENTER]forbedres!  "
gameforge.guild_building_npc._90_say = "Mit navn er Starbuck, og jeg er ansvarligt for at[ENTER]forbedre smykker.[ENTER]Jeg er meget bedre end landsby-smeden![ENTER]N\229r jeg forbedrer dine smykker \248ges[ENTER]sandsynligheden for succes med 10%.[ENTER]Jeg kan forbedre armb\229nd, \248rering og k\230der.[ENTER]Giv mig det smykke, der skal forbedres! "
