gameforge.heavens_cave_keyquest._020_npcChat = "I grotten "
gameforge.heavens_cave_keyquest._030_say = "Lyt opm\230rksomt min dreng! Jeg fort\230ller dig kun[ENTER]denne historie en gang... "
gameforge.heavens_cave_keyquest._040_say = "Lyt opm\230rksomt min pige! Jeg fort\230ller dig kun[ENTER]denne historie en gang... "
gameforge.heavens_cave_keyquest._050_say = "Nu om stunder tilbeder vi Drageguden, men engang[ENTER]vogtede tre guder over os. Men Bahar-Taraji,[ENTER]skabelsens gudinde, blev myrdet af hendes[ENTER]skinsyge bror Beran-Setaou. Den tredje gud,[ENTER]Baljit-Elvedin, som vi i dag kender som[ENTER]Drageguden, begav sig til at s\248rge dybt over sin[ENTER]s\248ster. "
gameforge.heavens_cave_keyquest._060_say = "En kamp br\248d ud mellem de to br\248dre, som[ENTER]Drageguden vandt. Rygtet siger, at spor fra[ENTER]kampen stadig kan findes p\229 stedet hvor[ENTER]sk\230nderiet fandt sted. Beran-Setaou blev lukket[ENTER]inde i en grotte efter hans nederlag, en grotte[ENTER]der senere blev kendt som Forbandelsens Grotte. "
gameforge.heavens_cave_keyquest._070_say = "Grotten er forseglet og bliver bevogtet af[ENTER]medlemmer af Baljit-Elvedins orden. Du skal[ENTER]aflevere en blodsten for at f\229 adgang. Jeg ved[ENTER]hvordan man producerer disse sten, men det er[ENTER]ikke nemt. "
gameforge.heavens_cave_keyquest._080_say = "Det begyndte med t\229rerne som Drageguden gr\230d over[ENTER]hans s\248ster, de blev senere til sten der faldt[ENTER]ned over jorden. Du kan stadig finde dem i[ENTER]ildlandet Doyyumhawn. Skaf 7 af disse t\229rer og[ENTER]fire stykker obsidian fra flammerne der lever der[ENTER]og bring dem til mig. "
gameforge.heavens_cave_keyquest._090_say_reward = "Saml 7 forsillet t\229rer og 4 stykker obsidian i[ENTER]Doyyumhwan. "
gameforge.heavens_cave_keyquest._100_say = "Du beh\248ver endnu en blodsten for at komme fordi[ENTER]vogteren af ordenen? S\229 saml yderligere syv[ENTER]fossilet t\229rer og fire stykker obsidian i[ENTER]ildlandet Doyyumhwan. "
gameforge.heavens_cave_keyquest._110_say = "Du skal bruge endnu en blodsten? Koe-Pung er ikke[ENTER]den klogeste, men du burde vente lidt, ellers[ENTER]opdager han m\229ske at du ikke er med i hans orden. "
gameforge.heavens_cave_keyquest._120_say = "Et par timer, jeg ville sige: %s "
