gameforge.heavens_cave_keyquest._310_say = "Hendes \229nd vandrer p\229 jorden. Hendes stemme vil[ENTER]tale til dig n\229r du b\230rer t\229rerne med dig. Led[ENTER]efter hende i den r\248de skov Lungsam! "
