gameforge.heavens_cave_keyquest._330_say = "Led efter Bahar-Tarajis stemme i den r\248de skov[ENTER]Lungsam. Selvom du ikke kan se gudindens \229nd, s\229[ENTER]kan du f\248le hendes tilstedev\230relse. "
gameforge.heavens_cave_keyquest._335_say = "En stille hviskende lyd hyler i vinden: G\229 til et[ENTER]sikkert sted... Vi kan ikke tale her...[ENTER]Klik p\229 missions rullen for at snakke med[ENTER]sp\248gelset. "
gameforge.heavens_cave_keyquest._340_say = "I det fjerne lyder stemmen fra den myrdede[ENTER]gudinde Bahar-Taraji... "
gameforge.heavens_cave_keyquest._350_say = "Min broders t\229rer... Han s\248rgede over mig i s\229[ENTER]lang tid, og alligevel kunne han ikke straffe[ENTER]Beran-Setaou for hans misgerninger. "
gameforge.heavens_cave_keyquest._360_say = "Han kunne ikke konfrontere sin bror Beran-Setaou,[ENTER]\248del\230ggeren, den som folket frygtede. "
gameforge.heavens_cave_keyquest._370_say = "Men du... Hvem er du? Du er anderledes! Du er[ENTER]ikke bange for ham. Tv\230rtimod, jeg kan se at du[ENTER]s\248ger kamp. "
gameforge.heavens_cave_keyquest._380_say = "%s! Tag disse dr\229ber af mit blod. Lav en blodsten[ENTER]af dem og s\248rg for at Beran-Setaou betaler for[ENTER]hans misgerninger. Forbandelsens grotte er ikke[ENTER]langt herfra. "
gameforge.heavens_cave_keyquest._390_say = "I det fjerne lyder stemmen fra den myrdede[ENTER]gudinde Bahar-Taraji... "
gameforge.heavens_cave_keyquest._400_say = "%s! Jeg genkender dig! "
gameforge.heavens_cave_keyquest._410_say = "Du har givet mig min broders t\229rer for at tr\248ste[ENTER]mig og du vil derfor modtage mit blod som[ENTER]bel\248nning, s\229 du kan forts\230tte kampen. "
gameforge.heavens_cave_keyquest._420_say = "G\229 tilbage til Seon-Hae med Bahar-Tarajis blod. "
gameforge.heavens_cave_keyquest._430_say = "Seon-Haes \248jne bliver fjerne da hun tager[ENTER]bloddr\229berne fra dig... "
gameforge.heavens_cave_keyquest._440_say = "Blodet fra en \230gte gudinde! Hurtigt, lad mig lave[ENTER]det om til en blodsten inden det t\248rrer ind. "
gameforge.heavens_cave_keyquest._450_say = "Vogteren Koe-Pung vil lade dig bruge portalen der[ENTER]leder ind til forbandelsens grotte hvis du har en[ENTER]blodsten p\229 dig. Men, det vil kun virke en gang.[ENTER]Hvis du skal bruge flere blodsten, s\229 kom tilbage[ENTER]til mig. Desv\230rre kan jeg kun producere en[ENTER]blodsten hver dag, s\229 vi ikke tiltr\230kker ordnens[ENTER]vrede. "
gameforge.heavens_cave_keyquest._460_say_reward = "Seon-Hae kan producere flere blodsten til dig,[ENTER]men kun en per dag. "
gameforge.heavens_cave_keyquest._470_say = "Jeg vil lave Bahar-Tarajis blod om til en[ENTER]blodsten. M\229 den tjene dig godt. "
gameforge.heavens_cave_keyquest._480_say_reward = "Jeg kan kun lave en blodsten om dagen.[ENTER]Ellers bliver Koe-Pung mist\230nksom. "
