gameforge.locale.bookworm = {}
gameforge.locale.bookworm.accept_ask = "Soon : Hvad venter du p\229?[ENTER]Da du har accepteret opgaven burde du skynde dig[ENTER]at l\248se den.[ENTER]Den som kommer f\248rst, f\229r pr\230mien! Afsted! "
gameforge.locale.bookworm.accept_failure_info_label = "G\229 tilbage til Soon. "
gameforge.locale.bookworm.accept_failure_info_text_1 = "G\229 tilbage til Soon. "
gameforge.locale.bookworm.accept_failure_info_text_2 = "G\229 tilbage til landsbyen og fort\230l Soon, at du[ENTER]ikke kunne finde Milgyo-bogen. "
gameforge.locale.bookworm.accept_failure_say_1 = "G\229 tilbage til landsbyen "
gameforge.locale.bookworm.accept_failure_say_2 = "Det virker til jeg er forfulgt af uheld - jeg kan[ENTER]bare ikke finde Milgyo-bogen. Det eneste jeg kan[ENTER]g\248re nu er at g\229 tilbage til byen. "
gameforge.locale.bookworm.accept_success_info_label = "Find Milgyo-bogen til Soon. "
gameforge.locale.bookworm.accept_success_info_text_1 = "Find Milgyo-bogen til Soon. "
gameforge.locale.bookworm.accept_success_info_text_2 = "G\229 tilbage til landsbyen, aflever bogen til Soon[ENTER]og modtag bel\248nningen. "
gameforge.locale.bookworm.accept_success_say_1 = "Der har vi jo Milgyo-bogen! "
gameforge.locale.bookworm.accept_success_say_2 = "Det er Milgyo-bogen![ENTER]Aflever det til Soon i landsbyen. "
gameforge.locale.bookworm.aranyeo_complete_say = "Hvilken idiot har afleveret denne bog til min[ENTER]\230gtemand? Han har stirret i den hele dagen, og[ENTER]l\230rer underlig messen udenad. Han l\248fter ikke en[ENTER]finger l\230ngere! Jeg smadre hver en knogle i hans[ENTER]krop n\229r jeg f\229r fingrene i ham! "
gameforge.locale.bookworm.aranyeo_complete_say2 = "Aranyeo : Hvad er der sket? Hvorfor har du[ENTER]koldsved p\229 panden? "
gameforge.locale.bookworm.aranyeo_start_say = "Hvor gik han nu hen? Hans attitude g\229r mig squ p\229[ENTER]nerverne! Han spilder hele dagen p\229 at l\230se[ENTER]b\248ger, uden at tjene en eneste Yang. Og han er[ENTER]endda ikke engang flov over det faktum at han er[ENTER]s\229 d\229rlig en rollemodel for hans b\248rn. "
gameforge.locale.bookworm.aranyeo_start_say2 = "Kan b\248ger bringe en mad p\229 bordet eller give dig[ENTER]t\248j p\229 kroppen? Jeg smadre alle hans knogler n\229r[ENTER]jeg f\229r fat i ham! "
gameforge.locale.bookworm.aranyeo_talk = "Snakke. "
gameforge.locale.bookworm.complete_say = "Soon : Oha! Ja, jeg kan se det! Jeg kan se det![ENTER]Jeg kan se den nye verden! "
gameforge.locale.bookworm.do_you_find_the_book = "Har du fundet Milgyo-Bogen? "
gameforge.locale.bookworm.do_you_mean_this_book = "Mener du denne bog? "
gameforge.locale.bookworm.etc_shop_start_say = "Han kom her ig\229r og spurgte ang\229ende Milgyo[ENTER]bogen. Han havde ingen Yang, men han spurgte om[ENTER]det konstant alligevel. M\229ske har Milgyo noget at[ENTER]g\248re med de brutale monstre i Seungryong dalen.[ENTER]Ved dog ikke hvorfor han pludselig har s\229dan en[ENTER]interesse i disse monstre. "
gameforge.locale.bookworm.etc_shop_start_say2 = "Jeg har medlidenhed med Aranyo.[ENTER]Hvorfor er hun stadig sammen med s\229dan en person? "
gameforge.locale.bookworm.etc_shop_talk_about_bookworm = "Om den l\230rte Soon. "
gameforge.locale.bookworm.order_accept = "Godt! Jeg vil finde den for dig! "
gameforge.locale.bookworm.order_accept_answer = "Tak! Jeg stoler p\229 dig. "
gameforge.locale.bookworm.order_find_book_label = "Dr\230b Milgyo`s disciple! "
gameforge.locale.bookworm.order_find_book_text_1 = "Dr\230b Milgyo`s disciple! "
gameforge.locale.bookworm.order_find_book_text_2 = "Tag Milgyo-bogen fra Milgyos discipel. "
gameforge.locale.bookworm.order_refuse = "Det bliver nok temmelig sv\230rt. "
gameforge.locale.bookworm.order_refuse_answer = "Soon : Hvorfor pr\248ver du ikke? Jeg ved, at du er[ENTER]i stand til at klare det! "
gameforge.locale.bookworm.order_say1 = "Vil du h\248re noget sjovt? Jeg kan med sikkerhed[ENTER]sige, at have l\230st alle b\248ger i denne verden! Pt.[ENTER]studerer jeg en samling af hellige skrifter.[ENTER]Rygter siger, at hemmelige informationer og[ENTER]henvisninger om hvordan man bliver en helgen, er[ENTER]skjult i Milgyo-bogen. "
gameforge.locale.bookworm.order_say2 = "Jeg vil s\229 gerne l\230se den bog!! Hvad siger du?[ENTER]Kan du f\229 fat i den bog? Hvis du kan give mig den[ENTER]bog, vil du f\229 en stor bel\248nning. Ogsp selv om[ENTER]jeg blev n\248dtil at s\230lge mit hus! "
gameforge.locale.bookworm.order_too_late = "En anden person har allerede afleveret Milgyo[ENTER]bogen til mig. Du beh\248ver ikke g\248re det mere. "
gameforge.locale.bookworm.start_find_bookworm_label = "G\229 til Soon "
gameforge.locale.bookworm.start_find_bookworm_text_1 = "G\229 til Soon "
gameforge.locale.bookworm.start_find_bookworm_text_2 = "G\229 til Soon og sp\248rg efter Milgyo-bogen. "
gameforge.locale.bookworm.start_say = "Kan du se den dybe visdom i dette dokument?[ENTER]Individuelle ord danner s\230tninger og det er s\229dan[ENTER]en vidunderlig historie opst\229r. Man bliver n\248d[ENTER]til at v\230nne sig til at blive ledt af andre folks[ENTER]fantasi og ikke alle kan lide det, men jeg elsker[ENTER]det. "
gameforge.locale.bookworm.start_say2 = "Jo mere du har, jo mere f\229r du.[ENTER]Jo mere du ved, jo mere forn\248jelse har du af[ENTER]livet. Oh.. Hvis bare jeg kunne l\230se b\248ger hele[ENTER]mit liv... "
gameforge.locale.bookworm.success_thanks = "Uha! Det er den! Jeg vil l\230se den med gl\230de! "
gameforge.locale.bookworm.talk = "Snakke. "
gameforge.locale.bookworm.talk_about_milgyo_book = "Sp\248rg til Milgyo-bogen. "
