gameforge.locale.christmas_santa.bye_msg = "Som du \248nsker. Held og lykke i dag![ENTER]Og glade feriedage, ho ho ho! "
gameforge.locale.christmas_santa.hairdye_msg = "%d Yang for en genstand fra denne s\230k. Der er[ENTER]forskelligt materiale til at opgradere genstande[ENTER]heri. Du kan f\229 lov at tage en genstand ud, men[ENTER]du m\229 ikke kigge i s\230kken! Hvad synes du? "
gameforge.locale.christmas_santa.hairdye_sold_out_msg = "Hmm, der ser man - Jeg har ikke mere opgraderings[ENTER]materiale! Jeg er virkelig ked af det. "
gameforge.locale.christmas_santa.intro_msg = "Ho, ho, ho! Gl\230delig jul! Du er heldig at du[ENTER]fangede mig. Jeg har meget travlt i disse dage.[ENTER]Vil du k\248be noget? "
gameforge.locale.christmas_santa.not_enough_money = "Jeg er virkelig ked af det, men desv\230rre har du[ENTER]ikke Yang nok, til at k\248be noget.[ENTER]Ikke desto mindre \248nsker jeg dig de gl\230deligste[ENTER]helligdage! "
