gameforge.locale.christmas_santa.select_buy = "Jeg k\248ber. "
gameforge.locale.christmas_santa.select_stop = "Helst ikke. "
gameforge.locale.christmas_santa.skill_book_msg = "Denne f\230rdighedsbog vil koste dig %d Yang, men du[ENTER]vil ikke vide hvilken f\230rdighedsbog det er indtil[ENTER]du \229bner den. \216nsker du stadig at pr\248ve lykken og[ENTER]k\248be en? "
gameforge.locale.christmas_santa.skill_book_sold_out_msg = "Oh, Jeg var sikker p\229 jeg havde nogle b\248ger[ENTER]her... Jeg er ked af det, men \229benbart har jeg[ENTER]solgt dem alle. "
