gameforge.locale.christmas_tree.christmas_say_title = "Juletr\230 "
gameforge.locale.christmas_tree.gain_item_msg = "Du h\230nger din sok p\229 tr\230et. S\229 lukker du dine[ENTER]\248jne og venter i 3 sekunder.[ENTER][DELAY value;500]. . .[/DELAY][ENTER][ENTER]Jeg h\229ber du kan lide din gave.[ENTER]Gl\230delig Jul. "
gameforge.locale.christmas_tree.greet = "Hej! Er du kommet for at beundre min pragt? Eller[ENTER]er der noget jeg kan g\248re for dig? "
gameforge.locale.christmas_tree.greet2 = "Som du \248nsker. Men nu hvor du har h\230ngt en sok p\229[ENTER]mig, vil jeg give dig en gave. Gl\230delig Jul! "
gameforge.locale.christmas_tree.intro_msg = "Jeg vil give dig noget hvis du h\230nger en sok p\229[ENTER]mig! Sokkerne finder du alle steder, spredt over[ENTER]hele kontinentet. F\248rst n\229r du mindst har opn\229et[ENTER]Level 10 m\229 du h\230nge en sok p\229 mig. "
