gameforge.locale.forked_condition = "Vi skal finde vogteren af portalen f\248r en af de[ENTER]andre riger g\248r.[ENTER]Lad os vise vores riges muskler og udvide dens[ENTER]magt! "
gameforge.locale.forked_condition2 = "Nu skal vi kun dr\230be, dem som stadig er i vores[ENTER]hellige land. Til angreb! "
gameforge.locale.forked_enter = "Deltag. "
gameforge.locale.forked_kill_boss = "Jeg er Thorr Sarch! Hvad vil du fra mig? Jeg er[ENTER]ikke d\248d, jeg vil komme tilbage til livet.[ENTER]legioner af krigere vil f\248lge mig![ENTER]Du har afsluttet nationskrigen. Alle vil blive[ENTER]transporteret tilbage til byen. "
gameforge.locale.forked_man_chat = "Deltag i Nationskrigen "
gameforge.locale.forked_man_say = "Der er fundet et nyt omr\229de. Det er i midten af[ENTER]kontinentet - det forbinder m\229ske alle rigerne[ENTER]sammen. Det sv\230rmer med m\248rke monstre. M\229ske[ENTER]kunne du begive dig derhen og konfrontere dem?[ENTER]Dr\230b dem alle og skab fred i vores rige igen. "
gameforge.locale.forked_man_say_cant = "Hey! Et nyt omr\229de er opdaget i den inderste del[ENTER]af kontinentet. Det kan muligvis forbinde alle[ENTER]rigerne. S\229 snart unders\248gelserne er f\230rdige der,[ENTER]kan du betr\230de omr\229det. "
gameforge.locale.forked_no_enter = "Deltage ikke. "
gameforge.locale.forked_open_gate = "D\248ren der har v\230ret lukket indtil nu, \229bnet. Lad[ENTER]os drage mod nye lande! Vi vil erobre dem! Alle[ENTER]vil blive transportert til den hellig grund. "
gameforge.locale.forked_rule = "Regler for at deltage i nationskrigen:[ENTER]1. Alle som d\248r i dette omr\229de bliver[ENTER]transporteret tilbage til byen, men[ENTER]slagsforvalteren kan bringe ham tilbage hertil[ENTER]med det samme.[ENTER]2. S\229 snart d\248rene til det hellige land er blevet[ENTER]\229bnet, er dette omr\229de lukket.[ENTER]3. For at f\229 adgang til det hellige land, skal du[ENTER]finde den matchende n\248gle. "
gameforge.locale.forked_rule_sungzi = "Regler for Nationskrigen:[ENTER]1. Det Rige, der har opn\229et f\230rrest sejre mod et[ENTER]andet Rige, udlukkes f\248rst.[ENTER]2. Fjendtlige monster vil dukke op. Det f\248rste[ENTER]rige der nedk\230mper et bestemt antal monster[ENTER]vinder.[ENTER]3. Hvis den Nihalede dr\230bes efter dette, ender[ENTER]kampen.[ENTER]4. Ingen genstande kan modtages under kampen.[ENTER]5. Den som dr\230bes 3 gange i det hellige land,[ENTER]bliver transporteret tilbage til landsbyen, og[ENTER]udelukkes fra nationskrigen. "
gameforge.locale.fortune_words_1_body = "Heldet tilsmiler dig i dag! Du vil v\230re \"meget[ENTER]heldig i dag\"! Dem som er beskyttet af denne[ENTER]harmoni vil der ske noget godt for i dag. "
gameforge.locale.fortune_words_1_title = "Meget held og lykke! "
gameforge.locale.fortune_words_2_body = "Det er godt. Hvad er det ordsproget siger? Du[ENTER]h\248ster hvad du s\229r. I dag, vil du havde \"Godt[ENTER]held\"! Jeg er s\229 glad for dig. En lille smule[ENTER]anstrengelser og du vil modtage mere end f\248r! "
gameforge.locale.fortune_words_2_title = "Stort held og lykke! "
gameforge.locale.fortune_words_3_body = "Det er ikke d\229rligt. I dag, vil du have \"Noget[ENTER]godt held\". Din dag vil g\229 en smule bedre end[ENTER]normalt, men forvent ikke store gaver! "
gameforge.locale.fortune_words_3_title = "Nogen held. "
gameforge.locale.fortune_words_4_body = "Intet godt, men heller intet d\229rligt! I dag har[ENTER]du \"Normalt held\". Det vil ikke rigtigt hj\230lpe[ENTER]dig videre, men det er bedre end at have uheld.[ENTER]Normale dage er ikke at kimse af, s\229 nyd den! "
gameforge.locale.fortune_words_4_title = "Normalt held. "
gameforge.locale.fortune_words_5_body = "Du er ikke s\230rlig heldig i dag. Selv om du kaster[ENTER]dine net ud s\229 samvittighedsfuld som du[ENTER]nogensinde har gjort, vil du ikke fange ret mange[ENTER]fisk i dag. P\229 plus siden vil du ikke sulte. Du[ENTER]vil have \"en smule d\229rligt held i dag\"! Men der[ENTER]er ikke noget der er bedre end at v\230re godt[ENTER]forberedt. Hvis du \248nsker det kan jeg s\230lge dig[ENTER]en Talisman som kan hj\230lpe dig med at forhindre[ENTER]d\229rligt held. Er du interesseret? "
gameforge.locale.fortune_words_5_title = "Lidt uheld. "
gameforge.locale.fortune_words_6_body = "I dag er en d\229rlig dag. En dag hvor selv det at[ENTER]g\248re dit bedste knapt vil give dig noget. I dag[ENTER]har du \"D\229rligt held\" og du er n\248d til at v\230re[ENTER]forsigtig med hvor du g\229r og hvad du g\248r. Jeg[ENTER]kunne dog, hj\230lpe dig og s\230lge dig en talisman s\229[ENTER]du kan afv\230rge skade. Er du interesseret? "
gameforge.locale.fortune_words_6_title = "Uheld. "
gameforge.locale.fortune_words_7_body = "Dette kommer til at v\230re din v\230rste dag i dit[ENTER]liv. Alle guder i himlen og p\229 jorden har vent[ENTER]dig ryggen. Ingenting vil komme til at virke i[ENTER]dag. Hvis du vil starte et b\229l vil det regne;[ENTER]Hvis du er t\248rstig, vil solen skinde ned p\229 dig.[ENTER]Du vil arbejde lige s\229 h\229rdt som alle andre, men[ENTER]du vil ikke modtage nogen bel\248nning for det. Du[ENTER]vil lide af \"Virkelig d\229rlig held\"! Uden en[ENTER]talisman, vil du have en sv\230rd tid. Er du[ENTER]interesseret i at k\248be en? "
gameforge.locale.fortune_words_7_title = "Stort uheld. "
