gameforge.locale.make_wonso.how_make = "Hvordan kan jeg lave risboller? "
gameforge.locale.make_wonso.how_make_detail = "N\229r du jagter monstre finder du alle slags[ENTER]ingredienser til risboller: B\248nnemasse,[ENTER]sukkermasse, frugtmasse og s\248de ris. Hvis du[ENTER]bringer mig nogle af disse masser og en portion[ENTER]s\248de ris, s\229 kan jeg lave dig en risbolle. Det[ENTER]siges at risboller har en specielt effekt n\229r de[ENTER]bliver spist... "
gameforge.locale.make_wonso.make_msg1 = "Har du de n\248dvendige ingredienser? Godt. Jeg[ENTER]tager b\248nnemassen og den s\248de ris og laver dig[ENTER]en... b\248nnekage! Bon appetit. "
gameforge.locale.make_wonso.make_msg2 = "Har du de n\248dvendige ingredienser? Godt. Jeg[ENTER]tager sukkermassen og den s\248de ris og laver dig[ENTER]en... sukkerkage! Bon appetit. "
gameforge.locale.make_wonso.make_msg3 = "Har du de n\248dvendige ingredienser? Godt. Jeg[ENTER]tager frugtmassen og den s\248de ris og laver dig[ENTER]en... frugtkage! Bon appetit. "
