gameforge.locale.monster_chat = {}
gameforge.locale.monster_chat_1001_1 = "h\230, h\230! Alle burde d\248. Kyaaa! "
gameforge.locale.monster_chat_1001_2 = "Sm\229, sm\229, sm\229 stykker... "
gameforge.locale.monster_chat_1001_3 = "Ingen undslipper! "
gameforge.locale.monster_chat_1001_4 = "Jorden vil drikke dit blod. D\248! "
gameforge.locale.monster_chat_1001_5 = "Tig, men det vil ikke hj\230lpe dig! "
gameforge.locale.monster_chat_1001_6 = "Du kan ikke skjule din frygt for mig! "
gameforge.locale.monster_chat_1002_1 = "Dr\230b! Dr\230b alle mennesker... "
gameforge.locale.monster_chat_1002_2 = "De elendige orme! "
gameforge.locale.monster_chat_1002_3 = "S\229 langsomt g\248r du mig vred... "
gameforge.locale.monster_chat_1002_4 = {}
gameforge.locale.monster_chat_1002_5 = "Dit blod vil flyde. "
gameforge.locale.monster_chat_1003_1 = "D\248d og \248del\230ggelse...! "
gameforge.locale.monster_chat_1003_2 = "Har du nogensinde set de s\229r, som et spyd kan rive? "
gameforge.locale.monster_chat_1003_3 = "Ja, l\248b alt du kan! Vi vil se hvor langt du kommer... "
gameforge.locale.monster_chat_1003_4 = "Alene synet af dine sk\230lvende h\230nder, g\248r det hele det v\230rd... "
gameforge.locale.monster_chat_1003_5 = "Dit udskud, vover du at udfordre mig? "
gameforge.locale.monster_chat_1003_6 = "D\248den vil v\230re din eneste f\248lgesvend! "
gameforge.locale.monster_chat_1004_1 = "Din sj\230l vil tilh\248re mig! "
gameforge.locale.monster_chat_1004_2 = "Ahh, friskt k\248d! "
gameforge.locale.monster_chat_1004_3 = "Det ser ud til, at endnu et mennesker finder sin d\248d her! "
gameforge.locale.monster_chat_1004_4 = "Du skal lide, lide og gr\230de alle dine smerter h\248jlydt ud... "
gameforge.locale.monster_chat_1004_5 = "Tror du virkelig at det latterlige v\229ben i din h\229nd vil v\230re i stand til at beskytte dig? "
gameforge.locale.monster_chat_1004_6 = "Dit mod bragte dig til mig. Og nu vil det forlade dig... "
gameforge.locale.monster_chat_1035_1 = "Hvis jeg d\248r, vil min h\230vn f\248lge dig i evigheder! "
gameforge.locale.monster_chat_1035_2 = "Jeg vil dr\230be dig og lade dig lide langsomt, meget langsomt... "
gameforge.locale.monster_chat_1035_3 = "Det vil v\230re mig en forn\248jelse at f\229 dig til at lide. "
gameforge.locale.monster_chat_1035_4 = "Din krop ryster som en senil gammel k\230lling! "
gameforge.locale.monster_chat_1035_5 = "Jeg kan lugte din frygt, du lille. "
gameforge.locale.monster_chat_1035_6 = "Jeg tror det er p\229 tide jeg befrier dig for et par af dine kropsdele. "
gameforge.locale.monster_chat_1036_1 = "Jeg vil sende dig ind i dit eget personlige helvede! "
gameforge.locale.monster_chat_1036_2 = "Din smerte vil drive dig til vanvid, inden du d\248r... "
gameforge.locale.monster_chat_1036_3 = "Du kan jamre! Du kan bede! Men det vil ikke hj\230lpe dig. "
gameforge.locale.monster_chat_1036_4 = "Du kommer til at opleve den v\230rste d\248d du kan forestille dig... "
gameforge.locale.monster_chat_1036_5 = {}
gameforge.locale.monster_chat_1036_6 = "Din magt bliver svagere. Du er allerede p\229 kanten af d\248den... "
gameforge.locale.monster_chat_1037_1 = "Er du klar til at drage til d\248ds hallerne for al evighed? "
gameforge.locale.monster_chat_1037_2 = "Du b\248r v\230nne dig til ideen om at hilse p\229 fuldst\230ndig m\248rke... "
gameforge.locale.monster_chat_1037_3 = "Velkommen til helvede. "
gameforge.locale.monster_chat_1037_4 = "Skrig s\229 meget som du vil! Ingen vil kunne h\248re dig! "
gameforge.locale.monster_chat_1037_5 = "Hvis du tror du kan dr\230be mig s\229dan her... S\229 er du mere naiv end jeg troede! "
gameforge.locale.monster_chat_1037_6 = "Ikke d\229rligt, men det vil stadig ikke v\230re nok til at rede dig fra d\248den. "
gameforge.locale.monster_chat_1038_1 = "Dette er helvede. "
gameforge.locale.monster_chat_1038_2 = "Jeg vil pille skindet af dine knogler. "
gameforge.locale.monster_chat_1038_3 = "Jeg vil h\248re dig klynke inden du d\248r. "
gameforge.locale.monster_chat_1038_4 = "Du ved det ikke nytter at hoppe, ikke? "
gameforge.locale.monster_chat_1038_5 = {}
gameforge.locale.monster_chat_1038_6 = "Nej, du skal ikke d\248 endnu. F\248rst vil jeg vide hvor mange sv\230rdslag din krop kan klare... "
gameforge.locale.monster_chat_1039_1 = "Indtil der kommer en ny ... "
gameforge.locale.monster_chat_1039_2 = "Tror du virkelig at du har bare den mindste chance for at undslippe? "
gameforge.locale.monster_chat_1039_3 = "Det er ikke jorden der flytter sig... Det er dine kn\230 der ryster af frygt! "
gameforge.locale.monster_chat_1039_4 = "Velkommen til stedet hvor du vil s\248ge din d\248d! "
gameforge.locale.monster_chat_1039_5 = "Jeg kan se panikken i dine \248jne. "
gameforge.locale.monster_chat_1039_6 = "Oh, s\229 ung og s\229 hj\230lpel\248s... "
gameforge.locale.monster_chat_1040_1 = "Vi ser alle dine bev\230gelser. "
gameforge.locale.monster_chat_1040_2 = "I en fart? \216nsker du virkelig at d\248? "
gameforge.locale.monster_chat_1040_3 = "D\248den har allerede taget plads ved din side... "
gameforge.locale.monster_chat_1040_4 = "Kan du h\248re min klokke kime? Det er det sidste du vil komme til at h\248re! "
gameforge.locale.monster_chat_1040_5 = "Hvis det s\229r ikke snart stopper med at bl\248de, kan det blive farligt for dig. "
gameforge.locale.monster_chat_1040_6 = "Du kan k\230mpe... Eller du kan lade d\248de overrumple dig... "
gameforge.locale.monster_chat_1041_1 = "Hvorfor er du her hvis du \248nsker at leve? "
gameforge.locale.monster_chat_1041_2 = "Ah, nye kroppe at \248del\230gge! "
gameforge.locale.monster_chat_1041_3 = "Det var din beslutning at kommer her, menneske! Og nu er du n\248d til at leve med konsekvenserne... "
gameforge.locale.monster_chat_1041_4 = "Vi kan ikke d\248, vi genopst\229r. "
gameforge.locale.monster_chat_1041_5 = "Det giver ingen mening at angribe os. (griner) "
gameforge.locale.monster_chat_1041_6 = "Hvad vil besejre dig: udmattelse eller d\248den? "
gameforge.locale.monster_chat_1091_1 = "Du er kommet s\229 langt.... og nu vil jeg sende dig til d\248den. "
gameforge.locale.monster_chat_1091_2 = "Offer din sj\230l og bliv en af os! "
gameforge.locale.monster_chat_1091_3 = "Kig p\229 dig! Svag og langsom... "
gameforge.locale.monster_chat_1091_4 = "Din sj\230l og din krop er begge mine! "
gameforge.locale.monster_chat_1091_5 = "Er du allerede udmattet? Dine ben ryster allerede! "
gameforge.locale.monster_chat_1091_6 = "Hvor l\230nge holder du det her ud? "
gameforge.locale.monster_chat_1093_1 = "Hvem kunne tro, at der fantes noget v\230re end d\248den? "
gameforge.locale.monster_chat_1093_2 = "Velkommen, d\248ds hungrende. "
gameforge.locale.monster_chat_1093_3 = "Du vil betale for dine fejltrin. Med dit blod og din sj\230l. "
gameforge.locale.monster_chat_1093_4 = "Efter jeg har \248delagt din krop, vil din sj\230l blive min! "
gameforge.locale.monster_chat_1093_5 = "Hvor l\230nge tror du du kan bek\230mpe mig? "
gameforge.locale.monster_chat_1093_6 = "Du more mig. Din frygt og din hast er virkelig underholdende... "
gameforge.locale.monster_chat_11000_1 = "Lyt, de der er bekymret om deres udvikling! "
gameforge.locale.monster_chat_11000_10 = "Hvis du \248nsker at l\230re naturens og lynets magt, anbefaler jeg l\230ring om helbredelse! "
gameforge.locale.monster_chat_11000_11 = "Det specielle ved en kriger er hvordan han g\229r i kamp. Koncentrer dig om at tr\230ne din krop! "
gameforge.locale.monster_chat_11000_12 = "Suras styrke er deres magi. Forbedre din intelligens, hastighed og styrke! "
gameforge.locale.monster_chat_11000_13 = "Brug Ninja evner! Koncentrerer dig om hastighed og styrke! "
gameforge.locale.monster_chat_11000_14 = "Shamaner benytter sig af regenererings, support og kamp Magi. Intelligens er vitalt! "
gameforge.locale.monster_chat_11000_15 = "Glem ikke din uddannelse! "
gameforge.locale.monster_chat_11000_16 = "Start en uddannelse n\229r du \248nsker at forbedre dine f\230rdigheder! "
gameforge.locale.monster_chat_11000_17 = "F\230rdigheder? Du kan n\229 op til mester level, hvilket opst\229r tilf\230ldigt imellem level 17 og 21! "
gameforge.locale.monster_chat_11000_18 = "\216nsker du at blive stormester? S\229 har du brug for en special f\230rdighedsbog! "
gameforge.locale.monster_chat_11000_19 = "S\229 snart du er f\230rdig med at l\230se en f\230rdighedsbog, forsvinder den! "
gameforge.locale.monster_chat_11000_2 = "Alle krigere op til level 5 lytter til mig! "
gameforge.locale.monster_chat_11000_20 = "\216nsker du at l\230se f\230rdighedsh\229ndbogen igen? S\229 vent en dag. "
gameforge.locale.monster_chat_11000_21 = "Opgrader din intelligens for at forbedre dine Sura egenskaber! "
gameforge.locale.monster_chat_11000_22 = "Oplev Suras store magt i kamp! "
gameforge.locale.monster_chat_11000_23 = "Ved du, hvor templet af den esoteriske sekt ligger? Det er midt i Seungryong dalen! "
gameforge.locale.monster_chat_11000_24 = "Edderkoppe-grotterne er tilbage. Du kan finde dem i Yongbi-\248rkenen! "
gameforge.locale.monster_chat_11000_25 = "Afslut missioner og brug bel\248nningen til opgradering! "
gameforge.locale.monster_chat_11000_26 = "Fiske? Det lyder dejligt! Du har allerede en fiskestang og agn fra fiskeren, eller? "
gameforge.locale.monster_chat_11000_27 = "\216nsker du at finde noget sv\230rer at jage? S\248g et portal! G\229 til en egn der svarer til din level! "
gameforge.locale.monster_chat_11000_28 = "Pas p\229 fjender fra andre Riger. Man ved aldrig... "
gameforge.locale.monster_chat_11000_29 = "Du \248nsker at fornye denne f\230rdighed? S\229 g\229 til den gamle dame! Men husk at have nok Yang med. "
gameforge.locale.monster_chat_11000_3 = "Se klinge kriger l\230ren hvis du \248nsker at blive kendt som en stor offensiv kriger! "
gameforge.locale.monster_chat_11000_30 = "Pr\248v at opn\229 den perfekte mester-level. S\229 er du den st\248rste! "
gameforge.locale.monster_chat_11000_31 = "Hvis du \248nsker at bes\248ge en anden by eller kampegn, s\229 s\248g efter gamle mennesker! "
gameforge.locale.monster_chat_11000_4 = "Hvis du \248nsker at blive dygtig til f\230rdighederne som kriger, g\229 og l\230r dem af mesteren i krigskunst. "
gameforge.locale.monster_chat_11000_5 = "Hvis du \248nsker at blive en Sura som er i stand til at bruge magiske sv\230rd, v\230lg v\229ben tr\230ning! "
gameforge.locale.monster_chat_11000_6 = "Tilmeld dig hos den sorte-magi-l\230re, hvis du \248nsker at blive mester i sort magi! "
gameforge.locale.monster_chat_11000_7 = "Bueskydnings tr\230ning er reserveret til ninjaer som er n\229et level 5! "
gameforge.locale.monster_chat_11000_8 = "V\230lg klinkekamps tr\230ning hvis du \248nsker at stige i de hemmelige ninja rang! "
gameforge.locale.monster_chat_11000_9 = "Hvis du som kriger \248nsker at beherske dragegudens slag, s\229 v\230lg dragemagt-l\230ren! "
gameforge.locale.monster_chat_11002_1 = "Lyt, de der er bekymret for deres sundhed. "
gameforge.locale.monster_chat_11002_10 = "Hvis du vil kontrollere magten af naturen og lynet, s\229 skriv dig op til helbredelses magts tr\230ning! "
gameforge.locale.monster_chat_11002_11 = "Det specielle ved en kriger, er hvordan han g\229r i kamp. Koncentrer dig p\229 at tr\230ne din krop! "
gameforge.locale.monster_chat_11002_12 = "Suras styrke er deres magi. Forbedre din intelligens, hastighed og styrke! "
gameforge.locale.monster_chat_11002_13 = "F\229 dine normale ninja egenskaber op p\229 et h\248jere niveau! Fokuser p\229 din hastighed og din fysiske styrke! "
gameforge.locale.monster_chat_11002_14 = "Shamaner bruger regenerering, support og kamp magi under kamp. Intelligens er vitalt for dem! "
gameforge.locale.monster_chat_11002_15 = "Glem ikke din uddannelse! "
gameforge.locale.monster_chat_11002_16 = "G\229 i l\230re, hvis du \248nsker at tr\230ne dine f\230rdigheder! "
gameforge.locale.monster_chat_11002_17 = "F\230rdigheder? Du kan n\229 op til mester level, hvilket opst\229r tilf\230ldigt imellem level 17 og 21! "
gameforge.locale.monster_chat_11002_18 = "\216nsker du at blive stormester? S\229 har du brug for en special f\230rdighedsbog! "
gameforge.locale.monster_chat_11002_19 = "S\229 snart du er f\230rdig med at l\230se en f\230rdighedsbog, forsvinder den! "
gameforge.locale.monster_chat_11002_2 = "Alle krigere op til level 5 lytter til mig! "
gameforge.locale.monster_chat_11002_20 = "\216nsker du at l\230se f\230rdighedsh\229ndbogen igen? S\229 vent en dag. "
gameforge.locale.monster_chat_11002_21 = "Opgrader din intelligens for at forbedre dine Sura egenskaber! "
gameforge.locale.monster_chat_11002_22 = "Oplev Suras store magt i kamp! "
gameforge.locale.monster_chat_11002_23 = "Ved du, hvor templet af den esoteriske sekt ligger? Det er midt i Seungryong dalen! "
gameforge.locale.monster_chat_11002_24 = "Edderkoppe-grotterne er tilbage. Du kan finde dem i Yongbi-\248rkenen! "
gameforge.locale.monster_chat_11002_25 = "Afslut missioner og brug bel\248nningen til opgradering! "
