gameforge.locale.monster_chat_11002_27 = "\216nsker du at finde noget sv\230rer at jage? S\248g et portal! G\229 til en egn der svarer til din level! "
gameforge.locale.monster_chat_11002_28 = "Pas p\229 fjender fra andre Riger. Man ved aldrig... "
