gameforge.locale.monster_chat_11002_5 = "Hvis du \248nsker at blive en Sura som er i stand til at bruge magiske sv\230rd, v\230lg v\229ben tr\230ning! "
gameforge.locale.monster_chat_11002_6 = "Tilmeld dig hos den sorte-magi-l\230re, hvis du \248nsker at blive mester i sort magi! "
gameforge.locale.monster_chat_11002_7 = "Bueskydnings tr\230ning er reserveret til ninjaer som er n\229et level 5! "
gameforge.locale.monster_chat_11002_8 = "V\230lg klinkekamps tr\230ning hvis du \248nsker at stige i de hemmelige ninja rang! "
