gameforge.locale.monster_chat_11004_1 = "Lyt, de der er bekymret for deres sundhed. "
gameforge.locale.monster_chat_11004_10 = "Hvis du \248nsker at l\230re naturens magt og specielt lyn, anbefaler jeg l\230ren om helbredelse! "
gameforge.locale.monster_chat_11004_11 = "Det specielle ved en kriger er hvordan han g\229r i kamp. Koncentrer dig om at tr\230ne din krop! "
gameforge.locale.monster_chat_11004_12 = "Suras styrke er deres magi. Forbedre din intelligens, hastighed og styrke! "
gameforge.locale.monster_chat_11004_13 = "Brug dine ninja egenskaber og forbedre din krigeriske kamp egenskaber! Koncentrer dig om din hurtighed og din fysiske styrke! "
gameforge.locale.monster_chat_11004_14 = "Shamaner bruger regenerering, support og kamp magi under kamp. Intelligens er vitalt for dem! "
gameforge.locale.monster_chat_11004_15 = "Glem ikke din uddannelse! "
gameforge.locale.monster_chat_11004_16 = "G\229 i l\230re, hvis du \248nsker at tr\230ne dine f\230rdigheder! "
gameforge.locale.monster_chat_11004_17 = "F\230rdigheder? Du kan n\229 op til mester level, hvilket opst\229r tilf\230ldigt imellem level 17 og 21! "
gameforge.locale.monster_chat_11004_18 = "\216nsker du at blive stormester? S\229 har du brug for en special f\230rdighedsbog! "
gameforge.locale.monster_chat_11004_19 = "S\229 snart du er f\230rdig med at l\230se en f\230rdighedsbog, forsvinder den! "
gameforge.locale.monster_chat_11004_2 = "Alle krigere op til level 5 lytter til mig! "
gameforge.locale.monster_chat_11004_20 = "\216nsker du at l\230se endnu en f\230rdigheds bog? Du er n\248d til at vente endnu en dag. "
gameforge.locale.monster_chat_11004_21 = "Opgrader din intelligens for at forbedre dine Sura egenskaber! "
gameforge.locale.monster_chat_11004_22 = "Oplev Suras store magt i kamp! "
gameforge.locale.monster_chat_11004_23 = "Ved du, hvor templet af den esoteriske sekt ligger? Det er midt i Seungryong dalen! "
gameforge.locale.monster_chat_11004_24 = "Edderkoppe-grotterne er tilbage. Du kan finde dem i Yongbi-\248rkenen! "
gameforge.locale.monster_chat_11004_25 = "Afslut missioner og brug bel\248nningen til opgradering! "
gameforge.locale.monster_chat_11004_26 = "Fiske? Det lyder dejligt! Du har allerede en fiskestang og agn fra fiskeren, eller? "
gameforge.locale.monster_chat_11004_27 = "\216nsker du at finde noget sv\230rer at jage? S\248g et portal! G\229 til en egn der svarer til din level! "
gameforge.locale.monster_chat_11004_28 = "Pas p\229 fjender fra andre Riger. Man ved aldrig... "
gameforge.locale.monster_chat_11004_29 = "Du \248nsker at fornye denne f\230rdighed? S\229 g\229 til den gamle dame! Men husk at have nok Yang med. "
gameforge.locale.monster_chat_11004_3 = "Se klinge kriger l\230ren hvis du \248nsker at blive kendt som en stor offensiv kriger! "
gameforge.locale.monster_chat_11004_30 = "Pr\248v at opn\229 den perfekte mester-level. S\229 er du den st\248rste! "
gameforge.locale.monster_chat_11004_31 = "Hvis du \248nsker at bes\248ge en anden by eller kampegn, s\229 s\248g efter gamle mennesker! "
gameforge.locale.monster_chat_11004_4 = "Hvis du \248nsker at blive dygtig til f\230rdighederne som kriger, g\229 og l\230r dem af mesteren i krigskunst. "
gameforge.locale.monster_chat_11004_5 = "Hvis du \248nsker at blive en Sura som er i stand til at bruge magiske sv\230rd, v\230lg v\229ben tr\230ning! "
gameforge.locale.monster_chat_11004_6 = "Tilmeld dig hos den sorte-magi-l\230re, hvis du \248nsker at blive mester i sort magi! "
gameforge.locale.monster_chat_11004_7 = "Bueskydnings tr\230ning er reserveret til ninjaer som er n\229et level 5! "
gameforge.locale.monster_chat_11004_8 = "V\230lg klinkekamp tr\230ning, hvis du \248nsker at bestige Ninjaens hemmelige rang! "
gameforge.locale.monster_chat_11004_9 = "Hvis du \248nsker at kontrollere kampen som kriger af Drageguden, v\230lg Dragemagt tr\230ning! "
gameforge.locale.monster_chat_1105_1 = "Den frosne tilstand er godt for dig. "
gameforge.locale.monster_chat_1105_2 = "Bjerget Sohan er med sikkerhed det bedste. "
gameforge.locale.monster_chat_1105_3 = "Se det gode vejr. "
gameforge.locale.monster_chat_1105_4 = "Jeg g\248r dig til mit spejlbillede. "
gameforge.locale.monster_chat_1105_5 = "Du kan leve evigt, eller i det mindste indtil isen smelter. "
gameforge.locale.monster_chat_1105_6 = "Hvordan tror du det vil f\248les, n\229r du stille bliver til stykker af is? "
gameforge.locale.monster_chat_1106_1 = "Mennesker...her?! "
gameforge.locale.monster_chat_1106_2 = "S\248vnig...Men v\229gen nok til dig... "
gameforge.locale.monster_chat_1106_3 = "Nogen her, p\229 mit bjerg?  "
gameforge.locale.monster_chat_1106_4 = "Du h\248re ikke til her! "
gameforge.locale.monster_chat_1106_5 = "Du g\248r klogt i at tr\230kke dig tilbage! "
gameforge.locale.monster_chat_1106_6 = "M\230rkeligt... S\229 ensom? "
gameforge.locale.monster_chat_1191_1 = "Det er l\230nge siden der har v\230ret en erfaren kriger her omkring. "
gameforge.locale.monster_chat_1191_2 = "Ikke andet at g\248re end at vente og polere v\229ben... "
gameforge.locale.monster_chat_1191_3 = "Skal jeg arbejde p\229 dem? "
gameforge.locale.monster_chat_1191_4 = {}
gameforge.locale.monster_chat_1191_5 = "Noget mangler. Jeg er ikke tilfreds. "
gameforge.locale.monster_chat_1191_6 = "Jeg vil g\248re en hurtig ende p\229 din smerte -det er den sidste smerte du kommer til at f\248le! "
gameforge.locale.monster_chat_1301_1 = "En langnakke "
gameforge.locale.monster_chat_1301_2 = "Din blege hud vil blive endnu blegere om et \248jeblik. "
gameforge.locale.monster_chat_1301_3 = "Du vil udfordre mig? FINT! "
gameforge.locale.monster_chat_1301_4 = "Du angreb mig! Pweck! Du kan ikke overleve! "
gameforge.locale.monster_chat_1301_5 = "Svage, svage menneske! "
gameforge.locale.monster_chat_1301_6 = "Lad os se hvor meget du kan tage! "
gameforge.locale.monster_chat_1302_1 = "Slap v\230k? T\230nk ikke engang p\229 det. "
gameforge.locale.monster_chat_1302_2 = "Ja. Kom n\230rmere. Pwiehk! "
gameforge.locale.monster_chat_1302_3 = "Sv\230rdet i din h\229nd ryster. Pwiehk!! "
gameforge.locale.monster_chat_1302_4 = "Du vil ikke overleve dette m\248de! "
gameforge.locale.monster_chat_1302_5 = "Her kommer mit sv\230rd! "
gameforge.locale.monster_chat_1302_6 = "Det g\248r ondt, ikke sandt? "
gameforge.locale.monster_chat_1303_1 = "Selv det gras du tr\230der p\229 kan ubevidst dr\230be. "
gameforge.locale.monster_chat_1303_2 = "V\230r forsigtigt med grasset. "
gameforge.locale.monster_chat_1303_3 = "Ja. Kom til mig. "
gameforge.locale.monster_chat_1303_4 = "Du v\229ger at komme t\230t p\229 mig? Well... S\229 m\229 du leve med konsekvenserne! "
gameforge.locale.monster_chat_1303_5 = "D\248! D\248! "
gameforge.locale.monster_chat_1303_6 = "Fortryder du, at du kom? "
gameforge.locale.monster_chat_1305_1 = "Hvem betvinger mig? "
gameforge.locale.monster_chat_1305_2 = "Du? \216nsker du at k\230mpe? "
gameforge.locale.monster_chat_1305_3 = "Kom hvis du t\248r! "
gameforge.locale.monster_chat_1305_4 = "Du t\230nker ikke p\229 at l\248be v\230k, vel? "
gameforge.locale.monster_chat_1305_5 = "Du har undervurderet r\230kkehviden af mit sv\230rd. "
gameforge.locale.monster_chat_1305_6 = "Bange? "
gameforge.locale.monster_chat_1901_1 = "Jeg tro du vil d\248 af mine h\230nder i dag. "
gameforge.locale.monster_chat_1901_2 = "Oh, jeg kan lide dig. "
gameforge.locale.monster_chat_1901_3 = "Hvordan g\229r det? Min k\230re afveksling. "
gameforge.locale.monster_chat_1901_4 = "Hey! Det vil ikke hj\230lpe at rande v\230k din kujon. "
gameforge.locale.monster_chat_1901_5 = "Har blikket af mig allerede f\229et det til at ryste ned af din rygrad? "
gameforge.locale.monster_chat_1901_6 = "\216nsker du ikke at skrige lidt? "
gameforge.locale.monster_chat_20001_1 = "Du ser ud til at v\230re nerv\248s... Bare rolig, ingenting vil eksplodere. "
gameforge.locale.monster_chat_20001_2 = "Af og til \248nsker jeg at g\229 lidt til fods. "
gameforge.locale.monster_chat_20001_3 = "Det er s\229 kedeligt. Selv mit barnebarn bes\248ger mig ikke l\230ngere. "
gameforge.locale.monster_chat_20001_4 = "N\229r man bliver gammel, har man brug for selvskab. "
gameforge.locale.monster_chat_20001_5 = "Mine bedste dage er forbi. "
gameforge.locale.monster_chat_20002_1 = "Solen er varm. "
gameforge.locale.monster_chat_20002_2 = "Dejligt vejr til at t\248rre en v\229d klud, ikke sandt? "
gameforge.locale.monster_chat_20002_3 = "Hvor er min dovne k\230reste? "
gameforge.locale.monster_chat_20002_4 = "Kalder sig for far, og har ikke engang d\229rlig samvittighed overfor b\248rnene! "
gameforge.locale.monster_chat_20002_5 = "B\248ger er b\248ger. Hverken arbejder han eller tjener han penge. Han l\230ser bare! "
gameforge.locale.monster_chat_20003_1 = "Oh, dudududu, baby. Har du sovet godt? "
gameforge.locale.monster_chat_20003_2 = "Du smiler som en engel. "
gameforge.locale.monster_chat_20003_3 = "Din mor er glad for, at du er sund og rask. "
gameforge.locale.monster_chat_20003_4 = "Har du igen brug for opm\230rksomhed? Er du sulten? "
gameforge.locale.monster_chat_20003_5 = "S\248de barn; vores barn. Sov lille barn, sov... "
gameforge.locale.monster_chat_20004_1 = "Igen en ny dag. "
gameforge.locale.monster_chat_20004_2 = "Hvor f\229r jeg i dag noget at spise? "
gameforge.locale.monster_chat_20004_3 = "Det er altid det samme med disse sv\230rd b\230re. "
gameforge.locale.monster_chat_20004_4 = "Lad mig se. M\229ske skulle jeg g\229 til Octavios restaurant. "
gameforge.locale.monster_chat_20004_5 = "N\229 ja.. Folk siger, der ikke er krig l\230ngere... "
gameforge.locale.monster_chat_20005_1 = "Sj\230len af en pottemester l\248ber igennem hans fingerspidser. "
gameforge.locale.monster_chat_20005_2 = "Siden landet er blevet s\229 kaotisk, findes overalt krigere. "
gameforge.locale.monster_chat_20005_3 = "Alle \248nsker hele tiden at k\230mpe. "
gameforge.locale.monster_chat_20005_4 = "Jeg beder om ro og fred p\229 jorden. "
gameforge.locale.monster_chat_20005_5 = "Hey - du der! Giv dig selv et kort \248jeblik til at falde til ro. "
gameforge.locale.monster_chat_20006_1 = "Ahhh, hvad g\248r jeg nu? "
gameforge.locale.monster_chat_20006_2 = "Jeg fandt ingen spor af min bror, men han lovede da at komme tilbage. "
gameforge.locale.monster_chat_20006_3 = "Og nu ser jeg bare de der krigere med deres sv\230rd. "
gameforge.locale.monster_chat_20006_4 = "Jeg savner min bror. "
gameforge.locale.monster_chat_20006_5 = "Er der nogen, der har set min bror? "
gameforge.locale.monster_chat_20007_1 = "Mmmmmh, dette k\248d er frisk! "
gameforge.locale.monster_chat_20007_2 = "Godt, at folk spiser mere k\248d igen. "
gameforge.locale.monster_chat_20007_3 = "Der er godt gang i min butik, bare k\248d er sv\230rt at f\229 fat i. "
gameforge.locale.monster_chat_20007_4 = "Hvorn\229r kommer det k\248d vi har bestilt? "
gameforge.locale.monster_chat_20007_5 = "Hvis det ikke snart kommer, bliver vi n\248d til at jage! "
gameforge.locale.monster_chat_20008_1 = "Jeg h\229ber at der med dette vejr kommer ekstra mange kunder. "
gameforge.locale.monster_chat_20008_2 = "Oh! Den dovne hund kommer sikkert snart og \248nsker at spise noget. "
gameforge.locale.monster_chat_20008_3 = "N\229, sikke et fattigt kreatur! "
gameforge.locale.monster_chat_20008_4 = "F\248r i tiden var han en meget god kriger. "
gameforge.locale.monster_chat_20008_5 = "Jeg undrer mig over, hvorfor han ikke g\229r i krig l\230ngere? "
gameforge.locale.monster_chat_20009_1 = "De unge folk... S\229 livlige og fulde af energi! "
gameforge.locale.monster_chat_20009_2 = "Krigerne ser meget bedre ud, n\229r de b\230rer v\229ben. "
gameforge.locale.monster_chat_20009_3 = "Den dr\230bende \229nd tager fat i enhver. "
gameforge.locale.monster_chat_20009_4 = "Styr dit hjerte, samle dine tanker, og berolig din sj\230l. "
gameforge.locale.monster_chat_20009_5 = "Er er ingen ufejlbarlig opskrift p\229 lykke, men nogle enkelte guidelines du kan holde dig til. "
gameforge.locale.monster_chat_20010_1 = "Jeg har medbragt en god genstand! "
gameforge.locale.monster_chat_20010_2 = "Vare fra fjerne lande! Smukt, ekstraordin\230re priser! "
gameforge.locale.monster_chat_20010_3 = "Kom - kom allesammen! "
gameforge.locale.monster_chat_20010_4 = "K\248b, k\248b, k\248b - s\229l\230nge der er noget. Det f\229es ikke overalt, og slet ikke hver dag! "
gameforge.locale.monster_chat_20010_5 = "Der er s\229 mange tyve her omkring. De burde holde sig v\230k fra mine vare! "
gameforge.locale.monster_chat_20011_1 = "Til dagligt er her meget t\248rt. "
gameforge.locale.monster_chat_20011_2 = "Kornh\248sten er ikke s\229 god som den plejre at v\230re. "
gameforge.locale.monster_chat_20011_3 = "Hvad h\230mmerr kornets opblomstring? "
gameforge.locale.monster_chat_20011_4 = "Det bliver spr\248dt og smager r\229ddent. "
gameforge.locale.monster_chat_20011_5 = "Et d\229rligt tegn. Landbruget er livets basis. "
gameforge.locale.monster_chat_20012_1 = "Riskager! Dejlige riskager! "
gameforge.locale.monster_chat_20012_2 = "Jeg s\230lger s\248de riskager! "
gameforge.locale.monster_chat_20012_3 = "Uha... Forretningen k\248rer ikke godt. "
gameforge.locale.monster_chat_20012_4 = "Jeg burde m\229ske pr\248ve i en anden by. "
gameforge.locale.monster_chat_20012_5 = "Der er s\229 mange vilde rovdyr her omkring... "
gameforge.locale.monster_chat_20013_1 = "P\229 s\229dan en dag er det bedst i en b\229d. "
gameforge.locale.monster_chat_20013_2 = "Perfekt vejr for fiskning. "
gameforge.locale.monster_chat_20013_3 = "Nu endnu et knob... Rigtigt! Ingen fisk vil bide denne krog af! "
gameforge.locale.monster_chat_20013_4 = "Denne forbandede bj\248rn har \248delagt min fiskestang. "
gameforge.locale.monster_chat_20013_5 = "Jeg burde reparere mine net igen. "
gameforge.locale.monster_chat_20014_1 = "Hu! "
gameforge.locale.monster_chat_20014_2 = "V\230r ikke bekymret om mig. S\229dan er jeg bare. "
gameforge.locale.monster_chat_20014_3 = "Haaaaa! "
gameforge.locale.monster_chat_20014_4 = "Hvad skal jeg g\248re s\229 de... Ohh, hvad sagde jeg lige? "
gameforge.locale.monster_chat_20014_5 = "Jeg kan bare ikke v\230re modig nok. Hu! "
gameforge.locale.monster_chat_20015_1 = "Denne \248kse st\229r mig til side de sidste 20 \229r. "
gameforge.locale.monster_chat_20015_2 = "Er stadig skarp, men ikke som dengang. "
gameforge.locale.monster_chat_20015_3 = "Jeg \248nsker at bruge og forbedre den. "
gameforge.locale.monster_chat_20015_4 = "Men jeg har brug for adskillige sten med malm. "
gameforge.locale.monster_chat_20015_5 = "Men hvordan f\229r jeg fat i dem?  "
gameforge.locale.monster_chat_20016_1 = "Kunderne overfalder n\230sten min butik. "
gameforge.locale.monster_chat_20016_2 = "Jeg h\229ber jeg f\230rdigg\248re alting i tide. "
gameforge.locale.monster_chat_20016_3 = "Slag p\229 slag og ingen klagen... "
gameforge.locale.monster_chat_20016_4 = "Dette er s\229dan en hammer b\248r lyde! "
gameforge.locale.monster_chat_20016_5 = "Rimelig varmt her. "
gameforge.locale.monster_chat_20017_1 = "Jeg er ikke i hum\248r til musik. "
gameforge.locale.monster_chat_20017_2 = "Mit instrument er i d\229rlig forfatning. "
gameforge.locale.monster_chat_20017_3 = "M\229ske skulle jeg f\229 et nyt instrument? "
gameforge.locale.monster_chat_20017_4 = "Mit instrument er gammelt og udslidt... Jeg elsker gamle ting! "
gameforge.locale.monster_chat_20017_5 = "Jeg er virkelig n\248d til at finde en erstatning for t\229re stingene. "
gameforge.locale.monster_chat_20018_1 = "Jeg har s\229 travlt! "
gameforge.locale.monster_chat_20018_2 = "Hver dag kommer nye s\229rede. "
gameforge.locale.monster_chat_20018_3 = "Der er ingen tid til private forn\248jelser! "
gameforge.locale.monster_chat_20018_4 = "Og vi har n\230sten ingen medicin tilovers. "
gameforge.locale.monster_chat_20018_5 = "Jeg h\229ber en eller anden kunne levere ingredienserne til noget medicin. "
gameforge.locale.monster_chat_20019_1 = "I 30 \229r marcherer jeg med min bue gennem bjergerne. "
gameforge.locale.monster_chat_20019_2 = "Derved har jeg ern\230ret min kone og har betalt uddannelsen for mine tre b\248rn. "
gameforge.locale.monster_chat_20019_3 = "Det er et h\229rdt liv, men det v\230rd. "
gameforge.locale.monster_chat_20019_4 = "Men nu er buestrengen g\229et i stykker. Betyder det, at jeg nu heller ikke bruges l\230ngere? "
gameforge.locale.monster_chat_20019_5 = "Hvis jeg ikke kan reparere denne bue, er jeg n\248d til at k\248be en ny en. Men jeg har ikke penge nok til at g\248re dette. "
gameforge.locale.monster_chat_20020_1 = "Hov! Hvad glor du p\229? "
gameforge.locale.monster_chat_20020_2 = "Hold afstand! "
gameforge.locale.monster_chat_20020_3 = "Oh.. Hvor lang tid skal jeg forts\230tte med at gemme mig p\229 den her m\229de? "
gameforge.locale.monster_chat_20020_4 = "Vil jeg d\248 i en eller anden m\248rk bagg\229rd? "
gameforge.locale.monster_chat_20020_5 = "Ahhhh, jeg h\229ber at der er nogen, der kan hj\230lpe mig! "
gameforge.locale.monster_chat_20021_1 = "Denne dag vil ende som alle andre. "
gameforge.locale.monster_chat_20021_2 = "Hvad jeg jeg g\248re? Hm? "
gameforge.locale.monster_chat_20021_3 = "Aldrig har jeg regnet med at jeg skulle d\248 p\229 den her m\229de. "
gameforge.locale.monster_chat_20021_4 = "Jeg kan stadig ikke forst\229 at han ikke er her mere. "
gameforge.locale.monster_chat_20021_5 = "Det fortjente han ikke. "
gameforge.locale.monster_chat_20022_1 = "Og igen en ny dejlig dag. "
gameforge.locale.monster_chat_20022_2 = "Ariyoung's \230gtemand er forsvundet. "
gameforge.locale.monster_chat_20022_3 = "Jeg ville hj\230lpe, men denne st\230dighed... "
gameforge.locale.monster_chat_20022_4 = "Hvis hun havde giftet sig med mig, havde hun ikke haft dette kedsomme liv. "
gameforge.locale.monster_chat_20022_5 = "M\229ske burde jeg dengang have vist mine f\248leleser mere. "
gameforge.locale.monster_chat_20023_1 = "Oh nej! Hvad skal jeg g\248re n\229r min dame har fundet ud af det? "
gameforge.locale.monster_chat_20023_2 = "Hvis jeg bare kunne leve af at l\230se b\248ger! "
gameforge.locale.monster_chat_20023_3 = "B\248ger er s\229 hemmeligsfyldt! "
gameforge.locale.monster_chat_20023_4 = "Jeg ved jeg ikke kan leve s\229dan her for altid, men... "
gameforge.locale.monster_chat_20023_5 = "Jeg h\229ber jeg kan g\248re noget for min kone, men... "
gameforge.locale.monster_chat_20024_1 = "Kom nu, l\230g nogen anstrengelser i det! "
gameforge.locale.monster_chat_20024_2 = "Hvad g\248r du? G\229r det ikke hurtigere? "
gameforge.locale.monster_chat_20024_3 = "Bare forestil dig en kriger der h\230ver sit sv\230rd og g\248r det samme! "
gameforge.locale.monster_chat_20024_4 = "Hvor er den idiot nu? "
gameforge.locale.monster_chat_20024_5 = "Du \248nsker at v\230re en mand? "
gameforge.locale.monster_chat_2091_1 = "Snit, snit... H\229r, strube... "
gameforge.locale.monster_chat_2091_2 = "Jeg har noget til dig: Evig s\248vn! "
gameforge.locale.monster_chat_2091_3 = "Tag en dyb ind\229nding. Bare rolig, det er kun gift! "
gameforge.locale.monster_chat_2091_4 = "Jeg vil kun efterlade dit ansigt! Det vil blive en dejlig dekoration... "
gameforge.locale.monster_chat_2091_5 = {}
gameforge.locale.monster_chat_2091_6 = "Viklet ind i silke vil du udg\248re en dejlig appetitv\230kker til senere... "
gameforge.locale.monster_chat_2092_1 = "Der er ikke mange af os tilbage. "
gameforge.locale.monster_chat_2092_2 = "Det er ikke de tobenede v\230sner der burde regere her. "
gameforge.locale.monster_chat_2092_3 = "Oh!? Det ser ud til at der blev fanget en i spindelv\230vet. "
gameforge.locale.monster_chat_2092_4 = "Jeg er en fredelig person. Jeg kan bare ikke lide at blive irriteret. "
gameforge.locale.monster_chat_2092_5 = "Er det alt hvad du kan pr\230stere? "
gameforge.locale.monster_chat_2092_6 = "Ingen kan m\229le sig med mig! "
gameforge.locale.monster_chat_2104_1 = "Hvorfor er mennesker s\229 v\229de inden i? Det g\248r mit sv\230rd helt rustent! "
gameforge.locale.monster_chat_2104_2 = "Er giften i din brod udt\248rret endnu? "
gameforge.locale.monster_chat_2104_3 = "Hvordan ser det nu ud med kampene? "
gameforge.locale.monster_chat_2104_4 = "Allerede udmattet af varmen?  "
gameforge.locale.monster_chat_2104_5 = "Jeg lader gerne folk forblive i \248rkenen. "
gameforge.locale.monster_chat_2104_6 = "Oh.... Begravet i \248rkenen. "
gameforge.locale.monster_chat_2105_1 = "Jeg fort\230ller dig en hemmelighed. Jeg hader m\248g. "
gameforge.locale.monster_chat_2105_2 = "Er det s\229 varmt, hva? "
gameforge.locale.monster_chat_2105_3 = "Dette omr\229de er farligt. "
gameforge.locale.monster_chat_2105_4 = {}
gameforge.locale.monster_chat_2105_5 = "Jeg rammer dig mellem dine \248jne. "
gameforge.locale.monster_chat_2106_1 = "Det virker til at der er noget her omkring som jeg skal have sl\229et ned. "
gameforge.locale.monster_chat_2106_2 = "Ahh ja, Jeg kan se mit n\230ste bytte. "
gameforge.locale.monster_chat_2106_3 = "Det kan jeg lide, det elsker jeg! "
gameforge.locale.monster_chat_2106_4 = "Den der er dejlig fed. Det er min! "
gameforge.locale.monster_chat_2106_5 = {}
gameforge.locale.monster_chat_2106_6 = "Jeg elsker duften af blod. "
gameforge.locale.monster_chat_2107_1 = "Til dagligdags er der kun f\229 ting der kan g\248res. "
gameforge.locale.monster_chat_2107_2 = "Hey! De er da temmelig tykke! "
gameforge.locale.monster_chat_2107_3 = "Vores leder vil elske det... "
gameforge.locale.monster_chat_2107_4 = {}
gameforge.locale.monster_chat_2107_5 = "Lad os tage vores danse sko p\229! "
gameforge.locale.monster_chat_2107_6 = "Denne pil er kun til dig. "
gameforge.locale.monster_chat_2108_1 = "N\229r jeg f\229r fat i en, s\229 vil jeg...  "
gameforge.locale.monster_chat_2108_2 = "Hey, hvad er der galt? "
gameforge.locale.monster_chat_2108_3 = "Tror du jeg er nem at besejre? Hm? "
gameforge.locale.monster_chat_2108_4 = "Sikke et uheld, at m\248de mig i \248rkenen! "
gameforge.locale.monster_chat_2108_5 = "Ah, denne f\248lelse! Jeg vil altid nyde den! "
gameforge.locale.monster_chat_2108_6 = "Mange tak! "
gameforge.locale.monster_chat_2191_1 = "Jeg kan lugte mennesker. Sikke en dejligt duft! "
gameforge.locale.monster_chat_2191_2 = "Godt. Kom til mig. "
gameforge.locale.monster_chat_2191_3 = {}
gameforge.locale.monster_chat_2191_4 = "Jeg er s\229 heldig med at du for vildt, og fandt vej hertil! "
gameforge.locale.monster_chat_2191_5 = "Bliv st\229ende! Kkkkkk! "
gameforge.locale.monster_chat_2191_6 = "Bid efter bid vil jeg rive det ud af dit k\248d... "
gameforge.locale.monster_chat_2202_1 = "Kom t\230ttere p\229 s\229 jeg kan br\230nde dit skind. "
gameforge.locale.monster_chat_2202_2 = "Ved du hvilken smerte s\229dan en stor m\230ngde varme kan forsage? "
gameforge.locale.monster_chat_2202_3 = "M\229ske burde jeg k\248le mine flammer ned med noget frisk blod. "
gameforge.locale.monster_chat_2202_4 = "Dit blod... Lad mig smage det. "
gameforge.locale.monster_chat_2202_5 = "Der er ingen grund til at g\248re en kamp ud af det. "
gameforge.locale.monster_chat_2202_6 = "Bliv som jeg! Kun flammer og varme. "
gameforge.locale.monster_chat_2204_1 = "S\229l\230nge jeg er her, kan ingen anden komme ind! "
gameforge.locale.monster_chat_2204_2 = "Jeg ved ikke hvorfor, men du irriterer. "
gameforge.locale.monster_chat_2204_3 = {}
gameforge.locale.monster_chat_2204_4 = "Kwuuh, ved du hvor de er? "
gameforge.locale.monster_chat_2204_5 = {}
gameforge.locale.monster_chat_2204_6 = "Du er en ret s\248rgelig modstander for mig! "
gameforge.locale.monster_chat_2205_1 = "Et sv\230rd dur kun til noget i h\229nden p\229 en kriger. "
gameforge.locale.monster_chat_2205_2 = "Husk at holde sv\230rdet i h\229nden. "
gameforge.locale.monster_chat_2205_3 = "Krigen kommer. "
gameforge.locale.monster_chat_2205_4 = "Og nu k\230mper vi til d\248den! "
gameforge.locale.monster_chat_2205_5 = "Vil du fortsat modst\229 mine angreb? "
gameforge.locale.monster_chat_2205_6 = "Ja, du burde ikke d\248 for hurtig. "
gameforge.locale.monster_chat_2206_1 = "Lava er livets eliksir. "
gameforge.locale.monster_chat_2206_2 = "Lava holder mig i live og vil blive din d\248d! "
gameforge.locale.monster_chat_2206_3 = "Det er vidunderligt, en verden af gl\248dende lava? "
gameforge.locale.monster_chat_2206_4 = "Du v\229ger at forstyrre mig? "
gameforge.locale.monster_chat_2206_5 = "Du vil g\229 hvis du har dit liv k\230rt. "
gameforge.locale.monster_chat_2206_6 = "Du vil m\229ske angre min tilstedev\230relse her. "
gameforge.locale.monster_chat_2291_1 = "Det er en dejlig dag. Alt hvad jeg \248nsker er at have noget fred og ro. "
gameforge.locale.monster_chat_2291_2 = "Intet kan sammenlignes med Doyyumhwan landet. "
gameforge.locale.monster_chat_2291_3 = "En smule frisk bold ville v\230re en dejlig forandring. "
gameforge.locale.monster_chat_2291_4 = "Du virker til at s\248ge din d\248d, ellers ville du ikke havde forstyrret mig nu.  "
gameforge.locale.monster_chat_2291_5 = "Fortryder du allerede at du dukkede op? "
gameforge.locale.monster_chat_2291_6 = "Det er for sent at flygte. M\248d din sk\230bne. "
gameforge.locale.monster_chat_301_1 = "Denne tid g\248r mig nerv\248s. "
gameforge.locale.monster_chat_301_2 = "For to dage siden blev en ung pige maltrakteret af et vildt dyr i dette omr\229de. "
gameforge.locale.monster_chat_301_3 = "De vilde dyr bliver mere og mere aggressive. Vi burde pr\248ve at dr\230be s\229 mange som muligt. "
gameforge.locale.monster_chat_301_4 = "Jeg er ikke i godt hum\248r i dag. Fremmede b\248r holde sig fra mig i dag. "
gameforge.locale.monster_chat_301_5 = "Den sidste kriger jeg dr\230bte, bad for sit liv. "
gameforge.locale.monster_chat_302_1 = "En eller anden er n\248d til at g\248re noget ved disse sten. "
gameforge.locale.monster_chat_302_2 = "Jeg stoler ikke p\229 de fredfyldte morgener. "
gameforge.locale.monster_chat_302_3 = "Sp\230ndingerne i luften g\248r mig utilpas. "
gameforge.locale.monster_chat_302_4 = "Disse pilespidser er blevet meget godt smedet. "
gameforge.locale.monster_chat_302_5 = "Hvis jeg var dig ville jeg v\230re forsigtig. Den pil sigtede direkte mod dit hovede. "
gameforge.locale.monster_chat_302_6 = "Jeg burde g\229 dertil og dr\230be en af de b\230ster. "
gameforge.locale.monster_chat_303_1 = "En god kampuddannelse er n\248dvendig i disse dage. "
gameforge.locale.monster_chat_303_2 = "Hvad sker der, hvis der pludselig kommer regeringssoldater? "
gameforge.locale.monster_chat_303_3 = "Hvorfor stirrer du s\229dan p\229 mig?  "
gameforge.locale.monster_chat_303_4 = "Kujoner har en lille chance for at overleve. "
gameforge.locale.monster_chat_303_5 = "Overvurder ikke dig selv. "
gameforge.locale.monster_chat_303_6 = "En eller anden virker til at have tr\230net dig virkelig godt. "
gameforge.locale.monster_chat_304_1 = "Selv mine forf\230dre klarede h\230vde i kamp i disse territorier. "
gameforge.locale.monster_chat_304_2 = "Du er n\248d til at v\230re p\229 vagt og dygtig her ude. "
gameforge.locale.monster_chat_304_3 = "Overvej ikke engang at spilde min tid. "
gameforge.locale.monster_chat_304_4 = "N\229, hvordan f\248les det s\229 at dit liv er i fare? "
gameforge.locale.monster_chat_304_5 = "Oh nej! Opgiver du allerede?  "
gameforge.locale.monster_chat_304_6 = "Du vil hurtig f\248le smerterne. "
gameforge.locale.monster_chat_305_1 = "Gud ske lov! Dette sv\230rd ser dejligt ud! "
gameforge.locale.monster_chat_305_2 = "\216g din stivsindighed, din magt! "
gameforge.locale.monster_chat_305_3 = "Tror du, at du kan blive s\229 st\230rk som jeg? "
gameforge.locale.monster_chat_305_4 = "Okay. Hvorfor g\248r vi det s\229 ikke f\248rst? "
gameforge.locale.monster_chat_305_5 = "Gud ske lov! Jeg er kun en svag dame! "
gameforge.locale.monster_chat_305_6 = "Du ser ud til at v\230re udmattet. Hvorfor opgiver du ikke bare? Ho, ho, ho! "
gameforge.locale.monster_chat_306_1 = "Hvad vil Serangyi mon lave idag? "
gameforge.locale.monster_chat_306_2 = "Jeg keder mig. Leg med mig "
gameforge.locale.monster_chat_306_3 = "Jeg selv fortr\230kker Sura-typen. "
gameforge.locale.monster_chat_306_4 = "He! Er du med p\229 en kamp? "
gameforge.locale.monster_chat_306_5 = "Undervurder mig ikke, bare fordi jeg er en dame! "
gameforge.locale.monster_chat_306_6 = "Smerte varer kun et \248jeblik. "
gameforge.locale.monster_chat_307_1 = "For at i verden, vil jeg bare ud her fra. "
gameforge.locale.monster_chat_307_2 = "Hvor sikkert er hjemmene af de enkelte medlemmer? god? "
gameforge.locale.monster_chat_307_3 = "Piger alts\229, hold k\230ft! "
gameforge.locale.monster_chat_307_4 = "Lad mig dr\230be dig med et slag. "
gameforge.locale.monster_chat_307_5 = "Tro ikke, du kan flygte. "
gameforge.locale.monster_chat_307_6 = "S\229 hvorfor begynder vi ikke? "
gameforge.locale.monster_chat_394_1 = "Glem aldrig: Alle m\230nd er fjender. "
gameforge.locale.monster_chat_394_2 = "N\229r en person har et smukt ansigt, kan vi jo v\230re lidt mildere. "
gameforge.locale.monster_chat_394_3 = "Hvad? \216nsker du at k\230mpe? "
gameforge.locale.monster_chat_394_4 = "Det tager ikke lang tid, men det vil kraftedme g\248re ondt. "
gameforge.locale.monster_chat_394_5 = "N\229\229, du ser ud til at have alvorlige smerter. "
gameforge.locale.monster_chat_394_6 = "Ses i helvede! "
gameforge.locale.monster_chat_401_1 = "Hvad laver du i den hvide h\230r? "
gameforge.locale.monster_chat_401_2 = "Hvor g\229r det hen? "
gameforge.locale.monster_chat_401_3 = "Hov! Vil du k\230mpe? "
gameforge.locale.monster_chat_401_4 = "h\230, h\230, h\230! Du undviger mine angreb. "
gameforge.locale.monster_chat_401_5 = "Tror du, at du kan flygte? "
gameforge.locale.monster_chat_401_6 = "Her kommer mit st\248d! "
gameforge.locale.monster_chat_402_1 = "Godt, jeg er s\229 s\248vnig! "
gameforge.locale.monster_chat_402_2 = "He! Flot rustning. Hvormeget har du betalt for den?  "
gameforge.locale.monster_chat_402_3 = "Men vi har smukt vejr. "
gameforge.locale.monster_chat_402_4 = "Oh! Du ser ud til at have \248vet meget. Dejligt! "
gameforge.locale.monster_chat_402_5 = "Hvad synes du om mine f\230rdigheder? Gode, eller? Ha, ha, ha! "
gameforge.locale.monster_chat_402_6 = "Hvad er der i vejen? Naturligvis! Det er denne forbandede hastighed! "
gameforge.locale.monster_chat_403_1 = "Hvorfor g\229r jeg ikke ud og jager. "
gameforge.locale.monster_chat_403_2 = "Idag er ingen som angriber vores landsby. "
gameforge.locale.monster_chat_403_3 = "Hvis du vil k\230mpe, s\229 k\230mp! Bastard! "
gameforge.locale.monster_chat_403_4 = "Ha, ha, ha! Du er jo kun en amat\248r! "
gameforge.locale.monster_chat_403_5 = "Skal jeg f\248rst ramme dig i armen eller benet? "
gameforge.locale.monster_chat_403_6 = "Her kommer min pil! "
gameforge.locale.monster_chat_404_1 = "Jeg skal nok \248ve lidt i landsbyen. "
gameforge.locale.monster_chat_404_2 = "Jeg f\248ler mig stiv. "
gameforge.locale.monster_chat_404_3 = "Hvad serveres der i dag af mad? "
gameforge.locale.monster_chat_404_4 = "Jeg kigger p\229 dig, s\229 skrig, s\229 meget du \248nsker. "
gameforge.locale.monster_chat_404_5 = "Ventet for lang tid, hva? Sving f\248rst sv\230rdet! "
gameforge.locale.monster_chat_404_6 = "Sv\230rdets klang er s\229 sp\230ndende!  "
gameforge.locale.monster_chat_405_1 = "Dette sv\230rd er klar til at benyttes! "
gameforge.locale.monster_chat_405_2 = "Hmm, lad os se: Hvem dr\230ber dette sv\230rd f\248rst... "
gameforge.locale.monster_chat_405_3 = "He! Hvem glor du p\229? "
gameforge.locale.monster_chat_405_4 = "F\248rst din mave! "
gameforge.locale.monster_chat_405_5 = "Er en sv\230rdskede til en sv\230rdk\230mper ikke standard? "
gameforge.locale.monster_chat_405_6 = "Jeg kunne t\230nke mig at bruge dig som sv\230rdskede. "
gameforge.locale.monster_chat_406_1 = "Jeg er ved at d\248 af sult! "
gameforge.locale.monster_chat_406_2 = "Er der noget at spise? "
gameforge.locale.monster_chat_406_3 = "Hvorfor er jeg stadig sulten efter al den mad? "
gameforge.locale.monster_chat_406_4 = "Waaah, d\248! "
gameforge.locale.monster_chat_406_5 = "Min mave vil afg\248re denne kamp! "
gameforge.locale.monster_chat_406_6 = "Det er valget mellem himmel og helvede! "
gameforge.locale.monster_chat_491_1 = "Jeg kan ikke holde mig tilbage l\230ngere! Min krop vibrerer. "
gameforge.locale.monster_chat_491_2 = "Uha. Jeg kan se nogle svin derover. "
gameforge.locale.monster_chat_491_3 = "P\229 jorden? "
gameforge.locale.monster_chat_491_4 = "Jeg dr\230ber dig med et slag. "
gameforge.locale.monster_chat_491_5 = "Det kommer til at blive et godt minde! "
gameforge.locale.monster_chat_491_6 = "D\248! "
gameforge.locale.monster_chat_492_1 = "Min krop er feminin. "
gameforge.locale.monster_chat_492_2 = "Hvorfor tr\230ner jeg ikke bare mere? "
gameforge.locale.monster_chat_492_3 = "Bange? Hm? "
gameforge.locale.monster_chat_492_4 = "Ah, bare et nyt offer for mit hvirvlende v\229ben. "
gameforge.locale.monster_chat_492_5 = "Kan du se mit angrebsm\248nster? Nej? Du tabte! "
gameforge.locale.monster_chat_492_6 = "Selv et lille snit skader sundheden, var du klar over det? "
gameforge.locale.monster_chat_493_1 = "Damn, disse h\230nder er virkelig upraktiske. "
gameforge.locale.monster_chat_493_2 = "Hvad glor du s\229dan p\229? Har du aldrig set nogen med en s\229dan h\229nd? "
gameforge.locale.monster_chat_493_3 = "I irriterer mig virkeligt. "
gameforge.locale.monster_chat_493_4 = "Skal jeg sl\229 dig? Hvis ikke, s\229 l\248b. Ja? "
gameforge.locale.monster_chat_493_5 = "Nu demonstrerer jeg mit store st\248d! "
gameforge.locale.monster_chat_493_6 = "Jeg ved, at du stirrer p\229 min h\229nd! "
gameforge.locale.monster_chat_494_1 = "Hov, du der! Hvis du vil k\230mpe mod mig, s\229 kom! "
gameforge.locale.monster_chat_494_2 = "Jeg kalder mig selv for temmelig pirrende. "
gameforge.locale.monster_chat_494_3 = "Hvorfor planl\230gger vi ikke noget? "
gameforge.locale.monster_chat_494_4 = "Nej, at flygte er ikke tilladt. K\230mp! "
gameforge.locale.monster_chat_494_5 = "Godt, tag den! "
gameforge.locale.monster_chat_494_6 = "Du er n\230sten d\248d. "
gameforge.locale.monster_chat_501_1 = "Leg med mig! Bliv her! "
gameforge.locale.monster_chat_501_2 = "Jeg kunne sk\230re noget dejligt ud af dine ben... "
gameforge.locale.monster_chat_501_3 = "Vi har ikke \248vet endnu. "
gameforge.locale.monster_chat_501_4 = "Oh, sikke en smuk rustning! Den vil jeg have. "
gameforge.locale.monster_chat_501_5 = "Fra nu af, vil det v\230re sv\230rt for dig, at ignorere mine angreb. "
gameforge.locale.monster_chat_501_6 = "Ha, ha, ha! Overrasket, hva? "
gameforge.locale.monster_chat_502_1 = "Sk\248nhed er ikke alt. "
gameforge.locale.monster_chat_502_2 = "Ikke glo, k\230mp! "
gameforge.locale.monster_chat_502_3 = "Jeg syntes ikke om m\229den du beglor mig p\229. Kom her! "
gameforge.locale.monster_chat_502_4 = "Det er en \230re, at d\248 gennem mit sv\230rd! "
gameforge.locale.monster_chat_502_5 = {}
gameforge.locale.monster_chat_502_6 = "Fantastisk! "
gameforge.locale.monster_chat_503_1 = "Hey, du der! Fingerne v\230k! "
gameforge.locale.monster_chat_503_2 = "Ser ud til, at min buestreng er g\229et i stykker! "
gameforge.locale.monster_chat_503_3 = "Lort. Idioterne er ankommet. "
gameforge.locale.monster_chat_503_4 = "Ikke d\229rligt. Men du vil alligevel d\248! "
gameforge.locale.monster_chat_503_5 = "Du er indforst\229et? Det er da dejligt! "
gameforge.locale.monster_chat_503_6 = "Her kommer min pil! "
gameforge.locale.monster_chat_504_1 = "Kom alle sammen! "
gameforge.locale.monster_chat_504_2 = "La, lala, jeg fl\248jter en sang... "
gameforge.locale.monster_chat_504_3 = "Se det sk\248nne vejr. "
gameforge.locale.monster_chat_504_4 = {}
gameforge.locale.monster_chat_504_5 = "Godt! Jeg s\230tter pris p\229 din vilje til at k\230mpe! "
gameforge.locale.monster_chat_504_6 = "Kom her! Allesammen til mig! "
gameforge.locale.monster_chat_601_1 = "Jeg sulter ihjel! "
gameforge.locale.monster_chat_601_2 = "Jeg \248nsker at spise frugter. "
gameforge.locale.monster_chat_601_3 = "Ja, fisk er ogs\229 i okay. Angrib! "
gameforge.locale.monster_chat_601_4 = "L\248b ikke v\230k! Bliv st\229ende! "
gameforge.locale.monster_chat_601_5 = "Jeg har vundet! Det ses jo klart! "
gameforge.locale.monster_chat_601_6 = "Ser du? Du har fors\248mt det hele! "
gameforge.locale.monster_chat_601_7 = "Du b\248r v\230re omhyggelig, haha! "
gameforge.locale.monster_chat_602_1 = "Hvor er jeg? "
gameforge.locale.monster_chat_602_2 = "Dejligt vejr.  "
gameforge.locale.monster_chat_602_3 = "Du er kommet for at jage mig? Latterligt! "
gameforge.locale.monster_chat_602_4 = "Du er mit bytte.  "
gameforge.locale.monster_chat_602_5 = "Hvilken tortur, hm? Godt.. Lad os g\248re det hurtigt! "
gameforge.locale.monster_chat_602_6 = "Se hvor st\230rk jeg er: Jeg kan svinge denne k\230mpe k\248lle! "
gameforge.locale.monster_chat_603_1 = "Kedeligt! "
gameforge.locale.monster_chat_603_2 = "Hele min krop kribler. "
gameforge.locale.monster_chat_603_3 = "Den som kommer f\248rst. "
gameforge.locale.monster_chat_603_4 = "Du har ramt mig f\248rst? Nu jager jeg dig. "
gameforge.locale.monster_chat_603_5 = "Er man f\248rst inde, er der ingen vej ud. Nu er flugten nyttel\248s! "
gameforge.locale.monster_chat_603_6 = "Dette bliver det sidste slag. Jeg smadrer dig! "
gameforge.locale.monster_chat_604_1 = "Jeg har lavet en l\230kker ny gift. Vil du smage? "
gameforge.locale.monster_chat_604_2 = "Jeg vil se hvordan den virker! Her, smag den! "
gameforge.locale.monster_chat_604_3 = "Hey du der! Kom her, vil du v\230re min testperson? "
gameforge.locale.monster_chat_604_4 = "Jeg forgifter dig!  "
gameforge.locale.monster_chat_604_5 = "Oh godt! En Fors\248gskanin! "
gameforge.locale.monster_chat_604_6 = "Dette er ikke sjovt hvis du giver s\229 hurtigt op! Kom nu, forsvar dig selv! "
gameforge.locale.monster_chat_631_1 = "Vent et \248jeblik. Jeg leder efter noget at jage. "
gameforge.locale.monster_chat_631_2 = "Det er ikke til nogen nytte hvis du bev\230ger dig s\229 langsomt. Bev\230g dig! "
gameforge.locale.monster_chat_631_3 = "Jeg er s\229 sulten! "
gameforge.locale.monster_chat_631_4 = "Det er fedt at jeg har fundet noget at jage! "
gameforge.locale.monster_chat_631_5 = "Lad alt h\229b forsvinde! Du vil ikke overleve mig! "
gameforge.locale.monster_chat_631_6 = "Nu vil du finde ud af hvordan rigtig smerte f\248les! "
gameforge.locale.monster_chat_632_1 = "Keeeedeligt! "
gameforge.locale.monster_chat_632_2 = "Findes der noget godt, som kan bruges som agn? "
gameforge.locale.monster_chat_632_3 = "Kom og k\230mp, hvis du t\248r! "
gameforge.locale.monster_chat_632_4 = "Du \248nsker at blive en kriger? S\229 vis mig hvad du har! "
gameforge.locale.monster_chat_632_5 = {}
gameforge.locale.monster_chat_632_6 = "Flygt til landsbyen, hvis du vil overleve! "
gameforge.locale.monster_chat_633_1 = "Det g\248r ondt, at sulte ihjel. "
gameforge.locale.monster_chat_633_2 = "Oh, de kommer os im\248de. "
gameforge.locale.monster_chat_633_3 = "Hvad synes du om en duel? "
gameforge.locale.monster_chat_633_4 = "Sammenlign mig ikke med andre bastards! "
gameforge.locale.monster_chat_633_5 = "Her kommer mit tordenst\248d! Ha! "
gameforge.locale.monster_chat_633_6 = "De som flygter nu, er ikke rigtige krigere! "
gameforge.locale.monster_chat_634_1 = "Dennegang burde giften virkelig g\248re godt! "
gameforge.locale.monster_chat_634_2 = "N\229r man er sulten, er flagermus en delikatesse. "
gameforge.locale.monster_chat_634_3 = "Hvad siger du til en kamp? "
gameforge.locale.monster_chat_634_4 = "N\229r min gift f\248rst er i din krop, findes der ingen helbredelse! "
gameforge.locale.monster_chat_634_5 = "Min magi vil br\230nde alt ned, hehehe! "
gameforge.locale.monster_chat_634_6 = "Br\230nd! ha, ha! "
gameforge.locale.monster_chat_635_1 = "Glem aldrig at slibe dit sv\230rd. Den n\230ste kamp er t\230ttere p\229 end tror. "
gameforge.locale.monster_chat_635_2 = "Besvimet? "
gameforge.locale.monster_chat_635_3 = "D\248, og v\229gn op i efterlivet! "
gameforge.locale.monster_chat_635_4 = "Besejre mig? Sikkert? "
gameforge.locale.monster_chat_635_5 = "K\230mp som en mand! "
gameforge.locale.monster_chat_635_6 = "Kom nu, bare en smule mere. "
gameforge.locale.monster_chat_636_1 = "Ha, jeg gl\230der mig til en dejlig kamp. "
gameforge.locale.monster_chat_636_2 = "Det er sjovt at k\230mpe, haha! "
gameforge.locale.monster_chat_636_3 = "Jeg \248nsker at k\230mpe hele tiden! "
gameforge.locale.monster_chat_636_4 = "Ha, Meget godt! Pr\248v det igen! "
gameforge.locale.monster_chat_636_5 = "Se mit sv\230rd rotere! "
gameforge.locale.monster_chat_636_6 = "Du vil fortryde, at have m\248dt mig! "
gameforge.locale.monster_chat_636_7 = "S\229 svag! Hvor latterligt! "
gameforge.locale.monster_chat_637_1 = "Jeg vil ikke forstyrres. "
gameforge.locale.monster_chat_637_2 = "Fald i s\248vn. For evigt! "
gameforge.locale.monster_chat_637_3 = "Stadig ikke faldet i s\248vn? "
gameforge.locale.monster_chat_637_4 = "Der er s\229 meget at g\248re! Lad os komme videre med det! "
gameforge.locale.monster_chat_637_5 = "V\230r ikke forundret over min magt! "
gameforge.locale.monster_chat_637_6 = "Jeg pulveriserer dig! "
gameforge.locale.monster_chat_691_1 = "Dejligt, st\230rke modstandere holder l\230ngere! Forsvar dig selv! "
gameforge.locale.monster_chat_691_2 = "Hvad? Har du et problem med min broder? "
gameforge.locale.monster_chat_691_3 = "Sammenlign mig ikke med en nybegynder. "
gameforge.locale.monster_chat_691_4 = "Han kan ikke lide dig, og det kan jeg heller ikke! "
gameforge.locale.monster_chat_691_5 = "Lad os k\230mpe. "
gameforge.locale.monster_chat_691_6 = "Til d\248den! "
gameforge.locale.monster_chat_701_1 = "Se, en sommerfugle! Hvor smuk! "
gameforge.locale.monster_chat_701_2 = "Ser du ikke sandheden, mellem himmel og jord? "
gameforge.locale.monster_chat_701_3 = "Senere vil det v\230re for sent. Tro p\229 det nu! "
gameforge.locale.monster_chat_701_4 = "Tro p\229 l\230ren af esoterikerne! "
gameforge.locale.monster_chat_701_5 = "De som tvivler vil blive dr\230bt! "
gameforge.locale.monster_chat_701_6 = "F\229 visdom gennem d\248dens favn! "
gameforge.locale.monster_chat_702_1 = "Sandheden omkring esoteriske er orden og forst\229else for himlen. "
gameforge.locale.monster_chat_702_2 = "Den esoteriske filosofi er ordenen af himlen. "
gameforge.locale.monster_chat_702_3 = "Esoterisk sandhed, tigergudens sandhed, Sabaha Sabah. "
gameforge.locale.monster_chat_702_4 = "Du v\229ger, at tvivle p\229 sandheden mellem himmel og jord? "
gameforge.locale.monster_chat_702_5 = {}
gameforge.locale.monster_chat_702_6 = "F\248l min klo! "
gameforge.locale.monster_chat_703_1 = "N\229r tigergudens sandhed, synges i evigheder, forsvinder al lidelse. "
gameforge.locale.monster_chat_703_2 = "Sandheden omkring esoteriske er orden og forst\229else for himlen. "
gameforge.locale.monster_chat_703_3 = "Sabaha Sabaha. Send os forst\229else. "
gameforge.locale.monster_chat_703_4 = "Tvivl aldrig! "
gameforge.locale.monster_chat_703_5 = "Modtag himlens torden! "
gameforge.locale.monster_chat_703_6 = "Et st\248d fra retten! "
gameforge.locale.monster_chat_704_1 = "Sandheden omkring esoteriske er orden og forst\229else for himlen. "
gameforge.locale.monster_chat_704_2 = "Esoterisk sandhed, tigergudens sandhed, Sabaha Sabah. "
gameforge.locale.monster_chat_704_3 = "Du synes jeg er en klovn g\248r du ikke? Det vil du ikke l\230nge! "
gameforge.locale.monster_chat_704_4 = "Sektens leder er en hellig, og st\229r over alle levende! "
gameforge.locale.monster_chat_704_5 = "Hent helvedets flammer! "
gameforge.locale.monster_chat_704_6 = "Jeg vil v\230de med du aldrig har set s\229 stor en stemmegaffel f\248r, eh? "
gameforge.locale.monster_chat_705_1 = "Esoterisk sandhed, tigergudens sandhed, Sabaha Sabah. "
gameforge.locale.monster_chat_705_2 = "Sandheden omkring esoteriske er orden og forst\229else for himlen. "
gameforge.locale.monster_chat_705_3 = "Bare fordi jeg er mindre end min broder, betyder det ikke at jeg vil finde mig i alting! "
gameforge.locale.monster_chat_705_4 = "Permanent smerte og m\248rke venter p\229 dig! "
gameforge.locale.monster_chat_705_5 = {}
gameforge.locale.monster_chat_705_6 = "Det er ikke slutningen. Den kommer en bedre vej. "
gameforge.locale.monster_chat_706_1 = "Vi beder om fred og ro! tak! "
gameforge.locale.monster_chat_706_2 = "N\229r frygt behersker vores liv, hj\230lper tigergudens sandhed. "
gameforge.locale.monster_chat_706_3 = "Den esoteriske sandhed er orden og forst\229else for himlen. "
gameforge.locale.monster_chat_706_4 = "Lad os alle m\248des i helvede! "
gameforge.locale.monster_chat_706_5 = "Jeg lader dig ikke g\229! "
gameforge.locale.monster_chat_706_6 = "Jeg giver dig alt hvad jeg har. "
gameforge.locale.monster_chat_707_1 = "Jeg beder dig. Hj\230lp os! "
gameforge.locale.monster_chat_707_2 = "Sandheden omkring esoteriske er orden og forst\229else for himlen. "
gameforge.locale.monster_chat_707_3 = "Esoterisk sandhed, tigergudens sandhed, Sabaha Sabah. "
gameforge.locale.monster_chat_707_4 = "(h\248jt grinen) D\248ren til helvede er \229ben. S\229 d\248! "
gameforge.locale.monster_chat_707_5 = "Jeg advare dig: Tving mig ikke til at bruge br\230ttet! "
gameforge.locale.monster_chat_707_6 = "Jeg ser allerede din d\248d! "
gameforge.locale.monster_chat_791_1 = "Lad mig t\230nke: Hvordan kan jeg opsummere himlens og jordens orden p\229 bare te par ord? "
gameforge.locale.monster_chat_791_2 = "Jeg kan h\248re sangene fra de troende. "
gameforge.locale.monster_chat_791_3 = "Det er rigtigt! Fortryd og du bliver reddet. "
gameforge.locale.monster_chat_791_4 = "Du lider af evig smerte, da du tivler p\229 den sande tro. "
gameforge.locale.monster_chat_791_5 = "Lad mig fortsat undervise dig. "
gameforge.locale.monster_chat_791_6 = "Du m\229 ikke anse det som smerte, men som undervisning. "
gameforge.locale.monster_chat_901_1 = "Jeg er m\229ske ikke k\248n, men jeg har det virkelig sjovt, hihihi! "
gameforge.locale.monster_chat_901_2 = "Du skal blive som os! "
gameforge.locale.monster_chat_901_3 = "Kom over til os, hihi! "
gameforge.locale.monster_chat_901_4 = "Haaa, haha! "
gameforge.locale.monster_chat_901_5 = "Og afsted! "
gameforge.locale.monster_chat_903_1 = "Dette er helvede! "
gameforge.locale.monster_chat_903_2 = "Ahhhhh!. "
gameforge.locale.monster_chat_903_3 = "Vi kan ikke g\248re det alene! Nej! "
gameforge.locale.monster_chat_903_4 = "Ogs\229 du skal smage denne smerte! "
gameforge.locale.monster_chat_903_5 = "Hvad med et bytte? Du giver mig din sj\230l, og jeg giver dig mine lidelser! "
gameforge.locale.monster_chat_903_6 = "Snart vil du finde evig frelse! "
gameforge.locale.monster_chat_904_1 = "Smerte! Smerte! "
gameforge.locale.monster_chat_904_2 = "Aargghh, damn! Min arm br\230nder! "
gameforge.locale.monster_chat_904_3 = "Hvorfor skal vi lide? Hvorfor? "
gameforge.locale.monster_chat_904_4 = "Det er ikke s\229 slemt, at lide af den mystiske sygdom! "
gameforge.locale.monster_chat_904_5 = {}
gameforge.locale.monster_chat_904_6 = "Ahhhh! "
gameforge.locale.monster_chat_905_1 = "Ahhhhh!. "
gameforge.locale.monster_chat_905_2 = "Jeg sl\229\229\229\229\229\229\229\229\229\229\229\229\229\229\229\229\229\229r dig ihjeld. "
gameforge.locale.monster_chat_905_3 = "V\230r ikke bare tilskuer. Deltag! "
gameforge.locale.monster_chat_905_4 = "Lad os v\230re venner! "
gameforge.locale.monster_chat_905_5 = "Du er allerede inficeret. "
gameforge.locale.monster_chat_905_6 = "Nu er du min ven. "
gameforge.locale.monster_chat_906_1 = "Hihihi! "
gameforge.locale.monster_chat_906_2 = "Kom her og spid dig p\229 mine pile. "
gameforge.locale.monster_chat_906_3 = "Du irriterer. "
gameforge.locale.monster_chat_906_4 = "Jeg inficerer dig med den mystiske sygdom. "
gameforge.locale.monster_chat_906_5 = "Dejlig lugt! "
gameforge.locale.monster_chat_906_6 = "D\248! "
gameforge.locale.monster_chat_907_1 = "Og hvis jeg finder en anden sygdom... "
gameforge.locale.monster_chat_907_2 = "(Griner) Det bliver sjovt. "
gameforge.locale.monster_chat_907_3 = "Hmm, pisk eller grib...? "
gameforge.locale.monster_chat_907_4 = "Ahhhh, jaaaa! "
gameforge.locale.monster_chat_907_5 = "Lad mig overf\248re denne sygdom til dig! "
gameforge.locale.monster_chat_907_6 = "Denne onde mystiske sygdom! "
