gameforge.locale.old_pirate.accept_success_say_1 = "Jeg har medicinen. "
gameforge.locale.old_pirate.accept_success_say_2 = "Jeg har f\229et medicinen til den gamle Pirat.[ENTER]Aflever den hos den gamle Pirat. "
gameforge.locale.old_pirate.baekgo_accept_ask = "Baek-Go:[ENTER]Du har ikke fundet noget?[ENTER]Vi skal stoppe sygdommen inden hele landsbyen[ENTER]bliver inficeret![ENTER]Skynd dig! "
gameforge.locale.old_pirate.baekgo_accept_failure_info_label = "G\229 tilbage til Baek-Go "
gameforge.locale.old_pirate.baekgo_accept_failure_info_text_1 = "G\229 tilbage til Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_failure_info_text_2 = "Forklar Baek-Go, at du ikke kunne finde nogen[ENTER]pr\248ve af den mystiske sygdom. "
gameforge.locale.old_pirate.baekgo_accept_failure_say_1 = "G\229 tilbage til Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_failure_say_2 = "Jeg kan ikke finde nogen pr\248ve af den mystiske[ENTER]sygdom![ENTER]Hvad skal jeg fort\230lle Baek-Go? "
gameforge.locale.old_pirate.baekgo_accept_success_info_label = "Aflever pr\248ven til Baek-Go "
gameforge.locale.old_pirate.baekgo_accept_success_info_text_1 = "Aflever pr\248ven af den mystiske sygdom til Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_success_info_text_2 = "Aflever pr\248ven af den mystiske sygdom og f\229[ENTER]medicinen til den gamle Pirat. "
gameforge.locale.old_pirate.baekgo_accept_success_say_1 = "Jeg har fundet en pr\248ve af den mystiske sygdom. "
gameforge.locale.old_pirate.baekgo_accept_success_say_2 = "Jeg har fundet en pr\248ve af den mystiske sygdom.[ENTER]Jeg b\248r tage den til Baek-Go. "
gameforge.locale.old_pirate.baekgo_do_you_get_the_virus = "Jeg ved ikke hvad der er \229rsagen til den mystiske[ENTER]sygdom. "
gameforge.locale.old_pirate.baekgo_iv_got_the_virus = "Jeg har fundet \229rsagen til den mystiske sygdom. "
gameforge.locale.old_pirate.baekgo_order_find_virus_label = "Dr\230b alle inficerede personer "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_1 = "Dr\230b alle, der er inficeret af den mystiske[ENTER]sygdom. "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_2 = "Dr\230b alle, der er inficeret af den mystiske[ENTER]sygdom og aflever en pr\248ve til Baek-Go.[ENTER]Han kan fremstille en medicin til den gamle Pirat. "
gameforge.locale.old_pirate.baekgo_order_too_late = "Baek-Go:[ENTER]En anden har allerede afleveret pr\248ven. Jeg har[ENTER]tilsendt Piraten sin medicin, og han burde nu[ENTER]have det godt igen. "
gameforge.locale.old_pirate.baekgo_start_say = "Baek-Go:[ENTER]Han havde kun en enkelt gang kontakt med en[ENTER]inficeret person, ogs\229 kom der bet\230ndelse i s\229ret[ENTER]og det begyndte at kl\248? "
gameforge.locale.old_pirate.baekgo_start_say2 = "Baek-Go:[ENTER]Du store himmel! Jeg er n\230sten sikker p\229 han har[ENTER]inficeret sig med den mystiske sygdom! Hvis han[ENTER]ikke bliver behandlet, vil sygdommen inficere[ENTER]hele landsbyen! "
gameforge.locale.old_pirate.baekgo_start_say3 = "Baek-Go:[ENTER]Han m\229 ikke inficere nogen! Du skal behandle ham[ENTER]med det samme. For at g\248re dette skal vi bruge en[ENTER]pr\248ve af virusen af den mystiske sygdom. Du kan[ENTER]f\229 denne pr\248ve fra en syg person. Der er masser[ENTER]af disse p\229 Sohan Bjerget i nord. "
gameforge.locale.old_pirate.baekgo_success_say = "Baek-Go:[ENTER]Du klarede det! Vent et \248jeblik! [DELAY[ENTER]value;1000] [/DELAY][ENTER][ENTER]Jeg har fremstillet det s\229 hurtig som jeg kunne,[ENTER]s\229 jeg er ikke sikker p\229 det virker. I det[ENTER]mindste burde han have det bedre bagefter.[ENTER]Aflever medicinen s\229 hurtigt som muligt. "
gameforge.locale.old_pirate.baekgo_talk = "Den gamle pirat har sendt mig. "
gameforge.locale.old_pirate.baekgo_talk_about_old_pirate = "Den gamle pirat sygdom "
gameforge.locale.old_pirate.complete_say = "Gammel Pirat:[ENTER]Det g\248r stadig ondt. Men jeg f\248ler mig meget[ENTER]bedre! S\229dan kan jeg leve. "
gameforge.locale.old_pirate.do_you_get_the_medicine = "Jeg har desv\230rre ikke f\229et fat i medicinen. "
gameforge.locale.old_pirate.do_you_mean_this_medicine = "V\230rsgo - her er din medicin! "
gameforge.locale.old_pirate.etc_shop_start_say = "Handelsdame:[ENTER]Den gamle Pirat? Klart, kender jeg ham. Du[ENTER]snakker om den bannende mand, der hele tiden kl\248r[ENTER]sig, ikke sandt?[ENTER]Han kommer hyppigt forbi, for at k\248be helende[ENTER]eliksirer. Han har allerede investeret flere[ENTER]tusind Yang i r\248de eliksirer. "
gameforge.locale.old_pirate.etc_shop_start_say2 = "Handelsdame:[ENTER]Hvor i alverden f\229r han alle de Yang fra n\229r han[ENTER]ikke engang arbejder? Jeg har allerede fortalt[ENTER]ham mange gange at han skal lade en doktor tilse[ENTER]ham, men han lytter ikke til mig. Den r\248de kur[ENTER]hj\230lper kun p\229 symptomerne men kurerer ikke[ENTER]sygdommen. Jeg er bange for at det ikke kommer[ENTER]til at g\229 ham godt. "
gameforge.locale.old_pirate.etc_shop_talk_about_old_pirate = "Kender du den gamle pirat? "
gameforge.locale.old_pirate.order_accept = "Jeg vil hj\230lpe dig. "
gameforge.locale.old_pirate.order_accept_answer = "Gamle Pirat:[ENTER]Dejligt. Held og lykke![ENTER]L\230gen er formodentlig i byen. "
gameforge.locale.old_pirate.order_find_medicine_label = "Medicin til den gamle pirat "
gameforge.locale.old_pirate.order_find_medicine_text_1 = "Hent medicin til den gamle Pirat "
gameforge.locale.old_pirate.order_find_medicine_text_2 = "Drag til Baek-Go i byen og sp\248rg ham efter[ENTER]medicin til den gamle pirat. "
gameforge.locale.old_pirate.order_refuse = "Det kan jeg desv\230rre ikke. "
gameforge.locale.old_pirate.order_refuse_answer = "Gamle Pirat:[ENTER]N\229, men s\229 har jeg ikke mere at sige! "
gameforge.locale.old_pirate.order_say1 = "Gamle Pirat:[ENTER]Hvad i alverden vil du mig? Lort! Den blandet[ENTER]forretningsdame har fortalt dig om det, hmm? Ja,[ENTER]det hun siger er sandt. Men jeg har ikke tid til[ENTER]at g\229 til l\230gen. Jeg har s\229 mange fjender! "
gameforge.locale.old_pirate.order_say2 = "Gamle Pirat:[ENTER]Man ved aldrig om en eller anden idiot ikke[ENTER]pludselig dukker op, og stikker en ned![ENTER]Men det kl\248r s\229 meget, at jeg absolut ikke kan[ENTER]holde det ud l\230ngere![ENTER]Hvad siger du? Kan du g\229 til l\230gen og hente noget[ENTER]medicin mod de kl\248ende s\229r?[ENTER]Hvis du bringer mig en medicin vil du f\229 en[ENTER]bel\248nning. "
gameforge.locale.old_pirate.order_too_late = "Gamle Pirat:[ENTER]En anden person har allerede afleveret medicinen.[ENTER]Tja, og derfor f\229r du heller ikke nogen bel\248nning. "
gameforge.locale.old_pirate.start_find_old_pirate_label = "G\229 til den gamle Pirat. "
gameforge.locale.old_pirate.start_find_old_pirate_text_1 = "G\229 til den gamle Pirat. "
gameforge.locale.old_pirate.start_find_old_pirate_text_2 = "G\229 til den gamle Pirat og sp\248rg hvorfor han ikke[ENTER]g\229r til l\230gen. "
gameforge.locale.old_pirate.start_say = "Gamle Pirat:[ENTER]Det kl\248r over det hele! Havde jeg ikke st\248dt ind[ENTER]i den kn\230gt, dengang, havde jeg aldrig f\229et[ENTER]sygdommen. Det var kun en ber\248ring! Det f\248les som[ENTER]om man r\229dner op indefra. Svin der! "
gameforge.locale.old_pirate.success_thanks = "Gamle Pirat:[ENTER]Hvad? Jeg har inficeret med den mystiske sygdom?[ENTER]Og det er den n\248dvendige medicin? Tusind tak! Du[ENTER]har formentligt reddet mit liv! Det v\230rds\230tter[ENTER]jeg virkelig! "
gameforge.locale.old_pirate.talk = "Er du den gamle Pirat? "
gameforge.locale.old_pirate.talk_about_medicine = "Hvorfor g\229r du ikke til l\230gen? "
