gameforge.locale.questscroll5 = {}
gameforge.locale.questscroll5.mission_10_hunt = "De sultene bj\248rnes vandring "
gameforge.locale.questscroll5.mission_10_mis = "Dr\230b 25 sortbj\248rne og 25 grizzlybj\248rne. "
gameforge.locale.questscroll5.mission_10_text = "Ohh, hj\230lp os. I den sidste tid, er et stigene[ENTER]antal gr\229- og sortbj\248rn begyndt at skade vores[ENTER]bikuber og i vores bistader og plantager. Hj\230lp[ENTER]os venligst og dr\230b de b\230ster, ellers vil vi[ENTER]sulte! "
gameforge.locale.questscroll5.mission_11_hunt = "Bl\229ulvenes storm "
gameforge.locale.questscroll5.mission_11_mis = "Dr\230b 35 bl\229ulve og 25 alpha-bl\229ulve. "
gameforge.locale.questscroll5.mission_11_text = "Har du allerede h\248rt om bl\229ulvenes storm? Den[ENTER]omhandler gerningerne af bl\229ulvene i sidste tid.[ENTER]De \248del\230gger alt hvad der er i vejen; som om de[ENTER]var en storm af pels og t\230nder. Kan du stoppe[ENTER]denne storm? "
gameforge.locale.questscroll5.mission_12_hunt = "Fordriv den hvide h\230r "
gameforge.locale.questscroll5.mission_12_mis = "Dr\230b 20 Hvid-Ed kommandanter "
gameforge.locale.questscroll5.mission_12_text = "I sidste tid har der v\230ret adskillige problemer[ENTER]med den hvide h\230r. Hyppigt kidnapper de rejsende[ENTER]handelsm\230nd og \248del\230gger flere landsbyer. S\248rg[ENTER]for at den hvide h\230r ikke forts\230tter med dette![ENTER]Dr\230b medlemmer og lederen af den hvide h\230r. "
gameforge.locale.questscroll5.mission_13_hunt = "Urolig sort vind "
gameforge.locale.questscroll5.mission_13_mis = "Dr\230b 25 Jak-To og 25 To-Su fra sortvind-banden. "
gameforge.locale.questscroll5.mission_13_text = "Folk fort\230ller, at sortvind-banden er igang med[ENTER]at overtage landet. Inden deres tropper bliver[ENTER]for st\230rke, burde vi dr\230be deres leder. Jeg beder[ENTER]om at du g\248r det. Dr\230b lederen! "
gameforge.locale.questscroll5.mission_14_hunt = "Stort ork opr\248r 1 "
gameforge.locale.questscroll5.mission_14_mis = "Dr\230b 30 stolte ork og 30 stolte ork-spioner. "
gameforge.locale.questscroll5.mission_14_text = "Hemmelige informationer viser, at Ork lederene i[ENTER]Seungryoung dalen i det neutrale omr\229de[ENTER]planl\230gger at underkaste sig vores verden. Jeg[ENTER]beder dig om at kontrollere de informationer. Og[ENTER]n\229r du allerede er der, kan du samtidig mindske[ENTER]deres styrke. "
gameforge.locale.questscroll5.mission_15_hunt = "Overfald fra de vilde "
gameforge.locale.questscroll5.mission_15_mis = "Dr\230b 30 vilde infanterister og 30 Vilde hellige "
gameforge.locale.questscroll5.mission_15_text = "Vi har fanget en vild spion og klaret at f\229 nogle[ENTER]vigtige informationer fra ham. \197benbart[ENTER]planl\230gger de et angreb p\229 kongeriget. Vi er n\248d[ENTER]til at komme deres angreb i fork\248bet. Vis din[ENTER]loyalitet til kongeriget. "
gameforge.locale.questscroll5.mission_16_hunt = "\216del\230g m\248rkets Metin "
gameforge.locale.questscroll5.mission_16_mis = "\216del\230g 3 m\248rkets Metin "
gameforge.locale.questscroll5.mission_16_text = "For nyligt begyndte det at regne med sten n\230r[ENTER]byen. De virker til at have en ond chi inden i[ENTER]dem, fordi siden da, har dyr i omr\229det started[ENTER]med at opf\248re sig virkelig m\230rkeligt. Tag dig[ENTER]venligst af dette problem, og \248del\230g stenene. Og[ENTER]selvf\248lgelig vil du blive passende bel\248nnet for[ENTER]dine anstrengelser. "
gameforge.locale.questscroll5.mission_17_hunt = "\216del\230g skumlens Metin "
gameforge.locale.questscroll5.mission_17_mis = "\216del\230g 2 af skumlens Metin "
gameforge.locale.questscroll5.mission_17_text = "For nyligt begyndte det at regne med sten n\230r[ENTER]byen. De virker til at have en ond chi inden i[ENTER]dem, fordi siden da, har dyr i omr\229det started[ENTER]med at opf\248re sig virkelig m\230rkeligt. Tag dig[ENTER]venligst af dette problem, og \248del\230g stenene. Og[ENTER]selvf\248lgelig vil du blive passende bel\248nnet for[ENTER]dine anstrengelser. "
gameforge.locale.questscroll5.mission_18_hunt = "Angreb fra Se-Rangs "
gameforge.locale.questscroll5.mission_18_mis = "Dr\230b 10 Se-Rangs af den hvide h\230r. "
gameforge.locale.questscroll5.mission_18_text = "Kriger, vi har f\229et nye informationer omhandlende[ENTER]den hvide h\230rs ankommen. Som reaktion p\229 vores[ENTER]pres, har Se-Rangs, den hvide h\230rs leder, startet[ENTER]et modoffensiv. Du bliver n\248d til at g\248re noget[ENTER]ved Se-Rang nu, og forhindre deres planer. "
gameforge.locale.questscroll5.mission_19_hunt = "Stort Ork opr\248r 2 "
gameforge.locale.questscroll5.mission_19_mis = "Dr\230b 20 stolte ork-krigere og 15 stolte[ENTER]Ork-troldm\230nd. "
gameforge.locale.questscroll5.mission_19_text = "De hemmelige informationer virker til at vise at[ENTER]lederne af Orcs i Seungryong Dalen planl\230gger at[ENTER]erobre verden. Lige s\229 sk\248rt som det m\229ske lyder,[ENTER]burde du m\229ske tjekke dette rygte. Og mens du er[ENTER]der kan du ogs\229 reducere deres tropper en smule. "
gameforge.locale.questscroll5.mission_1_hunt = "\216del\230g kampens Metin "
gameforge.locale.questscroll5.mission_1_mis = "\216del\230g 3 kampens Metin. "
