gameforge.locale.questscroll5.mission_20_hunt = "Hemmeligheden om aberne 1 "
gameforge.locale.questscroll5.mission_20_mis = "Dr\230b 30 abe-soldater og 30 abe-kastere. "
gameforge.locale.questscroll5.mission_20_text = "Vi har endelig fundet locationen for den normale[ENTER]abe grotte i \248rkenen. Normalt er aberne der lever[ENTER]der harml\248se, men n\229r de samler sig er de en stor[ENTER]trussel mod kongeriget. G\229 til den normale abe[ENTER]grotte og tjek abe situationen ud. "
gameforge.locale.questscroll5.mission_21_hunt = "Hemmelighed om de s\248de aber 1 "
gameforge.locale.questscroll5.mission_21_mis = "Dr\230b 30 s\248de abe-soldater og 30 s\248de abe-kaster. "
gameforge.locale.questscroll5.mission_21_text = "Vi har endelig fundet placeringen af den lette[ENTER]abe grotte i \248rkenen. Normalt er aberne der lever[ENTER]her harml\248se, men n\229r de samles er de en stor[ENTER]trussel imod kongeriget. G\229 til den lette abe[ENTER]grotte og tjek situationen omkring aberne. "
gameforge.locale.questscroll5.mission_22_hunt = "Dem der s\229r vind, h\248ster storm. "
gameforge.locale.questscroll5.mission_22_mis = "Dr\230b 4 Choung af sortvind-banden. "
gameforge.locale.questscroll5.mission_22_text = "Chuong leder af sort vinds banden, volder[ENTER]problemer. Da de er mester af sv\230rd kunsten,[ENTER]begynder de at udfordre krigere, for deres egen[ENTER]forn\248jelses skyld. Stop dem inden hele sort vinds[ENTER]banden joiner ham. "
