gameforge.locale.questscroll5.mission_27_hunt = "Edderkoppernes vrede 1 "
gameforge.locale.questscroll5.mission_27_mis = "Dr\230b 40 baby edderkopper. "
gameforge.locale.questscroll5.mission_27_text = "Edderkopper, der ellers lever fredeligt i Yonbi[ENTER]\248rkenen er p\229 det sidste pludselig begyndt at[ENTER]angribe og dr\230be rejsende. Udover det faktum at[ENTER]ofrene ikke er glade for dette, er disse angreb[ENTER]d\229rlige for vores \248konomi i vores kongerige. V\230r[ENTER]venlig at s\230tte en stopper for dette. "
