gameforge.locale.questscroll5.mission_29_hunt = "Tilh\230nger af den sorte tro 2 "
gameforge.locale.questscroll5.mission_29_mis = "Dr\230b 20 m\248rke kriger og 25 \248verste m\248rke Arahan "
gameforge.locale.questscroll5.mission_29_text = "Endelig har vi modtaget ordre om at tilintetg\248re[ENTER]den farligste sekt i hele kongeriget - Den[ENTER]esoteriske sekt i Seungryong Dalen. Tag der til[ENTER]og udryd dem. Men lav ikke den fejl at[ENTER]undervurder dem. Selv om de til tider taller om[ENTER]en masse uforst\229eligt nonsens nogen gange, er de[ENTER]stadig meget erfarne krigere. "
