gameforge.locale.questscroll5.mission_34_mis = "Dr\230b 35 baby gift-edderkopper og 35 dr\230bende[ENTER]gift-edderkopper "
gameforge.locale.questscroll5.mission_34_text = "Et hule system er blevet fundet i Yongbi \248rkenen,[ENTER]hvilket tjener som skjulested for edderkopperne[ENTER]der lever der. Vi har ingen detaljer om disse[ENTER]huler, men omr\229det er kendt for at v\230re meget[ENTER]farligt. P\229 den anden side, giver det at have en[ENTER]masse edderkopper p\229 et afgr\230nset omr\229de dig ogs\229[ENTER]mulighed for at reducere deres antal en smule.[ENTER]Tag dertil nu! Og v\230r forsigtig! "
