gameforge.locale.questscroll5.mission_37_text = "For nyligt begyndte det at regne med sten n\230r[ENTER]byen. De virker til at have en ond chi inden i[ENTER]dem, fordi siden da, har dyr i omr\229det started[ENTER]med at opf\248re sig virkelig m\230rkeligt. Tag dig[ENTER]venligst af dette problem, og \248del\230g stenene. Og[ENTER]selvf\248lgelig vil du blive passende bel\248nnet for[ENTER]dine anstrengelser. "
gameforge.locale.questscroll5.mission_38_hunt = "Skorpion plage "
gameforge.locale.questscroll5.mission_38_mis = "Dr\230b 30 Konge skorpioner og 20 unge skorpion m\230nd. "
gameforge.locale.questscroll5.mission_38_text = "Disse skorpion v\230sner tyrannisere rejsende og[ENTER]handelsm\230nd, hvilket er virkelig d\229rligt for[ENTER]vores kongeriges \248konomi. Hj\230lp os venligs med at[ENTER]slippe af med denne plage. "
gameforge.locale.questscroll5.mission_39_hunt = "D\248dens selvskab 1 "
gameforge.locale.questscroll5.mission_39_mis = "Dr\230b 30 d\230mon soldater og 20 d\230mon bueskytter. "
gameforge.locale.questscroll5.mission_39_text = "Har du h\248rt historien om D\230mon t\229rnet? Den[ENTER]Esoteriske sekt har samlet D\230mon soldater der med[ENTER]magtfulde besv\230rgelser. Bek\230mp dem og opdag hvor[ENTER]magtfulde de er. "
gameforge.locale.questscroll5.mission_3_hunt = "Gr\229ulvene dukker op 2 "
gameforge.locale.questscroll5.mission_3_mis = "Dr\230b 30 alpha-gr\229ulve. "
gameforge.locale.questscroll5.mission_3_text = "Har du h\248rt tingene om alpha-gr\229ulvene? De var[ENTER]ellers undervejs enkeltvis, men i sidste tid er[ENTER]de under indflydelse af det onde Ch og begyndt at[ENTER]rejse i flok. Kan du dr\230be nogle af de[ENTER]alpha-gr\229ulve? Du f\229r sikkert en bel\248nning. "
gameforge.locale.questscroll5.mission_40_hunt = "D\248dens selvskab 2 "
gameforge.locale.questscroll5.mission_40_mis = "Dr\230b 30 d\230mon spydkriger og 25 d\230mon shamaner. "
gameforge.locale.questscroll5.mission_40_text = "Har du h\248rt historien om D\230mon t\229rnet? Den[ENTER]Esoteriske sekt har samlet D\230mon soldater der med[ENTER]magtfulde besv\230rgelser. Bek\230mp dem og opdag hvor[ENTER]magtfulde de er. "
gameforge.locale.questscroll5.mission_41_hunt = "Hemmelighed om de st\230rke aber 2 "
gameforge.locale.questscroll5.mission_41_mis = "Dr\230b 15 st\230rke abe-soldater og 15 st\230rke[ENTER]abe-generaler. "
gameforge.locale.questscroll5.mission_41_text = "Vi har endelig fundet placeringen af den lette[ENTER]abe grotte i \248rkenen. Normalt er aberne der lever[ENTER]her harml\248se, men n\229r de samles er de en stor[ENTER]trussel imod kongeriget. G\229 til den lette abe[ENTER]grotte og tjek situationen omkring aberne. "
gameforge.locale.questscroll5.mission_42_hunt = "Isen vil smelte "
gameforge.locale.questscroll5.mission_42_mis = "Dr\230b 25 is-golem p\229 Sohan bjerget. "
gameforge.locale.questscroll5.mission_42_text = "Kender du Sohan bjerget som er permanent d\230kket[ENTER]af is? Mange opdagelsesrejsende og krigere er[ENTER]draget dertil men aldrig vent tilbage. Find[ENTER]grunden til dette om de er blevet angrebet eller[ENTER]hvad der er sket. M\229ske kan du finde ud af noget[ENTER]mens du jager monstre der. "
gameforge.locale.questscroll5.mission_43_hunt = "Hemmelighederne af de st\230rke aber 1 "
gameforge.locale.questscroll5.mission_43_mis = "Dr\230b 30 st\230rke abe soldater og 30 st\230rke abe[ENTER]kaster. "
gameforge.locale.questscroll5.mission_43_text = "Vi har endelig fundet placeringen af den lette[ENTER]abe grotte i \248rkenen. Normalt er aberne der lever[ENTER]her harml\248se, men n\229r de samles er de en stor[ENTER]trussel imod kongeriget. G\229 til den lette abe[ENTER]grotte og tjek situationen omkring aberne. "
gameforge.locale.questscroll5.mission_44_hunt = "Den gule tiger\229nd "
gameforge.locale.questscroll5.mission_44_mis = "Dr\230b 30 oksefr\248-generaler. "
gameforge.locale.questscroll5.mission_44_text = "Jeg er sikker p\229 at du har opdaget at dyrene er[ENTER]blevet virkelig vilde og voldelige p\229 det sidste.[ENTER]Kongerigest hemmelige service tror at grunden til[ENTER]dette er at den gule tiger \229nd, konge af alle dyr[ENTER]p\229 kontinentet, i \248jeblikket samler sine[ENTER]unders\229tter. Som modforanstaltning, burde vi[ENTER]eliminere lederne, som er hans h\248jere h\229nd. "
gameforge.locale.questscroll5.mission_45_hunt = "Ejer af Sohan bjerget? "
gameforge.locale.questscroll5.mission_45_mis = "Dr\230b 35 k\248lige is m\230nd og 30 yetis. "
gameforge.locale.questscroll5.mission_45_text = "Den nihalede, Sohan bjergets herre, samler[ENTER]d\230moner. Inden han har samlet alle tropperne,[ENTER]skal vi dr\230be is-m\230nd og yetis, troppernes[ENTER]rygrad! Hj\230lp os og du bliver bel\248nnet i stor[ENTER]stil. "
gameforge.locale.questscroll5.mission_46_hunt = "Chunwa Bong-ki "
gameforge.locale.questscroll5.mission_46_mis = "Dr\230b 45 tr\230fr\248-soldater og 35 tr\230fr\248-leder. "
gameforge.locale.questscroll5.mission_46_text = "Den gule tiger \229nd har \229benbart rottet sig sammen[ENTER]med tr\230 fr\248 monsterene. Sl\229 deres union fra[ENTER]hinanden med det samme. Hvis du ignorere dem vil[ENTER]det blive skidt for kongeriget! "
gameforge.locale.questscroll5.mission_47_hunt = "Ismonster! Deres sande v\230sen "
gameforge.locale.questscroll5.mission_47_mis = "Dr\230b 45 magiske is. "
gameforge.locale.questscroll5.mission_47_text = "Vi har fundet ud af hvordan is monsterene p\229[ENTER]Sohan bjerget kommunikere med hinanden: De[ENTER]spreder information via de sv\230vende splinter af[ENTER]is som du kan finde alle steder. For at sv\230kke[ENTER]enhederne i is landet, er det n\248dvendigt at vi[ENTER]distribuere denne udsendelse af information. S\229[ENTER]venligst: \216del\230g det fortryllede is! "
gameforge.locale.questscroll5.mission_48_hunt = "Hemmeligheden om D\230mon t\229rnet "
gameforge.locale.questscroll5.mission_48_mis = "Dr\230b 45 onde \229ndekriger. "
gameforge.locale.questscroll5.mission_48_text = "Rygterne siger at de onde spydm\230nd i D\230mon t\229rnet[ENTER]er uovervindelige. \197benbart rejser de sig hver[ENTER]gang de er blevet dr\230bt. Hvis det er sandt har vi[ENTER]m\248rke tider foran os. Find venligst ud af mere[ENTER]omkring dette! "
gameforge.locale.questscroll5.mission_49_hunt = "D\230mon t\229rnets herre "
gameforge.locale.questscroll5.mission_49_mis = "Dr\230b 60 onde \229ndeshaman. "
gameforge.locale.questscroll5.mission_49_text = "Efter n\248je unders\248gelser fandt vi ud af at \229nde[ENTER]soldaterne konstant genopliver. Vi er n\248d til at[ENTER]nedl\230gge den brutale D\230mon Shaman for at[ENTER]forhindre dette. "
gameforge.locale.questscroll5.mission_4_hunt = "Gr\229ulvene dukker op 1 "
gameforge.locale.questscroll5.mission_4_mis = "Dr\230b 35 gr\229ulve. "
gameforge.locale.questscroll5.mission_4_text = "Har du h\248rt om gr\229 ulvene? De plejer at rejse[ENTER]rundt alene, men grundet den d\229rlige indflydelse[ENTER]den onde Chi har haft i de forgangne uger, er de[ENTER]begyndt at jage rejsende i flok.[ENTER]Kan du eliminere disse gr\229 ulve? Du vil f\229 en[ENTER]bel\248nning for det. "
gameforge.locale.questscroll5.mission_50_hunt = "Unders\248g Doyyumhwan "
gameforge.locale.questscroll5.mission_50_mis = "Dr\230b 45 kamp tiger slaver. "
gameforge.locale.questscroll5.mission_50_text = "Doyyumhwan er et lava omr\229de, der er beboet af[ENTER]ukendte monstere. Vi er n\248d til at udforske dette[ENTER]omr\229de.[ENTER]Kan du hj\230lpe os? "
gameforge.locale.questscroll5.mission_51_hunt = "Flamme \229nden! Dens identitet "
gameforge.locale.questscroll5.mission_51_mis = "Dr\230b 45 flamme \229nder. "
gameforge.locale.questscroll5.mission_51_text = "Gruppen der var sendt for at besejre de k\230mpende[ENTER]tigere er blevet elimineret af ukendte fjender.[ENTER]Rygtet siger at, disse fjender ligner 'br\230ndende[ENTER]piger'. Find sandheden om dette. "
gameforge.locale.questscroll5.mission_52_hunt = "Reducer antallet af kamp tigere "
gameforge.locale.questscroll5.mission_52_mis = "Dr\230b 60 kamp tiger slave og 40 kamp tigere. "
gameforge.locale.questscroll5.mission_52_text = "Nu hvor vi kan bek\230mpe ild \229nderne, er vi n\248d til[ENTER]at udslette dem totalt i en \229ben kamp. En mission[ENTER]som denne tager h\230ren som regel h\229nd om, men for[ENTER]at f\229 maksimal kamp styrke til at bek\230mpe ild[ENTER]\229nderne, skal vi have en bedre teknik.[ENTER]S\248rg venligst for at kamp tigerne ikke kommer i[ENTER]vejen for os. "
gameforge.locale.questscroll5.mission_53_hunt = "Udforsk flammerne "
gameforge.locale.questscroll5.mission_53_mis = "Dr\230b 40 flammer. "
gameforge.locale.questscroll5.mission_53_text = "Flammerne er ubeskriveligt brutale. De holder af[ENTER]at smerten fra de mennesker hvis skind de[ENTER]fort\230re. Vi ved stadig ikke hvordan vi skal dr\230be[ENTER]dem. Kunne du finde ud af mere om disse flammer? "
gameforge.locale.questscroll5.mission_54_hunt = "Flamme-kriger "
gameforge.locale.questscroll5.mission_54_mis = "Dr\230b 60 flamme-kriger. "
gameforge.locale.questscroll5.mission_54_text = "Sidst blev et barn af en adelig familie dr\230bt af[ENTER]en flamme-krigere, da det kom for t\230t p\229[ENTER]ildlandet! N\229r du dr\230ber flamme-krigerne f\229r du[ENTER]en bel\248nning! Hvorfor udfordrer du dem ikke? "
gameforge.locale.questscroll5.mission_55_hunt = "Unders\248gelserne af \229ndetr\230erne "
gameforge.locale.questscroll5.mission_55_mis = "Dr\230b 30 \229ndetr\230er. "
gameforge.locale.questscroll5.mission_55_text = "Som regel ser de bare ud som tr\230er - men s\229[ENTER]pludseligt, kommer de til live og angriber dyr og[ENTER]mennesker. Find ud af hvordan vi kan \248del\230gge[ENTER]\229nde tr\230erne. "
gameforge.locale.questscroll5.mission_56_hunt = "Hemmeligheden om sp\248gelsesskoven "
gameforge.locale.questscroll5.mission_56_mis = "Dr\230b 40 \229nde stubbe og 30 Dryader. "
gameforge.locale.questscroll5.mission_56_text = "Unders\248gelser har vist at \229nde skoven er et[ENTER]omr\229de befolket med \229nde stubbe og Dryader. Hvis[ENTER]du eliminere dem, vil du m\229ske v\230re i stand til[ENTER]at g\248re en ende p\229 spredningen af \229nde tr\230erne. "
gameforge.locale.questscroll5.mission_5_hunt = "S\248rg for landsbyerne "
gameforge.locale.questscroll5.mission_5_mis = "Dr\230b 40 vildsvin. "
gameforge.locale.questscroll5.mission_5_text = "I de sidste f\229 uger, er sorgerne i landsbyen t\230t[ENTER]p\229 byen blevet v\230rre. Vildsvin som normalt kun[ENTER]angreb sm\229 dyr i bjergene er pludselig blevet[ENTER]agressive. De er begyndt at komme ind p\229 markerne[ENTER]og angriber landm\230ndene. Kunne du drive[ENTER]vildsvinene v\230k? "
gameforge.locale.questscroll5.mission_6_hunt = "Tiger og bj\248rne "
gameforge.locale.questscroll5.mission_6_mis = "Dr\230b 25 tiger og 30 bj\248rne. "
gameforge.locale.questscroll5.mission_6_text = "Har du h\248rt det nyeste? Hvis Tigere og bj\248rne kun[ENTER]spiser hvidl\248g og l\248g i 100 dage, kan de[ENTER]transformere sig til store Tigere og ild bj\248rne.[ENTER]Jeg er sikker p\229 at det aldrig er sket f\248r, men[ENTER]det vil ikke skade at tjekke alligevel. Dr\230b[ENTER]nogle tigere og bj\248rne og find ud af hvad der er[ENTER]i deres maver. "
gameforge.locale.questscroll5.mission_7_hunt = "\216del\230g beg\230rets Metin "
gameforge.locale.questscroll5.mission_7_mis = "\216del\230g 2 beg\230rets Metin. "
gameforge.locale.questscroll5.mission_7_text = "For nyligt begyndte det at regne med sten n\230r[ENTER]byen. De virker til at have en ond chi inden i[ENTER]dem, fordi siden da, har dyr i omr\229det started[ENTER]med at opf\248re sig virkelig m\230rkeligt. Tag dig[ENTER]venligst af dette problem, og \248del\230g stenene. Og[ENTER]selvf\248lgelig vil du blive passende bel\248nnet for[ENTER]dine anstrengelser. "
gameforge.locale.questscroll5.mission_8_hunt = "\216del\230g slagets Metin "
gameforge.locale.questscroll5.mission_8_mis = "\216del\230g 2 slagets Metin. "
gameforge.locale.questscroll5.mission_8_text = "For nyligt begyndte det at regne med sten n\230r[ENTER]byen. De virker til at have en ond chi inden i[ENTER]dem, fordi siden da, har dyr i omr\229det started[ENTER]med at opf\248re sig virkelig m\230rkeligt. Tag dig[ENTER]venligst af dette problem, og \248del\230g stenene. Og[ENTER]selvf\248lgelig vil du blive passende bel\248nnet for[ENTER]dine anstrengelser. "
gameforge.locale.questscroll5.mission_9_hunt = "S\248rg for landsbyerne 2 "
gameforge.locale.questscroll5.mission_9_mis = "Dr\230b 30 r\248de vildsvin. "
gameforge.locale.questscroll5.mission_9_text = "I en tid har vildsvin og deres ledere de r\248de[ENTER]vildsvin, angrebet landsbyen n\230r byen. Regeringen[ENTER]har beordret at de r\248de vildsvin dr\230bt. Alle[ENTER]krigere b\248r dr\230be 30 af dem hver. V\230r venlig ogs\229[ENTER]at hj\230lpe til. "
gameforge.locale.questscroll_10_hunt = "Slange-menneske soldater "
gameforge.locale.questscroll_10_mis = "Dr\230b soldater, der er halv menneske, halv slange. "
gameforge.locale.questscroll_10_text = "Man kan ikke kalde dem mennesker. Men det er ogs\229[ENTER]forkert at sige at de ikke er mennesker.[ENTER]De ligner mennesker, men deres krop, hud og[ENTER]opf\248rsel ligner giftige slangers. De strejfer om[ENTER]i \248rkenen og angriber de handlende.[ENTER]Dr\230b 20 af disse soldater, der halv menneske,[ENTER]halv slange. N\229r du dr\230ber dem, f\229r du f\248lgende[ENTER]bel\248nning: "
gameforge.locale.questscroll_11_hunt = "Slangemenneske-bueskytter "
gameforge.locale.questscroll_11_mis = "Dr\230b bueskytterne, der er halv menneske, halv[ENTER]slange. "
gameforge.locale.questscroll_11_text = "De er lige s\229 intelligente som mennesker. De er[ENTER]snu og forst\229r sig fremragende i brugen af v\229ben.[ENTER]Bueskytter, halvt menneske halvt slange, angriber[ENTER]de handlende fra afstand. Mange handlende er[ENTER]allerede d\248de.[ENTER]Dr\230b 20 bueskytter der er halvt menneske halvt[ENTER]slange. N\229r du gennemf\248rer opgaven f\229r du[ENTER]f\248lgende bel\248nning: "
gameforge.locale.questscroll_12_hunt = "\216rken banditter "
gameforge.locale.questscroll_12_mis = "Dr\230b \248rken banditterne. "
gameforge.locale.questscroll_12_text = "I Yongbi \248rkenen lever der onde v\230sener. De er[ENTER]kendt som \248rkenbusk r\248vere, og deres ugerninger[ENTER]skriger til himmelen. De plyndrer og dr\230ber[ENTER]handlende for sjov. De har ogs\229 \248delagt[ENTER]landsbyerne i \248rkenen. "
gameforge.locale.questscroll_13_hunt = "Kamp tiger "
gameforge.locale.questscroll_13_mis = "Dr\230b kamp tigerne. "
gameforge.locale.questscroll_13_text = "Der er dyr kaldet kamp tigere. Deres blod er[ENTER]lavet af ild, og deres kroppe er lavet af[ENTER]vulkansk granit. Dette er ufattelig magtfulde[ENTER]monstre! De lever af lava og ilden fra vulkanen.[ENTER]Nogen gange kommer de ned fra vulkanen, angriber[ENTER]mennesker og \230der dem...[ENTER]Dr\230b 20 af disse kamp tigere. N\229r du har dr\230bt[ENTER]dem, vil du f\229 f\248lgende bel\248nning: "
gameforge.locale.questscroll_14_hunt = "Krigsm\230nd "
gameforge.locale.questscroll_14_mis = "Dr\230b krigsm\230ndene. "
gameforge.locale.questscroll_14_text = "Doyyumhwan er stor, varm og huser vilde dyr. Der[ENTER]m\248des krigerne fra Chunjo, Jinno og Shinsoo.[ENTER]Frygtsomme og st\230rke monstre venter krigerne.[ENTER]Krigsm\230ndene er dem der har kontrol over[ENTER]Doyyumhwan.[ENTER]Du vil udfordre dem? N\229r du dr\230ber 20 af dem, f\229r[ENTER]du f\248lgende bel\248nning: "
gameforge.locale.questscroll_15_hunt = "Taehwa-kriger "
gameforge.locale.questscroll_15_mis = "Dr\230b Taehwa-krigeren. "
gameforge.locale.questscroll_15_text = "H\248r efter, alle jer som tror i er frygtl\248se og[ENTER]st\230rke krigere! Dette er den flammende slagmark[ENTER]af t\229rer, smerte, kampe og d\248d! Jeg lever her med[ENTER]mine mange monstre og skurke! Hvem er modig nok[ENTER]til at udfordre mig? Findes der en, som kan[ENTER]mods\230tte mig med et sv\230rd i sin h\229nd?[ENTER][ENTER]Hvis du stoler p\229 din sv\230rdarm, s\229 pr\248v at[ENTER]udfordre mig! N\229r du vinder mod mig og mine 12[ENTER]kammerater, f\229r du f\248lgende bel\248nning: "
gameforge.locale.questscroll_16_hunt = "M\248rkebj\248rne "
gameforge.locale.questscroll_16_mis = "Dr\230b m\248rkebj\248rne. "
gameforge.locale.questscroll_16_text = "Jeg frygter at dette er slutningen. Men lad mig[ENTER]fort\230lle dig en vigtig begivenhed. N\229r du l\230ser[ENTER]dette brev, er jeg allerede d\248d eller forsvundet.[ENTER]Jeg levede i Seungryoungs dalen, hvor jeg samlede[ENTER]medicinske planter. Men monstre, som blev kaldt[ENTER]m\248rke bj\248rne, begyndte at bruge alle slags[ENTER]grusomheder. De dr\230bte min familie.[ENTER][ENTER]Tag h\230vn for mig og min familie. Hvis du dr\230ber[ENTER]25 m\248rke bj\248rne, f\229r du f\248lgende bel\248nning: "
gameforge.locale.questscroll_17_hunt = "K\230mpe m\248rkebj\248rne "
gameforge.locale.questscroll_17_mis = "Dr\230b k\230mpe m\248rkebj\248rne. "
gameforge.locale.questscroll_17_text = "Bj\248rnemonstrene har skabt et nyt monster ved at[ENTER]parre sig med nogle af de onde monstre. Det er[ENTER]k\230mpem\248rke bj\248rne, st\248rre og st\230rkere end m\248rke[ENTER]bj\248rne og med en ufattelig ondskab. S\229 l\230nge[ENTER]disse v\230sener findes i Seungryoungs dalen, vil[ENTER]menneskerne lide.[ENTER][ENTER]Dr\230b 20 gigantm\248rke bj\248rne. Hvis du har succes[ENTER]f\229r du f\248lgende bel\248nning: "
gameforge.locale.questscroll_18_hunt = "Soldater, der er inficeret med den underlige[ENTER]sygdom "
gameforge.locale.questscroll_18_mis = "Dr\230b soldaterne, der er inficeret med den[ENTER]underlige sygdom. "
gameforge.locale.questscroll_18_text = "Landsbyen blev udslettet. De, der inficeret med[ENTER]den underlige sygdom, angriber dem, der kommer[ENTER]forbi. De overfalder rejsende handelsm\230nd og[ENTER]spiser mennesker. De er ekstrem farlige![ENTER]Dr\230b 35 soldater, der er inficeret med den[ENTER]underlige sygdom. Hvis du har succes f\229r du[ENTER]f\248lgende bel\248nning: "
gameforge.locale.questscroll_19_hunt = "Beskyttelse mod den underlige sygdom "
gameforge.locale.questscroll_19_mis = "Dr\230b bueskytterne, som er inficeret med den[ENTER]underlige sygdom. "
gameforge.locale.questscroll_19_text = "Den underlige sygdom er \229rsagen til at adskillige[ENTER]inficerede medf\248rer de store problemer. Mest[ENTER]farlig er de inficerede bueskytter.[ENTER]De skyder med giftpile, der lammer rejsende, s\229[ENTER]de kan angribes eller kidnappes.[ENTER][ENTER]Dr\230b 25 bueskytter, der er inficeret med den[ENTER]underlige sygdom. Hvis du har succes f\229r du[ENTER]f\248lgende bel\248nning: "
gameforge.locale.questscroll_1_hunt = "Ild-bj\248rn "
gameforge.locale.questscroll_1_mis = "Dr\230b 25 ild-bj\248rn. "
gameforge.locale.questscroll_1_text = "Ild-bj\248rn kan hyppigt m\248des i n\230rheden af[ENTER]hovedbyen. De skrider gennem omegn og de tykke[ENTER]landsveje. De finder flere og flere offer.[ENTER]Adskillige mennesker blev dr\230bt. Dr\230b 25[ENTER]ild-bj\248rn. Hvis du har succes f\229r du f\248lgende[ENTER]bel\248nning: "
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "4 fjender dr\230bt. "
gameforge.locale.questscroll_20_text = "Jeg er bange for at jeg er f\230rdig! Mit syn er[ENTER]allerede sl\248ret... N\229r du l\230ser dette brev, er[ENTER]min krop allerede r\229dden. De svin bortf\248rte mig.[ENTER]Jeg kunne stikke af, men s\229ret var s\229 dybt at jeg[ENTER]br\248d sammen. Jeg kender dig ikke, men tag h\230vn[ENTER]for mig![ENTER]Dr\230b fire fjender i denne omgivelse. Hvis du har[ENTER]succes f\252r du f\248lgende bel\248nning: "
gameforge.locale.questscroll_2_hunt = "Stortiger "
gameforge.locale.questscroll_2_mis = "Dr\230b 20 stortiger. "
gameforge.locale.questscroll_2_text = "Navnet p\229 ondskaben, Stor-tigre, kan h\248res i[ENTER]luften. Disse tigre befinder sig t\230t p\229[ENTER]hovedstaden. De angriber mennesker og \230der ligene[ENTER]af de handlende. Deres ofre er tall\248se.[ENTER][ENTER]Dr\230b 20 stor-tigre. Hvis du har succes f\229r du[ENTER]f\248lgende bel\248nning: "
gameforge.locale.questscroll_3_hunt = "Bjergets hundegud "
gameforge.locale.questscroll_3_mis = "Dr\230b bjergets hundegud. "
gameforge.locale.questscroll_3_text = "Bjergets hundegud leder en flok hundemonstre ikke[ENTER]langt herfra. Han er st\230rk og vild. For ikke s\229[ENTER]lang tid siden, blev han set ved landsbyen og[ENTER]begyndte at angribe de handlende. Mange er[ENTER]allerede faldet til dette monster. Dens[ENTER]ugerninger kan ikke l\230ngere ignoreres.[ENTER][ENTER]Dr\230b bjergets hundegud. Hvis du har succes f\229r du[ENTER]f\248lgende bel\248nning: "
gameforge.locale.questscroll_4_hunt = "Svinegud "
gameforge.locale.questscroll_4_mis = "Dr\230b svineguden. "
gameforge.locale.questscroll_4_text = "P\229 denne tid af \229ret er markene klare til h\248st.[ENTER]Nu skal landm\230ndene h\248ste hvad de har s\229et. Men[ENTER]svineguden og dens ledsagere \230der alt kornet.[ENTER]Deres gr\229dighed truer landm\230ndende. Vi m\229 dr\230be[ENTER]dem.[ENTER]Dr\230b svineguden. Han findes hyppigt i n\230rheden af[ENTER]hovedbyen. Hvis du har succes f\229r du f\248lgende[ENTER]bel\248nning: "
gameforge.locale.questscroll_5_hunt = "Bj\248rnegud "
gameforge.locale.questscroll_5_mis = "Dr\230b bj\248rneguden. "
gameforge.locale.questscroll_5_text = "I sine naturlige omgivelser var bj\248rneguden god.[ENTER]Men i noget tid har han befundet sig i n\230rheden[ENTER]af hovedstaden og angrebet menneskerne. Han[ENTER]finder flere og flere ofre. Det er umuligt at[ENTER]sige hvor mange der allerede er d\248de. Han skal[ENTER]forsvinde herfra.[ENTER]Dr\230b bj\248rneguden. Hvis du har succes f\229r du[ENTER]f\248lgende bel\248nning: "
gameforge.locale.questscroll_6_hunt = "Tigergud "
gameforge.locale.questscroll_6_mis = "Dr\230b tigerguden. "
gameforge.locale.questscroll_6_text = "Jeg kan knapt nok tro det. Hvordan kunne[ENTER]tigerguden g\248re noget s\229 forf\230rdeligt? Jeg er kun[ENTER]en simpel kvinde, som altid tilbad tigerguden der[ENTER]nogle gange kunne ses ved bjergstien. Men en dag[ENTER]angreb tigerguden og dens flok min familie! Den[ENTER]dr\230bte dem alle og jeg mistede en arm.[ENTER][ENTER]Tag h\230vn for familien. Hvis du dr\230ber tigerguden[ENTER]f\229r du f\248lgende bel\248nning: "
gameforge.locale.questscroll_7_hunt = "Leder af den hvide h\230r "
gameforge.locale.questscroll_7_mis = "Dr\230b leder af den hvide h\230r. "
gameforge.locale.questscroll_7_text = "Den hvide h\230r er en gruppe kvinder som er blevet[ENTER]efterladt af deres m\230nd og er blevet behandlet[ENTER]d\229rligt af verden. Selvom de er fattige, er de[ENTER]dog brutale mod indbyggerne. En kvinde blev[ENTER]stenet til d\248de da hun kom ind i byen. Vi kan[ENTER]ikke tillade at de kommer ind i byen og angriber[ENTER]indbyggerne igen.[ENTER]Dr\230b 20 leder af den hvide h\230r. Hvis du har[ENTER]succes f\229r du f\248lgende bel\248nning: "
gameforge.locale.questscroll_8_hunt = "Leder af sortvind-klanen "
gameforge.locale.questscroll_8_mis = "Dr\230b lederen af sortvind-klanen. "
gameforge.locale.questscroll_8_text = "Tyvene fra Sortvind banden har terroriseret de[ENTER]rejsende i lang tid. De er s\229 frygtsomme, at[ENTER]ingen t\248r sl\229 igen. Men dette kan ikke blive ved,[ENTER]ellers vil de forudrette en stor m\230ngde skade.[ENTER][ENTER]Dr\230b 20 leder af sortvind-klanen. Hvis du har[ENTER]succes f\229r du f\248lgende bel\248nning: "
gameforge.locale.questscroll_9_hunt = "Barbar h\248vding "
gameforge.locale.questscroll_9_mis = "Dr\230b barbar h\248vdingen. "
gameforge.locale.questscroll_9_text = "Det er noget tid siden barbarene sidst krydsede[ENTER]gr\230nsen og angreb landsbyen. Antallet dr\230bt af[ENTER]dem var over hundrede. Antallet af dem der blev[ENTER]skadet var h\248jere. Disse onde barbarer er s\229[ENTER]brutale at ingen har fors\248gt at stoppe dem. Men[ENTER]vi kan ikke tolerere dem l\230ngere.[ENTER][ENTER]Dr\230b 25 barbar h\248vdinge. Hvis du har succes f\229r[ENTER]du f\248lgende bel\248nning: "
gameforge.locale.quest_temp_reward_1 = "Missionsbel\248nning "
gameforge.locale.quest_temp_reward_2 = "Mens testfasen k\248re, f\229es ingen bel\248nning.[ENTER]Senere, efter du har f\229et bel\248nningen, kan du[ENTER]gentage denne mission. "
