gameforge.locale.skeleton_gem = {}
gameforge.locale.skeleton_gem.accept_ask = "Handelsmand:[ENTER]Oh, endelig! Du ligner en person der kan bruge[ENTER]sit v\229ben godt. Mit liv er i fare. Hj\230lp mig! "
gameforge.locale.skeleton_gem.accept_failure_info_label = "G\229 tilbage til handelsmanden. "
gameforge.locale.skeleton_gem.accept_failure_info_text_1 = "G\229 tilbage til handelsmanden. "
gameforge.locale.skeleton_gem.accept_failure_info_text_2 = "Forklar handelsmanden, at du ikke kunne finde[ENTER]nogen d\230mon-\230delsten+. "
gameforge.locale.skeleton_gem.accept_failure_say_1 = "G\229 tilbage handelsmanden. "
gameforge.locale.skeleton_gem.accept_failure_say_2 = "Jeg kan ikke finde nogen d\230mon-\230delsten+.[ENTER]Hvad skal jeg fort\230lle handelsmanden? "
gameforge.locale.skeleton_gem.accept_success_info_label = "Tilbage til handelsmanden "
gameforge.locale.skeleton_gem.accept_success_info_text_1 = "Aflever d\230mon-\230delstenen + til handelsmanden. "
gameforge.locale.skeleton_gem.accept_success_info_text_2 = "Du klarede at tage d\230mon-\230delstenen + fra d\230mon[ENTER]magikeren. Aflever den til handelsmanden. "
gameforge.locale.skeleton_gem.accept_success_say_1 = "Modtaget d\230mon-\230delsten+ "
gameforge.locale.skeleton_gem.accept_success_say_2 = "Du har nu d\230mon-\230delsten+. Aflever den hos[ENTER]handelsmanden. "
gameforge.locale.skeleton_gem.i_dont_have_the_skeleton_gem_yet = "Jeg har stadig ikke fundet nogen d\230mon-\230delsten. "
gameforge.locale.skeleton_gem.i_have_the_skeleton_gem = "Her er D\230mon\230delstenen+! "
gameforge.locale.skeleton_gem.order_accept = "Jeg vil finde den til dig! "
gameforge.locale.skeleton_gem.order_accept_answer = "Handelsmand:[ENTER]Oh, en million gange tak. Jeg vil aldrig glemme[ENTER]hvad du gjorde for mig! "
gameforge.locale.skeleton_gem.order_get_skeleton_gem_ = "Led efter D\230mon\230delsten+. "
gameforge.locale.skeleton_gem.order_get_skeleton_gem_text = "Find D\230montroldmanden og tag D\230mon\230delstenen+ fra[ENTER]ham. "
gameforge.locale.skeleton_gem.order_refuse = "Jeg tror dette er for farligt for mig. "
gameforge.locale.skeleton_gem.order_refuse_answer = "Handelsmand:[ENTER]Jeg forst\229r din t\248ven. Selvf\248lgelig er det en[ENTER]sv\230r og farlig opgave![ENTER]Men hvis tingene forts\230tter som nu, s\229 bliver det[ENTER]min undergang! "
gameforge.locale.skeleton_gem.order_say = "Handelsmand:[ENTER]Nu er alting forbi. Der er intet tilbage at g\248re,[ENTER]bortset fra at vente p\229 d\248den. Hvis de tyve ikke[ENTER]havde angrebet mig, s\229 ville jeg aldrig have[ENTER]mistet mine ejendele. Hvorfor skulle det ogs\229 ske[ENTER]for mig? "
gameforge.locale.skeleton_gem.order_say2 = "Handelsmanden:[ENTER]Hj\230lp mig! Hvis du kan f\229 fat i d\230mon-magierens[ENTER]d\230mon-\230delsten, vil jeg bel\248nne dig. "
gameforge.locale.skeleton_gem.order_too_late = "Handelsmanden:[ENTER]En anden har allerede givet mig den.[ENTER]Du skal ikke bekymre dig mere om det. "
gameforge.locale.skeleton_gem.start_find_peddler_label = "G\229 til handelsmanden. "
gameforge.locale.skeleton_gem.start_find_peddler_text_1 = "G\229 til handelsmanden "
gameforge.locale.skeleton_gem.start_find_peddler_text_2 = "G\229 til handelsmanden og sp\248rg ham om d\230mon-[ENTER]\230delstenen +. "
gameforge.locale.skeleton_gem.start_say = "Handelsmandens brev:[ENTER]Jeg ved ikke hvad jeg skal g\248re.[ENTER]Min d\230mon-\230delsten + blev stj\229let. Jeg betalte[ENTER]alt for denne sten![ENTER]Kan du m\229ske hj\230lpe mig?[ENTER]Jeg har seri\248st brug for din hj\230lp! "
gameforge.locale.skeleton_gem.success_say = "Handelsmand:[ENTER]Du klarede det virkelig? Kom her mine elskede[ENTER]sten! Mange tak. Du kan ikke forestille dig hvor[ENTER]lettet jeg er. "
gameforge.locale.skeleton_gem.talk_about_skeleton_gem = "Sp\248rg om D\230mon\230delstenen+ "
gameforge.locale.skill_group = {}
gameforge.locale.skill_group.board = "F\248lgende st\229r i informationsfolderen:[ENTER]Vi rekruterer modige m\230nd og kvinder, der er[ENTER]villige til at k\230mpe for Rigets fred og Rigets[ENTER]borgere![ENTER][ENTER]Foruds\230tning for at blive medlem i milit\230ret: Er[ENTER]mindst level 5. "
gameforge.locale.skill_group.dialog_assassin_1 = "Her tr\230nes ninjer, som er gode til at gemme sig[ENTER]og logge deres fjender i baghold. De fokusere p\229[ENTER]at bruge dolke og gift. Kun Ninjer som er under[ENTER]uddannelse og er level 5 eller over kan deltage.[ENTER]N\229r du har n\229et dette level, modtager du et[ENTER]rekrutterings brev. Hvis du er klar til at snige[ENTER]dig omkring i m\248rke hj\248rner i Ninjaernes verden,[ENTER]s\229 kom og find mig. S\229 kan vi tale videre. "
gameforge.locale.skill_group.dialog_assassin_2 = "Ninjaer tr\230nes her, som er gode til at gemme sig,[ENTER]og fange deres fjender i et baghold. De fokusere[ENTER]p\229 at bruge knive og gift. Hvis du er klar til at[ENTER]snige dig omkring i de m\248rke hj\248rner i Ninja[ENTER]verden s\229 kom og find mig. S\229 kan vi tale videre. "
gameforge.locale.skill_group.dialog_assassin_3 = "Ninjaer som mestre buen tr\230nes her. De l\230re dig[ENTER]hvordan du affyre en m\229lrettet salve af pile mod[ENTER]fjenden fra lange distancer. Kun Ninjaer som er[ENTER]l\230rlinge og har et minimum af level 5 kan joine[ENTER]tr\230ningen. S\229 snart du har n\229et det[ENTER]hensigtsm\230ssige level vil du modtage et[ENTER]rekrutterings brev. Hvis du er interesseret i det[ENTER]s\229 kom og bes\248g mig. "
gameforge.locale.skill_group.dialog_assassin_4 = "Ninjaer som mestre buen tr\230nes her. De l\230re dig[ENTER]hvordan du affyre en m\229lrettet salve af pile mod[ENTER]fjenden fra lange distancer. F\248lg mig. Jeg vil[ENTER]g\248re dig til den bedste bueskytte p\229 dette[ENTER]kontinent. "
gameforge.locale.skill_group.dialog_assassin_5 = "V\230lg imellem klinge kamp tr\230ning og bueskydnings[ENTER]tr\230ning, og du vil f\229 de f\230rdigheder du \248nsker. "
gameforge.locale.skill_group.dialog_shaman_1 = "Dette er stedet hvor Shamaner som vil f\248lge[ENTER]Dragegudens l\230re m\248des. De l\230re dig hvordan du[ENTER]bruger amuletter og din mentale styrke, hvilket[ENTER]tillader Shamaner at kaste deres fjenders teknik[ENTER]tilbage p\229 dem. Det tillader dem ogs\229 at for\248ge[ENTER]deres forsvars v\230rdier igennem hellig beskyttelse[ENTER]og at supporte venskabelige krigere. Kun shamaner[ENTER]som er elever eller har minimum level 5 kan[ENTER]deltage. S\229 snart du har n\229et dette level, vil du[ENTER]modtage et rekrutterings brev. n\229r du er klar til[ENTER]undervisningen i Dragemagts l\230ren, s\229 kom og led[ENTER]efter mig. "
gameforge.locale.skill_group.dialog_shaman_2 = "Dette er stedet hvor Shamaner som vil f\248lge[ENTER]Dragegudens l\230re m\248des. De l\230re dig hvordan du[ENTER]bruger amuletter og din mentale styrke, hvilket[ENTER]tillader Shamaner at kaste deres fjenders teknik[ENTER]tilbage p\229 dem. Det tillader dem ogs\229 at for\248ge[ENTER]deres forsvars v\230rdier igennem hellig beskyttelse[ENTER]og at supporte venskabelige krigere. Tror du du[ENTER]er klar til at sprede Drageguden l\230re sammen med[ENTER]mig? En ydmyg troende er altid velkommen. "
gameforge.locale.skill_group.dialog_shaman_3 = "Dette er stedet hvor Shamaner som vil f\248lge[ENTER]Dragegudens l\230re m\248des. De l\230re dig hvordan du[ENTER]bruger amuletter og din mentale styrke, hvilket[ENTER]tillader Shamaner at kaste deres fjenders teknik[ENTER]tilbage p\229 dem. Det tillader dem ogs\229 at for\248ge[ENTER]deres forsvars v\230rdier igennem hellig beskyttelse[ENTER]og at supporte venskabelige krigere. Kun shamaner[ENTER]som er l\230rlinge eller har minimum level 5 kan[ENTER]deltage. S\229 snart du har n\229et dette level vil du[ENTER]modtage et rekrutterings brev. Jeg vil vente p\229[ENTER]dig. "
gameforge.locale.skill_group.dialog_shaman_4 = "Shamaner tilbeder naturens og lynets magt her.[ENTER]Det l\230re egenskaber forbundet med lyn, storm men[ENTER]ogs\229 kr\230fter til healing her. Shamaner der f\248lger[ENTER]healings doktrinen, arbejder ofte som en gruppe[ENTER]for at hj\230lpe med at supporte hinanden. \216nsker du[ENTER]at arbejde med mig for at hj\230lpe andre? Din[ENTER]support vil hj\230lpe alle dem som lider. Hj\230lp mig[ENTER]venligst. "
gameforge.locale.skill_group.dialog_shaman_5 = "V\230lg imellem dragemagts tr\230ning eller[ENTER]helbredelses tr\230ning, og du vil f\229 de egenskaber[ENTER]du beh\248ver. "
gameforge.locale.skill_group.dialog_sura_1 = "Jeg l\230re dem som er blevet velsignet med dj\230vlens[ENTER]s\230d, hvordan de bruger deres magiske evner.[ENTER]De l\230re at fortrylle sv\230rd og rustninger hvilket[ENTER]for\248ger angrebs og forsvarsstyrke. De l\230re ogs\229[ENTER]at hidkalde \229nder fra helvede og s\229 reducere[ENTER]deres fjenders moral. Kun Suraer som er l\230rlinge[ENTER]eller har n\229et minimum level 5 kan deltage. S\229[ENTER]snart du har n\229et dette level, vil du modtage et[ENTER]rekrutterings brev. Hvis du er klar til at p\229tage[ENTER]dig din dj\230velske arv, s\229 kom her. "
gameforge.locale.skill_group.dialog_sura_2 = "Jeg l\230re dem som er blevet velsignet med dj\230vlens[ENTER]s\230d, hvordan de bruger deres magiske evner.[ENTER]De l\230re at fortrylle sv\230rd og rustninger hvilket[ENTER]for\248ger angrebs og forsvarsstyrke. De l\230re ogs\229[ENTER]at hidkalde \229nder fra helvede og s\229 reducere[ENTER]deres fjenders moral. Er du klar til at svinge[ENTER]fortryllede sv\230rd og kaste besv\230rgelser? Jeg kan[ENTER]forsikre dig om at kr\230fterne du finder her, helt[ENTER]sikkert leder efter folk af deres egen slags. "
gameforge.locale.skill_group.dialog_sura_3 = "Hvis du er interesseret i dette sted: Du vil kun[ENTER]finde dem som har dedikeret dem selv til m\248rket[ENTER]her. De l\230re hvordan de h\229ndtere \229nder, d\230moner[ENTER]og flammerne fra helvede. Kun Sura som er[ENTER]l\230rlinge eller har n\229et minimum level 5 kan klare[ENTER]denne tr\230ning. S\229 snart du har n\229et det[ENTER]n\248dvendige level vil du modtage et rekrutterings[ENTER]brev. Hvis du kalder m\248rket dit hjem, vil du helt[ENTER]sikkert finde dine br\248dre og s\248stre her. "
gameforge.locale.skill_group.dialog_sura_4 = "Hvis du er interesseret i dette sted: Du vil kun[ENTER]finde dem som har dedikeret dem selv til m\248rket[ENTER]her. De l\230re hvordan de h\229ndtere \229nder, d\230moner[ENTER]og flammerne fra helvede. Hvis du er interesseret[ENTER]i at blive venner med onde \229nder som langsomt vil[ENTER]fort\230re dine tanker bid efter bid, s\229 kom til[ENTER]mig! Join vores orden og efterlad[ENTER]menneskeligheden bag dig. "
gameforge.locale.skill_group.dialog_sura_5 = "V\230lg imellem sort magi tr\230ning og v\229bentr\230ning og[ENTER]du vil f\229 de egenskaber du har brug for. "
gameforge.locale.skill_group.dialog_warrior_1 = "Ved du hvor du er? Angribere tr\230nes her, krigere[ENTER]som er de hurtigste og de modigste her. Teknikker[ENTER]til hurtig, gentagende slag og dygtige angribere[ENTER]opl\230res her med sv\230rd og spyd.[ENTER]Kun krigere som er l\230rlinge eller har n\229et[ENTER]minimum level 5 kan deltage i tr\230ningen. S\229 snart[ENTER]du har n\229et det n\248dvendige level vil du modtage[ENTER]et rekrutterings brev. Hvis du \248nsker at finde[ENTER]den virkelige styrke i din krop, s\229 kom med mig! "
gameforge.locale.skill_group.dialog_warrior_2 = "Ved du hvor du er? Angribere tr\230nes her, krigere[ENTER]som er de hurtigste og de modigste her. Teknikker[ENTER]til hurtig, gentagende slag og dygtige angribere[ENTER]opl\230res her med sv\230rd og spyd.[ENTER]S\229 hvad bliver det til? \216nsker du at tr\230ne? "
gameforge.locale.skill_group.dialog_warrior_3 = "Jeg l\230re krigere hvordan de fokusere deres Chi[ENTER]rigtigt. Dette kr\230ver en langsom, mentalt[ENTER]udmattende kamp stil. Dog, tilgeng\230ld, vil du[ENTER]v\230re i stand til at ramme adskillige modstandere[ENTER]samtidig. Og det uigennemtr\230ngelige forsvar af[ENTER]den store intellektuelle kriger er fuldkommen[ENTER]legendarisk. Kun krigere som er l\230rlinge eller[ENTER]med et minimums level p\229 5 kan deltage i[ENTER]tr\230ningen. S\229 snart du har n\229et det p\229kr\230vede[ENTER]level vil du modtage et rekrutterings brev. Hvis[ENTER]du er interesseret s\229 kom og se mig. "
gameforge.locale.skill_group.dialog_warrior_4 = "Jeg l\230re krigere hvordan de fokusere deres Chi[ENTER]rigtigt. Dette kr\230ver en langsom, mentalt[ENTER]udmattende kamp stil. Dog, tilgeng\230ld, vil du[ENTER]v\230re i stand til at ramme adskillige modstandere[ENTER]samtidig. Og det uigennemtr\230ngelige forsvar af[ENTER]den store intellektuelle kriger er fuldkommen[ENTER]legendarisk. Hvad bliver det til? Kan du h\229ndtere[ENTER]mentale kampe? "
gameforge.locale.skill_group.dialog_warrior_5 = "V\230lg imellem kropsstyrke tr\230ning og mental styrke[ENTER]tr\230ning og du vil modtage de f\230rdigheder du har[ENTER]brug for. "
gameforge.locale.skill_group.invite = "Bekendtg\248relse fra milit\230rrekrutteringen "
gameforge.locale.skill_group.lets_join_skill_group_1 = "[COLOR r;1|g;0.6|b;0.6]Bekendtg\248relse fra[ENTER]milit\230rrekrutteringen[/COLOR][ENTER]Hvis du beundre krigerne grundet deres hurtighed[ENTER]og angrebsstyrke. Vil jeg anbefale Kropsstyrke[ENTER]tr\230ning. Hvis du \248nsker at blive us\229rlig og[ENTER]eliminere hele grupper af monster med et enkelt[ENTER]slag, vil jeg anbefale mental kamp tr\230ning.[ENTER][ENTER]Jeg vil vente p\229 dig p\229 bytorvet. "
gameforge.locale.skill_group.lets_join_skill_group_2 = "[COLOR r;1|g;0.6|b;0.6]Bekendtg\248relse om Ninja[ENTER]rekrutteringen[/COLOR][ENTER]Hvis du \248nsker at g\248re dig selv kendt som en[ENTER]fremragende Bueskytte, s\229 l\230r kunsten fra[ENTER]bueskytte tr\230neren. Hvis du er klar til at udf\248re[ENTER]forskellige hemmelige missioner i skyggerne af[ENTER]natten som en Ninja, s\229 er klinkekamp det rigtige[ENTER]for dig.[ENTER][ENTER]Jeg vil vente p\229 dig p\229 bytorvet. "
gameforge.locale.skill_group.lets_join_skill_group_3 = "[COLOR r;1|g;0.6|b;0.6]Bekendtg\248relse om Sura[ENTER]rekrutteringen[/COLOR][ENTER]\216nsker du at blive en super menneskelig sv\230rd[ENTER]mester og f\229 dine modstandere til at f\248le spidsen[ENTER]af din fortryllede klinge? S\229 anbefaler jeg dig[ENTER]at du l\230re magisk v\229bentr\230ning. Dog hvis du[ENTER]\248nsker at blive en truende hersker af flammer og[ENTER]besv\230rgelser, b\248r du l\230re den m\248rke magis kunst.[ENTER][ENTER]Jeg vil vente dig p\229 bytorvet. "
gameforge.locale.skill_group.lets_join_skill_group_4 = "[COLOR r;1|g;0.6|b;0.6]Bekendtg\248relse af Shamans[ENTER]rekrutteringen[/COLOR][ENTER]Hvis du \248nsker at v\230kke kr\230fterne fra drageguden[ENTER]i dine kampe og bruge flamme\229nde imod dine[ENTER]fjender, s\229 vil jeg anbefale Dragemagts tr\230ning.[ENTER]Dog hvis du \248nsker at lindre og heale smerten for[ENTER]dem som lider, s\229 skal du kigge p\229 Helbredelses[ENTER]l\230re.[ENTER][ENTER]Jeg vil vente p\229 dig p\229 bytorvet. "
gameforge.locale.stamina_food = {}
gameforge.locale.stamina_food.accept_ask = "Oakgu:[ENTER]Hvad er det? Da jeg var ung, kunne jeg fange mere[ENTER]end ti gr\248nne fr\248er! "
gameforge.locale.stamina_food.accept_failure_say_1 = "G\229 tilbage til Oakgu. "
gameforge.locale.stamina_food.accept_failure_say_2 = "Jeg kan ikke f\229 fat i gr\248nt fr\248k\248d.[ENTER]Hvad skal jeg dog fort\230lle Oakgu? "
gameforge.locale.stamina_food.accept_success_info_label = "Aflever det gr\248nne fr\248k\248d til Oakgu. "
gameforge.locale.stamina_food.accept_success_info_text_1 = "Aflever det gr\248nne fr\248k\248d til Oakgu. "
gameforge.locale.stamina_food.accept_success_info_text_2 = "Aflever det gr\248nne fr\248k\248d, og du vil snart kunne[ENTER]spise en gr\248n fr\248suppe. "
gameforge.locale.stamina_food.accept_success_say_1 = "Jeg har gr\248nt fr\248k\248d. "
gameforge.locale.stamina_food.accept_success_say_2 = "Jeg har gr\248nt fr\248k\248d.[ENTER]Bring det til Oakgu. "
gameforge.locale.stamina_food.baekgo_accept_failure_info_label = "G\229 tilbage til Oakgu. "
gameforge.locale.stamina_food.baekgo_accept_failure_info_text_1 = "G\229 tilbage til Oakgu. "
gameforge.locale.stamina_food.baekgo_accept_failure_info_text_2 = "Forklar Oakgu, at du ikke kunne finde noget gr\248nt[ENTER]fr\248k\248d. "
gameforge.locale.stamina_food.butcher = {}
gameforge.locale.stamina_food.butcher.start_say = "Gammel mand i Suhpyung restauranten:[ENTER]Jeg er ikke s\229 snild som jeg har v\230ret f\248r. Da[ENTER]jeg var ung, kunne jeg arbejde en hel uge igennem[ENTER]og havde bagefter stadig nok energi til at g\229 p\229[ENTER]drikketure hver aften! Men nu er det allerede[ENTER]sv\230rt bare at st\229 p\229 benene.[ENTER]En frisk gr\248n fr\248suppe ville nok v\230re et godt[ENTER]middel til at opfylde min energi. "
gameforge.locale.stamina_food.butcher.start_say2 = "Gammel mand i Suhpyung restauranten:[ENTER]Du vil vide, hvad gr\248n fr\248suppe er? N\229r du spiser[ENTER]en sk\229l fr\248suppe bliver du ikke udmattet![ENTER]Selv n\229r du har arbejdet en hel uge i marken, har[ENTER]du energi om aftenen![ENTER]Min ven Oakgu er den bedste kok til gr\248n[ENTER]fr\248suppe. Af en eller anden grund laver han ikke[ENTER]l\230ngere den suppe. "
gameforge.locale.stamina_food.butcher.talk = "Snakke. "
gameforge.locale.stamina_food.complete_say = "Oakgu:[ENTER]Har du det? Fort\230l ingen om den gr\248nne fr\248suppe.[ENTER]Og meget vigtigt:End ikke den dumme mand inde i[ENTER]Suhpyung restauranteten![ENTER]Jeg har ikke nok, og n\229r folk h\248rer om suppen,[ENTER]kommer de allesammen og t\248mmer mine rester. "
gameforge.locale.stamina_food.food_manager = {}
gameforge.locale.stamina_food.food_manager.order_say = "Oakgu:[ENTER]Gr\248n fr\248suppe? Ja! Den har jeg kokt for mange \229r[ENTER]siden.[ENTER]Men det kunne jeg kun i mine unge \229r. Dengang var[ENTER]monsterne ikke s\229 farlige, og jeg kunne jage de[ENTER]gr\248nne fr\248er uden frygt. "
gameforge.locale.stamina_food.food_manager.order_say2 = "Oakgu:[ENTER]Men nu?[ENTER]Jeg er gammel og har ikke nok energi til at klare[ENTER]det. Jeg \248nsker selv at spise min gr\248nne[ENTER]fr\248suppe. Men de gr\248nne fr\248 er ikke nemme at[ENTER]fange! Hvis du henter gr\248nt fr\248k\248d koger jeg den[ENTER]bedste gr\248nne fr\248suppe du nogensinde har smagt! "
