gameforge.main_quest_flame_lv100._020_say = "Yak-Hwan leder efter dig. V\230r venligt at ops\248g[ENTER]ham. "
gameforge.main_quest_flame_lv100._030_say = "Velkommen. Yon-I-Walker har afsluttet sine[ENTER]unders\248gelser. F\230nomenet du har observeret i[ENTER]Ildland er blevet identificeret som en sort[ENTER]substans. "
