gameforge.main_quest_flame_lv100._160_sendLetter = "Nimbus sk\230r "
gameforge.main_quest_flame_lv100._170_say = "Alkymisten leder efter dig. Det ser ud til at[ENTER]haste! "
gameforge.main_quest_flame_lv100._180_say = "En katastrofe! Jeg fortalte Yak-Hwan at handle[ENTER]med omhu.[ENTER]Og hvad g\248r han? Kaster os med hoved f\248rst og[ENTER]sv\230rdet rejst ud i kaos! Den sorte substans gro[ENTER]og spredes hurtigere, n\229r v\230rten, den har[ENTER]indlejret, d\248r.[ENTER]Nu h\248rer jeg at 300 smittede d\230moner allerede er[ENTER]blevet dr\230bt! Det er ikke godt... "
gameforge.main_quest_flame_lv100._190_say = "Under disse omst\230ndigheder, vil selv mit Nimbus[ENTER]sk\230r, som skulle forvise den sorte substans, ikke[ENTER]l\230ngere v\230re nok. Jeg har h\229rdt brug for[ENTER]ingredienser for at lave mere af det. "
