gameforge.main_quest_flame_lv100._260_sayTitle = "Nimbus sk\230r "
gameforge.main_quest_flame_lv100._270_say = "Find 10 fundamentsten, 50 bj\248rnegalder, 10[ENTER]edderkops gifts\230kke og 200 energi fragmenter.[ENTER]Bring disse ingredienser til alkymisten. "
gameforge.main_quest_flame_lv100._280_say = "Du har fundet alle ingredienserne! Godt, jeg vil[ENTER]begynder at arbejde. Jeg vil kalde p\229 dig s\229[ENTER]snart, Nimbus sk\230ret er f\230rdigt. "
gameforge.main_quest_flame_lv100._290_say = "Hvis vi ikke stopper den sorte substans, ser det[ENTER]ikke godt ud for os. G\229, bring mig alle[ENTER]ingredienserne til Nimbus sk\230ret! "
