gameforge.main_quest_flame_lv100._400_say = "Nej, ikke i dag. Jeg er her, fordi alkymisten[ENTER]gerne vil sp\248rge om din tilgivelse vedr\248rende[ENTER]hans skarpe tunge tidligere. Han har sendt dig[ENTER]denne kurv med godbidder. "
gameforge.main_quest_flame_lv100._410_say = "Jeg er tilbageholdende med at g\248re noget for den[ENTER]utaknemmelig lille idiot. Men fordi det er dig,[ENTER]vil jeg male fundamentstenene. Vent et \248jeblik. "
