gameforge.main_quest_flame_lv101._040_say = "Jeg vil betr\230kke dit sv\230rd med Nimbus sk\230ret.[ENTER]Hvis du nu dr\230ber inficererede d\230moner, vil den[ENTER]sorte substans inde i dem forsvinde, og vil ikke[ENTER]l\230ngere sprede sig. "
gameforge.main_quest_flame_lv101._050_say = "Nu kan du ogs\229 teste dig selv i den mystiske[ENTER]f\230stnings indre. Du har allerede et passage[ENTER]dokument. M\229ske vil du finde et spor omkring,[ENTER]hvad M\248rkets tjenere planl\230gger og ogs\229 resterne[ENTER]af min manglende spejder, der. "
