gameforge.main_quest_flame_lv101._070_say = "Jeg tager afsted med det samme. "
gameforge.main_quest_flame_lv101._080_say = "Danke Ich w\252nsche dir das Beste "
gameforge.main_quest_flame_lv101._090_notice = "Tving dig vej ind i fortet og bek\230mp d\230monerne[ENTER]indeni.[ENTER]Hold \248jnene \229bne for den forsvundne spejder og[ENTER]vigtige spor. "
gameforge.main_quest_flame_lv101._100_sayTitle = "Festung erkunden "
gameforge.main_quest_flame_lv101._110_say = "Tving dig vej ind i fortet og bek\230mp d\230moner i[ENTER]fortets indre. Kig efter spor for at finde ud af[ENTER]hvad tjenerene planl\230gger og efter den forsvundne[ENTER]spejder! "
gameforge.main_quest_flame_lv101._120_sayReward = "Du kannst diesen Dungeon nicht alleine betreten Bilde eine Gruppe um passieren zu d\252rfen Du erh\228ltst keinen weiteren Passierschein "
gameforge.main_quest_flame_lv101._130_say = "Har du allerede v\230ret i fortets indre? Der er[ENTER]n\248dt til at v\230re nogle spor, som viser M\248rkets[ENTER]tjeneres planer, samt resterne af min spejder! G\229[ENTER]tilbage til Ildland og s\248g i fortet. "
gameforge.main_quest_flame_lv101._140_say = "Der Sp\228her ist schon eine Weile tot In seiner Tasche findest du einen Brief \220berbringe ihn Yak Hwan "
gameforge.main_quest_flame_lv101._150_notice = "Du har fundet Yak-Hwans spejder. "
gameforge.main_quest_flame_lv101._160_say = "Hast du Neuigkeiten "
gameforge.main_quest_flame_lv101._170_say = {}
gameforge.main_quest_flame_lv101._180_say = "I f\248lge dit ansigt er det d\229rlige nyhedder...Jeg[ENTER]var allerede bange for dette. Bar han p\229 et brev?[ENTER]Vis mig det. Der m\229 ogs\229 v\230re spor efter de m\248rke[ENTER]tjeneres planer. Tag tilbage og led efter det.[ENTER]Jeg vil l\230se brevet senere. "
gameforge.main_quest_flame_lv101._190_notice = "Du har fundet en nittet halsk\230de, som tilh\248rer[ENTER]m\248rkets tjenere. Vis den til Yak-Hwan. "
gameforge.main_quest_flame_lv101._200_say = "Interessant, en nittet halsk\230de tilh\248rende de[ENTER]m\248rke tjenere. M\229ske kan den v\230re et spor p\229,[ENTER]hvad de planl\230gger! Men stadig intet nyt om min[ENTER]spejder? V\230r venlig at blive ved med at lede[ENTER]efter ham. Han er n\248dt til at v\230re i fortet. "
gameforge.main_quest_flame_lv101._210_notice = "Du har fundet en nittet halsk\230de, samt spejderen.[ENTER]Rapporter tilbage til Yak-Hwan. "
gameforge.main_quest_flame_lv101._220_say = "Rapporter til Yak-Hwan. "
gameforge.main_quest_flame_lv101._230_say = "Du var succesfuld! Denne nittet halsk\230de tilh\248rer[ENTER]de m\248rke tjenere. Den indeholder helt sikkert et[ENTER]skjult spor om deres planer. Og hvad er det? Et[ENTER]brev fra min spejder? Vis mig det. "
gameforge.main_quest_flame_lv101._240_say = {}
gameforge.main_quest_flame_lv101._250_say = "Ein Brief den mir mein Sp\228her hinterlassen hat Ich bin ersch\252ttert Lass uns gemeinsam seine letzten Worte lesen "
gameforge.main_quest_flame_lv101._260_sayTitle = "Hastigt skrevne ord: "
gameforge.main_quest_flame_lv101._270_say = "Yak-Hwan, jeg vil ikke komme tilbage i live, men[ENTER]jeg h\229ber, dette brev n\229r dig. Jeg har fundet et[ENTER]fort i Ildland, som ikke er markeret p\229 noget[ENTER]kort. Dets hersker er en kr\230ftfuld Ildlands d\230mon[ENTER]- en unik aura omringer ham, samt alle de d\230moner[ENTER]der f\248lger ham.[ENTER]Hans br\248l er \248red\248vende, og han synes at vogte[ENTER]noget. Men hvad det er, kan jeg ikke sige. Tilgiv[ENTER]mig, jeg har mislykkedes ... "
gameforge.main_quest_flame_lv101._280_say = "Vi er n\248dt til at finde ud af, hvad der er gemt i[ENTER]fortet.[ENTER]Se her, inde i den nittede halsk\230de er der en[ENTER]ingravering. Jeg vil sp\248rge Yon-I-Walker til[ENTER]r\229ds. Han vil kontakte dig, hvis han beh\248ver din[ENTER]hj\230lp. "
gameforge.main_quest_flame_lv101._290_sendLetter = "Gravur entschl\252sseln "
gameforge.main_quest_flame_lv101._300_say = "Yon-I-Walker leder efter dig. G\229 til ham. "
gameforge.main_quest_flame_lv101._310_say = "Willkommen ich habe dich bereits erwartet Ich brauche etwas Hilfe dabei die Gravur in diesem Nietenhalsband zu entschl\252sseln "
gameforge.main_quest_flame_lv101._320_say = {}
gameforge.main_quest_flame_lv101._330_say = "Tegnene p\229 indersiden af den nittede halsk\230de[ENTER]stammer fra en gammel kultur, som eksisterede for[ENTER]lang tid siden. For at tyde den har jeg brug for[ENTER]Flammekongens blod. De flyder, som lava, i hans[ENTER]\229re. "
gameforge.main_quest_flame_lv101._340_say = "Betragt det som gjort. "
gameforge.main_quest_flame_lv101._350_say = "Wenn du das Blut erhalten hast musst du so schnell wie m\246glich zu mir zur\252ckkehren Denn selbst dieses Gef\228\223 kann seine Hitze nur f\252r eine begrenzte Zeit ohne Schaden \252berstehen "
gameforge.main_quest_flame_lv101._360_notice = "Skaf Flammekonges blod. "
gameforge.main_quest_flame_lv101._370_say = "Vi kan ikke g\248re indgrevering l\230selig uden[ENTER]Flammekongens blod! "
gameforge.main_quest_flame_lv101._380_notice = "Du har f\229et Flammekongens blod.[ENTER]G\229 tilbage til Yon-I-Walker. "
gameforge.main_quest_flame_lv101._390_say = "Tal med Yon-I-Walker. "
gameforge.main_quest_flame_lv101._400_say = "Ah, godt. Med dette blods hj\230lp vil jeg v\230re i[ENTER]stand til at indgraveringen l\230selig. Dette kr\230ver[ENTER]noget tid. Kom tilbage igen i morgen. "
gameforge.main_quest_flame_lv101._410_say = "Vent endnu %d t. %d min. "
gameforge.main_quest_flame_lv101._420_say = "Jeg har brug for lidt mere tid. Kom tilbage igen[ENTER]senere! "
gameforge.main_quest_flame_lv101._430_sendLetter = "Indgraveringen "
gameforge.main_quest_flame_lv101._440_say = "Du er kommet p\229 det helt rigtige tidspunkt! Jeg[ENTER]har afkodet indgraveringen p\229 den nittede[ENTER]halsk\230de. "
gameforge.main_quest_flame_lv101._450_say = "Sie verr\228t uns dass die Diener der Dunkelheit einen der m\228chtigesten Feuerd\228monen entsandt haben um die Siegel der Tore zu schmelzen hinter denen die Sechs Drachen an einem verborgenen Ort gefangen gehalten werden Es wird auch ein spezieller Schmelzofen erw\228hnt Ich habe alles in diesem Schreiben an Yak Hwan festgehalten Bringe es bitte zu ihm "
gameforge.main_quest_flame_lv101._460_say = {}
gameforge.main_quest_flame_lv101._470_notice = "\220berbringe Yak Hwan den Brief von Yon I Walker "
gameforge.main_quest_flame_lv101._480_sayTitle = "Post f\252r Yak Hwan "
gameforge.main_quest_flame_lv101._490_say = "\220berbringe Yak Hwan den Brief von Yon I Walker "
gameforge.main_quest_flame_lv101._500_say = "Konnte Yon I Walker die Gravur lesen Oh ein Brief mit allen Informationen von ihm Sehr gut zeig her "
gameforge.main_quest_flame_lv101._510_say = "Den storsl\229ede drages segl...aha... Fortet, som[ENTER]vi har opdaget, m\229 v\230re den legendariske r\248de[ENTER]drages fort![ENTER]En af de drager, som m\248rkets tjenere er n\248dt til[ENTER]at dr\230be for at f\229 nattens perler, som formodes[ENTER]at v\230re fanges der. Her, tage dette passage[ENTER]dokument og led efter den. Du vil snart f\229 brug[ENTER]for det... "
