gameforge.main_quest_flame_lv99._190_say = "Hm wir tappen im Dunkeln Ich habe rein gar nichts \252ber diese geheimnisvolle Festung herausfinden k\246nnen In diesem Brief habe ich alles zusammengetragen was wir bis jetzt wissen Bitte \252berbringe ihn Yon I Walker Er wird wissen was zu tun ist "
gameforge.main_quest_flame_lv99._200_say = "Tag til Yon-I-Walker. "
gameforge.main_quest_flame_lv99._210_say = "Was kann ich f\252r dich tun Ah ein Brief Yak Hwan bittet also um meine Hilfe Dann werden wir mal versuchen Licht in die Dunkelheit zu bringen "
gameforge.main_quest_flame_lv99._220_say = {}
gameforge.main_quest_flame_lv99._230_say = {}
gameforge.main_quest_flame_lv99._240_say = "Eine geheimnisvolle Aura die aus dem Inneren einer Festung str\246mt Interessant Schaue dich zun\228chst einmal in der n\228heren Umgebung dort um Ich habe da einen Verdacht worum es sich bei dieser Aura handeln k\246nnte Hier nimm dieses Papier und wickel es um deine Waffe Wenn sich mein Verdacht best\228tigt sollte sich das Papier schwarz f\228rben sobald du damit D\228monen t\246test die unter dem Einfluss der dunklen Aura stehen "
gameforge.main_quest_flame_lv99._250_notice = "Besejr d\230moner, som er i n\230rheden af fortet. "
gameforge.main_quest_flame_lv99._260_sayTitle = "D\230mon jagt "
gameforge.main_quest_flame_lv99._270_say = "Besejr Ildlands d\230monener, som er i n\230rheden af[ENTER]fortet og tjek om dit v\229ben skifter farve. "
gameforge.main_quest_flame_lv99._280_say = "Hmm, jeg er sikker p\229 der er beviser at finde i[ENTER]Ildland p\229 denne aura. Tag tilbage en gang til og[ENTER]besejr d\230moner, der er t\230t p\229 dette fort. "
gameforge.main_quest_flame_lv99._290_notice = "Dit v\229ben er blevet sort. Tag tilbage til[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv99._300_say = "Ah so wie ich es erwartet hatte Das ist h\246chst bemerkenswert Ich werde dieses Papier etwas n\228her untersuchen Ruhe dich solange aus "
gameforge.main_quest_flame_lv99._310_sendLetter = "Aura erforschen "
gameforge.main_quest_flame_lv99._320_say = "Yon-I-Walker leder efter dig. Tag til ham og find[ENTER]ud af mere. "
gameforge.main_quest_flame_lv99._330_say = "Ah, der er du! Den aura er forr\230derisk og g\248r mit[ENTER]sind uklart.[ENTER]Jeg har brug for sol urter til at lysne mit sind[ENTER]og forts\230tte mine unders\248gelser. Kan du skaffe[ENTER]mig nogle? "
gameforge.main_quest_flame_lv99._340_say = "Selvf\248lgelig. "
gameforge.main_quest_flame_lv99._350_say = "Sol urter gror p\229 varme, t\248rre steder - de findes[ENTER]i Ildland hele \229ret rundt. Jeg vil markere[ENTER]stedet, hvor jeg sidst fandt nogle, p\229 kortet.[ENTER]Men jeg er ikke helt sikker p\229 det er det pr\230cise[ENTER]sted... "
gameforge.main_quest_flame_lv99._360_say = "Jeg vil tage af sted med det samme! "
gameforge.main_quest_flame_lv99._370_notice = "Tag til det markerede sted i Ildland og led efter[ENTER]sol urter. "
gameforge.main_quest_flame_lv99._380_sayTitle = "Sonnenkr\228uter besorgen "
gameforge.main_quest_flame_lv99._390_say = "Drag til stedet, som Yon-I-Walker har markeret p\229[ENTER]kortet, og led efter sol urter. "
gameforge.main_quest_flame_lv99._400_say = "Du kommer tilbage tomh\230ndet? Det er ikke godt.[ENTER]Jeg f\248ler det, som om mit sind bliver mere og[ENTER]mere uklart af auraen. V\230r venlig at f\229 fat i[ENTER]nogle sol urter til mig. "
gameforge.main_quest_flame_lv99._410_notice = "Du har fundet sol urter. Tag dem med tilbage til[ENTER]Yon-I- Walker. "
gameforge.main_quest_flame_lv99._420_say = "Ah, du har fundet sol urter![ENTER]Storartet. Nu kan jeg forts\230tte mine[ENTER]unders\248gelser.[ENTER]Yak-Hwan vil fort\230lle dig om resultaterne. "
gameforge.main_quest_flame_lv99._430_say = "Eventyret forts\230tter, s\229 snar du har n\229et level[ENTER]%d. "
gameforge.main_quest_lv1 = {}
gameforge.main_quest_lv1._10_sendLetter = "Velkommen til Metin 2 "
gameforge.main_quest_lv1._20_say = "Det sp\230ndende eventyr i Metin2 er ved at begynde.[ENTER]Til start find venligst Byvagten.[ENTER]Han vil give dig nogle basis informationer og[ENTER]forskellige opgaver.[ENTER][ENTER]Hvis du vil g\229 p\229 jagt, kan du finde nogle vilde[ENTER]dyr uden for bygr\230nsen. De vil blive vist p\229[ENTER]minikortet som sm\229 r\248de prikker. Du b\248r[ENTER]koncentrere dig om vild hundene f\248rst, da de er[ENTER]det letteste m\229l.[ENTER]Held og lykke! "
gameforge.main_quest_lv1._30_targetVid = "Find byvagten "
gameforge.main_quest_lv1._40_sayTitle = "Find byvagten "
gameforge.main_quest_lv1._50_sayReward = "Tal med byvagten ved at klikke p\229 ham. Han er den[ENTER]NPC som pilen peger p\229. Hvis du ikke kan se ham,[ENTER]er du m\229ske for langt v\230k. F\248lg den blinkende[ENTER]cirkel p\229 kortet indtil du n\229r byvagten. "
gameforge.main_quest_lv1._60_sayTitle = "Byvagt: "
gameforge.main_quest_lv1._70_say = "Du m\229 v\230re ny i byen! Jeg kan se de ikke har[ENTER]gjort dig til soldat endnu. Har du haft noget[ENTER]tr\230ning endnu? Se p\229 dig selv! Har du nogensinde[ENTER]brugt et v\229ben? H\248r her! Du er n\248d til at v\230re[ENTER]forsigtig hvis du vil overleve denne krig. Jeg[ENTER]vil assistere dig indtil du har n\229et level 10. Og[ENTER]lad dig ikke narre til at tro at det kommer til[ENTER]at blive let! G\229 s\229! "
gameforge.main_quest_lv1._80_say = "G\229 nu og l\230r det grundl\230ggende inden for jagt og[ENTER]kamp. N\229r du har n\229et et h\248jere levet kom tilbage[ENTER]til byen og snak med mig igen. Hvorfor st\229r du[ENTER]stadig her? Du vil ikke f\229 erfaring ved bare at[ENTER]h\230nge her! "
gameforge.main_quest_lv10 = {}
gameforge.main_quest_lv10._100_sayReward = "Du har modtaget 50,000 erfaringspoint.[ENTER]Du har modtaget 12,000 Yang.[ENTER]Du har f\229et Udsmykkede Guld Sko +4.[ENTER]Du har modtaget 5 Lilla Eliksir. "
gameforge.main_quest_lv10._10_sendLetter = "G\229 til kaptajnen "
gameforge.main_quest_lv10._110_sayTitle = "Uddannelse hos kaptajnen "
gameforge.main_quest_lv10._120_sayReward = "Kaptajnens f\248rste mision bringer dig til nabo[ENTER]byen. Der skal du bes\248ge musikeren Yu-Hwan og[ENTER]sp\248rge efter det hemmelige dokument til[ENTER]kaptajnen. "
gameforge.main_quest_lv10._130_sayTitle = "Musikeren Yu-Hwan: "
gameforge.main_quest_lv10._140_say = "Livet er som en dr\248m, som alt i livet. Hvorfra[ENTER]kommer vi? Hvor g\229r vi hen?[ENTER]Vores verden er fuld af had.[ENTER]Hjertelig flid bel\248nnes ikke.[ENTER]Er du her for at lytte til min[ENTER]musik?  "
gameforge.main_quest_lv10._150_say = "Oh, kaptajnen har sendt dig![ENTER]Psst, ikke s\229 h\248jt ... Ingen m\229 f\229 min sande[ENTER]identitet af vide. Du er nok trov\230rdig n\229r[ENTER]kaptajnen sender dig! Her har du det. Dokumentet[ENTER]indeholder alle de informationer jeg kunne samle.[ENTER]Aflever dem til kaptajnen. "
gameforge.main_quest_lv10._160_sayTitle = "Musikeren Yu-Hwan: "
gameforge.main_quest_lv10._170_say = "Skynd dig videre! Hvis du bliver her for l\230nge,[ENTER]vil noget skidt ske. Husk: Livet er kort, nyd det[ENTER]s\229 l\230nge du kan. "
gameforge.main_quest_lv10._180_targetVid = "G\229 tilbage til kaptajnen "
gameforge.main_quest_lv10._190_sayReward = "Musikeren Yu-Hwan som i al hemmelighed arbejder[ENTER]som spion har givet dig vigtige dokumenter.[ENTER]Bring dem til kaptajnen i den f\248rste by. "
gameforge.main_quest_lv10._200_say = "Dette er dokumentet fra musikeren? Ikke d\229rligt[ENTER]for en uerfaren eventyrer som dig![ENTER]Jeg har store forventninger hvad din fremtid[ENTER]ang\229r. Tag dette som anerkendelse og tak for dit[ENTER]h\229rde arbejde. Og arbejd fortsat s\229 engageret for[ENTER]vores land.  "
gameforge.main_quest_lv10._20_sayReward = "Du er nu erfaren nok til at tjene dit kongerige[ENTER]som fuldt udviklet kriger. Fra nu af vil[ENTER]kaptajnen give dig nye opgaver. Du vil finde ham[ENTER]i den f\248rste by. G\229 og se ham; han venter p\229 dig. "
gameforge.main_quest_lv10._30_sayTitle = "Kaptajn "
gameforge.main_quest_lv10._40_say = "Jeg kender dig... N\229 ja - jeg har h\248rt om dig. Du[ENTER]er den nye eventyre og har allerede vist hvad du[ENTER]kan. Jeg ved ikke hvor uddannet du er, men du vil[ENTER]i fremtid f\229 flere opgaver.  "
gameforge.main_quest_lv10._50_say = "Du vil m\248de adskillige udfordringer, s\229 forbered[ENTER]dig godt. Har du h\248rt historien om de tre Riger[ENTER]fra kontinenten p\229 den lyse himmel?[ENTER]Du kender den ikke?[ENTER]Hvad f\229r man da l\230rt idag af uddannelse? Er jeg[ENTER]n\248d til at l\230re dig de grundl\230ggende[ENTER]ting?  "
gameforge.main_quest_lv10._60_say = "Dette er vigtigt, da det er historien om[ENTER]kontinentet. S\229 jeg vil opsummere den for dig.[ENTER]Engang for l\230nge siden var kongeriget forenet.[ENTER]Men s\229 kom Metin stenen ned og bragte krig og[ENTER]konflikt. Kontinentet blev delt i tre[ENTER]individuelle lande: Shinsoo er handels[ENTER]kongeriget, Chunjo er religions kongeriget og[ENTER]Jinno er det milit\230re kongerige. "
gameforge.main_quest_lv10._70_say = "Rigernes ledere pr\248ver at f\229 afsluttet uroen, som[ENTER]opstod med metin-stenene, for at samle[ENTER]kontinenten igen.[ENTER]Du skal ogs\229 arbejde h\229rdt for at forene[ENTER]kontinentet igen![ENTER]Det er vigtigt, og m\229 aldrig[ENTER]glemmes!  "
gameforge.main_quest_lv10._80_say = "Jeg vil give dig din f\248rste mission.[ENTER]V\230r ikke bange, det er en let mission. I den[ENTER]n\230ste landsby findes en musiker, kaldet Yu-Hwan.[ENTER]Folk tror han har afsluttet sin milit\230rkarriere[ENTER]for at blive musiker. Men i grunden er han en[ENTER]spion. Jeg har brug for et dokument fra Yu-Hwan.[ENTER]Hent det. Glem ikke, at det her er en hemmelig[ENTER]mission. "
gameforge.main_quest_lv10._90_say = "Tryk p\229 m for at finde ud af hvordan du kommer[ENTER]til den n\230ste by p\229 kortet. Brug telepotterings[ENTER]portalen med det tilsvarende bynavn.[ENTER]Skynd dig! Yu-Hwan er en h\248j fyr - men du vil[ENTER]kende ham p\229 hans musikinstrumenter. "
