gameforge.main_quest_lv12._160_sayReward = "Du har dr\230bt det n\248dvendige antal Alpha gr\229 ulve.[ENTER]G\229 nu tilbage til kaptajnen og reporter din[ENTER]succes. "
gameforge.main_quest_lv12._170_say = "Dr\230bte du Alpha gr\229 ulvene? Godt arbejde.[ENTER]Takket v\230re dig er det meget lettere at holde[ENTER]landsbyen sikker nu. Det er virkelig godt nyt i[ENTER]krigstider som disse. "
gameforge.main_quest_lv12._180_sayReward = "Du har modtaget 40,000 erfaringspoint.[ENTER]Du har modtaget 10,000 Yang.[ENTER]Du har modtaget en F\230rdighedsbog. "
gameforge.main_quest_lv12._20_say = "Adskillige Alpha gr\229 ulve har skabt kaos lige[ENTER]uden for landsbyen. De har randt vildt i et[ENTER]stykke tid, men nu er deres adf\230rd kommet helt ud[ENTER]af kontrol! De er begyndt at angribe landsbyen og[ENTER]folk p\229 gaden. For at f\229 kontrol over situationen[ENTER]er vi n\248d til at dr\230be nogle Alphs Gr\229 ulve.[ENTER]Kunne du hj\230lpe? Eliminer 10 Alpha Gr\229 ulve for[ENTER]os. "
gameforge.main_quest_lv12._30_sayReward = "Du vil modtage 24.000 erfaringspoint og 3.500[ENTER]Yang som bel\248nning. "
gameforge.main_quest_lv12._40_sendLetter = "Dr\230b 10 Alpha gr\229 ulve "
gameforge.main_quest_lv12._50_sayReward = "Alpha-gr\229ulve forstyrer freden. Dr\230b 10[ENTER]alpha-gr\229ulve for at overst\229 krisen. "
gameforge.main_quest_lv12._60_sayReward = "Indtil nu, har du dr\230bt %s alpha-gr\229ulve. "
gameforge.main_quest_lv12._65_counter = "Rest antal "
gameforge.main_quest_lv12._70_sayReward = "Du har dr\230bt 10 ulve.[ENTER]G\229 tilbage til kaptajnen. "
gameforge.main_quest_lv12._80_npcChat = "Dr\230b alpha-gr\229ulve "
gameforge.main_quest_lv12._90_say = "Du har stadig ikke klaret opgaven?[ENTER]Har du problemer med at dr\230be 10 alpha-gr\229ulve?[ENTER]\216nsker du at forts\230tte opgaven?  "
gameforge.main_quest_lv14 = {}
gameforge.main_quest_lv14._100_sayTitle = "Mission afsluttet "
gameforge.main_quest_lv14._10_sayReward = "Kaptajnen har en ny opgave for dig. Find ham. "
gameforge.main_quest_lv14._110_sayReward = "Du har \248delagt en Metin af kamp. G\229 til kaptajnen[ENTER]og fort\230l ham om din succes. "
gameforge.main_quest_lv14._120_say = "Godt arbejde! Du er blevet en p\229lidelig hj\230lper![ENTER]Nu ved jeg, at jeg kan give dig flere opgaver.[ENTER]Jeg er stolt af dig. Her er din bel\248nning.[ENTER]Forts\230t det gode arbejde!  "
gameforge.main_quest_lv14._130_sayReward = "Du har modtaget 20,000 erfaringspoint.[ENTER]Du har modtaget 20,000 Yang.[ENTER]Du har modtaget en klump guld. "
gameforge.main_quest_lv14._140_sayReward = "Du har modtaget en %s. "
gameforge.main_quest_lv14._20_say = "Jeg kender til den m\248rke energi fra Metin[ENTER]stenene. Musikeren Yu-Hwan fortalte mig at Metin[ENTER]stenene f\229r dyrene til at g\229 amok og spreder[ENTER]forf\230rdelige sygdomme. "
gameforge.main_quest_lv14._30_say = "Hvis vi ikke g\248r noget ved Metin stenene, vil dyr[ENTER]angribe landsbyen igen, eller v\230rre; en sygdom[ENTER]vil m\229ske bryde ud! Kunne du tage dig af stenene[ENTER]der er landet uden for landsbyen. "
gameforge.main_quest_lv14._40_sayReward = "Du vil modtage 48.000 erfaringspoint og 10.000[ENTER]Yang, plus en \197ndesten (+0 til +2) som bel\248nning. "
gameforge.main_quest_lv14._50_sendLetter = "\216del\230g Metin af slaget "
gameforge.main_quest_lv14._60_sayReward = "Metin stenene er en seri\248s fare. Hj\230lp kaptajnen[ENTER]med at \248del\230gge en Metin af slaget. "
gameforge.main_quest_lv14._70_sayTitle = "Mission afsluttet "
