gameforge.main_quest_lv14._90_sendLetter = "G\229 tilbage til kaptajnen "
gameforge.main_quest_lv15 = {}
gameforge.main_quest_lv15._100_say = "Vores rige, Jinno, har altid v\230ret en st\230rk[ENTER]milit\230r magt. Kejseren har samlet kontinentet med[ENTER]sin kraftfulde og gennempr\248vede kavaleri. Selv om[ENTER]vi nu er opdelt p\229 grund af de opt\248jer Metin[ENTER]Stenene for\229rsager, er vores rige stadig de rette[ENTER]ejere af magten Iryung. "
gameforge.main_quest_lv15._10_qSetTitle = "Den aktuelle situation "
gameforge.main_quest_lv15._110_say = "Vi har stadig det bedstuddannede milit\230r af alle[ENTER]tre kongeriger. Hvis vi \248nskede, kunne vi smadre[ENTER]de andre lande. Du burde tr\230nere h\229rdere for at[ENTER]blive en god soldat.  "
gameforge.main_quest_lv15._120_say = "Jeg har t\230nkt mig at give dig en ny opgave. Tag[ENTER]denne ammunition til Yu-Hwan i nabo landsbyen.[ENTER]Vi opbevarer denne ammunition flere steder for[ENTER]ekstra sikkerhed, s\229 vi hurtigt kan f\229 adgang til[ENTER]det i en n\248dsituation. Hvis du leverer det til[ENTER]Yu-Hwan, vil du v\230re med til at udruste[ENTER]landsbyen. "
gameforge.main_quest_lv15._130_sayReward = "Du har modtaget 36.000 erfaringspoint.[ENTER]Du har modtaget 10.000 Yang.[ENTER]Du har modtaget et Smykke. "
gameforge.main_quest_lv15._140_sayTitle = "Den aktuelle situation "
gameforge.main_quest_lv15._150_sayReward = "Kaptajnen har betroet dig en leverance til[ENTER]Yu-Hwan. Tag til ham i den anden landsby. "
gameforge.main_quest_lv15._160_say = "Engang var der en blodig kamp mellem Sung Mahi og[ENTER]Drage Guden. Siden da, er folket blevet delt og[ENTER]konkurrerer mod hinanden i en endel\248s krig... Dig[ENTER]igen! Har du brug for noget? Kaptajnen har sendt[ENTER]mig noget vigtigt? Tak. Og nu afsted igen - det[ENTER]er ikke godt, hvis folk ser os sammen. "
gameforge.main_quest_lv15._170_makequestbutton = "Snak med kaptajnen "
gameforge.main_quest_lv15._175_say = "Du har givet Yu-Hwan Kaptajnen's leverance.[ENTER]G\229 nu tilbage til Kaptajnen og afhent din[ENTER]bel\248nning. "
gameforge.main_quest_lv15._180_say = "Godt g\229et! Hvis du forts\230tter p\229 denne m\229de, kan[ENTER]du blive en rigtig vigtig hj\230lper for vores[ENTER]landsby. Her er din bel\248nning. "
gameforge.main_quest_lv15._20_say = "Som du m\229ske har h\248rt, er den fred situationen[ENTER]mellem kongerigerne ikke god i \248jeblikket. G\229 til[ENTER]Kaptajnen, han kan give dig mere information. "
gameforge.main_quest_lv15._30_say = "Jeg synes du skal finde ud af mere om vores[ENTER]nuv\230rende situation. Dirigere din opm\230rksomhed p\229[ENTER]vores rige f\248rst. For at vinde en krig, er det[ENTER]n\248dvendigt at kende dig selv, f\248r du kan kende[ENTER]dine fjender. "
gameforge.main_quest_lv15._40_say = "Vores rige, Shinsoo, har altid v\230ret et centrum[ENTER]for handel. Vores omfattende handels ruter bragte[ENTER]mange handlende og varer over til os fra hele[ENTER]verden. Men siden Metin Stenene kom, er disse[ENTER]forbindelser brudt ned, og vores \248konomi har f\229et[ENTER]det meget v\230rre. Vi var velst\229ende \233n gang, men[ENTER]vi har aldrig haft megen milit\230r magt, hvilket er[ENTER]hvorfor vi har hyret nogle lejesoldater. Disse[ENTER]krigere er meget p\229lidelige og loyale overfor[ENTER]dem, der betaler dem. "
gameforge.main_quest_lv15._50_say = "Takket v\230ret lejesvendene har vores land f\229et[ENTER]stabiliteten igen. For at forberede os mod[ENTER]kommende krige har vi brug for flere lejesvende[ENTER]og en st\230rk \248konomi.  "
gameforge.main_quest_lv15._60_say = "Jeg har en anden opgave til dig. Tag denne[ENTER]specialiteter til Yu-Hwan, der bor i nabo[ENTER]landsbyen. Vores land var og er stadig et[ENTER]kongerige af handel og vi handler med forskellige[ENTER]specialiteter fra forskellige regioner. Afkastet[ENTER]vi f\229r fra det gavner landsbyen. "
gameforge.main_quest_lv15._70_say = "Chunjo: Vores Rige bliver styret af guvern\248r Yoo[ENTER]Young. Grundlaget er vores religion. Den hj\230lper[ENTER]os, og vi var de f\248rste der havde viden om Sung[ENTER]Mahi\180s eksistens. Vores shamaner havde advaret os[ENTER]om metin-stenene. Vores store shamaner arbejder[ENTER]h\229rdt for landets sikkerhed. Shamanerne har mange[ENTER]f\230rdigheder, deres styrke ligger i vores tro.[ENTER]Uden den ville det kun v\230re et sp\248rgsm\229l om tid,[ENTER]inden vi ville blive erobret af andre[ENTER]Riger.  "
gameforge.main_quest_lv15._80_say = "De mennesker i vores land har en meget st\230rk tro[ENTER]og beder til Drage Guden hver dag. Den velvillige[ENTER]Drage Gud beskytter os mod opstandelsen af Sung[ENTER]Mahi. Med hans hj\230lp vi forts\230tter med at[ENTER]forsvare os selv fra disse barbariske angreb og[ENTER]genforener imperiumet under vores kontrol. "
gameforge.main_quest_lv15._90_say = "Jeg vil give dig en opgave du skal udf\248re.[ENTER]Aflever denne stenstatue af drageguden til[ENTER]Yu-Hwan i nabo byen. Vores land er religi\248s, og[ENTER]den dybe tro p\229 drageguden er meget vigtig for[ENTER]os. Hvis du afleverer statuen til Yu-Hwan hj\230lper[ENTER]du med til at styrke troen i byen. "
gameforge.main_quest_lv16 = {}
