gameforge.main_quest_lv16._30_sayReward = "Der er en fjendtlig spion i vores landsby.[ENTER]Kaptajnen vil give dig mere information om det. "
gameforge.main_quest_lv16._40_say = "Jeg har en fornemmelse af, at vi har en spion i[ENTER]vores midte. Nogen af landsbyens indbyggere er i[ENTER]hemmelig kontakt med Hvid-Ed Soldater. Jeg har[ENTER]brug for din hj\230lp i denne sag: G\229 ud og dr\230be[ENTER]Hvid-Ed Soldater, m\229ske vil du v\230re i stand til[ENTER]at finde nogle oplysninger om spionen. "
