gameforge.main_quest_lv2._200_sendLetter = "Praktisk opgaven fuldf\248rt "
gameforge.main_quest_lv2._20_say = "Byvagt:[ENTER]Din interesse er prisv\230rdig, men du b\248r indsamle[ENTER]flere erfaringer point. Kom tilbage n\229r du har[ENTER]n\229et et h\248jere level! "
gameforge.main_quest_lv2._210_say = "Du er bedre end jeg troede![ENTER]Men jeg formoder at hvem som helst kunne have[ENTER]gjort det. Ha ha! Tilbage i mine dage, var[ENTER]opgaverne meget vanskeligere. V\230r forberedt til[ENTER]den n\230ste. Her, har du tjent dig nogle eliksir og[ENTER]Yang, s\229 du kan forbedre dit udstyr. Jeg ringer[ENTER]til dig, s\229 snart jeg har en ny opgave til dig. "
gameforge.main_quest_lv2._220_sayReward = "Du har modtaget 250 erfaringspoints.[ENTER]Du har modtaget 15,000 Yang. "
