gameforge.main_quest_lv2._30_sendLetter = "Byvagtens brev "
gameforge.main_quest_lv2._40_targetVid = "Find byvagten "
gameforge.main_quest_lv2._50_sayReward = "N\229r du l\230ser dette brev har du opn\229et en nyt[ENTER]level. Tillykke! G\229 til byvagten s\229 du kan f\229 din[ENTER]f\248rste \248velsesopgave! "
gameforge.main_quest_lv2._60_say = "Du mangler stadig disciplin, selvom du har vist[ENTER]mig, at du kan h\229ndtere et v\229ben! Tror du[ENTER]virkelig, at du er klar til at tage nogle vilde[ENTER]dyr? Jeg har t\230nkt mig at se hvor dygtig du er[ENTER]f\248rst. Forlad landsbyen og dr\230b 9 Vildhunde, kom[ENTER]s\229 tilbage og f\229 din bel\248nning. "
gameforge.main_quest_lv2._70_say = "De er ikke farlige, s\229 det burde ikke v\230re alt[ENTER]for sv\230rt. Hvis du ikke gennemf\248rer denne opgave,[ENTER]vil du aldrig kunne overleve i denne egn![ENTER]Drag afsted - jo f\248r du er f\230rdig, jo[ENTER]bedre!  "
gameforge.main_quest_lv2._80_sayReward = "Fra tid til anden vil Landsbyboerne give dig[ENTER]opgaver, der giver dig erfaringspoint og Yang.[ENTER]Det betaler sig at kigge efter folk, der giver[ENTER]dig opgaver! "
gameforge.main_quest_lv2._90_sayReward = "For at dr\230be de Vilde Hunde vil du modtage:[ENTER]Erfaringspoint: 550[ENTER]Yang: 1.000[ENTER]Genstand: %s, Antal: %s "
