gameforge.main_quest_lv27._100_makequestbutton = "Den Metin Sten er blevet \248delagt "
gameforge.main_quest_lv27._105_say = "Du har \248delagt en Skumlens Metin. G\229 til[ENTER]kaptajnen og fort\230l ham om din succes. "
gameforge.main_quest_lv27._10_makequestbutton = "\216del\230g Metin stenene "
gameforge.main_quest_lv27._110_say = "Har du \248delagt Metin stenen? Tak! Landsbyen er i[ENTER]sikkerhed for nu! Hvor kommer disse sten fra? Vi[ENTER]har knap nok nogle oplysninger om dem, selvom de[ENTER]skaber s\229 mange problemer. Jeg h\248rte, at Uriel[ENTER]den kloge unders\248ger Metin Sten. Men jeg ved[ENTER]ikke, hvad han har fundet ud af indtil videre.[ENTER]Uanset hvad, du gjorde et godt stykke arbejde! "
gameforge.main_quest_lv27._120_sayTitle = "Bel\248nning: "
gameforge.main_quest_lv27._130_sayReward = "Du har modtaget 3,300,000 erfaringspoint.[ENTER]Du har modtaget 270,000 Yang.[ENTER]Du har modtaget en f\230rdighedsmanual Bog. "
gameforge.main_quest_lv27._140_sayReward = "Du modtager %s. "
gameforge.main_quest_lv27._20_say = "\216del\230ggelsen for\229rsaget af Metin Stenene er[ENTER]blevet v\230rre. Landet lider. Metin Stenene skal[ENTER]\248del\230gges. G\229 til kaptajnen. "
gameforge.main_quest_lv27._30_say = "\216del\230ggelsen for\229rsaget af Metin Stenene er[ENTER]blevet v\230rre. Landet lider. Metin Stenene skal[ENTER]\248del\230gges. G\229 til kaptajnen. "
gameforge.main_quest_lv27._40_say = "Jeg h\248rte, at du har arbejdet meget h\229rdt. Folk[ENTER]har talt om dit gode arbejde. Du skylder mig[ENTER]noget for at sende dig til det rette sted. Ha,[ENTER]ha! Blive ikke irriteret, det var kun for sjov![ENTER]Du har gjort dit job rigtig godt.[ENTER][ENTER]Men der kommer flere og flere Metin Sten. Det er[ENTER]et alvorligt problem. "
gameforge.main_quest_lv27._50_say = "Hvis antallet af Metin Sten stiger, lider folk.[ENTER]Jeg undrer mig over om Shamanerne har ret og den[ENTER]onde Gud Sung Mahi virkelig er opstanden... Men[ENTER]f\248rst er vi n\248dt til at tage os af det[ENTER]indlysende. Lad mig vide, n\229r du har \248delagt en[ENTER]Metin Sten! "
gameforge.main_quest_lv27._60_sayTitle = "Mission: "
gameforge.main_quest_lv27._70_say = "Den metin-sten som du skal \248del\230gge er Skumlens[ENTER]Metin. S\248g den!  "
gameforge.main_quest_lv27._80_say = "Flere og flere Metin Sten er for nylig blevet[ENTER]observeret. Deres onde str\229ling skal stoppes![ENTER]\216del\230g en Skumlens Metin. "
gameforge.main_quest_lv27._90_say = "Du har \248delagt Skumlens Metin.[ENTER]Tilbage til kaptajnen. "
gameforge.main_quest_lv3 = {}
gameforge.main_quest_lv3._100_say = "V\230r hilset. Har byvagten sendt dig?[ENTER]Jeg har en nem opgave for dig. Min far har glemt[ENTER]en vigtig bog her. Han har brug for[ENTER]den.  "
gameforge.main_quest_lv3._10_npcChat = "Jeg har f\230rdiggjort den f\248rste opgave. "
gameforge.main_quest_lv3._110_say = "Kunne du aflevere bogen til min far?[ENTER]Jeg ville selv g\248re det, men jeg skal blive i[ENTER]butikken.[ENTER]Hvis du g\248rer det for ham, vil han vise dig[ENTER]taknemmelighed.[ENTER]Du skal vide, at han s\230lger rustninger i denne[ENTER]landsby.  "
gameforge.main_quest_lv3._120_sayItem = "Fremstilling af rustninger "
gameforge.main_quest_lv3._130_targetVid = "Find rustnings-handelsmanden "
gameforge.main_quest_lv3._140_sendLetter = "Aflever bogen "
gameforge.main_quest_lv3._150_sayReward = "Aflever bogen, som handelsdamens fader glemte,[ENTER]til ham. Det er rustnings-handelsmanden fra byen. "
gameforge.main_quest_lv3._160_sayTitle = "Rustnings-handelsmand: "
gameforge.main_quest_lv3._170_say = "Hvad f\248rer dig til mig?[ENTER]N\229 - min datter har sendt dig? Mange tak.[ENTER]Jeg har brug for denne bog s\229 jeg kan fremstille[ENTER]nye rustninger. "
gameforge.main_quest_lv3._180_say = "Min datter er nok meget optaget, n\229r hun sender[ENTER]dig for at aflevere bogen. Lad mig se.. Hvad[ENTER]kunne v\230re en passende bel\248nning til[ENTER]dig...?  "
gameforge.main_quest_lv3._190_say = "Som bel\248nning vil jeg give dig nogle Yang, s\229 du[ENTER]kan k\248be noget ordentligt udstyr til dig selv.[ENTER]Det skulle v\230re nok ikke? Mange tak. N\229r jeg har[ENTER]brug for hj\230lp igen vil jeg nok bede dig om endnu[ENTER]en tjeneste. Og n\229r du har brug for en ny[ENTER]rustning s\229 kom og bes\248g mig. Min butik er altid[ENTER]\229ben. "
gameforge.main_quest_lv3._200_sayReward = "Du har modtaget 850 erfaringspoint.[ENTER]Du har modtaget 5,000 Yang.[ENTER]Du har modtaget 20 Bl\229 Eliksirer. "
gameforge.main_quest_lv3._20_say = "Det ser ud som om du har haft det sjovt med at[ENTER]klare din f\248rste opgave. Venter du allerede p\229[ENTER]den n\230ste? S\248g mig n\229r du er n\229et n\230ste level. S\229[ENTER]vil jeg give dig et nyt job. "
gameforge.main_quest_lv3._30_sendLetter = "Meddelelse fra byvagten "
gameforge.main_quest_lv3._40_sayReward = "Stop med at jage og g\229 til byvagten.[ENTER]Han har en yderlig opgave til dig. "
gameforge.main_quest_lv3._50_say = "Jeg er glad for at du kom forbi. Du kender[ENTER]formentligt almindelige handelsdamen ved[ENTER]almindelige vare, ikke? Hun har bedt mig om noget[ENTER]hj\230lp. Kan du finde ud af hvad hun beh\248ver? Jeg[ENTER]h\229ber ikke det er noget seri\248st, men jeg er[ENTER]sikker p\229 at du kan hj\230lpe hende. "
gameforge.main_quest_lv3._60_say = "Til din information: Handeldamen s\230lger[ENTER]regenerative eliksirer og andre genstande som kan[ENTER]v\230re praktiske i fremtiden. S\229 det ville ikke[ENTER]skade at v\230re p\229 god jord hos hende! G\229 nu. "
gameforge.main_quest_lv3._70_targetVid = "Find handelsdamen "
gameforge.main_quest_lv3._80_sendLetter = "Hj\230lp handelsdamen "
gameforge.main_quest_lv3._90_sayReward = "G\229 til landhandlen, handelsdamen har brug for din[ENTER]hj\230lp. "
gameforge.main_quest_lv30 = {}
gameforge.main_quest_lv30._100_say = "Der er indskrifter p\229 sten s\248jlerne. Du tager[ENTER]hurtigt en kopi af dem. "
gameforge.main_quest_lv30._10_targetVid = "Find Uriel "
gameforge.main_quest_lv30._110_say = "Uriel havde ret: Der var virkelig indskriptioner[ENTER]i sten s\248jlerne. Du kunne ikke l\230se dem men i det[ENTER]mindste tage en kopi. Tag dine noter til Uriel. "
gameforge.main_quest_lv30._120_say = "Fandt du Hasun mindestenen? Ohh du har endda en[ENTER]kopi. Virkelig godt! Det er en unik historisk[ENTER]opdagelse! Lad os se.[ENTER]Hmm... Det ser ud til at det er information[ENTER]omkring Metin stenene. Jeg kan dog ikke afkode[ENTER]det hele. Det er skrevet p\229 virkelig gammeldags,[ENTER]nogen af bogstaverne ser n\230sten antikke ud. Hvad[ENTER]g\248r vi nu? "
gameforge.main_quest_lv30._130_say = "Ahh, jeg har en ide! Kender du Seungryong dalen?[ENTER]Der er et mystisk antikt sted. Hvis du finder[ENTER]gamle inskriptioner der, vil jeg m\229ske v\230re i[ENTER]stand til at drage nogle konklusioner omkring de[ENTER]manglende bogstaver. Drag til Seungryong dalen og[ENTER]se efter Seul Rong mindesstenene. "
gameforge.main_quest_lv30._140_targetVid = "Mindesten i Seungryong dalen. "
gameforge.main_quest_lv30._150_say = "Uriel den l\230rde har brug for flere antikke[ENTER]tekster for at drage konklusioner omkring nogen[ENTER]af de bogstaver han ikke kender.[ENTER]Drag til Seungryong dalen og se efter[ENTER]inskriptioner p\229 Seul Rong mindestenen. "
gameforge.main_quest_lv30._160_say = "Har du fundet flere inskriptioner? Ohh! Takket[ENTER]v\230re dig, vil jeg snart v\230re i stand til at l\248se[ENTER]hemmeligheden omkring Metin stenene. Mine[ENTER]unders\248gelser vil m\229ske give resultater endnu[ENTER]hurtigere end jeg troede. Tusind tak! Jeg vil[ENTER]lade dig det vide n\229r jeg har brug for din hj\230lp[ENTER]igen. Og her, tag venligst denne bel\248nning for[ENTER]dine anstrengelser. "
gameforge.main_quest_lv30._20_sendLetter = "Hemmelighederne om Metin stenene "
gameforge.main_quest_lv30._30_say = "Uriel har endelig klaret at f\229 nogle[ENTER]informationer om de hemmelige Metin sten. G\229 og[ENTER]find den l\230rde Uriel. "
gameforge.main_quest_lv30._40_sayTitle = "Uriel: "
gameforge.main_quest_lv30._50_say = "Kaptejnen har allerede sendt dig til mig en gang.[ENTER]Du virker til at v\230re meget talentfuld. Jeg har[ENTER]brug for en tjeneste. Du kender til Metin stenen,[ENTER]ikke? Metin stenene kom ned fra himlen. De[ENTER]udvikler ond energi og spreder sygdomme og f\229r[ENTER]dyrene til at g\229 amok. Vi ved ikke hvordan de er[ENTER]kommet ind i vores verden, og hvad de indeholder.[ENTER]Det g\248r min forskning meget sv\230re. Dog har jeg[ENTER]for nygenligt fundet n\248glen til hemmeligheden om[ENTER]Metin stenene. "
gameforge.main_quest_lv30._60_say = "Der er en tavle, et minde fra et antikt[ENTER]kongerige, i en hule i den lette Abe grotte. Jeg[ENTER]tror at informationen p\229 tavlen er omkring Metin[ENTER]stenenes hemmelighed. Bring mig venligst[ENTER]informationen fra Hasun stenminden i den lette[ENTER]Abe grotte! "
gameforge.main_quest_lv30._70_sayReward = "Du har modtaget 122.000 erfaringspoint.[ENTER]Du har modtaget 20.000 Yang.[ENTER]Du har modtaget et S\248lv armb\229nd. "
gameforge.main_quest_lv30._80_targetVid = "Sten minde i den lette Abe grotte. "
gameforge.main_quest_lv30._90_say = "Den l\230rde Uriel tror han har fundet et spor som[ENTER]m\229ske kan hj\230lpe ham med arbejdet med Metin[ENTER]stenene. Drag til den lette Abe grotte og se[ENTER]efter Hasun mindestenen. "
gameforge.main_quest_lv32 = {}
gameforge.main_quest_lv32._100_sayReward = "OBS: N\229r du rider p\229 hesten g\229r det hurtigere og[ENTER]er mere bekvemt. "
gameforge.main_quest_lv32._10_sendLetter = "Den hemmelige bog "
gameforge.main_quest_lv32._110_npcChat = "Siderne fra den hemmelige bog "
gameforge.main_quest_lv32._120_sayTitle = "Handelsmand: "
gameforge.main_quest_lv32._130_say = "Lige siden alle disse probelmer startede i[ENTER]verden, har handel v\230ret virkelig sv\230rt. Hvad[ENTER]\248nsker du at k\248be? Ohh, du er sendt fra den l\230rde[ENTER]Uriel? Han er regelm\230ssig kunde her, han leder[ENTER]altid efter antikke b\248ger fra forskellige steder.[ENTER]Det er faktisk lidt en plage. Ha, ha, ha. \216nsker[ENTER]du at vide mere om de antikke b\248ger? Hmm, antikke[ENTER]b\248ger... "
gameforge.main_quest_lv32._140_say = "Jeg har h\248rt noget for nogen dage siden, men jeg[ENTER]kan ikke give det videre til dig gratis! Hvis du[ENTER]kl\248r mig p\229 ryggen vil jeg kl\248 dig p\229 din, ehh?[ENTER]V\229ben handel er g\229et rimelig godt p\229 det sidste,[ENTER]men desv\230rre kan jeg bare ikke f\248lge med den[ENTER]store eftersp\248rgsel! Jeg bliver overrandt med[ENTER]ordre! Du st\229r bare her og laver ingen ting,[ENTER]hvorfor g\248r du ikke noget nyttigt til en forskel[ENTER]og f\229r fat i 20 s\248lv sv\230rd +0 til mig? S\229 snart[ENTER]du bringer dem til mig, vil jeg give dig[ENTER]informationen du \248nsker. "
gameforge.main_quest_lv32._150_targetVid = "Find handelsmanden "
gameforge.main_quest_lv32._160_sayTitle = "Du har 20 s\248lv sv\230rd +0 "
gameforge.main_quest_lv32._170_say = "Handelsmanden har h\248rt om de gamle sider. Giv ham[ENTER]20 s\248lvsv\230rd +0, s\229 vil han fort\230lle dig hvad han[ENTER]ved. "
gameforge.main_quest_lv32._180_sayTitle = "Find 20 s\248lv sv\230rd +0 "
gameforge.main_quest_lv32._190_say = "Handelsmanden har h\248rt om de gamle sider men vil[ENTER]ikke dele informationen for ingenting. Skaf 20[ENTER]S\248lvsv\230rd +0 og bring dem til handelsmanden for[ENTER]at f\229 informationerne. "
gameforge.main_quest_lv32._200_npcChat = "Jeg har f\229et fat i de sv\230rd "
gameforge.main_quest_lv32._20_targetVid = "S\248g den l\230rte Uriel "
gameforge.main_quest_lv32._210_say = "Godt. Du er mere talentet end jeg troede. Takket[ENTER]v\230re din hj\230lp, g\229r handlen meget bedre meget[ENTER]snart. Hvad din side ang\229r... For et par dage[ENTER]siden passerede jeg en pavillon og et minde ved[ENTER]siden af den. Jeg havde et hvil der og bem\230rkede[ENTER]dette stykke lasede papir i bunden af den. "
gameforge.main_quest_lv32._220_say = "P\229 det tidspunkt t\230nkte jeg ikke videre over det.[ENTER]Men nu tror jeg det kan have v\230ret en af de gamle[ENTER]sider du leder efter. Navnet p\229 mindesm\230rket,[ENTER]hmm... Var det Weol mindet? Ja, det var hvad det[ENTER]hed. Weol mindet n\230r den tilst\248dende by. Du[ENTER]skulle tage et kig der! "
gameforge.main_quest_lv32._230_sayTitle = "Handelsmand: "
gameforge.main_quest_lv32._240_say = "Aflever 20 s\248lv sv\230rd +0, ogs\229 f\229r du[ENTER]informationerne om de gamle sider. "
gameforge.main_quest_lv32._250_sendLetter = "S\248g efter den f\248rste side. "
gameforge.main_quest_lv32._260_targetVid = "Et minde ved siden af pavillonen "
gameforge.main_quest_lv32._270_say = "Handelsmanden har set en gammel side ved foden af[ENTER]Weol mindet da han havde et hvil i pavillonen ved[ENTER]siden af mindet.[ENTER]G\229 til Weol mindet n\230r den f\248rste by og se om det[ENTER]virkelig er siden du leder efter. "
gameforge.main_quest_lv32._280_npcChat = "Weol mindet "
gameforge.main_quest_lv32._290_say = "Der er mindet.[ENTER]Oh Der er den! Jeg har siden! "
gameforge.main_quest_lv32._300_sendLetter = "Den f\248rste side "
gameforge.main_quest_lv32._30_say = "Den l\230rde Uriel sp\248rger efter dig. Han har brug[ENTER]for hj\230lp med hans forskning omkring en gammel,[ENTER]hemmelig bog. Tag til Uriel og se hvad du kan[ENTER]g\248re for ham. "
gameforge.main_quest_lv32._310_targetVid = "S\248g den l\230rte Uriel "
gameforge.main_quest_lv32._320_sayTitle = "Fundet f\248rste side "
gameforge.main_quest_lv32._330_say = "Du har fundet den omvandrende handelsmands spor[ENTER]og har fundet den f\248rste manglende side. Bring[ENTER]den til den l\230rde Uriel. "
gameforge.main_quest_lv32._340_say = "S\229, fandt du den gamle side? Ohh, du har den,[ENTER]nice! Lad os se hvad der er skrevet p\229 den.[ENTER]Hmm... Det ligner en dagbog. H\248r "
gameforge.main_quest_lv32._350_sayTitle = "F\248rste bogside: "
gameforge.main_quest_lv32._360_sayReward = "Lee Seop fra Taejo kongeriget udvider sit[ENTER]territorium igennem erobringer. Han \248nsker at[ENTER]overtage et hvert land, med hans milit\230re magt.[ENTER]Vi er n\248d til at sikre at han ikke tager vores[ENTER]land. Vores muligheder er begr\230nsede da hans h\230r[ENTER]er s\229 stor og st\230rk. Det er grunden til vi har[ENTER]besluttet at bruge forbudt heksekr\230ft! "
gameforge.main_quest_lv32._370_sayTitle = "F\248rste bogside (forts\230ttelse): "
gameforge.main_quest_lv32._380_sayReward = "Dette er vores eneste chance for at overleve. Vi[ENTER]ved ikke om det ville blive en succes, men vi b\248r[ENTER]helt bestemt pr\248ve. Inden de angriber os, er vi[ENTER]n\248d til at f\229 informationer omkring den forbudte[ENTER]sorte heksekr\230ft. If\248lge legende, b\248r vi kunne[ENTER]finde ud af det i Drage dalen. "
gameforge.main_quest_lv32._390_say = "Fra indholdet kan jeg se at den antikke tro[ENTER]eksisterede i dette land. Inden Lee Seop fra[ENTER]Taejo kongeriget forener alle landene, alle lande[ENTER]har deres specielle karakteristikas. S\229 vidt jeg[ENTER]ved, har alle lande endda haft deres egen[ENTER]religi\248se tro. Forfatteren af denne bog virker[ENTER]til at have v\230ret rimelig uddannet. Han har[ENTER]formentligt tilh\248rt en af ordnerne eller har[ENTER]m\229ske endda v\230ret deres kaptajn. Ordens medlemmer[ENTER]blev betragtet som eliten i samfundet. "
gameforge.main_quest_lv32._400_say = "Der er blevet snakket en masse omkring de gamle[ENTER]historier om Drage Dalen. Jeg kender ogs\229 et par[ENTER]sagn omkring det. Vi er m\229ske endda stadig i[ENTER]stand til at finde informationer omkring den,[ENTER]eller m\229ske endda flere sider fra bogen. Jeg har[ENTER]desv\230rre aldrig fundet informationer omkring hvor[ENTER]denne Dal er. Tag til j\230geren Yang-Shin i nabo[ENTER]byen, han kender omr\229det virkelig godt. Han ved[ENTER]m\229ske hvor Drage Dalen er og om der er noget[ENTER]brugbart der kan findes der. "
gameforge.main_quest_lv32._40_say = "Velkommen.[ENTER]Dit arbejde sidste gang var meget brugbart. Med[ENTER]din hj\230lp, var jeg i stand til at g\248re nogle[ENTER]virkelig store fremskridt. Men nu har jeg et[ENTER]problem. Mens jeg har forsket i nogle[ENTER]informationer omkring meteorene, fandt jeg en[ENTER]gammel bog. S\229 vidt jeg kan forst\229, er der[ENTER]vigtige informationer omkring grunden til[ENTER]\230ndringerne der i, som p\229virker vores land.[ENTER]Det er virkelig vigtigt. "
gameforge.main_quest_lv32._410_say = "Hvor sp\230ndende! Ohh, inden jeg glemmer det: Her[ENTER]er din bel\248nning for den f\248rste side! "
gameforge.main_quest_lv32._420_sayReward = "Du modtager 1.000.000 erfaringspoint. "
gameforge.main_quest_lv32._430_sayReward = "Du har modtaget 50,000 Yang. "
gameforge.main_quest_lv32._440_sayReward = "Du har modtaget gudindens t\229re. "
gameforge.main_quest_lv32._450_sendLetter = "G\229 til j\230geren "
gameforge.main_quest_lv32._460_targetVid = "Find j\230geren Yang-Shin "
gameforge.main_quest_lv32._470_sayTitle = "Sp\248rg Yang-Shin omkring Drage dalen. "
gameforge.main_quest_lv32._480_say = "P\229 den f\248rste side i den hemmelige bog er Drage[ENTER]dalen n\230vnt. Uriel har h\248rt historier omkring den[ENTER]men ved ikke hvor den er. G\229 til nabo byen og[ENTER]sp\248rg efter j\230geren Yang-Shin om han kender mere[ENTER]til den. "
gameforge.main_quest_lv32._490_sayReward = "OBS: J\230geren findes i nabolandsbyen. "
gameforge.main_quest_lv32._500_npcChat = "Informationer om Dragedalen "
gameforge.main_quest_lv32._50_say = "Problemet er at bogen er meget gammel og \248delagt.[ENTER]Bogen er givet videre fra h\229nd til h\229nd i \229revis,[ENTER]hvilket formentligt er grunden til at den er s\229[ENTER]skadet. 13 sider mangler i bogen. Kan du finde[ENTER]dem til mig? Der er formentligt nogle[ENTER]informationer om hvordan krigen afsluttes p\229[ENTER]disse sider. "
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin: "
gameforge.main_quest_lv32._520_say = "Du \248nsker at vide hvor Drage dalen er? Det er et[ENTER]meget gammelt navn for Seungryong Dalen. Der er[ENTER]ingen drager der, men der er en stor m\230ngde orker[ENTER]og endda en hemmelig sekt lever der i stedet.[ENTER]Hvorfor \248nsker du at tage til s\229 farligt et sted?[ENTER]Selv jeg, en klog j\230ger, kan ikke lide at g\229 der.[ENTER]Det ville v\230re bedre hvis du holdte dig v\230k[ENTER]derfra. "
gameforge.main_quest_lv32._530_say = "Hvad? Du leder efter de gamle bog sider? Hmm! Jeg[ENTER]h\248rte engang fra en j\230ger at Ork troldmanden har[ENTER]nogen sider. Jeg overvejer om det er sandt?[ENTER]Hvis du er s\229 nysgerrige, s\229 g\229 og find ud af[ENTER]det. Jeg har allerede sagt at det er et farligt[ENTER]sted. Tag godt vare p\229 dig selv! "
gameforge.main_quest_lv32._540_sendLetter = "S\248g efter den anden side "
gameforge.main_quest_lv32._550_say = "Som j\230geren allerede har n\230vnt s\229 er de Stolte[ENTER]ork-troldm\230nd i besiddelse af den anden side af[ENTER]dagbogen. Dr\230b Stolt ork-troldm\230nd og hent den[ENTER]anden side.[ENTER]Aflever den til Uriel. "
gameforge.main_quest_lv32._560_sendLetter = "Den anden side "
gameforge.main_quest_lv32._570_sayTitle = "Anden side fundet "
gameforge.main_quest_lv32._580_say = "Jagten p\229 den stolte ork troldmand har v\230ret[ENTER]succes rig: Du har fundet den anden side af den[ENTER]hemmelige bog. Bring den til den l\230rde Uriel. "
gameforge.main_quest_lv32._590_say = "Er det den anden side?[ENTER]Lad mig se. Hm. Det er ikke nemt at l\230se. Der[ENTER]st\229r...  "
gameforge.main_quest_lv32._600_sayTitle = "Anden bogside: "
gameforge.main_quest_lv32._60_say = "S\229 snart du finder en af de gamle sider, s\229 bring[ENTER]den til mig. S\229 vil jeg pr\248ve at tyde den. Hmm...[ENTER]Hvor kunne du starte med at lede? Noget tid siden[ENTER]fortalte en handelsmand i nabolandsbyen mig at[ENTER]han havde fundet en gammel dagbogsside. G\229 til[ENTER]ham og se hvad du kan finde ud af. "
gameforge.main_quest_lv32._610_sayReward = "De m\248rke magikeres f\248lgere er blevet fundet.[ENTER]De var gemt i Drage dalen. De er meget informeret[ENTER]omkring heksekr\230fter som er blevet videregivet[ENTER]igennem mange \229r. Det tog os en masse[ENTER]overbevisning, nogle trusler og en smule smiger[ENTER]inden de gik med til at hj\230lp os. Og resultatet[ENTER]var: Du har brug for et specielt sted for at[ENTER]udf\248re forbudt heksekr\230fter. Stedet skal v\230re[ENTER]fuld af ond energi. Tiden l\248ber ud, s\229 jeg er n\248d[ENTER]til at finde et passende sted s\229 hurtigt som[ENTER]muligt. "
gameforge.main_quest_lv32._620_say = "Hmm, vi har brug for et sted fuld af negativ[ENTER]energi til sort heksekr\230fter. Et sted hvor alt[ENTER]kan forvandlet til ond energi. Hmm.... Hvor kan[ENTER]vi finde s\229dan et sted? Hmm... Hmm... Jeg ved[ENTER]det, det kunne v\230re Hwang templet! Folket kalder[ENTER]det ikke M\248rkets tempel for ingen ting. Det er et[ENTER]sted hvor ingen god hjertet \248nsker at drage til.[ENTER]Selv dyr \248nsker ikke at v\230re der. Og den[ENTER]hemmelige sekt er ikke ude p\229 noget godt. "
gameforge.main_quest_lv32._630_say = "Ydermere er der en sammenh\230ng imellem de forbudte[ENTER]heksekr\230fter og den hemmelige sekt. Du kan finde[ENTER]n\248glen til det i Hwang Templet. Find ud af hvad[ENTER]der sker i Hwang Templet og se om du kan finde[ENTER]flere bog sider der![ENTER]Her er din bel\248nning for den anden side... "
gameforge.main_quest_lv32._640_sayReward = "Du modtager 1.000.000 erfaringspoint. "
gameforge.main_quest_lv32._650_sayReward = "Du har modtaget 50,000 Yang. "
gameforge.main_quest_lv32._660_sayReward = "Du har f\229et et hvidt flag "
gameforge.main_quest_lv32._670_sendLetter = "Den tredje side "
gameforge.main_quest_lv32._680_say = "Du har bragt de f\248rste to sider af den f\248rste bog[ENTER]til Uriel. Den n\230ste side kan findes i Hwang[ENTER]Templet. "
gameforge.main_quest_lv32._690_sayReward = "OBS: Denne serie af opgaver vil forts\230tte n\229r du[ENTER]har n\229et level 40. "
gameforge.main_quest_lv32._70_targetVid = "G\229 til handelsmanden "
gameforge.main_quest_lv32._80_sayTitle = "S\248g siderne fra den hemmelige bog "
gameforge.main_quest_lv32._90_say = "Den l\230rte Uriel sagde at han havde h\248rt noget om[ENTER]en handelsmand med en gammel dagbogsside. G\229 til[ENTER]handelsmanden og sp\248rg ham om det. Du vil finde[ENTER]ham i den anden landsby. "
