gameforge.main_quest_lv40._120_sayReward = "Ydermere har du f\229et livets velsignelse. "
gameforge.main_quest_lv40._130_sendLetter = "Afsted til Yongbi-\248rkenen "
gameforge.main_quest_lv40._140_targetVid = "S\248gning af mindet "
gameforge.main_quest_lv40._150_targetVid = "S\248gning af Wha mindet "
gameforge.main_quest_lv40._160_sayTitle = "S\248g efter den fjerde side "
gameforge.main_quest_lv40._170_say = "Den l\230rte Uriel tror, at man kan finde en[ENTER]yderligere side i abe-grotten i Yongbi-\248rkenen.[ENTER]Der findes et minde, m\229ske kan den fjerde side[ENTER]findes d\233r.[ENTER]G\229 til Yongbi-\248rkenen og s\248g efter mindet i[ENTER]abe-grotten.[ENTER]Obs: Gennem vagten i Yongi-\248rkenen kan du f\229[ENTER]adgang til abe-grotten.  "
gameforge.main_quest_lv40._180_say = "Det er wha mindet "
gameforge.main_quest_lv40._190_say = "Men der er ingen gammel dagbogs side at se. Jeg[ENTER]er n\248d til at komme videre og finde et andet[ENTER]minde. "
gameforge.main_quest_lv40._200_npcChat = "S\248gning efter Su mindet "
gameforge.main_quest_lv40._20_say = "Den l\230rde Uriel leder efter gamle dagbogs sider.[ENTER]Du har allerede bragt ham to af dem. Nu[ENTER]forts\230tter den sp\230ndende jagt efter den hemmelige[ENTER]gamle bog. Opdagelserne har indtil videre[ENTER]indikeret at den stolte m\248rke fanatiker der bor i[ENTER]Hwang Templet har n\230ste side.[ENTER]Drag p\229 vej! "
gameforge.main_quest_lv40._210_say = "Det er det! Su mindet. "
gameforge.main_quest_lv40._220_say = "Men der er ingen gammel dagbogs side at se. Jeg[ENTER]er n\248d til at komme videre og finde et andet[ENTER]minde. "
gameforge.main_quest_lv40._230_sendLetter = "Den fjerde side "
gameforge.main_quest_lv40._240_sayTitle = "Fundet den fjerde side "
gameforge.main_quest_lv40._250_say = "Det antikke minde viste sig at v\230re trofaste[ENTER]vogtere af deres skatte: du har fundet den fjerde[ENTER]gamle side i Jungsun Dong. Bring den til den[ENTER]l\230rde Uriel. "
gameforge.main_quest_lv40._260_npcChat = "Den fjerde gamle side "
gameforge.main_quest_lv40._270_say = "Ohh! Du har fundet den fjerde gamle side.[ENTER]Forh\229bentlig vil det give os noget nyt indsigt[ENTER]med de nye informationer vi har modtaget fra[ENTER]bogen. "
gameforge.main_quest_lv40._280_sayTitle = "Fjerde side: "
gameforge.main_quest_lv40._290_sayReward = "Nu er jeg i den dybe hule hvor aberne lever.[ENTER]Mine f\248lgesvende er lamsl\229ede, men den d\229rlige[ENTER]energi vi har samlet her er stadig[ENTER]utilstr\230kkeligt. Tiden g\229r stadig alt for hurtigt[ENTER]og Lee Seops kavaleri kommer t\230ttere og t\230ttere[ENTER]p\229. Jeg overvejer om vi vil n\229 det i tide? "
gameforge.main_quest_lv40._300_sayTitle = "Fjerde side fortsat: "
gameforge.main_quest_lv40._30_sayTitle = "Fundet den tredje side "
gameforge.main_quest_lv40._310_sayReward = "Jeg er n\248d til at finde den n\230ste placering s\229[ENTER]hurtigt som muligt. Ingen ting er tabt endnu. Jeg[ENTER]vil pr\248ve Edderkoppen grotten. Denne gang bliver[ENTER]vores \248nske m\229ske endda opfyldt. "
gameforge.main_quest_lv40._320_say = "Hmm. Abegrotten er ikke det sted vi s\248ger. S\229 lad[ENTER]os pr\248ve igen! If\248lge hvad der st\229r her, skal vi[ENTER]tage til Edderkoppe hulen. Men f\248rst er vi n\248d[ENTER]til at rette opm\230rksom heden mod en mere[ENTER]presserende aff\230re: Kaptajnen er meget bange da[ENTER]en masse fremmede h\230nger ud n\230r landsbyen og[ENTER]sp\248rger om m\230rkelige sp\248rgsm\229l. Du skulle g\229 ud[ENTER]og se hvad der sker der. "
gameforge.main_quest_lv40._330_say = "Hele situationen g\248r mig usikker. Lad os se hvad[ENTER]kaptajnen siger. Ohh, inden jeg glemmer det: Her[ENTER]er din bel\248nning for den fjerde side. "
gameforge.main_quest_lv40._340_sayReward = "Du har modtaget 2.000.000 erfaringspoints. "
gameforge.main_quest_lv40._350_sayReward = "Fristelsesmiddel f\229et "
gameforge.main_quest_lv40._360_sendLetter = "De uhyggelige fremmede "
gameforge.main_quest_lv40._370_targetVid = "G\229 til Kaptajnen "
gameforge.main_quest_lv40._380_sayTitle = "F\229 noget at vide om de fremmede af kaptajnen "
gameforge.main_quest_lv40._390_say = "Rygter siger at en masse fremmede dukker op i[ENTER]landsbyen. De sp\248ger om mist\230nksomme sp\248rgsm\229l[ENTER]omkring mindet. Kaptajnen \248nsker at g\248re noget[ENTER]ved det. G\229 og se ham og find ud af mere. "
gameforge.main_quest_lv40._400_npcChat = "De fremmede i landsbyen "
gameforge.main_quest_lv40._40_say = "Den l\230rde Uriels formodninger omkring den stolte[ENTER]m\248rke fanatiker var korrekte. Du har fundet den[ENTER]tredje dagbogs side i deres besiddelse. Tag siden[ENTER]til Den l\230rde Uriel. "
gameforge.main_quest_lv40._410_say = "Der er et st\248t stigende antal fremmede der kommer[ENTER]til byen. De sp\248ger om mindet og antikke b\248ger.[ENTER]Nogen mennesker kender til det, men de \248nsker[ENTER]ikke at fort\230lle det til fremmede. Jeg er bange[ENTER]for det m\229ske kan f\229 os alle i problemer. Ingen[ENTER]ved hvem der har sendt disse fremmede og hvor[ENTER]langt de vil g\229 for at f\229 deres informationer. Vi[ENTER]er jo efter alt stadig i krig. "
gameforge.main_quest_lv40._420_say = "Hvis min kilde er korrekt, Nakajuma fra nabo byen[ENTER]har noget at g\248re med det.[ENTER]Fors\248g venligst at finde ud af fra ham hvad de[ENTER]fremmede \248nsker her. "
gameforge.main_quest_lv40._430_sendLetter = "S\248g Nakajima "
gameforge.main_quest_lv40._440_say = "Kaptajnen tror der er forbindelse mellem Nakajima[ENTER]og de fremmede som sp\248ger alle steder i byen om[ENTER]minderne. G\229 til Nakajuma og find ud af hvad han[ENTER]ved. Du vil finde ham i yderkanten af den anden[ENTER]by. "
gameforge.main_quest_lv40._450_npcChat = "Kender du de fremmede i byen? "
gameforge.main_quest_lv40._460_sayTitle = "Nakajima: "
gameforge.main_quest_lv40._470_say = "Undskyld mig? Hvad slags sp\248rgsm\229l er det? Jeg er[ENTER]ked af det. Jeg kan ikke hj\230lpe dig. Jeg har ikke[ENTER]den mindste anelse om hvad du taler om. Nej, nej.[ENTER]Det er h\229rdt nok at finde arbejde i \248jeblikket[ENTER]som det er. Hvad er det meningen jeg skal leve[ENTER]af, ehh? "
gameforge.main_quest_lv40._480_say = "Ohh well, jeg indr\248mmer det. Men jeg indvilligede[ENTER]kun i det fordi de lovede mig en masse Yang.[ENTER]Jeg ved ikke hvad de fremmede \248nskede her. Men de[ENTER]har givet mig en mission: Det er meningen jeg[ENTER]skal dr\230be den brutale kaptajn. "
gameforge.main_quest_lv40._490_say = "Du kan formentligt finde ud af mere om den[ENTER]brutale kaptajn. Den fremmede \248nsker virkelig at[ENTER]jeg dr\230bte ham. Ohh, jeg har en god ide: Hvorfor[ENTER]g\229r du ikke ud og dr\230ber ham for mig? Vil du? "
gameforge.main_quest_lv40._500_sendLetter = "Dr\230b de brutale kaptajner "
gameforge.main_quest_lv40._50_say = "Oh, du har fundet den n\230ste information?![ENTER]Det er den tredje side.[ENTER]Lad mig se, hvad der st\229r. "
gameforge.main_quest_lv40._510_say = "Nakajima har indr\248mmet at de fremmede \248nsker at[ENTER]dr\230be den brutale kaptajn. Da de fremmede har[ENTER]spurgt omkring om dagbogs siderne, m\229 den brutale[ENTER]kaptajn tydeligvis have en af disse sider.[ENTER]for at finde ud af mere, er jeg n\248d til at dr\230be[ENTER]den brutale kaptajn. De kan findes uden for den[ENTER]anden by. "
gameforge.main_quest_lv40._520_sendLetter = "Fundet den femte side "
gameforge.main_quest_lv40._530_say = "Jeg kom dertil inden de fremmede og tog den femte[ENTER]dagbogs side fra den brutale kaptajn. Jeg er[ENTER]sikker p\229 at de fremmede vil forsvinde nu hvor[ENTER]der ikke er noget tilbage til dem at finde her.[ENTER]Jeg m\229 hellere bringe denne side til den l\230rde[ENTER]Uriel s\229 han kan afkode den. "
gameforge.main_quest_lv40._540_sayTitle = "Den femte side "
gameforge.main_quest_lv40._550_sayReward = "Obs: Du kan f\248rst aflevere den femte side fra den[ENTER]hemmelige bog til Uriel, n\229r du har opn\229et Level[ENTER]47. Pas indtil da godt p\229 siden. "
gameforge.main_quest_lv40._60_sayTitle = "Tredje side: "
gameforge.main_quest_lv40._70_sayReward = "Vi har fundet et omr\229de der er styret af ond m\248rk[ENTER]energi. Men det er ikke nok. Stedet er ondt, men[ENTER]det er ikke hensigtsm\230ssigt til at ud\248ve magi,[ENTER]hvilket er et stort nederlag. Men vores spioner[ENTER]snakker om et gemt sted i \248rkenen der kunne v\230re[ENTER]lovende for os. Vi vil drage dertil nu, og er[ENTER]meget optimistiske. "
gameforge.main_quest_lv40._80_say = "S\229 de var ikke istand til at n\229 m\229let i Drage[ENTER]dalen. Hmm... Yongbi \248rkenen? Du m\248der sj\230ldent[ENTER]nogen der, og omr\229det er n\230sten uudforsket. Men[ENTER]dette er alt sammen meget kompliceret. Hvor[ENTER]pr\230cis er det omr\229de de taler om? Jeg formoder at[ENTER]de mener Abe grotten Jungsun Dong. Det er en dyb[ENTER]grotte som er meget godt udrustet til at samle[ENTER]m\248rk energi. "
gameforge.main_quest_lv40._90_say = "G\229 venligst til Jungsun Dong og se efter sten[ENTER]mindet. Med en smule held kan du finde flere[ENTER]sider n\230r mindet. Ohh, vi skal selvf\248lgelig ikke[ENTER]glemme bel\248nningen for den tredje side. "
gameforge.main_quest_lv47 = {}
gameforge.main_quest_lv47._100_sayTitle = "Siden i edderkoppe-grotten "
gameforge.main_quest_lv47._10_sayTitle = "Siden fra den brutale kaptajn "
gameforge.main_quest_lv47._110_say = "Uriel tror at yderligere information omkring m\248rk[ENTER]heksekr\230ft kan findes i edderkoppe grotten. M\229ske[ENTER]vil vi finde et minde som det i abe grotten der[ENTER]ogs\229.[ENTER]Du kan komme til edderkoppe-grotten via Yongi[ENTER]\248rkenen. "
gameforge.main_quest_lv47._120_npcChat = "Mok mindet "
gameforge.main_quest_lv47._130_say = "Virkelig! Her er et minde og ogs\229 en dagbogs[ENTER]side. Hurtigt tilbage til Uriel. "
gameforge.main_quest_lv47._140_sayTitle = "Fundet den sjette side "
gameforge.main_quest_lv47._150_say = "Du har fundet endnu et gammelt minde i edderkoppe[ENTER]grotten og ogs\229 den sjette dagbogs side som var[ENTER]gemt der. Bring den til den l\230rde Uriel. "
gameforge.main_quest_lv47._160_npcChat = "Den sjette side "
gameforge.main_quest_lv47._170_say = "Hvordan var edderkoppe grotten? Fandt du den[ENTER]sjette side? Det er fantastisk! Jeg var bange for[ENTER]at du m\229ske var for sent p\229 den. Vi h\248re altid om[ENTER]andre folk som ogs\229 s\248ger hemmelighederne omkring[ENTER]de m\248rke heksekr\230fter. Det virker til at v\230re[ENTER]meget vigtig information. Lad os se hvad denne[ENTER]side siger. "
gameforge.main_quest_lv47._180_say = "Ohh nej, denne side er meget sv\230r at l\230se. Det[ENTER]kommer til at tage l\230nge tid end normalt at[ENTER]afkode den her. Men dens indhold ser ud til at[ENTER]v\230re meget vigtig. Dette symbol betyder 'm\248rk[ENTER]heksekr\230ft', s\229 vi er klar p\229 det rigtige spor.[ENTER]Jeg vil gerne vide hvorfor m\248rke heksekr\230fter er[ENTER]blevet forbudt. Der er formentlig en god grund[ENTER]til det. "
gameforge.main_quest_lv47._190_say = "Mens jeg fors\248ger at afkode denne side, b\248r du g\229[ENTER]til musikeren Yu-Hwan. Jeg har h\248rt at han har[ENTER]nogen interessante informationer til vores[ENTER]s\248gning. N\229r du kommer tilbage, vil jeg v\230re i[ENTER]stand til at fort\230lle hvad denne side siger. Men[ENTER]selvf\248lgelig vil du f\229 din bel\248nning nu. "
gameforge.main_quest_lv47._200_sayReward = "Du har modtaget 3.000.000 erfaringspoints! "
gameforge.main_quest_lv47._20_say = "Ved level 40, klarede du at f\229 fat i den femte[ENTER]side af den hemmelige dagbog fra den brutale[ENTER]kaptajn. Tag nu til Uriel. "
gameforge.main_quest_lv47._210_sayReward = "Du har f\229et 75.000 Yang "
gameforge.main_quest_lv47._220_sayReward = "Du har modtaget dragens velsignelse. "
gameforge.main_quest_lv47._230_sendLetter = "G\229 til Yu-Hwan "
gameforge.main_quest_lv47._240_targetVid = "S\248g Musikeren Yu-Hwan "
gameforge.main_quest_lv47._250_sayTitle = "De hemmelige kr\230fter "
gameforge.main_quest_lv47._260_say = "Musikeren Yu-Hwan har m\229ske nogle informationer[ENTER]omkring de gamle dagbogs sider. G\229 ud og se ham[ENTER]og sp\248rg ham om det. "
gameforge.main_quest_lv47._270_npcChat = "Noget nyt? "
gameforge.main_quest_lv47._280_say = "Nyd livet, for det er meget kort![ENTER]Trallalaaa... Ahh, der er du igen. Du kommer[ENTER]formentligt lige fra den l\230rde Uriel. Han spurgte[ENTER]om jeg kunne sp\248rge lidt omkring. Jeg har fundet[ENTER]ud af at i alle kongeriger har folk g\229et rundt og[ENTER]ledt efter vigtige dokumenter.[ENTER]Desv\230rre har ingen kunne fort\230lle mig hvad det[ENTER]hele pr\230sis er omkring. "
gameforge.main_quest_lv47._290_say = "Det er en smule underligt at disse m\230rkelige[ENTER]krybartige skikkelser h\230nger her omkring mens vi[ENTER]er i krig. Dig ekskluderet, selvf\248lgelig! Jeg har[ENTER]ogs\229 h\248rt at \248rkenbanditterne har v\230ret i stand[ENTER]til at f\229 fat i noget der kunne v\230re rimelig[ENTER]vigtigt for os. M\229ske skulle du pr\248ve at se hvad[ENTER]du kan f\229 ud af dem. "
gameforge.main_quest_lv47._300_say = "\216rkenbanditterne er temmelig farlige v\230sner, s\229[ENTER]pas p\229. Men jeg tror det vil v\230re det v\230rd. Jeg[ENTER]vil dedikere en sang til dig, og betro vinden[ENTER]den, s\229 den kan f\248lge dig ind i \248rkenen. "
gameforge.main_quest_lv47._30_npcChat = "Den femte side "
gameforge.main_quest_lv47._310_sendLetter = "\216rkenbanditterne "
gameforge.main_quest_lv47._320_sayTitle = "S\248gningen efter de hemmelige informationer "
gameforge.main_quest_lv47._330_say = "Uriel har brug for alt information omkring sort[ENTER]heksekr\230fter. Yu-Hwan, musikeren, sagde at[ENTER]\248rkenbanditterne stjal nogen ting der kunne havde[ENTER]hjulpet os. Jeg burde g\229 nu og dr\230be et par[ENTER]\248rkenbanditter. "
gameforge.main_quest_lv47._340_sendLetter = "Fundet den syvende side "
gameforge.main_quest_lv47._350_targetVid = "S\248gning efter musikeren Yu-Hwan "
gameforge.main_quest_lv47._360_say = "Takket v\230re informationen musikeren Yu-Hwan gav[ENTER]dig, var du istand til at finde den syvende ide[ENTER]af den hemmelige bog ved \216rkenbanditterne. G\229 til[ENTER]Yu-Hwan og fort\230l ham at hans informationer var[ENTER]korrekte. "
gameforge.main_quest_lv47._370_say = "Dine \248jne er s\229 smukke som en bjergs\248 lalalala...[ENTER]Ah - det er dig igen. Var det en succesfuld tur[ENTER]til \248rkenbanditterne? Hvad, var det alt? Et[ENTER]gammelt stykke papir? Det kan jeg ikke bruge til[ENTER]noget. Men hvis det g\248r dig glad... Bring det til[ENTER]Uriel. Og send ham mine bedste \248nsker! "
gameforge.main_quest_lv47._380_sendLetter = "G\229 til Uriel. "
gameforge.main_quest_lv47._390_targetVid = "G\229 til Uriel. "
gameforge.main_quest_lv47._400_sayTitle = "Den syvende side "
gameforge.main_quest_lv47._40_say = "Du har f\229et den femte side? Ufatteligt. Du er[ENTER]virkelig heldig at disse sider eksistere efter s\229[ENTER]mange \229r. Du er virkelig kyndig. Lad os nu se[ENTER]hvad denne side siger. "
gameforge.main_quest_lv47._410_say = "Du har fundet den syvende side af den gamle[ENTER]dagbog. Bring den til Uriel. "
gameforge.main_quest_lv47._420_say = "Hey, godt at se dig igen! Jeg har gode nyheder:[ENTER]Jeg har f\230rdiggjort dekrypteringen af den sjette[ENTER]side. Ikke d\229rligt, hva? Jeg m\229 indr\248mme at jeg[ENTER]er temmelig stolt af mig selv. For det der[ENTER]virkelig fangede mit blik, var at dette tegn...[ENTER]Undskyld mig? Har du fundet endnu en? Du godeste![ENTER]Det var virkelig hurtigt. Vis mig. Wow, hvor fik[ENTER]du den fra? Hvis ikke jeg tager fejl, var det[ENTER]tegnene der blev brugt af Imperial familien. "
gameforge.main_quest_lv47._430_say = "Siden disse tegn meget sj\230lden er brugt, og kun[ENTER]af ganske f\229 personer, er det meget sv\230rt at[ENTER]overs\230tte dem. Men jeg g\229r ud fra at lidt[ENTER]udfordring aldrig har skadet nogen, haha! Jeg ser[ENTER]frem til det. \216rkenbanditterne stjal dette fra de[ENTER]mystiske fremmed? Hmm... Betyder det at de[ENTER]fremmede forst\229r disse tegn? Dette er ved at[ENTER]blive s\229 forvirrende. Vi er n\248d til at sikre os[ENTER]at vi ikke overser noget. "
gameforge.main_quest_lv47._440_say = "Ohh ja, overser: Inden jeg koncentrere mig om den[ENTER]n\230ste side, b\248r jeg nok fort\230lle dig hvad der var[ENTER]p\229 den sjette side. Hrm-hrm... "
gameforge.main_quest_lv47._450_sayTitle = "sjette side: "
gameforge.main_quest_lv47._460_sayReward = "Tiden l\248ber ud. Nu har vi endda fors\248gt at bruge[ENTER]m\248rke heksekr\230fter i Edderkoppe grotten og det[ENTER]virker stadig ikke.[ENTER]Hvad overser vi? Nogen af vores mystikere tror at[ENTER]de m\248rke heksekr\230fter kr\230ver st\248re ofre.[ENTER]Hvis det er sandt m\229 det v\230re en ekstremt[ENTER]magtfuld kraft. "
gameforge.main_quest_lv47._470_sayReward = "If\248lge eventyr og legender, kr\230ver denne type[ENTER]magi altid menneskelige ofringer. Men hvis jeg[ENTER]dr\230ber deres k\230re ved alteret, vil mit ry iblandt[ENTER]folk blive virkelig skadet. Vi har brug for en[ENTER]passende stedfortr\230der. Lad os pr\248ve med Slange[ENTER]sv\230rdkrigerne fra \248rkenen. "
gameforge.main_quest_lv47._480_say = "Aha. S\229 fordi de ikke kunne ofre mennesker,[ENTER]besluttede de at bruge Slange krigere. Jeg kan[ENTER]ikke lade som om jeg kan lide denne nye[ENTER]udvikling. Det kommer til at blive barbarisk...[ENTER]Vi har dog stadig behov for at f\248lge deres spor.[ENTER]G\229 ud i \248rkenen og dr\230b nogle Slange sv\230rdkrigere[ENTER]og Slange bueskytter. Hvem ved hvad vi ellers[ENTER]m\229ske finder der. Forresten: Din bel\248nning er i[ENTER]denne pung! "
gameforge.main_quest_lv47._490_sendLetter = "Dr\230b slangev\230sener "
gameforge.main_quest_lv47._500_sayTitle = "Den ottende side "
gameforge.main_quest_lv47._50_sayTitle = "Femte side: "
gameforge.main_quest_lv47._510_say = "Dagbogen beskriver fors\248get p\229 at ofre Slange[ENTER]sv\230rdkrigere og Slange bueskytter for at udf\248re[ENTER]sort heksekunst. Drag til Yongbi \216rkenen og dr\230b[ENTER]Slange sv\230rdkrigere. Hold udkig efter flere[ENTER]informationer. "
gameforge.main_quest_lv47._520_sendLetter = "Fundet den ottende side "
gameforge.main_quest_lv47._530_targetVid = "G\229 til Uriel den l\230rte "
gameforge.main_quest_lv47._540_say = "Du har fundet den ottende side af dagbogen med[ENTER]Slange sv\230rdkrigerne i \248rkenen. Tag det til den[ENTER]l\230rde Uriel. "
gameforge.main_quest_lv47._550_say = "Det er den ottende side. Meget godt. Siden den er[ENTER]meget kort, tror jeg jeg kan l\230se den med det[ENTER]samme. Vent venligst et \248jeblik... Ahh, ja. "
gameforge.main_quest_lv47._560_sayTitle = "Ottende side: "
gameforge.main_quest_lv47._570_sayReward = "De n\248dvendige ofre fundet. Vi er heldige. Jeg[ENTER]overvejer om det er et tegn? Vi har brug for en[ENTER]ceremoniel klokke. Hvis jeg husker rigtigt har[ENTER]Edderkopperne noget i den stil. Well drag videre[ENTER]nu. "
gameforge.main_quest_lv47._580_say = "Ahh, Edderkoppe grotten igen, underligt. Du er[ENTER]n\248d til at drage dertil og se efter klokken. Det[ENTER]kommer til at blive en udmattende rejse, s\229 slap[ENTER]lidt af f\248rst og kom tilbage senere. Jeg skal[ENTER]lige have mig en t\230nkepause, og have oversat[ENTER]nogle flere dele. Og bare rolig, selvf\248lgelig vil[ENTER]du f\229 din bel\248nning for den ottende side nu. "
gameforge.main_quest_lv47._590_sayReward = "Du har f\229et 3.000.000 erfaringspoints[ENTER]Du har f\229et 70.000 Yang[ENTER]Du har f\229et tapperhedens kappe[ENTER]Obs: For n\230ste opgave skal du mindst have opn\229et[ENTER]level 50. "
gameforge.main_quest_lv47._60_sayReward = "Lee Seop er ankommet til Taejo kongeriget med[ENTER]hans kavaleri, men virker til at vil blive der en[ENTER]tid. I mellemtiden regner b\229de store og sm\229[ENTER]meteorer ned over landet. De er skyld i kaos,[ENTER]destruktioner og konflikter. Det veldige[ENTER]kongerige er blevet delt i tre mindre kongeriger.[ENTER]De k\230mper ogs\229 imod hinanden, i stedet for at[ENTER]bek\230mpe ondskaben sammen. Drageguden taler ikke[ENTER]til os mere heller. Nogen gange holder han med[ENTER]den ene gruppe andre gange den anden. Selv om[ENTER]alle k\230mper om hans st\248tte og i mellemtiden[ENTER]bliver katastrofen bare v\230rre og v\230rre. "
gameforge.main_quest_lv47._70_sayTitle = "Uriel: "
gameforge.main_quest_lv47._80_say = "Et \248jenidende forklare om vores tidlige dage.[ENTER]Helt uvurderligt! Ohh yeah, betaling. Her er en[ENTER]bel\248nning for dit fremragende arbejde. Og noget[ENTER]andet: En anden har helt sikkert gang i den samme[ENTER]unders\248gelse som vi har. S\229 vi har ingen tid at[ENTER]spilde. I bunden af denne side st\229r der at Lee[ENTER]Seop har ledt efter m\248rk energi i edderkoppe[ENTER]grotten. Hvis du finder noget der, s\229 kom og se[ENTER]mig med det samme.[ENTER]Jeg kan ikke vente! "
gameforge.main_quest_lv47._90_sendLetter = "Den sjette side "
gameforge.main_quest_lv50 = {}
gameforge.main_quest_lv50._100_say = "Hey, ikke s\229 hurtigt, Brushoved! Glem ikke din[ENTER]bel\248nning for den niende side! "
gameforge.main_quest_lv50._10_sayTitle = "Dr\230b Stolt soldatgiftedderkop "
gameforge.main_quest_lv50._110_sayReward = "Du modtager 5.000.000 erfaringspoint. "
gameforge.main_quest_lv50._120_sayReward = "Du har modtaget 125,000 Yang. "
gameforge.main_quest_lv50._130_sayReward = "Du har modtaget Den Viise Kejsers Symbol "
gameforge.main_quest_lv50._140_sendLetter = "Sporet er i Island "
gameforge.main_quest_lv50._150_targetVid = "Den gamle kiste med papirer "
gameforge.main_quest_lv50._160_sayTitle = "S\248g den gamle kiste med papirerne "
gameforge.main_quest_lv50._170_say = "P\229 Bjerget Sohan er de fjendtlige h\230re endelig[ENTER]st\248dt p\229 hinanden. Kig efter yderligere dagbogs[ENTER]sider eller andet skriftligt materiale om[ENTER]forl\248bet af kampen. "
gameforge.main_quest_lv50._180_npcChat = "En gammel kiste med papir "
gameforge.main_quest_lv50._190_say = "Disse er milit\230re planer og noter.[ENTER]Og her er en anden dagbog side![ENTER]Jeg vil tage det til Uriel. "
gameforge.main_quest_lv50._200_sendLetter = "Den tiende side "
gameforge.main_quest_lv50._20_say = "Vores tidligere forskning viser, at der er spor i[ENTER]Edderkoppe-grotten. Fang Stolt soldatgiftedderkop[ENTER]i Kuahlo Dong. Hvis du finder den anden side fra[ENTER]den gamle bog s\229 tag den til Uriel den l\230rde. "
gameforge.main_quest_lv50._210_sayTitle = "Fundet den fjerde side "
gameforge.main_quest_lv50._220_say = "Du har fundet den tiende side af den hemmelige[ENTER]dagbog i Island. Den var i en gammel kasse med[ENTER]papirer. Tag den til Uriel. "
gameforge.main_quest_lv50._230_say = "Ah, du har fundet den forsvundne tiende Dagbog[ENTER]side!Storartet, vi n\230rmere os slutningen af[ENTER]historien. Det er godt de dokumenterede alt[ENTER]ellers ville denne viden g\229 tabt. Lad os se hvad[ENTER]siden siger. "
gameforge.main_quest_lv50._235_sayTitle = "Tiende Side: "
gameforge.main_quest_lv50._240_sayReward = "Det er lykkedes os at afvise det f\248rste angreb.[ENTER]Men det n\230ste vil snart f\248lge. Terr\230net er et[ENTER]handicap for Lee Seops tunge jern soldater og det[ENTER]vil give os nogle fordele, men de er bare alt for[ENTER]mange. Vi kan ikke vinde. Vi har kun en sidste[ENTER]chance, afslutte vores sorte trolddom forskning.[ENTER]Under d\230kke af m\248rket vi vil tr\230nge ind p\229[ENTER]fjendens linjer og g\229 tilbage til[ENTER]Edderkoppe-grotten. Jeg vil bede. Ikke for[ENTER]sejren, men for en lille smule h\229b ... "
gameforge.main_quest_lv50._250_say = "Ooohh. Jeg tror, at vi er der n\230sten! Snart vil[ENTER]vi finde ud af, hvad sorte trolddom handler om.[ENTER]Jeg kan ikke vente! Du er n\248dt til at vende[ENTER]tilbage til Edderkoppe-grotten en gang mere.[ENTER]Forh\229bentlig er ellevte side af bogen der. "
gameforge.main_quest_lv50._260_say = "Og her er - igen - din velfortjente bel\248nning! "
gameforge.main_quest_lv50._270_sayReward = "Du har modtaget 5,500,000 erfaringspoints. "
gameforge.main_quest_lv50._280_sayReward = "Du har modtaget 137,500 Yang. "
gameforge.main_quest_lv50._290_sayReward = "Du har modtaget Den Viise Kejsers Handske. "
gameforge.main_quest_lv50._300_sayTitle = "Dr\230b Klo gift-edderkop "
gameforge.main_quest_lv50._30_sendLetter = "Den niende side "
gameforge.main_quest_lv50._310_say = "Den sorte hekseri forskning videref\248res i[ENTER]Edderkoppe-grotten. G\229 der og dr\230b nogle Klo[ENTER]gift-edderkop for at finde de kr\230vede[ENTER]oplysninger. "
gameforge.main_quest_lv50._320_sendLetter = "Den 11te side "
gameforge.main_quest_lv50._330_targetVid = "G\229 tilbage til den l\230rte Uriel "
gameforge.main_quest_lv50._335_sayTitle = "Du har fundet den ellevte side "
gameforge.main_quest_lv50._340_say = "Du har fundet den ellevte dagbog side i[ENTER]Edderkoppe-grotten. Tage den til Uriel. "
gameforge.main_quest_lv50._350_say = "Har du fundet ud af nye oplysninger? Aha, den[ENTER]ellevte side! Lad os se... Ah ja, det ser ganske[ENTER]let ud. Jeg er blevet helt god til at l\230se disse[ENTER]tegn nu. Nu, se dette! "
gameforge.main_quest_lv50._355_sayTitle = "Ellevte Side: "
gameforge.main_quest_lv50._360_sayReward = "Det har sl\229et fejl. Trods alle vores[ENTER]forberedelser, var vi n\248dt til at handle hurtigt.[ENTER]For hurtigt. Nu er en masse af os s\229ret, og nogle[ENTER]af os er blevet sindssyg. Sort trolddom er[ENTER]virkelig ond. Lee Seop's kavaleri har spottet os,[ENTER]men det er irrelevant nu. Vi har ikke nok m\230nd[ENTER]til at forsvare os selv imod ham, og vi kommer[ENTER]til at d\248 alligevel. "
gameforge.main_quest_lv50._365_sayTitle = "Forts\230ttelsen af den ellevte Side: "
gameforge.main_quest_lv50._370_sayReward = "En sidste tanke er at holde resten af tropper[ENTER]sammen og give os styrke: Vores informanter fra[ENTER]dragedalen har l\248jet. Det var bevidst de ikke[ENTER]advarede os imod de forf\230rdelige bivirkninger af[ENTER]sort trolddom. De vil betale for at g\248re det. Det[ENTER]vil v\230re vores sidste gerning p\229 denne jord. "
gameforge.main_quest_lv50._380_say = "N\229, i sidste ende viste det sig en lille smule[ENTER]anderledes, end de havde h\229bet p\229. En trist[ENTER]historie. Men desv\230rre kan du ikke stole p\229[ENTER]nogen, der er besk\230ftiget med sort trolddom. De[ENTER]burde have t\230nkt p\229 det. Det er m\230rkeligt nok, at[ENTER]forfatteren af disse linier endda har form\229et at[ENTER]f\229 oplysninger om disse forbudte ordninger. Hvem[ENTER]ved, hvad slags m\229l hans informanter havde. Vi[ENTER]b\248r afslutte denne vej selv, selv om det er[ENTER]farligt. Vi ved allerede s\229 meget, s\229 det ville[ENTER]v\230re en skam at give op nu. "
gameforge.main_quest_lv50._390_say = "Du har allerede v\230ret i dragedalen. Jeg tror[ENTER]ikke, vi vil finde noget ellers der. Hmm, jeg[ENTER]spekulerer p\229, hvor vi ellers kan kigge... Jeg[ENTER]ved det! Mindesm\230rker spillede en stor rolle i[ENTER]vores s\248gning. Og der er ogs\229 mindesm\230rker rundt[ENTER]omkring, som vi ikke har unders\248gt endnu. Dem i[ENTER]de andre riger! Det er meget farligt der. Du vil[ENTER]sandsynligvis blive angrebet konstant. S\229[ENTER]forbered dig godt og kom og se mig, n\229r du er[ENTER]klar. "
gameforge.main_quest_lv50._400_say = "Men f\248rst vil jeg give dig din bel\248nning for den[ENTER]ellevte side. "
gameforge.main_quest_lv50._40_targetVid = "G\229 til Uriel den l\230rte "
gameforge.main_quest_lv50._410_sayReward = "Du har modtaget 6,000,000 erfaringspoint.[ENTER]Du har modtaget 150,000 Yang.[ENTER]Du har modtaget Dragens medalje.[ENTER]Tip: For n\230ste opgave, skal du v\230re level 55. "
gameforge.main_quest_lv50._50_sayTitle = "Fundet den niende side "
gameforge.main_quest_lv50._60_say = "Du har fundet den niende side i[ENTER]Edderkoppe-grotten. Tag den til Uriel den l\230rde. "
gameforge.main_quest_lv50._70_say = "Du har fundet ud af noget andet om sort hekseri?[ENTER]Wow, den niende side! Jeg er virkelig sp\230ndt p\229[ENTER]at se, om magien virker eller ej.[ENTER]Lad os f\229 et kig. Hmm, der st\229r her... "
gameforge.main_quest_lv50._75_sayTitle = "Niende Side: "
gameforge.main_quest_lv50._80_sayReward = "Lee Seop's angreb er begyndt. Og vi ved stadig[ENTER]ikke pr\230cis, hvordan man bruger sort heksekunst.[ENTER]Jeg er virkelig nerv\248s. Vi er p\229 forreste linje,[ENTER]fors\248ger at forsvare vores rige, men vores styrke[ENTER]er utilstr\230kkelige. Fjendens h\230r er alt for st\230rk[ENTER]og hvis det ikke snart sker noget, kommer vi til[ENTER]at tabe kampen. Vi har brug for at tr\230kke os[ENTER]tilbage. Det ville v\230re bedst for os at tr\230kke os[ENTER]tilbage til et ufrugtbar sted, hvor de ikke vil[ENTER]v\230re i stand til at bruge deres heste ordentligt:[ENTER]Island. Med en smule held vil vi s\229 have tid nok[ENTER]til at forske videre.[ENTER]\197h, Gud hj\230lpe os... "
gameforge.main_quest_lv50._90_say = "Hmm... Angrebet begyndte, inden de var i stand[ENTER]til at udforske den sort heksekunst ordentligt.[ENTER]De var n\248dt til at barrikadere sig i Island. Det[ENTER]m\229 betyde Bjerget Sohan, som ogs\229 kaldes Island i[ENTER]dag. Vi b\248r kigge efter nogle flere spor. G\229 til[ENTER]Bjerget Sohan og se, hvad du kan finde ud af. "
gameforge.main_quest_lv55 = {}
gameforge.main_quest_lv55._100_say = "Du har fundet den tolvte side i Joan omr\229det.[ENTER]Tag det til Uriel i Yongan omr\229det. "
gameforge.main_quest_lv55._10_sendLetter = "S\248gning efter minderne "
gameforge.main_quest_lv55._110_say = "Du har fundet den tolvte side i Yongan[ENTER]omr\229det.Tag det til Uriel i Pyungmoo omr\229det. "
gameforge.main_quest_lv55._120_say = "Jeg er glad for at se dig igen. Jeg er ked af, at[ENTER]jeg var n\248dt til at sende dig her, der og alle[ENTER]vegne, men i det mindst har vores succes bevist[ENTER]vi havde ret, tror du ikke? Lad os se hvad den[ENTER]siger. Jeg h\229ber, det var det hele v\230rd. "
gameforge.main_quest_lv55._130_sayTitle = "Tolvte side: "
gameforge.main_quest_lv55._140_sayReward = "Vi fandt informanterne og de har betalt for deres[ENTER]bedrag med deres liv. Men det vigtigste var at vi[ENTER]var i stand til at presse nogle informationer ud[ENTER]af dem: Vi har ikke brug for Edderkoppe-grotten,[ENTER]men for M\248rkt tempel. Det er der hvor de gamle[ENTER]tro tilh\230ngere har udf\248rt deres m\248rke ritualer[ENTER]siden tidernes morgen. "
gameforge.main_quest_lv55._145_sayTitle = "Forts\230ttelsen af det tolvte Side: "
gameforge.main_quest_lv55._150_sayReward = "Vi har kun en m\229de at stoppe Lee Seop p\229 tilbage.[ENTER]Vi har brug for at rejse til M\248rkt tempel s\229ledes[ENTER]at vi kan udf\248re sort trolddom. Der er ikke mange[ENTER]af os tilbage og anstrengelsen fra de sidste par[ENTER]m\229neder har helt sikkert taget sine ofre. Men[ENTER]selv en h\229ndfuld tr\230tte m\230nd kan \230ndre verdens[ENTER]sk\230bne, n\229r de har magtfulde oplysninger.[ENTER]Vi m\229 ikke glemme vores m\229l. Lad os g\229. "
gameforge.main_quest_lv55._160_say = "Ah, s\229 de fandt det rigtige sted. Jeg havde ret[ENTER]trods alt! Det er virkelig det M\248rkt tempel. Du[ENTER]husker sikkert , det m\248rke sted, der summende af[ENTER]d\229rlig energi. S\229 l\230nger nogen kan huske har[ENTER]ritualer og ceremonier fundet sted der, hvor[ENTER]\230rlige landsby folk ikke burde holde sig v\230k fra. "
gameforge.main_quest_lv55._170_say = "Nu til dags er monstre det eneste, der bor i[ENTER]templet, der har ikke v\230ret mennesker der i lang[ENTER]tid. Det er meget farligt, men jeg er sikker p\229[ENTER]at du kan klare det. G\229 til Dragedalen og kig[ENTER]efter den sidste side i M\248rkt tempel. Den[ENTER]historie, denne dagbog fort\230ller os ender her.[ENTER]Jeg har brug for at finde ud af, hvordan det[ENTER]ender. Held og lykke! \197h, vent et sekund, her er[ENTER]din bel\248nning for den tolvte side. "
gameforge.main_quest_lv55._180_sayReward = "Du har modtaget 26.000 erfaringspoint.[ENTER]Du har modtaget 15.000 Yang.[ENTER]Du har modtaget en Grise n\230se. "
gameforge.main_quest_lv55._190_sayReward = "Du har modtaget 162,500 Yang. "
gameforge.main_quest_lv55._200_sendLetter = "Den sidste side "
gameforge.main_quest_lv55._20_say = "Da du allerede har fundet flere dagbog sider i[ENTER]n\230rheden af mindesm\230rker, mener Uriel, at du vil[ENTER]v\230re i stand til at finde ud af mere information[ENTER]om den hemmelige m\248rke heksekunst i n\230rheden af[ENTER]uudforskede mindesm\230rker. G\229 til Chunjo Kongerige[ENTER]og unders\248g mindesm\230rker i Joan omr\229det. "
gameforge.main_quest_lv55._210_sayTitle = "Dr\230b Fjols i Templet "
gameforge.main_quest_lv55._220_say = "Indtil videre har du fundet 12 af de 13 dagbog[ENTER]sider. Nu er der kun et skridt tilbage. Uriel[ENTER]siger at sort magi er blevet brugt p\229 M\248rkt[ENTER]tempel. Du b\248r g\229 der hen og finde ud af nogle[ENTER]flere oplysninger. Start din s\248gning ved at dr\230be[ENTER]fjols i templet. "
gameforge.main_quest_lv55._230_say = "Jeg er n\248dt til at g\229 dybere ind i templet! "
gameforge.main_quest_lv55._240_sendLetter = "M\248rkt tempel "
gameforge.main_quest_lv55._250_sayTitle = "Den onde energi i templet "
gameforge.main_quest_lv55._260_sayReward = "Efter du har brugt lidt tid i templet, har du[ENTER]udvikler en fornemmelse for dette m\230rkelige,[ENTER]m\248rke sted: Langsomme skygger flimrer i hvert[ENTER]hj\248rne. M\248rk energi siver ud af hver spr\230kke og[ENTER]krog ligesom olie. Det er indlysende, at selve[ENTER]templet er bag det. Det er her det hele[ENTER]begyndte... "
gameforge.main_quest_lv55._270_say = "Du bliver bevidst om det faktum, at den[ENTER]ugudelighed der ligger i luften bliver st\230rkere,[ENTER]jo l\230ngere du bev\230ger dig hen imod midten af[ENTER]templet. Du skal fors\248ge at finde midten af[ENTER]templet. Det er her, kilden til m\248rket skal v\230re. "
gameforge.main_quest_lv55._280_npcChat = "Gum mindet "
gameforge.main_quest_lv55._290_say = "Gum mindet er hjertet i templet. Du bev\230ge dig[ENTER]langsomt n\230rmere og finder faktisk den sidste[ENTER]dagbog side. "
gameforge.main_quest_lv55._300_say = "Du har fundet den sidste side i dagbogen i M\248rkt[ENTER]tempel. G\229 til Uriel og rapportere til ham om din[ENTER]opdagelse. "
gameforge.main_quest_lv55._30_say = "Da du allerede har fundet flere dagbog sider i[ENTER]n\230rheden af mindesm\230rker, mener Uriel, at du vil[ENTER]v\230re i stand til at finde ud af mere information[ENTER]om den hemmelige m\248rke heksekunst i n\230rheden af[ENTER]uudforskede mindesm\230rker. G\229 til Jinno Kongerige[ENTER]og unders\248g mindesm\230rker i Pyungmo omr\229det. "
gameforge.main_quest_lv55._310_say = "Der er, den trettende og sidste side! Jeg kan[ENTER]ikke fort\230lle dig, hvor taknemmelig jeg er for at[ENTER]du g\248r dette. Se hvordan mine h\230nder ryster. Jeg[ENTER]er alt for sp\230ndt til at l\230se siden. Pyha... Ah[ENTER]ja, lad os se, hvordan historien ender. "
gameforge.main_quest_lv55._320_sayTitle = "Trettende Side: "
gameforge.main_quest_lv55._330_sayReward = "Vi er endelig ankommet.[ENTER]Efter alle vores pr\248velser har vi f\248lgende[ENTER]mission: Vi har brug for at udf\248re ceremonien og[ENTER]aktivere den sorte trolddoms magi. Jeg h\229ber[ENTER]bare, vi er st\230rke nok. En masse af os svajer[ENTER]lidt, fordi vi er s\229 udmattede af den lange rejse[ENTER]og for hele tiden at flygte fra Lee Seop's[ENTER]krigere. Men vi er stadig n\248dt til at pr\248ve[ENTER]ellers vil vores kongerige forsvinde. "
gameforge.main_quest_lv55._335_sayTitle = "Forts\230ttelsen af den Trettende Side: "
gameforge.main_quest_lv55._340_sayReward = "Der er syv af os. Vi har taget vores bedste t\248j[ENTER]p\229, selv om de ligner klude nu. Vi skal samles i[ENTER]en rundkreds og holde i h\229nd, s\229 magt linjerne[ENTER]bliver forseglet. S\229 vil vi begynde at synge de[ENTER]magiske ord og h\229be, at den sorte hekseri ikke[ENTER]kr\230ver flere ofre.[ENTER]... "
gameforge.main_quest_lv55._350_sayReward = "... Det er overst\229et ...[ENTER]I begyndelsen var det alt sammen meget lovende.[ENTER]V\230relset blev fyldt med energi og sang, men[ENTER]pludselig f\248lte jeg mig virkelig underlig. Mine[ENTER]seks kolleger kombattanter faldt ned p\229 deres[ENTER]kn\230. Templet begyndte at sk\230lve. Lyn slog ned og[ENTER]vi blev skubbet bagl\230ns. Og linjerne af magt blev[ENTER]brudt...[ENTER]Nu er der stille. Mine kammerater ligger d\248d p\229[ENTER]jorden. Magien virkede ikke.[ENTER]Vi har svigtet. "
gameforge.main_quest_lv55._360_say = "Hvad? Er det alt?!?[ENTER]Det er vanvittigt! Alt dette arbejde for[ENTER]ingenting? Jeg kan ikke tro det. Vi rejste,[ENTER]k\230mpede, oversatte og hang over det i timevis.[ENTER]Alt det for ingenting! Vi er lige s\229 kloge som vi[ENTER]var f\248r. Men det synes at v\230re bedre, hvis vi[ENTER]holder os v\230k fra sort heksekunst, hvilket er,[ENTER]hvad jeg troede fra starten. Men viden er bedre[ENTER]end at tro, er det ikke? "
gameforge.main_quest_lv55._370_say = "Vi vil holde en pause f\248rst. Jeg har hovedpine og[ENTER]du er sikkert helt udslidt ogs\229. Jeg har brug for[ENTER]at t\230nke det igennem f\248rst. N\229r jeg er f\230rdig,[ENTER]vil vi snakke videre. P\229 trods af alt, gav du mig[ENTER]en uvurderlig service. Det vil ikke v\230re[ENTER]ubel\248nnet! "
gameforge.main_quest_lv55._380_sayReward = "Du f\229r 7.000.000 erfaringspints. "
gameforge.main_quest_lv55._390_sayReward = "Du har modtaget 175,000 Yang. "
gameforge.main_quest_lv55._400_sayReward = "Du har modtaget leder bogen. "
gameforge.main_quest_lv55._40_say = "Da du allerede har fundet flere dagbog sider i[ENTER]n\230rheden af mindesm\230rker, mener Uriel, at du vil[ENTER]v\230re i stand til at finde ud af mere information[ENTER]om den hemmelige m\248rke heksekunst i n\230rheden af[ENTER]uudforskede mindesm\230rker. G\229 til Shinsoo[ENTER]Kongerige og unders\248g mindesm\230rker i Yongan[ENTER]omr\229det. "
gameforge.main_quest_lv55._50_npcChat = "Der er den! "
gameforge.main_quest_lv55._60_say = "Dette er det monument, Uriel var p\229 udkig efter.[ENTER]Der er ogs\229 en foldet side! Jeg vil hurtigt[ENTER]aflevere det Uriel. "
gameforge.main_quest_lv55._70_sendLetter = "Fandt tolvte side "
gameforge.main_quest_lv55._80_targetVid = "G\229 tilbage til Uriel "
gameforge.main_quest_lv55._90_say = "Du har fundet den tolvte side i Pyungmo Omr\229det.[ENTER]Tag det til Uriel i Joan omr\229det. "
gameforge.main_quest_lv6 = {}
gameforge.main_quest_lv6._100_sayReward = "G\229 til smeden. Han har brug for din hj\230lp. "
gameforge.main_quest_lv6._10_targetVid = "G\229 til Byvagten "
gameforge.main_quest_lv6._110_say = "Hvem er du, og hvad vil du her?[ENTER]Jeg har travlt s\229 forstyrre mig ikke.[ENTER]\197h Byvagten sendte dig? Jeg troede ikke at nogen[ENTER]nogensinde ville komme. Det er ikke en vanskelig[ENTER]opgave, og vil det ikke tage lang tid. Lige det[ENTER]rigtige for en unge eventyrer som dig. "
gameforge.main_quest_lv6._120_say = "Jeg skulle modtage en svinen\230se fra[ENTER]lagerforvalteren, men jeg har ikke f\229et den. F\229[ENTER]fat i svinen\230sen. Skynd dig! "
gameforge.main_quest_lv6._130_targetVid = "Sp\248rg Lagerforvalteren "
gameforge.main_quest_lv6._140_sendLetter = "G\229 til Lagerforvalteren "
gameforge.main_quest_lv6._150_sayReward = "Smeden venter en presserende levering fra[ENTER]Lagerforvalteren. G\229 til Lagerforvalteren og bed[ENTER]ham om en Svinen\230se til smeden. "
gameforge.main_quest_lv6._160_sayTitle = "Lagerforvalter: "
gameforge.main_quest_lv6._170_say = "Velkommen. Jeg er lagerforvalteren i denne[ENTER]landsby. N\229r du har for mange ting og sager, kan[ENTER]du lagre dem i lagerhuset. Det er meget[ENTER]praktisk.  "
gameforge.main_quest_lv6._180_say = "\216nsker du at... Ah, smeden sendt dig for at hente[ENTER]en Svinen\230se! "
gameforge.main_quest_lv6._190_say = "Jeg er bange for jeg ved at blive gammel og[ENTER]glemsom. Tidligere ville s\229dan noget aldrig v\230re[ENTER]sket. Her er den Svinen\230se. Aflevere den straks[ENTER]til Smeden. Vi ses senere. "
gameforge.main_quest_lv6._200_sendLetter = "Tilbage til smeden "
gameforge.main_quest_lv6._20_sayReward = "Byvagten har en ny mission til dig. G\229 til ham og[ENTER]sp\248rge ham, hvad det hele handler om. "
gameforge.main_quest_lv6._210_sayReward = "Lagerforvalteren har fuldst\230ndig glemt levering.[ENTER]Han har nu givet dig Svinen\230se. Skynd dig at[ENTER]aflever det til Smeden, s\229 han ikke er n\248dt til[ENTER]at vente l\230ngere. "
gameforge.main_quest_lv6._220_say = "Du kom tilbage hurtigere end jeg troede! Du b\248r[ENTER]holde denne hastighed, det kan v\230re nyttigt i[ENTER]fremtiden. Og lyt nu opm\230rksomt, jeg har nogle[ENTER]vigtige oplysninger til Dem. "
gameforge.main_quest_lv6._230_say = "Kender du noget til opgraderinger? Selvf\248lgelig[ENTER]ikke! Du er stadig en ung eventyrer! Det er om[ENTER]dette: Hvis du giv mig et stykke af dit udstyr,[ENTER]kan jeg opgradere det for kun et par Yang,[ENTER]s\229ledes at dets kvalitet vil forbedres. "
gameforge.main_quest_lv6._240_say = "Kunsten at for\230dle kan ske p\229 flere forskellige[ENTER]m\229der - jo h\248jere du str\230ber, des h\229rdere er det.[ENTER]Til en for\230dling af +3 eller under kan du bare[ENTER]brug lidt Yang, mens alt opefter skal bruge andre[ENTER]genstande. Ligesom for eksempel, den Svinen\230se du[ENTER]bragte mig. Men sommetider kan det, du \248nsker at[ENTER]for\230dle g\229 i stykker, selvom det bliver lavet af[ENTER]en dygtig Smed, som mig. Kom igen, hvis du har[ENTER]lidt tid. Jeg kan skabe fantastiske v\229ben! "
gameforge.main_quest_lv6._250_sayReward = "Du har modtaget %s erfaringspoint. "
gameforge.main_quest_lv6._260_sayReward = "Du har modtaget %s Yang. "
gameforge.main_quest_lv6._270_sayReward = "Du har modtaget noget Ulveskind+. "
gameforge.main_quest_lv6._30_say = "Hey, du der! Nu er tiden ikke inde til at h\230nge[ENTER]og lave ingenting. Du er n\248dt til at lave noget[ENTER]h\229rd tr\230ning! Uddannelse er den eneste m\229de at[ENTER]for\248ge dine chancer for overlevelse i disse[ENTER]tider! "
gameforge.main_quest_lv6._40_say = "Men nu du er her alligevel, har jeg en mission[ENTER]til dig: Smeden var her for et \248jeblik siden og[ENTER]sagde noget om grise og leverings problemer.[ENTER]M\229ske har han brug for hj\230lp. G\229 til ham og[ENTER]fort\230lle ham, at jeg har sendt dig. Afsted med[ENTER]dig! "
gameforge.main_quest_lv6._50_sayReward = "Hvis du afslutter missionen for Smeden vil du f\229[ENTER]en bel\248nning. "
gameforge.main_quest_lv6._60_sayReward = "Erfaringspoints: %s "
gameforge.main_quest_lv6._70_sayReward = "Yang: %d "
gameforge.main_quest_lv6._80_targetVid = "Find Smeden "
gameforge.main_quest_lv6._90_sendLetter = "Smeden mission "
gameforge.main_quest_lv60 = {}
gameforge.main_quest_lv60._100_say = "Sohan bjerget? Jeg s\229 engang en gammel gravsten[ENTER]der! "
gameforge.main_quest_lv60._10_sendLetter = "Et nyt spor "
gameforge.main_quest_lv60._110_say = "Du kan ikke tilf\230ldigvis huske nogen indskrift p\229[ENTER]den? \197benbart ikke. Denne gravsten kan m\229ske give[ENTER]os v\230rdifulde informationer om den M\248rke Nation.[ENTER]Kunne du m\229ske g\229 til Sohan bjerget og lave en[ENTER]kopi af indskriften til mig? "
gameforge.main_quest_lv60._120_say = "If\248lge Uriels unders\248gelser, tilh\248rte de syv[ENTER]Drage Pr\230stinder den M\248rke Nation.[ENTER]Unders\248g den gamle gravsten ved Sohan bjerget.[ENTER]Den m\248rke Nations Hovedstad skulle havde ligget[ENTER]her, engang for l\230nge siden. "
gameforge.main_quest_lv60._130_say = "Du kan ikke tilf\230ldigvis huske nogen indskrift p\229[ENTER]den? \197benbart ikke. Denne gravsten kan m\229ske give[ENTER]os v\230rdifulde informationer om den M\248rke Nation.[ENTER]Kunne du m\229ske g\229 til Sohan bjerget og lave en[ENTER]kopi af indskriften til mig? "
gameforge.main_quest_lv60._140_sayReward = "Du har lokaliseret den gamle gravsten fra den[ENTER]M\248rke Nations tid og lavet en kopi af[ENTER]inskriptionen. Bring den til Uriel. "
gameforge.main_quest_lv60._150_say = "If\248lge Uriels unders\248gelser, tilh\248rte de syv[ENTER]Drage Pr\230stinder den M\248rke Nation.[ENTER]Unders\248g den gamle gravsten ved Sohan bjerget.[ENTER]Den m\248rke Nations Hovedstad skulle havde ligget[ENTER]her, engang for l\230nge siden. "
gameforge.main_quest_lv60._160_say = "Endelig! Lad mig analysere inskriptionerne...[ENTER]Det siger f\248lgende: Den M\248rke Nation har[ENTER]dedikeret sig selv til m\248rk magi og tjener Sung[ENTER]Mahi, D\230monernes Gud. "
gameforge.main_quest_lv60._170_say = "Oh my... Sung Mahi! S\229 fors\248gt de syv Drage[ENTER]Pr\230stinder m\229ske at fremkalde Sung Mahi ved brug[ENTER]af de forbudte heksekr\230fter? "
gameforge.main_quest_lv60._180_say = "Du har gjort det godt. For s\229dan en indsats, er[ENTER]det kun fair at du modtager en bel\248nning. "
gameforge.main_quest_lv60._190_sayReward = "Du har modtaget %s erfaringspoint. "
gameforge.main_quest_lv60._200_sayReward = "Du har modtaget %s Yang. "
gameforge.main_quest_lv60._20_say = "Uriel har fundet nye informationer om historien[ENTER]fra den gamle dagbog. Bes\248g Uriel og find ud af[ENTER]mere. "
gameforge.main_quest_lv60._210_sayReward = "Du modtager %d. "
gameforge.main_quest_lv60._220_sendLetter = "M\248rk Nation II "
gameforge.main_quest_lv60._230_say = "If\248lge Uriel, var \197ndeskoven engang en del af den[ENTER]M\248rke Nations kongerige. Der er m\229ske yderligere[ENTER]spor der.[ENTER]Men skoven er fuld af fare og Metin Stenene har[ENTER]gjort alle v\230snerne der vanvittige. Find det Onde[ENTER]tr\230, for at f\229 flere beviser. Tal derefter med[ENTER]Uriel. "
gameforge.main_quest_lv60._240_say = "Den M\248rke Nation er omringet af talrige[ENTER]hemmeligheder. Takket v\230ret dig, har vi v\230ret[ENTER]istand til at komme til bunds i nogen af disse,[ENTER]men vi mangler stadig vigtig information. Drag[ENTER]venligst ud og jagt et gammelt dokument. Det[ENTER]skulle befinde sig i \197ndeskoven n\230r Sohan[ENTER]bjerget. "
gameforge.main_quest_lv60._250_counter = "Manglende sider: "
gameforge.main_quest_lv60._260_say = "Den M\248rke Nation er omringet af talrige[ENTER]hemmeligheder. Takket v\230ret dig, har vi v\230ret[ENTER]istand til at komme til bunds i nogen af disse,[ENTER]men vi mangler stadig vigtig information. Drag[ENTER]venligst ud og jagt et gammelt dokument. Det[ENTER]skulle befinde sig i \197ndeskoven n\230r Sohan[ENTER]bjerget. "
gameforge.main_quest_lv60._270_sayReward = "Du har besejret Ondt Tr\230 og tager dokumentet. Det[ENTER]er skrevet p\229 et fremmed sprog. Giv Uriel lov at[ENTER]overs\230tte det. "
gameforge.main_quest_lv60._280_say = "Endelig! Du har fundet det gamle dokument.[ENTER]Forh\229bentligt vil det kaste noget lys over dette[ENTER]mysterium! "
gameforge.main_quest_lv60._290_say = "Men hvad...? Der er n\230sten ingenting i det![ENTER]Dokumentet er faktisk lavet af ti sider. Vend[ENTER]venligst tilbage til skoven og find de[ENTER]tilbagev\230rende ni sider. "
gameforge.main_quest_lv60._300_say = "Du har stadig brug for at finde %d sider. "
gameforge.main_quest_lv60._30_say = "Hvordan har du det? Husker du dagbogen og[ENTER]historien i den? Den som brat ender p\229 den[ENTER]trettende og sidste side? "
gameforge.main_quest_lv60._310_say = "S\229, nu m\229 vi se...[ENTER]\197benbart fangede den M\248rke Nation den h\248je[ENTER]pr\230stinde fra Drage kulten ved brug af en[ENTER]forbandelse og misbrugte den hellige kraft fra de[ENTER]syv kvinder for at kunne udf\248re den antikke form[ENTER]for sorte heksekr\230fter. "
gameforge.main_quest_lv60._320_say = "For at tilkalde Sung Mahi, skal de Sorte[ENTER]heksekr\230fter bruges samtidig p\229 syv forskellige[ENTER]placeringer. Men Lee Seop og hans h\230r lykkedes[ENTER]med at stoppe ritualet i tide og afv\230rgede den[ENTER]M\248rke Nations plan. "
gameforge.main_quest_lv60._330_say = "Denne nation var helt sikkert en man skulle[ENTER]frygte. De var istand til at kontrollere[ENTER]menneskelig bevidsthed igennem Sort Magi! "
gameforge.main_quest_lv60._340_sendLetter = "Sporet "
gameforge.main_quest_lv60._350_say = "Uriel har opdaget spor vedr\248rende Gum[ENTER]mindesm\230rket i den gamle rulle. G\229 til ham og[ENTER]find ud af mere. "
gameforge.main_quest_lv60._360_say = "Lad os opsummere hvad vi har l\230rt indtil nu:[ENTER]Engang var der et folk, som kaldte dem selv den[ENTER]M\248rke Nation og tjente d\230mon guden Sung Mahi. For[ENTER]at tilkalde ham, indfangede de, de syv Drage[ENTER]pr\230stinder og misbrugte deres hellige kr\230fter til[ENTER]den forbudte Sorte Heksekr\230fts kunst. Men dette[ENTER]skulle udf\248res p\229 syv placeringer p\229 den samme[ENTER]tid. "
gameforge.main_quest_lv60._370_say = "Drage Pr\230stinderne udf\248rte kun de Sorte[ENTER]Heksekr\230fter i dette ene t\229rn og ikke p\229 syv[ENTER]forskellige placeringer...[ENTER]Dette er grunden til at hidkaldelsen af Sung Mahi[ENTER]fejlede! "
gameforge.main_quest_lv60._380_say = "Den M\248rke Nation m\229 have givet de syv Drage[ENTER]Pr\230stinder forkerte informationer. "
gameforge.main_quest_lv60._390_say = "M\229ske viste de ikke hvordan de skulle g\248re det...[ENTER]Det kunne v\230re en mulighed, men den gamle rulle[ENTER]n\230vner dette t\229rn i relation til Gum mindet. Det[ENTER]virker til at de taler omkring D\230mon t\229rnet ved[ENTER]Hwang Templet. "
gameforge.main_quest_lv60._400_say = "Vi har endelig fundet et afg\248rende bevis p\229 de[ENTER]syv Drage Pr\230stinder! Slap lidt af og s\229 vil vi[ENTER]tale om hvad vi skal g\248re som det n\230ste. Jeg[ENTER]frygter at en rejse til D\230mon T\229rnet l\230gger[ENTER]truende foran dig... "
gameforge.main_quest_lv60._40_say = "Ja, selvf\248lgelig. Syv personer rendte fra Lee[ENTER]Seop og hans kavaleri ind i Hwang Templet og i[ENTER]deres desperation, de indf\248rte den forbudte sorte[ENTER]magi... i slutningen, overlevede kun en a f dem. "
gameforge.main_quest_lv60._410_sayReward = "Den n\230ste del af eventyret er tilg\230ngelig n\229r du[ENTER]har n\229et level 66. "
gameforge.main_quest_lv60._50_say = "Korrekt. Jeg har udf\248rt yderligere forskning og[ENTER]har fundet ud af at det syv medlemmer af den[ENTER]hellige kult var Drage Pr\230stinder. I gamle ruller[ENTER]er de associeret med et teokratisk folk kaldet[ENTER]den M\248rke Nation.[ENTER]Var disse Drage Pr\230stinder del af denne mystiske[ENTER]nation? Her, l\230s denne rulle grundigt igennem og[ENTER]tal s\229 med mig igen n\229r du er f\230rdig. "
gameforge.main_quest_lv60._60_sendLetter = "M\248rk Nation I "
gameforge.main_quest_lv60._70_say = "If\248lge Uriels efterforskning er de syv Drage[ENTER]Pr\230stinder fra den M\248rke Nation.[ENTER]Unders\248g den gamle gravsten p\229 Sohan bjerget. Det[ENTER]formodes at den M\248rke Nation engang var der.[ENTER]Inden du g\229r, tal med Uriel engang til. "
gameforge.main_quest_lv60._80_say = "Deres ufatteligt h\248jtudviklede heksekr\230fter og[ENTER]det faktum at de if\248lge dagbogen, blev udslettet[ENTER]af Lee Seop, peger alt sammen imod ideen om at de[ENTER]syv Drage pr\230stinder faktisk var en del af den[ENTER]M\248rke Nation. "
gameforge.main_quest_lv60._90_say = "I den gamle rulle er der et kort. Ved n\230rmere[ENTER]inspektion, kan du fastsl\229 at den M\248rke Nations[ENTER]hovedstad m\229 havde v\230ret placeret p\229 Sohan[ENTER]bjerget. "
gameforge.main_quest_lv66 = {}
gameforge.main_quest_lv66._100_say = "Utroligt! Forst\229r du hvad dette betyder?![ENTER]Oprindeligt var der ikke nogen d\230moner eller[ENTER]\229nder i D\230mon T\229rnet. Som det er nu er en arv fra[ENTER]Drage pr\230stinderne. I et sidste desperat fors\248g[ENTER]p\229 at besejre Lee Seops kavaleri, \229bnede hun[ENTER]d\248ren til en verden af d\230moner ved at bruge det[ENTER]forbandede og m\248rke ritual. Til slut, betalte hun[ENTER]for dette med hendes liv. "
gameforge.main_quest_lv66._10_sendLetter = "Dagbogen "
gameforge.main_quest_lv66._110_say = "Det er denne \229bning h\248stmanden og hans d\230moniske[ENTER]f\248lge brugte til at komme til vores verden.[ENTER]Dog fejlede den store mission for den m\248rke[ENTER]nation og Drage Pr\230stinderne: hidkaldelsen af[ENTER]Sung Mahi var ikke succefuld, Lee Seop kom[ENTER]tilgeng\230ld til magten, og etablerede til sidst et[ENTER]forenet verdens kongerige.[ENTER][ENTER]Tak for din hj\230lp, jeg har endelig l\248st det[ENTER]st\248rste mysterium i mit liv! "
gameforge.main_quest_lv66._120_say = "Som din bel\248nning, vil jeg gerne give dig et[ENTER]velsignelses dokument. Tag venligst imod min[ENTER]gave, jeg insistere! "
gameforge.main_quest_lv66._130_sendLetter = "Du har post. "
gameforge.main_quest_lv66._140_say = "Lee Chung har et brev til dig. L\230s det og find ud[ENTER]af hvem den hemlighedsfulde afsender er. "
gameforge.main_quest_lv66._150_say = "Du har gjort dig selv meget sparsom her p\229 det[ENTER]sidste, hva? Jeg skal give dig dette brev - har[ENTER]ingen idee om hvem der sendte det, han[ENTER]introducerede ikke sig selv. "
gameforge.main_quest_lv66._160_say = "Papiret brevet er skrevet p\229, virker til at v\230re[ENTER]meget gammelt. Med hurtige kraget\230r, er der[ENTER]skrevet f\248lgende:[ENTER]Har vigitig information om De Syv Dragepr\230stinger[ENTER]og Sung Mahi. Venter p\229 dig, p\229 bagsiden af[ENTER]D\230mont\229rnet i Hwang Templet. Jeg er i skyggen af[ENTER]et tr\230. Skynd dig! Tiden er knap! "
gameforge.main_quest_lv66._170_sendLetter = "Annunymt brev "
gameforge.main_quest_lv66._180 = "G\229 til Hwang Temple og m\248d den hemmelighedsfulde[ENTER]brevskriver ved bagsiden af D\230mon t\229rnet. "
gameforge.main_quest_lv66._190_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._200_say = "Velkommen! Tillad mig at indtroucere mig selv[ENTER]f\248rst: Mit navn er Lee Chung. Det er meget modigt[ENTER]af dig at f\248lge instruktioner fra en du ikke[ENTER]engang kender. Jeg har ikke snydt mig selv ved at[ENTER]v\230lge dig - og du vil heller ikke fortryde min[ENTER]beslutning![ENTER]H\248r hvad jeg har at fort\230lle! "
gameforge.main_quest_lv66._20_say = "Uriel har nyt om den sidste overlevende Drage[ENTER]Pr\230stinde. Hendes dagbog skulle v\230re i[ENTER]D\230mont\229rnet. G\229 til Uriel og find ud af mere. "
gameforge.main_quest_lv66._210_sendLetter = "Ny Ond "
gameforge.main_quest_lv66._220_say = "H\248r hvad Lee Chung har og fort\230lle dig. "
gameforge.main_quest_lv66._230_say = "Der er en grund til at du skulle komme til Hwang[ENTER]Templet: I nyere tid er der foreg\229et nogle meget[ENTER]m\230rkelige ting. Og for nyeligt har vi opdaget en[ENTER]indgang til en enorm grotte bag i D\230mont\229rnet! "
gameforge.main_quest_lv66._240_say = "En gigantisk grotte? Hvad er der i den? "
gameforge.main_quest_lv66._250_say = "I denne grotte, l\230gger en ny, ut\230nkelig ond og[ENTER]venter p\229 os. Vores spejdere snakker om et[ENTER]grusomt v\230sen, som f\229r d\230monerne til at gemme sig[ENTER]i skyggerne. Dens frygtindgydende fremkomsten og[ENTER]dens um\230ttelige lyst til livet, f\229r os til at[ENTER]tro, at dette b\230st er ingen ringere end den[ENTER]legendariske Agwi - en af de ti store ondskaber i[ENTER]D\230mon verdnen.[ENTER]Hvis vi har ret, s\229 er vi alle i meget stor fare. "
gameforge.main_quest_lv66._260_say = "Mere frygtindgydende end d\230moner... Dette v\230sen[ENTER]m\229 v\230re virkelig kr\230ftfuldt og ondt. "
gameforge.main_quest_lv66._270_say = "S\229dan er det. Mine m\230nd og jeg har fors\248gt mange[ENTER]gange at storme Dj\230vlens katakomber. Men vi har[ENTER]fejlet hver gang og lidt meget store tab.[ENTER]I denne sag har vi behov for hj\230lp fra en[ENTER]framragende kriger - det er derfor vi har[ENTER]hidkaldt dig herti. Vil du hj\230lpe os? "
gameforge.main_quest_lv66._280_say = "Ja, jeg vil hj\230lpe dig. "
gameforge.main_quest_lv66._290_say = "Oh, det giver os nyt h\229b![ENTER]Nu, hvor jeg ved at du st\229r p\229 vores side, vil[ENTER]jeg fort\230lle dig hele sandheden: Jeg, Lee Chung,[ENTER]er Komandant over Skygge krigerne. Ve er en[ENTER]hemmelig elite enhed af Lee Seops h\230r. "
gameforge.main_quest_lv66._300_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._30_say = "Ah, godt at se dig sund og sikker igen. Er du[ENTER]klar til et nyt eventyr? Vi mangler stadig vigtig[ENTER]informationer om den M\248rke Nation og de syv Drage[ENTER]Pr\230stinder. Den sidste Drage Pr\230stinde m\229 have[ENTER]gemt hendes dagbog i D\230mont\229rnet inden hun[ENTER]udf\248rte de sorte heksekr\230fter. Drag ud og bring[ENTER]mig dagbogen. Det er muligt at D\230mon kongen har[ENTER]det i hans besiddelse. "
gameforge.main_quest_lv66._310_say = "Skygge krigerne har forfulgt et m\229l siden[ENTER]dengang, at forhindre opstandelsen af Sung Mahi.[ENTER]Det er vores mission. Lad os fors\248ge sammen at[ENTER]sende denne Agwi tilbage til helvedet han kom fra[ENTER]og s\229 finde ud af hvordan han klarede at komme[ENTER]ind i vores verden i f\248rste omgang! "
gameforge.main_quest_lv66._320_sendLetter = "Ingen tid "
gameforge.main_quest_lv66._330_say = "Lee Chung, kommand\248r af Skygge krigerne, s\248ger[ENTER]dig. Det er meget hastende! "
gameforge.main_quest_lv66._340_say = "Jeg har en hastende foresp\248rgsel. Kan du se den[ENTER]s\229rede soldat derovre?[ENTER]Det er en af mine spejdere, som udforskede[ENTER]Dj\230vlens katakomber under min ordre. Da han[ENTER]gjorde dette, blev han angrebet af Agwi og[ENTER]forgiftet. Giften har spredt sig i hele hans krop[ENTER]- han har ikke meget tid tilbage. "
gameforge.main_quest_lv66._350_say = "Han har brug for en modgift og han har brug for[ENTER]den hurtigt![ENTER]Kan du hente noget? Du kan finde det i den R\248de[ENTER]Skov n\230r den R\248de dryade.[ENTER]Han er en af vores bedste krigere - red hans liv[ENTER]og jeg vil bel\248nne dig med %s. "
gameforge.main_quest_lv66._360_say = "Jeg vil hente modgiften! "
gameforge.main_quest_lv66._370_say = "Mange tak! Han tr\230kker stadig vejret, men han[ENTER]bliver svagere hvert minut. Vi har ingen tid at[ENTER]miste! "
gameforge.main_quest_lv66._380_notice = "Du har %d minutter tilbage. "
gameforge.main_quest_lv66._390_sendLetter = "Modgiften "
gameforge.main_quest_lv66._400_say = "Du ved ud fra hvad Lee Chung fortalte dig, at[ENTER]modgiften kan findes i den R\248de skov. F\230ld %d R\248d[ENTER]Dryader til denne.[ENTER][ENTER]I den R\248de skov er der endnu st\248rre fare end der[ENTER]er i \229ndeskoven, s\229 v\230r forsigtig. "
gameforge.main_quest_lv66._40_say = "Du har besejret D\230mon Kongen og har modtaget[ENTER]Drage Pr\230stindens dagbog. Tag den til den l\230rte[ENTER]Uriel. Han vil analysere den. "
gameforge.main_quest_lv66._410_say = "Tiden er udl\248bet. Soldaten d\248r, bring ham[ENTER]modgiften hurtigst muligt. "
gameforge.main_quest_lv66._420_say = "Du har %d minutter tilbage. "
gameforge.main_quest_lv66._430_say = "Du har endelig fundet modgiften! Hurtigt, bring[ENTER]den til Lee Chung! "
gameforge.main_quest_lv66._440_say = "Her, hurtigt! Jeg tror du er ankommet p\229 det helt[ENTER]rigtige tidspunkt. Det er en enorm byrde du har[ENTER]taget af mine skuldre. Mine m\230nd og jeg er[ENTER]ekstremt taknemmelige for det du har gjort. "
gameforge.main_quest_lv66._450_say = "Takket v\230re din hj\230lp, overlevede min soldat. Her[ENTER]er din bel\248nning for at rede ham. "
gameforge.main_quest_lv66._460_say = "Det tog sin tid. Han klamre sig med alt sin[ENTER]styrke til livet. Heldigvis er du kommet i tide. "
gameforge.main_quest_lv66._470_say = "Han virker til at klare sig igennem. Men det var[ENTER]t\230t p\229 - han d\248de n\230sten fordi det tog dig s\229[ENTER]lang tid at finde modgiften.[ENTER]Jeg er ked af det, men dette er alt jeg kan give[ENTER]dig som bel\248nning. "
gameforge.main_quest_lv66._480_sendLetter = "Rapporten "
gameforge.main_quest_lv66._490_say = "Spejderen har genvundet bevidsthed. Lyt til hvad[ENTER]han observerede da han var i Dj\230vlens Katakomber. "
gameforge.main_quest_lv66._500_say = "Tak fordi du reddede mig. Jeg s\229 utrolige ting i[ENTER]Dj\230vlens Katakomber. Men s\229 blev jeg opdaget,[ENTER]og... "
gameforge.main_quest_lv66._50_say = "Du fandt den! Den sidste Drage Pr\230stindes dagbog.[ENTER]Min h\229nd sk\230lver af forventning! Jeg har brug for[ENTER]lidt tid til at unders\248ge indholdet. Tag noget[ENTER]tid og hvil dig. Jeg vil kalde p\229 dig n\229r jeg kan[ENTER]fort\230lle dig mere. "
gameforge.main_quest_lv66._510_say = "Hvad s\229 du? "
gameforge.main_quest_lv66._520_say = "Der var folk i sorte kapper med h\230tter, trukket[ENTER]over deres ansigter.[ENTER]Uddragene af deres samtaler tilod mig at finde ud[ENTER]af at de var M\248rkets tjenere.[ENTER]Men det er ikke alt: En skr\230kkelig \229nd i form af[ENTER]en kvinde sv\230vede over deres hoveder. M\248rkets[ENTER]tjenere kaldte hende Banshee. "
gameforge.main_quest_lv66._530_say = "Det lyder ikke godt. Hvad havde M\248rkets tjener og[ENTER]denne Banshee planlagt? "
gameforge.main_quest_lv66._540_say = "Banshee fremkaldte Agwi ved brug af sort magi,[ENTER]disse dj\230velske v\230sner kom direkte fra helveds[ENTER]k\230ber. De kaldte kongen af Agwi Azrael. "
gameforge.main_quest_lv66._550_say = "Jeg skyndte mig ud for at informere Lee Chung[ENTER]omkring dette. Men jeg snublede og blev opdaget.[ENTER][ENTER]Ah, jeg husker lige, kommand\248r Lee Chung har[ENTER]noget vigtigt at fort\230lle dig. Jeg vil skynde mig[ENTER]til ham, hvis jeg var dig. "
gameforge.main_quest_lv66._560_sendLetter = "M\248rk trussel "
gameforge.main_quest_lv66._570_say = "G\229 til Lee Chung og ta med ham om den nye trussel[ENTER]der lure i Dj\230vlens katakomber. "
gameforge.main_quest_lv66._580_say = "Det min spejder reporterede er rimelig skr\230mmende[ENTER]ikke? M\248rkets tjenere, en form for sekt, er[ENTER]ansvarlige for Agwis fremkomst. De har ogs\229[ENTER]fremkaldt \229nden fra den sidste Drage Pr\230stinde.[ENTER]Som en Banshee, en manifestation af det onde, er[ENTER]hun kommet tilbage til denne verden og ved hj\230lp[ENTER]af hendes magiske kr\230fter, kan de snart hidkalde[ENTER]D\230monguden Sung Mahi. "
gameforge.main_quest_lv66._590_say = "Hvad?! Denne Banshee er \229nden fra den sidste[ENTER]Drage Pr\230stinde?! "
gameforge.main_quest_lv66._600_say = "Uden tvivl. Selv blandt hendes s\248stre fra Drage[ENTER]kulten, er det kun hende der besidder kraften til[ENTER]at fremkalde de hellige fire himmel skildvagter[ENTER]og at fremf\248re den sorte heksekr\230ft.[ENTER]Nu ved vi hvem der er bag denne nye trussel:[ENTER]disse m\248rkets tjenere og Banshee planl\230gger at[ENTER]f\230rdigg\248re den M\248rke Nations arbejde og v\230kke[ENTER]Sung Mahi! "
gameforge.main_quest_lv66._60_sendLetter = "Puslespillets l\248sning "
gameforge.main_quest_lv66._610_say = "Vi har meget at takke dig for: du har redet en af[ENTER]mine m\230nd fra den sikre d\248d og kun derved, har vi[ENTER]v\230ret i stand til at l\230re om den pludselige[ENTER]fremkomst af Agwi og den seneste trussel i[ENTER]Dj\230vlens Katakomber. Tag lidt tid og f\229 slappet[ENTER]af, og s\229 vil vi starte med at tale om en[ENTER]passende taktik. "
gameforge.main_quest_lv66._620_say = "Eventyret vil forts\230tte n\229r du har n\229et level 72. "
gameforge.main_quest_lv66._70_say = "Uriel leder efter dig. Han har nu l\230st dagbogen. "
gameforge.main_quest_lv66._80_say = "Ah vidunderligt. Der er du.[ENTER]Den sidste Drage Pr\230stindes fort\230lling er[ENTER]virkelig forbl\248ffende. H\248r godt efter: "
gameforge.main_quest_lv66._90_say = "Min sk\230bne er nu besejlet! Jeg har barrikaderet[ENTER]mig i det h\248jeste etage i dette t\229rn og Lee Seops[ENTER]m\230nd er lige ved at bryde igennem d\248ren til mit[ENTER]sidste f\230ngsel. Der er ingen udvej, jeg har tabt.[ENTER][ENTER]Nej! Det kan ikke ende s\229dan her! Det kan ikke[ENTER]alt sammen v\230re afgjort allerede. Jeg er n\248d til[ENTER]at fremmane den Sorte heksekr\230ft, denne antikke[ENTER]onde kraft, alen og fremkalde m\248rke kr\230fter.[ENTER]Det vil helt sikkert betyde min d\248d. Men mine[ENTER]fjender vil tage del i min undergang, hvis det er[ENTER]den sidste ting jeg g\248r! "
gameforge.main_quest_lv7 = {}
gameforge.main_quest_lv7._100_say = "Hvad, har du ikke afleveret den endnu?[ENTER]Fiskestangen er til fiskerne ved floden. Skynd[ENTER]dig, han har desperat brug for den! "
gameforge.main_quest_lv7._10_targetVid = "Endnu et \248nske "
gameforge.main_quest_lv7._110_npcChat = "V\229bensmeden har sendt en ny stang! "
gameforge.main_quest_lv7._120_say = "Mange tak. Nu kan jeg endelig skille mig af med[ENTER]min betroede men meget udtjente fiskestang.[ENTER]Jeg tjener ikke bare mine penge p\229 fiskeri, men[ENTER]det er ogs\229 en stor gl\230de for mig i livet![ENTER]Kender du noget til fiskeri? "
gameforge.main_quest_lv7._130_say = "Tag fiskestangen i h\229nden, og put madding p\229[ENTER]krogen ved at klikke p\229 den. S\229 kast den ved at[ENTER]bruge dine fiskeevner. N\229r du tror du m\229ske har[ENTER]fanget en fisk, brug dine evner igen. Disse vande[ENTER]er meget gode til fiskeri grundet deres[ENTER]biologiske mangfoldighed.[ENTER]Fisk er ikke kun n\230ringsrige og sunde, men kan[ENTER]ogs\229 hj\230lpe dig med at f\229 fat i v\230rdifulde[ENTER]skatte. Du burde pr\248ve det. "
gameforge.main_quest_lv7._140_say = "N\229 ja - her er kviteringen p\229 at jeg har f\229et[ENTER]fiskestangen. Du burde aflevere den hos smeden. "
gameforge.main_quest_lv7._150_sayItem = "Kvitering p\229 fiskestang "
gameforge.main_quest_lv7._160_sayReward = "Du har afleveret fiskestangen hos fiskeren. G\229[ENTER]tilbage med kviteringen til smeden, s\229 du kan f\229[ENTER]din bel\248nning. "
gameforge.main_quest_lv7._170_say = "Har du fundet Fiskeren?[ENTER]Super, du har sparet mig noget v\230rdigfuldt tid[ENTER]ved at lave den levering. Som bel\248nning, vil jeg[ENTER]give dig nogle Yang og 1,500 erfaringspoint. "
gameforge.main_quest_lv7._180_sendLetter = "Kupon "
gameforge.main_quest_lv7._190_sayReward = "Med denne kupon f\229r du en del af din rustning[ENTER]gratis for\230dlet. Tag en udrustning og tr\230k den[ENTER]over smeden, s\229 for\230dlingen kan gennemf\248res. "
gameforge.main_quest_lv7._200_sayItem = "Kupon til en gratis genstands for\230dling "
gameforge.main_quest_lv7._20_sayReward = "G\229 til smeden.[ENTER]Han s\248ger nogen, der har afleveret noget til[ENTER]fiskeren. "
gameforge.main_quest_lv7._210_sayTitle = "Info: "
gameforge.main_quest_lv7._220_sayReward = "1) Kuponen vises ikke i inventaret.[ENTER]2) En succesfuld opgradering - som alle andre -[ENTER]er ikke 100% garanteret. "
gameforge.main_quest_lv7._230_sayTitle = "Kupon er allerede brugt "
gameforge.main_quest_lv7._240_sayReward = "Du har allerede brugt kuponen til en gratis[ENTER]for\230dling. Den er kun gyldig til en for\230dling. "
gameforge.main_quest_lv7._30_say = "V\230r hilset eventyre! Kunne du g\248re mig endnu en[ENTER]tjeneste? Normalt sp\248rger jeg ikke andre[ENTER]mennesker om at g\248re ting for mig, men du virker[ENTER]meget p\229lidelig. T\230nk p\229 det som en \230re! "
gameforge.main_quest_lv7._40_say = "Jeg har smedet en fiskestang til fiskeren.[ENTER]Desv\230rre har jeg meget travlt, derfor kan jeg[ENTER]ikke aflevere den selv. Kunne du ikke klare det[ENTER]for mig? "
gameforge.main_quest_lv7._50_sayItem = "En fiskestang med stor elasticitet "
gameforge.main_quest_lv7._60_say = "Fiskeren skulle v\230re et sted n\230r floden.[ENTER]Hvis du levere fiskestangen til fiskeren, vil jeg[ENTER]for\230dle et stykke af dit udstyr gratis. Det er en[ENTER]fair aftale; synes du ikke? "
gameforge.main_quest_lv7._70_sendLetter = "Find fiskeren "
gameforge.main_quest_lv7._80_sayReward = "Smeden har smedet en fiskestang til fiskeren.[ENTER]Find fiskeren ved floden og aflever fiskestangen[ENTER]til ham. "
gameforge.main_quest_lv7._90_npcChat = "Hvem er fiskestangen til? "
gameforge.main_quest_lv72 = {}
gameforge.main_quest_lv72._100_say = "Himlens t\229re f\229r sin perfekte glans fra de[ENTER]magiske unison fra det hellige gummi tr\230, Bl\229[ENTER]krystal essens, og R\248d helveds kvarts. Det bl\229[ENTER]krystal essens skal hentes ved herskeren af is[ENTER]landet. "
gameforge.main_quest_lv72._10_sendLetter = "Slidt sten tavle "
gameforge.main_quest_lv72._110_say = "Du har lavet en note af denne markante[ENTER]inskription. Reporter til Lee Chung hvad du lige[ENTER]har l\230st. "
gameforge.main_quest_lv72._120_say = "Ah, du er vendt tilbage i god behold! Hvis jeg[ENTER]l\230ser dit ansigt korrekt, s\229 g\229r jeg ud fra du[ENTER]har haft succes? "
gameforge.main_quest_lv72._130_say = "Faktisk, ja! Takket v\230re inskriptionen p\229 den[ENTER]slidte sten tavle, har jeg fundet ud af at du kan[ENTER]fremkalde hellige kr\230fter ved at bruge en magisk[ENTER]juvel, kendt som himlens t\229re. "
gameforge.main_quest_lv72._140_say = "Himlens t\229re... s\229 de eksistere. Har du fundet[ENTER]nogen spor i retning af hvordan vi f\229r fat i[ENTER]disse? "
gameforge.main_quest_lv72._150_say = "For at producere Himlens t\229re, skal du have[ENTER]helligt gummi tr\230, bl\229 krystal essens og r\248d[ENTER]helveds kvarts. Det siges at bl\229 krystal essens[ENTER]skal erhverves fra herskeren af Is landet. "
gameforge.main_quest_lv72._160_say = "Herskeren af Is landet? Hmm... Med det m\229 de mene[ENTER]Mount Sohan.[ENTER]Jeg vil vise dine noter til skygge krigernes[ENTER]troldm\230nd og analysere den med dem.[ENTER]Jeg vil kontakte dig n\229r jeg ved mere! "
gameforge.main_quest_lv72._170_say = "Tag dette som bel\248nning for dine handlinger. Jeg[ENTER]forts\230tter med at regne med din hj\230lp! "
gameforge.main_quest_lv72._180_sendLetter = "Isnende skat "
gameforge.main_quest_lv72._190_say = "Kommand\248r Lee Chung har informeret dig om at det[ENTER]f\248rste element der skal bruges til Himlens t\229re,[ENTER]bl\229 krystal essens, har noget at g\248re med den[ENTER]legendariske nihalede skat ved Sohan bjerget.[ENTER]Den bliver overv\229get meget n\248je af Is golems,[ENTER]Yetier og k\248lige ism\230nd. Jagt disse monstre for[ENTER]at komme i besiddelse af den bl\229 krystal essens.[ENTER]Tal med Lee Chung igen inden du drage i kamp. "
gameforge.main_quest_lv72._200_say = "Skygge krigernes troldm\230nd har fundet ud af at[ENTER]den frygtindgydende nihalede af Sohan bjerget ser[ENTER]efter den bl\229 essens som var det \230blet i dens[ENTER]\248je. "
gameforge.main_quest_lv72._20_say = "Lee Chung, kommand\248r over Skygge krigerne, vil[ENTER]gerne tale med dig. Han har fundet ud af hvordan[ENTER]du kan besejre Agwi i Dj\230vlens Katakomber. "
gameforge.main_quest_lv72._210_say = "Den Nihaledes skat vogtes af Is golems, Yetier og[ENTER]K\248lige ism\230nd.[ENTER][ENTER]50 Bl\229 krystal Essens er n\248dvendige for at kunne[ENTER]fremstille himlens t\229re. "
gameforge.main_quest_lv72._220_say = "R\248d helveds kvarts menes at befinde sig i enten[ENTER]Hwang templet eller i Ild landet. Jeg har sendt[ENTER]spejdere ud for at finde ud af mere. "
gameforge.main_quest_lv72._230 = "Kommand\248r Lee Chung har informeret dig om at det[ENTER]f\248rste element der er n\248dvendigt til Himlens[ENTER]t\229re, Bl\229 krystal essens, har noget at g\248re med[ENTER]den legendariske nihaledes skat p\229 Sohan bjerget.[ENTER]Den bliver n\248je overv\229get af is golems, Yetier og[ENTER]K\248lige ism\230nd. Jagt disse monstre for at komme i[ENTER]besiddelse af den bl\229 krystal essens. "
gameforge.main_quest_lv72._240_notice = "Du s\248ger igennem kroppene af de besejrede monstre[ENTER]og finde en bl\229, glimtende \230delsten.[ENTER]Det m\229 v\230re den bl\229 krystal essens. "
gameforge.main_quest_lv72._250_notice = "Du skal finde %d Bl\229 krystal essens. "
gameforge.main_quest_lv72._260_say = "Jeg tror du har f\229et r\229d nok for i dag. Kom[ENTER]tilbage i morgen. "
gameforge.main_quest_lv72._270_say = "Disse krystaller er ubrugelige. Se selv: De har[ENTER]revner. For at kunne bruge dem, skal de v\230re[ENTER]fejlfri! Forts\230t din s\248gning! "
gameforge.main_quest_lv72._280_say = "Disse er af en fremragende kvalitet! Forts\230t! Jeg[ENTER]beh\248ver stadig %d. "
gameforge.main_quest_lv72._290_say = "Du har samlet alle de bl\229 krystal essens vi[ENTER]beh\248ver. Jeg kan f\248le den nihaledes kr\230ft i dem.[ENTER]Fantastisk... De vibrere positivt med energi.[ENTER]Godt g\229et! "
gameforge.main_quest_lv72._300_say = "Eventyret vil forts\230tte n\229r du har n\229et level 78. "
gameforge.main_quest_lv72._30_say = "Til forskel fra de d\230moner vi er vandt til, kan[ENTER]du ikke bare dr\230be Agwi. Vi Skygge krigere har[ENTER]allerede pr\248vet alle mulige m\229der vi kunne komme[ENTER]i tanke om - uden succes. "
gameforge.main_quest_lv72._40_say = "Men nu har jeg fundet ud af at Drage Pr\230stinden[ENTER]besidder kr\230ften til at fremkalde hellige kr\230fter[ENTER]som er istand til at forvise onde \229nder. "
gameforge.main_quest_lv72._50_say = "I den R\248de skov der var en af Drage Pr\230stindernes[ENTER]hellige templer. S\248g der efter ruiner og tegn p\229[ENTER]deres kult. Spejdere har reporteret omkring en[ENTER]slidt tavle lavet af sten, som er blevet d\230kket[ENTER]af krat... M\229ske vil vi finde noget brugbart p\229[ENTER]denne sten. "
gameforge.main_quest_lv72._60_sendLetter = "Opdagelsen "
gameforge.main_quest_lv72._70_say = "Lee Chung har fortalt at Drage Pr\230stinderne var[ENTER]istand til at fremkalde hellige kr\230fter, en antik[ENTER]hvid magi, som fremkalder onde \229nder. S\248g i den[ENTER]R\248de skov efter den slidte sten tavle som Lee[ENTER]Chung spurgte om, og erhverv yderligere beviser. "
gameforge.main_quest_lv72._80_say = "Efter en lang efters\248gning, finder du en sten[ENTER]tavle i underskoven, som ser ud til at have lagt[ENTER]der i \229rhundreder. Det m\229 v\230re den gamle tavle[ENTER]som Lee Chung talte om! Du afkoder omhyggeligt[ENTER]den slidte inskription. "
gameforge.main_quest_lv72._90_say = "Himlens t\229re er Drage Pr\230stindernes mest[ENTER]v\230rdifulde hemmelighed. Kunsten at fremstille dem[ENTER]har v\230ret holdt hemmeligt i generationer og i[ENTER]ekstreme tilf\230lde, forsvaret med blod. Agwi og[ENTER]d\230moner kan ikke umiddelbart n\230rme sig dem der[ENTER]b\230re disse juveler. Hvis Himlens t\229re f\248rst er[ENTER]fyldt med styrken fra de hellige kr\230fter, er[ENTER]effekten af disse dem overlegne. De skinder s\229[ENTER]klart som polar stjernen p\229 himlen, syv sol[ENTER]skiver lange. "
gameforge.main_quest_lv78 = {}
gameforge.main_quest_lv78._100_say = "Ah fantastisk! Det virkede. Her er din R\248de[ENTER]helveds kvarts. "
gameforge.main_quest_lv78._10_sendLetter = "R\248d helveds kvarts "
gameforge.main_quest_lv78._110_sendLetter = "Sidste element "
gameforge.main_quest_lv78._120_say = "Lee Chung og r\229det af troldm\230nd har opdaget at du[ENTER]kan erhverve det sidste element Helligt gummi[ENTER]tr\230, fra R\248d ondt tr\230. Forts\230t og jagt dem i den[ENTER]r\248de skov og saml 100 potioner tr\230 gummi. Tal med[ENTER]Lee Chung inden du drager ud. "
gameforge.main_quest_lv78._130_say = "Lee Chung og r\229det af troldm\230nd har opdaget at du[ENTER]kan erhverve det sidste element Helligt gummi[ENTER]tr\230, fra R\248d ondt tr\230. Forts\230t og jagt dem i den[ENTER]r\248de skov og saml 100 potioner tr\230 gummi. "
gameforge.main_quest_lv78._140_say = "Dette er det sidste step i produktionen af[ENTER]himlens t\229re. Pas p\229 dig selv, den r\248de skov[ENTER]myldre med d\248delige v\230sner! "
gameforge.main_quest_lv78._150_say = "Du mangler stadig at samle %d potioner fra det[ENTER]Hellige gummi tr\230. "
gameforge.main_quest_lv78._160_notice = "Du har fundet nok Helligt gummi tr\230! Bring det[ENTER]til Kommand\248r Lee Chung. "
gameforge.main_quest_lv78._170_say = "Er det det Hellige Gummi tr\230? Jeg kan m\230rke de[ENTER]enorme kr\230fter. Fantastisk![ENTER]Desv\230rre var jeg n\248d til at sende alle[ENTER]troldm\230ndene p\229 mission. De vil v\230re v\230k i en[ENTER]tid. Er der ikke en kemiker i din hjem by, der[ENTER]g\229r ved navnet Baek-Go? "
gameforge.main_quest_lv78._180_say = "Jo, det er der. "
gameforge.main_quest_lv78._190_say = "Ah, superb! Tag de tre elementer og bring dem til[ENTER]Baek-Go. Han vil v\230re i stand til at danne[ENTER]himlens t\229re af dem. "
gameforge.main_quest_lv78._200_say = "Du har en lang og udmattende rejse bag dig. Tag[ENTER]venligst denne bel\248nning for alle dine[ENTER]anstrengelser. "
gameforge.main_quest_lv78._20_say = "Lee Chung, kommand\248r over skygge krigerne har[ENTER]fundet ud af mere om de r\248de helveds kvarts. For[ENTER]at danne disse, skal du bruge tre forskellige[ENTER]substanser: Vulkansk jord fra Doyyumhwan,[ENTER]Skindende h\229rpragt og Fundament sten.[ENTER]Jagt Flamme, Flamme kriger og k\230mpende tigere i[ENTER]ild landet for at f\229 disse substanser og saml 20[ENTER]af hver til 20 r\248de helveds kvarts.[ENTER]Tal med Lee Chung igen inden du drager i kamp. "
gameforge.main_quest_lv78._210_sendLetter = "Himlens t\229re "
gameforge.main_quest_lv78._220_say = "Drag tilbage til din hjem by, s\248g Baek-Go og bed[ENTER]ham danne Himlens t\229re ud af de tre elementer i[ENTER]Lee Chungs navn. "
gameforge.main_quest_lv78._230_say = "Du har v\230ret v\230k i en del tid. Jeg var begyndt at[ENTER]sp\248rge mig om der var sket noget med dig. Hvad[ENTER]bringer dig til mig? "
gameforge.main_quest_lv78._240_say = "Lee Chung har bedt mig komme til dig for en[ENTER]tjeneste. "
gameforge.main_quest_lv78._250_say = "Lee Chung?! Kommand\248r over skygge krigerne... Oh![ENTER]Shhhhh! Stille! Du st\229r foran en skygge kriger[ENTER]troldman. Men den information er top hemmelig,[ENTER]ingen i landsbyen kan vide det.[ENTER]Hvilken tjeneste beder Lee Chung mig om? "
gameforge.main_quest_lv78._260_say = "Han beder dig lave Himlens t\229re ud af disse tre[ENTER]elementer. "
gameforge.main_quest_lv78._270_say = "Himlens t\229re eh... Han har s\229 mange troldm\230nd til[ENTER]r\229dighed, hvorfor efterlader han altid de sv\230re[ENTER]opgaver til mig?![ENTER]...[ENTER]Ok. Nu er vi her jo, Himlens t\229re.[ENTER]Smukt! Jeg vil sende dem direkte til Lee Chung[ENTER]via sendebud og han kan hidkalde dig n\229r alt er[ENTER]klart. Kan du fort\230lle mig hvad det er til? "
gameforge.main_quest_lv78._280_say = "Jeg kan ikke rigtigt fort\230lle dig noget[ENTER]specifikt. Kun dette: denne sten sammekalder de[ENTER]hellige kr\230fter for at forvise d\230moner og andre[ENTER]onde v\230sner. "
gameforge.main_quest_lv78._290_say = "Meget interessant. Jeg \248nsker dig den bedste[ENTER]succes i din opgave. Som bel\248nning for dine[ENTER]handlinger indtil nu, her er to skrumpe hoveder.[ENTER]Nu hvor jeg ved hvordan processen virker, er jeg[ENTER]glad for at kunne hj\230lpe dig, hvis du skulle[ENTER]bruge yderligere himmel t\229re.[ENTER]Oh og vil du v\230re s\248d ogs\229 at overbringe mine[ENTER]bedste hilsner til Lee Chung? "
gameforge.main_quest_lv78._300_say = "Eventyret forts\230tter n\229r du er n\229et level 84. "
gameforge.main_quest_lv78._30_say = "Vores troldm\230nd har fundet ud af at R\248d helveds[ENTER]kvarts som skal bruges til at producere Himlens[ENTER]t\229re, b\230re ildens kr\230fter i sig.[ENTER]Denne kvarts m\229 ogs\229 v\230re grunden til den[ENTER]ufattelige styrke v\230snerne i ild landet har. "
gameforge.main_quest_lv78._40_say = "R\248d helveds kvart laves af tre substanser.[ENTER]Vulkansk jord, Skinnende h\229rpragt og Fundament[ENTER]sten. Du kan finde dem alle i ild landet. "
gameforge.main_quest_lv78._50_say = "Du gjorde det! Endelig har vi de %d stykker af[ENTER]r\248d helveds kvarts vi skal bruge. Din tapperhed[ENTER]og styrke har endnu engang overg\229et mine[ENTER]forventninger! "
gameforge.main_quest_lv78._60_say = "En substans mangler. Vi har behov for Vulkansk[ENTER]jord, Skinnende h\229rpragt s\229 vel som Fundament[ENTER]sten. "
gameforge.main_quest_lv78._70_say = "Jeg er ked af det, men jeg kan kun producere syv[ENTER]stykker R\248d helveds kvarts pr. dag. Denne[ENTER]procedure er en udfordring for mine magiske[ENTER]f\230rdigheder. Jeg er ikke engang troldmand! "
gameforge.main_quest_lv78._80_say = "Okay s\229! Jeg vil nu mikse de tre substanser[ENTER]sammen og fors\248ge at lave R\248d helveds kvarts. "
gameforge.main_quest_lv78._90_say = "Argh! Magien fejlede. \197benbart overvurderede jeg[ENTER]min magiske kapacitet. N\230ste gang vil det g\229[ENTER]bedre er jeg sikker p\229. "
gameforge.main_quest_lv84 = {}
gameforge.main_quest_lv84._100_say = "Nu hvor du har besejret General Tartaros, er en[ENTER]indgang til en tidligere gemt etage af Dj\230vlens[ENTER]Katakomber blevet \229bnet. Prins Charon m\229 v\230re der[ENTER]nede! Teleporter til den sjette etage og m\248d[ENTER]prinsen af Agwi. Men v\230r forsigtig! Han er[ENTER]ekstremt st\230rk og snedig som en dj\230vel. "
gameforge.main_quest_lv84._10_sendLetter = "Kampen begynder "
gameforge.main_quest_lv84._110_say = "Den m\229de du bev\230ger dig igennem Dj\230vlens[ENTER]katakomber - frit og frygtl\248s - det er umuligt at[ENTER]du bare er en almindelig d\248delig![ENTER]Den bastalte obliks p\229 femte sal vil agere som[ENTER]portal til den skjulte sjette etage. "
gameforge.main_quest_lv84._120_say = "Prins Charon levere alle hans kommandoer til Agwi[ENTER]general Tartaros derfra.[ENTER]Hvad venter du p\229? Besejr Charon og forhindre[ENTER]m\248rkets tjenere og Banshees skumle planer! "
gameforge.main_quest_lv84._130_sayReward = "Du gjore det! Charon, prins af Agwi, er blevet[ENTER]tilintetgjort. "
gameforge.main_quest_lv84._140_say = "Udmattet men lettet, t\248rre du svenden af din[ENTER]pande. Pludselig lyder en skinger latter igennem[ENTER]Dj\230vlens katakomber, s\229 gennemtr\230ngende at den[ENTER]sk\230re ind til marven i dine ben:[ENTER]Ahahahahaha! For sent, dit patetiske menneske![ENTER]Vores mester Sung Mahi er allerede genopst\229et og[ENTER]der er ingen ting du kan g\248re for at stoppe det[ENTER]nu![ENTER]Dagen n\230rmer sig hvor Sung Mahi vil n\229 sin fulde[ENTER]styrke p\229 \248en hvor de onde drager sover. Din[ENTER]verden er d\248dsd\248mt! "
gameforge.main_quest_lv84._150_sendLetter = "Uafsluttet historie "
gameforge.main_quest_lv84._160_say = "Drag til Lee Chung og afl\230g rapport om Banshees[ENTER]truende besked til ham. "
gameforge.main_quest_lv84._170_say = "Efter du reportere om din sejr over Tartaros og[ENTER]Charon til kommand\248ren, gentager du Banshees[ENTER]frygtindgydende besked. Med et seri\248st ansigts[ENTER]udtryk, begynder han at tale: "
gameforge.main_quest_lv84._180_say = "Jeg gik ud fra at n\229r vi besejrede Agwi prinsen[ENTER]ville vi forpurre m\248rkets tjenere og Banshees[ENTER]planer. Hvor tog jeg fejl... "
gameforge.main_quest_lv84._190_say = "Banshee m\229 have klaret at f\230rdigg\248re opstandelsen[ENTER]af Sung Mahi sammen med Azrael, konge over Agwi.[ENTER]Jeg gyser ved tanken om det... "
gameforge.main_quest_lv84._200_say = "\216en hvor de onde drager sover...[ENTER]Hmm, med det m\229 de mene de M\248rke Dragers Klippe.[ENTER]Det er en u-kortlagt \248 langt herfra.[ENTER]Selv om vi ikke opn\229ede hvad vi havde h\229bet p\229,[ENTER]skylder vi dig stadig vores st\248rste[ENTER]taknemmelighed. Uden din hj\230lp ville vi aldrig[ENTER]havde v\230ret i stand til at afd\230kke det onde der[ENTER]lurede i Dj\230vlens katakombers dyb. "
gameforge.main_quest_lv84._20_say = "Lee Chung har modtaget himlens t\229re og har[ENTER]forberedt alt til din mission ind i dj\230vlens[ENTER]katakomber. Drag til ham og find ud af mere. "
gameforge.main_quest_lv84._210_say = "Du har udrettet en virkelig stor gerning, en[ENTER]gerning som ingen ud over dig var i stand til.[ENTER]Jeg vil v\230re klar til at st\229 ved din side til[ENTER]hver en tid, i resten af mit liv. Farvel! "
gameforge.main_quest_lv84._30_say = "Nu hvor vi holder himlens t\229re i vores h\229nd, er[ENTER]det kun et sp\248rgsm\229l om tid inden vi besejre[ENTER]M\248rkets tjenere og bortviser Agwi ud af vores[ENTER]verden! Men t\229rnes fulde kraft vil f\248rst blive[ENTER]frigivet n\229r de anvendes p\229 en specifik position[ENTER]i Dj\230vlens katakomber. "
gameforge.main_quest_lv84._40_say = "Vi kender til de fem etager i Dj\230vlens[ENTER]katakomber. P\229 den femte og sidste etage vi[ENTER]kender til, vil du st\248de p\229 Tartaros, den[ENTER]skr\230kindjagende Agwi general og og i tredje linje[ENTER]bag King Azrael og Charon. Besejr ham ved hj\230lp[ENTER]af Himlens t\229re. "
gameforge.main_quest_lv84._50_say = "Men hvor er Charon? "
gameforge.main_quest_lv84._60_sendLetter = "Genereal Tartaros "
gameforge.main_quest_lv84._70_say = "Brug kun Himlens t\229re n\229r du er n\229et til femte[ENTER]etage i Dj\230vlens katakomber. Indgangen til[ENTER]dj\230vlens katakomber kan finde bag D\230mon t\229rnet. "
gameforge.main_quest_lv84._80_say = "De hellige kr\230fter begynder at yde en effekt[ENTER]inden i Himlens t\229re. Du m\230rker en enorm kr\230ft[ENTER]flyde igennem din krop. Kr\230ften af disse sten er[ENTER]fuldst\230ndig vanvittig.[ENTER][ENTER]Besejr General Tartaros. "
gameforge.main_quest_lv84._90_sendLetter = "Prins Charon "
gameforge.main_quest_lv9 = {}
gameforge.main_quest_lv9._10_targetVid = "Find byvagten "
gameforge.main_quest_lv9._20_sendLetter = "Snak med byvagten "
gameforge.main_quest_lv9._30_sayReward = "Du har taget de f\248rste skridt p\229 vejen til at[ENTER]blive en sand helt. Det er nu tid til st\248rre[ENTER]ting. Drag til byvagten og modtag din sidste[ENTER]begynder mission fra ham. "
gameforge.main_quest_lv9._40_say = "Er du klar til at gennemf\248re sv\230rer opgaver? Det[ENTER]bliver nok n\230ppe s\229 nemt som nu. Hvis Riget skal[ENTER]opleve en god fremtid skal du arbejde h\229rdt! Du[ENTER]har gennemf\248rt adskillige opgaver. Derfor har du[ENTER]fortjent f\248lgende..[ENTER]Det vil nytte dig en del.  "
gameforge.main_quest_lv9._50_say = "Fra nu af vil kaptajnen stille dig opgaverne. Han[ENTER]vil holde \248je med dig i fremtiden. Sammel lidt[ENTER]erfaring og g\229 til kaptajnen. Held og[ENTER]lykke!  "
gameforge.main_quest_lv90 = {}
gameforge.main_quest_lv90._010_sendLetter = "M\248rk Drage Klippe "
gameforge.main_quest_lv90._020_say = "Din rejse har v\230ret lang og besv\230rlig. Men nu har[ENTER]du endelig n\229et dit m\229l: M\248rk Drage Klippe. Ops\248g[ENTER]Admiral Angur. Du vil finde ham i Kap Drageild. "
gameforge.main_quest_lv90._030_say = "Velkommen til M\248rk Drage Klippe, fremmede! Er du[ENTER]kommet for at hj\230lpe os i kampen mod Sung Mahi? "
gameforge.main_quest_lv90._040_say = "Ja, absolut. Lee Chung, skygge krigernes[ENTER]kommand\248r, sendte mig. "
gameforge.main_quest_lv90._050_say = "Lee Chung! Han har l\230nge v\230ret en af mine[ENTER]f\248lgesvende. S\229 du er her p\229 hans anmodning. Ja,[ENTER]s\229 ved jeg, at jeg kan stole p\229 dig. "
gameforge.main_quest_lv90._060_say = "Jeg takker dig. Hvordan er situationen her? "
gameforge.main_quest_lv90._070_say = "D\230moner hersker over store dele af \248en.[ENTER]Intet og ingen er beskyttet mod dem. De spiser[ENTER]endda hinanden. Den m\248rke indflydelse fra Sung[ENTER]Mahi har f\229et dem alle til at miste forstanden. "
gameforge.main_quest_lv90._080_say = "I kunne bruge din hj\230lp. Kunne du udforske \248en og[ENTER]give mig en opdateret rapport p\229 situationen? "
gameforge.main_quest_lv90._090_say = "Selvf\248lgelig. "
gameforge.main_quest_lv90._1000_say = "Forst\229et. "
gameforge.main_quest_lv90._100_say = "Jeg takker dig. Vent, jeg vil gerne vise dig[ENTER]vejen. "
gameforge.main_quest_lv90._1010_say = "Du er meget flittig, men det er ikke nok. Bliv[ENTER]ved med at indsamle! "
gameforge.main_quest_lv90._1020_sayTitle = "Indsaml ler sten "
gameforge.main_quest_lv90._1030_say = "Drag i kamp mod Manticore for at samle ler sten. "
gameforge.main_quest_lv90._1040_1_notice = "Du har samlet nok ler sten. "
gameforge.main_quest_lv90._1040_2_notice = "Lever dem til Admiral Angmur. "
gameforge.main_quest_lv90._1050_say = "Tal med admiral Angmur. "
gameforge.main_quest_lv90._1060_say = "Meget godt, takket v\230re dig har vi nok materialer[ENTER]til at styrke forsvars volden. S\229 snart vi er[ENTER]f\230rdige med det, vil jeg sende bud efter dig. "
gameforge.main_quest_lv90._1070_sendLetter = "Lee Chungs opgave "
gameforge.main_quest_lv90._1080_say = "Lee Chung har en opgave til dig. "
gameforge.main_quest_lv90._1090_say = "Desv\230rre er det nogle d\229rlige nyhedder, der[ENTER]bringer os sammen igen: M\248rkets tjenere er t\230t p\229[ENTER]deres m\229l.[ENTER]Snart vil Sung Mahi v\230re uovervindelig.[ENTER]Vi har ingen tid at spilde. Tag til teleporteren.[ENTER]Derfra vil et skib tage dig til M\248rk Drage[ENTER]Klippe. Ops\248g Admiral Angmur. Jeg har allerede[ENTER]sendt et brev, som annoncerer din ankomst. "
gameforge.main_quest_lv90._1100_say = "Jeg vil tage afsted med det samme. "
gameforge.main_quest_lv90._110_sayReward = "Udforsk M\248rk Drage Klippe. G\229 hertil f\248rst: (%d,[ENTER]%d). "
gameforge.main_quest_lv90._1110_sayTitle = "Tag afsted mod \248en "
gameforge.main_quest_lv90._1120_say = "Tag til Teleporter. Han vil bringe dig til M\248rk[ENTER]Drage Klippe. "
gameforge.main_quest_lv90._1160_targetInfo = "Pilen over NPC viser dig at denne person \248nsker[ENTER]at tale med dig. Hvis du ikke kan se NPC p\229 din[ENTER]sk\230rm, f\248lg den blikende prik p\229 minimappet. "
gameforge.main_quest_lv90._1170_posInfo = "F\248lg den blinkende prik p\229 minimappet. "
