gameforge.main_quest_lv90._200_say = {}
gameforge.main_quest_lv90._210_sayReward = "Din tredje destination er: %d, %d "
gameforge.main_quest_lv90._220_sayReward = "Du har udforsket alle regioner.[ENTER]Returner til Admiral Angmur. "
gameforge.main_quest_lv90._230_say = "Tal med admiral Angmur. "
gameforge.main_quest_lv90._240_say = "Efter du har vandret hele \248en igennem, er[ENTER]f\248lgende erkendelse blevet klar for dig: Overalt[ENTER]vrimler det med d\230moner. "
gameforge.main_quest_lv90._250_say = "Du har gjort det godt. Tag dette som tak for din[ENTER]hj\230lp. "
gameforge.main_quest_lv90._260_sendLetter = "Lee Chungs brev "
gameforge.main_quest_lv90._270_say = "Mens du giver din nuv\230rende forklaring omkring[ENTER]situationen p\229 M\248rk Drage Klippe, bliver Admiral[ENTER]Angmurs ansigtsudtryk m\248rkere. "
gameforge.main_quest_lv90._280_say = "Jeg ville gerne have v\230ret i stand til at bringe[ENTER]dig bedre nyhedder. "
gameforge.main_quest_lv90._290_say = "D\230monerne p\229 \248en bliver endnu st\230rkere. Selv hvis[ENTER]vi er ude af stand til at stoppe Sung Mahi og[ENTER]M\248rkets tjenere, m\229 Drage Guden v\230re os[ENTER]barmhjertige. "
gameforge.main_quest_lv90._300_say = "Ja, jeg indr\248mmer, at det synes temmelig dystert. "
gameforge.main_quest_lv90._310_say = "Ja, kan du sige det igen ...[ENTER]Lee Chung skal have afsl\248ret et afg\248rende[ENTER]fingerpeg.[ENTER]Han sendte mig et brev med nogle vigtige[ENTER]oplysninger.[ENTER]Men det n\229ede aldrig mig. Budskabet blev opfanget[ENTER]af gnolls. "
gameforge.main_quest_lv90._320_say = "Vi er n\248dt til at finde dette brev. Kan du hj\230lpe[ENTER]os? "
gameforge.main_quest_lv90._330_say = "Selvf\248lgelig. Jeg er allerede p\229 vej. "
gameforge.main_quest_lv90._340_say = "Jeg takker dig. Gnolls er allerede meget t\230t her[ENTER]p\229. "
gameforge.main_quest_lv90._350_sayTitle = "Find Lee Chungs brev. "
gameforge.main_quest_lv90._360_say = "Et af de f\248lgedende v\230sner har Lee Chungs brev:[ENTER]Gnoll kriger, Gnoll bueskytte, Gnoll forsvarer,[ENTER]Gnoll magiker, Gnoll general,Gnoll Lord eller[ENTER]\216verste Gnoll vagt "
gameforge.main_quest_lv90._370_say = "Hvis vi vil stoppe Sung Mahi, beh\248ver vi dette[ENTER]brev![ENTER]Tyvene kommer fra r\230kkerne i Gnoll stammen. "
gameforge.main_quest_lv90._380_1_notice = "Du har fundet brevet. "
gameforge.main_quest_lv90._380_2_notice = "Bring det til Admiral Angmur. "
gameforge.main_quest_lv90._390_say = "Tal med admiral Angmur. "
gameforge.main_quest_lv90._400_say = "Du er tilbage, og du har brevet! Ja, jeg vidste,[ENTER]jeg kunne regne med dig. Lad os s\229 se. "
gameforge.main_quest_lv90._410_say = "Hilsner Angmur![ENTER]Min ven, i Sung Mahis tomme lejre fandt vi noget:[ENTER]M\248rkets tjenere har henvendt sig til deres[ENTER]allierede p\229 \248en ved at bruge hemmelige beskeder.[ENTER]En s\229dan besked var sendt til Gnoll stammen. Hvis[ENTER]du kunne opfange dette, vil vi v\230re et vigtigt[ENTER]skridt foran d\230monerne! Jeg sender %s som st\248tte,[ENTER]og \248nsker dig styrke og mod i denne m\248rke tid.[ENTER]L.C. "
gameforge.main_quest_lv90._420_say = "Mine spejdere vil finde ud af, om gnolls allerede[ENTER]har modtaget brevet eller ej. I mellemtiden tag[ENTER]dette her, som en tak. "
gameforge.main_quest_lv90._430_sendLetter = "Gnoll brev I "
gameforge.main_quest_lv90._440_say = "Admiral Angmur kigger efter dig. Find ud af, hvad[ENTER]han vil. "
gameforge.main_quest_lv90._450_say = "Gnoll generalen har allerede modtaget brevet, som[ENTER]tjenerne har sendt. Kan du f\229 fat i det for os?[ENTER]V\230r forsigtig: gnolls er ekstremt aggressive.[ENTER]De angriber f\248rst og stiller sp\248rgsm\229l senere. "
gameforge.main_quest_lv90._460_say = "Jeg er allerede p\229 vej. "
gameforge.main_quest_lv90._470_say = "Tak. Jeg vidste jeg kunne regne med dig. "
gameforge.main_quest_lv90._480_sayTitle = "Find Gnoll brevet! "
gameforge.main_quest_lv90._490_say = "Find Gnoll generalen. Han har brevet! "
gameforge.main_quest_lv90._500_say = "Vi har ingen til at spilde. V\230r venlig at skynde[ENTER]dig og bring brevet til mig. "
gameforge.main_quest_lv90._510_1_notice = "Du har fundet Gnoll brevet. "
gameforge.main_quest_lv90._510_2_notice = "Bring det til Admiral Angmur. "
gameforge.main_quest_lv90._520_say = "Tal med admiral Angmur. "
gameforge.main_quest_lv90._530_say = "Du har brevet! Endelig nogle gode nyhedder, hva?[ENTER]Hmm...[ENTER]Jeg kan ikke l\230se et eneste ord. Dette brev ser[ENTER]ud til at v\230re krypteret. Vores l\230rde kende vejen[ENTER]omkring kryptologi. Jeg vil ops\248ge ham direkte.[ENTER]S\229 snart jeg ved mere, vil jeg kontakte dig. "
