gameforge.main_quest_lv90._570_say = "Admiral Angmur kigger efter dig. Find ud af, hvad[ENTER]han vil. "
gameforge.main_quest_lv90._580_say = "Det krypterede brev indeholder to sider. Beskeden[ENTER]kan kun blive afkodet, n\229r begge sider bliver[ENTER]lagt over hinanden. Gnoll Lord har den anden[ENTER]side.[ENTER]Kan du hj\230lpe os? "
gameforge.main_quest_lv90._590_say = "Selvf\248lgelig. "
gameforge.main_quest_lv90._600_say = "Tak. Din hj\230lp er uvurderlig! "
gameforge.main_quest_lv90._610_sayTitle = "Gnoll brev II "
gameforge.main_quest_lv90._620_say = "Find den anden side af Gnoll brevet![ENTER]Du vil f\229 den fra Lord Gnoll. "
gameforge.main_quest_lv90._630_say = "Tiden er ved at l\248be ud. Skynd dig og find den[ENTER]anden side af brevet. "
gameforge.main_quest_lv90._640_1_notice = "Du har fundet den anden side. Bring den til[ENTER]Admiral Angmur! "
gameforge.main_quest_lv90._650_say = "Fantastisk, nu kan vi afkode beskeden: Hmm, det[ENTER]ser ud til der bliver talt om dragerne, som over[ENTER]dybt i hjertet af verden. Det taler om en metode,[ENTER]hvorp\229 du kan v\230kke dem og g\248re dem gale.[ENTER]Oh ho! Det lyder ikke godt... "
gameforge.main_quest_lv90._660_say = {}
gameforge.main_quest_lv90._670_say = "Det ser ud til at Manticore og R\248d tyvs banden[ENTER]ogs\229 har modtaget breve. Jeg vil finde ud af mere[ENTER]omkring disse nyhedder, og s\229 vil jeg sende bud[ENTER]efter dig. "
gameforge.main_quest_lv90._680_say = "Admiral Angmur har en ny opgave til dig. "
gameforge.main_quest_lv90._690_sendLetter = "Manticore "
gameforge.main_quest_lv90._700_say = "Admiral Angmur har en ny opgave til dig. "
gameforge.main_quest_lv90._710_say = "Godt, du er her! Vores informationer omkring[ENTER]Manticore er meget gamle. Vi er n\248dt til at finde[ENTER]ud af, hvor st\230rke deres tropper er nu. "
gameforge.main_quest_lv90._720_say = "Kan du g\229 ud og udspionerer dem? Deres lejr er[ENTER]ikke langt herfra. "
gameforge.main_quest_lv90._730_say = "Selvf\248lgelig. Hvad skal jeg g\248re? "
gameforge.main_quest_lv90._740_say = "Besejre 50 Manticore krigere, 40 Manticore[ENTER]soldater, 20 Manticore b\248ddeler, samt besejrer[ENTER]General Cor 10 gange.[ENTER]S\229 rapporter tilbage til mig. "
gameforge.main_quest_lv90._750_say = "(Resterende: %s %s, %s %s) "
gameforge.main_quest_lv90._760_say = {}
gameforge.main_quest_lv90._770_say = "Informationerne du har f\229et er ikke nok. Du er[ENTER]n\248dt til at finde ud af mere. "
gameforge.main_quest_lv90._780_1_notice = "Du har samlet det n\248dvendig antal af[ENTER]informationer omkring Manticore. "
gameforge.main_quest_lv90._780_2_notice = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv90._790_say = "Har du gennemf\248rt din opgave? Rigtig godt. S\229 giv[ENTER]mig en rapport p\229 den nuv\230rende situation. "
gameforge.main_quest_lv90._800_say = "Manticores troper er ikke s\230rlig store. Du har en[ENTER]fordel i antal.[ENTER]Men deres krigere er meget godt tr\230net og de er[ENTER]ekstremt h\229rde.[ENTER]Jeg ville anbefale, at du styrker forsvars muren[ENTER]omkring fortet. Det vil ikke p\229 nuv\230rende[ENTER]tidspunkt kunne modst\229 et angreb fra Manticore. "
gameforge.main_quest_lv90._810_say = "Ja, det er den information, vi har brug for. Jeg[ENTER]vil bruge dit r\229d og styrke forsvars muren.[ENTER]Tag venligst dette som bel\248nning. "
gameforge.main_quest_lv90._820_say = "Tal med admiral Angmur. "
gameforge.main_quest_lv90._830_sayTitle = "Manticore tropperne "
gameforge.main_quest_lv90._840_say = "Besejre 50 Manticore krigere, 40 Manticore[ENTER]soldater, 20 Manticore b\248dler, samt besejrer[ENTER]General Cor 10 gange. "
gameforge.main_quest_lv90._850_sendLetter = "Styrk forsvaret I "
gameforge.main_quest_lv90._860_say = "Admiral Angmur kigger efter dig. Det ser ud til[ENTER]at v\230re vigtigt. Tag hentil ham med det samme. "
gameforge.main_quest_lv90._870_say = "Ah, der er du. Du havde ret, vores forsvar ville[ENTER]ikke have kunne holde til et angreb. Men vi har[ENTER]ikke materialerne, som vi beh\248ver for at kunne[ENTER]styrke det. "
gameforge.main_quest_lv90._880_say = "Vi har brug for ler sten og fint sand. Kan du[ENTER]hj\230lpe os med at f\229 fat i disse byggematerialer[ENTER]for os? "
gameforge.main_quest_lv90._890_say = "Naturligvis. "
gameforge.main_quest_lv90._900_say = "Rigtig godt. Led f\248rst efter fint sand. Gnolls[ENTER]har et stort udbud af det. 50 spande burde v\230re[ENTER]nok. "
gameforge.main_quest_lv90._910_sayTitle = "Fint sand "
gameforge.main_quest_lv90._920_say = "K\230mp mod Gnolls og f\229 fat i 50 spande med fint[ENTER]sand. "
gameforge.main_quest_lv90._930_say = "Uheldigvis har du ikke nok.[ENTER]Vi har brug for mere fint sand. Bliv venligst ved[ENTER]med at samle. "
gameforge.main_quest_lv90._940_1_notice = "Du har nu samlet nok fint sand. "
gameforge.main_quest_lv90._940_2_notice = "Aflever det til Admiral Angmur. "
gameforge.main_quest_lv90._950_say = "Ok. "
gameforge.main_quest_lv90._960_say = "Jeg takker dig! Med det fine sand vil vi nu v\230re[ENTER]i stand til at styrke forsvaret.[ENTER]Mine m\230nd vil g\229 i gang med styrkelsen med det[ENTER]samme.[ENTER]Jeg vil sende bud efter dig, s\229 snart vi har brug[ENTER]for din hj\230lp igen. "
gameforge.main_quest_lv90._970_sendLetter = "Styrk forsvaret II "
gameforge.main_quest_lv90._980_say = "Admiral Angmur kigger efter dig. Find ud af, hvad[ENTER]han vil. "
gameforge.main_quest_lv90._990_say = "For at f\230rdigg\248re konstruktionen har vi brug for[ENTER]ler sten.[ENTER]Manticores hamstre disse som guld. Jeg t\230nker, at[ENTER]100 sten vil v\230re nok. Du vil selvf\248lgelig blive[ENTER]gener\248st bel\248nnet for din hj\230lp. "
gameforge.main_quest_lv91 = {}
gameforge.main_quest_lv91._010_sendLetter = "Manticore brevet "
gameforge.main_quest_lv91._020_say = "Admiral Angmur har en ny opgave til dig. "
gameforge.main_quest_lv91._030_say = "Ja, det er endnu engang tid til at lede vores[ENTER]opm\230rksomhed hen til de intrigante tjenere af[ENTER]M\248rket.[ENTER]Vi har brug for at komme i besiddelse af de breve[ENTER]de har send til Manticore og R\248d tyvene![ENTER]Bes\248g Manticore f\248rst. "
gameforge.main_quest_lv91._040_say = {}
gameforge.main_quest_lv91._050_say = "Forst\229et. "
gameforge.main_quest_lv91._060_say = "General Cor er taget ud for at aflevere brevet[ENTER]til Martyaxwar. Du er n\248dt til at stoppe[ENTER]overdragelsen! "
gameforge.main_quest_lv91._070_sayTitle = "Manticore brevet "
gameforge.main_quest_lv91._080_say = "Besejre General Cor og find brevet. "
gameforge.main_quest_lv91._090_1_notice = "Du kom for sent. Martyaxwar har allerede modtaget[ENTER]brevet. "
gameforge.main_quest_lv91._090_2_notice = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv91._100_say = "Du kom for sent. Jeg har allerede givet[ENTER]Martyaxwar brevet. Menneskernes sk\230bne er[ENTER]forsejlet! "
gameforge.main_quest_lv91._110_say = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv91._120_say = "Der er du endelig. Har du brevet? "
gameforge.main_quest_lv91._130_say = "Nej, jeg kom for sent. General Cor havde allerede[ENTER]givet brevet til Martyaxwar. "
gameforge.main_quest_lv91._140_say = {}
gameforge.main_quest_lv91._150_say = "Ja, det g\248r s\229 ikke situationen lettere...[ENTER]Mine spejdere vil lede efter Martyaxwar placering.Her, tag dette som bel\248nning i mellemtiden, Jeg[ENTER]vil informere dig, s\229 snart jeg h\248re noget nyt. "
gameforge.main_quest_lv91._160_sendLetter = "Martyaxwar gemmested "
gameforge.main_quest_lv91._170_say = "Admiral Angmur leder efter dig. Han ved, hvor[ENTER]Martyaxwar placering er. "
gameforge.main_quest_lv91._180_say = "Endelig, der er du! Vi har nu fundet Martyaxwar[ENTER]placering. Mine spejdere har ogs\229 observeret, at[ENTER]han har placeret brevet i hans pig halsk\230de, den[ENTER]han aldrig fjerner. "
gameforge.main_quest_lv91._190_say = "Jeg vil tage af sted med det samme! "
gameforge.main_quest_lv91._200_sayTitle = "Besejre Martyaxwar. "
gameforge.main_quest_lv91._210_say = "Find Martyaxwar og tag hans pig halsk\230de fra ham. "
gameforge.main_quest_lv91._220_say = "Vi kan ikke spilde tiden. Skynd dig og bring mig[ENTER]pig halsk\230den! "
gameforge.main_quest_lv91._230_1_notice = "Du har modtaget pig halsk\230den. Brevet er fundet i[ENTER]en lomme p\229 indersiden af den. "
gameforge.main_quest_lv91._230_2_notice = "Bring den til Admiral Angmur. "
gameforge.main_quest_lv91._240_say = "G\229 til admiral Angmur. "
gameforge.main_quest_lv91._250_say = "Godt arbejde. Det var ikke en let modstander. Vi[ENTER]kan kun h\229be, at dette brev fort\230ller os mere[ENTER]omkring d\230monernes skumle planer. "
gameforge.main_quest_lv91._260_say = "For pokker, jeg troede lige s\229 meget. Det er[ENTER]krypteret igen! Yon-I-Walker, vores l\230rde, m\229[ENTER]kigge p\229 det. G\229 venligst til ham. "
gameforge.main_quest_lv91._270_sendLetter = "Afkodning "
gameforge.main_quest_lv91._280_say = "G\229 til Yon-I-Walker for at f\229 brevet afkodet. "
gameforge.main_quest_lv91._290_say = "*mumlen* Woah, jeg skr\230mte mig selv![ENTER]Hvem er du? "
gameforge.main_quest_lv91._300_say = "Admiral Angmur har sendt mig. "
gameforge.main_quest_lv91._310_say = "Ah, ja! Du er her p\229 grund af brevet.[ENTER]Angmur har allerede fortalt mig om det. "
gameforge.main_quest_lv91._320_say = "Jeg har ikke v\230ret i stand til at afkode brevet[ENTER]endnu.[ENTER]Men det ser ud til at v\230re skriften fra krebsdyrs[ENTER]stammen, som opholder sig Nefrit bugten. "
gameforge.main_quest_lv91._330_say = "For at v\230re i stand til at fortolke disse tegn,[ENTER]har jeg brug for krebsdyrs satmmens Carapax[ENTER]skrift. Kan du skaffe mig ti af disse? "
gameforge.main_quest_lv91._340_say = "Selvf\248lgelig. "
gameforge.main_quest_lv91._350_sayTitle = "Carapax skrift "
gameforge.main_quest_lv91._360_say = "Drag i kamp mod krebsdys stammen og f\229 fat i ti[ENTER]Carapax skrifter. "
gameforge.main_quest_lv91._370_say = "Carapax skriftet er desv\230rre blevet beskadiget,[ENTER]s\229 jeg kan ikke bruge det. Bring mig venligt et[ENTER]andet. "
gameforge.main_quest_lv91._380_say = "Du har fundet et Carapax skrift. De har form af[ENTER]et skildpaddeskjold. "
gameforge.main_quest_lv91._390_say = "Perfekt nu kan jeg afkode brevet. Godt arbejde.[ENTER]Tag dette som et bevis p\229 min taknemlighed. "
gameforge.main_quest_lv91._400_say = "Bring mig %d stykker mere! "
gameforge.main_quest_lv91._410_1_notice = "Du har fundet et Carapax skrift. "
gameforge.main_quest_lv91._410_2_notice = "Aflever det til Yon-I-Walker. "
gameforge.main_quest_lv91._420_sendLetter = "Manticore brevet er afkodet. "
gameforge.main_quest_lv91._430_say = "Yon-I-Walker leder efter dig. G\229 til ham og find[ENTER]ud af om han allerede har afkodet brevet eller[ENTER]ikke. "
gameforge.main_quest_lv91._440_say = "*mumlen* ...ah! Der er du! Tak for din hj\230lp. Jeg[ENTER]har v\230ret i stand til at afkode en stor del af[ENTER]brevet. Men jeg g\248r ikke nogen fremskridt i den[ENTER]sidste det. Jeg er bange for, jeg har brug for at[ENTER]bede om din hj\230lp endnu en gang. Jeg har h\229rdt[ENTER]brug for Carapax pulver.[ENTER]Du kan finde det p\229 Hummer generalen eller Konge[ENTER]krabben fra krabsdyrs stammen. "
gameforge.main_quest_lv91._450_say = "Carapax pulver "
gameforge.main_quest_lv91._460_say = "Ja, krabsdyrs stammen har det i deres besiddelse.[ENTER]Selv en lille dosis af dette pulver er d\248deligt![ENTER]Tre doser skulle v\230re nok. Held og lykke. "
gameforge.main_quest_lv91._470_say = "Jeg tager afsted med det samme. "
gameforge.main_quest_lv91._480_sayTitle = "Carapax pulver "
gameforge.main_quest_lv91._490_say = "K\230mp mod Hummer generalen og Konge krabben fra[ENTER]krebsdyrs sammen og f\229 tre doser af Carapax[ENTER]pulver. "
gameforge.main_quest_lv91._500_say = "Carapax pulver er ekstremt giftigt. Jeg er n\248dt[ENTER]til at vente en dag for at bestemme dets virkning[ENTER]til at aftage.[ENTER]Kom tilbage igen i morgen, forh\229bentlig vil jeg[ENTER]v\230re i stand til at fort\230lle dig mere. "
gameforge.main_quest_lv91._510_say = "Du har Carapax pulveret! "
gameforge.main_quest_lv91._520_say = "Godt arbejde! Nu kan jeg endelig afkode brevet.[ENTER]Tag venligst dette som bel\248nning. "
gameforge.main_quest_lv91._530_say = "Bring mig %d stykker mere! "
gameforge.main_quest_lv91._540_say = "Dette Carapax pulver er forurenet. Bring mig[ENTER]venligst en ny dosis. "
gameforge.main_quest_lv91._550_1_notice = "Du har fundet en dosis Carapax pulver. "
gameforge.main_quest_lv91._550_2_notice = "Bring det til Yon-I-Walker. "
gameforge.main_quest_lv91._560_sendLetter = "Forgiftet! "
gameforge.main_quest_lv91._570_say = "Admiral Angmur har h\229rdt brug for dig. Find ud af[ENTER]hvad han har brug for. "
gameforge.main_quest_lv91._580_say = "Der er du! Priset v\230re Drage Guden.[ENTER]Yon-I-Walker er blevet forgiftet af Carapax[ENTER]pulveret. "
gameforge.main_quest_lv91._590_say = "Han ville skynde sig og blev uforsigtig. Hvad der[ENTER]g\248r det hele v\230rre er, at vores forsyning af[ENTER]medicinske urter er opbrugt.[ENTER]S\248g eget sten blomsten, dens rod kan neutralisere[ENTER]giften. Jeg har markeret placering, hvor du kan[ENTER]finde den p\229 kortet. "
gameforge.main_quest_lv91._600_say = "Selvf\248lgelig. "
gameforge.main_quest_lv91._610_say = "Jeg vidste, at jeg kunne regne med dig. Skynd dig[ENTER]venligst, vi har ikke meget tid! "
gameforge.main_quest_lv91._620_sayTitle = "Red Yon-I-Walker! "
gameforge.main_quest_lv91._630_say = "Find sten blomst r\248dderne, for at kunne helbrede[ENTER]den forgiftede Yon-I-Walker. "
gameforge.main_quest_lv91._640_1_notice = "Bring Yon-I-Walker sten blomstens rod. "
gameforge.main_quest_lv91._650_say = "*host*[ENTER]*hak*[ENTER]Ah, der er du. Jeg har det ikke s\229 godt. Har du[ENTER]fundet sten blomstens r\248dder? "
gameforge.main_quest_lv91._660_say = "Ja, jeg har dem her. "
gameforge.main_quest_lv91._670_say = "Ah, jeg har det allerede bedre. Det ser ud til[ENTER]min tid alligevel ikke er kommet.[ENTER]Jeg takker dig. Tag denne bel\248nning. Nu kan jeg[ENTER]f\230rdigg\248re mit arbejde. Admiral Angmur vil[ENTER]informere dig, s\229 snart jeg har afkodet brevet. "
gameforge.main_quest_lv91._680_say = "Yon-I-Walker vil gerne tale med dig. "
gameforge.main_quest_lv91._760_say = "(Resterende: %s %s, %s %s) "
gameforge.main_quest_lv91._770_say = {}
gameforge.main_quest_lv91._780_say = "Dette eventyr forts\230tter s\229 snart du er n\229et[ENTER]level 92. "
gameforge.main_quest_lv92 = {}
gameforge.main_quest_lv92._010_sendLetter = "R\248d tyvs brev "
gameforge.main_quest_lv92._020_say = "Det sidste brev sendt af M\248rkets tjenere er hos[ENTER]R\248d tyvs banden. Admiral Angmur har flere[ENTER]informationer til dig. "
gameforge.main_quest_lv92._030_say = "Vi komme t\230ttere og t\230ttere p\229 at finde ud af,[ENTER]hvad M\248rkets tjenere planl\230gger. Det sidste brev[ENTER]er p\229 nuv\230rende tidspunkt i h\230nderne p\229 R\248d tyvs[ENTER]banden. "
gameforge.main_quest_lv92._040_say = "R\248d tyvs banden? "
gameforge.main_quest_lv92._050_say = "Det er en gruppe kriminelle, som blev bortvist[ENTER]fra M\248rk Drage Klippe. Det underlige ved R\248d[ENTER]tyvene er, at de er mennesker, som har allieret[ENTER]sig med d\230monerne. "
gameforge.main_quest_lv92._060_say = "D\230moner, som har allieret sig med mennesker i[ENTER]stedet for at \230de dem? M\230rkv\230rdigt. "
gameforge.main_quest_lv92._070_say = "De er samlet af et f\230lles m\229l: guld- R\248d tyvenes[ENTER]lejr er ikke langt herfra. Besejre R\248dtyv b\248ddel[ENTER]og M\248rk general.[ENTER]En af dem har brevet. "
gameforge.main_quest_lv92._080_say = "Men de er blevet advaret om vores intentioner i[ENTER]mellem tiden, og de har nu revet brevet i 4[ENTER]stykker. Vi er n\248d til at finde dem alle. "
gameforge.main_quest_lv92._090_say = "Forst\229et. "
gameforge.main_quest_lv92._100_say = "Tak! "
gameforge.main_quest_lv92._110_sayTitle = "R\248d tyvs brev "
gameforge.main_quest_lv92._120_say = "Bek\230mp R\248dtyv b\248ddel og M\248rk general. Find alle[ENTER]fire dele af brevet. "
gameforge.main_quest_lv92._130_say = "Brevet er endnu ikke komplet. Find alle delene. "
gameforge.main_quest_lv92._140_1_notice = "Du har fundet en af delene af R\248d tyvs brevet. "
gameforge.main_quest_lv92._140_2_notice = "Vis den til admiral Angmur. "
gameforge.main_quest_lv92._150_say = "Tal med admiral Angmur. "
gameforge.main_quest_lv92._160_say = "Godt arbejde. Her, tag dette som et bevis p\229 min[ENTER]taknemlighed. "
gameforge.main_quest_lv92._170_sendLetter = "R\248d tyvs brev "
gameforge.main_quest_lv92._180_say = "Admiral Angmur har brug for din hj\230lp. "
gameforge.main_quest_lv92._190_say = "Godt du er her. Vi har et problem. "
gameforge.main_quest_lv92._200_say = "Hvad sker der? "
gameforge.main_quest_lv92._210_say = "Der er faktisk en femte del af R\248d tyvs brevet.[ENTER]Uden den del, er resten af brevet v\230rdil\248st. Jeg[ENTER]har allerede sendt Bae-Yong, en af mine modigste[ENTER]m\230nd, men noget m\229 v\230re sket. Han burde have[ENTER]v\230ret tilbage for lang tid siden. Kan du lede[ENTER]efter ham? "
gameforge.main_quest_lv92._220_say = "Selvf\248lgelig! Ved du, hvor kan kan v\230re nu? "
gameforge.main_quest_lv92._230_say = "En ide, ja. Det sidste han n\230vnte var, at han[ENTER]ville tage til Nefrit bugten. Men ingen kan sige[ENTER]med sikkerhed om, han kom derud eller ej. "
gameforge.main_quest_lv92._240_say = "Jeg vil tage af sted med det samme! "
gameforge.main_quest_lv92._250_sayTitle = "Den savnede soldat "
gameforge.main_quest_lv92._260_say = "Find den femte del af brevet. For at g\248re dette,[ENTER]kig efter Bae-Yong i Nefrit bugten. "
gameforge.main_quest_lv92._270_say = "Har du endnu ikke fundet Bae-Yong?[ENTER]Det er et sp\248rgsm\229l om liv eller d\248d! V\230r venlig[ENTER]at blive ved med at lede. "
gameforge.main_quest_lv92._280_say = "*host*[ENTER]Tak, fordi du fandt mig. Jeg blev h\229rdt skadet i[ENTER]kamp, og jeg frygtede, at jeg ikke havde meget[ENTER]tid tilbage...[ENTER]Her, jeg tog dette fra en R\248d tyv. Giv det til[ENTER]Admiralen.[ENTER]G\229! Jeg vil v\230re o...[ENTER](Han d\248r i dine arme.) "
gameforge.main_quest_lv92._290_1_notice = "F\248r Bae-Yong d\248de, gav han dig den manglede del[ENTER]af brevet. "
gameforge.main_quest_lv92._290_2_notice = "Vend tilbage til Admiral Angmur. "
gameforge.main_quest_lv92._300_say = "Du er tilbage! Fandt du Bae-Yong? "
gameforge.main_quest_lv92._310_say = "Ja, men... "
gameforge.main_quest_lv92._320_say = "Men?[ENTER]\197h nej. Er han d\248d? "
gameforge.main_quest_lv92._330_say = "Jeg kunne ikke g\248re mere for ham. Jeg[ENTER]kondolerer.Han var en modig mand. Han forsvarede[ENTER]den sidste del af brevet med sit liv. Her er det. "
gameforge.main_quest_lv92._340_say = "Tabet af Bae-Yong g\248r os alle meget ondt. Men jeg[ENTER]er meget stolt af ham. Han f\230rdiggjorde sin[ENTER]mission. Nu har vi alle delene af brevet. "
gameforge.main_quest_lv92._350_say = "Jeg takker dig for alt. Her, tag dette som[ENTER]bel\248nning.[ENTER]Jeg vil g\229 hen og t\230nde et lys for Bae-Yong i[ENTER]templet nu.[ENTER]Jeg vil tilkalde dig senere. "
gameforge.main_quest_lv92._360_say = "Drag til admiral Angmur. "
gameforge.main_quest_lv92._370_sendLetter = "Afkodning af R\248d tyvs brevet "
gameforge.main_quest_lv92._380_say = "Admiral Angmur har nogle vigtige nyhedder til dig[ENTER]omkring R\248d tyvs brevet.[ENTER]H\248r hvad han har at sige. "
gameforge.main_quest_lv92._390_say = "\197h, der er du. M\248rkets tjenere giver mig[ENTER]hovedpine.[ENTER]Dette brev er ogs\229 kodet. V\230r venlig at tage det[ENTER]til Yon-I-Walker. "
gameforge.main_quest_lv92._400_say = "Forst\229et. "
gameforge.main_quest_lv92._410_say = "Tag dette kodet brev til Yon-I-Walker. "
gameforge.main_quest_lv92._420_say = "Argh! Skal du altid snige dig s\229dan ind p\229 mig?![ENTER]Hvad kan jeg g\248re for dig? "
gameforge.main_quest_lv92._430_say = "Her er R\248d tyvs brevet. Ligesom de andre, er det[ENTER]kodet. "
gameforge.main_quest_lv92._440_say = "Lad mig se. Hmm, det ser ud til at v\230re tegn fra[ENTER]Tritonerne. Afkodningen burde ikke v\230re s\229 sv\230r. "
gameforge.main_quest_lv92._450_say = "Fantastisk. Hvor lang tid har du brug for? "
gameforge.main_quest_lv92._460_say = "Ikke s\229 hurtigt. Afkodningen er ikke speciel[ENTER]sv\230r, men uden de n\248dvendig ressourcer vil det[ENTER]ikke virke. "
gameforge.main_quest_lv92._470_say = "Selvf\248lgelig ikke. Det ville have v\230ret for nemt. "
gameforge.main_quest_lv92._480_say = "Jeg ser, du ikke har mistet din sans for humor,[ENTER]hehe.[ENTER]For at afkode brevet, skal jeg bruge Oin v\230gte.[ENTER]Fra Triton stammen, kun General Kappa og Triton[ENTER]hamselv m\229 b\230re disse sj\230ldne v\230gte. V\230r venlig[ENTER]at f\229 ti af dem. "
gameforge.main_quest_lv92._490_say = "Jeg vil tage afsted med det samme. "
gameforge.main_quest_lv92._500_sayTitle = "Find Oin v\230gte! "
gameforge.main_quest_lv92._510_say = "Kun Triton, kongen af Tritonerne og General Kappa[ENTER]b\230rer disse Oin v\230gte. "
gameforge.main_quest_lv92._520_say = "Jeg kan ikke afkode brevet uden disse v\230gte.[ENTER]Jeg har brug for dem hurtigt. "
gameforge.main_quest_lv92._530_1_notice = "Du har fundet en tritonisk Oin v\230gte. "
gameforge.main_quest_lv92._530_2_notice = "Hurtigt bring dem til Yon-I-Walker. "
gameforge.main_quest_lv92._540_say = "Du har gjort det godt. S\229 snart jeg har afkodet[ENTER]brevet, vil jeg lade Admiral Angmur vide det.[ENTER]Du skal slappe af lidt. Her, tag denne polet som[ENTER]et bevis p\229 min taknemlighed. "
gameforge.main_quest_lv92._550_say = "Yon-I-Walker vil gerne tale med dig. "
gameforge.main_quest_lv92._560_sendLetter = "M\248rke planer "
gameforge.main_quest_lv92._570_say = "Dette brev fra M\248rkets tjenere er blevet afkodet.[ENTER]Admiral Angmur vil tale med dig om de skumle[ENTER]planer. "
gameforge.main_quest_lv92._580_say = "Det er nu lykkedes os at afkode den hemmelige[ENTER]besked. Kan du huske det brev, der blev send til[ENTER]Gnollerne? Der tale de allerede om drager, som[ENTER]sov dybt inde i \248en, samt en metode til at v\230kke[ENTER]dem og g\248re dem vrede.[ENTER]Nu har vi fundet ud af form\229et med de M\248rke[ENTER]tjenere forf\248lger dette. "
gameforge.main_quest_lv92._590_say = "Hvis du s\229 dr\230ber en drage p\229 dette tidspunkt,[ENTER]n\229r dens sind er sort som helvedes k\230ber, spytter[ENTER]den en Nattens Perle ud. Med hj\230lp fra denne[ENTER]perle, kan de um\229lelige kr\230fter fra Sung Mahi[ENTER]blive hidkaldt til vores verden. Dette er deres[ENTER]skumle plan! "
gameforge.main_quest_lv92._600_say = "Vores n\230ste skridt er n\248dt til at v\230re[ENTER]gennemt\230nkt.[ENTER]S\229 snart jeg har nogle nyhedder til dig, kalder[ENTER]jeg p\229 dig. Tak for alt. "
gameforge.main_quest_lv92._610_say = "Eventyret fors\230tter, s\229 snart du n\229r level 93. "
gameforge.main_quest_lv93 = {}
gameforge.main_quest_lv93._010_sendLetter = "Oplagring af kraft I "
gameforge.main_quest_lv93._020_say = "Admiral Angmur vil tale med dig. "
gameforge.main_quest_lv93._030_say = "Vi er lige i h\230lene p\229 M\248rkets tjenere. "
gameforge.main_quest_lv93._040_say = "For at besejre dem, har vi brug for at styrke[ENTER]vores kr\230fter. Ved du noget om det indre lys? Det[ENTER]er koncentreret energi. Nogle mystiske v\230sner[ENTER]eller planter har det i sig. Yon-I-Walker kan[ENTER]lave en drik fra det. G\229 til ham, som det n\230ste. "
gameforge.main_quest_lv93._050_say = "Forst\229et. "
gameforge.main_quest_lv93._060_say = "\197h, det er min redningsmand![ENTER]Det indre lys, \229h ja...min drik vil g\248re dig til[ENTER]en v\230rdig modstader for M\248rkets tjenere. "
gameforge.main_quest_lv93._070_say = "Til dette har jeg brug for det indre lys af[ENTER]kykloperne og giganterne. Kun disse stammer[ENTER]ledere af hver af grupperne vil have det i sig.[ENTER]Tag kyklopernes f\248rst. "
gameforge.main_quest_lv93._080_say = "Forst\229et. "
gameforge.main_quest_lv93._090_sayTitle = "Det indre lys I "
gameforge.main_quest_lv93._100_say = "Besejr Polyphemos, kongen af kykloperne, og[ENTER]plyndrer hans indre lys. "
gameforge.main_quest_lv93._110_say = "Du er tilbage med tomme h\230nder? Jeg kan ikke[ENTER]hj\230lpe dig med dette. Bring mig det indre lys. "
gameforge.main_quest_lv93._120_1_notice = "Du har fundet det indre lys. Bring det til[ENTER]Yon-I-Walker. "
gameforge.main_quest_lv93._130_say = "Tal med Yon-I-Walker. "
gameforge.main_quest_lv93._140_say = "S\229 det er det indre lys...f\248r jeg kan arbejde med[ENTER]det, er det n\248dt til at blive renset. Det vil[ENTER]tage noget tid. Jeg vil lade dig vide, n\229r det er[ENTER]f\230rdigt. "
gameforge.main_quest_lv93._150_sendLetter = "Oplagring af kraft II "
gameforge.main_quest_lv93._160_say = "Yon-I-Walker leder efter dig. "
gameforge.main_quest_lv93._170_say = "Det inre lys fra Polyphemos er nu renset. Det[ENTER]n\230ste er det som tilh\248rer giganterne. Du vil v\230re[ENTER]n\248dt til at besejre Kong Wubba for at f\229 det. "
gameforge.main_quest_lv93._180_say = "Jeg vil tage afsted med det samme. "
gameforge.main_quest_lv93._190_sayTitle = "Det indre lys II "
gameforge.main_quest_lv93._200_say = "Besejrer giganternes konge, kong Wubba, og[ENTER]plyndrer hans indre lys. "
gameforge.main_quest_lv93._210_say = "Du kommer tilbage tomh\230ndet? Det vil ikke undre[ENTER]mig, hvis du ikke er klar til denne udfordring.[ENTER]Drag ud og pr\248v igen! "
gameforge.main_quest_lv93._220_1_notice = "Du holder det indre lys af giganterne i dine[ENTER]h\230nder. "
gameforge.main_quest_lv93._220_2_notice = "Bring det til Yon-I-Walker. "
gameforge.main_quest_lv93._230_say = "Tal med Yon-I-Walker. "
gameforge.main_quest_lv93._240_say = "Kong Wubbas indre lys indeholde enorme krafter.[ENTER]Jeg tror, det kommer fra st\248rrelsen. Jeg er nu[ENTER]n\248dt til at rense det. Det vil tage noget tid. "
gameforge.main_quest_lv93._250_sendLetter = "Oplagring af kraft III "
gameforge.main_quest_lv93._260_say = "Yon-I-Walker leder efter dig. "
gameforge.main_quest_lv93._270_say = "Du er her, fantastisk. Jeg har brug for din[ENTER]hj\230lp. For at effekterne af min drik til at[ENTER]udvikle sig fuldt ud, har jeg brug for en[ENTER]yderligere bestanddel: Millenium essensen. "
gameforge.main_quest_lv93._280_say = "Millenium essensen? Har aldrig h\248rt om den. "
gameforge.main_quest_lv93._290_say = "Det er en meget effektiv blanding lavet af mange[ENTER]forskellige urters essenser. Kender du Octavio?[ENTER]Han bor p\229 fastlandet, og er den eneste, som er i[ENTER]stand til at lave Millenium essensen. G\229 til ham.[ENTER]Jeg h\229ber, han vil hj\230lpe os. Han kan v\230re en[ENTER]smule st\230dig... "
gameforge.main_quest_lv93._300_say = "Forst\229et. "
gameforge.main_quest_lv93._310_sayTitle = "Tal med Octavio! "
gameforge.main_quest_lv93._320_say = "Ops\248g Octavio. Han bor p\229 fastlandet og er den[ENTER]eneste, som kan brygge Millenium essensen. "
gameforge.main_quest_lv93._330_say = "Hej! Hvad kan jeg g\248re for dig? En Samgyetang[ENTER]m\229ske? Det er huset specialitet med... "
gameforge.main_quest_lv93._340_say = "Octavio, jeg er her ikke for den gode mad! Jeg[ENTER]gar brug for noget lidt anderledes: Millenium[ENTER]essensen. "
gameforge.main_quest_lv93._350_say = "Uhhh, shhh, ikke s\229 h\248jt! Millenium essensen...[ENTER]Nej, det er ikke muligt: Hvordan kender du til[ENTER]den?[ENTER]Kun f\229 kan klare kr\230fterne, som den giver. Jeg[ENTER]vil ikke tage den risiko. G\229 nu, f\248r nogen andre[ENTER]h\248re dig. "
gameforge.main_quest_lv93._360_say = "Octavio, vent og lyt! Yon-I-Walker fra M\248rk Drage[ENTER]Klippe sendte mig. Vi har brug for essensen[ENTER]hurtigt.[ENTER]Uden den, har vi ikke en chance mod M\248rkets[ENTER]tjenere.[ENTER]Og s\229 vil verden, som vi kender den, v\230re[ENTER]fortabt. Kun du kan lave essensen. V\230r venlig! "
gameforge.main_quest_lv93._370_say = "Yon-I-Walker siger du? Hmm, han er en af mine[ENTER]gammel venner. Vi har haft mange godt snakke over[ENTER]en flaske vin. Jeg er n\248dt til at t\230nke over det.[ENTER]Kom tilbage i morgen tidlig, s\229 vil jeg give dig[ENTER]et svar. "
gameforge.main_quest_lv93._380_say = {}
gameforge.main_quest_lv93._390_say = "Jeg har ikke besluttet mig endnu. Kom tilbage[ENTER]igen senere. "
gameforge.main_quest_lv93._400_npcChat = "Millenium essensen "
gameforge.main_quest_lv93._410_say = "Octavio vil tale med dig. "
gameforge.main_quest_lv93._420_say = "S\229, jeg har t\230nkt over, hvad du efterspurgte hele[ENTER]natten. Jeg l\248ber en stor risiko med dette, men[ENTER]jeg er sikker p\229, at jeg g\248r det rigtige. Ja, jeg[ENTER]vil hj\230lpe dig. "
gameforge.main_quest_lv93._430_say = "Fantastisk! "
gameforge.main_quest_lv93._440_say = "Men jeg har det ikke p\229 lagret i \248jeblikket. Kan[ENTER]du f\229 fat p\229 nogle f\229 ingredienser for mig? S\229[ENTER]vil jeg vil jeg lave essensen til dig. "
gameforge.main_quest_lv93._450_say = "Selvf\248lgelig. Hvad skal du bruge? "
gameforge.main_quest_lv93._460_say = "Jeg mangler Gango-rod, Tue-svamp og Alperose. Jeg[ENTER]mangler 200 af hver ingrediens. "
gameforge.main_quest_lv93._470_say = "Jeg vil straks tage afsted. Hvor kan jeg find dem[ENTER]alle? "
gameforge.main_quest_lv93._480_say = "Du vil finde disse planter i flere forskellige[ENTER]omr\229der p\229 kontinentet.[ENTER]Mens du leder, vil jeg starte mine forberedelser[ENTER]her. "
gameforge.main_quest_lv93._490_sayTitle = "Millenium opskriften "
gameforge.main_quest_lv93._500_say = "S\248g efter Gango-rod, Tue-svamp og Alperose.[ENTER]Du skal bruge 200 af hver. "
gameforge.main_quest_lv93._510 = "Du vil finde disse planter i flere forskellige[ENTER]omr\229der p\229 kontinentet.[ENTER]Mens du leder, vil jeg starte mine forberedelser[ENTER]her. "
gameforge.main_quest_lv93._520_say = "\197h, du er tilbage, rigtig godt. Og du har alting[ENTER]med dig.[ENTER]S\229 skal jeg begynde at arbejde straks. Jeg m\229[ENTER]ikke blive forstyrret imens. Kom tilbage i morgen[ENTER]p\229 samme tid. S\229 burde essensen v\230re klar. "
gameforge.main_quest_lv93._530_say = "Har det. Vi ses i morgen. "
gameforge.main_quest_lv93._540_say = "Jeg forstod, at du har hurtigt brug for den, men[ENTER]du er n\248dt til at v\230re t\229lmodig et lille stykke[ENTER]tid endnu.[ENTER]Kom tilbage igen senere. "
gameforge.main_quest_lv93._550_say = "Octavio leder efter dig. "
gameforge.main_quest_lv93._560_say = "\197h, du er komme til mig p\229 det helt rigtig[ENTER]tidspunkt: Millenium essensen er lige blevet klar[ENTER]til brug! Du kan nu tage den til Yon-I-Walker. "
gameforge.main_quest_lv93._570_say = "Tak! "
gameforge.main_quest_lv93._580_sendLetter = "Millenium essensen "
gameforge.main_quest_lv93._590_say = "Yon-I-Walker leder efter dig. "
gameforge.main_quest_lv93._600_say = "Du har Millenium essensen![ENTER]Nu jar jeg alle ingredienserne til min drik. Jeg[ENTER]kalder p\229 dig, s\229 snart den er f\230rdig. "
gameforge.main_quest_lv93._610_say = "Forst\229et. "
gameforge.main_quest_lv93._620_say = "Eventyret fors\230tter, n\229r du n\229r level 94. "
gameforge.main_quest_lv93._630_say = "%s: %d stykker, %s: %d stykker,[ENTER]%s: %d stykker "
gameforge.main_quest_lv93._640_say = "Jeg har en g\230ste hus at k\248re. Jeg har ikke al den[ENTER]tid i verden. Bring mig alle de manglede[ENTER]ingredienser, og skynd dig venlist. "
gameforge.main_quest_lv93._650_1_notice = "Du har fundet de n\248dvendige ingredienser til[ENTER]Millenium essensen. "
gameforge.main_quest_lv93._650_2_notice = "Returner til Octavio. "
gameforge.main_quest_lv94 = {}
gameforge.main_quest_lv94._010_sendLetter = "Leviathans Perler "
gameforge.main_quest_lv94._020_say = "Yon-I-Walker leder efter dig. "
gameforge.main_quest_lv94._030_say = "Jeg gjorde det. Jeg har klaret at kombinere den[ENTER]mest effektive essens, som er kendt for os med[ENTER]den anden.[ENTER]I pr\230senterer for dig: Leviathans Perler! "
gameforge.main_quest_lv94._040_say = "Tak! "
gameforge.main_quest_lv94._050_say = "Hvis du tager disse kapsler, vil du m\229ske ikke[ENTER]f\248le nogen forandring. Men et veltr\230net \248je, s\229[ENTER]som mine eller Angmurs vil v\230re i stand til at[ENTER]fort\230lle det.[ENTER]Angmur vil tale med dig. G\229 til ham nu. "
gameforge.main_quest_lv94._060_sayTitle = "Styrk dig selv! "
gameforge.main_quest_lv94._070_say = "Slug Leviathans Perler og s\248g admiral Angmur. "
gameforge.main_quest_lv94._080_sendLetter = "Kald fra Tordenbjergene "
gameforge.main_quest_lv94._090_say = "Admiral Angmur har nyhedder til dig. "
gameforge.main_quest_lv94._1000_say = "Jeg har brug for lidt tid til at analysere[ENTER]pr\248verne. Kom tilbage igen i morgen, og s\229 vil[ENTER]jeg forh\229bentlig have nogle resultater klar. "
gameforge.main_quest_lv94._100_say = "Ah, Leviathans Perler viser deres effekt: Jeg kan[ENTER]se klart en aura af styrke omkring dig.[ENTER]Mine spejdere har en ide om, hvor hovedkvarterene[ENTER]af de m\248rke tjenere m\229ske er. Stedet er st\230rkt[ENTER]bevogtet.[ENTER]Kunne du unders\248ge det? "
gameforge.main_quest_lv94._1010_say = "Jeg vil reportere mine opdagelser til Angmur. Han[ENTER]vil tage kontakt til dig. "
gameforge.main_quest_lv94._1020_say = "Admiral Angmur har informationer omkring det[ENTER]sorte guld. Drag til ham. "
gameforge.main_quest_lv94._1030_say = "Aye, der er du. Analysen af det sorte guld er[ENTER]endnu ikke f\230rdig. Jeg h\229ber, jeg vil v\230re i[ENTER]stand til at fort\230lle dig mere snart. Her, tag[ENTER]dette som en bel\248nning for dine anstrengelser. "
gameforge.main_quest_lv94._1040_say = "Vi kan ikke spilde tiden. Hurtigt, bring mig[ENTER]pr\248verne af det sorte guld. "
gameforge.main_quest_lv94._1050_say = "Eventyret forts\230tter, s\229 snart du er n\229et level[ENTER]95. "
gameforge.main_quest_lv94._1060_say = "(Resterende: %s %s, %s %s) "
gameforge.main_quest_lv94._1070_say = {}
gameforge.main_quest_lv94._1080_say = "Manglende m\230ngde: "
gameforge.main_quest_lv94._1090_say = {}
gameforge.main_quest_lv94._110_say = "Selvf\248lgelig. "
gameforge.main_quest_lv94._120_say = "Tak. Kom, jeg vil vise dig, hvilke omr\229der du er[ENTER]n\248d til at unders\248ge. Reporter tilbage til mig,[ENTER]n\229r du er f\230rdig. "
gameforge.main_quest_lv94._130_say = {}
gameforge.main_quest_lv94._140_say = "Under Admiral Angmurs ordre, unders\248g[ENTER]Tordenbjergene. Dit f\248rste m\229l er: (%d, %d) "
gameforge.main_quest_lv94._150_sayTitle = "Tordenbjergene "
gameforge.main_quest_lv94._160_say = "Unders\248g Tordenbjergene og reporter tilbage til[ENTER]admiral Angmur. "
gameforge.main_quest_lv94._170_say = "Du har ikke unders\248gt alle omr\229der endnu, vel?[ENTER]Vi regner med disse informationer. V\230r venlig at[ENTER]f\248lge mine ordre. "
gameforge.main_quest_lv94._180_say = "Dit f\248rste m\229l er: %d, %d "
gameforge.main_quest_lv94._190_say = "Dit andet m\229l er: %d, %d "
gameforge.main_quest_lv94._200 = {}
gameforge.main_quest_lv94._210_say = "Dit tredje m\229l er: %d, %d "
gameforge.main_quest_lv94._220_say = "Du er n\229et dit f\248rste m\229l. Den n\230ste placering[ENTER]er: (%d, %d) "
gameforge.main_quest_lv94._230_say = "Du er n\229et dit andet m\229l: Den n\230ste placering er:[ENTER](%d, %d) "
gameforge.main_quest_lv94._240 = "Du er n\229et det tredje m\229l. "
gameforge.main_quest_lv94._250_say = "Du var i stand til at ide om situation i[ENTER]Tordenbjergene.[ENTER]Reporter nu tilbage til admiral Angmur. "
gameforge.main_quest_lv94._260_say = "G\229 tilbage til admiral Angmur. "
gameforge.main_quest_lv94._270_say = "Ah, du er tilbage! Rigtig godt, vi vil evaluere[ENTER]informationerne, som du har samlet og arbejde p\229[ENTER]en strategi. "
gameforge.main_quest_lv94._280_say = "Her er din bel\248nning. "
gameforge.main_quest_lv94._290_sendLetter = "Sv\230k de r\248de tyve. "
gameforge.main_quest_lv94._300_say = "Admiral Angmur leder efter dig. "
gameforge.main_quest_lv94._310_say = "Et direkte angreb ser ud til at v\230re for[ENTER]risikabelt for mig p\229 dette tidspunkt. F\248r vi[ENTER]forts\230tter offensiven, burde vi sv\230kke fjendens[ENTER]tropper. "
gameforge.main_quest_lv94._320_say = "De f\248lgende grupper lever i Tordenbjergene:[ENTER]giganterne, kykloperne og r\248d tyvene.[ENTER]Vi vil angribe r\248d tyvene f\248rst! "
gameforge.main_quest_lv94._330_say = "Hvilken svaghed har r\248d tyvene? "
gameforge.main_quest_lv94._340_say = "R\248d h\248vdingen b\230rer altid en speciel kappe, et[ENTER]symbol p\229 styrke og uovervindelighed. Fl\229 ham ud[ENTER]af hans kappe - det vil smuldre r\248d tyvs bandens[ENTER]motivation! "
gameforge.main_quest_lv94._350_say = "R\248d h\248vdingen? Det vil ikke v\230re en nem opgave... "
gameforge.main_quest_lv94._360_say = "Du har ret. Men hvis der er en, som kan matche[ENTER]ham, s\229 er det dig. Held og lykke! "
gameforge.main_quest_lv94._370_sayTitle = "R\248d h\248vding "
gameforge.main_quest_lv94._380_say = "Besejr r\248d h\248vdingen og fl\229 hans kappe fra ham. "
gameforge.main_quest_lv94._390_say = "...fejlede? Nej, jeg tror ikke p\229 det. G\229 ud og[ENTER]besejre r\248d h\248vdingen igen. Jeg er sikker p\229, du[ENTER]vil besejre ham denne gang. "
gameforge.main_quest_lv94._400_1_notice = "Du har besejret r\248d h\248vdingen. "
gameforge.main_quest_lv94._400_2_notice = "Tag hans kappe og bring den til admiral Angmur. "
gameforge.main_quest_lv94._410_say = "Admiral Angmur venter p\229 dig. "
gameforge.main_quest_lv94._420_say = "Kappen! Jeg vidste, du kunne g\248re det. Vi vil[ENTER]h\230nge den op n\230r deres lejr, s\229 de kan se den -[ENTER]det vil tage modet fra r\248d tyvs banden.[ENTER]Mit folk vil tage sig af det. P\229 den m\229de kan du[ENTER]komme dig. "
gameforge.main_quest_lv94._430_sendLetter = "Sv\230k kykloperne "
gameforge.main_quest_lv94._440_say = "Admiral Angmur vil gerne tale med dig. "
gameforge.main_quest_lv94._450_say = "Vores plan virkede: da r\248d tyvene s\229 kappen br\248d[ENTER]en stor m\230ngde af forstyrrelser ud. I sidste[ENTER]ende, endte det med at d\230monerne og menneskerne[ENTER]k\230mpede mod hinanden. Nu er banden fuldst\230ndig[ENTER]uorganiseret.[ENTER]De n\230ste for os er kykloperne. "
gameforge.main_quest_lv94._460_say = "Hvordan skal vi forts\230tte? "
gameforge.main_quest_lv94._470_say = "Kykloperne tilbeder deres leder. Hvis vi fjerner[ENTER]ledelse trup, vil kykloperne bryde ud i panik og[ENTER]sprede sig. Besejr General Outis %d gange, Arges[ENTER]%d gange og Polyphemos %d gange. "
gameforge.main_quest_lv94._480_say = "Det vil v\230re en forn\248jelse. "
gameforge.main_quest_lv94._490_say = "V\230r forsigtig. "
gameforge.main_quest_lv94._500_sayTitle = "Bek\230mp kykloperne! "
gameforge.main_quest_lv94._510_say = "Besejr general Outis %d gange, Arges %d gange og[ENTER]Polyphemos %d gange. "
gameforge.main_quest_lv94._520 = "Jeg kan n\230sten ikke tro, at du havde andre tanker[ENTER]omkring kykloperne, af alle v\230sner! G\229! Jeg ved,[ENTER]at du kan klare det! "
gameforge.main_quest_lv94._530_1_notice = "Du har besejret kyklopernes ledere. "
gameforge.main_quest_lv94._530_2_notice = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv94._540_say = "G\229 til admiral Angmur. "
gameforge.main_quest_lv94._550_say = "Nyheden om dine gerninger g\229r forud for dig![ENTER]Kykloperne er p\229 flygt.[ENTER]Dem som er tilbage, er giganterne. Jeg vil samle[ENTER]informationer om deres svaghedder, og s\229 sende[ENTER]bud efter dig. "
gameforge.main_quest_lv94._560_sendLetter = "Sv\230k giganterne "
gameforge.main_quest_lv94._570_say = "Admiral Angmur kalder p\229 dig. "
gameforge.main_quest_lv94._580_say = "Mine spejdere har opdaget giganternes svaghed. "
gameforge.main_quest_lv94._590_say = "Fort\230l mig det! "
gameforge.main_quest_lv94._600_say = "Giganterne besidder et totem, som har stor[ENTER]spirituel v\230rdi. Hvis vi tager det fra dem, vil[ENTER]vil v\230re i stand til at bryde deres vilje. "
gameforge.main_quest_lv94._610_say = "Hvor kan jeg finde denne totem? "
gameforge.main_quest_lv94._620_say = "Totemet har form som et lang stykke rav.[ENTER]For at beskytte det fra tyve, blev det delt i %d[ENTER]dele.[ENTER]Kong Wubba og hans officerer b\230re dem p\229 sig. "
gameforge.main_quest_lv94._630_say = "Forst\229et. "
gameforge.main_quest_lv94._640_sayTitle = "Gigantens totem "
gameforge.main_quest_lv94._650_say = "Overtag alle stykker af totemet. "
gameforge.main_quest_lv94._660_say = "Giganterne er meget st\230rke modstandere. Men du er[ENTER]n\248dt til at besejre dem og bringe mig dette[ENTER]totem! "
gameforge.main_quest_lv94._670_say_1_notice = "Du har samlet alle totem delene. "
gameforge.main_quest_lv94._670_say_2_notice = "G\229 tilbage til admiral Angmur. "
gameforge.main_quest_lv94._680_say = "Aye, jeg var begyndt at blive bekymret for dig![ENTER]Du gjorde det virkelig.[ENTER]Nu har vi alle giganternes totems. Din bel\248nning[ENTER]for dette vil v\230re stor. "
gameforge.main_quest_lv94._690_sendLetter = "Til Tordenbjergene "
gameforge.main_quest_lv94._700_say = "Admiral Angmur leder efter dig. "
gameforge.main_quest_lv94._710_say = "Mine spejdere har observeret kykloperne, da de[ENTER]samlede noget i Tordenbjergene og bar det v\230k. "
gameforge.main_quest_lv94._720_say = "Find ud af, hvad kykloperne er ude p\229. Det er[ENTER]helt sikkert ikke noget godt...Jeg tvivler p\229, at[ENTER]de vil opgive deres hemmelighed nemt. "
gameforge.main_quest_lv94._730_say = "Forst\229et. "
gameforge.main_quest_lv94._740_sayTitle = "Hvad planl\230gger kykloperne? "
gameforge.main_quest_lv94._750_say = "Find ud af, hvad kykloperne samler i[ENTER]Tordenbjergene. "
gameforge.main_quest_lv94._760_say = "Find ud af, hvad kykloperne er ude p\229. Det er[ENTER]helt sikkert ikke noget godt...Jeg tvivler p\229, at[ENTER]de vil opgive deres hemmelighed nemt. "
gameforge.main_quest_lv94._770_1_notice = "Du holder en skinnende sort sten, som haren lap[ENTER]papir i din h\229nd. "
gameforge.main_quest_lv94._770_2_notice = "Vis admiral Angmur dit fund. "
gameforge.main_quest_lv94._780_say = "Drag til admiral Angmur. "
gameforge.main_quest_lv94._790_say = "Har du fundet ud af, hvad kykloperne laver i[ENTER]Tordenbjergene? "
gameforge.main_quest_lv94._800_say = "Kykloperne ville ikke tale frivilligt, men til[ENTER]sidst endte jeg med at f\229 dem overbevidst om at[ENTER]give mig denne: en sort sten og denne lap papir. "
gameforge.main_quest_lv94._810_say = "Vi har lokaliseret det sorte gulds \229re i[ENTER]Tordenbjergene, og er nu igang med at mine det,[ENTER]som du anbefalede.[ENTER]For overleveringen vil vi m\248des, som planlagt i[ENTER]Tordenbjergene. "
gameforge.main_quest_lv94._820_say = "Sort guld...Det er en \229re, der kun eksistere i[ENTER]Tordenbjergene. Hvorfor har m\248rkets tjenere brug[ENTER]for det? "
gameforge.main_quest_lv94._830_say = "Vi er n\248dt til at finde ud af, hvad de planl\230gger. "
gameforge.main_quest_lv94._840_say = "Her siger det: "
gameforge.main_quest_lv94._850_sendLetter = "Sort guld "
gameforge.main_quest_lv94._860_say = "Admiral Angmur vil gerne tale med dig om det[ENTER]sorte guld. "
gameforge.main_quest_lv94._870_say = "Alkymisten kunne ikke analysere det sorte guld.[ENTER]Stykket var for lille. "
gameforge.main_quest_lv94._880_say = "Tag til alkymisten f\248rst. Han vil fort\230lle dig,[ENTER]hvor mange pr\248ver, han har brug for. "
gameforge.main_quest_lv94._890_say = "Tal med alkymisten. "
gameforge.main_quest_lv94._900_say = "V\230r hilset. Har admiral Angmur allerede[ENTER]informeret dig om din opgave? "
gameforge.main_quest_lv94._910_say = "Ja. Hvor mange pr\248ver af sort guld har du brug[ENTER]for? "
gameforge.main_quest_lv94._920_say = "Hmm, lad mig t\230nke mig om et \248jeblik. Jeg t\230nker[ENTER]%d pr\248ver skulle v\230re nok til en analyse. "
gameforge.main_quest_lv94._930_say = "Forst\229et. "
gameforge.main_quest_lv94._940_sayTitle = "Guldet i Tordenbjergene "
gameforge.main_quest_lv94._950_sayTitle = "Tag til alkymisten. "
gameforge.main_quest_lv94._960_say = "Led efter pr\248ver af sort guld i Tordenbjergene. "
gameforge.main_quest_lv94._970_1_notice = "Du har opdaget en sort gulds \229re og sikrede en[ENTER]pr\248ve fra \229ren. "
gameforge.main_quest_lv94._970_2_notice = "Bring det til alkymisten. "
gameforge.main_quest_lv94._980_say = "Ah, du har fundet sort guld. Vis mig det! Hmm,[ENTER]ingen t\229re og dette stykke er stort nok...ja, jeg[ENTER]kan bruge det til min analyse. Nu mangler jeg kun[ENTER]%d . "
gameforge.main_quest_lv94._990_say = "Jeg kan ikke bruge denne pr\248ve. Den er for lys[ENTER]til en fuld analyse. Bring mig en anden! "
gameforge.main_quest_lv95 = {}
gameforge.main_quest_lv95._010_sendLetter = "Guld feber "
gameforge.main_quest_lv95._020_say = "Admiral Angmur leder efter dig. Han har nye[ENTER]informationer om det sorte guld. "
gameforge.main_quest_lv95._030_say = "Det sorte guld udvinder energi fra v\230sner i dets[ENTER]omgiveser og frigiver det i en anden krop. De[ENTER]m\248rke tjenere har til hensigt at indgyde Sung[ENTER]Mahi med stj\229lne kr\230fter! Giganten kaptajn Klo[ENTER]hamstre store m\230ngder af sort guld i[ENTER]Tordenbjergene. F\229 fat i det! "
gameforge.main_quest_lv95._040_say = "Betragt det som gjort! "
gameforge.main_quest_lv95._050_say = {}
gameforge.main_quest_lv95._060_say = {}
gameforge.main_quest_lv95._070_sayTitle = "P\229 krogen: Kaptajn Klo "
gameforge.main_quest_lv95._080_say = "Besejre giganten Kaptajn Klo og sikre det sorte[ENTER]guld! "
gameforge.main_quest_lv95._090_say = "Vi har ingen tid at spilde. Besejre Kaptajn Klo[ENTER]og sikre det sorte guld! "
gameforge.main_quest_lv95._100_1_notice = "Der er intet spor af sort guld. I stedet bar[ENTER]Kaptajn Klo et brev. "
gameforge.main_quest_lv95._100_2_notice = {}
gameforge.main_quest_lv95._110_say = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv95._120_say = "Aye, s\229 var du i stand til at holde stand mod[ENTER]Kaptajn Klo. Hvad er det? Vis mig det! "
gameforge.main_quest_lv95._130_say = {}
gameforge.main_quest_lv95._140_say = "Forbandelser. Kaptajn Klo har allerede givet det[ENTER]sorte guld til Banshee.[ENTER]Den sidste s\230tning udg\248r et puslespil: Livets[ENTER]forbandelse vil blive tilkaldt fra tidens t\229gen[ENTER]af m\230rkets h\230r. "
gameforge.main_quest_lv95._150_say = "Vi er n\248dt til at stoppe den levering! Vi tror,[ENTER]at Banshees gemmested er vest p\229 Gautama Klippen[ENTER]- et guds forladt sted, sikkert omgivet af tyk[ENTER]t\229ge.[ENTER]Orker og lemure har hjemsted der. "
gameforge.main_quest_lv95._160_say = {}
gameforge.main_quest_lv95._170_say = "S\229 snart jeg ved, hvilken rute der skal bruges[ENTER]for at bringe det sorte guld til Banshee, vil jeg[ENTER]fort\230lle dig det. "
gameforge.main_quest_lv95._180_sendLetter = "Afv\230rge leveringen "
gameforge.main_quest_lv95._190_say = "G\229 til admiral Angmur. Han har flere[ENTER]informationer om leveringen af det sorte guld. "
gameforge.main_quest_lv95._200_say = "Mine spejdere har fundet ud af, at Kaptajn Shruk,[ENTER]orkernes kommand\248r, transporter det sorte guld[ENTER]til Gautama Klippen. Han b\230rer det i en pose, som[ENTER]er fastgjort til hans b\230lte. Tag det fra ham! "
gameforge.main_quest_lv95._210_say = {}
gameforge.main_quest_lv95._220_say = "Forst\229et. Jeg vil drage ud p\229 jagten med det[ENTER]samme. "
gameforge.main_quest_lv95._230_sayTitle = "Afv\230rge leveringen! "
gameforge.main_quest_lv95._240_say = "S\248g efter Kaptajn Shruk og sikre posen, som[ENTER]indeholder det sorte guld, f\248r det n\229r Banshee. "
gameforge.main_quest_lv95._250_say = "Kaptajn Shruk er ikke ligev\230gtig. Men du kan sl\229[ENTER]ham![ENTER]Pr\248v igen. "
gameforge.main_quest_lv95._260_1_notice = "Du har f\229et posen. "
gameforge.main_quest_lv95._260_2_notice = "G\229 tilbage til admiral Angmur. "
gameforge.main_quest_lv95._270_say = "brig dit bytte til admiral Angmur. "
gameforge.main_quest_lv95._280_say = "Er det sorte guld i denne pose? Vis mig det! Hey?!Der er kun en note her... "
gameforge.main_quest_lv95._290_say = "Leveringen af det sorte guld vil finde sted, n\229r[ENTER]det er blevet fuldst\230ndig behandlet. "
gameforge.main_quest_lv95._300_say = "Forbandet, det sorte guld er stadig i de forkerte[ENTER]h\230nder. I det mindste ved vi, at det er blevet[ENTER]behandlet, f\248r Banshee kan bruge det til hendes[ENTER]form\229l. "
gameforge.main_quest_lv95._310_say = "Det er stadig ikke forsent. Jeg vil finde ud af,[ENTER]hvem der p\229 nuv\230rende tidspunkt er i besiddelse[ENTER]af det sorte guld, og om det allerede er blevet[ENTER]behandlet. S\229 snart jeg har fundet ud af det, vil[ENTER]jeg kalde p\229 dig. Her tag dette, som bel\248nning.[ENTER]Vi ses snart! "
gameforge.main_quest_lv95._320_sendLetter = "Stop behandlingen "
gameforge.main_quest_lv95._330_say = "G\229 til admiral Angmur. Han har nyheder om det[ENTER]sorte guld. "
gameforge.main_quest_lv95._340_say = "Vi har opdaget, at de store trolde personligt[ENTER]overv\229ger behandlingen af det sorte guld og vil[ENTER]efterf\248lgende tage det til Banshee. "
gameforge.main_quest_lv95._350_say = "Lige nu holder han til p\229 Gautama Klippen.[ENTER]Undg\229 at det sorte guld n\229r dets m\229l.[ENTER]Hurtigt f\248r det er for sent! "
gameforge.main_quest_lv95._360_say = {}
gameforge.main_quest_lv95._370_sayTitle = "Den store trold "
gameforge.main_quest_lv95._380_say = "Besejr troldenes leder og stop f\230rdig\248relsen af[ENTER]det sorte guld. "
gameforge.main_quest_lv95._390_say = "Hvert minut t\230ller! Stop den store trold! "
gameforge.main_quest_lv95._400_notice = "Du har besejret den store trold. "
gameforge.main_quest_lv95._410_say = "Du kan ikke stoppe os! Banshee har allerede[ENTER]modtaget det sorte guld. Du kommer for sent, dit[ENTER]fjols! "
gameforge.main_quest_lv95._420_say = "Lykken strammes. Tag tilbage til admiral Angmur[ENTER]og giv ham din report. "
gameforge.main_quest_lv95._430_say = "Tal med admiral Angmur. "
gameforge.main_quest_lv95._440_say = "Det var hurtigt! Har du det sorte guld? "
gameforge.main_quest_lv95._450_say = "Nej, jeg kom for sent. Banshee har det allerede. "
gameforge.main_quest_lv95._460_say = "M\229 Drage guden v\230re os barmhjertig. Men vi vil[ENTER]ikke give op s\229 let! Jeg vil sende mine spejdere[ENTER]ud for at finde, hvor Banshee befinder sig.[ENTER]S\229 snart jeg ved dette, vil jeg fort\230lle dig det.[ENTER]Brug tiden til at slappe af og tag dette som[ENTER]bel\248nning. "
gameforge.main_quest_lv95._470_sendLetter = "Livets forbandelse "
gameforge.main_quest_lv95._480_say = "Admiral Angmur har nye informationer til dig. G\229[ENTER]til ham. "
gameforge.main_quest_lv95._490_say = "Nu ved vi, hvad der menes med livets forbandelse[ENTER]og m\248rkets h\230r. Der levede engang en frygtelig[ENTER]magiker p\229 M\248rk Drage Klippe. Han havde[ENTER]forh\229bninger om at dominere hele kontinentet, og[ENTER]han stoppede bogstaveligt ikke for noget for at[ENTER]opn\229 dette: ved at bruge sort magi, rejste han de[ENTER]d\248de og sendt dem i kamp, som hans h\230r. "
gameforge.main_quest_lv95._500_say = {}
gameforge.main_quest_lv95._510_say = "Ved at tilkalde de d\248de - selv tanken om det g\248r[ENTER]mig til at krumme t\230er. M\248rkets tjenere bruger[ENTER]det sorte guld til at lave en h\230r af d\248de. Vi er[ENTER]n\248dt til at stoppe dem! "
gameforge.main_quest_lv95._520_say = "Led efter lemurenes magiker i de gamle ruiner p\229[ENTER]Gautama Klippen- Han ved noget om denne[ENTER]forbandelse. Hvis du sp\248rger p\230nt, er jeg sikker[ENTER]p\229, han vil fort\230lle dig alt, vi har brug for at[ENTER]vide. "
gameforge.main_quest_lv95._530_say = "Sp\248rge p\230nt...hmmm. Forst\229et. "
gameforge.main_quest_lv95._540_sayTitle = "Livets forbandelse "
gameforge.main_quest_lv95._550_say = "Besejre lemurenes magiker og saml informationer[ENTER]om livets forbandelse og tilkaldningen af de[ENTER]d\248de. "
gameforge.main_quest_lv95._560_say = "Vi har ingen tid at spilde. Besejr lemurenes[ENTER]magiker og klem informationerne om livets[ENTER]forbandelse ud af ham. "
gameforge.main_quest_lv95._570_1_notice = "Du har besejret lemurenes magiker og fundet en[ENTER]stentavle med en inskription. "
gameforge.main_quest_lv95._570_2_notice = "Vis den til admiral Angmur. "
gameforge.main_quest_lv95._580_say = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv95._590_say = "Aye, bar lemurenes magiker denne stentavle? Lad[ENTER]mig se p\229 den. "
gameforge.main_quest_lv95._600_sayReward = "Tre ting er n\248dvendige for at kunne v\230kke de d\248de:1. En menneske krop[ENTER]2. ...[ENTER]Lemurenes tavle er \248delagt her. Resten af[ENTER]inskriptionen mangler. "
gameforge.main_quest_lv95._610_say = "Jeg er bange for, at du er n\248d til at drage ud[ENTER]igen. Vi er n\248dt til at have resten af[ENTER]inskriptionen.[ENTER]Der m\229 v\230re to dele mere af Lemur tavlen. "
gameforge.main_quest_lv95._620_say = "Her er din bel\248nning for alt, hvad du har gjort[ENTER]indtil nu.[ENTER]V\230r venlig at drage af sted for at jage resten af[ENTER]lemurenes tavle! "
gameforge.main_quest_lv95._630_sendLetter = "Inskriptionen "
gameforge.main_quest_lv95._640_sayTitle = "Find lemur tavlen! "
gameforge.main_quest_lv95._650_say = "Besejr lemurenes magiker og fin resten af[ENTER]stentavlens dele. "
gameforge.main_quest_lv95._660_say = "V\230r venlig, vi er n\248dt til at vide, hvad[ENTER]inskriptionen siger. Giv ikke op! "
gameforge.main_quest_lv95._670_say = "Bring de to manglede \248delagte dele af lemurenes[ENTER]tavle til admiral Angmur. "
gameforge.main_quest_lv95._680_say = "Aye, du er tilbage! Lad os s\230tte stykkerne af[ENTER]lemurenes tavle sammen og l\230se inskriptionen. "
gameforge.main_quest_lv95._690_sayReward = "Tre ting er n\248dvendige for at v\230kke de d\248de:[ENTER]1. En menneske krop[ENTER]2. Sort guld[ENTER]3. D\230mons tr\230s bark[ENTER]Kun en magiker med fremragende f\230rdigheder kan[ENTER]hidkalde livets forbandelse og opretholde den. Og[ENTER]n\229r de d\248r, falder hele den ikke d\248de h\230r med[ENTER]dem. "
gameforge.main_quest_lv95._700_say = "S\229 det er grunden til, at vores kirkeg\229rde er[ENTER]blevet besudlet og ligene stj\229let fra deres[ENTER]grave. De skal bringes til live og marchere imod[ENTER]os, som h\230r af ikke d\248de. Hvilke kvalmende tanke. "
gameforge.main_quest_lv95._710_say = "Vi er n\248dt til at stoppe skandal\248se gerning! "
gameforge.main_quest_lv95._720_say = "Aye, men tiden arbejder imod os. Kun Banshee er[ENTER]st\230rk nok til at hidkalde en forbandelse af denne[ENTER]st\248rrelse - men vi ved ikke, hvor hun gemmer sig.[ENTER]Jeg vil sende flere m\230nd ud og lede efter[ENTER]placeringen af den m\248rke h\248je pr\230stinde. S\229 snart[ENTER]jeg h\248re noget, vil jeg lade dig vide det. "
gameforge.main_quest_lv95._730_say = {}
gameforge.main_quest_lv95._740_say = "Eventyret forts\230tter s\229 snart, du er n\229et level[ENTER]96. "
gameforge.main_quest_lv95._750_say = "Reporter tilbage til admiral Angmur. "
