gameforge.main_quest_lv96._010_sendLetter = "Forhindre forbandelsen "
gameforge.main_quest_lv96._020_say = "Admiral Angmur vil gerne tale med dig. "
gameforge.main_quest_lv96._030_say = "Godt, at du er her. Vi har fundet en m\229de at[ENTER]sabotere tjenerenes og Banshee planer. "
gameforge.main_quest_lv96._040_say = {}
gameforge.main_quest_lv96._050_say = {}
gameforge.main_quest_lv96._060_say = "For at de d\248des sj\230le kan opgive deres kroppe, er[ENTER]et medium n\248dvendigt. Dette medium er den hellige[ENTER]jord, som giganterne opbevarer i s\230kke. Hvis du[ENTER]er i stand til at stj\230le 100 s\230kke, vil vi v\230re i[ENTER]stand til at forhindre livets forbandelse. "
gameforge.main_quest_lv96._070_say = "Jeg vil tage af sted med det samme! "
