gameforge.main_quest_lv96._090_say = "Besejr giganterne og stj\230l 100 s\230kke af hellig[ENTER]jord. "
gameforge.main_quest_lv96._100_say = "Tiden arbejder imod os. Hurtigt skynd dig og[ENTER]stj\230l s\230kkene fyldt med hellig jord! "
gameforge.main_quest_lv96._110_1_notice = "Du har stj\229let alle s\230kkene med hellig jord. "
gameforge.main_quest_lv96._110_2_notice = "Bring dem til Admiral Angmur. "
gameforge.main_quest_lv96._120_say = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv96._130_say = "Som altid, kan vi regne med dig! V\230r venlig at[ENTER]tage dette som bel\248nning. "
gameforge.main_quest_lv96._140_sendLetter = "Forhindre forbandelsen "
gameforge.main_quest_lv96._150_say = "Admiral Angmur har endnu en opgave til dig. "
gameforge.main_quest_lv96._160_say = "Troldene vogter ogs\229 over et medium for at[ENTER]tilkalde de d\248de. Men vi ved ikke, hvordan det[ENTER]ser ud. Tag til troldene og bring alt tilbage som[ENTER]ser mist\230nkeligt ud. "
gameforge.main_quest_lv96._170_say = {}
gameforge.main_quest_lv96._180_say = {}
gameforge.main_quest_lv96._190_say = "Forst\229et. "
gameforge.main_quest_lv96._200_sayTitle = "Troldenes medium "
gameforge.main_quest_lv96._210_say = "Besejr troldene og find ud af, hvilket form deres[ENTER]medium har. "
gameforge.main_quest_lv96._220_say = "Jeg ved, at du ikke har nogen ledetr\229de. Men[ENTER]noget er at finde der! "
gameforge.main_quest_lv96._230_1_notice = "Du har fundet en m\248nt taske og en gylden medalje. "
gameforge.main_quest_lv96._230_2_notice = "Tage disse genstande til Admiral Angmur. "
gameforge.main_quest_lv96._240_say = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv96._250_say = "Godt klaret! Jeg vil bede Yon-I-Walker om at[ENTER]analysere disse genstande. "
gameforge.main_quest_lv96._260_say = "Find Yon-I-Walker og f\229 ham til at fort\230lle dig[ENTER]resultaterne af hans analyse. "
gameforge.main_quest_lv96._270_say = "Ah, der du er! Jeg har allerede v\230ret i standtil[ENTER]at kigge p\229 de genstande, du fandt hos troldene. "
gameforge.main_quest_lv96._280_say = {}
gameforge.main_quest_lv96._290_say = "En gylden medalje i tasken frigiver en st\230rk m\248rk[ENTER]kraft. De er mediet. V\230r venlig at reportere[ENTER]dette til admiral Angmur. "
gameforge.main_quest_lv96._300_sendLetter = "Forhindre forbandelsen "
gameforge.main_quest_lv96._310_say = "G\229 til admiral Angmur. "
gameforge.main_quest_lv96._320_say = "Her, tag guld jagerens b\229nd. Brug det til at[ENTER]lokalisere troldenes m\248nt tasker. "
gameforge.main_quest_lv96._330_say = "Vi har brug for 100 m\248nter. Men jeg er bange for[ENTER]ikke alle m\248nter, du vil finde, vil v\230re til at[ENTER]bruge, som medium. Du har en hel del arbejde[ENTER]foran dig. "
gameforge.main_quest_lv96._340_say = "Intet problem. "
gameforge.main_quest_lv96._350_sayTitle = "Jagt guld "
gameforge.main_quest_lv96._360_say = "G\229 op imod troldene i kam og saml m\248nt tasker.[ENTER]Ikke alle af m\248nterne er medier - f\229 dem tjekket[ENTER]hos Yon-I- Walker. "
gameforge.main_quest_lv96._370_say = "Jeps, jeg kan klart m\230rke en sort magi her. "
gameforge.main_quest_lv96._380_say = "Fantastisk, vi har nu alle de guld m\248nter, som[ENTER]kan blive brugt, som medium. Det vil sikkert ikke[ENTER]gl\230de Banshee![ENTER]Her, tag dette som bel\248nning. Angmur vil udstede[ENTER]din n\230ste opgave. "
gameforge.main_quest_lv96._390_say = "Der mangler stadig noget guld. Saml %d flere. "
gameforge.main_quest_lv96._400_sendLetter = "Forhindre forbandelsen "
gameforge.main_quest_lv96._410_say = "Admiral Angmur leder efter dig. "
gameforge.main_quest_lv96._420_say = "Vi er n\248dt til at sikre, at m\248rkets tjenere ikke[ENTER]er i stand til at f\229 fat i d\230mon tr\230s bark. "
gameforge.main_quest_lv96._430_say = "D\230mon tr\230er er en af de mest mystiske arter i[ENTER]vores verden og tjener ingen, ikke engang Sung[ENTER]Mahi.[ENTER]Der er tre typer af dem p\229 Gautama Klippen:[ENTER]Aku-Boku, Arboretum og Sycomore. Riv barken af[ENTER]dem! "
gameforge.main_quest_lv96._440_say = {}
gameforge.main_quest_lv96._450_say = "Forst\229et. "
gameforge.main_quest_lv96._460_sayTitle = "Besk\230ring af d\230mon tr\230erne "
gameforge.main_quest_lv96._470_say = "Riv barken af Aku-Boku, Arboretum og Sycomore. "
gameforge.main_quest_lv96._480_counterName = "(Resterende: %s %s, %s %s) "
gameforge.main_quest_lv96._490_say = {}
gameforge.main_quest_lv96._500_say = "Tiden er knap. Lav splinter ud af tr\230 d\230monerne[ENTER]og sikre deres bark, inden tjenerne g\248r det! "
gameforge.main_quest_lv96._510_1_notice = "Du har besejret alle tr\230 d\230monerne, men nogen kom[ENTER]f\248r dig: barken er allerede revet af stammerne. "
gameforge.main_quest_lv96._510_2_notice = "Reporter disse nyheder til admiral Angmur. "
gameforge.main_quest_lv96._520_say = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv96._530_say = "Godt at se du kom tilbage uskadt! Havde du[ENTER]succes?![ENTER]Barken var allerede revet af tr\230 d\230monerne og der[ENTER]var friske spor af kamp? M\248rkets tjenere m\229 v\230re[ENTER]n\229et dertil f\248r os. "
gameforge.main_quest_lv96._540_say = {}
gameforge.main_quest_lv96._550_say = "Hvis de har barken, s\229 vil de ogs\229 finde en m\229de[ENTER]at hidkalde livets forbandelse. Det ser ud til,[ENTER]at det er uundg\229eligt - vi vil drage i krig.[ENTER]Banshee vil ikke v\230re i stand til at gemme sig[ENTER]meget l\230ngere. Mine m\230nd finder allerede spor fra[ENTER]hende. Jeg vil kalde p\229 dig, n\229r vi har fundet[ENTER]hende. "
gameforge.main_quest_lv96._560_sayTitle = "Eventyret forts\230tter, s\229 snart du er n\229et level[ENTER]97. "
gameforge.main_quest_lv96._570_counterName = "(Resterende: %s %s, %s %s) "
gameforge.main_quest_lv96._580_sayReward = "%s: %d stykker "
gameforge.main_quest_lv96._590_say = "Guld m\248nterne tjener som et medium. Godt, s\229 vil[ENTER]jeg s\248ge r\229d hos Yon-I-Walker om, hvad vores[ENTER]n\230ste tr\230k skal v\230re. Jeg vil kontakte dig snart. "
gameforge.main_quest_lv96._600_say = {}
gameforge.main_quest_lv96._610_say = {}
gameforge.main_quest_lv96._620_1_notice = "Du har modtaget en M\248nt taske. "
gameforge.main_quest_lv96._620_2_notice = "Bring den til Yon-I-Walker. "
gameforge.main_quest_lv96._630_say = "Det er bare en normal m\248nt, ikke et medium. Bliv[ENTER]ved med at lede! "
gameforge.main_quest_lv97 = {}
gameforge.main_quest_lv97._010_sendLetter = "Stop Banshee "
gameforge.main_quest_lv97._020_say = "Banshees gemmested er blevet fundet! G\229 til[ENTER]admiral Angmur for at finde ud af mere. "
gameforge.main_quest_lv97._030_say = "Mine m\230nd har endelig fundet Banshees base p\229[ENTER]Gautama Klippen. Hun er gennemhullet dybt i[ENTER]skovenes m\248rke i dette omr\229de, og her arbejder[ENTER]hun p\229 sine sorte magi.[ENTER]Ydremere har hun v\230kket en af hendes tidligere[ENTER]Drage kult tempels tjener. Sammen med hende agter[ENTER]hun at tilkalde Livets forbandelse. "
gameforge.main_quest_lv97._040_say = "Uden hendes hj\230lp vil Banshee ikke v\230re i stand[ENTER]til at vedligeholde forbandelsen. Besejre tempel[ENTER]tjeneren Mu-Shu, og berolig vores kammeraters[ENTER]sj\230le f\248r deres kroppe rejser sig mod os. "
gameforge.main_quest_lv97._050_say = "Det er n\230sten umuligt at komme t\230t p\229 tempel[ENTER]tjeneren uopdaget for at angribe hende. Brug det[ENTER]\248jeblik, hvor hun er i s\229 dybt i hendes m\248rke[ENTER]magi, at hun falder i trance! "
gameforge.main_quest_lv97._060_say = "Forst\229et. "
gameforge.main_quest_lv97._070_say = "V\230r forsigtig! I livet var hun den prim\230re[ENTER]bodyguard for den h\248je pr\230stinde og var[ENTER]veluddannede ikke kun p\229 magi, men ogs\229 i sv\230rd[ENTER]kamp. "
gameforge.main_quest_lv97._080_sayTitle = "Tempel tjeneren "
gameforge.main_quest_lv97._090_say = "Besejre Mu-Shu, Banshees tempel tjener p\229 Gautama[ENTER]klippen. "
gameforge.main_quest_lv97._100_notice = "Dr\230ber slag ramte, tempel tjeneren synker til[ENTER]jorden. "
gameforge.main_quest_lv97._110_say = "I fjolser! Du tog villigt maddingen Banshee havde[ENTER]fastsat for dig. Mens du spildte din tid p\229 mig,[ENTER]er fruen og Yah-Ki, den sande tempel tjener,[ENTER]allerede begyndt p\229 forbandelsen. Jeg beder til,[ENTER]at det lykkedes! "
gameforge.main_quest_lv97._120_say = "En dobbeltg\230nger har ledt dig p\229 vildspor! Efter[ENTER]du s\248ger hende, finder du en ligende halsk\230de p\229[ENTER]en Martyaxwar. I inderlommen er der et dokument. "
gameforge.main_quest_lv97._130_say = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv97._140_say = "Du er tilbage! Fik du besejret tempel tjeneren? "
gameforge.main_quest_lv97._150_say = "Nej, vi er blevet bedraget af en dobbeltg\230nger.[ENTER]Den rigtige tempel tjener var i stand til at[ENTER]forberede tilkaldelsen af de d\248de i fred. Her,[ENTER]jeg fandt dette dokument. "
gameforge.main_quest_lv97._160_say = "Forbandet! Hvordan kunne vil falde for hendes[ENTER]lille spil?![ENTER]V\230r venlig, at vise mig dokumentet. "
gameforge.main_quest_lv97._170_say = {}
gameforge.main_quest_lv97._180_say = {}
gameforge.main_quest_lv97._190_say = "Hmm, krypteret. Men m\229ske kan denne meddelelse[ENTER]afsl\248re for os, hvor hendes base faktisk er[ENTER]skjult. Jeg har set tegn, som disse f\248r... Jeg[ENTER]tror, at Yak-Hwan, palads vagten viste mig noget[ENTER]ligende for nyligt. Tag til ham. Han skal tage et[ENTER]kig p\229 det. "
gameforge.main_quest_lv97._200_sendLetter = "Krypteret dokument "
gameforge.main_quest_lv97._210_say = "Tag til Yak-Hwan og vis ham det krypteret[ENTER]dokument. "
gameforge.main_quest_lv97._220_say = "V\230r hilset! Mit navn er Yak-Hwan. Det er en \230re[ENTER]at m\248de dig. Dine gerninger er allerede[ENTER]legendariske![ENTER]Hvad kan jeg g\248re for dig? Ah, en krypteret[ENTER]besked.[ENTER]Lad mig se p\229 den. "
gameforge.main_quest_lv97._230_say = "Ja, jeg burde v\230re i stand til at afkode disse[ENTER]tegn uden problem. Men for at v\230re i stand til at[ENTER]g\248re det, har jeg brug for jord forsil.[ENTER]Alkymisten har en klump af det liggende. V\230r[ENTER]venlig at g\229 til ham og sp\248rg efter det. "
gameforge.main_quest_lv97._240_say = {}
gameforge.main_quest_lv97._250_say = {}
gameforge.main_quest_lv97._260_say = "Selvf\248lgelig. "
gameforge.main_quest_lv97._270_sayTitle = "Jord forsil "
gameforge.main_quest_lv97._280_say = "Tag til alkymisten og sp\248rg ham om jord forsilet. "
gameforge.main_quest_lv97._290_say = "Har du glemt noget? Du er n\248dt til at bring mig[ENTER]jord forsilet. "
gameforge.main_quest_lv97._300_notice = "Alkymisten har givet dig jord forsilet. Tag nu[ENTER]tilbage til Yak-Hwan. "
gameforge.main_quest_lv97._310_say = "Ah, jord forsilet.. Rigtig godt, jeg skal nok f\229[ENTER]det til at virke. Jeg vil reportere, hvad jeg[ENTER]finder ud af til Admiralen. "
gameforge.main_quest_lv97._320_sendLetter = "Gennem bagd\248ren "
gameforge.main_quest_lv97._330_say = "Admiral Angmur leder efter dig. "
gameforge.main_quest_lv97._340_say = "Nu ved vi, at tempel tjeneren Yah-Ki er ved at[ENTER]rejse sig. Men basen ligner en f\230stning -[ENTER]bev\230bnet tropper patruljerer d\248gnet rundet. Et[ENTER]frontalt angreb vil v\230re rent selvmord. "
gameforge.main_quest_lv97._350_say = "Af den grund, vil vi angribe i et baghold.[ENTER]Mine m\230nd leder efter et egnet sted.[ENTER]Distraher vagterne for at give os mere tid. "
gameforge.main_quest_lv97._360_say = {}
gameforge.main_quest_lv97._370_say = "Den st\248rste fare kommer fra en flok vagter, som[ENTER]kalder sig selv Den sorte d\248ds brigade.[ENTER]Denne brigade indeholder Moghu, Carnifex og[ENTER]general Albus. Deres leder er Skeletos. Eliminer[ENTER]dem, f\248r de opdager min spejder trop. "
gameforge.main_quest_lv97._380_say = "Forst\229et. "
gameforge.main_quest_lv97._390_sayTitle = "Den sorte d\248ds brigade "
gameforge.main_quest_lv97._400_say = "Eliminer Den sorte d\248ds brigade, best\229ende af[ENTER]Moghu, Carnifex, general Albus og Skeletos. "
gameforge.main_quest_lv97._410_say = "Besejr medlemmerne af Den sorte d\248ds brigade, f\248r[ENTER]de opdager spejder troppen. "
gameforge.main_quest_lv97._420_say = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv97._430_say = "Vores plan er klar! Mens du distraherede Den[ENTER]sorte d\248ds brigade, har mine m\230nd fundet et[ENTER]passende sted til et baghold. S\229 snart vores[ENTER]angrebs strategi er klar, kalder jeg p\229 dig. "
gameforge.main_quest_lv97._440_sendLetter = "Tempel tjeneren "
gameforge.main_quest_lv97._450_say = "Admiral Angmur har brug for din hj\230lp! "
gameforge.main_quest_lv97._460_say = "Godt du er her. Skeletos, lederen af Den sorte[ENTER]d\248ds brigade, har overlevet og angreb mine m\230nd,[ENTER]lige da de planlagde at angribe basen. Ingen[ENTER]kunne komme forbi ham. "
gameforge.main_quest_lv97._470_say = {}
gameforge.main_quest_lv97._480_say = "Du har besejret ham en gang, v\230r venlig at hj\230lp[ENTER]mit folk p\229 Gautama Klippen! G\229 op i mod[ENTER]Skeletos.[ENTER]Storm efterf\248lgende basen og dr\230b tempel tjeneren[ENTER]Yah-Ki. "
gameforge.main_quest_lv97._490_say = "Forst\229et. "
gameforge.main_quest_lv97._500_say = {}
gameforge.main_quest_lv97._510_sayTitle = "Besejr Yah-Ki "
gameforge.main_quest_lv97._520_say = "Besejr tempel tjeneren Yah-Ki og stop hende i at[ENTER]tilkalde h\230ren af d\248de. "
gameforge.main_quest_lv97._530_say = "Den afg\248rende dag er kommet. Hvis vi falder,[ENTER]falder verden med os. Men hvis vi sejrer. vil[ENTER]vores gerninger stdig blive sunget om hundrede \229r[ENTER]fra nu. Stop m\248rkets tjenere. Besejr tempel[ENTER]tjeneren Yah-Ki! "
gameforge.main_quest_lv97._540_say = "Hvorfor er du her? Kampen er endnu ikke vundet![ENTER]Besejr tempel tjeneren Yah-Ki. Alt vores h\229b[ENTER]hviler p\229 dig. "
gameforge.main_quest_lv97._550_1_notice = "Du har bregt din modstander i kn\230 og sejren er[ENTER]din! "
gameforge.main_quest_lv97._550_2_notice = "Der er ingen tid til at slappe af - tempel[ENTER]tjeneren Yah- Ki venter p\229 dig. "
gameforge.main_quest_lv97._560_notice = "Du har vundet! Med et bloddryppende skrig synker[ENTER]Yah- Ki til jorden. "
gameforge.main_quest_lv97._570_say = "Aaargh! Det kan ikke passe! Besejret af en[ENTER]d\248delig...[ENTER]oh, Banshee, tilgiv mig! Jeg har fejlet. Jeg[ENTER]kunne ikke fuldf\248re min opga... "
gameforge.main_quest_lv97._580_say = "Du leder blandt hendes livl\248se krop og finder et[ENTER]forseglet brev. Vend tilbage til admiral Angmur[ENTER]med det. "
gameforge.main_quest_lv97._590_say = "Aye, velsignet er Drage guden! Du er tilbage[ENTER]uskadt![ENTER]Besejrede du tempel tjeneren? "
gameforge.main_quest_lv97._600_say = "Ja, jeg har sendt hende tilbage til det Helvede,[ENTER]hun kravlede ud af. Da hun d\248de, tiggede hun[ENTER]Banshee om tilgivelse for hendes fiasko. Hun bar[ENTER]p\229 dette. "
gameforge.main_quest_lv97._610_say = "Et forseglet brev. Vis mig det! "
gameforge.main_quest_lv97._620_sayReward = "Min herskerinde.[ENTER]De faldt for vores f\230lde, og din plan virker.[ENTER]Tilkaldelsen af din d\248de h\230r skrider fremad, og[ENTER]inden vil v\230re i stand til at stoppe os nu. N\229r[ENTER]f\248rst de sj\230lel\230se kroppe begynder at marchere,[ENTER]vil vi angribe Kap drageild og begrave dens[ENTER]befolkning under os. Vi vil s\229 drage over til[ENTER]fastlandet og m\248des med dig i Ildland. Verden vil[ENTER]br\230nde under vores fodsport![ENTER]Jeg bukker mig dybt for dig.[ENTER]Din evige tjener "
gameforge.main_quest_lv97._630_say = "En besked til Banshee! Ja, den forbannede heks[ENTER]kommer til at vente forg\230ves p\229 sin h\230r af m\248rke[ENTER]i Ildland.[ENTER]Jeg takker dig. Uden din hj\230lp, ville Kap[ENTER]drageild og dens befolkning v\230re j\230vnet med[ENTER]jorden af de d\248des h\230r. Du har ikke kun reddet[ENTER]os, du har ogs\229 genoprettet fred i vores[ENTER]forf\230dres sj\230le. Jeg overr\230kker dig denne[ENTER]bel\248nning til dig for alt, hvad du har gjort. "
gameforge.main_quest_lv97._640_sayTitle = "Eventyret fors\230tter s\229 snart du er kommet i level[ENTER]98. "
gameforge.main_quest_lv97._650_say = "Vi har brug for tid til at lokalisere basen.[ENTER]V\230r venlig, vi kan ikke miste mere tid! "
gameforge.main_quest_lv97._660_say = "Yak-Hwan har brug for jod forsil? Det er meget[ENTER]heldigt, at jeg ikke har brugt det hele endnu.[ENTER]Her, det var s\229 lidt. Bring det nu til ham og giv[ENTER]ham mine varmeste hilsner. "
gameforge.main_quest_lv97._670_counterName = "(Resterende: %s %s, %s %s) "
gameforge.main_quest_lv97._680_sayReward = {}
gameforge.main_quest_lv97._690_1_notice = "Du har elimineret Den sorte d\248ds brigade. "
gameforge.main_quest_lv97._690_2_notice = "Reporter tilbage til admiral Angmur. "
gameforge.main_quest_lv97._700_sayTitle = "Besejr Skeletos, lederen af Den sorte d\248ds[ENTER]brigade! "
gameforge.main_quest_lv97._710_say = "Tempel tjeneren kan f\248rst blive besejret, n\229r du[ENTER]har besejret Skeletos. "
gameforge.main_quest_lv98 = {}
gameforge.main_quest_lv98._010_sendLetter = "Genopbygningen af fortet "
gameforge.main_quest_lv98._020_say = "Admiral Angmur sp\248rger efter dig hj\230lp. G\229 til[ENTER]ham. "
gameforge.main_quest_lv98._030_say = "Tak fordi du kom. Kampen passerede os ikke uden[ENTER]at efterlade spor. Fortet blev ogs\229 angrebet og[ENTER]den beskyttende mur blev revet ned mange steder.[ENTER]Denne fred vil ikke vare l\230nge. Vi skulle bruge[ENTER]roen til vores fordel og genopbygge. "
gameforge.main_quest_lv98._040_say = "For at styrke den beskyttende mur, har vi brug[ENTER]Skaldyds pansringen fra krebsdyrs stammen. "
gameforge.main_quest_lv98._050_say = "Forst\229et. Hvor mange af denne rustning har du[ENTER]brug for? "
gameforge.main_quest_lv98._060_say = "100 af dem burde v\230re nok. Du kan stadig angribe[ENTER]krebsdyrs stammen i Nephite bugten. "
gameforge.main_quest_lv98._070_say = "Ja, det er ikke helt nok Skaldyds pansring.[ENTER]V\230r venlig at samle nogle flere. "
gameforge.main_quest_lv98._080_1_notice = "Du har samlet alle Skaldyds pansringer, du har[ENTER]brug for. "
gameforge.main_quest_lv98._080_2_notice = "Bring dem til admiral Angmur. "
gameforge.main_quest_lv98._090_say = "Rigtig godt. Skaldyds pansringen vil hj\230lpe os[ENTER]med at genopbygge den beskyttende mur. Tag[ENTER]venligst dette som bel\248nning. Jeg vil sp\248rge mine[ENTER]ingeni\248rer om, de har brug for andre materialer,[ENTER]og s\229 lade dig vide det. "
gameforge.main_quest_lv98._130_sendLetter = "Genopbygningen af fortet "
gameforge.main_quest_lv98._140_say = "Admiral Angmur har igen brug for din hj\230lp. G\229[ENTER]til ham. "
gameforge.main_quest_lv98._150_say = "For yderligere at forst\230rke, har vi brug for[ENTER]triton spyd.[ENTER]Som navnet antyder, vil du finde dem bland[ENTER]Tritonerne.[ENTER]Mig mig venligst 100. "
gameforge.main_quest_lv98._160_say = "Forst\229et. "
gameforge.main_quest_lv98._170_say = "Der er du! Ja, det er ikke nok triton spyd. V\230r[ENTER]venlig at forts\230tte. "
gameforge.main_quest_lv98._180_1_notice = "Du har samlet alle triton spydene. "
gameforge.main_quest_lv98._180_2_notice = "Bring dem til Admiral Angmur. "
gameforge.main_quest_lv98._190_say = "Perfekt! Nu kan vi bygge et mere defensiv[ENTER]bef\230stning.[ENTER]Jeg takker dig for din hj\230lp. Forresten leder[ENTER]Yak-Hwan efter dig. Find ud af, hvad han vil. "
gameforge.main_quest_lv98._200_sendLetter = "N\248dsituationen "
gameforge.main_quest_lv98._210_say = "G\229 til Yak-Hwan. Han har en vigtig opgave til dig. "
gameforge.main_quest_lv98._220_say = "Ah, det er s\229 godt, du er her! Vi er afh\230ngige af[ENTER]din hj\230lp igen. "
gameforge.main_quest_lv98._230_say = {}
gameforge.main_quest_lv98._240_say = {}
gameforge.main_quest_lv98._250_say = {}
gameforge.main_quest_lv98._260_say = "De h\229rde tider af krig er ikke forbig\229et[ENTER]befolkningen i fortet uden spor. De lider af[ENTER]hungern\248d, og deres elendighed bliver st\248rre for[ENTER]hver dag. Med mindre vi g\248r noget snart, ser det[ENTER]ikke godt ud for dem. "
gameforge.main_quest_lv98._270_say = {}
gameforge.main_quest_lv98._280_say = "Bander af trolde ligger p\229 lur efter vores[ENTER]forsynings transporter og angriber dem. Vi er[ENTER]n\248dt til at stoppe denne plyndring. Kaptajn Shruk[ENTER]og hans generaler st\229r bag det. Dr\230b troldenes[ENTER]kaptajn og 50 general Ogg! "
gameforge.main_quest_lv98._290_say = {}
gameforge.main_quest_lv98._300_say = "Du er tilbage allerede? Der er stadig nogle[ENTER]trolde tilbage. V\230r venlig at tage dig af dem[ENTER]alle! "
gameforge.main_quest_lv98._310_1_notice = "Du har besejret alle troldene. "
gameforge.main_quest_lv98._310_2_notice = "Vend nu tilbage til Yak-Hwan. "
gameforge.main_quest_lv98._320_say = "Endelig, kommer vores mad forsynings transporter[ENTER]til fortet og vores folk kan blive forsynter med[ENTER]mad og medicin! N\248dsituationen er forbi. Du er[ENTER]virkelig en helt. "
gameforge.main_quest_lv98._330_sendLetter = "Anerkendelse "
gameforge.main_quest_lv98._340_say = "Yak-Hwan vil tale med dig. "
gameforge.main_quest_lv98._350_say = "Takket v\230re din hj\230lpe er faren p\229 M\248rk Drage[ENTER]klippe forvist for en tid. For dette vil folket[ENTER]gerne personligt sig tak til dig. "
gameforge.main_quest_lv98._360_say = "G\229 en tur omkring i fortet og tal med folk. "
gameforge.main_quest_lv98._370_say = {}
gameforge.main_quest_lv98._380_say = "Tak. Jeg vil bes\248ge alle beboerne. "
gameforge.main_quest_lv98._390_say = "Ikke alle beboerne har haft en chance for at[ENTER]takke dig.[ENTER]De vil blive meget skuffet. V\230r venlig at sikre[ENTER]dig, du ikke har glemt nogen. "
gameforge.main_quest_lv98._400_say = "Tapperhed og visdom er er i dit hjerte at m\229le.[ENTER]Dine gerninger vil blive sunget i generationer[ENTER]fra nu af. Jeg bukker for dig. "
gameforge.main_quest_lv98._410_say = "M\229 du v\230re godt rustet mod alle farer, for altid! "
gameforge.main_quest_lv98._420_say = "Du vil f\229 en h\230dersplads i vores hjerter for[ENTER]altid. "
gameforge.main_quest_lv98._430_say = "Det var nogle turbulente tider, ikke? Jeg er[ENTER]sikker p\229 at Drage guden alene var ansvarlig for[ENTER]at bane din vej til vores \248. "
gameforge.main_quest_lv98._440_1_notice = "Du har talt med alle beboerne. "
gameforge.main_quest_lv98._440_2_notice = "Vend nu tilbage til Yak-Hwan. "
gameforge.main_quest_lv98._450_say = "Det har sandelig betydet noget for beboerne i[ENTER]fortet.[ENTER]Admiralen ville gerne tale med dig endnu engang.[ENTER]G\229 til ham som det n\230ste. "
gameforge.main_quest_lv98._460_say = {}
gameforge.main_quest_lv98._470_say = {}
gameforge.main_quest_lv98._480_sendLetter = "Admiralens tak "
gameforge.main_quest_lv98._490_say = "Admiral Angmur vil gerne vise sin taknemmelighed[ENTER]for dig. G\229 til ham. "
gameforge.main_quest_lv98._500_say = "Uden dig ville beboerne i fortet v\230re blevet[ENTER]indvaderet af d\230moner. For din st\248tte i kampen[ENTER]mod m\248rkets tjenere, takker jeg dig p\229 vegne af[ENTER]mine tropper og hele folket.[ENTER]P\229 M\248rk Dage Klippe vil du altid finde et sted at[ENTER]kalde hjemme. "
gameforge.main_quest_lv98._510_say = {}
gameforge.main_quest_lv98._520_say = "Men Banshee og m\248rkets tjenere vil ikke holde[ENTER]nogen form for pause og vil fors\230tte uendeligt[ENTER]med smedningen af deres m\248rke planer.[ENTER]Eventyret forts\230tte s\229 snart du er kommet i level[ENTER]99. "
