gameforge.manwoo = {}
gameforge.manwoo._10_npcChat = "Fiskeopdradt "
gameforge.manwoo._20_sayTitle = "Fisker: "
gameforge.manwoo._30_say = "Jeg vil udvide min fiskeopdr\230t, derfor har jeg[ENTER]brug for levende karper. Disse fiske kan bruges i[ENTER]opdr\230t og er popul\230r hos fisker, men det er ikke[ENTER]nemt at fange dem.  "
gameforge.manwoo._40_say = "Hvis du bringer mig en karpe, vil jeg give dig en[ENTER]bel\248nning. Jeg har en kiste p\229 mit loftsrum der[ENTER]har v\230ret der i \229revis. Jeg kan ikke huske hvad[ENTER]der er i det. Det er m\229ske noget totalt[ENTER]ubrugeligt, eller noget meget v\230rdifuldt. Hvor om[ENTER]alting er kan et monster ogs\229 gemme sig der i.[ENTER]Hvis du vil have det, bring mig en karpe i live. "
gameforge.manwoo._50_npcChat = "Bytter karpe mod kiste "
gameforge.manwoo._60_say = "Bringer du mig en karpe til mit fiskeopdr\230t?[ENTER]Mange tak! Her er den lovede kiste. Held og lykke! "
gameforge.manwoo._70_sayReward = "Du har f\229et en kiste![ENTER]H\248jreklik for at \229bne den. "
