gameforge.map_warp._110_sayReward = "Det koster %s Yang "
gameforge.map_warp._11_array = "Egnen Jungrand "
gameforge.map_warp._120_sayReward = "Men jeg vil \248ge prisen hvis du forts\230tter s\229dan[ENTER]her! "
gameforge.map_warp._12_array = "Egnen Waryong "
gameforge.map_warp._130_say = "Som jeg sagde: Du kan f\248rst teleportere dig n\229r[ENTER]du har n\229et level 60. \216nsker du stadig at[ENTER]teleportere? Hvis ikke s\229 luk vinduet. Og stop[ENTER]med at skifte mening. Jeg st\229r ikke her for[ENTER]sjovt. "
gameforge.map_warp._13_array = "Egnen Imha "
gameforge.map_warp._140_sayReward = "Din rejse vil koste dig %d Yang. "
gameforge.map_warp._14_array = "Slottet Milaard "
gameforge.map_warp._150_say = "Jeg ville ogs\229 teleportere dig gratis, men jeg[ENTER]har en stor familie. Jeg er n\248d til at br\248df\248de,[ENTER]s\229 jeg er n\248d til at tjene penge. "
