gameforge.map_warp._160_sayReward = "Det koster %s Yang "
gameforge.map_warp._16_array = "Slottet Dendera "
gameforge.map_warp._170_say = "Jeg teleporterer dig nu...[ENTER]Du vil lande et farligt sted.. Pas godt p\229 dig[ENTER]selv.. s\229....  "
