gameforge.map_warp._250_say = "Som du \248nsker... Vi ses snart! "
gameforge.map_warp._260_npcChat = "M\248rk Drage Klippe "
gameforge.map_warp._270_say = "Fornyligt er en mystisk \248 blevet fundet. Den er[ENTER]blevet kaldt M\248rk Drage Klippe. Dem som \248nsker at[ENTER]overleve der, er n\248dt til at have en smule[ENTER]erfaring. Af den grund, vil jeg kun tage krigere,[ENTER]som er n\229et level 90. Er du klar til at tage[ENTER]denne rejse? "
gameforge.map_warp._280_say = "Du kan kun komme til \248en med skib - og denne[ENTER]rejse er lang og besv\230rlig. Jo h\248jere level, jo[ENTER]st\248rre opkr\230vning for transporten. Af den grund,[ENTER]er jeg n\248dt til at bede dig om et h\248jere afgift[ENTER]fra dig. "
gameforge.map_warp._280_sayReward = "Din rejse vil koste dig %d Yang. "
gameforge.map_warp._30_say = "Det er p\229 sin m\229de en fascinerende omegn, men[ENTER]sker her noget ud over det s\230dvanlige? Slet[ENTER]ikke... Andre dele af landet ser meget anderledes[ENTER]ud! Der findes sikkert en interessant omegn jeg[ENTER]kan teleportere dig hen til, men da de m\248rke[ENTER]kr\230fter er blevet st\230rkere, er rum og tid til[ENTER]dels kaotisk. Derfor kan det ske, at din[ENTER]hjem-teleportation ikke sker \248jeblikkeligt.[ENTER]\216nsker du alligevel at[ENTER]teleportere?  "
gameforge.map_warp._40_say = "Hmm... Med dit nuv\230rende level, er du for svag[ENTER]til at udholde rejsen igennem tid og rum. Kom[ENTER]igen n\229r du har et level der er h\248jere end 10. "
gameforge.map_warp._50_say = "Hvor \248nsker du at teleportere dig hen? "
gameforge.map_warp._60_sayReward = "Det koster %s Yang "
gameforge.map_warp._70_say = "Det her er omegne jeg kan teleportere dig hen,[ENTER]n\229r du har n\229et level 60. "
gameforge.map_warp._80_sayReward = "Men det koster s\229 %s Yang. "
