gameforge.neutral_warp._65_npcChat = "Jeg vil g\229 til den gamle dame's s\248ster. "
gameforge.neutral_warp._70_say = "Den gamle dame har allerede fortalt mig, at du[ENTER]var p\229 vej. Hun sagde, at jeg ikke skulle opkr\230ve[ENTER]dig for denne tur, fordi du g\248r hende en[ENTER]tjeneste. Vi drikker ofte te sammen, og jeg er[ENTER]glad for at hj\230lpe hende. Men du skal ikke narre[ENTER]dig selv, s\229dan bliver det ikke i fremtiden! V\230r[ENTER]forsigtig der over, fordi dem der er tilknyttede[ENTER]til udenlandske kongeriger bliver ikke set p\229 med[ENTER]venlighed. "
gameforge.new_christmas = {}
gameforge.new_christmas._010_npcChat = "Ho ho ho! "
gameforge.new_christmas._020_say = "Ah det er dig![ENTER]Vi har ikke set hinanden i lang tid.[ENTER]Endnu et \229r er allerede kommet og g\229et, ho ho![ENTER]M\229ske du sp\248rger dig selv hvorfor Jeg er tilbage[ENTER]her i landsbyen.[ENTER]Tillad mig at forklare... "
gameforge.new_christmas._030_say = "Tider er h\229rde. Ingen \248nsker at k\248be b\248ger eller[ENTER]andre s\229danne ting i disse dage.[ENTER]Med min krybende alder, er det alt for tr\230ls at[ENTER]flyve rundt p\229 en rensdyr-ledet sl\230de.[ENTER]S\229 med det i tankerne, har jeg besluttet for at[ENTER]fejre jul i \229r i landsbyen. "
gameforge.new_christmas._040_say = "Hvis du har yderligere sp\248rgsm\229l, kan du altid[ENTER]komme og sp\248rge mig. Gl\230delig jul! "
gameforge.new_christmas._050_npcChat = "Vil du have noget gl\248gg? "
gameforge.new_christmas._060_say = "Ho ho ho! Jeg er sikker p\229 at du ved hvad det er,[ENTER]ikke? Der findes ingen bedre drik til vinterlige[ENTER]dage![ENTER]Du blander et godt glas vin, en knivspids kanel[ENTER]og en flok nelliker ... mmmmm! "
gameforge.new_christmas._070_say = "I dette kolde vejr, vil et sip af gl\248gg g\248re dig[ENTER]godt! Det giver dig styrke og hj\230lper dig med at[ENTER]bev\230ge dig hurtigere. Vil du gerne smage? Meget[ENTER]godt, her er en til dig! "
gameforge.new_christmas._080_say = "Det ser ud til at du kan lide smagen af gl\248gg ho[ENTER]ho! F\248ler du det varmer dig indefra?[ENTER]\197h, og smagen, s\229 s\248d og frugtagtig! Gl\230delig jul! "
gameforge.new_christmas._090_npcChat = "Mere gl\248gg tak! "
gameforge.new_christmas._100_say = "H\230ng p\229 et sekund![ENTER]Jeg glemte en lille detalje![ENTER]Jeg kan kun tilberede gl\248gg til dig en gang om[ENTER]dagen, jeg har ikke ingredienser nok til at lave[ENTER]mere. Og det varer kun i 20 timer. I en flaske er[ENTER]der 6 portioner, virkningerne af en t\229r vare i 30[ENTER]minutter. Brug dem med omtanke! "
gameforge.new_christmas._110_say = "Du er velkommen! Du har m\229ttet vente l\230nge nok.[ENTER]Denne vidunderlige drik vil give dig vinger, ho[ENTER]ho ho! S\229 jeg h\229ber du nyder det.[ENTER]Gl\230delig jul! "
gameforge.new_christmas._120_say = "Hvad, du vil have noget mere?[ENTER]Beklager, men jeg tror, du har f\229et nok.[ENTER]24 timer er ikke g\229et siden din sidste ration af[ENTER]gl\248gg. For meget af det her er ikke godt for dig,[ENTER]ved du! Kom tilbage igen senere.[ENTER]Indtil da, nyd festen! "
