gameforge.new_christmas_sock = {}
gameforge.new_christmas_sock._010_npcChat = "Hvad er der med de sokker? "
gameforge.new_christmas_sock._020_say = "Sokkerne! Jeg havde n\230sten glemt dem![ENTER]Jeg \248nskede at skjule min gaver i sokker h\230ngende[ENTER]over pejsen. Men disse u-julede skabninger har[ENTER]stj\229let dem alle![ENTER]Hj\230lp mig med at f\229 dem tilbage. "
gameforge.new_christmas_sock._030_say = "Sokkerne er ikke s\229 nemme at finde. Du f\229r brug[ENTER]for Rensdyr Kalven for at snuse dem op. "
gameforge.new_christmas_sock._040_say = "Er den ikke s\248d?[ENTER]Den har ogs\229 en fremragende lugtesans. En[ENTER]specialist i str\248mpe jagt![ENTER]Den bliver hos dig i 2 timer og hj\230lper dig med[ENTER]s\248gningen. Bagefter bliver den tr\230t og har behov[ENTER]for 24 timers hvile, f\248r den kan forts\230tte.[ENTER]Hvis du ikke \248nsker at vente s\229 l\230nge, s\229 tag et[ENTER]kig ned til venstre og se hvad der gemmer sig bag[ENTER]den roterende m\248nt, jeg har h\248rt at en anden[ENTER]Rensdyr Kalv venter der. Men jeg vil ogs\229 v\230re[ENTER]glad for at se dig hvis du bes\248ger mig igen i[ENTER]morgen! "
gameforge.new_christmas_sock._050_npcChat = "Jeg bringer dig sokker! "
gameforge.new_christmas_sock._060_say = "Bring mig mindst 5 sokker, og du vil modtage en[ENTER]bel\248nning.[ENTER]Urrgh, duften af muggen sokke er uudholdelig![ENTER]Kom tilbage n\229r du har indsamlet nok.[ENTER]Gl\230delig jul! "
gameforge.new_christmas_sock._070_say = "Ho ho ho, har du samlet sokker nok.[ENTER]Hmm, lad mig se.[ENTER]URRGH denne lugt! N\229 det er absolut de rigtige[ENTER]sokker![ENTER]Gl\230delig jul! "
gameforge.new_christmas_sock._080_npcChat = " - Rensdyr Kalv "
gameforge.new_christmas_sock._090_say = "Du har allerede modtaget et Rensdyr Kalv Segl fra[ENTER]mig i dag. Jeg er bange for at den lille fyr har[ENTER]brug for en pause nu. Det vil v\230re tilbage i fuld[ENTER]vig\248r igen i morgen. Hvis du ikke \248nsker at vente[ENTER]s\229 l\230nge, s\229 tag et kig ned til venstre og se[ENTER]hvad der gemmer sig bag den roterende m\248nt, jeg[ENTER]har h\248rt at en anden Rensdyr Kalv venter der. Men[ENTER]jeg vil ogs\229 v\230re glad for at se dig hvis du[ENTER]bes\248ger mig igen i morgen! "
gameforge.new_christmas_sock._100_say = "Du har allerede bragt mig dine str\248mper i dag.[ENTER]Husk, du kan kun aflevere hver 24 timer. "
