gameforge.new_quest_lv17._020_say_title = "Gaven til Chaegirab "
gameforge.new_quest_lv17._021_say = "Min onkel Chaegirab har viet sit liv til[ENTER]videnskab og har investeret alle sine Yang i hans[ENTER]forskning. Han har altid v\230ret god ved mig, s\229[ENTER]jeg vil gerne overraske ham med en gave. Vil du[ENTER]g\229 til Uriel og sp\248rge ham, om han har en id\233 om[ENTER]hvad jeg kunne give ham? Han er min onkels gamle[ENTER]l\230rer og han kender ham meget godt. "
gameforge.new_quest_lv17._030_say = "Men du beh\248ver ikke fort\230lle min onkel om det! "
gameforge.new_quest_lv17._031_say = "Vil du hj\230lpe mig? "
gameforge.new_quest_lv17._039_say_title = "Uriel: "
gameforge.new_quest_lv17._040_say_title = "Snak med Uriel "
gameforge.new_quest_lv17._040_target = "Uriel: "
gameforge.new_quest_lv17._041_say = "Tal med Uriel om hans tidligere elev Chaegirab. "
gameforge.new_quest_lv17._042_say = "Uriel er i %s. "
gameforge.new_quest_lv17._050_say_title = "Wonda-Rim \248nsker at give Chaegirab en gave... "
gameforge.new_quest_lv17._051_say = "En videnskabsmands gl\230de i livet, kommer fra[ENTER]forskning. S\229 simpelt er det. Den bedste m\229de at[ENTER]g\248r Chaegirab glad er ved at st\248tte hans arbejde.[ENTER]Den Mu-Rang Ulv er en sj\230lden g\230st i disse lande,[ENTER]men dens pels er ogs\229 en sj\230lden l\230kkerbisken for[ENTER]alle biologer. Fem stykker pels burde v\230re nok.[ENTER]S\229 kan du fort\230lle Wonda-Rim det. "
gameforge.new_quest_lv17._052_say = "Jeg er sikker p\229 at denne imponerende pels vil[ENTER]imponere biologen. "
gameforge.new_quest_lv17._060_select = "Ja, det vil jeg lade ham vide. "
gameforge.new_quest_lv17._065_say_title = "Tilbage til Wonda-Rim "
gameforge.new_quest_lv17._066_say = "Uriel t\230nkte p\229 en stor gave for Chaegirab. G\229[ENTER]tilbage til Wonda-Rim og fort\230lle ham om det. "
gameforge.new_quest_lv17._067_say = "Wonda-Rim er i %s. "
gameforge.new_quest_lv17._070_say = "Uriel's forslag lyder godt. Jeg \248nsker virkelig[ENTER]at g\248re dette som en overraskelse for min onkel[ENTER]Chaegirab, jeg er n\248dt til at f\229 fat i denne[ENTER]pels. Kan du g\229 ud og dr\230be 5 Mu-Rangs for mig? "
gameforge.new_quest_lv17._071_say = "Jeg skulle til at dr\230be Mu-Rang-ulve for at f\229[ENTER]deres pels. "
gameforge.new_quest_lv17._072_say = "5 er nok til en god gave. "
gameforge.new_quest_lv17._073_say = "Lad os g\229! "
gameforge.new_quest_lv17._074_notice = "Du har plyndret nogle gode kvalitet pelse. "
gameforge.new_quest_lv17._075_say = "Jag Mu-Rang Ulve og plyndre deres pels. "
gameforge.new_quest_lv17._076_say_reward = "Du har samlet %s af 5 stykker pels. "
gameforge.new_quest_lv17._081_say_title = "Pels til Wonda-Rim "
gameforge.new_quest_lv17._082_say = "Du har plyndret pels nok, tag det til Wonda-Rim. "
gameforge.new_quest_lv17._092_say_reward = "Du har allerede indsamlet %s stykker ulve pels. "
gameforge.new_quest_lv17._110_say = "Dette er rigtig dejlig pels, tak. Kunne du[ENTER]aflevere den til min onkel? "
gameforge.new_quest_lv17._120_target = "Onkel Chaegirab "
gameforge.new_quest_lv17._121_say = "Wonda-Rim har bedt dig om at tage ulve pels til[ENTER]Chaegirab. "
gameforge.new_quest_lv17._122_say = "Chaegirab er i %s. "
gameforge.new_quest_lv17._130_say = "Aha. S\229 det er det, han fors\248ger at g\248re nu. "
gameforge.new_quest_lv17._131_say = "Fra hvem er denne pels? Det er fra Wonda-Rim, men[ENTER]du dr\230bte ulve for ham? Jeg er flov over at have[ENTER]en nev\248, der lader andre g\248r arbejdet for ham. S\229[ENTER]jeg er ked af det, men jeg kan ikke acceptere[ENTER]dette, selvom jeg ved, at du har brugt en masse[ENTER]tid og kr\230fter p\229 det. "
gameforge.new_quest_lv17._132_say_reward = "Fort\230l Wonda-Rim, at jeg ser lige igennem ham![ENTER]Hvis han virkelig \248nsker at behandle mig s\229dan,[ENTER]s\229 skulle han selv g\229 p\229 jagt. "
gameforge.new_quest_lv17._140_say = "Chaegirab acceptere ikke den pels og er vred p\229[ENTER]Wonda-Rim for hans dovenskab. Han har sendt dig[ENTER]tilbage til Wonda-Rim. "
gameforge.new_quest_lv17._141_say = "Hvad sagde min onkel? Jeg h\229ber, at han kunne[ENTER]lide min gave? "
gameforge.new_quest_lv17._142_1_select = "Ja, han var begejstret. "
gameforge.new_quest_lv17._142_2_select = "Nej, slet ikke. "
gameforge.new_quest_lv17._143_say = "Godt! Jeg elsker at give andre mennesker en[ENTER]godbid. Og selvf\248lgelig vil jeg give dig en[ENTER]gener\248s bel\248nning. Her, tag den! "
gameforge.new_quest_lv17._144_say_reward_a = "Du har modtaget 20,000 erfaringspoint.[ENTER]Du har modtaget 20,000 Yang.[ENTER]Du har modtaget en klump guld. "
gameforge.new_quest_lv17._144_say_reward_b = "Du l\248j over for Wonda-Rim og har mistet god/ond[ENTER]karma. "
gameforge.new_quest_lv17._145_say = "Han accepterede ikke pelsen? Hmm, m\229ske var det[ENTER]ikke s\229dan en god ide at sende dig p\229 jagt i[ENTER]stedet for mig. Jeg vil g\248re det anderledes n\230ste[ENTER]gang. "
gameforge.new_quest_lv17._146_say_reward = "Men jeg \248nsker ikke at alt dit h\229rde arbejde skal[ENTER]v\230re spildt: G\229 til Yang-Shin. Han vil k\248be pels[ENTER]af dig til en god pris. "
gameforge.new_quest_lv17._147_say = "Sikke en skuffende vending, begivenhederne tog.[ENTER]N\229, i det mindste har du stadig pelsen. G\229 til[ENTER]j\230geren Yang-Shin i Yayang og s\230lg pelsen til[ENTER]ham. "
gameforge.new_quest_lv17._148_say = "Sikke en skuffende vending, begivenhederne tog.[ENTER]N\229, i det mindste har du stadig pelsen. G\229 til[ENTER]j\230geren Yang-Shin i Bokjung og s\230lg pelsen til[ENTER]ham. "
gameforge.new_quest_lv17._149_say = "Sikke en skuffende vending, begivenhederne tog.[ENTER]N\229, i det mindste har du stadig pelsen. G\229 til[ENTER]j\230geren Yang-Shin i Bakra og s\230lg pelsen til ham. "
gameforge.new_quest_lv17._151_say = "Mu-Rang Pels? Der kommer lige tilpas. Jeg vil[ENTER]lave mig noget undert\248j af det. Her er en pose[ENTER]Yang for din indsats. \197h, jeg fandt ogs\229 denne[ENTER]bog i g\229r, m\229ske du kan bruge den. "
gameforge.new_quest_lv17._152_say_reward = "Du har modtaget 40,000 erfaringspoint.[ENTER]Du har modtaget 10,000 Yang.[ENTER]Du har modtaget en F\230rdighedsbog. "
gameforge.new_quest_lv17._160_target = "Yang-Shin: "
gameforge.new_quest_lv17._161_say_title = "Yang-Shin: "
gameforge.new_quest_lv22 = {}
gameforge.new_quest_lv22._010_target = "Landsby vagt: "
gameforge.new_quest_lv22._011_say = "Landsby vagten har en mission til dig. G\229 til ham[ENTER]og find ud af, hvad det hele handler om. "
gameforge.new_quest_lv22._015_npcChat = "Den syge bror "
gameforge.new_quest_lv22._016_send_letter = "Den syge vagt "
gameforge.new_quest_lv22._017_say_title = "Landsby vagt: "
gameforge.new_quest_lv22._018_say_title = "Baek-Go: "
gameforge.new_quest_lv22._019_say_title = "D\230mont\229rn-vagt "
gameforge.new_quest_lv22._021_say = "Jeg er bekymret for min bror, Demon T\229rn Vagten.[ENTER]Han har ikke f\248lt sig godt for nylig og nu er han[ENTER]virkelig syg. Han fik en rigtig kraftig hovedpine[ENTER]og et underlig hududsl\230t, men han kan bare ikke[ENTER]forlade sin post. Kan du f\229 noget medicin til ham[ENTER]fra Baek-Go? "
gameforge.new_quest_lv22._022_say = "Jeg ville g\229 selv, men Demon T\229rn er i Hwang[ENTER]Templet, lige i centrum af dalen af Seungryong.[ENTER]Og hele stedet vrimler bare med farlige v\230sner... "
gameforge.new_quest_lv22._023_say = "Der er du igen. Du glemte symptomerne? Du skulle[ENTER]fors\248ge at lytte, n\229r nogen taler til dig. Min[ENTER]bror har f\229et en hovedpine og et hud udsl\230t. G\229[ENTER]nu og fort\230l det til Baek-Go! "
gameforge.new_quest_lv22._024_select = "Hj\230lp Broderen "
gameforge.new_quest_lv22._025_say_title = "Baek-Go's medicin "
gameforge.new_quest_lv22._026_say = "Tal med Baek-Go om medicinen til Demon T\229rn[ENTER]vagten. "
gameforge.new_quest_lv22._027_say = "Baek-Go er i %s. "
gameforge.new_quest_lv22._030_target = "Baek-Go: "
gameforge.new_quest_lv22._031_say = "S\229 du har brug for medicin? Det er farligt at[ENTER]administrere medicin uden at vide om det er den[ENTER]rigtige! Du er n\248dt til at fort\230lle mig om[ENTER]symptomerne p\229 sygdommen. "
gameforge.new_quest_lv22._032_1_select = "Hovedpine og udsl\230t "
gameforge.new_quest_lv22._032_2_select = "Ondt i halsen og kramper "
gameforge.new_quest_lv22._032_3_select = "Jeg ved det ikke. "
gameforge.new_quest_lv22._035_say = "Lyder som d\230mon kradsm\230rker for mig. Dette[ENTER]opst\229r, n\229r alt for mange mide-bef\230ngt b\230ster er[ENTER]t\230t p\229. Jeg kan producere noget, der kan hj\230lpe[ENTER]ham. Du bliver n\248dt til selv at f\229 fat i nogle[ENTER]ingredienser til det. "
gameforge.new_quest_lv22._040_say = "Jeg beh\248ver: "
gameforge.new_quest_lv22._041_say_reward = "Du skal jagte: "
gameforge.new_quest_lv22._042_say = "Jeg har ogs\229 brug for: "
gameforge.new_quest_lv22._043_say = "Jeg har aldrig h\248rt om s\229dan en sygdom. Er du[ENTER]sikker p\229, at Landsby vagten fortalte dig de[ENTER]rigtige symptomer? Jeg ville sp\248rge ham igen,[ENTER]hvis jeg var dig. "
gameforge.new_quest_lv22._044_say = "Jeg kan ikke lave en diagnose uden symptomer.[ENTER]G\229 tilbage og sp\248rge igen. "
gameforge.new_quest_lv22._050_set_title = "Medicin "
gameforge.new_quest_lv22._056_notice = "Godt, nu mangler jeg bare %s bundter urter. "
gameforge.new_quest_lv22._057_notice = "Det burde v\230re alle de urter jeg har brug for.[ENTER]Nu hurtigt g\229 tilbage til Baek-Go. "
gameforge.new_quest_lv22._058_notice = "Godt, nu er der kun %s lever tilbage. "
gameforge.new_quest_lv22._060_notice = "Ah, nogle levere. Nu mangler jeg bare %s. "
gameforge.new_quest_lv22._061_notice = "Det burde v\230re alle de levere jeg har brug for.[ENTER]Nu hurtigt g\229 tilbage til Baek-Go. "
gameforge.new_quest_lv22._062_notice = "Desv\230rre kan jeg ikke bruge denne lever. "
gameforge.new_quest_lv22._063_say = "Du har brug for endnu %s x medicinske planter+. "
gameforge.new_quest_lv22._064_say = "Du har brug for endnu %s x Tiger lever+. "
gameforge.new_quest_lv22._065_say = "Nu har du f\229et alle ingredienserne til medicinen.[ENTER]G\229 nu og aflevere det til Baek-Go. "
gameforge.new_quest_lv22._066_say = "Saml ingredienserne til Baek-Go's medicin: "
gameforge.new_quest_lv22._070_say = "Tak, nu kan jeg lave medicin til de d\230mon[ENTER]skrammer. "
gameforge.new_quest_lv22._071_say = "F\230rdig! Her er din medicin. De friske[ENTER]ingredienser betyder, at medicinen ikke holder[ENTER]sig i lang tid - s\229 du skal aflevere den til din[ENTER]patient inden for de n\230ste %s minutter. "
gameforge.new_quest_lv22._072_say = "Du kan finde Landsby vagtens bror i centrum af[ENTER]Hwang templet. Men v\230r forsigtig p\229 vej derhen,[ENTER]for i Seungryong Dalen vrimler det med farlige[ENTER]v\230sner! "
gameforge.new_quest_lv22._073_say = "Det er ikke nok. Har du taber ingredienserne p\229[ENTER]vej her over? Jeg kan ikke g\248re noget for dig[ENTER]uden resten af komponenterne. "
gameforge.new_quest_lv22._080_target = "D\230mont\229rn-vagt "
gameforge.new_quest_lv22._082_set_clock = "Resterende tid "
gameforge.new_quest_lv22._083_say = "N\229 du har stadig tid nok, men du er n\248dt til at[ENTER]skynde dig. S\229 skynd dig til vagten i Seungryong[ENTER]Dalen nu, f\248r medicinen ikke virker mere! "
gameforge.new_quest_lv22._084_say = "Tiden er l\248bet ud, fordi du var for langsom.[ENTER]Men du b\248r tage medicinen til D\230mont\229rn-vagt[ENTER]alligevel. Det kan stadig fungere. "
gameforge.new_quest_lv22._085_say = "Tak fordi du bragte mig den medicin. Den kl\248e er[ENTER]ved at sl\229 mig ihjel. "
gameforge.new_quest_lv22._086_say = "\197h, det smager ganske godt. Jeg kan allerede[ENTER]m\230rke kl\248en bliver bedre. "
gameforge.new_quest_lv22._087_say = "Du har fortjent en s\230rlig gener\248s bel\248nning for[ENTER]at g\248r det! "
gameforge.new_quest_lv22._088_say_reward = "Du har modtaget 50,000 erfaringspoint.[ENTER]Du har modtaget 12,000 Yang.[ENTER]Du har f\229et Udsmykkede Guld Sko +4.[ENTER]Du har modtaget 5 Lilla Eliksir. "
gameforge.new_quest_lv22._089_say = "\197h, det smager forf\230rdeligt. Medicinen virker[ENTER]ikke mere - hvor lang tid tog det dig at komme[ENTER]hertil? Min tunge f\248les som abe m\248g. "
gameforge.new_quest_lv22._090_say = "Hmm, vent et sekund ... det synes at blive bedre[ENTER]nu. Ja, det virker! OK, i dette tilf\230lde vil jeg[ENTER]ikke v\230re ond. Du f\229r din bel\248nning alligevel. "
gameforge.new_quest_lv22._091_say = "Det ser ud til at du har mistet medicinen. V\230r[ENTER]venlig at g\229 p\229 jagt igen, og f\229 ingredienserne[ENTER]til et nyt l\230gemiddel til Baek-Go. Jeg blive[ENTER]snart selv til en d\230mon, hvis det kl\248e bliver ved[ENTER]meget l\230ngere. "
gameforge.new_quest_lv22._095_say_reward = "Du har modtaget 50,000 erfaringspoint.[ENTER]Du har modtaget 8,000 Yang. "
gameforge.new_quest_lv22._098_say = "Du har mistet medicinen igen? Jeg har aldrig m\248dt[ENTER]en s\229dan bims person i hele mit liv! N\229 ja, der[ENTER]er ikke meget, vi kan g\248re ved det nu. "
gameforge.new_quest_lv22._100_say_reward = "Du har modtaget 25,000 erfaringspoint. "
gameforge.new_quest_lv26 = {}
gameforge.new_quest_lv26._010_target = "Yang-Shin: "
gameforge.new_quest_lv26._020_say_title = "Yang-Shin: "
gameforge.new_quest_lv26._020_set_title = "Desert\248ren "
gameforge.new_quest_lv26._021_say = "Yang-Shin har problemer med at finde gode jagt[ENTER]marker. G\229 til ham og find ud af hvordan du kan[ENTER]hj\230lpe ham. "
gameforge.new_quest_lv26._025_say = "Intet er som, det plejer at v\230re, f\248r Metin[ENTER]Stenene kom ned. Selv det at g\229 p\229 jagt er blevet[ENTER]umulige masser af steder, fordi vilde dyr begyndt[ENTER]at opf\248re sig som om de har hundegalskab.[ENTER]Vandreren Nakajima bor derude et eller andet[ENTER]sted, jeg er sikker p\229 at han vil vide, hvor der[ENTER]er nogle gode jagtomr\229de. Kunne du lede efter ham[ENTER]og sp\248rge? "
gameforge.new_quest_lv26._030_target = "Nakajima: "
gameforge.new_quest_lv26._031_say = "S\229 du \248nsker at vide et godt sted at jage?[ENTER]V\230r ikke s\229 forhastet, hvis jeg skulle g\248re noget[ENTER]for dig, s\229 skal du ogs\229 g\248re mig en tjeneste. "
gameforge.new_quest_lv26._032_say = "Du b\248r vide ... Jeg bor ikke her frivilligt. Jeg[ENTER]har brug for at skjule mig, fordi jeg flygtede[ENTER]fra de grusomheder i milit\230ret. Jeg \248nsker blot,[ENTER]at min elskede kone Ah-Yu skulle vide, at jeg[ENTER]stadig er i live. Kan du aflevere denne besked[ENTER]til hende? Men husk, at det er kun for Ah-Yu's[ENTER]\248rer! Til geng\230ld vil hun fort\230lle dig, hvor vi[ENTER]kyssede for f\248rste gang - Jeg \248nsker at m\248de[ENTER]hende der, og dens omr\229de er et godt sted at[ENTER]jage. "
gameforge.new_quest_lv26._034_say_title = "Nakajima: "
gameforge.new_quest_lv26._035_say_title = "Ah-Yu: "
gameforge.new_quest_lv26._036_say_title = "Kig efter Nakajima "
gameforge.new_quest_lv26._037_say = "Nakajima burde kender nogle gode steder at jage.[ENTER]Kig efter ham. "
gameforge.new_quest_lv26._038_say = "Nakajima er i %s. "
gameforge.new_quest_lv26._040_say = "Er du Nakajima? Yang-Shin sendte mig! Han er p\229[ENTER]udkig efter nogle jagtomr\229de, m\229ske har du en id\233[ENTER]om, hvor jagt ikke er s\229 farligt? "
gameforge.new_quest_lv26._050_target = "Ah-Yu: "
gameforge.new_quest_lv26._051_say = "Nakajima er en desert\248r og skjuler sig for h\230ren[ENTER]nu. Hans kone Ah-Yu mener, at han faldt i krigen.[ENTER]Lad hende vide, at Nakajima stadig er i live. "
gameforge.new_quest_lv26._052_say = "Ah-Yu er i %s. "
gameforge.new_quest_lv26._057_say = "Nakajima ... han er i live? Min elskede mand er i[ENTER]live? Jeg kan ikke takke jer nok for at fort\230lle[ENTER]mig dette! Det var Yonjang Dalen han talte om.[ENTER]Jeg har t\230nkt mig at tage afsted straks og m\248de[ENTER]ham. "
gameforge.new_quest_lv26._058_say = "Tak for at g\248re denne genforening mulig. Tag[ENTER]denne Rose med dig, m\229ske du kunne give den til[ENTER]en elsket en? Og nu ... undskyld mig, men jeg er[ENTER]n\248dt til at skynde mig! "
gameforge.new_quest_lv26._061_say = "Dalen Yonjang - hvor Nakajima og Ah-Yu f\248rst[ENTER]kyssede - er stadig et meget godt jagt omr\229de. "
gameforge.new_quest_lv26._062_say = "Yang-Shin vil blive glad, n\229r han h\248rer det. G\229[ENTER]til %s og give ham den gode nyhed. "
gameforge.new_quest_lv26._063_say = "Yonjang dalen? Det lyder muligt, da jeg aldrig[ENTER]har h\248rt om at Metin Sten skulle have forurenet[ENTER]det p\229g\230ldende omr\229de.[ENTER]Jeg skal nok v\230re i stand til til at f\229 stor[ENTER]udbytte der! Her du fortjener denne bel\248nning. "
gameforge.new_quest_lv26._064_sayReward = "Du f\229r 35,000 erfaringspoint. "
gameforge.new_quest_lv26._065_sayReward = "Du har modtaget 17,500 Yang. "
gameforge.new_quest_lv28 = {}
gameforge.new_quest_lv28._010_target = "Yu-Hwan: "
gameforge.new_quest_lv28._011_say = "Yu-Hwan, musikeren, har brug for din hj\230lp. G\229[ENTER]hurtigt og find ud af hvad der sker! "
gameforge.new_quest_lv28._015_npcChat = "Ah-Yu's bekymringer "
gameforge.new_quest_lv28._016_say = "Ah-Yu synes at have noget i sinde, som hun ikke[ENTER]\248nsker at fort\230ller Yu-Hwan. Bes\248ge hende og og[ENTER]se, om hun \248nsker at \229bne sig for dig. "
gameforge.new_quest_lv28._017_say = "Ah-Yu er i %s. "
gameforge.new_quest_lv28._018_select = "Jeg vil tale med Ah-Yu snart! "
gameforge.new_quest_lv28._019_say_title = "Ah-Yu: "
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan: "
gameforge.new_quest_lv28._021_say = "Kender du Ah-Yu? Hun samler urter til mine[ENTER]eliksirer. Hun plejede at v\230re i godt hum\248r, men[ENTER]i g\229r virkede hun helt ud af den. Hun ville bare[ENTER]ikke fort\230lle mig, hvad der var galt, men m\229ske[ENTER]er det fordi hun arbejder for mig?[ENTER]Venligst g\229 og se til hende og find ud af,[ENTER]hvordan hun har det.[ENTER]M\229ske vil hun \229bne sig for dig! "
gameforge.new_quest_lv28._022_say = "Det er meget p\230nt af Yu-Hwan at bekymre sig om[ENTER]mig. Men ja, jeg har noget i tankerne... Jeg[ENTER]ville ikke snakke om det, men det giver mig en[ENTER]h\229rd kamp! Det handler om Yang-Shin, j\230geren.[ENTER]Han har afpresset mig siden, han fandt ud af at[ENTER]min mand Nakajima er en desert\248r. Yang-Shin truer[ENTER]med at sladre om ham! Og s\229 vil de dr\230be ham... "
gameforge.new_quest_lv28._023_say = "Denne gang kr\230vede han en Bj\248rne-klo til geng\230ld[ENTER]for hans tavshed. Men jeg kan ikke g\229 p\229 jagt nu.[ENTER]Kan du hj\230lpe mig og give Yang- Shin, hvad han[ENTER]\248nsker? "
gameforge.new_quest_lv28._024_set_title = "Jagt bj\248rne "
gameforge.new_quest_lv28._025_notice = "Lad os g\229 p\229 jagt! Dr\230b Bera det er den bedste[ENTER]m\229de at f\229 fat i Bj\248rne-klo. "
gameforge.new_quest_lv28._026_notice = "Jeg har hentet en Bj\248rne-klo! "
gameforge.new_quest_lv28._027_notice = "Det var det hele. Afsted til Yang-Shin! "
gameforge.new_quest_lv28._028_notice = "Denne Bj\248rne-klo er ubrugelig. "
gameforge.new_quest_lv28._029_say = "Du har brug for en anden %s x Bj\248rne-klo. "
gameforge.new_quest_lv28._031_say_reward = "Du skal jagte: "
gameforge.new_quest_lv28._032_say = "Ah-Yu har bedt dig om at opfylde Yang-Shin's[ENTER]\248nske. "
gameforge.new_quest_lv28._032_say_reward = "Du har brug for en anden %s x Bj\248rne-klo.[ENTER]Jagt Bera for at f\229 dem. "
gameforge.new_quest_lv28._035_target = "Yang-Shin: "
gameforge.new_quest_lv28._036_say = "Du har fundet den \248nskede Bj\248rne-klo. Tag det til[ENTER]Yang-Shin for at betale Ah-Yu's g\230ld. "
gameforge.new_quest_lv28._037_say = "Yang-Shin er i %s. "
gameforge.new_quest_lv28._038_say_title = "Yang-Shin: "
gameforge.new_quest_lv28._040_npcChat = "Afpresning "
gameforge.new_quest_lv28._041_say_title = "Bj\248rne-klo "
gameforge.new_quest_lv28._042_say = "Du har bragt mig nogle Bj\248rne-klo? V\230r venlig[ENTER]ikke at t\230nke d\229rligt om mig! Vi lever i h\229rde[ENTER]tider, og jeg er n\248dt til at f\229 enderne til at[ENTER]m\248des, nu hvor vildtet er s\229 vanskelig, og da[ENTER]Metin Stene har vendte dyr til morderiske b\230ster.[ENTER]Livet som j\230ger har aldrig v\230ret s\229 farlig. "
gameforge.new_quest_lv28._043_say = "Fort\230l det til Ah-Yu, at hun ikke har noget at[ENTER]bekymre sig om. Hun kan regne med det. I hvert[ENTER]fald indtil jeg har brug for noget igen...[ENTER]hehehe! "
gameforge.new_quest_lv28._044_say = "Hvad, \248nsker du at spise mig af uden bytte? Jeg[ENTER]\248nskede friske Bj\248rne-klo! "
gameforge.new_quest_lv28._045_say_reward = "Det er p\230nt af dig at hj\230lpe Ah-Yu. Men det[ENTER]betyder ogs\229, at du er n\248dt til at g\248re, hvad jeg[ENTER]siger. Nu g\229 p\229 jagt og kom ikke tilbage f\248r du[ENTER]har to stykker Bj\248rne-klo! "
gameforge.new_quest_lv28._046_say = "Giv Ah-Yu budskabet om, at Yang-Shin vil stoppe[ENTER]med at afpresning hende, fordi du hjalp ham. "
gameforge.new_quest_lv28._051_say = "Du er vores frelser! Jeg er uendeligt[ENTER]taknemmelig. Her, tag alle mine Yang. Det er ikke[ENTER]meget, men du fortjener det. "
gameforge.new_quest_lv28._055_1_select = "Tak, det vil v\230re meget nyttigt! "
gameforge.new_quest_lv28._055_2_select = "Nej, jeg kan ikke acceptere dette. "
gameforge.new_quest_lv28._056_say = "Dette er alt, hvad jeg har. Men det er det v\230rd,[ENTER]hvis jeg kan slippe af med denne barbariske[ENTER]halspine. "
gameforge.new_quest_lv28._057_say = "\197h, tak! Din plads ved Drage Gud`ens side er[ENTER]garanteret! "
gameforge.new_quest_lv28._058_say_reward = "Du har modtaget %s Yang. "
gameforge.new_quest_lv28._059_say_reward = "Du har modtaget %s erfaringspoint. "
gameforge.new_quest_lv28._070_say = "Jeg beh\248ver: "
gameforge.new_quest_lv29 = {}
gameforge.new_quest_lv29._010_target = "Yonah: "
gameforge.new_quest_lv29._015_npcChat = "Det \248delagte porcel\230n "
gameforge.new_quest_lv29._020_say_title = "Yonah: "
gameforge.new_quest_lv29._021_say = "Mit elskede Celadon Porcel\230n! Det har v\230ret i min[ENTER]familie i tre generationer, og nu er tre af de[ENTER]\230dle vaser i stykker. Jeg s\229, at den luskebuks[ENTER]til Taurean hang omkring lageret tidligere. Jeg[ENTER]er sikker p\229 at det er hans skyld! "
gameforge.new_quest_lv29._022_say = "Det ville ikke v\230re den f\248rste t\229belige ting han[ENTER]har gjort, men det er virkelig at overskride[ENTER]gr\230nsen. Nogen b\248r give ham en l\230restreg![ENTER]Har du tid til at g\248re det? "
gameforge.new_quest_lv29._023_1_select = "Med gl\230de "
gameforge.new_quest_lv29._023_2_select = "Dette kommer ikke mig ved "
gameforge.new_quest_lv29._024_say = "Jeg har ikke tid til at opdrage onde b\248rn.[ENTER]Du bliver n\248dt til at fange ham selv. Men jeg[ENTER]tvivl p\229 om at du kan klarer det... "
gameforge.new_quest_lv29._030_target = "Taurean: "
gameforge.new_quest_lv29._031_say = "Yonah`s dyrebare familie arvestykker, tre vaser[ENTER]lavet af Celadon porcel\230n, er alle i stykker. Han[ENTER]mener, at Taurean har skylden. G\229 til Taurean og[ENTER]find ud af det. "
gameforge.new_quest_lv29._032_say = "Taurean er i %s. "
gameforge.new_quest_lv29._033_say_title = "Taurean: "
gameforge.new_quest_lv29._034_say_reward = "Hvad kigger du p\229 mig for? Jeg har ikke gjort[ENTER]noget ... "
gameforge.new_quest_lv29._035_say_reward = "Hvad har du gjort med Yonah`s vaser? "
gameforge.new_quest_lv29._036_say_reward = "Vaser? Yonah? Jeg ved bare ikke, hvad du taler om! "
gameforge.new_quest_lv29._037_say_reward = "S\229 v\230r venlig at forklare mig igen, hvorfor tre[ENTER]af dem er itu. "
gameforge.new_quest_lv29._038_say_reward = "Jeg sv\230rger, at jeg ikke har v\230ret i n\230rheden af[ENTER]en vase nogen steder i dag, og jeg har heller[ENTER]ikke set Yonah's i dag. I virkeligheden,[ENTER]tilbragte jeg hele dagen med at sl\229se med Harang.[ENTER]Hun l\229set mig enda inde i laden for en tid! G\229 ud[ENTER]og sp\248rg hende, hvis du ikke tror mig! "
gameforge.new_quest_lv29._040_target = "Harang: "
gameforge.new_quest_lv29._041_say = "Taurean h\230vder, at han er uskyldig. Han spillede[ENTER]med Harang hele dagen og kunne ikke have sl\229et[ENTER]vaser itu. G\229 til Harang og sp\248rge, om det er[ENTER]sandt. "
gameforge.new_quest_lv29._042_say_reward = "Harang, har du set Taurean for nylig? "
gameforge.new_quest_lv29._043_say_title = "Harang: "
gameforge.new_quest_lv29._044_say_reward = "Taurean? Ja, vi spillede hele dagen. Er der noget[ENTER]galt? "
gameforge.new_quest_lv29._045_say_reward = "Yonah sagde, at Taurean \248delagde tre af hans[ENTER]vaser. "
gameforge.new_quest_lv29._046_say_reward = "Yonah er ond. Han jager Taurean og mig v\230k s\229[ENTER]snart vi kommer i n\230rheden af ham. Han er altid[ENTER]s\229 bekymret for hans porcel\230n. Den eneste person[ENTER]der er tilladt at r\248re ved hans dyrebare vaser er[ENTER]hans ven Stald drengen. M\229ske han \248delagde dem?! "
gameforge.new_quest_lv29._047_say = "Harang er i %s. "
gameforge.new_quest_lv29._050_target = "Stald-kn\230gt: "
gameforge.new_quest_lv29._051_say = "Harang bekr\230ftet, at Taurean er uskyldig. Men de[ENTER]kan ogs\229 v\230re i ledtog med hinanden.[ENTER]F\248r du g\248re afsiger din dom b\248r du sp\248rge Yonah's[ENTER]ven Stald Drengen. "
gameforge.new_quest_lv29._052_say = "\197h, gode gamle Yonah. S\229 bekymret for hans[ENTER]porcel\230n, at han bebrejder landsbyen b\248rn.[ENTER]Han er ikke klar over, at Metin stenene har[ENTER]skylden - lige siden de startede med at forgifte[ENTER]vores land har vores ressourcer ikke v\230ret det de[ENTER]plejede at v\230re. Selv porcel\230n er begyndt at[ENTER]smuldre. Men Yonah n\230gter bare at tro det... "
gameforge.new_quest_lv29._053_say = "Hvis du har samlet noget H\248 for ham, kan han[ENTER]fordel porcel\230nen i hans kasser en lille smule[ENTER]bedre. Jeg er sikker p\229 det ville v\230re en god[ENTER]m\229de at formilde ham. "
gameforge.new_quest_lv29._054_say = "Stald-dreng er i[ENTER]%s eller i %s. "
gameforge.new_quest_lv29._061_say = "Taurean er naturligvis ikke skyld i Yonah`s itu[ENTER]sl\229ede vaser. Det er den onde str\229ling fra Metin[ENTER]stenene, der g\248r alt spr\248dt.[ENTER]Saml H\248 for Yonah, s\229 han kan gemme sit porcel\230n[ENTER]bedre! Jeg er sikker p\229, at nogle af[ENTER]Landsbyboerne kan give dig nogle. "
gameforge.new_quest_lv29._062_say = "Du kan finde %s og %s foran portene til[ENTER]landsbyen. Du burde v\230re i stand til at f\229 en[ENTER]anst\230ndig m\230ngden H\248 ud af str\229hatte, de havde[ENTER]p\229. "
gameforge.new_quest_lv29._063_notice = "Jeg f\229r et dejlig bundt H\248 ud af dette. Nu[ENTER]mangler jeg bare en anden %s. "
gameforge.new_quest_lv29._064_notice = "Denne hat er ikke lavet af str\229, men fra kokos[ENTER]fibre. Det nytter ikke for mig. "
gameforge.new_quest_lv29._065_1_say = "Jeg kan se at du har en masse H\248 med jer. Jeg er[ENTER]sikker p\229 at Yonah vil v\230re beroliget, hvis du[ENTER]giver ham noget af det. "
gameforge.new_quest_lv29._065_notice = "Denne hat er ikke lavet af str\229, men af kokos[ENTER]fibre. Den er ogs\229 helt \248delagt... "
gameforge.new_quest_lv29._066_say = "Du kan ogs\229 jage Vild infanterist eller Stor vild[ENTER]infanterist. Du kan f\229 H\248 fra deres str\229hatte. "
gameforge.new_quest_lv29._067_say_reward = "Du har samlet %s af %s bundter H\248. "
gameforge.new_quest_lv29._068_notice = "Du har jagtet et bundt H\248. "
gameforge.new_quest_lv29._070_npcChat = "H\248stakken "
gameforge.new_quest_lv29._071_say_reward = "Taurean, du n\230vnte tidligere, at du var i[ENTER]h\248stakken tidligere. Har du tilf\230ldigvis taget[ENTER]noget H\248 med dig? "
gameforge.new_quest_lv29._072_say_reward = "Haha, lad os se ... det var alt i mit h\229r og i[ENTER]mine sko. Kan du se den? Her er nogle flere, tage[ENTER]det! "
gameforge.new_quest_lv29._073_notice = "Det er ikke meget H\248, men det burde v\230re nok til[ENTER]et lille bundt. Nu mangler jeg bare %s mere. "
gameforge.new_quest_lv29._074_say_reward = "Det var ikke mig, jeg sv\230rger! Har Harang ikke[ENTER]fortalt dig at vi havde en kamp i den h\248stak? "
gameforge.new_quest_lv29._075_say_reward = "Du var ude i h\248stakken tidligere, var du ikke?[ENTER]Har du tilf\230ldigvis taget noget H\248 med dig der[ENTER]fra? "
gameforge.new_quest_lv29._076_say_reward = "Hvordan kan du vide noget om den h\248stak?[ENTER]Hvad, har jeg stadig H\248 i mit t\248j? \197h ja, her er[ENTER]noget! "
gameforge.new_quest_lv29._077_say_reward = "Kan jeg f\229 det? "
gameforge.new_quest_lv29._078_say_reward = "Jeg formoder det... "
gameforge.new_quest_lv29._079_say_reward = "Jeg har ikke tid lige nu. Jeg har brug for at g\229[ENTER]ud og berolige Taurean med det hele om de vaser! "
gameforge.new_quest_lv29._080_npcChat = "H\248 til Yonah "
gameforge.new_quest_lv29._081_say_reward = "Er der mere H\248 rundt omkring i stalden, jeg kunne[ENTER]bringe til Yonah? "
gameforge.new_quest_lv29._082_say_title = "Stald-kn\230gt: "
gameforge.new_quest_lv29._083_say_reward = "Vi har ikke meget H\248. De vilde dyr og banditter[ENTER]uden for landsbyen har forhindret os i at sk\230re[ENTER]noget mere af det. "
gameforge.new_quest_lv29._084_say_reward = "Men jeg kan give dig en lille smule! "
gameforge.new_quest_lv29._085_notice = "Det er virkelig ikke s\229 meget, men i det mindste[ENTER]er nok til et bundt. Nu mangler jeg bare en anden[ENTER]%s mere. "
gameforge.new_quest_lv29._086_say_reward = "Jeg er bange for at jeg ikke kan g\248re andet for[ENTER]dig. "
gameforge.new_quest_lv29._090_send_letter = "H\248 i stedet for slag "
gameforge.new_quest_lv29._091_say = "Du har samlet nok H\248 for Yonah. Tag det til %s. "
gameforge.new_quest_lv29._101_say_reward = "Det er ikke Taurean skyld. Str\229lingen fra de[ENTER]Metin Sten har gjort porcel\230n sk\248rt. "
gameforge.new_quest_lv29._102_say_title = "Yonah: "
gameforge.new_quest_lv29._103_say_reward = "Hvad sagde du? Det er fuldst\230ndig nonsens, den[ENTER]luskebuks har l\248jet for dig! "
gameforge.new_quest_lv29._104_say_reward = "Taurean spillede i h\248stakken med Harang hele[ENTER]dagen. "
gameforge.new_quest_lv29._105_say_reward = "Jeg skulle sende dig de bedste \248nsker fra din ven[ENTER]Stald Drengen og jeg har ogs\229 bragt dig noget H\248[ENTER]til at hj\230lpe dig med at beskytte din vaser. "
gameforge.new_quest_lv29._106_say_reward = "Jeg indr\248mmer, jeg er lidt flov over min[ENTER]reaktion. Men du skal vide, at jeg er meget[ENTER]knyttet til mit porcel\230n, fordi det bringer gode[ENTER]minder tilbage fra min familie. N\229r en vase g\229r i[ENTER]stykker, er det mere end blot et tabt objekt for[ENTER]mig... "
gameforge.new_quest_lv29._107_say_reward = "Jeg er n\248dt til at undskylde over for dig og[ENTER]Taurean. Her er en lille bel\248nning for din[ENTER]indsats. "
gameforge.new_quest_lv29._108_notice = "Du har modtaget %s erfaringspoint. "
gameforge.new_quest_lv29._109_say_reward = "Jeg skulle sende dig de bedste \248nsker fra din ven[ENTER]Stald Drengen og jeg har ogs\229 bragt dig noget H\248[ENTER]til at hj\230lpe dig med at beskytte din vaser. "
gameforge.new_quest_lv29._110_say_reward = "Det er meget p\230nt af dig, men kan du hente mig en[ENTER]anden %s bundter af H\248, s\229 mine vaser er virkelig[ENTER]sikker? "
gameforge.new_quest_lv29._111_say_reward = "Jeg tror, det vil v\230re sv\230rt at finde mere H\248.[ENTER]Men mine vaser er n\230sten hellige for mig. Jeg[ENTER]ville v\230re utrolig taknemmelig, hvis du fik fat i[ENTER]nogle til mig, og jeg vil ogs\229 give dig nogle[ENTER]Yang for det. "
gameforge.new_quest_lv29._112_say_reward = "Den m\248gunge Harang er naturligvis i ledtog med[ENTER]Taurean. "
gameforge.new_quest_lv29._113_say_reward = "Tilsyneladende tror ingen p\229 mig, n\229r jeg siger,[ENTER]at jeg s\229 drengen h\230ngende rundt p\229 lageret[ENTER]tidligere. "
gameforge.new_quest_lv29._114_say_reward = "Det er okay. Her er en vis kompensation for din[ENTER]indsats. "
gameforge.new_quest_lv29._115_say_reward = "Her, %s Yang. "
gameforge.new_quest_lv42 = {}
gameforge.new_quest_lv42._010_send_letter = "Knurre Knurre "
gameforge.new_quest_lv42._020_target = "Octavio: "
gameforge.new_quest_lv42._021_say = "Min mave rumler som et vildsvin. M\229ske jeg skulle[ENTER]bes\248ge Octavio. Han laver den bedste skaldyr[ENTER]ragout her i omegnen. "
gameforge.new_quest_lv42._022_say_title = "Octavio: "
gameforge.new_quest_lv42._023_say = "Vil du have noget skaldyr ragout? Den med alle[ENTER]hoveder i? \197h, det er jeg ked af, mit k\248kken har[ENTER]ikke set nogle fisk i flere dage. Normalt leverer[ENTER]fiskeren en fantastisk dybhavsfisk til min[ENTER]gryderet. "
gameforge.new_quest_lv42._024_say = "Godt han har ikke v\230ret her i dagevis. Kunne du[ENTER]m\229ske g\229 hen og sp\248rge ham, hvad der sker? "
gameforge.new_quest_lv42._025_say = "Octavio er i %s. "
gameforge.new_quest_lv42._026_select = "Jeg er taget afsted for at finde fiskeren! "
gameforge.new_quest_lv42._030_target = "Fisker: "
gameforge.new_quest_lv42._031_say = "De ubekymrede dage p\229 havet er over! Fiskere[ENTER]forsvinde hver dag, det er forf\230rdeligt! Siden de[ENTER]Metin sten blev kastet i havet, dengang s\229[ENTER]fredelige hvaler har forvandlet sig til brutale[ENTER]s\248uhyrer. Fiskeri er blevet en farlig handel. "
gameforge.new_quest_lv42._032_say = "Vores spyd kan ikke skade hvalerne mere. Deres[ENTER]hud er h\229rdere end Ork hud! "
gameforge.new_quest_lv42._033_say = "M\229ske Yonah ved, hvad de skal g\248re. Han plejede[ENTER]at g\229 til havet ganske ofte og jager hvaler hvert[ENTER]\229r. "
gameforge.new_quest_lv42._034_say_title = "Fisker: "
gameforge.new_quest_lv42._035_say = "Octavio venter p\229 hans dybhavsfisk. Sp\248rg[ENTER]Fiskeren hvorfor leverancen er forsinket. "
gameforge.new_quest_lv42._036_say = "Fisker er i %s. "
gameforge.new_quest_lv42._037_send_letter = "Rasende Hav Monster "
gameforge.new_quest_lv42._038_say = "Fiskeren har bedt dig om at bede Yonah til r\229d[ENTER]om, hvordan de jager de onde hvaler. "
gameforge.new_quest_lv42._039_say = "Yonah er i %s. "
gameforge.new_quest_lv42._040_target = "Yonah: "
gameforge.new_quest_lv42._041_say = "Jeg har h\248rt om hvad der er sket med hvalerne.[ENTER]Det er en d\229rlig forretning for fiskerne. Selv[ENTER]hvis de t\248r at vove sig ud p\229 havet, er deres[ENTER]spyd bare for svage til at tr\230nge igennem[ENTER]hvalhud. Da jeg arbejdede p\229 en hvalfanger,[ENTER]brugte vi specielle v\229ben til hvaler med gamle og[ENTER]arret hud. De var i stand til at tr\230nge gennem[ENTER]alt... "
gameforge.new_quest_lv42._042_say = "Det er en speciel teknik til at h\230rde hval fanger[ENTER]spyd. Den eneste person, der kan lave denne type[ENTER]spyd er en Smed. "
gameforge.new_quest_lv42._043_say_reward = "G\229 til smeden "
gameforge.new_quest_lv42._044_say_title = "Yonah: "
gameforge.new_quest_lv42._045_say = "Yonah anbefaler at vi bruge meget robuste og[ENTER]skarpe spyd til hval jagt. G\229 til Smeden og[ENTER]sp\248rge ham, om han kan lave nogle af disse spyd. "
gameforge.new_quest_lv42._050_target = "Smed "
gameforge.new_quest_lv42._051_say = "Ja, jeg har h\248rt om de spyd og jeg kan ogs\229 lave[ENTER]dem. Men, for at de kan f\229 den n\248dvendige[ENTER]holdbarhed, skal jeg bruge en Diamant Sten. "
gameforge.new_quest_lv42._052_say = "Jeg beh\248ver: "
gameforge.new_quest_lv42._053_say_reward = "Proces: "
gameforge.new_quest_lv42._054_say_title = "Smed "
gameforge.new_quest_lv42._060_set_title = "Diamantsten "
gameforge.new_quest_lv42._061_notice = "Lad os se. Jeg har brug for en hakke til mine[ENTER]sten. Jeg spekulerer p\229, om min er her omkring et[ENTER]sted eller hvorvidt Deokbae er n\248dt til at skaffe[ENTER]mig en ny? "
gameforge.new_quest_lv42._062_say = "Du har brug for %s x Diamantsten "
gameforge.new_quest_lv42._063_say = "Du har alt, hvad du beh\248ver. G\229 nu hurtigt[ENTER]tilbage til Smeden. "
gameforge.new_quest_lv42._064_say = "Godt, nu har jeg f\229et alt, hvad jeg har brug for.[ENTER]Kom tilbage p\229 samme tid i morgen for at afhente[ENTER]spydene. Jern som dette, skal forarbejdes[ENTER]omhyggeligt. "
gameforge.new_quest_lv42._065_say = "Du kan f\229 en Diamantsten ved at hakke p\229 en[ENTER]Diamant-\229re med en hakke. "
gameforge.new_quest_lv42._066_say = "Smeden har brug for en Diamant Sten for at lave[ENTER]et s\230rlige spyd til hval jagt. Kig efter \229re af[ENTER]Diamant, s\229 du kan f\229 mine Diamant Sten.[ENTER]Hvis du ikke har en hakke til minedrift, du kan[ENTER]k\248be en hos Deokbae. "
gameforge.new_quest_lv42._067_say = "Smeden er i %s. "
gameforge.new_quest_lv42._068_say = "Vi har brug for en anden %s x Diamant Sten, f\248r[ENTER]vi kan p\229begynde arbejdet p\229 spydet. "
gameforge.new_quest_lv42._070_set_title = "Spydet "
gameforge.new_quest_lv42._071_set_clock = "Ventetid "
gameforge.new_quest_lv42._072_say = "Smeden skulle v\230re f\230rdig nu. G\229 til ham og[ENTER]afhent det s\230rlige spyd til jagt p\229 hvaler. "
gameforge.new_quest_lv42._073_say = "De Spyd er ikke f\230rdig endnu. Du skal v\230re lidt[ENTER]mere t\229lmodig. "
gameforge.new_quest_lv42._074_say = "Her er dine spyd. Tag dem til Fiskeren. "
gameforge.new_quest_lv42._075_say = "Jeg har allerede bedt dig om at vente, indtil[ENTER]spydet er f\230rdig. Kom tilbage senere. "
gameforge.new_quest_lv42._079_say = "Du har modtaget nogle Hval Spyd fra Smeden. Tag[ENTER]dem til Fiskeren. "
gameforge.new_quest_lv42._080_say = "Godt! Disse spyd er virkelig imponerende! Vi kan[ENTER]beskytte os mod hval angreb nu. Venligst lad[ENTER]Octavio vide, at han vil have frisk fisk igen[ENTER]snart! "
gameforge.new_quest_lv42._081_say_reward = "Du har modtaget 500,000 Yang. "
gameforge.new_quest_lv42._082_say_reward = "Som en s\230rlig anerkendelse, har du modtaget 3x: "
gameforge.new_quest_lv42._083_say = "Der er ikke nok spyd til at drive en hval v\230k.[ENTER]Der er kun lige nok til at kildre deres k\248d. "
gameforge.new_quest_lv42._084_say_reward = "G\229 venligst tilbage til Smeden igen og f\229 ham til[ENTER]at lave nogle flere spyd. "
gameforge.new_quest_lv42._090_say = "Fiskerne er godt udstyret og kan g\229 p\229 jagt i det[ENTER]\229bne hav igen nu. G\229 til Octavio og fors\248ge at[ENTER]forsikre ham om, at han vil f\229 en ny leverance[ENTER]snart. "
gameforge.new_quest_lv42._095_say = "Hvad sagde du? Fredelig hvaler er blevet[ENTER]aggressive s\248uhyrer? Det er forf\230rdeligt ...[ENTER]Tak fordi du hjalp fiskerne. En stor del af min[ENTER]menu er afh\230ngige af deres leverancer. "
gameforge.new_quest_lv42._096_say = "\197h, og om din rumlende mave: Selvf\248lgelig kan jeg[ENTER]tilbyde dig fisk og skaldyr ragout, men vil du[ENTER]ikke foretr\230kker noget sushi? "
gameforge.new_quest_lv42._098_say_reward = "Du har modtaget 750,000 erfaringspoint.[ENTER]Du har modtaget 2 stykker Sushi. "
gameforge.new_quest_lv43 = {}
gameforge.new_quest_lv43._005_send_letter = "Bes\248g Wonda-Rim "
gameforge.new_quest_lv43._006_send_letter = "Den for\230ldrel\248se "
gameforge.new_quest_lv43._010_target = "Wonda-Rim: "
gameforge.new_quest_lv43._011_say = "Du har ikke h\248rt fra Wonda-Rim fornylig. Hans[ENTER]forhold til sin onkel er forbedret nu, og de kan[ENTER]have glemt hele episode med Mu-Rang pelsen nu.[ENTER]Hvorfor g\229r du ikke ud og bes\248ger ham. "
gameforge.new_quest_lv43._012_say = "Wonda-Rim er i %s. "
gameforge.new_quest_lv43._020_say = "Det er p\230nt af dig at komme forbi. "
gameforge.new_quest_lv43._021_say_title = "Wonda-Rim: "
gameforge.new_quest_lv43._022_say = "Jeg blev opdraget af min onkel Chaegirab. Vi har[ENTER]altid haft et godt forhold ... men n\229r jeg[ENTER]sp\248rger ham om mine for\230ldre, undg\229r han[ENTER]sp\248rgsm\229let. De er d\248de, men det er alt, hvad han[ENTER]vil fort\230lle mig. "
gameforge.new_quest_lv43._023_say_reward = "Jeg \248nsker at blive gift og stifte familie en[ENTER]dag, s\229 jeg burde egentlig vide, hvor jeg kom[ENTER]fra. Kunne du tale med min onkel og bede ham om[ENTER]at fort\230lle om mine for\230ldre? Men du m\229 ikke[ENTER]fort\230lle ham, at jeg sendte dig. "
gameforge.new_quest_lv43._024_select = "Jeg vil tale med ham! "
gameforge.new_quest_lv43._025_say = "Wonda-Rim er ikke Chaegirab biologiske nev\248, han[ENTER]er bare opdraget af ham. Nu er det tid for ham at[ENTER]finde ud af, hvem hans rigtige for\230ldre er. Sp\248rg[ENTER]Chaegirab om Wonda-Rim's afstamning. "
gameforge.new_quest_lv43._026_say = "Chaegirab er i %s. "
gameforge.new_quest_lv43._030_target = "Chaegirab: "
gameforge.new_quest_lv43._031_say_title = "Chaegirab: "
gameforge.new_quest_lv43._032_say = "Wonda-Rim ... nej, jeg er ikke hans biologiske[ENTER]onkel. Jeg ved ikke hvem hans for\230ldre er. Jeg[ENTER]har sk\230rmet ham fra sandheden s\229 l\230nge, fordi jeg[ENTER]ikke troede han var parat til at f\229 det at vide.[ENTER]Men m\229ske er tiden endelig kommet. "
gameforge.new_quest_lv43._033_say = "Jeg fandt ham med en horde af Ork Krigere i[ENTER]Seungryong Dalen. Hvis der stadig er en m\229de at[ENTER]finde ud af om Wonda-Rim's afstamning, b\248r du[ENTER]kunne finde det ved Ork Krigere. "
gameforge.new_quest_lv43._034_say = "Jeg kan v\230re streng ved ham, men jeg vil altid[ENTER]v\230re hans onkel. Selv om han forbliver et skvat. "
gameforge.new_quest_lv43._035_say_reward = "G\229 til Seungryong Dalen og jagt Ork Krigere[ENTER]indtil du finder et bevis om Wonda-Rim's[ENTER]herkomst. "
gameforge.new_quest_lv43._036_say = "Du har opdaget et gammelt brev i en sl\229et Ork -[ENTER]kriger`s beskidte taske. Det er n\230sten umuligt at[ENTER]tyde, men du kan genkende navnet Wonda- Rim p\229[ENTER]den. Dette er de beviser du leder efter, s\229 g\229 og[ENTER]tag det til Wonda-Rim. "
gameforge.new_quest_lv43._041_say = "Lad os g\229! Den bedste chance har du for at finde[ENTER]ud af noget om Wonda-Rim`s afstamning er ved at[ENTER]dr\230be Ork Krigere. De kunne have nogle beviser! "
gameforge.new_quest_lv43._043_notice = "Fingerpeg om Wonda-Rim... "
gameforge.new_quest_lv43._045_say = "Jeg har fortalt dig alt hvad jeg ved. Det eneste[ENTER]fingerpeg vi har, er de Ork Krigere. Men desv\230rre[ENTER]kan du ikke have en anst\230ndig samtale med dem... "
gameforge.new_quest_lv43._049_say = "Et brev? Lad os se ... Disse tegn er virkelig[ENTER]sv\230re til l\230se ... Det handler om en razzia,[ENTER]tilsyneladende br\230ndte Orkerne deres g\229rd ned, og[ENTER]de m\229tte l\248be for deres liv. De m\229tte efterlade[ENTER]deres barn der ... Og her er et navn. "
gameforge.new_quest_lv43._050_say = "Tak for at bringe mig det. Nu ved jeg endelig,[ENTER]hvad der skete. "
gameforge.new_quest_lv43._051_say = "Jeg skulle tale med Chaegirab. Han gik \229benbart[ENTER]gennem en masse besv\230r for at redde mig. Jeg har[ENTER]t\230nkt mig at pr\248ve at blive en bedre nev\248 for[ENTER]ham. P\229 gensyn, min ven! "
gameforge.new_quest_lv43._052_say_title = "Information: "
gameforge.new_quest_lv43._053_say_reward = "Du har modtaget 32,000 Yang. "
gameforge.new_quest_lv43._054_say_reward = "Du har modtaget 1,250,000 erfaringspoint. "
gameforge.new_quest_lv43._060_say = "Har du talt med min onkel Chaegirab? Et hint?[ENTER]Hvad snakker du om? Hvis du ikke har noget at[ENTER]vise, s\229 skal du holde igen med at g\230tte![ENTER][ENTER]Sp\248rg min onkel igen. Efter alt, s\229 betaler jeg[ENTER]dig for det. "
gameforge.new_quest_lv52 = {}
gameforge.new_quest_lv52._010_send_letter = "Brev fra Kaptajnen "
gameforge.new_quest_lv52._020_say_title = "Loyale landsmand "
gameforge.new_quest_lv52._021_say_reward = "Jeg vil gerne have, at du g\248r mig en tjeneste.[ENTER]Jeg kan ikke sove mere, og p\229 trods af Baek- G\229's[ENTER]medicin, har jeg bare brugt hele natten p\229 at[ENTER]vende og dreje mig. Kunne du se efter ham og[ENTER]sp\248rg om en st\230rkere sove medicin? "
gameforge.new_quest_lv52._022_say = "Baek-Go er i %s. "
gameforge.new_quest_lv52._030_set_title = "En god nats s\248vn "
gameforge.new_quest_lv52._035_target = "Baek-Go: "
gameforge.new_quest_lv52._040_say = "Kaptajnen har et problemer med at sove. G\229 til[ENTER]Baek-Go, og bede ham om en st\230rkere sovepiller[ENTER]til Kaptajn. "
gameforge.new_quest_lv52._041_say = "Sove medicin til Kaptajnen? Jeg er bange for at[ENTER]jeg ikke har noget st\230rkere at give dig.[ENTER]Dog kunne Yu-Hwan lave noget p\229 et[ENTER]naturl\230gemiddel basis, som ville give dig de[ENTER]\248nskede resultater. "
gameforge.new_quest_lv52._042_say = "Ah, du fik mit brev. for jeg ved ikke, hvad jeg[ENTER]skal g\248re mere, for kan bare ikke f\229 en god nats[ENTER]s\248vn. Kan du hj\230lpe mig og sp\248rge Baek-Go for at[ENTER]f\229 et r\229d. "
gameforge.new_quest_lv52._042_select = "S\229 er det bedre at jeg g\229r til Yu-Hwan! "
gameforge.new_quest_lv52._043_say = "Baek-Go er i %s. "
gameforge.new_quest_lv52._044_say_title = "Baek-Go: "
gameforge.new_quest_lv52._045_say = "Yu-Hwan er i %s. "
gameforge.new_quest_lv52._046_say = "S\229 g\229 til Kaptajnen og fort\230l ham, at du ikke kan[ENTER]hj\230lpe ham. "
gameforge.new_quest_lv52._049_say_title = "Yu-Hwan: "
gameforge.new_quest_lv52._050_target = "Yu-Hwan: "
gameforge.new_quest_lv52._051_say = "Baek-Go havde ikke noget st\230rkere medicin[ENTER]tilbage. Yu-Hwan kunne m\229ske hj\230lpe selv, hvis[ENTER]han kender til en urt, der har den \248nskede[ENTER]virkning. "
gameforge.new_quest_lv52._052_say = "For jeg kender Kaptajnen godt. Som du m\229ske[ENTER]allerede ved, har jeg v\230ret p\229 hemmelige[ENTER]missioner for ham i temmelig lang tid. Men jeg[ENTER]kan fort\230lle dig nu, at urter vil ikke l\248se hans[ENTER]problemer. "
gameforge.new_quest_lv52._053_say = "Der er en anden grund til, at Kaptajnen ikke kan[ENTER]sove mere. Og tro mig, han ved pr\230cis hvad[ENTER]\229rsagen er. Men det er noget, han m\229 finde ud af,[ENTER]af sig selv, og jeg kan ikke g\248re det for ham. G\229[ENTER]og se ham og sp\248rg om det. "
gameforge.new_quest_lv52._054_say_title = "Kaptajn "
gameforge.new_quest_lv52._055_say_reward = "Ah, du fik mit brev. Jeg ved bare ikke hvad jeg[ENTER]skal g\248re mere. V\230r venlig at g\229 og sp\248rge[ENTER]Baek-G\229 om hans r\229d, s\229 jeg endelig kan f\229 en god[ENTER]nats hvile igen. "
gameforge.new_quest_lv52._055_select = "Ja Herre! "
gameforge.new_quest_lv52._056_say = "Tak! "
gameforge.new_quest_lv52._056_say_reward = "Jeg har allerede set ham, og han har ingen[ENTER]st\230rkere medicin p\229 lager. Men jeg har t\230nkt mig[ENTER]at kigge efter Yu-Hwan og sp\248rge ham, om han ikke[ENTER]kan hj\230lpe dig. "
gameforge.new_quest_lv52._060_target = "Kaptajn "
gameforge.new_quest_lv52._061_say = "Yu-Hwan \248nsker ikke at blabre om nogen andres[ENTER]hemmeligheder, s\229 det er nok noget ganske[ENTER]ubehageligt. Men det er ikke til nogen nytte, du[ENTER]burde tale med kaptajnen om det.[ENTER]Hvis vi ikke ved, hvad \229rsagen er, s\229 kan vi ikke[ENTER]l\248se hans s\248vn problemer. S\229 g\229 til %s. "
gameforge.new_quest_lv52._062_say_reward = "Der er ingen st\230rkere sove medicin til r\229dighed.[ENTER]Men Kaptajn, m\229ske kan jeg hj\230lpe dig hvis jeg[ENTER]fandt ud af \229rsagen til din s\248vnl\248shed. "
gameforge.new_quest_lv52._063_say_reward = "Det er ikke noget, jeg vil fort\230lle en ung mand[ENTER]som dig. "
gameforge.new_quest_lv52._064_say_reward = "Det er ikke noget, jeg vil fort\230lle en ung kvinde[ENTER]som dig. "
gameforge.new_quest_lv52._065_say_reward = "Men hvis jeg ikke kan f\229 en god nats s\248vn snart,[ENTER]s\229 bliver jeg sk\248r. Jeg formoder, jeg er n\248dt til[ENTER]at ...[ENTER]Men husk, at det er kun for dine \248rer: jeg er[ENTER]hjems\248gt af fire sp\248gelser hver nat. Men det er[ENTER]ikke det v\230rste ... jeg er ansvarlig for deres[ENTER]d\248d. "
gameforge.new_quest_lv52._066_say_reward = "De er fire soldater. De siger, at de var[ENTER]tortureret og dr\230bt af M\248rk plage\229nd og M\248rk[ENTER]besv\230rger i Seungryong Dalen. Jeg var den, der[ENTER]beordrede dem til at g\229 der - jeg har sendt dem[ENTER]lige i D\248den! "
gameforge.new_quest_lv52._067_say_reward = "Hvad kan vi g\248re ved den slags sp\248gelser? "
gameforge.new_quest_lv52._068_say_reward = "De \248nsker h\230vn! Hvad skal jeg g\248re? Hvis jeg[ENTER]tager afsted og s\248ger h\230vn, vil landsbyen st\229[ENTER]uden lederskab og vil blive overvundet. Og hvis[ENTER]jeg ikke tager afsted, vil jeg g\229 amok. "
gameforge.new_quest_lv52._069_say_reward = "Hvis jeg ikke havde ansvaret for landsbyens[ENTER]sikkerhed ville jeg straks g\229. Jeg kan kun se en[ENTER]vej ud: "
gameforge.new_quest_lv52._070_say_reward = "En eller anden vil s\248ge h\230vn p\229 mine vejne![ENTER]Men hvordan kan jeg sende flere m\230nd ind i dalen[ENTER]og risikere velvidende at det kunne sende dem mod[ENTER]deres egen ruin!?[ENTER]Det kan jeg ikke sp\248rge en anden om bare for min[ENTER]natte s\248vns skyld? "
gameforge.new_quest_lv52._071_say_reward = "En beslutning som den er ikke let. "
gameforge.new_quest_lv52._080_1_select = "Den gode i landsbyen... "
gameforge.new_quest_lv52._080_2_select = "Det bliver ikke let... "
gameforge.new_quest_lv52._080_3_select = "Du kan ikke forvente noget! "
gameforge.new_quest_lv52._081_say_reward = "... vejer tungere end din fejhed. Jeg vil h\230vne[ENTER]dine m\230nd. Og hvis jeg ikke kommer tilbage, vil[ENTER]jeg se dig i aften! "
gameforge.new_quest_lv52._082_say_reward = "...besk\230ftiger sig med disse M\248rk plage\229nd og[ENTER]M\248rk besv\230rger.[ENTER]Men du vil sove godt i aften, jeg lover! "
gameforge.new_quest_lv52._083_say_reward = "Har du et d\248ds\248nske? Det er s\229 farligt at bek\230mpe[ENTER]M\248rk plage\229nd og M\248rk besv\230rger. Pr\248v at fort\230lle[ENTER]disse sp\248gelser hvor meget der er brug for dig[ENTER]her! "
gameforge.new_quest_lv52._084_say_reward = "Du har ret. Men jeg h\229bede stadig, at du[ENTER]frivilligt vil p\229tage dig det, du g\248r b\229de mig og[ENTER]min landsby en stor tjeneste. "
gameforge.new_quest_lv52._090_1_select = "Godt... "
gameforge.new_quest_lv52._090_2_select = "Nej, jeg vil ikke klare det! "
gameforge.new_quest_lv52._091_say_reward = "...hvis jeg er dit sidste h\229b, s\229 vil jeg fjerne[ENTER]disse M\248rk plage\229nd og M\248rk besv\230rger for dig! "
gameforge.new_quest_lv52._092_say_reward = "Hvis jeg pr\248ver det, vil et andet sp\248gelse finde[ENTER]dig. "
gameforge.new_quest_lv52._093_say_reward = "OK. Jamen s\229 lad mig give dig nogle Yang for din[ENTER]indsats. "
gameforge.new_quest_lv52._093_say_reward_exp = "Du har modtaget 20,000 erfaringspoint. "
gameforge.new_quest_lv52._093_say_reward_gold = "Du f\229r 25.000 Yang "
gameforge.new_quest_lv52._100_notice = "Samtalen er blevet afsluttet. "
gameforge.new_quest_lv52._110_say_reward = "Jeg h\229bede du ville sige det. Men jeg ved[ENTER]desv\230rre ikke, hvilke M\248rk besv\230rger eller M\248rk[ENTER]plage\229nd der dr\230bte dem. Jeg h\229ber, at jeg vil[ENTER]f\248le det, n\229r en af de sp\248gelser er frigivet. "
gameforge.new_quest_lv52._111_say_reward = "Jeg sender dig et brev. Sp\248gelserne fortalte mig,[ENTER]at h\230vnen er n\248dt til at finde sted i Drage[ENTER]Guden's Triangle. Der er tre s\248jler der, der[ENTER]danner hj\248rnerne i trekanten. "
gameforge.new_quest_lv52._120_set_title = "H\230vn 4 af de faldne "
gameforge.new_quest_lv52._125_say_title = "Brev fra Kaptajnen "
gameforge.new_quest_lv52._130_say_reward = "Der er yderligere 3 soldater at h\230vne! "
gameforge.new_quest_lv52._131_say = "Du ser ud til at det var en succes. Jeg har lige[ENTER]h\248rt stemmen fra en af mine faldne soldater.[ENTER]Sagde han at han tilgiver mig nu, for at hans d\248d[ENTER]er blevet h\230vnet. Og det er takket v\230re dig! "
gameforge.new_quest_lv52._132_say = "H\230vn venligst ogs\229 de andre faldne soldater og[ENTER]dr\230be M\248rk plage\229nd, M\248rk besv\230rger, H\248j plage\229nd[ENTER]og H\248j besv\230rger. Husk, at du kan kun frigive dem[ENTER]i trekanten af tre store Drage Gud`s s\248jler. "
gameforge.new_quest_lv52._140_say_reward = "Yderligere 2 soldater at h\230vne! "
gameforge.new_quest_lv52._141_say = "Du har elimineret en mere af mine soldater's[ENTER]Mordere! I den halve lys s\229 jeg en falden soldat[ENTER]holder sin h\229nd i en salut. "
gameforge.new_quest_lv52._150_say_reward = "Der er en soldat tilbage at h\230vne! "
gameforge.new_quest_lv52._151_say = "Du er utrolig! En falden soldat's sp\248gelse stod[ENTER]her ved siden af mig bare for et minut siden, og[ENTER]han b\248d mig farvel. Det vil nok v\230re ganske[ENTER]vanskeligt at finde den sidste morderen. "
gameforge.new_quest_lv52._160_say = "De sp\248gelser, der har plaget kaptajnen er de unge[ENTER]soldater, der faldt i l\248bet af hans mission. De[ENTER]blev dr\230bt af M\248rk plage\229nder, M\248rk besv\230rger,[ENTER]H\248j plage\229nder og H\248j besv\230rger. "
gameforge.new_quest_lv52._161_say = "Du er n\248dt til at fjerne den ansvarlige M\248rk[ENTER]besv\230rger og M\248rk plage\229nd i trekanten af Drage[ENTER]Gudens tre s\248jler for at h\230vne soldaterne. "
gameforge.new_quest_lv52._162_say = "Drage Gudens trekant er i midten af Seungryong[ENTER]Dalen. "
gameforge.new_quest_lv52._170_send_letter = "F\248rste soldat h\230vnet "
gameforge.new_quest_lv52._171_send_letter = "Anden soldat h\230vnet "
gameforge.new_quest_lv52._172_send_letter = "Tredje soldat h\230vnet "
gameforge.new_quest_lv52._173_send_letter = "Alle soldaterne er h\230vnet "
gameforge.new_quest_lv52._180_say_reward = "Du har h\230vnet alle 4 soldater! "
gameforge.new_quest_lv52._181_say = "Du har fundet den sidste morder! Den sidste af de[ENTER]fire faldne soldater dukkede bare op og bad mig[ENTER]om at takke for dit mod. Han efterlod noget her[ENTER]for dig: %s. "
gameforge.new_quest_lv52._182_say = "Kom og se mig for at f\229 din bel\248nning. Jeg venter[ENTER]p\229 dig i %s. "
gameforge.new_quest_lv52._183_say_reward = "Du har gjort mig og min landsby en stor tjeneste.[ENTER]Her er den bel\248nning, som sp\248gelset gav mig til[ENTER]dig: %s "
gameforge.new_quest_lv52._184_say_reward = "Og her er nogle Yang fra mig. Jeg har t\230nkt mig[ENTER]at g\229 p\229 pension nu og endelig f\229 noget s\248vn. "
gameforge.new_quest_lv52._185_say_reward = "Jeg st\229r dig i stor g\230ld, min s\248n. "
gameforge.new_quest_lv52._186_say_reward = "Jeg st\229r i g\230ld til dig for altid. "
gameforge.new_quest_lv52._190_say_title = "Information: "
gameforge.new_quest_lv52._191_say_reward = "Du har modtaget 3,300,000 erfaringspoint.[ENTER]Du har modtaget 270,000 Yang.[ENTER]Du har modtaget en f\230rdighedsmanual Bog. "
gameforge.new_quest_lv52._85_say = "S\229 m\229ske senere? G\229 venligst til Baek-Go, n\229r du[ENTER]g\248r! "
gameforge.new_quest_lv54 = {}
gameforge.new_quest_lv54._010_target = "Kaptajn "
gameforge.new_quest_lv54._020_say_title = "De friske forsyninger "
gameforge.new_quest_lv54._030_say = "Det er sv\230rt at f\229 vores tropper motiveret i[ENTER]\248jebliket, is\230r fordi det er s\229 sv\230rt at f\229[ENTER]friske forsyninger. Handelsdame, en vigtig[ENTER]leverand\248r for os, har kun sendt os en lille[ENTER]m\230ngde af de eliksir, vi har brug for. "
gameforge.new_quest_lv54._031_say_reward = "Venligst g\229 til Handelsdameen og find ud af, hvad[ENTER]problemet er. "
gameforge.new_quest_lv54._032_select = "Jeg vil give dig de eliksirer! "
gameforge.new_quest_lv54._040_say_title = "Handelsdame: "
gameforge.new_quest_lv54._040_set_title = "Friske forsyninger "
gameforge.new_quest_lv54._050_target = "Handelsdame: "
gameforge.new_quest_lv54._051_say = "Ja, at f\229 friske forsyninger har v\230ret rigtig[ENTER]vanskeligt for nylig. Handels ruterne er blevet[ENTER]ganske usikre og landevejsr\248vere og vilde dyr[ENTER]bliver ved med at dukke op. Den Rejsende[ENTER]Handelsmand, fra hvem jeg f\229r mine varer, har[ENTER]ikke en chance mod de tigre. "
gameforge.new_quest_lv54._052_say = "M\229ske kan Kaptajnen og hans soldater hj\230lpe.[ENTER]G\229 venligst til ham og sp\248rge ham, om han ikke[ENTER]kan sende sine soldater der for at beskytte de[ENTER]handlende. "
gameforge.new_quest_lv54._054_say = "G\229 til Handelsdameen og find ud af hvorfor der er[ENTER]forsinkelse p\229 friske eliksir forsyninger. "
gameforge.new_quest_lv54._055_say = "Handelsdame er i %s. "
gameforge.new_quest_lv54._056_say_title = "Kaptajn "
gameforge.new_quest_lv54._060_say = "Sikre handels ruterne? Ja ... det ville jeg gerne[ENTER]g\248re. Men jeg har bare ikke soldater nok til at[ENTER]beskytte De Rejsende Handelsm\230nd fra alle andre[ENTER]kongeriger. "
gameforge.new_quest_lv54._061_say = "Endvidere m\229 vi soldater ikke jage tigre.[ENTER]Kun j\230gerne fra j\230gernes orden har lov til at[ENTER]g\248re det. Det ville ikke g\248re landsbyen noget[ENTER]godt at kr\230nke disse forskrifter. "
gameforge.new_quest_lv54._062_say_reward = "Du b\248r derfor tale med Yang-Shin. Han er medlem[ENTER]af j\230gerens orden. M\229ske kan han hj\230lper dig med[ENTER]at f\229 problemerne med tigre under kontrol. "
gameforge.new_quest_lv54._064_say = "G\229 til kaptajnen og fors\248g at overbevise ham om[ENTER]at sikre handelsruterne mod tigre. "
gameforge.new_quest_lv54._065_say = "Kaptajn er i %s. "
gameforge.new_quest_lv54._070_target = "Yang-Shin: "
gameforge.new_quest_lv54._071_say = "Masser af mine j\230gere blev indrulleret som[ENTER]krigere og faldt under krigen. Nu er det blevet[ENTER]n\230sten umuligt at holde bestanden af vilde dyr[ENTER]afbalanceret. De vilde katte er et s\230rligt[ENTER]problem da de udvider deres territorium og er til[ENTER]fare for rejsende. "
gameforge.new_quest_lv54._072_say = "Hvis du hj\230lper os med dette her kan jeg tilbyde[ENTER]dig dette v\230rdifuld Tiger Skjold +3, det har til[ENTER]h\248rt min d\248de kammerat Mi-Song, som en bel\248nning.[ENTER]For at f\229 det b\248r du reducere tigeren befolkning[ENTER]kraftig. "
gameforge.new_quest_lv54._073_say = "Is\230r Forbandet hvid tiger har formeret sig[ENTER]ukontrolleret. "
gameforge.new_quest_lv54._074_say = "Som bevis, har jeg brug for: "
gameforge.new_quest_lv54._075_say = "Du skal jagte: "
gameforge.new_quest_lv54._076_say = "Kig efter Yang-Shin og fors\248g at overbevis ham om[ENTER]at sikre handelsruterne mod tigre. "
gameforge.new_quest_lv54._077_say_title = "Yang-Shin: "
gameforge.new_quest_lv54._078_say = "Yang-Shin er i %s. "
gameforge.new_quest_lv54._080_set_title = "Tiger pels "
gameforge.new_quest_lv54._081_notice = "Ah, den er glimrende. Bare %s flere af dem! "
gameforge.new_quest_lv54._082_notice = "F\230rdig! Nu g\229 hurtigt tilbage til Yang-Shin. "
gameforge.new_quest_lv54._083_notice = "Denne tiger pels er ubrugelig. "
gameforge.new_quest_lv54._084_say = "Du skal bare have %s x Skinnende tigerskind. "
gameforge.new_quest_lv54._085_say = "Jagt Skinnende tigerskind fra Forbandet hvid[ENTER]tiger. "
gameforge.new_quest_lv54._090_npcChat = "Jeg har f\229et tiger pels. "
gameforge.new_quest_lv54._091_say = "Det er langtfra nok for mig. Hvordan skal jeg[ENTER]finde ud af p\229 grundlag af disse f\229 skind, om[ENTER]Gaderne er sikre igen? "
gameforge.new_quest_lv54._092_say = "Ahh endelig! Disse pelse vil bringe mig en stor[ENTER]profit ... er! Du er her stadig? Takke v\230re dig[ENTER]er vejene endelig sikre igen! Jeg er sikker p\229 at[ENTER]Kaptajnen vil give dig en smuk bel\248nning. "
gameforge.new_quest_lv54._093_say = "Og nu g\229 v\230k. Jeg har brug for at rense pelsen. "
gameforge.new_quest_lv54._094_say = "\197h, har kaptajnen ikke givet dig en bel\248nning?[ENTER]Det er ikke mit problem. Og i tilf\230lde af at du[ENTER]fors\248ger at t\248mme mig for pelse: Glem det, jeg[ENTER]kommer ikke til at skille mig af med dem! "
gameforge.new_quest_lv54._095_say_reward = "Men jeg har lovet dig et skjold, og du skal have[ENTER]et. Denne beskidte gamle ting er ikke til nogen[ENTER]nytte for mig mere alligevel. "
gameforge.new_quest_lv54._096_say = "Bel\248nning: "
gameforge.new_quest_lv54._097_say_reward = "Du har modtaget et Tiger Skjold +3. "
gameforge.new_quest_lv54._098_say = "Du \248nsker at spise mig af med et par pelse? P\229[ENTER]den m\229de har jeg min g\230ld ... Jeg mener at p\229 den[ENTER]m\229de, bliver gaderne aldrig sikker nok! "
gameforge.new_quest_lv54._099_say_reward = "G\229 p\229 jagt, indtil du har samlet %s pels! "
gameforge.new_quest_lv54._100_say = "Det var alt, nu g\229 hurtigt tilbage til Yang-Shin. "
gameforge.new_quest_lv54._101_say_reward = "Du har modtaget 3,750,000 erfaringspoint. "
gameforge.new_quest_lv54._102_say_reward = "Du har modtaget 125,000 Yang. "
gameforge.new_quest_lv7 = {}
gameforge.new_quest_lv7._010_target = "Octavio: "
gameforge.new_quest_lv7._011_say_title = "Octavio: "
gameforge.new_quest_lv7._012_say_title = "Gammel dame "
gameforge.new_quest_lv7._020_say_title = "Datterens bryllup "
gameforge.new_quest_lv7._021_say = "Har du nogen b\248rn? S\229 vil du sikkert forst\229 mine[ENTER]bekymringer ... det handler om min datter![ENTER]Hun har m\248dt en mand, der helt har fordrejet[ENTER]hendes hoved. Og nu er hun flygtet til et andet[ENTER]kongerige med sin k\230reste. "
gameforge.new_quest_lv7._022_say = "Han er fra Chunjo. Selvf\248lgelig var jeg imod det![ENTER]Jeg t\230nkte at en dame fra Shinsoo ikke kan gifte[ENTER]sig med en spirituel dr\248mmer fra Chunjo. Vi[ENTER]skiltes efter et sk\230nderi, hun flygtede med ham[ENTER]til Chunjo. "
gameforge.new_quest_lv7._023_say = "Han er fra Jinno. Selvf\248lgelig var jeg imod det![ENTER]Jeg t\230nkte at en dame fra Chunjo ikke kan gifte[ENTER]sig med en brutal mand fra Jinno. Vi skiltes[ENTER]efter et sk\230nderi, hun flygtede med ham til[ENTER]Jinno. "
gameforge.new_quest_lv7._024_say = "Han er fra Shinsoo. Selvf\248lgelig var jeg imod[ENTER]det! Jeg t\230nkte at en dame fra Jinno ikke kan[ENTER]gifte sig med en sv\230kling uden penge fra Shinsoo.[ENTER]Vi skiltes efter et sk\230nderi, hun flygtede med[ENTER]ham til Shinsoo. "
gameforge.new_quest_lv7._030_say = "Jeg h\248rte, at hun \248nsker at gifte sig med ham der. "
gameforge.new_quest_lv7._031_say = "Min datter venter p\229 et tegn fra mig.[ENTER]Hvad skal jeg g\248re? Hun er mit eneste barn![ENTER]Selvf\248lgelig har jeg t\230nkt mig at give hende min[ENTER]velsignelse. G\229 venligst til den gamle dame for[ENTER]mig, og bed hende om at hj\230lpe med[ENTER]forberedelserne. "
gameforge.new_quest_lv7._040_target = "Gammel dame "
gameforge.new_quest_lv7._041_say = "Kig efter den gamle dame og bed hende om at lave[ENTER]bryllups forberedelser. "
gameforge.new_quest_lv7._042_say = "Gammel dame er i %s. "
gameforge.new_quest_lv7._051_say = "Et bryllup, siger du? N\229, det er et vigtig[ENTER]\248jeblik i en kvindes liv. Alt skal v\230re rigtigt,[ENTER]lige fra brudekjolen og gommen`s smoking til[ENTER]forlovelsesringene, som efter ceremonien bliver[ENTER]til vielsesringe. N\229r brudens far har givet sit[ENTER]samtykke, og de n\248dvendige Yang til ceremonien er[ENTER]blevet udbetalt, kan festen arrangeres. "
gameforge.new_quest_lv7._052_say = "Blomsterne er s\230rdeles vigtige - intet bryllup[ENTER]kan finde sted uden en brudebuket gommen giver[ENTER]sin elskede. Buketten b\248r have f\248lgende blomster: "
gameforge.new_quest_lv7._054_say = "Jeg beh\248ver: "
gameforge.new_quest_lv7._055_say = "Du skal jagte: "
gameforge.new_quest_lv7._056_say = "Jeg har stadig brug for: "
gameforge.new_quest_lv7._060_say = "Kom tilbage til mig, n\229r du har f\229et alle tre[ENTER]blomster. Jeg vil kontrollere, om de er friske[ENTER]nok, og vil derefter lave en p\230n buket. Derefter[ENTER]kan du tage den til min s\248ster. Hun vil foretage[ENTER]ceremonien. "
gameforge.new_quest_lv7._081_say = "Saml en blomst af hver slags. Du f\229r dem ved at[ENTER]dr\230be Sulten alpha-ulve, Sulten bl\229ulve og Sulten[ENTER]alpha-bl\229ulve. "
gameforge.new_quest_lv7._082_say = "Denne visne blomst er ikke s\230rlig dekorative. Alt[ENTER]dette arbejde og intet at vise frem! "
gameforge.new_quest_lv7._083_say = "Denne visne blomst er ikke s\230rlig dekorative. Alt[ENTER]dette arbejde og intet at vise frem! "
gameforge.new_quest_lv7._084_say = "Denne visne blomst er ikke s\230rlig dekorative. Alt[ENTER]dette arbejde og intet at vise frem! "
gameforge.new_quest_lv7._085_1_say_reward = "Du mangler %s Blodr\248d blomst. Du kan f\229 dem ved[ENTER]at dr\230be Sultne Alpha Ulve. "
gameforge.new_quest_lv7._085_2_say_reward = "Du mangler %s Orangefarvet blomst. Du kan f\229 dem[ENTER]ved at dr\230be Sulten bl\229ulve. "
gameforge.new_quest_lv7._085_3_say_reward = "Du mangler stadig %s Duftende gul blomst.[ENTER]Du kan f\229 dem ved at dr\230be nogle Sulten[ENTER]alpha-bl\229ulve. "
gameforge.new_quest_lv7._085_say_reward = "Du mangler stadig %s Blodr\248d blomst. "
gameforge.new_quest_lv7._086_say_reward = "Du mangler stadig %s Orange-Farvet blomst. "
gameforge.new_quest_lv7._087_say_reward = "Du mangler %s Duftende gul blomst. "
gameforge.new_quest_lv7._088_notice = "Denne blomst er glimrende. Very nice! "
gameforge.new_quest_lv7._089_notice = "Denne blomst er glimrende. Very nice! "
gameforge.new_quest_lv7._090_notice = "Denne blomst er glimrende. Very nice! "
gameforge.new_quest_lv7._091_say = "F\230rdig! Disse blomster udg\248r en dejlig buket.[ENTER]G\229 nu tilbage til den gamle dame hurtigt, inden[ENTER]blomsterhovederne begynder at h\230nge! "
gameforge.new_quest_lv7._092_say = "Saml blomster til en bryllups buket. "
gameforge.new_quest_lv7._110_say = "Det er smukke blomster, men de er bare ikke[ENTER]specielle nok til s\229dan et stort bryllup. "
gameforge.new_quest_lv7._111_say = "Du kan f\229 dem ved at dr\230be Sulten alpha-ulve,[ENTER]Sulten bl\229ulve og Sulten alpha-bl\229ulve. "
gameforge.new_quest_lv7._112_say = "Disse blomster skulle blive en smuk buket. "
gameforge.new_quest_lv7._115_say = "Tak, det ser flot ud! Her, tag denne buket af[ENTER]blomster og g\229 til min s\248ster med den. "
gameforge.new_quest_lv7._116_say_reward = "Du kan finde hende i Bokjung, et omr\229de af Chunjo[ENTER]Riget. "
gameforge.new_quest_lv7._117_say_reward = "Du kan finde hende i Bakra, et omr\229de af Jinno[ENTER]Riget. "
gameforge.new_quest_lv7._118_say_reward = "Du kan finde hende i Yayang, et omr\229de af Shinsoo[ENTER]Kongeriget. "
gameforge.new_quest_lv7._120_set_title = "S\248ster "
gameforge.new_quest_lv7._125_notice = "Dette er det rigtige rige, s\229 burde jeg v\230re i[ENTER]stand til at finde den gamle dame`s s\248ster her. "
gameforge.new_quest_lv7._129_say = "Dette er det rigtige rige, s\229 skal jeg bare finde[ENTER]Octavio her. "
gameforge.new_quest_lv7._130_say = "Dette synes at v\230re det rette rige. Nu kigger vi[ENTER]efter den gamle dame's s\248ster. "
gameforge.new_quest_lv7._131_say = "Der ser ikke ud til at v\230re det rette rige. "
gameforge.new_quest_lv7._132_say_reward = "Du er n\248dt til at g\229 til Bokjung, et omr\229de af[ENTER]Chunjo Riget. "
gameforge.new_quest_lv7._133_say_reward = "Du er n\248dt til at g\229 til Bakra, et omr\229de af[ENTER]Jinno Riget. "
gameforge.new_quest_lv7._134_say_reward = "Du er n\248dt til at g\229 til Yayang, et omr\229de af[ENTER]Shinsoo Riget. "
gameforge.new_quest_lv7._135_say = "G\229 tilbage til Octavio i Yongan i Shinsoo Riget. "
gameforge.new_quest_lv7._136_say = "G\229 tilbage til Octavio i Joan i Chunjo Riget. "
gameforge.new_quest_lv7._137_say = "G\229 tilbage til Octavio i Pyungmoo i Jinno Riget. "
gameforge.new_quest_lv7._140_say = "Her er blomster til Octavio's datters forest\229ende[ENTER]bryllup. De skal afleveres til Bruden med en[ENTER]velsignelse. Hun vil vide, hvem de er fra. "
gameforge.new_quest_lv7._141_say = "Det er smukke blomster! De vil f\229 Bruden til at[ENTER]gl\248de. Dette afslutter forberedelserne.[ENTER]Fort\230l til Octavio, at han er inviteret til[ENTER]Vielsen. Jeg ved, at han vil blive glad for det. "
gameforge.new_quest_lv7._142_say = "Nu ud og find Octavio, hvad venter du p\229? "
gameforge.new_quest_lv7._143_say = "Du har bragt blomster til Octavio's datters[ENTER]bryllup? Hvor p\230nt af dig! Men ... hvor er de?[ENTER]Har du mister dem p\229 din vej hertil?. "
gameforge.new_quest_lv7._144_say_reward = "G\229 tilbage til dit rige og f\229 en ny buket[ENTER]blomster til brylluppet. "
gameforge.new_quest_lv7._145_say = "G\229 til den gamle dame`s s\248ster f\248r blomsterne[ENTER]visne v\230k. "
gameforge.new_quest_lv7._150_say = "Hvorfor stinker du af Tyrefr\248 suppe? Ah ja, det[ENTER]er faktisk ligegyldigt, s\229 l\230nge du har gode[ENTER]nyheder. "
gameforge.new_quest_lv7._151_say = "Jeg kan ikke takke dig nok. Jeg er s\229 glad for,[ENTER]at Jeg komme med til min datters bryllup! "
gameforge.new_quest_lv7._152_say = "Her, tag din bel\248nning: "
gameforge.new_quest_lv7._153_say_reward = "Et v\229ben smedet for h\229nden af en kampsports[ENTER]mester. Pas godt p\229 det! "
gameforge.new_quest_lv7._154_say_reward = "Du har modtaget %s erfaringspoint. "
gameforge.new_quest_lv7._155_say_reward = "Du har modtaget %s Yang. "
gameforge.new_quest_lv7._160_say = "Du forveksler mig \229benbart med en fjern[ENTER]sl\230gtning. Jeg har ikke en datter og har ikke nok[ENTER]Yang til at kunne arrangere et bryllup. "
gameforge.new_quest_lv7._165_say = "Vil du pr\248ve en skefuld af min Tyrefr\248 suppe?[ENTER]Jeg brugte en gammel opskrift fra min Tante. "
gameforge.new_quest_lv75 = {}
gameforge.new_quest_lv75._010_target = "Heuk-Young: "
gameforge.new_quest_lv75._020_set_title = "Den legendariskes dagbog "
gameforge.new_quest_lv75._021_say = "Jeg har fundet disse kriger rester. Jeg ved ikke[ENTER]om det er den Sura som Heuk-Young leder efter,[ENTER]men jeg er sikker p\229 at hun er interesseret i[ENTER]dem. "
gameforge.new_quest_lv75._022_say = "Ikke bare en Sura d\248de her. Jeg har set deres[ENTER]rester. Jeg spekulerer p\229 om den legendariske[ENTER]kriger ogs\229 er blandt dem? Jeg b\248r rapportere[ENTER]tilbage til Heuk-Young ang\229ende dette. "
gameforge.new_quest_lv75._023_say = "Jeg har fundet et stykke papir, fastfrosset i den[ENTER]underjordiske Is-Golem. Jeg kan knapt l\230se det,[ENTER]men det kunne v\230re en ledetr\229d der interesserer[ENTER]Heuk-Young. "
gameforge.new_quest_lv75._024_say = "Jeg har fundet en del ting der m\229ske interesserer[ENTER]Heuk-Young. Jeg b\248r g\229 til hende og give hende[ENTER]det stykke papir. S\229 kan jeg ogs\229 fort\230lle hende[ENTER]om liget. "
gameforge.new_quest_lv75._025_say = "Heuk-Young har bedt mig om at holde \248je med alle[ENTER]spor der omhandler den legendariske Sura.[ENTER]Desv\230rre har jeg ingen anelse om hvad jeg leder[ENTER]efter... "
gameforge.new_quest_lv75._030_say = "Led efter den legendariske k\230mper Akuma. Han var[ENTER]den mest ber\248mte Sura der nogensinde har levet -[ENTER]en n\230sten us\229rlig kriger. Rygtet har det at han[ENTER]engang udfordrede kejseren. Jeg tror at det her[ENTER]er stedet hvor Akuma forsvandt, flere hundrede \229r[ENTER]siden. V\230r s\229 venlig og hold \248je med spor der kan[ENTER]fort\230lle os hvor han var. "
gameforge.new_quest_lv75._040_say = "dummy "
gameforge.new_quest_lv75._050_npcChat = "Unders\248g faldne krigere "
gameforge.new_quest_lv75._060_say = "Det ligner resterne af en kriger. Den venstre arm[ENTER]ligner dog ikke et menneskes... Det m\229 have v\230ret[ENTER]en Sura. Jeg skal fort\230lle Heuk-Young om dette. "
gameforge.new_quest_lv75._070_notice = "En bogside.. Indfrosset i resterne af en[ENTER]underjordisk Is-Golem... "
gameforge.new_quest_lv75._090_say = "Jeg kan ikke fort\230lle dig pr\230cis hvad vi leder[ENTER]efter. Bare se dig omkring og kom tilbage n\229r du[ENTER]finder noget. "
gameforge.new_quest_lv75._100_say = "Hvad har du der? Lad mig se! "
gameforge.new_quest_lv75._105_say = "Et papir... Hvad er det for en skrift? Det m\229[ENTER]v\230re ret s\229 gammelt. Du har m\229ske fundet noget[ENTER]vigtigt. De ting der er skrevet her p\229 ser[ENTER]bekendte ud. Det ser ud som om siden engang var[ENTER]en del af en bog. "
gameforge.new_quest_lv75._109_say = "Hvis vi kunne finde nogle flere sider, s\229 ville[ENTER]det hele give mere mening. Led efter flere[ENTER]ledetr\229de! "
gameforge.new_quest_lv75._110_say = "Der er du jo igen. Har du fundet noget? Fort\230l! "
gameforge.new_quest_lv75._115_say = "En d\248d Sura... Det kunne v\230re ham, eller bare en[ENTER]af hans tilh\230ngere. Men vi skal bruge flere[ENTER]beviser for at v\230re sikker. Led efter beviser p\229[ENTER]hvem det kunne v\230re. V\229ben, smykker, eller m\229ske[ENTER]noter eller noget i den retning. "
gameforge.new_quest_lv75._120_say = "Skelettet af en Sura og en bogside? Lad mig se[ENTER]pergamentet... Hmm, du har m\229ske fundet Akumas[ENTER]rester. Men, vi skal bruge flere beviser. Pr\248v at[ENTER]finde nogle flere bogsider. "
gameforge.new_quest_lv75._130_say = "Jeg har fundet nogle beviser, men jeg er ikke[ENTER]sikker p\229 om den legendariske Sura virkelig var[ENTER]her eller ej. Jeg skal bruge mere information. "
gameforge.new_quest_lv75._140_1_select = "Godt "
gameforge.new_quest_lv75._140_2_select = "Is kreatur "
gameforge.new_quest_lv75._140_3_select = "P\229 fortvivlelsens rand "
gameforge.new_quest_lv75._140_4_select = "M\248rk terror "
gameforge.new_quest_lv75._140_5_select = "D\248dens ansigt "
gameforge.new_quest_lv75._140_6_select = "Krigerens sk\230bne "
gameforge.new_quest_lv75._140_7_select = "Nej, jeg er ikke interesseret. "
gameforge.new_quest_lv75._150_say = "Jeg kan kun afkode dele af s\230tningerne. De[ENTER]fort\230ller noget om h\248viske liv og en stor[ENTER]k\230rlighed til eventyr... "
gameforge.new_quest_lv75._160_1_say = "Skriften p\229 det gule pergament er falmet og[ENTER]rystet, som var det skrevet af en meget gammel[ENTER]eller meget svag person: \"...Is kreaturer. Selv[ENTER]mine Sura evner hjalp mig ikke til at besejre dem[ENTER]alle. Nogle af dem vandrer stadig i grotterne og[ENTER]jeg skal v\230re ekstra forsigtig i tilf\230lde af at[ENTER]de finder mig. Indtil for nylig tilb\248d de mig[ENTER]beskyttelse, men nu...\" Derefter er der ikke mere[ENTER]tekst tilbage. "
gameforge.new_quest_lv75._160_2_say = "Denne side er ogs\229 meget slidt. Ud fra datoen der[ENTER]er i toppen i hj\248rnet kan du genkende det der[ENTER]ligner en slags dagbog: \"Det er ikke den f\248rste[ENTER]gang jeg opf\248rte mig anderledes mens jeg ledte[ENTER]efter grotten. Jeg var s\229 stolt og tilfreds med[ENTER]mig selv! Alle disse ting har ledt mig til min[ENTER]sikre d\248d...\" Det sidste ord er understreget[ENTER]kraftigt. "
gameforge.new_quest_lv75._160_3_say = "Pergament siden er meget skadet, stykker af den[ENTER]ser ud til at v\230re fl\229et ud. Du kan kun afkode[ENTER]dele af beskeden: \"... Kejserens hof... da de[ENTER]l\230rde l\230rte mig alt jeg s\229 desperat \248nskede at[ENTER]vide... nem \229bning til portalen, men... d\248d og[ENTER]terror i m\248rket...\" En stor takket rift[ENTER]forhindrer dig i at kunne l\230se resten. "
gameforge.new_quest_lv75._160_4_say = "Du finder en skitse p\229 denne side af pergamentet:[ENTER]Det er et billede af en kvindes ansigt. Under det[ENTER]st\229r der nogle ord skrevet i teksten som du[ENTER]allerede er bekendt med. Men skriften ser usikker[ENTER]og rystet ud: \"D\248den har dens kl\248er fremme - Jeg[ENTER]fandt ud af dette i g\229r. Jeg tog kun et enkelt[ENTER]hurtigt kig p\229 monsteret inden frygten tog over[ENTER]og jeg blev n\248dt til at tr\230kke mig tilbage. Oh[ENTER]min k\230re Sunmi, hvis jeg bare havde vidst! Hvis[ENTER]jeg kendte til den ubeskrivelige r\230dsel noget[ENTER]f\248r, s\229 var jeg aldrig g\229et ned p\229 dette niveau!\" "
gameforge.new_quest_lv75._160_5_say = "Under Hee-Se dynastiet levede der en legendarisk[ENTER]Sura kaldet Akuma. Han var s\229 talentfuld i kamp[ENTER]at han knapt kunne finde en v\230rdig modstander til[ENTER]at teste sin styrke imod. En dag fandt han nogle[ENTER]noter om et mystisk sted, der for l\230nge siden[ENTER]blev forseglet, og han besluttede sig for at[ENTER]bruge alt sin tid p\229 at finde dette sted. Han[ENTER]fandt endda ud af hvordan man finder portaler og[ENTER]hvordan man \229bner dem. Han lovede at komme[ENTER]tilbage til hans elsker Sunmi s\229 snart hans[ENTER]gerninger var overst\229et... Men han vendte aldrig[ENTER]tilbage. "
gameforge.new_quest_lv75._170_say = "Skriften lader til at v\230re antik... Den er ogs\229[ENTER]meget rystet og ulige, som om forfatteren ikke[ENTER]havde megen styrke tilbage... "
gameforge.new_quest_lv75._171_say = "Det giver ikke mening. Vi skal bruge flere sider. "
gameforge.new_quest_lv75._172_say = "Jeg begynder at forst\229 hvad der m\229ske skete her.[ENTER]Men der er stadig meget jeg ikke er sikker p\229. "
gameforge.new_quest_lv75._173_say = "Har du lyst til at h\248re detaljerne? "
gameforge.new_quest_lv75._174_say = "Endnu en side! Hvem der end skrev disse ting m\229[ENTER]have v\230ret fuldst\230ndig desperat. Skal jeg[ENTER]opsummere hvad det siger? "
gameforge.new_quest_lv75._175_say = "Nogle sider er i s\229 d\229rlig en tilstand at jeg kun[ENTER]kan g\230tte hvad der st\229r. Men, jeg begynder at[ENTER]forst\229 hvad der skete i denne grotte for s\229 mange[ENTER]\229r tilbage. "
gameforge.new_quest_lv75._176_say = "Ikke meget mangler. Vil du vide hvad jeg har[ENTER]fundet? "
gameforge.new_quest_lv75._177_say = "Det lader til at der ikke mangler mange sider[ENTER]igen. "
gameforge.new_quest_lv75._178_say = "Vil du vide hvad jeg har fundet ud af? "
gameforge.new_quest_lv75._180_notice = "Jeg har fundet den sidste side ved de[ENTER]underjordiske Is-Golemmer. "
gameforge.new_quest_lv75._185_send_letter = "Det skulle v\230re alle siderne! "
gameforge.new_quest_lv75._190_notice = "Jeg fandt denne side hos de underjordiske Is-[ENTER]Golemmer. "
gameforge.new_quest_lv75._195_send_letter = "Jeg har fundet en side! "
gameforge.new_quest_lv75._200_npcChat = "Unders\248g faldne krigere "
gameforge.new_quest_lv75._210_say = "Der ligger 3 sider af det skr\248belige pergament[ENTER]ved de meneskelige skeletter. De takkede sider[ENTER]indikerer at der er blevet revet ud af en bog.[ENTER]Skriften p\229 siden er udtv\230ret og sv\230r at l\230se. "
gameforge.new_quest_lv75._220_say = "Jeg tror at dette her er nok. Jeg tager det til[ENTER]Heuk-Young. "
gameforge.new_quest_lv75._230_say = "Gad vide hvem disse jordiske rester tilh\248rer? En[ENTER]ting er sikkert, han havde ikke noget p\229 sig der[ENTER]stadig kan bruges i dag. "
gameforge.new_quest_lv75._240_send_letter = "Jeg har siderne! "
gameforge.new_quest_lv75._250_say = "Jeg b\248r g\229 tilbage til Heuk-Young. M\229ske kan hun[ENTER]l\248se puslespillet. "
gameforge.new_quest_lv75._270_say = "Jeg er overrasket over at du har fundet s\229 mange[ENTER]ting i de grotter. Disse sider ligner noget der[ENTER]har v\230ret en del af en bog. De ting der st\229r[ENTER]skrevet her er meget interessante. Det giver alt[ENTER]sammen mening n\229r jeg t\230nker p\229 de andre[ENTER]historier jeg har h\248rt... Hvis du giver mig de[ENTER]sider, s\229 binder jeg dem og laver dem til en bog.[ENTER]M\229ske kan det blive nyttigt n\229r du g\229r til[ENTER]Forbandelsens grotte. Hvis den ikke er nyttig for[ENTER]dig, s\229 er jeg sikker p\229 at du finder nogen der[ENTER]vil k\248be den af dig. "
gameforge.new_quest_lv75._280_say = "Jeg har bundet siderne ind til en bog og tilf\248jet[ENTER]nogle af mine noter. M\229ske kan du bruge dem.[ENTER]Jeg fort\230ller dig resten af historien hvis du vil. "
gameforge.new_quest_lv75._290_1_select = "Ja, fort\230l mig mere! "
gameforge.new_quest_lv75._290_2_select = "Nej, jeg er ikke interesseret i det! "
gameforge.new_quest_lv75._310_say = "Hvad vil du fra mig? Kan du ikke se at jeg l\230ser? "
gameforge.new_quest_lv75._320_say = "Soon: "
gameforge.new_quest_lv75._330_say = "Det er en meget interessant bog du har der.[ENTER]Hvor er den fra? Kan jeg se den? "
gameforge.new_quest_lv75._340_say = "Dette er noterne fra Forbandelsens grotte, ikke?[ENTER]De ser gamle ud. Skriften er us\230dvanlig og[ENTER]stavelsen er meget gammeldags... Det m\229 have[ENTER]v\230ret h\229rdt arbejde at f\229 fat i en bog som denne.[ENTER]Selvf\248lgelig vil jeg gerne have fat i den.[ENTER]Er du m\229ske interesseret i at s\230lge den? "
