gameforge.new_quest_premium_lv4._300_say = "Jeg skal tage noget moskus olie til[ENTER]v\229ben-handelsmanden. Jeg skal lede mig selv til[ENTER]den roterende m\248nt, bestille en anderledes[ENTER]duftende olie og hente det ved lagerforvalteren. "
