gameforge.new_quest_premium_lv4._55_qSetTitle = "Tilbage til v\229ben-handelsmanden "
gameforge.new_quest_premium_lv4._60_sayTitle = "Slynglen "
gameforge.new_quest_premium_lv4._65_qSetTitle = "Tag moskus olien til v\229ben-handelsmanden "
gameforge.new_quest_premium_lv4._70_say = "Det er rigtigt, jeg har ikke sunget under hendes[ENTER]vindue l\230ngere fordi.. Oh, alts\229, det er s\229[ENTER]pinligt at snakke om! Min krops lugt er ret[ENTER]frast\248dende. Jeg vasker mig selv hele tiden, men[ENTER]lugten forsvinder bare ikke. Det er derfor jeg[ENTER]vil producere en duftende olie der kan henrykke[ENTER]handelsdamen, min lille sangfugl, med dens skarpe[ENTER]og fascinerende lugt. Hun l\230gger stor v\230gt p\229 det[ENTER]fysiske udsende. "
