gameforge.notify_test_server = {}
gameforge.notify_test_server._10_chat = "Testserver "
gameforge.npc_talk = {}
gameforge.npc_talk._100_say = "Jeg er en meget gammel mand, men jeg er stadig[ENTER]frisk og rask fordi jeg har en speciel[ENTER]hemmelighed. Jeg har fundet ud af at en drik[ENTER]lavet af Gongo rodsaft og tue svamp kan forl\230nge[ENTER]dit liv. Hvis du \248nsker at pr\248ve drikken, bring[ENTER]ingredienserne til Yu-Hwan. Han kan brygge[ENTER]drikken til dig. "
gameforge.npc_talk._10_say = "St\229 stille! Du skal forholde dig fornuftigt og[ENTER]stop med at provokere en strid. Du burde have[ENTER]respekt overfor dine medmennesker. Er det[ENTER]forst\229et?  "
gameforge.npc_talk._110_npcChat = "Du ser meget st\230rk ud... "
gameforge.npc_talk._120_say = "I mange \229r er den skjulte styrke givet videre i[ENTER]vores familie.[ENTER]Min far fortalte mig at, hvis man blander[ENTER]klokkeblomster p\229 den rigtige m\229de, s\229 giver den[ENTER]en eliksir der giver ekstra styrke i et kort[ENTER]stykke tid.[ENTER]S\229 vidt jeg ved, s\229 kan Beak-Go brygge denne[ENTER]eliksir. Du skal bare bringe ham en klokkeblomst. "
gameforge.npc_talk._130_npcChat = "G\229, fort\230l det p\229 bjerget... "
gameforge.npc_talk._140_sayTitle = "Yu-Hwan, musikeren: "
gameforge.npc_talk._150_say = "...Over bakkerne og alle steder... Kan du ogs\229[ENTER]lide musik? Jeg synger alle slags sange i[ENTER]ensomhed her, s\229 jeg ikke bliver fanget i krigen.[ENTER]Men uden et land til at beskytte mig, vil jeg[ENTER]ikke v\230re i stand til at blive ved med det. "
gameforge.npc_talk._160_npcChat = "Hvorfor l\230ser du s\229 meget? "
gameforge.npc_talk._170_sayTitle = "Bogormen Soon: "
gameforge.npc_talk._180_say = "Oh, eventyrer! Verden er fuld af problemer og kun[ENTER]med kundskab kan du overleve.[ENTER]\198r altid dine b\248ger. I d\229rlige tider - og nu om[ENTER]stunder er det altid d\229rlige tider - vil de[ENTER]hj\230lpe dig. Tro mig! "
gameforge.npc_talk._190_npcChat = "Har du nogen b\248rn? "
gameforge.npc_talk._200_say = "Faktisk \248nskede jeg ikke b\248rn, men...[ENTER]Okay jeg forts\230tter med at samle Kaki blomster[ENTER]for hvis du forbereder dem rigtigt, kan du[ENTER]forbedre din magiske energi med dem. Baek-Go[ENTER]fandt ud af det. Han beh\248ver kun en enkelt blomst[ENTER]for at lave 100 drikke. Desv\230rre har Kaki[ENTER]blomsten ogs\229 en side effekt. Hvis en kvinde b\230re[ENTER]en halsk\230de lavet af denne blomst, vil hun f\229 en[ENTER]s\248n. Imellem os to, drog min kone skaml\248st fordel[ENTER]af dette. "
gameforge.npc_talk._20_npcChat = "Mmm, det dufter godt her... "
gameforge.npc_talk._210_npcChat = "Hvad er der galt med din fod? "
gameforge.npc_talk._220_sayTitle = "Handu-Up: "
gameforge.npc_talk._230_say = "Den bliver bedre. Mens jeg tog en g\229tur for[ENTER]nyligt, snublede jeg over en Gango rod og[ENTER]forstuvede min ankel. Heldigvis kender jeg l\230gen[ENTER]Baek-Go, s\229 han behandlede mig og gav mig nogle[ENTER]r\229d: For at heale sm\229 s\229r kan du brygge en drik[ENTER]fra den samme Gango rod. S\229 jeg lavede den[ENTER]skyldige rod om til en te og den kurerrede skaden[ENTER]den havde forsaget. "
gameforge.npc_talk._240_npcChat = "Hvem er du? "
gameforge.npc_talk._250_sayTitle = "Wonda-Rim: "
gameforge.npc_talk._260_say = "Jeg er Wonda-Rim, Chaegirabs nev\248. Min onkel er[ENTER]ber\248mt! Kender du ham? Han eksperimentere meget[ENTER]med drikke og urter. Da han gjorde dette, fandt[ENTER]han ud af at du kan f\229 en stor m\230ngde beskyttelse[ENTER]imod magisk energi hvis du mikser 100 Bo-vand med[ENTER]et morb\230r. S\229 vidt jeg ved, kan Huahn-So[ENTER]producere denne drik til dig hvis du bringer ham[ENTER]ingredienserne. "
gameforge.npc_talk._270_npcChat = "Hvorfor har du s\229 mange ar? "
gameforge.npc_talk._280_sayTitle = "Forr\230deren Balso : "
gameforge.npc_talk._290_say = "Jeg er ikke en god k\230mper og jeg kommer konstant[ENTER]til skade i krig. P\229 et tidspunkt spurgte jeg[ENTER]Yu-Hwan om han kunne lave en drik til mig som[ENTER]kunne beskytte min krop imod skader. Han bryggede[ENTER]noget fra klokkeblomst saft og syren, men[ENTER]desv\230rre var beskyttelsen ikke tilstr\230kkelig,[ENTER]ellers var det bare min egen udulighed. Men jeg[ENTER]er sikker p\229 at drikken vil hj\230lpe dig. "
gameforge.npc_talk._300_npcChat = "Hvorfor kalder s\229 mange folk dig forr\230der? "
gameforge.npc_talk._30_sayTitle = "OCtavio, gastronomen: "
gameforge.npc_talk._310_say = "Jeg flygtede fra krigen for at tilslutte mig sort[ENTER]vinds klanen. Mine kammerater tilgav mig det[ENTER]aldrig. Bagefter fandt jeg ud af at sort vinds[ENTER]krigerne dr\230ber uskyldige mennesker, s\229 jeg[ENTER]forlod dem med det samme. Det var skr\230kkeligt! "
gameforge.npc_talk._320_say = "Har du uskyldige folk p\229 din samvittighed? S\229[ENTER]fortjener du virkelig dit navn. Du stoppede dem[ENTER]fra at leve et godt liv. "
gameforge.npc_talk._330_say = "Vi lever i en lov l\248s verden. Men jeg har[ENTER]besluttet at jeg ikke vil g\248re noget d\229rligt[ENTER]mere, nogen sinde. Jeg \248nsker ikke at folk[ENTER]fortsat skal beskrive mig som en forr\230der.[ENTER][ENTER]Har du nogle Yang til mig? "
gameforge.npc_talk._340_npcChat = "De kalder dig den l\230rde? "
gameforge.npc_talk._350_sayTitle = "Uriel, den l\230rte: "
gameforge.npc_talk._360_say = "Der er s\229 mange ting jeg \248nsker at l\230re i denne[ENTER]store verden. Ignorance kombineret med[ENTER]milit\230rmagt sat sammen er en specielt farlig[ENTER]kombination. Du har ikke lyst til at leve som[ENTER]disse ignorante soldater, vel?[ENTER]Viden er magt! "
gameforge.npc_talk._370_npcChat = "Min kilde siger at du ud\248ver medicin? "
gameforge.npc_talk._380_say = "Jeg g\248r hvad jeg kan. Men der er flere og flere[ENTER]tilskadekommende hver dag i denne farlige verden.[ENTER]Vi har ikke nok medicin eller urter. Tiderne er[ENTER]h\229rde! M\229ske kunne du give mig en h\229nd senere? "
gameforge.npc_talk._390_npcChat = "Hvordan g\229r jagt forretningen? "
gameforge.npc_talk._400_sayTitle = "Yang-Shin, j\230geren: "
gameforge.npc_talk._40_say = "Velkommen! Vores traditionelle restaurant er s\229[ENTER]popul\230r at vi kunne \229bne dem i hele verden. Hvis[ENTER]du vil have noget godt at spise, s\229 kom forbi og[ENTER]pr\248v vores mad. "
gameforge.npc_talk._410_say = "Hmm, lige siden Metin stenene kom ned, er dyrene[ENTER]blevet virkelig vilde. Nu til dags risikere du[ENTER]dit liv bare du g\229r ud og jagter en kylling. Det[ENTER]er en farlig tid at jage. Heldigvis er jeg en af[ENTER]de bedste! "
gameforge.npc_talk._420_npcChat = "Hvor kommer din store precished fra? "
gameforge.npc_talk._430_say = "Jeg er dygtig med en bue, fordi jeg har en s\230rlig[ENTER]opskrift, hehe! N\229r du mikser fersken blomst saft[ENTER]med syren, kan du f\229 en drik der for\248ger din[ENTER]presseision. Bring ingredienserne til Yu-Hwan,[ENTER]jeg er sikker p\229 han vil brygge en drik til dig. "
gameforge.npc_talk._440_npcChat = "S\229dan en smuk blomster krans... "
gameforge.npc_talk._450_say = "Jeg plejede at samle fersken blomster med min[ENTER]bror. Men i dag er jeg n\248d til at g\248re det alene.[ENTER]De ser ikke s\230rlig smukke ud, men de har en[ENTER]s\230rlig effekt. Hvis du tager fersken blomster til[ENTER]Baek-Go vil han brygge en drik af det som g\248r dig[ENTER]meget adr\230t til fods. "
gameforge.npc_talk._460_npcChat = "Hvor er din broder? "
gameforge.npc_talk._470_say = "P\229 det seneste har min bror rejst meget. Jeg ser[ENTER]ham knapt mere, og jeg er bekymret for ham. "
gameforge.npc_talk._480_npcChat = "S\230lger du riskager? "
gameforge.npc_talk._490_sayTitle = "Yu-Rang, riskage-s\230lger: "
gameforge.npc_talk._500_say = "P\229 grund af krigen er det sv\230rt at s\230lge[ENTER]riskager. Takket v\230re banditterne har jeg mistet[ENTER]mange kunder. Jeg ved slet ikke hvad jeg skal[ENTER]g\248re for at tjene til f\248den l\230ngere. "
gameforge.npc_talk._50_say = "Selvom at det er en stor restaurant, er[ENTER]interi\248ret overraskende simpelt. "
gameforge.npc_talk._510_npcChat = "Hvem k\248ber normalt vare fra dig? "
gameforge.npc_talk._520_say = "Jeg s\230lger de fleste af min kager til rejsende.[ENTER]En dag kom en mystisk sort kl\230dt rytter for at se[ENTER]mig. Som betaling gav han mig en opskrift su kan[ENTER]lave med zin vand. Det er en drik der forbedre[ENTER]din angrebs styrke. Jeg solgte opskriften til[ENTER]Huahn-So. Hvis du tager noget sim vand og[ENTER]alperose til Huahn-So, vil han producere Zin vand[ENTER]til dig. "
gameforge.npc_talk._530_npcChat = "Hvorfor ser du s\229 ked ud? "
gameforge.npc_talk._540_say = "Oh, hvem kunne have vidst at vores s\248de dr\248mme[ENTER]ville blive sl\229et i stykker s\229 n\229desl\248st... Min[ENTER]stakkels mand, han faldt i kampen! ... Jeg beder[ENTER]dig, h\230vn hans d\248d. "
gameforge.npc_talk._550_npcChat = "S\229 mange folk er faldet i krigen... "
gameforge.npc_talk._560_say = "Vi mister flere og flere m\230nd i krigen, s\229[ENTER]kvinderne i landsbyen samlede og spurgte Huahn-So[ENTER]om at lave en bedre healings eliksir. Efter megen[ENTER]forskning, producerede han en eliksir der \248ger[ENTER]forsvaret, s\229 der skal bruges f\230rre healing[ENTER]eliksirer. G\229 til ham. Jeg er sikker p\229 at han[ENTER]kan producere eliksiren han kalder SamBo-vand til[ENTER]dig. Han skal bare bruge noget Dok-vand og en[ENTER]aplerose for at lave det. "
gameforge.npc_talk._570_npcChat = "Ohh, hvor s\248dt et barn... "
gameforge.npc_talk._580_sayTitle = "Ah-Yu: "
gameforge.npc_talk._590_say = "Han skriger endnu en gang... Jeg ved ikke om han[ENTER]vil have slik eller... \197hh nej!  "
gameforge.npc_talk._600_npcChat = "Hvordan har i to det? "
gameforge.npc_talk._60_npcChat = "Fort\230l mig noget om keramik. "
gameforge.npc_talk._610_say = "Mit barn! Ugh. Nu da min mand er faldet i krigen,[ENTER]bliver jeg n\248dt til at s\248rge for mig selv. Jeg[ENTER]pr\248ver at ern\230re mine b\248rn og jeg selv alene.[ENTER]Med Bo-vand fandt jeg en mulighed for at \248ge mit[ENTER]liv. Jeg har brug for at bringe Yu-Hwan 100[ENTER]Kakiblomst safte og en Tue-svamp.[ENTER]Af dette kan han brygge Bo-vand som jeg nemt kan[ENTER]s\230lge. Jeg skal kunne komme videre p\229 en eller[ENTER]anden m\229de...  "
gameforge.npc_talk._620_npcChat = "Hvem er din \230gtemand? "
gameforge.npc_talk._630_sayTitle = "Aranyo: "
gameforge.npc_talk._640_say = "Min s\229kaldte husbond er gift med sine b\248ger. Han[ENTER]kigger knapt nok p\229 mig l\230ngere. Og jeg er ikke[ENTER]en grim kvinde.  "
gameforge.npc_talk._650_npcChat = "Hvis forretning? "
gameforge.npc_talk._660_say = "Siden krigen br\248d ud, har forretningen v\230ret[ENTER]rigtig d\229rlig. Handlernes union var engang en rig[ENTER]og m\230gtig union, men disse dage er forbi nu. Vi[ENTER]kan ikke ignorere de vilde monstre, Hvid-ed[ENTER]soldaterne og Sort-vind soldaterne l\230ngere. "
gameforge.npc_talk._670_npcChat = "Hvorfor er du i s\229 d\229rligt hum\248r? "
gameforge.npc_talk._680_sayTitle = "Taurean: "
gameforge.npc_talk._690_say = "Harang er en ond pige! Jeg hader hende! Jeg er[ENTER]svag og hun driller mig ofte!  "
gameforge.npc_talk._700_say = "Du er en mand, og du har store muskler. Styrk dem[ENTER]en gang i mellem!  "
gameforge.npc_talk._70_sayTitle = "Yonah, pottemageren: "
gameforge.npc_talk._710_npcChat = "Hvad har du gang i "
gameforge.npc_talk._720_sayTitle = "Harang: "
gameforge.npc_talk._730_say = "Jeg venter p\229 Taurean. Vi spiller ofte sammen og[ENTER]vi k\230mper ogs\229 en del. Sikke en kujon! Hvis han[ENTER]ikke kommer frivilligt, vil jeg give ham en h\229rd[ENTER]omgang! "
gameforge.npc_talk._740_npcChat = "Taurean er bange for dig. "
gameforge.npc_talk._750_say = "Taurean er faktisk st\230rkere end mig. S\229 nu har[ENTER]jeg t\230nkt p\229 en m\229de hvor jeg alligevel kan[ENTER]vinde. En hvid Ninja fortalte mig at man kan[ENTER]mikse ungt vand med morb\230r og lave en drik som[ENTER]g\248r dig hurtigere. S\229 vil jeg endelig v\230re i[ENTER]stand til at besejre Taurean! Hvis du ogs\229 \248nsker[ENTER]at blive en hurtigere angriber, bring[ENTER]ingredienserne til Huahn-So. Jeg er sikker p\229 han[ENTER]laver drikken til dig. "
gameforge.npc_talk._760_npcChat = "Ny indsigt... "
gameforge.npc_talk._770_say_title = "Seon-Pyeong: "
gameforge.npc_talk._780_say = "Min ven, verdenen er fyldt med ubesvarede[ENTER]sp\248rgsm\229l. Jeg er en s\248ger af svar, og en s\248ger[ENTER]af kundskab. Har du nogensinde h\248rt om episke[ENTER]v\229ben og \229ndesten? "
gameforge.npc_talk._790_npcChat = "Hvad laver du? "
gameforge.npc_talk._800_say = "Du ved nok allerede at jeg forsker ukendt[ENTER]kundskab. For tiden leder jeg efter en metode til[ENTER]yderligere forbedring af v\229ben og m\229der at \248ge[ENTER]kraften i \229ndesten. "
gameforge.npc_talk._80_say = "Jeg elsker at v\230re pottemager. Det er meget[ENTER]tilfredsstillende at forme ler med dine egne[ENTER]h\230nder og se hvordan noget bliver skabt... Jeg[ENTER]laver normalt kun simple ting. \216stp\229 i udkanten[ENTER]af kontinentet er produktions metoderne meget[ENTER]mere udviklede. Jeg s\229 noget pottemageri der[ENTER]engang, og blev virkelig inspireret. Nogen gange,[ENTER]n\229r jeg har tiden, pr\248ver jeg at eksperimentere.[ENTER]Men jeg har stadig ikke fundet ud af hvilket[ENTER]tricks de bruger. "
gameforge.npc_talk._810_npcChat = "V\229ben forskningen... "
gameforge.npc_talk._820_say = "Interessant er det ikke? Vil du vide mere om det?[ENTER]S\229 v\230r venlig at bringe mig et passende level 65[ENTER]v\229ben +9.[ENTER]Jeg har ogs\229 brug for en F\230gtnings skrift og to[ENTER]Velsignelses dok. Jeg vil pr\248ve at lave et episk[ENTER]v\229ben med dem. "
gameforge.npc_talk._830_say = "Dog, jeg kan ikke garantere at det virker. "
gameforge.npc_talk._840_npcChat = "\197ndestenene... "
gameforge.npc_talk._850_say = "\197ndesten er meget udbredte, men selvom at de er[ENTER]brugt meget, s\229 ved de fleste folk ikke hvad[ENTER]deres virkelige kr\230ft er. Men min forskning har[ENTER]hjulpet mig til at finde ud af mere omkring dem.[ENTER]Hvis du bringer mig endnu en \229ndesten, s\229 kan jeg[ENTER]forbedre den for dig. "
gameforge.npc_talk._90_npcChat = "Du er meget livlig af din alder... "
gameforge.olympic_badge = {}
gameforge.olympic_badge._010_npcChat = "Helt's medalje "
gameforge.olympic_badge._020_say = "Hj\230lp mig! "
gameforge.olympic_badge._030_say = "Irriterende tyve...[ENTER]De br\248d ind i mit hus sidste nat![ENTER]De stjal Heltens Medalje. Mine forf\230dre blev[ENTER]bel\248nnet med den medalje efter han l\248b 42,195 km[ENTER]fra kamppladsen til kejseren, for at fort\230lle ham[ENTER]om deres kamp sejr.[ENTER]Og nu er den v\230k! "
gameforge.olympic_badge._040_say = "Ohh ven... Det har affektionsv\230rdi for min[ENTER]familie og jeg. Hvad i verden skal jeg g\248re? "
gameforge.olympic_badge._050_say = "Vil du hj\230lpe mig? "
gameforge.olympic_badge._060_npcChat = "Helt's medalje "
gameforge.olympic_badge._070_say = "Endelig! Du er tilbage![ENTER]Fandt du Helten`s medaljen? "
gameforge.olympic_badge._080_say = "Men hvorfor? Hvad \248nsker de tyve at g\248re med min[ENTER]medalje? Den er v\230rdil\248s til fremmede! Kan du[ENTER]hj\230lpe mig med at finde den? "
gameforge.olympic_badge._090_npcChat = "Find Helten's medalje! "
gameforge.olympic_badge._100_say = "Du kommer tomh\230ndet tilbage? Oh nej, jeg er s\229[ENTER]ulykkelig. Hvis du ikke kan hj\230lpe mig, hvem kan[ENTER]s\229? Forts\230t med at lede, please! "
gameforge.olympic_badge._110_say = "Du har fundet min medalje![ENTER]Men vent... Det er kun et stykke af den. Hvilken[ENTER]sk\230ndsel, de har br\230kket den i fem stykker![ENTER]Bring mig venligst alle fragmenterne! S\229 er jeg[ENTER]m\229ske i stand til at samle medaljen igen. "
gameforge.olympic_badge._120_say = "De elendige kriminelle har \248delagt min families[ENTER]arvestykke! Tak fordi du fandt alle stykkerne.[ENTER]Nu kan jeg samle stykkerne sammen igen. "
gameforge.olympic_badge._130_say = "Tusind tak! Du har genoprettet min families \230re.[ENTER]Selvf\248lgelig vil alt dit besv\230r ikke v\230re[ENTER]forg\230ves. Her er din bel\248nning! "
gameforge.olympic_badge._140_say = "\216nsker du virkelig at afbryde denne mission? Hvis[ENTER]du v\230lger 'ja', vil du ikke v\230re istand til at[ENTER]genoptage den senere. "
gameforge.olympic_badge._150_say = "Jeg forst\229r hvis ikke du har tid nok til det nu.[ENTER]Kom igen n\229r det passer dig bedre. Men lad mig[ENTER]ikke vente for l\230nge! "
gameforge.olympic_badge._160_say = "Desv\230rre ankommer du for sent og kan ikke hj\230lpe[ENTER]mig nu. Jeg \248nsker dig det bedste i fremtiden. "
gameforge.olympic_badge._170_say = "Jagt monstrene der stjal fra mig! Men v\230r[ENTER]forsigtig, de er meget st\230rke - mindst level 30.[ENTER]Hvis du bringer min helte medalje tilbage, vil[ENTER]jeg give dig en gener\248s bel\248nning! "
gameforge.olympic_badge._180_say = "Find Helten`s medalje og tag den med til Yu- Hwan. "
gameforge.olympic_badge._190_say = "Yu-Hwan har brug for din hj\230lp. G\229 og se ham! Du[ENTER]vil finde ham i den anden by. "
