gameforge.skill_reset2._10_npcChat = "Nulstil f\230rdigheder "
gameforge.skill_reset2._110_say = "Hvis du skifter mening, kan du komme igen. "
gameforge.skill_reset2._120_say = "Du har ikke nok Yang.[ENTER]Uden det kan jeg ikke hj\230lpe dig, da jeg selv[ENTER]skal leve af noget. "
gameforge.skill_reset2._130_say = "Denne genstand muligg\248r at du kan v\230lge en ny[ENTER]l\230re og glemme den gamle. For at kunne bruge den[ENTER]skal du mindst have opn\229et level 31.[ENTER]\216nsker du at glemme din l\230re og v\230lge en ny en? "
gameforge.skill_reset2._135_say = "Du f\248lger ikke nogen overlevering og har ikke[ENTER]nogen f\230rdighedspoint jeg kan s\230tte tilbage! "
gameforge.skill_reset2._140_say = "Denne genstand kan kun bruges fra level 31. "
gameforge.skill_reset2._20_say = "Du har ikke p\229begyndt noget tr\230ning endnu! S\229[ENTER]l\230nge du ikke har brugt nogen f\230rdighedspoint kan[ENTER]du heller ikke tilbages\230tte dem. Kom tilbage n\229r[ENTER]du har lavet en fejl i din tr\230ning s\229 vil jeg med[ENTER]gl\230de hj\230lpe dig. "
gameforge.skill_reset2._30_say = "Jeg er bange for at jeg ikke kan hj\230lpe dig mit[ENTER]barn. Du har allerede n\229et level %s men desv\230rre[ENTER]kan du kun \230ndre din tr\230ning op til level 30. "
gameforge.skill_reset2._40_say = "Du f\248lger ikke nogen overlevering og har ikke[ENTER]nogen f\230rdighedspoint jeg kan s\230tte tilbage! "
gameforge.skill_reset2._50_say = "Hej, hos mig er du rigtig.[ENTER]Dine \248jne fort\230ller stor sorg.[ENTER]Jeg s\248rger for at folk kan glemme deres l\230re, s\229[ENTER]de kan starte forfra. \216nsker du at glemme din[ENTER]l\230re? Det koster dig %s Yang.  "
gameforge.skill_reset2._60_select = "Nulstil ikke "
gameforge.skill_reset2._70_say = "Se bare p\229 det dunkle ansigt! Har du det ikke[ENTER]godt? Hvis du er ulykkelig omkring din[ENTER]overbevisning: Jeg kan hj\230lpe dig med at glemme[ENTER]alting p\229 ingen tid. "
gameforge.skill_reset2._80_say = "Dette betyder at alle dine f\230rdighedspoint vil[ENTER]blive sat tilbage og kan blive genindsat.[ENTER]Desv\230rre kan jeg ikke give dig de point tilbage[ENTER]som du har f\229et fra at l\230se b\248ger, de vil blive[ENTER]tabt efter tilbages\230tningen. Vil du forts\230tte?[ENTER]Glemme alting og starte fra starten igen? S\229 har[ENTER]jeg brug for %s Yang fra dig. "
