gameforge.spider_dungeon_3floor_boss._110_sendLetter = "Ny fare "
gameforge.spider_dungeon_3floor_boss._120_say = "Du har lavet en perfekt kopi af inskriptionen.[ENTER]Vis den til Kaptajnen. "
gameforge.spider_dungeon_3floor_boss._130_say = "Fantastisk, du gjorde det! Vis mig den s\229... Hmm.[ENTER]Disse tegn er ikke mig bekendt, jeg kan ikke[ENTER]forst\229 et eneste ord. Du b\248r sp\248rge den l\230rte[ENTER]Uriel til r\229ds. "
gameforge.spider_dungeon_3floor_boss._140_say = "G\229 til den l\230rte Uriel og vis ham inskriptionen.[ENTER]Han vil sikkert v\230re i stand til at overs\230tte den. "
gameforge.spider_dungeon_3floor_boss._150_say = "Kaptajnen beder mig tyde denne mystiske[ENTER]inskription? Naturligvis. Jeg elsker en god[ENTER]udfordring. Giv det til mig.[ENTER]Det er... jamen det er jo forf\230rdeligt! Her, jeg[ENTER]skriver overs\230ttelsen ned p\229 dette papir. Bring[ENTER]det til Kaptajnen s\229 hurtigt du kan og vend[ENTER]tilbage til mig igen. Hvis det der er skrevet her[ENTER]er sandt, s\229 er vi alle i stor fare! G\229, g\229! "
gameforge.spider_dungeon_3floor_boss._160_say = "Du har ikke v\230ret ved Kaptajnen endnu?! Kom nu![ENTER]Du skal skynde dig. Vi har ikke nogen tid miste.[ENTER]Han skal l\230se dette brev! "
gameforge.spider_dungeon_3floor_boss._170_sayTitle = "Aflever Uriels brev "
gameforge.spider_dungeon_3floor_boss._180_say = "Den n\248gterne gamle mand... er et tak for meget at[ENTER]sp\248rge om?! Nuvel. Han sagde at informationen var[ENTER]yderst vigtig, s\229 jeg m\229 hellere g\229 til Kaptajnen[ENTER]med det s\229 hurtigt som muligt. "
gameforge.spider_dungeon_3floor_boss._190_npcChat = "Uriels brev "
gameforge.spider_dungeon_3floor_boss._200_say = "\197h nej! Hvis det der er skrevet her er sandt, s\229[ENTER]har en farlig spindler d\230mon sat sin spind[ENTER]indenfor p\229 tredje etage i Edderkoppegrotten -[ENTER]Edderkoppe-baronessen. Indskriften siger, at du[ENTER]brug for en s\230rlig n\248gle for at komme til denne[ENTER]skjulte hule. G\229 f\248rst Uriel og sp\248rge ham om[ENTER]denne n\248gle. S\229 saml dig en gruppe og storm denne[ENTER]Edderkoppe-baronesses skjulested! Her jeg har en[ENTER]anden Passage billet til dig. "
gameforge.spider_dungeon_3floor_boss._20_say = "Denne port kan kun \229bnes med Spindlernes N\248gle. "
gameforge.spider_dungeon_3floor_boss._210_npcChat = "Spindlernes N\248gle "
gameforge.spider_dungeon_3floor_boss._220_say = "Jeg b\248r g\229 til Uriel s\229 snart jeg kan. "
gameforge.spider_dungeon_3floor_boss._230_say = "Ah, du er tilbage. S\229 g\229r jeg ud fra at Kaptajnen[ENTER]har givet dig ordre til at tilintetg\248re[ENTER]Edderkoppe- baronessen? Men indgangen til[ENTER]Baronessens yngle- kammer er forseglet og kan kun[ENTER]\229bnes med Spindlernes N\248gle. Fremstillingen af[ENTER]denne n\248gle er meget arbejdsomt. Men hvis du[ENTER]bringer mig en Edderkops Gifts\230k, en[ENTER]Edderkoppe-\230gges\230k, et Edderkoppenet,[ENTER]Edderkoppe\248jne, Edderkoppeben sammen med[ENTER]Edderkoppe dronningens gift, s\229 vil jeg lave en[ENTER]til dig. "
gameforge.spider_dungeon_3floor_boss._240_say = "Du vil have mig til at lave en Spindlernes N\248gle[ENTER]til dig? For at g\248re dette skal jeg bruge en[ENTER]Edderkops Gifts\230k, en Edderkoppe-\230gges\230k, et[ENTER]Edderkoppenet, Edderkoppe\248jne, Edderkoppeben[ENTER]sammen med Edderkoppe dronningens gift. Har du[ENTER]fundet alle disse substanser? "
gameforge.spider_dungeon_3floor_boss._250_say = "Storartet! Du har alle de ting jeg skal bruge for[ENTER]at lave Spindlernes N\248gle. Vent et \248jeblik. Det[ENTER]skulle ikke tage s\229 lang tid at lave... "
gameforge.spider_dungeon_3floor_boss._260_say = "Ha, f\230rdig! Her din Spindlere n\248gle. Den vil give[ENTER]dig adgang til Edderkoppe-baronessens skjulested.[ENTER]Jeg \248nsker dig og dine kammerater held og lykke i[ENTER]kampen mod dette langbenede b\230st![ENTER]Men du er n\248dt til at skynde sig - n\248glen er[ENTER]meget ustabil. Efter 24 timer, vil den falde fra[ENTER]hinanden tilbage til dens oprindelige stykker. "
gameforge.spider_dungeon_3floor_boss._270_say = "\197h nej... Jeg er bange for at sige at ingen er[ENTER]f\248dt perfekt. Du m\229 forst\229 at smedningen af denne[ENTER]n\248gle er ekstremt kompliceret. Selv den mindste[ENTER]fejl vil lede til et mislykkedet fors\248g.[ENTER]Desv\230rre har jeg mistet alle edderkoppe[ENTER]substanserne du indsamlede til mig i[ENTER]fremstillingsprocessen . Det n\230ste fors\248g vil[ENTER]helt sikkert virke! "
gameforge.spider_dungeon_3floor_boss._280_say = "Der mangler stadig noget, jeg kan ikke lave[ENTER]Spindlernes N\248gle til dig endnu. Her er de[ENTER]elementer vi skal bruge: En Edderkops Gifts\230k, en[ENTER]Edderkoppe-\230gges\230k, et Edderkoppenet,[ENTER]Edderkoppe\248jne, Edderkoppeben sammen med[ENTER]Edderkoppe dronningens gift. "
gameforge.spider_dungeon_3floor_boss._300_say = "Din gruppeleder er g\229et ind i grotten. Vil du[ENTER]f\248lge med? "
gameforge.spider_dungeon_3floor_boss._30_npcChat = "Reset SD3 quest "
gameforge.spider_dungeon_3floor_boss._310_say = "Du var for lang tid om det. N\248glen er allerede[ENTER]g\229et i opl\248sning. F\229 den fremstillet p\229 ny for at[ENTER]f\229 adgang til denne lokalitet. "
gameforge.spider_dungeon_3floor_boss._320_say = "Der er allerede en gruppe i Baronessens[ENTER]Yngle-grotte som udf\248rer et angreb p\229[ENTER]Edderkoppe-baronessen. "
gameforge.spider_dungeon_3floor_boss._330_say = "Du kan kun komme ind, n\229r den foreg\229ende gruppe[ENTER]har afsluttet deres opgave. Du skal vende tilbage[ENTER]om %s minutter. "
gameforge.spider_dungeon_3floor_boss._340_say = "Ventetid til at portene til Baronessens[ENTER]Yngle-grotte gen\229bner: "
gameforge.spider_dungeon_3floor_boss._350_say = "%s minutter "
gameforge.spider_dungeon_3floor_boss._360_say = "Krigeren der gik ind i grotten f\248r dig kan[ENTER]begynde at bev\230ge sig igen efter at der er g\229et[ENTER]10 sekunder. Vent venligst. "
gameforge.spider_dungeon_3floor_boss._370_say = "Kunne du t\230nke dig at starte missionen? Du vil[ENTER]have 20 minutter at gennemf\248re den. Ingen vil[ENTER]v\230re i stand til at forlade baronessens yngel-[ENTER]hule, f\248r denne tid er g\229et.[ENTER]Et nyt fors\248g kan udf\248res efter en time. "
gameforge.spider_dungeon_3floor_boss._380_say = "Du skal bruge Spindlernes N\248gle for at \229bne[ENTER]indgangen. "
gameforge.spider_dungeon_3floor_boss._390_say = "Kun lederen af en gruppe kan bruge Spindlernes[ENTER]N\248gle. "
gameforge.spider_dungeon_3floor_boss._400_say = "Edderkoppe-baronessen er blevet besejret! Om tre[ENTER]minutter bliver alle krigere teleporteret ud af[ENTER]grotten. "
gameforge.spider_dungeon_3floor_boss._40_say = "F\248r fremstillingen af n\248glen "
gameforge.spider_dungeon_3floor_boss._410_say = "Det virkede ikke. Pr\248v venligst igen! "
gameforge.spider_dungeon_3floor_boss._420_notice = "Advarsel: Edderkoppe-baronessen er ved at blive[ENTER]vred! Hendes angreb vil blive st\230rkere, men hun[ENTER]har ogs\229 nedsat hendes forsvar. "
gameforge.spider_dungeon_3floor_boss._50_npcChat = "Edderkoppe-grotten 3 "
gameforge.spider_dungeon_3floor_boss._60_say = "Ah, godt at du er her. Jeg har vigtige[ENTER]oplysninger for dig: en gruppe spejdere har[ENTER]afsl\248ret en tredje etage i Edderkoppegrotten.[ENTER]Det formodes at v\230re nogle s\230rdeles kolosale og[ENTER]forr\230deriske edderkopper indlejret d\233r.[ENTER]Udover dette, fandt mine m\230nd en gammel gravsten[ENTER]med en indskrift, men de var ude af stand til at[ENTER]lave en kopi af det. G\229 p\229 jagt efter denne sten[ENTER]og bring mig en kopi af denne inskription. Her er[ENTER]en Passage billet, som vil give dig adgang til[ENTER]Edderkoppegrotten uhindret. "
gameforge.spider_dungeon_3floor_boss._70_sendLetter = "Inskriptionen "
gameforge.spider_dungeon_3floor_boss._80_say = "P\229 den tredje etage i Edderkoppe grotten vil du[ENTER]finde en gammel gravsten med en inskription[ENTER]indgraveret p\229 den. Lav en kopi af denne og bring[ENTER]den til Kaptajnen. "
gameforge.spider_dungeon_3floor_boss._90_say = "Perfekt, du fandt den gamle gravsten og lavede en[ENTER]kopi af inskriptionen p\229 den! G\229 tilbage til[ENTER]Kaptajnen og vis det til ham. "
