gameforge.subquest_01._120_targetVid = "Find Yonah pottemageren "
gameforge.subquest_01._130_sayReward = "Handelsdamen har brug for en tom flaske fra[ENTER]pottemageren Yonah, s\229 hun kan fremstille en r\248d[ENTER]eliksir. "
gameforge.subquest_01._140_sayTitle = "Yonah: "
gameforge.subquest_01._150_say = "Oh k\230re! Pokkers ogs\229! Jeg kan ikke stoppe den[ENTER]hoste! Hvordan skal jeg kunne arbejde p\229 den[ENTER]m\229de? Har handelsdamen sendt dig?[ENTER]Jeg har tomme flasker, men jeg kan ikke give dig[ENTER]en gratis. "
gameforge.subquest_01._160_say = "Jeg har astma.[ENTER]Folk har fortalt mig, at ferskenfr\248 skulle v\230re[ENTER]et dejligt middel mod astma. Hvis du finder nogen[ENTER]til mig, kan du f\229 min tomme flaske.[ENTER]Du kan finde ferskenfr\248 hos vores vildsvin ude[ENTER]for byen. N\229r landsm\230ndene planter ferskentr\230er,[ENTER]er det vildsvinene som graver dem op[ENTER]igen.  "
gameforge.subquest_01._170_sendLetter = "F\229 fat i ferskenfr\248. "
gameforge.subquest_01._180_sayReward = "Handelsdamen har brug for en tom flaske til[ENTER]hendes mikstur fra Yonah pottermageren.[ENTER]Yonah, der har astma, vil give dig en tom flaske,[ENTER]hvis du finder nogle Ferskenfr\248 til ham. Du[ENTER]finder disse fr\248 ved at jagte vildsvin. "
gameforge.subquest_01._190_npcChat = "For at f\229 ferskenfr\248... "
gameforge.subquest_01._200_say = "Du kan finde ferskenfr\248 hos vores vildsvin ude[ENTER]for byen. N\229r landsm\230ndene planter ferskentr\230er,[ENTER]er det vildsvinene der graver dem ud igen.[ENTER]Host, host.[ENTER]Tusind tak. "
gameforge.subquest_01._20_npcChat = "F\229 fat i tom flaske "
