gameforge.subquest_01._220_sayTitle = "G\229 tilbage til Yonah "
gameforge.subquest_01._230_sayReward = "Du har fundet ferskenfr\248, aflever dem til Yonah. "
gameforge.subquest_01._240_say = "Oh, du har fundet dem! "
gameforge.subquest_01._250_say = "Tak. Nu kan jeg i det mindste g\248re noget imod min[ENTER]astma og kan forts\230tte mit[ENTER]arbejde.  "
gameforge.subquest_01._260_say = "Her er en tom flaske. Tag den med til handelsdamen "
gameforge.subquest_01._270_sendLetter = "Levere den tomme flaske "
gameforge.subquest_01._280_sayReward = "Handelsdamen ved landhandlen har brug for den[ENTER]tomme flaske fra pottemageren. Aflever den. "
gameforge.subquest_01._290_sayTitle = "Handelsdame: "
gameforge.subquest_01._300_say = "Tak.[ENTER]Jeg h\229ber det var ikke alt for besv\230rligt.[ENTER]Du f\229r det her, som tak for dit[ENTER]arbejde.  "
gameforge.subquest_01._30_say = "Undskyld? Hvis du ikke lige har for travlt, kunne[ENTER]du m\229ske g\248re mig en tjeneste? Jeg har brug for[ENTER]en tom flaske til min r\248de eliksir. "
gameforge.subquest_01._310_sayReward = "Du f\229r 1500 erfaringspoint.[ENTER]Du f\229r 1000 Yang. "
