gameforge.subquest_01._60_select = "frasige. "
gameforge.subquest_01._70_say = "\216nsker du virklig at afbryde opgaven? "
gameforge.subquest_01._80_say = "Tak for hj\230lpen. Kom igen, n\229r du har tid. "
gameforge.subquest_01._90_say = "Fortsat held og lykke.[ENTER]Kom snart igen "
