gameforge.subquest_02._110_say = "Alt den snak om mad g\248r mig sulten, og jeg kunne[ENTER]s\229 godt t\230nke mig sammenkogt vild, bj\248rn, k\229l og[ENTER]to \230g. "
gameforge.subquest_02._120_say = "Har min far sagt hvad han \248nsker at[ENTER]spise?  "
gameforge.subquest_02._121_select = "Sammenkogt svin, bj\248rn, k\229l og et \230g "
gameforge.subquest_02._122_select = "Sammenkogt vild, bj\248rn, k\229l og et \230g "
gameforge.subquest_02._123_select = "Sammenkogt vild, bj\248rn, k\229l og to \230g "
gameforge.subquest_02._124_select = "Oh ... jeg har glemt det ... "
gameforge.subquest_02._130_say = "Tak fordi du kom med de oplysninger til mig, s\229[ENTER]hurtigt. Her er din bel\248nning. "
gameforge.subquest_02._140_sayReward = "Du har modtaget 1.000 erfaringspoint.[ENTER]Du har modtaget 1.500 Yang. "
gameforge.subquest_02._150_say = "Handelsdame:[ENTER]Jeg er ikke overrasket, han har altid ret[ENTER]us\230dvanlige anmodninger.[ENTER]Vil du venligst sp\248rge ham igen? "
gameforge.subquest_02._160_say = "Handelsdame:[ENTER]Sagde han, det? Er du sikker? Det lyder ikke som[ENTER]min far ... Vil Du venligst sp\248rge ham igen?[ENTER]Jeg tror ikke han mente den ret. "
gameforge.subquest_02._20_say = "Du ved, at rustnings-handelsmanden er min far,[ENTER]g\248r du ikke? Jeg vil tilberede middag for ham,[ENTER]men jeg ved ikke, hvad han \248nsker at spise.[ENTER]Kunne du sp\248rge ham, hvad han gerne vil have?[ENTER]Jeg vil bel\248nne dig for din tid. "
