gameforge.subquest_02._40_sayReward = "G\229 til rustnings-handelsmanden og sp\248rg ham. "
gameforge.subquest_02._50_say = "Velkommen![ENTER]Jeg har rustninger, der beskytter dig mod dolk-[ENTER]og sv\230rdangreb. "
gameforge.subquest_02._60_say = "Oh, min datter sender dig?[ENTER]Hun sp\248rger hvad jeg kunne t\230nke mig til[ENTER]aftensmad. Mmmhh, jeg kunne t\230nke mig at f\229 en[ENTER]dejlig sammenkogt suppe med vild, bj\248rn, k\229l og[ENTER]to \230g. Det ville v\230re dejligt!  "
