gameforge.subquest_03._30_say = "Kan du hente ingredienserne til medicinen for[ENTER]mig? Jeg sp\248rger dig, fordi du er en soldat. Jeg[ENTER]har brug for en Bl\229 Ulv's Lever for medicinen. "
