gameforge.subquest_03._50_sayReward = "Siden Metin-sten styrter ned p\229 jorden er der[ENTER]opst\229et en ukendt sygdom.[ENTER]For at Baek-Go kan lave medicin har han brug for[ENTER]en lever fra en bl\229ulv. "
gameforge.subquest_03._60_npcChat = "For at f\229 en lever fra en bl\229ulv "
