gameforge.subquest_04._10_targetVid = "Hvordan har Deokbae det? "
gameforge.subquest_04._110_sayReward = "G\229 og aflevere Brevet fra Smeden til Deokbae,[ENTER]skovhugger. Du finder ham i den anden landsby,[ENTER]som du kun kan komme til via portalen. "
gameforge.subquest_04._120_sendLetter = "Et brev fra smeden "
gameforge.subquest_04._130_targetVid = "Find br\230ndehuggeren, Deokbae. "
gameforge.subquest_04._140_npcChat = "Et brev fra smeden "
gameforge.subquest_04._150_sayTitle = "Tr\230samleren Deokbae: "
gameforge.subquest_04._160_say = "Velkommen. Jeg har nogle gode \248kser her. Vil du[ENTER]k\248be en? Du beh\248ver ikke en \248kse? S\229 hvorfor er[ENTER]du her? Ah, et brev fra Smeden. Tak.[ENTER]Jeg er en skovhugger, men jeg s\230lger ogs\229 \248kser[ENTER]og andre v\230rkt\248jer. Nogle gange bestiller jeg[ENTER]nogle v\230rkt\248jer hos ham. S\229dan blev vi gode[ENTER]venner. "
gameforge.subquest_04._170_say = "Jeg ville virkelig gerne have en drink med ham i[ENTER]Seo-Pyung Bar. Tak fordi du bragte mig brevet.[ENTER]Send mine bedste \248nsker til Smeden. "
gameforge.subquest_04._180_say = "Et brev fra smeden?[ENTER]Det er lang tid siden jeg har h\248rt noget fra ham.[ENTER]Hvor er brevet? Du har ikke tabt det undervejs,[ENTER]vel?  "
gameforge.subquest_04._190_select = "Her er det. "
gameforge.subquest_04._200_select = "Ah alligevel ikke "
gameforge.subquest_04._20_say = "Hej der, eventyrer! Jeg vil gerne bede dig om en[ENTER]tjeneste. Kender du en fyr kaldet Deokbae? Han er[ENTER]en skovhugger og en af mine gode venner. M\229ske[ENTER]det er en smule kedeligt, men han er virkelig en[ENTER]af de sidste h\229rdtarbejdende skovarbejdere[ENTER]derude. "
gameforge.subquest_04._210_say = "Afslut mission? "
gameforge.subquest_04._220_say = "Det gl\230der mig.[ENTER]Kom tilbage, hurtig. "
gameforge.subquest_04._230_say = "Du har tabt den?[ENTER]Forsvind...  "
gameforge.subquest_04._240_say = "G\229 til smeden og hent brevet Tab det ikke igen![ENTER]Ses. "
gameforge.subquest_04._250_sayReward = "G\229 tilbage til smeden og hent bel\248nningen. "
gameforge.subquest_04._260_targetVid = "Tilbage til smeden "
gameforge.subquest_04._270_npcChat = "Jeg har afleveret brevet. "
gameforge.subquest_04._280_say = "S\229 hvordan har Deokbae det? Hehe, han har ikke[ENTER]\230ndret sig. Tak. Tag dette som en bel\248nning. Det[ENTER]er ikke meget, men det kan komme til nytte \233n[ENTER]dag. Tak igen. "
gameforge.subquest_04._290_sayReward = "Du har f\229et 4.000 erfaringspoints.[ENTER]Du har f\229et 3.000 Yang. "
gameforge.subquest_04._30_say = "Det er lang tid siden jeg har set ham, og jeg har[ENTER]skrevet ham et brev, for at sp\248rge hvordan han[ENTER]har det.[ENTER]Det ville gl\230de mig, hvis du kunne give ham[ENTER]brevet. Pas godt p\229 dig selv, og p\229 brevet! "
gameforge.subquest_04._40_say = "\197h, ved du ikke hvordan man kommer til den n\230ste[ENTER]landsby? Tryk p\229 'M' for at se miniature kortet.[ENTER]En bl\229 prik vil blive vist p\229 det. Denne dot[ENTER]repr\230senterer portalen, der vil tage dig ind i[ENTER]det tilst\248dende omr\229de. Den anden landsby er ogs\229[ENTER]beliggende i dette omr\229de. "
