gameforge.subquest_05._280_say = "Det er ikke godt at h\248re...[ENTER]Forsvind...  "
gameforge.subquest_05._290_say = "Dejligt, meget godt S\229 kom igen  "
gameforge.subquest_05._300_say = "Er du helt sikker p\229, at r\230kkef\248lgen er[ENTER]korrekt?  "
