gameforge.subquest_05._350_say = "Godt, det er simpelthen fantastisk! Mange tak! "
gameforge.subquest_05._40_say = "Aha ... Hmhm ... Nej, det ...[ENTER]Yikes, hvor kom du fra? Hvor vover du forstyrre[ENTER]mens jeg l\230ser! \197h nej, undskyld, jeg ville ikke[ENTER]r\229be af dig. Nogle gange kommer jeg p\229 noget, som[ENTER]jeg ikke forst\229r, n\229r jeg l\230ser og det er bare s\229[ENTER]frustrerende.[ENTER]Kan du give mig en h\229nd med noget? "
gameforge.subquest_05._50_say = "Jeg er ved at unders\248ge vifterne, der bruges af[ENTER]shamanerne. Jeg har problemer med at finde ud af[ENTER]hvilke der er de bedste. Jeg kan umuligt teste[ENTER]dem alle. Uriel, forskeren, ved alt om disse[ENTER]vifter. Kunne du sp\248rge ham for mig? Jeg er[ENTER]interesseret i f\248lgende typer af vifter: Aquanske[ENTER]vifter, Himlens fuglevifter, Trearmede vifter og[ENTER]Tranevingens vifter. "
gameforge.subquest_05._60_say = "Jeg \248nsker, at han kan sortere dem efter[ENTER]angrebsv\230rdien.  "
gameforge.subquest_05._70_select = "Det kan jeg g\248re "
gameforge.subquest_05._80_select = "Nej tak "
gameforge.subquest_05._90_say = "Vil du afslutte denne mission? "
