gameforge.subquest_06._100_say = "Kom ud, nu! Ubrugelig tyv... "
gameforge.subquest_06._10_targetVid = "Bestille Rustning "
gameforge.subquest_06._110_say = "Tak! G\229 tilbage til Smeden og sp\248rg ham om[ENTER]hvordan han kommer videre med den rustning. "
gameforge.subquest_06._120_sayReward = "G\229 til Smeden og sp\248rg ham, hvor langt han er[ENTER]kommet med rustningen som rustnings-handelsmanden[ENTER]har bestilt. "
gameforge.subquest_06._130_npcChat = "Rustning til rustnings-handelsmanden "
gameforge.subquest_06._140_say = "Hvad er der nu? Hvorfor forstyrrer du mig? Oh,[ENTER]Det er rustnings-handelsmanden der har sendt dig?[ENTER]Den gamle mand er meget ut\229lmodig. Det er ikke,[ENTER]at jeg ikke \248nsker at g\248re det. Jeg har bare ikke[ENTER]har de n\248dvendige materialer til det.[ENTER]Kunne du hente dem for mig? Til at producere[ENTER]rustningen har jeg brug for jernmalm, l\230der og[ENTER]kul. Du kan f\229 jernmalm fra Uriel, l\230der fra[ENTER]Octavio og kul fra Yonah. "
gameforge.subquest_06._150_select = "Jeg f\229r materialer til dig. "
gameforge.subquest_06._160_select = "Nej, ikke lige nu. "
gameforge.subquest_06._170_say = "Er du sikker p\229 du vil holde op med denne mission? "
gameforge.subquest_06._180_say = "Du kan ogs\229 g\248re det senere. Men du m\229 ikke vente[ENTER]alt for l\230nge, denne mission er presserende! "
gameforge.subquest_06._190_say = "N\229, jeg formoder, jeg bliver n\248dt til at skaffe[ENTER]disse ting selv. V\230r forsigtig. "
gameforge.subquest_06._200_say = "S\229 afsted med dig igen, s\229 jeg kan komme tilbage[ENTER]til at arbejde i fred ... "
gameforge.subquest_06._20_npcChat = "Bestille Rustning "
