gameforge.subquest_06._221_say = "Jern Malm - du kan f\229 det fra Uriel. "
gameforge.subquest_06._222_say = "L\230der - du kan f\229 det fra Octavio. "
gameforge.subquest_06._223_say = "Kul - du kan f\229 det fra Yonah. "
