gameforge.subquest_06._240_targetVid = "G\229 til Uriel. "
gameforge.subquest_06._250_targetVid = "G\229 til Yonah. "
gameforge.subquest_06._260_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_06._270_say = "Tak for at bringe mig min bog tilbage! Nu kan jeg[ENTER]forts\230tte min forskning. Her, tag noget Jern malm[ENTER]Brug det godt. "
gameforge.subquest_06._280_say = "Du har brug for jern malm? Jeg kan give dig[ENTER]noget. Men jeg har brug for en tjeneste fra dig:[ENTER]Jeg har for nylig mistet en bog, mens jeg blev[ENTER]forfulgt af en flok vilde hunde. Jeg tror, at[ENTER]disse vilde hunde har min bog. Bring den tilbage[ENTER]til mig og s\229 vil jeg give dig noget jern malm. "
gameforge.subquest_06._285_say = "Uriel vil give dig Jern Malm, hvis du henter hans[ENTER]bog hos de vilde hunde til ham. "
gameforge.subquest_06._290_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_06._300_say = "Mere Jern malm? Jeg har allerede givet dig noget.[ENTER]Nu har jeg ikke mere tilbage. "
gameforge.subquest_06._30_say = "Kunne du hj\230lpe mig? Tak fordi du gjorde min[ENTER]datter en tjeneste. Jeg har brug for at bede dig[ENTER]om en tjeneste nu. Jeg har bedt landsby Smeden om[ENTER]at producere nogle rustninger, men jeg har ikke[ENTER]h\248rt noget fra ham. Kunne du finde ud af, hvordan[ENTER]det g\229r med det? "
gameforge.subquest_06._310_npcChat = "Jeg har brug for l\230der. "
gameforge.subquest_06._320_sayTitle = "Octavio: "
gameforge.subquest_06._330_say = "Tak for Galden! Nu kan jeg endelig g\229 tilbage til[ENTER]min l\230kker mad. Mmm ... Her, tag dette L\230der som[ENTER]en bel\248nning. "
gameforge.subquest_06._340_say = "Jeg kan give dig noget L\230der.[ENTER]Der er dog intet i livet der er gratis.[ENTER]Hvad med at bytte? Jeg vil give dig L\230deret, hvis[ENTER]du finder mig en Galde.[ENTER]Jeg bruger ofte Galder i mine opskrifter.[ENTER]Det g\248r ikke noget, hvis du ikke er interesseret. "
gameforge.subquest_06._345_say = "Octavio vil give dig L\230der hvis du giver ham en[ENTER]Galde. "
gameforge.subquest_06._350_npcChat = "Jeg har brug for l\230der "
gameforge.subquest_06._360_say = "Jeg har allerede givet dig l\230der.[ENTER]Har du tabt det?[ENTER]Jeg har ikke mere. "
gameforge.subquest_06._370_npcChat = "Jeg har brug for kul. "
gameforge.subquest_06._380_say = "Tak for ler. Du kradser min ryg og jeg kradser[ENTER]din: Her er dit kul. P\229 gensyn! "
gameforge.subquest_06._390_say = "Hvad sker der? Du er her for at f\229 Kul? Jeg har[ENTER]masser af Kul. Men du f\229r det ikke gratis. Du er[ENTER]n\248dt til at g\248re noget for mig f\248rst. "
gameforge.subquest_06._395_say = "Yonah vil give dig Kul, hvis du giver ham Ler. Du[ENTER]kan f\229 det ved at jage R\248de Vildsvin. "
gameforge.subquest_06._400_say = "Jeg er ved at l\248be t\248r for Ler til mit porcel\230n.[ENTER]Hvis du bringe mig noget, vil jeg give dig nogle[ENTER]Kul. Det ville v\230re bedst, hvis du dr\230ber nogle[ENTER]R\248de vildsvin, som de tro det eller ej spiser[ENTER]ler. P\229 forh\229nd tak! "
gameforge.subquest_06._40_select = "Ja det g\248r jeg "
gameforge.subquest_06._410_npcChat = "Jeg har brug for kul. "
gameforge.subquest_06._420_say = "Hvad? Jeg har allerede givet dig Kul! Fors\248ger du[ENTER]at narre mig? "
gameforge.subquest_06._430_npcChat = "Jeg har alle materialerne. "
gameforge.subquest_06._440_say = "\197benbart har du intet jernmalm. G\229 til[ENTER]Uriel...  "
gameforge.subquest_06._450_say = "Du har ingen l\230der G\229 til[ENTER]Octavio...  "
gameforge.subquest_06._460_say = "Du har ikke nogen kul. Hmm, ingen Kul? F\229 noget[ENTER]fra Yonah. "
