gameforge.subquest_06._510_sayReward = "Jeg har alle de n\248dvendige materialer. Afsted til[ENTER]Smeden. "
gameforge.subquest_06._520_npcChat = "Jeg har f\229et dit materiale. "
gameforge.subquest_06._530_say = "Du har allerede f\229et alle materialer?[ENTER]Jeg er imponeret! Tak, nu kan jeg levere de[ENTER]bestilte varer til rustnings-handelsmanden. G\229 og[ENTER]fort\230l ham den gode nyhed! "
gameforge.subquest_06._540_sayReward = "Fort\230l rustnings-handelsmanden at hans bestilling[ENTER]er f\230rdig snart. "
