gameforge.subquest_07._100_say = "Vent et \248jeblik, jeg vil v\230re sikker p\229 at det er[ENTER]den rigtige bog ... Hmm, ja, det er virkelig[ENTER]fantastisk. Jeg vil helt sikkert koge disse[ENTER]retter! Tak! "
gameforge.subquest_07._10_targetVid = "Den bedste kogebog "
gameforge.subquest_07._110_say = "Hmm, men jeg har brug for ... Vent, ven! Kan jeg[ENTER]bede Dem om en anden tjeneste? Jeg har n\230sten[ENTER]f\229et alle de ingredienser til denne fantastiske[ENTER]ret, men jeg ser der mangler stadig en Gr\229 ulve[ENTER]tarm. Denne ingrediens er ikke let at f\229 fat p\229[ENTER]og den er bedst at spise, n\229r den er frisk. Skaf[ENTER]mig Venligst en! "
gameforge.subquest_07._120_sayReward = "Hent en Ulve Tarm til Octavio. Du kan f\229 den fra[ENTER]de Gr\229 Ulve. "
gameforge.subquest_07._130_npcChat = "Jeg har f\229et en Ulve tarm. "
gameforge.subquest_07._140_say = "Takket v\230re jer, kan jeg endelig lave dette[ENTER]sj\230ldne m\229ltid. Dette vil v\230re en fest! Jeg er[ENTER]virkelig taknemmelig for din hj\230lp. Tag venligst[ENTER]denne beskedne bel\248nning. "
gameforge.subquest_07._150_sayReward = "Du har modtaget 12.000 erfaringspoint.[ENTER]Du har modtaget 5.000 Yang.[ENTER]Du har modtaget en Ulve klo. "
gameforge.subquest_07._160_say = "Jeg har brug for en gr\229ulvetarm. Levere mig[ENTER]venligst en.  "
gameforge.subquest_07._20_npcChat = "Den bedste kogebog "
gameforge.subquest_07._30_say = "Hmm, er der nogen chance for, at du kender Soon[ENTER]bogorm, der bruger al sin tid p\229 at l\230se?[ENTER]Jeg har h\248rt, at Soon ejer en god kogebog.[ENTER]Find venligst ud af om det er rigtigt. Den[ENTER]kogebog er tilsyneladende fuld af sj\230ldne og[ENTER]eksotiske opskrifter, og jeg er ivrig efter at[ENTER]l\230re dem. "
gameforge.subquest_07._40_targetVid = "Sp\248rg Soon "
gameforge.subquest_07._50_sayReward = "Sp\248rg Soon om han har en udenlandsk kogebog. "
gameforge.subquest_07._60_npcChat = "Har du en speciel kogebog? "
gameforge.subquest_07._70_say = "Bla, bla ... Oh! Dig igen! Hvad vil du?[ENTER]Ja, jeg har en kogebog, der indeholder eksotiske[ENTER]m\229ltider. Tag den med dig, hvis du vil, jeg[ENTER]beh\248ver den ikke. Men du skal ikke forstyrre mig,[ENTER]n\229r jeg l\230ser! "
gameforge.subquest_07._80_targetVid = "Soon har givet dig den udenlandske kogebog. Bring[ENTER]den til Octavio. "
gameforge.subquest_07._90_npcChat = "Her er kogebogen! "
