gameforge.subquest_08._100_sayReward = "G\229 til v\229ben-handelsmanden og sp\248rg ham hvor du[ENTER]kan k\248be Riskager. "
gameforge.subquest_08._10_targetVid = "Riskage "
gameforge.subquest_08._110_npcChat = "Hvad ved du om Ris Kager? "
gameforge.subquest_08._120_sayTitle = "V\229ben-handelsmand: "
gameforge.subquest_08._130_say = "Hvad? Ris kage? Er det et nyt v\229ben?! Ja, godt s\229[ENTER]kan du ...[ENTER]\197h, du mener spiselige Ris Kager. Hvorfor sagde[ENTER]du ikke det i f\248rste omgang? Du m\229 hellere g\229 til[ENTER]Octavio. Han ved alt hvad der er at vide om mad. "
gameforge.subquest_08._140_makequestbutton = "Riskage "
gameforge.subquest_08._150_sayReward = "G\229 til Octavio og sp\248rg ham, hvad han ved om Ris[ENTER]Kager. "
gameforge.subquest_08._160_say = "Hmm, Ris Kager? Dem med de r\248de kirseb\230r og[ENTER]sukker p\229 toppen? Yeah, jeg har spist dem f\248r. Du[ENTER]kan f\229 dem fra ris kage s\230lgeren i den n\230ste[ENTER]landsby. Hun kaldes Yu-Rang, tror jeg. "
gameforge.subquest_08._170_select = "Nej, desv\230rre ingen tid. "
gameforge.subquest_08._180_say = "Du har en lang vej foran dig. Vi ses en anden[ENTER]gang. "
gameforge.subquest_08._190_say = "N\229, vil du helt sikkert blive savnet. Vi ses! "
gameforge.subquest_08._200_say = "Du vil se, det er det v\230rd. Ha en god tur! "
gameforge.subquest_08._20_say = "Undskyld mig, kunne det behage jer at hj\230lp mig?[ENTER]Min baby vil ikke stoppe med at gr\230de og jeg ved[ENTER]bare ikke, hvad jeg skal g\248re for at berolige[ENTER]den. Min baby elsker riskager og jeg tror det[ENTER]kunne hj\230lpe. Jeg tror, at v\229ben-handelsmanden[ENTER]ved hvor man kan f\229 nogle. Kunne du sp\248rge ham[ENTER]for mig? "
gameforge.subquest_08._210_makequestbutton = "Find Yu-Rang "
gameforge.subquest_08._220_targetVid = "Riskage "
gameforge.subquest_08._230_sayReward = "G\229 til Riskage s\230lgeren Yu-Rang. Du kan finde[ENTER]hende i den n\230ste landsby. "
gameforge.subquest_08._240_sayTitle = "Yu-Rang: "
gameforge.subquest_08._250_say = "Kan jeg hj\230lpe dig? \197h, RisKager! Selvf\248lgelig[ENTER]kan jeg give dig nogle! Men ... kunne du g\248re[ENTER]noget for mig f\248rst? En dreng ved navn Taurean[ENTER]kommer ofte her og irriterer mig, selvom jeg[ENTER]aldrig har noget til ham. Hvis du straffer[ENTER]Taurean for mig, s\229 vil jeg give dig nogle[ENTER]RisKager, OK? "
gameforge.subquest_08._260_makequestbutton = "Find Taurean "
gameforge.subquest_08._270_sayReward = "Yu-Rang bliver altid drillet af Taurean. Straf[ENTER]ham og hun vil give dig en Riskage. "
gameforge.subquest_08._280_npcChat = "Hvorfor driller du Yu-Rang? "
gameforge.subquest_08._290_say = "Hvad, hvem er det jeg skal have irriteret? \197h, du[ENTER]mener den pige, der s\230lger RisKager? Nej, jeg[ENTER]\248nskede ikke at irritere hende! Jeg keder mig[ENTER]bare, og hun s\229, s\229 flot ud og hun havde ikke[ENTER]meget at lave. S\229 jeg bes\248gte hende et par gange[ENTER]og \248nskede at spille med hende, men hun blev[ENTER]vred... Piger er m\230rkelige. Jeg formoder jeg vil[ENTER]ikke bes\248ge hende mere! "
gameforge.subquest_08._300_makequestbutton = "G\229 tilbage til Yu-Rang "
gameforge.subquest_08._30_select = "Acceptere "
gameforge.subquest_08._310_targetVid = "Riskage "
gameforge.subquest_08._320_sayReward = "Taurean vil ikke genere Yu-Rang mere. G\229 til[ENTER]hende og f\229 din Riskage. "
gameforge.subquest_08._330_say = "Ha, ha! Du straffede Taurean! Tak. Nu vil han[ENTER]t\230nke sig om to gange, f\248r han kommer tilbage[ENTER]igen. Her er din Riskage. Nyd dit m\229ltid! "
gameforge.subquest_08._340_makequestbutton = "Tilbage til Ah-Yu "
gameforge.subquest_08._350_targetVid = "Riskage til Ah-Yu "
gameforge.subquest_08._360_sayReward = "Du har modtaget en Riskage fra Yu-Rang. Tag det[ENTER]til Ah-Yu. Du kan finde hende og hendes barn i[ENTER]den f\248rste landsby. "
gameforge.subquest_08._370_npcChat = "Her er den Ris kage til dit barn. "
gameforge.subquest_08._380_say = "Du bragte mig Riskagen! Mange tak.[ENTER]Oh! Se, min baby gr\230der ikke mere og spiser[ENTER]lykkeligt sin kage. Du gjorde det. Tak for din[ENTER]hj\230lp! "
gameforge.subquest_08._390_sayReward = "Du f\229r 26.000 erfaringspoint.[ENTER]Du f\229r 10.000 Yang. "
gameforge.subquest_08._40_say = "Men ... Jeg kan ikke forlade dette sted, og[ENTER]barnet terroriserer hele kvarteret ... Det vil[ENTER]ikke tage lang! Er du sikker p\229, at du ikke har[ENTER]tid nok? "
gameforge.subquest_08._50_say = "Du har travlt?[ENTER]S\229 kom igen senere.[ENTER]Og stop med at gr\230de, s\248de barn. "
gameforge.subquest_08._60_say = "Jeg tror jeg bliver n\248dt til at sp\248rge en anden.[ENTER]Held og lykke p\229 rejsen! "
gameforge.subquest_08._70_say = "Mange tak! Det er en virkelig lettelse for mig. "
