gameforge.subquest_09._140_sayReward = "Du har modtaget 36.000 erfaringspoint.[ENTER]Du har modtaget 10.000 Yang.[ENTER]Du har modtaget et Smykke. "
gameforge.subquest_09._20_npcChat = "Den Gyldne \216kse "
gameforge.subquest_09._30_say = "Kan du huske min ven Deokbae? Jeg har lovet at[ENTER]smede ham en flot \248kse. Men desv\230rre holdt jeg[ENTER]ikke \248je med den og s\229 kom en kvindelig Hvid-Ed[ENTER]soldat og stjal den fra mig. Kan du bringe \248ksen[ENTER]tilbage? En Hvid-Ed soldat burde have den. Du[ENTER]skulle kunne genkende den. Der er ikke mange af[ENTER]dem. Jeg vil give dig en fantastisk bel\248nning for[ENTER]at g\248re det! "
