gameforge.subquest_09._60_say = "Jeg \248nsker virkelig denne \248kse! Vil vi se[ENTER]hinanden igen? Farvel. "
gameforge.subquest_09._70_say = "Tak for at du vil finde den.[ENTER]Pas godt p\229 dig, klanen driller nok. "
