gameforge.subquest_10._100_sayReward = "Sp\248rg smeden om h\229rn\229len. "
gameforge.subquest_10._10_targetVid = "Find H\229rn\229len "
gameforge.subquest_10._110_npcChat = "Den stj\229lende h\229rn\229l. "
gameforge.subquest_10._120_say = "Hvad? Hun tror, jeg stjal hendes h\229rn\229l? Det er[ENTER]utroligt! Hvem tror hun, jeg er? Jeg har arbejdet[ENTER]i min butik! Ah, jeg burde nok ikke fort\230lle dig[ENTER]dette, men v\229ben-handelsmanden var i[ENTER]handelsdamens butik for nylig. "
gameforge.subquest_10._130_makequestbutton = "Den stj\229lende h\229rn\229l. "
gameforge.subquest_10._140_sayReward = "Sp\248rg v\229ben-handelsmanden om den dekorative[ENTER]h\229rn\229l. "
gameforge.subquest_10._150_say = "Hvad? Du tror jeg har stj\229let h\229rn\229len? Nej,[ENTER]aldrig, det var ikke mig! \198rligt! Jeg har v\230ret i[ENTER]forretningen for at bes\248ge damen! Men hun var der[ENTER]ikke. I stedet s\229 jeg en Hvid-Ed bueskytte. Da[ENTER]hun s\229 mig, flygtede hun. M\229ske har hun stj\229let[ENTER]h\229rn\229len. "
gameforge.subquest_10._160_sayReward = "F\229 h\229rn\229len tilbage fra Hvid-Ed bueskytten! "
gameforge.subquest_10._170_sendLetter = "Du har fundet h\229rn\229len "
gameforge.subquest_10._180_targetVid = "G\229 til forretningen. "
gameforge.subquest_10._190_npcChat = "Jeg har din h\229rn\229l her. "
gameforge.subquest_10._200_say = "\197h, mange tak. Jeg er s\229 lykkelig, jeg har[ENTER]endelig f\229et min elskede h\229rn\229l tilbage! Du har[ENTER]allerede hjulpet mig s\229 ofte! Hvordan kan jeg[ENTER]nogensinde vise min p\229sk\248nnelse? Jeg har et[ENTER]Rytterkort. Jeg ved, det er ikke noget s\230rligt,[ENTER]men jeg har ikke brug for det mere, fordi jeg[ENTER]ikke bare kan forlade min butik.[ENTER]Tag det som et tegn p\229 min taknemmelighed. "
gameforge.subquest_10._20_say = "Lyt lige.. Jeg har sidst forladt min forretning,[ENTER]da jeg skulle hente noget vigtigt. Mens jeg var[ENTER]undervejs stjal nogen min ynglings h\229rn\229l. "
gameforge.subquest_10._210_sayReward = "Du har modtaget 60.000 erfaringspoint.[ENTER]Du har modtaget 10.000 Yang.[ENTER]Du har modtaget et : Rytterkort. "
gameforge.subquest_10._220_say = "Du har stadig ikke fundet min flotte h\229rn\229l?[ENTER]Jeg h\229ber du finder den. "
gameforge.subquest_10._230_select = "Stoppe "
gameforge.subquest_10._240_say = "\216nsker du at stoppe? "
gameforge.subquest_10._250_say = "Ja, de er absolut ikke et let bytte... M\229ske b\248r[ENTER]du tage en pause og pr\248ve igen senere? "
gameforge.subquest_10._260_say = "Hvor er min ynglings h\229rn\229l?[ENTER]Det var vel intet... farvel  "
gameforge.subquest_10._270_say = "Mange tak. Det betyder virkelig meget for mig. "
gameforge.subquest_10._30_say = "Min far gav mig den dekorative h\229rn\229l i[ENTER]f\248dselsdagsgave. Jeg elsker den. Jeg kan ikke[ENTER]forlade min forretning, ellers bliver der bare[ENTER]stj\229let endnu mere. Kunne du m\229ske g\229 og s\248ge[ENTER]den? Jeg tror det var smeden, som fortalte for[ENTER]lang tid siden, at han havde brug for en[ENTER]h\229rn\229l.  "
gameforge.subquest_10._40_select = "Jeg s\248ger den "
gameforge.subquest_10._50_say = "Sikker p\229 du vil afbryde opgaven? "
gameforge.subquest_10._60_say = "Vi ses n\230ste gang Farvel "
gameforge.subquest_10._70_say = "Hvor i alverden er min h\229rn\229l? Farvel ... "
gameforge.subquest_10._80_say = "Du s\248ger den for mig?[ENTER]Oh.. Tusind tak  "
gameforge.subquest_10._90_targetVid = "G\229 til Smeden "
gameforge.subquest_11 = {}
gameforge.subquest_11._100_targetVid = "Sp\248rg Yu-Hwan om Mirines bror. "
gameforge.subquest_11._10_targetVid = " Find min bror. "
gameforge.subquest_11._110_npcChat = "Har du set Mirines storebror? "
gameforge.subquest_11._120_say = "Jeg blev forelsket uden at vide, hvad k\230rlighed[ENTER]betyder ... Lalalaa ...[ENTER]Hvem er det du leder efter? Mirines bror? Vi[ENTER]havde en hurtig snak, f\248r han gik ind i bjergene[ENTER]for at lede efter nogle sj\230ldne urter. Jeg ved[ENTER]ikke, hvor han er nu. Landsbyen j\230ger g\229r ofte[ENTER]ind i bjergene. Hvorfor kan du ikke sp\248rge ham?[ENTER]La, la, la, k\230rlighed er trist, men smuk ... "
gameforge.subquest_11._130_targetVid = "Sp\248rg Yang-Shin om Mirines bror. "
gameforge.subquest_11._140_say = "Mirines bror? Ja, han var p\229 udkig efter urter i[ENTER]bjergene. Han var s\229 glad, da han fandt visse[ENTER]sj\230ldne urter. Han \248nskede at k\248be nogle nye[ENTER]kjoler til sin s\248ster med den fortjeneste, han[ENTER]fik fra dem. Han er virkelig rar. Jeg er sikker[ENTER]p\229 han vil v\230re tilbage om et par dage.[ENTER]Tror du ikke? "
gameforge.subquest_11._150_targetVid = "Fort\230l Mirine nyhederne. "
gameforge.subquest_11._160_npcChat = "Nyhederne om Mirines bror. "
gameforge.subquest_11._170_say = "Se, jeg har modtaget et brev fra min bror! Han[ENTER]har skrevet, at han fandt et sted med masser af[ENTER]urter og at det vil v\230re et stykke tid, f\248r han[ENTER]kommer hjem.[ENTER]Undskyld, jeg skulle ikke kede dig med dette.[ENTER]Her, det er ikke meget, men jeg h\229ber du[ENTER]acceptere det og tilgiver mig. Tak fordi du vil[ENTER]p\229tage dig den lange rejse. "
gameforge.subquest_11._180_sayReward = "Du har f\229et 122.000 erfaringspoints.[ENTER]Du har f\229et 5.000 Yang. "
gameforge.subquest_11._20_npcChat = " Find min bror. "
gameforge.subquest_11._30_say = "Kan jeg bede dig om en tjeneste?[ENTER]Min bror har v\230ret undervejs i lang tid, og jeg[ENTER]har ikke h\248rt noget fra ham. Jeg er lidt[ENTER]bekymret. Kunne du m\229ske g\229 ud og lede efter[ENTER]ham?  "
gameforge.subquest_11._40_say = "Min bror ville bes\248ge musikeren Yu-Hwan i den[ENTER]n\230ste landsby. Hvis du g\229r til Yu-Hwan, kan du f\229[ENTER]nogle nyheder om min bror. Tak p\229 forh\229nd. "
gameforge.subquest_11._50_select = "Ja det g\248r jeg "
gameforge.subquest_11._60_say = "Vil du opgive din s\248gning for altid ? "
gameforge.subquest_11._70_say = "Mange tak.[ENTER]S\248g efter ham for mig.[ENTER]Jeg er meget bekymret.[ENTER]Ses. "
gameforge.subquest_11._80_say = "Det er synd, at du ikke vil hj\230lpe...[ENTER]Ses. "
gameforge.subquest_11._90_say = "Du vil s\248ge ham for mig?[ENTER]Tusind tak, jeg er meget bekymret for ham.[ENTER]Held og lykke.  "
gameforge.subquest_12 = {}
gameforge.subquest_12._100_qSetTitle = "Mi-Jung af Hvid-Ed "
gameforge.subquest_12._10_targetVid = "Dr\230b Mi-Jung af Hvid-Ed "
gameforge.subquest_12._110_sayReward = "G\229 derefter tilbage til landsbyvagten. "
gameforge.subquest_12._120_sayTitle = "Mi-Jung af Hvid-Ed "
gameforge.subquest_12._130_sayReward = "G\229 og dr\230b Mi-Jung af Hvid-Ed. G\229 til[ENTER]landsbyvagten n\229r du er f\230rdig. "
gameforge.subquest_12._140_targetVid = "G\229 tilbage til landsbyvagten. "
gameforge.subquest_12._150_sayTitle = "Du har dr\230bt Mi-Jung fra Hvid Eid "
gameforge.subquest_12._160_sayReward = "G\229 tilbage til landsbyvagten og tag imod din[ENTER]bel\248nning. "
gameforge.subquest_12._170_npcChat = "Jeg dr\230bte Mi-Jung. "
gameforge.subquest_12._180_say = "Oh! Du er virkelig s\229 god som jeg har h\248rt.[ENTER]Fantastisk. Takket v\230re dig vil det v\230re meget[ENTER]nemmere at klare problemerne med Hvid-Ed nu. Godt[ENTER]arbejde! "
gameforge.subquest_12._190_sayReward = "Du har modtaget 122.000 erfaringspoint.[ENTER]Du har modtaget 20.000 Yang.[ENTER]Du har modtaget et S\248lv armb\229nd. "
gameforge.subquest_12._20_say = "Kom lige herover.[ENTER]Du ser ud til at v\230re en god k\230mper.[ENTER]Jeg har h\248rt en masse om dig fra[ENTER]kaptajnen.  "
gameforge.subquest_12._30_say = "Kan du g\229 efter Mi-Jung af Hvid-Ed?[ENTER]Det er sv\230rt for os at beskytte landsbyen mod de[ENTER]konstante angreb fra Hvid-Ed. Hvis vi dr\230ber[ENTER]Mi-Jung, en af deres ledere, s\229 vil situationen[ENTER]\230ndres. Byens sikkerhed ligger i dine h\230nder. Jeg[ENTER]stoler p\229 at du ikke fejler! "
gameforge.subquest_12._40_select = "Ja det g\248r jeg "
gameforge.subquest_12._50_select = "Ikke nu "
gameforge.subquest_12._60_say = "Du vil virkelig ikke hj\230lpe os?  "
gameforge.subquest_12._70_say = "Det er ikke det rigtige tidspunkt.[ENTER]Kom igen senere "
gameforge.subquest_12._80_say = "Hvis du ikke vil, kan der ikke g\248res noget ved[ENTER]det, Alts\229 g\229... "
gameforge.subquest_12._90_say = "du vil ikke hj\230lpe os?  "
gameforge.subquest_13 = {}
gameforge.subquest_13._100_targetVid = "G\229 til Ariyoung "
gameforge.subquest_13._10_targetVid = "Materialer til at fremstille v\229ben. "
gameforge.subquest_13._110_targetVid = "G\229 til Ah-Yu. "
gameforge.subquest_13._120_sayReward = "V\229ben-handelsmanden skal bruge din hj\230lp. Skaf[ENTER]jernmalm fra Uriel og linned fra Ariyoung til[ENTER]ham. "
gameforge.subquest_13._130_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_13._140_say = "Du bruger jernmalm? Du kan f\229 noget hvis du g\248r[ENTER]mig en tjeneste.  "
gameforge.subquest_13._150_say = "Jeg tabte noget, da jeg skulle l\248be for mit liv[ENTER]fra tigrene: Det er et bundt indeholdende vigtigt[ENTER]b\248ger, bundet sammen med nogle klude.[ENTER]Hvis jeg ikke har dem, kan jeg ikke forts\230tte min[ENTER]forskning p\229 Metin Stenene. Bring mig Pakken og[ENTER]du vil f\229 noget malm af mig. "
gameforge.subquest_13._160_npcChat = "Jeg har din pakke. "
gameforge.subquest_13._170_say = "Tak![ENTER]Jeg har mange gange bedt om en tjeneste. V\230rsgo![ENTER]Her har du jernmalm. Jeg h\229ber du kan bruge det[ENTER]til noget.  "
gameforge.subquest_13._180_say = "Hvad? Du har brug for endnu mere Jern malm? Det[ENTER]vokser ikke p\229 tr\230erne, ved du![ENTER]Jeg vil give dig noget mere Jern malm, men du[ENTER]bliver n\248dt til at g\248re mig en tjeneste f\248rst.[ENTER]Tigerne har stj\229let min taske. Jeg m\229tte l\248be for[ENTER]mit liv, og der var meget vigtige dokumenter i[ENTER]den. Hvis jeg ikke har dem, kan jeg ikke[ENTER]forts\230tte min forskning om Metin Stenene. Find[ENTER]tasken, som tigerne stjal fra mig. "
gameforge.subquest_13._190_say = "Har jeg allerede givet dig.[ENTER]Har du da glemt det igen?  "
gameforge.subquest_13._200_sayTitle = "Pakke fundet "
gameforge.subquest_13._20_npcChat = "Materiale til v\229ben "
gameforge.subquest_13._210_say = "Du har fundet Uriels taske.[ENTER]G\229 tilbage til Uriel "
gameforge.subquest_13._220_npcChat = "Giv mig h\248rl\230rred. "
gameforge.subquest_13._230_say = "Du har brug for Linned? Jeg har givet det til[ENTER]Ah-Yu. Vent![ENTER]Hvis du vil se hende alligevel kan du tage dette[ENTER]brev. Vi er gode venner, men p\229 grund af hendes[ENTER]barn har ikke set hinanden i et stykke tid. Jeg[ENTER]vil ogs\229 fort\230lle hende, at hun skulle give dig[ENTER]noget Linned ... Ja, dette hj\230lper alle![ENTER]Og give hende min hilsen. "
gameforge.subquest_13._240_say = "Ariyoung:[ENTER]Du har sikkert f\229et h\248rl\230rredet fra Ah-Yu,[ENTER]eller?  "
gameforge.subquest_13._250_npcChat = "Ariyoungs brev "
gameforge.subquest_13._260_say = "Et brev fra Ariyoung? Det er dejligt at h\248re fra[ENTER]hende efter al denne tid. Vi plejede at m\248des til[ENTER]en snak ganske ofte. Men sidst, har det v\230ret[ENTER]lidt sv\230rt. Vent et \248jeblik.[ENTER]Der st\229r her at du har brug for noget Linned?[ENTER]Ariyoung gav mig noget. Jeg kan give dig noget af[ENTER]det. Tak for at bringe mig hendes brev. Jeg vil[ENTER]svare hende med det samme ... "
gameforge.subquest_13._270_qSetTitle = "Lad os g\229 til v\229ben-handelsmanden "
gameforge.subquest_13._280_targetVid = "G\229 til v\229ben-handelsmanden. "
gameforge.subquest_13._290_sayTitle = "Aflever materialet "
gameforge.subquest_13._300_sayReward = "Jeg har alle materialerne.[ENTER]Afsted til v\229ben-handelsmanden. "
gameforge.subquest_13._30_say = "Hey, kan jeg bede dig om en tjeneste?[ENTER]Jeg pr\248ver at smede nye v\229bentyper. Det er ikke[ENTER]nemt at finde de passende materialer. Jeg har[ENTER]mange bestillinger og kan derfor selv ikke lede[ENTER]efter materialer. Kunne du s\248ge det for[ENTER]mig?  "
gameforge.subquest_13._310_say = "Godt klaret. Du er virkelig god og meget hurtig.[ENTER]Lad mig nu arbejde p\229 disse v\229ben![ENTER]*Clank, Clank*[ENTER]Her er de. Det er de nye v\229bentyper.[ENTER]Jeg gjorde mit bedste. Jeg h\229ber du kan lide dit[ENTER]nye v\229ben.[ENTER]Hav det sjovt med det! "
gameforge.subquest_13._320_sayTitle = "Bel\248nning: "
gameforge.subquest_13._330_sayReward = "Du har modtaget 122.000 erfaringspoint.[ENTER]Du har modtaget 20.000 Yang. "
gameforge.subquest_13._340_sayReward = "Du har modtaget et Bredsv\230rd +3 "
gameforge.subquest_13._350_sayReward = "Du har modtaget en Sakse dolk +3. "
gameforge.subquest_13._360_sayReward = "Du har modtaget en P\229fuglens vifte +3. "
gameforge.subquest_13._40_say = "Naturligvis vil du f\229 noget for din indsats. N\229r[ENTER]mine v\229ben er f\230rdige, vil du f\229 et af dem. Jeg[ENTER]har brug for f\248lgende materialer: Jernmalm og[ENTER]h\248rl\230rred. Du f\229r jernmalm hos Uriel og h\248rl\230rred[ENTER]hos Ariyoung. Sig til n\229r du har f\229et fat i alle[ENTER]materialer.  "
gameforge.subquest_13._50_say = "Er du sikker p\229 du ikke vil gennemf\248re denne[ENTER]opgave? "
gameforge.subquest_13._60_say = "Jeg tror det var for meget for dig.[ENTER]Kom tilbage n\229r du har mere tid! "
gameforge.subquest_13._70_say = "Hvis du ikke \248nsker det, kan der ikke g\248res noget[ENTER]ved det.[ENTER]Farvel. "
gameforge.subquest_13._80_say = "Meget godt![ENTER]S\229 snart v\229benet er f\230rdig, vil du f\229 en af mig.[ENTER]Held og lykke. "
gameforge.subquest_13._90_sendLetter = "Kig efter materialer "
gameforge.subquest_15 = {}
gameforge.subquest_15._100_targetVid = "G\229 tilbage til Byvagten "
gameforge.subquest_15._10_targetVid = "Eun-Jung fra Hvid Eid "
gameforge.subquest_15._110_sayReward = "Du har dr\230bt Eun-Jung fra Hvid Eid. G\229 tilbage[ENTER]til Byvagten og rapportere til ham. "
gameforge.subquest_15._120_say = "Du er fantastisk! Du er endnu bedre end jeg[ENTER]forventede. Vi var ikke i stand til at g\248re noget[ENTER]ved de to ledere af Hvid Eid, og du besejrede dem[ENTER]begge lige s\229dan. "
gameforge.subquest_15._130_say = "Det er utroligt. Du modtager en passende[ENTER]bel\248nning. V\230r venlig at tage dette og forts\230t[ENTER]med at arbejde for freden i landsbyen! "
gameforge.subquest_15._140_sayReward = "Du har modtaget 150.000 erfaringspoint.[ENTER]Du har modtaget 25.000 Yang.[ENTER]Du har modtaget en Guld Halsk\230de +4. "
gameforge.subquest_15._20_say = "Kom her et \248jeblik.[ENTER]Jeg har h\248rt en masse om dig fra kaptajn.[ENTER]Du synes at v\230re frygtl\248s. Derfor har jeg brug[ENTER]for din hj\230lp igen: De hvide Eid har opf\248rt sig[ENTER]v\230rre end nogensinde f\248r. "
gameforge.subquest_15._30_say = "Du har besejret Mi-Jung, lederen af Hvid Eid. Men[ENTER]vi er stadig i fare! Den fare fra De Hvide Eid er[ENTER]ikke faldet, men er v\230rre end nogensinde! "
gameforge.subquest_15._40_say = "For at afslutte dette, har vi v\230ret n\248dt til at[ENTER]fjerne de f\248rende Eun-Jung. Resten af dem b\248r[ENTER]ikke v\230re noget problem.[ENTER]G\229 ud og dr\230be Eun-Jung! Vores sk\230bne er i dine[ENTER]h\230nder! "
gameforge.subquest_15._50_sayTitle = "Landsby vagt: "
gameforge.subquest_15._60_say = "Kommer du tilbage senere? Du er den rigtige[ENTER]person til dette. "
gameforge.subquest_15._70_say = "Du kan ikke g\248re det? Ah godt. Vi ses snart. "
gameforge.subquest_15._80_say = "Jeg vidst du ville hj\230lpe os.[ENTER]Dr\230b Eun-Jung, resten klare vi.[ENTER]Held og lykke. "
gameforge.subquest_15._90_sayReward = "Dr\230b leder Eun-Jung. Forh\229bentlig vil Hvid Eid[ENTER]v\230re stille s\229. "
gameforge.subquest_16 = {}
gameforge.subquest_16._100_qSetTitle = "Sp\248rg Yu-Hwan "
gameforge.subquest_16._10_targetVid = "S\248g det tunge kavaleri "
gameforge.subquest_16._110_targetVid = "G\229 til Yu-Hwan "
gameforge.subquest_16._120_say = "Livet er s\229 vidunderligt - k\230rlighed er s\229[ENTER]vidunderlig ...[ENTER]\197h, dig igen! Hvad vil du nu? Information om det[ENTER]tunge kavaleri? Hvorfor sp\248rger du mig om dem?[ENTER]Kaptajnen m\229 have store planer? "
gameforge.subquest_16._130_sayTitle = "Yu-Hwan: "
gameforge.subquest_16._140_say = "N\230ppe nogen originale tekster fra dette tidspunkt[ENTER]har overlevet, men jeg kender nogle sange om det[ENTER]tunge kavaleri. Bare et minut, jeg vil lige tune[ENTER]mit instrument ...[ENTER]\197h, du har travlt? I dag tager ingen sig tid til[ENTER]at lytte mere ...[ENTER]N\229 ja. Groft sagt Isup`s kavaleri var n\230sten[ENTER]uovervindelig. Ekstremt godt uddannede Soldater,[ENTER]tung rustning og samtidig hurtigt og mobile. "
gameforge.subquest_16._150_say = "Det var den bedste h\230r dette kontinent nogensinde[ENTER]havde set. Mange riger faldt fordi intet kunne[ENTER]stoppe kavaleriet. Det ville v\230re det samme i[ENTER]dag. Men du skal bruge skrappe tr\230ningsmetoder og[ENTER]en masse h\248jkvalitets jern for at m\248nstre s\229dan[ENTER]en h\230r. Du b\248r sp\248rge handelsmanden og den l\230rte[ENTER]Uriel om det. De kender sikkert flere detaljer. "
gameforge.subquest_16._160_makequestbutton = "G\229 til handelsmanden "
gameforge.subquest_16._170_qSetTitle = "Det tunge kavaleri "
gameforge.subquest_16._180_targetVid = "Handelsmand: "
gameforge.subquest_16._190_sayReward = "Musikeren Yu-Hwan siger at handelsmanden og den[ENTER]l\230rte Uriel m\229ske har informationer om det[ENTER]pansrede kavaleri. G\229 f\248rst til handelsmanden. "
gameforge.subquest_16._200_sayTitle = "Handelsmand: "
gameforge.subquest_16._20_npcChat = "Det tunge kavaleri "
gameforge.subquest_16._210_say = "Hvad vil du fra en simpel handelsmand som mig?[ENTER]Jern panseret fra det pansrede kavaleri? Det er[ENTER]gamle historier. Hvem er interesseret i dem? Jeg[ENTER]bliver n\248dt til at skaffe til dagen og vejen, jeg[ENTER]kan ikke bare st\229 og snakke hele dagen! "
gameforge.subquest_16._220_say = "Det bliver sv\230rere og sv\230rere at f\229 enderne til[ENTER]at m\248des. Siden disse sten begyndte at falde ned[ENTER]fra himlen, har jeg ... Hvad siger du?[ENTER]\197h ja, det kavaleri.[ENTER]S\229 vidt jeg ved, havde de s\230rlige rustninger og[ENTER]at producere dem kr\230vede s\230rlig viden. De var de[ENTER]bedste rustning der nogensinde er lavet![ENTER]Standard knive eller endda pile kunne ikke[ENTER]gennemtr\230nge disse perfekt rustninger! "
gameforge.subquest_16._230_say = "Du kan forestille dig hvor vigtig rustningen var[ENTER]med de penge der var n\248dvendige for at s\230tte[ENTER]kavaleriet op. Det siges at de opbrugte hele[ENTER]kongerigets skatte! Hvis jeg solgte s\229dan en[ENTER]rustning ville jeg v\230re sikret resten af livet! "
gameforge.subquest_16._240_say = "Nutildags kan rustninger endda laves af Metin[ENTER]sten. Med denne nye form for rustning, er det[ENTER]ikke l\230ngere blot en dr\248m at have det tunge[ENTER]kavaleri ligesom i gamle dage. Men jeg taler for[ENTER]meget. Jeg er n\248dt til at komme videre. Vi ses! "
gameforge.subquest_16._250_sayTitle = "Det tunge kavaleri "
gameforge.subquest_16._260_say = "Den Handelsmand vidste noget om jern rustninger[ENTER]af det tunge kavaleri. Begiv dig til den n\230ste[ENTER]landsby og tal med forskeren Uriel om tr\230ningen. "
gameforge.subquest_16._270_sayTitle = "Uriel: "
gameforge.subquest_16._280_say = "Hvad bringer dig her? Den tunge kavaleri?[ENTER]Naturligvis ved jeg noget om dem. Alle g\248r. Denne[ENTER]h\230r vil g\229 over i historien som en af de bedste[ENTER]af alle tider! En masse af, hvad der bliver sagt[ENTER]kan v\230re overdrevn, men disse beredne soldater[ENTER]var meget frygtede. Og med rette. "
gameforge.subquest_16._290_say = "Den tunge kavaleri var overlegen i forhold til[ENTER]alle andre, prim\230rt p\229 grund af sin intense[ENTER]tr\230ning. Kun de allerbedste var i stand til at[ENTER]afslutte uddannelsen, mange af dem d\248de. Jeg tror[ENTER]at hvis den samme tr\230ning blev brugt nutildags,[ENTER]ville der ikke v\230re en eneste soldat tilbage n\229r[ENTER]de var f\230rdige. "
gameforge.subquest_16._300_say = "Jeg vil give dig nogle detaljerede oplysninger om[ENTER]tr\230ningen, s\229 vil du ikke v\230re helt uvidende. Jeg[ENTER]ved, at nogle forf\230rdelige krige foreg\229r i[ENTER]\248jeblikket, men jeg er ikke sikker p\229, at det en[ENTER]god id\233 at oprette en frygtindgydende h\230r som Det[ENTER]tunge kavaleri igen. "
gameforge.subquest_16._30_say = "Jeg har en ny opgave til dig.[ENTER]Du har f\229et ordre om at samle informationer om[ENTER]det tunge kavaleri. De var for lang tid siden de[ENTER]vigtigste rytter under kongen Isup, grundl\230ggeren[ENTER]og foreneren af kontinentet. Det kavaleri blev[ENTER]frygtet af andre lande pga. deres utrolige[ENTER]hastighed og angrebsstyrke.  "
gameforge.subquest_16._310_say = "G\229 til kaptajnen og fort\230l ham hvad du har fundet[ENTER]ud af omkring det tunge[ENTER]kavaleri.  "
gameforge.subquest_16._320_makequestbutton = "G\229 til kaptajnen "
gameforge.subquest_16._330_npcChat = "Fort\230l om det tunge kavaleri "
gameforge.subquest_16._340_sayTitle = "Kaptajn "
gameforge.subquest_16._350_say = "Har du v\230ret i stand til at finde noget ud af[ENTER]det? Skynd dig at fort\230l! ...[ENTER]Hmm, det er meget interessant. S\229 det er ikke[ENTER]andet end tunge rustninger og h\229rd tr\230ning? S\229 er[ENTER]det muligt! En s\229dan h\230r kunne genforene tre[ENTER]Kongeriger! "
gameforge.subquest_16._360_say = "Men jeg skal bruge en masse penge. Og en masse[ENTER]gode smede. Og rekrutter, der frivilligt g\229r[ENTER]gennem helvede for at blive det bedste af det[ENTER]bedste! Nej, nej! Kig ikke p\229 mig p\229 den m\229de.[ENTER]Ikke v\230r bekymret, du har gjort nok lige for[ENTER]tiden. "
gameforge.subquest_16._370_say = "Her tag din bel\248nning, og en pause.[ENTER]Vi ses senere! "
gameforge.subquest_16._380_sayReward = "Du har f\229et 150.000 erfaringspoints.[ENTER]Du har f\229et 30.000 Yang.[ENTER]Du har f\229et Guld \248rering. "
gameforge.subquest_16._40_say = "Med de oplysninger, du indsamlede vil vi v\230re i[ENTER]stand til at styrke vores milit\230re magt. Bes\248g[ENTER]musikeren Yu-Hwan f\248rst. Jeg er sikker p\229, at han[ENTER]kender ganske meget om Isup`s kavaleri. "
gameforge.subquest_16._50_say = "Hmm, som du vil. Vi ses senere s\229. "
gameforge.subquest_16._60_say = "Vil jeg nogensinde f\229 kommando over et kavaleri[ENTER]regiment som det?[ENTER]V\230r forsigtig. "
gameforge.subquest_16._70_say = "Tak, pas godt p\229 dig selv.  "
gameforge.subquest_16._80_sayTitle = "Det tunge kavaleri "
gameforge.subquest_16._90_sayReward = "Kaptajnen er p\229 udkig efter information om kong[ENTER]Isuo`s legendariske kavaleri. Musikeren Yu-Hwan[ENTER]har sandsynligvis nogle oplysninger. G\229 ud og[ENTER]sp\248rge ham. "
gameforge.subquest_17 = {}
gameforge.subquest_17._100_targetVid = "Tal med handelsdamen "
gameforge.subquest_17._10_targetVid = "Historien om Ariyoung's \198gtemand "
gameforge.subquest_17._110_say = "G\229 til handelsdamen ved landhandlen og sp\248rg om[ENTER]Ariyoungs mand. "
gameforge.subquest_17._120_npcChat = "Ariyoung`s mand "
gameforge.subquest_17._130_say = "Det er en s\248rgelig historie. Hun ved ikke hvad[ENTER]der skete med hendes mand? Han er et sted hvor[ENTER]ingen nogensinde kommer tilbage fra...[ENTER]Han var bare p\229 vej tilbage til landsbyen en dag,[ENTER]han blev bortf\248rt og dr\230bt af den Sort vind[ENTER]bande. "
gameforge.subquest_17._140_say = "Hun bliver knust n\229r du fort\230ller hende det. De[ENTER]elskede hinanden s\229 meget. Men hun bliver n\248dt[ENTER]til at finde ud af det. Ellers vil hendes[ENTER]usikkerhed sl\229 hende ihjel. "
gameforge.subquest_17._150_targetVid = "Trist nyt "
gameforge.subquest_17._160_sayTitle = "Ariyoung: "
gameforge.subquest_17._170_say = "Handelsdamen har d\229rlige nyheder. G\229 til Ariyoung[ENTER]og fort\230lle hende om hendes mands d\248d. "
gameforge.subquest_17._180_npcChat = "Din mand er d\248d ... "
gameforge.subquest_17._190_say = "Hvad ... hvad siger du?! Han ... han blev dr\230bt[ENTER]af Sortvind banden? Oh ... ingen ... han er[ENTER]d\248d... Jeg ved ikke hvad jeg skal g\248re uden ham! "
gameforge.subquest_17._200_say = "Kan du bringe mig liget, af min afd\248de \230gtemand?[ENTER]S\229 jeg kan tage afsked. Hvis dette ikke er[ENTER]muligt, s\229 m\229ske finde alle ting han havde p\229[ENTER]sig? Ligemeget hvad, bare jeg har et minde.[ENTER]Goo-Pae's af sortvind-banden er nok dem der har[ENTER]tingene. Bring mig noget. "
gameforge.subquest_17._20_say = "Der er g\229et lang tid, siden jeg sidst har h\248rt[ENTER]noget fra min mand.[ENTER]Forh\229bentlig er der ikke sket ham noget.[ENTER]Jeg ved godt at bekymringer ikke hj\230lper, men jeg[ENTER]er s\229 bange. Jeg kan f\229 ro i mit hjerte. "
gameforge.subquest_17._210_select = "Ja, jeg hj\230lper dig. "
gameforge.subquest_17._220_say = "Kom igen, n\229r du har overvejet det en ekstra[ENTER]gang.. "
gameforge.subquest_17._230_say = "Du har ikke fundet noget? Tak alligevel![ENTER]Oh, stakkels mig! "
gameforge.subquest_17._240_say = "Jeg kan ikke udtrykke det i ord, hvor taknemmelig[ENTER]jeg er for din hj\230lp! Jeg vil bede for dig. "
gameforge.subquest_17._250_sendLetter = "Dr\230b Goo-Pae's "
gameforge.subquest_17._260_say = "Sort vind banden har r\248vet og dr\230bt Ariyoung`s[ENTER]\230gtemand. Dr\230b nogle Goo-Pae for at f\229 et minde[ENTER]om Ariyoungs \230gtemand. "
gameforge.subquest_17._270_npcChat = "Omkring din \230gtemand... "
gameforge.subquest_17._280_say = "Hvordan gik det? Har du fundet et minde om min[ENTER]\230gtemand? Han bet\248d alt for mig. Noget som helst? "
gameforge.subquest_17._290_select = "Ikke endnu. Jeg s\248ger stadig! "
gameforge.subquest_17._300_say = "Goo-Pae af sort-vind er ikke nem. Tag en lille[ENTER]pause. Tak for din hj\230lp. "
gameforge.subquest_17._30_say = "Jeg h\229ber at den blandet handelsdame har h\248rt[ENTER]noget om min \230gtemand. Hun har s\229 mange kunder,[ENTER]m\229ske har nogen fortalt hende[ENTER]noget.  "
gameforge.subquest_17._310_say = "S\229 jeg bliver n\248dt til at vente p\229 en anden helt,[ENTER]der vil hj\230lpe mig. Farvel. "
gameforge.subquest_17._320_say = "Oh, tusind tak.[ENTER]V\230r s\229 venlig at levere mig et minde om min[ENTER]\230gtemand. "
gameforge.subquest_17._330_sendLetter = "Ariyoungs Vielsesring "
gameforge.subquest_17._340_targetVid = "G\229 til Ariyoung "
gameforge.subquest_17._350_sayTitle = "G\229 til Ariyoung "
gameforge.subquest_17._360_say = "Du har fundet Ariyoung's mand's vielsesring p\229 en[ENTER]af de dr\230bte Goo-Paes. Du kan ikke forestille dig[ENTER]et bedre minde.[ENTER]Tag den Ring til Ariyoung. "
gameforge.subquest_17._370_npcChat = "Jeg har fundet denne Ring. "
gameforge.subquest_17._380_say = "Denne ring... er... min \230gtemands! Tusind tak![ENTER]Nu kan min mand finde fred og ro. Jeg vil begrave[ENTER]ringen sammen med en brev fra mig![ENTER]Fra nu af vil jeg leve alene.[ENTER]Men i det mindste har jeg f\229et vielsesringen![ENTER]Det er en dejlig f\248lelse.. jeg takker dig s\229[ENTER]mange, mange gange. "
gameforge.subquest_17._390_sendLetter = "Mission afsluttet! "
gameforge.subquest_17._400_say = "Dine handlinger for Ariyoung fort\230lles vidt[ENTER]omkring. Mange folk v\230rdiger din[ENTER]hj\230lp.  "
gameforge.subquest_17._40_select = "Jeg g\229r til handelsdamen. "
gameforge.subquest_17._410_sayReward = "Du f\229r 300.000 erfaring. "
gameforge.subquest_17._420_sayReward = "Du har modtaget 10.000 Yang. "
gameforge.subquest_17._50_select = "Nej, desv\230rre ingen tid. "
gameforge.subquest_17._60_say = "Vil du opgive din s\248gning for altid ? "
gameforge.subquest_17._70_say = "Kom igen, n\229r du har overvejet det en ekstra[ENTER]gang.. "
gameforge.subquest_17._80_say = "Du har ikke tid?[ENTER]Ikke tid til s\229dan en let opgave?[ENTER]Okay, s\229 ... "
gameforge.subquest_17._90_say = "Mange tak for din venlighed.[ENTER]Aaah, hvor er dog min \230gtemand.  "
gameforge.subquest_18 = {}
gameforge.subquest_18._100_say = "S\248g manden, der l\230ser digte og b\230rer laser, og[ENTER]tal med ham. "
gameforge.subquest_18._10_targetVid = "Hvor Har Han Gemt Sig? "
gameforge.subquest_18._110_npcChat = "Hvor er min \230gtemand? "
gameforge.subquest_18._120_say = "Jeg ved ikke hvor han kunne gemme sig.[ENTER]Han er blevet s\229 god til det, at det er virkelig[ENTER]sv\230rt at finde ham. Burde jeg virkelig h\230nge en[ENTER]klokke om halsen p\229 ham, som handelsmanden[ENTER]anbefalede? "
gameforge.subquest_18._130_npcChat = "Find Soon! "
gameforge.subquest_18._140_say = "Du h\248re et vidunderligt digt. fortryllet af[ENTER]ordene, vil du f\248lge stemmen indtil du finder en[ENTER]mand i laser.[ENTER][ENTER]Dette m\229 v\230re Aranyos mand![ENTER][ENTER]Du er lige ved at vende rundt, og drage tilbage[ENTER]til Aranyo da han griber din skulder. "
gameforge.subquest_18._150_say = "Du er ikke herfra.[ENTER]Har min kone sendt dig?[ENTER]Oh nej! Han ved, hvem jeg er! Hvad skal jeg bare[ENTER]sige? "
gameforge.subquest_18._153_select = "Jeg kom lige forbi. "
gameforge.subquest_18._157_select = "I grunden nu "
gameforge.subquest_18._160_say = "Ah. Hvor dejligt at l\230re dig at kende, ha, ha.[ENTER]Godt vejr, ik\180?[ENTER]Har du i den seneste tid l\230st en god bog?[ENTER]Jeg l\230ser fortiden en af Oja.[ENTER]Den kan jeg varmt anbefale.  "
gameforge.subquest_18._170_say = "Jeg har ret, har jeg ikke? Min kones h\229n bliver[ENTER]s\229 slem nu, at jeg ikke kan l\230se i fred hjemme[ENTER]mere. Hun forst\229r mig bare ikke, og bliver ved[ENTER]med at sende folk efter mig... Du fandt mig her,[ENTER]men jeg kan drage et andet sted hen n\229r som[ENTER]helst. Hvad hvis du holdte hemmeligt at du s\229 mig[ENTER]her? Jeg vil give dig nogle gode jagt tips hvis[ENTER]du g\248r. "
gameforge.subquest_18._180_sendLetter = "G\229 tilbage til Aranyo "
gameforge.subquest_18._190_say = "G\229 tilbage til Aranyo og fort\230l at du ikke kunne[ENTER]finde Soon. "
gameforge.subquest_18._200_npcChat = "Soons hemmelighed. "
gameforge.subquest_18._20_sayTitle = "Aranyo: "
gameforge.subquest_18._210_say = "Du kunne ikke finde ham?[ENTER]Jeg har endda sat nogle f\230lder op. Hvor fanden[ENTER]har han gemt sig? Jeg er bare s\229 optaget af andre[ENTER]ting. Sikke en elendig sk\230bne.  "
gameforge.subquest_18._220_sendLetter = "Tilbage til Soon "
gameforge.subquest_18._230_say = "Drag tilbage til soon og fort\230l ham at du var[ENTER]succesfuld. "
gameforge.subquest_18._240_npcChat = "Her er jeg. "
gameforge.subquest_18._250_say = "Gik alt godt? Du redede mit liv! Tag dette[ENTER]eventyr. Som lovet her er din bel\248nning. "
gameforge.subquest_18._260_sayReward = "Du har modtaget 7.000 erfaringspoint. "
gameforge.subquest_18._270_sayReward = "Du har modtaget 10.000 Yang. "
gameforge.subquest_18._280_say = "G\229 tilbage til Aranyo og fort\230l hende hvor du har[ENTER]fundet Soon. "
gameforge.subquest_18._290_npcChat = "Gemmelegen er sv\230r "
gameforge.subquest_18._300_say = "Tusind tak, fordi du ikke fortalte hvor jeg[ENTER]gemmer mig.[ENTER]Det er sv\230rt at gemme sig, s\229 min kone ikke[ENTER]finder mig. Jeg \248nsker jo bare at l\230se[ENTER]lidt.  "
gameforge.subquest_18._30_say = "Min \230gtemand er meget irriterende. Han kalder sig[ENTER]selv for en af de l\230rte! Mens vi skal k\230mpe for[ENTER]vores daglige br\248d, l\230ser han bare b\248ger. Har du[ENTER]set ham? Hvorfor har jeg dog giftet mig med en[ENTER]s\229dan en bogorm? "
gameforge.subquest_18._310_npcChat = "Soons gemmested "
gameforge.subquest_18._320_say = "Du har fundet ham?[ENTER]Tusind tak! Hvis han opdager, at han er blevet[ENTER]fundet, pr\248ver han m\229ske at flygte igen. Jeg[ENTER]tager dertil med det samme. Det er p\229 tide jeg[ENTER]f\229r ham! Og du f\229r dette som bevis p\229 min[ENTER]taknemmelighed. Bare vent, solstr\229le! "
gameforge.subquest_18._33_select = "Jeg vil hj\230lpe dig. "
gameforge.subquest_18._37_select = "Til det har jeg ingen tid. "
gameforge.subquest_18._40_say = "\216nsker du af afslutte opgaven? "
gameforge.subquest_18._50_say = "Okaaaay... M\229ske pr\248ver du at finde ham senere. "
gameforge.subquest_18._60_say = "M\229ske finder du ham alligevel... "
gameforge.subquest_18._70_say = "Det ville v\230re meget dejligt. N\229r du ser en[ENTER]fattig forfatter, s\229 fort\230l mig det. Han er[ENTER]formodentlig den eneste i hele landsbyen. Han[ENTER]kunne skrive et digt i dette \248jeblik og \248nsker[ENTER]m\229ske at v\230re alene. N\229r han finder ud af at jeg[ENTER]leder efter ham, fors\248ger han m\229ske at flygte. S\229[ENTER]v\230r forsigtig. "
gameforge.subquest_18._80_sendLetter = "S\248g Soon. "
gameforge.subquest_18._90_sayTitle = "S\248g bogormen "
gameforge.subquest_19 = {}
gameforge.subquest_19._100_sendLetter = "Find en ulvepels "
gameforge.subquest_19._10_npcChat = "Led efter en st\248vkost "
gameforge.subquest_19._110_sayTitle = "Find en ulvepels "
gameforge.subquest_19._120_sayReward = "Find en ulvepels, s\229 den gammel dame kan g\248re[ENTER]rent i hendes hus, og undg\229 at hoste s\229 meget.[ENTER]Du finder den hos gr\229ulvene. "
gameforge.subquest_19._130_targetVid = "G\229 tilbage til den gamle dame "
gameforge.subquest_19._140_npcChat = "Lever ulvepels "
gameforge.subquest_19._150_say = "En ulvepels, det er godt... Ohh, nej. Denne er[ENTER]ikke god. Drag tilbage til Gr\229ulvene. Du er m\229ske[ENTER]i stand til at finde en bedre en. "
gameforge.subquest_19._160_say = "Jeg har brug for en st\248vkost. Undskyld, men det[ENTER]der kan jeg ikke bruge til[ENTER]noget.  "
gameforge.subquest_19._170_select = "Jeg pr\248ver igen, "
gameforge.subquest_19._180_select = "gider ikke mere. "
gameforge.subquest_19._190_say = "\216nsker du virkelig at afbryde opgaven? "
gameforge.subquest_19._200_say = "bare kom tilbage senere. "
gameforge.subquest_19._20_say = "Host! Host! Ohh k\230re, hosten vil blive min d\248d.[ENTER]Jeg har ingen ting at g\248re mit hus rent med, s\229[ENTER]alt st\248vet bliver h\230ngene her. Ohh, hvorfor har[ENTER]jeg ikke en st\248vekost? Min s\248n tog den, for at[ENTER]arbejde p\229 et eller andet v\229ben. Mit eget k\248d og[ENTER]blod sl\229r mig ihjel! "
gameforge.subquest_19._210_say = "Jeg ved det er sv\230rt, men v\230r venlig og pr\248v igen. "
gameforge.subquest_19._220_say = "Tak for hj\230lpen. "
gameforge.subquest_19._230_say = "Du er da eventyreren der var her for nyligt![ENTER]Hvordan lyder min hoste? Host, host! Som du kan[ENTER]h\248re har det ikke rigtigt forbedret sig. Huset er[ENTER]stadig fuld af st\248v.[ENTER][ENTER]Ohh? Du har en ulvepels med til mig? Hvor[ENTER]pr\230gtigt! Du er meget nobelt indstillet. Vent et[ENTER]\248jeblik, jeg er tilbage om et sekund. "
gameforge.subquest_19._240_say = "En, to, en, to. Den ene fod foran den anden...[ENTER]Rigtigt, her er jeg igen. Mange tusind tak![ENTER]Endelig, kan jeg g\248re mit hus ordentligt rent.[ENTER]Jeg har ogs\229 fundet noget jeg gerne vil give dig.[ENTER]Jeg ved virkelig ikke om det er noget v\230rd, men[ENTER]m\229ske er det brugbart for dig. Endnu engang tak.[ENTER]Farewell! "
gameforge.subquest_19._250_sendLetter = "En st\248vet genstand "
gameforge.subquest_19._260_say = "Din bel\248nning best\229r af en stor, tyk genstand som[ENTER]er d\230kket med et tykt lag st\248v og er sv\230rd at[ENTER]identificere. Nysgerrige, b\248rster du st\248vet af. "
gameforge.subquest_19._270_say = "Det er en gammel rusting af h\248j kvalitet,[ENTER]fremstillet af en veluddannet smed. Sikke et[ENTER]held!  "
gameforge.subquest_19._280_say = "Der er et rygte. Det er gammelt men kan stadig[ENTER]bruges. Well, det er i det mindste noget! "
gameforge.subquest_19._290_say = "Det er et s\230t rygter, men trods alt dit h\229b,[ENTER]viste det sig at var totalt v\230rdil\248s. "
gameforge.subquest_19._300_sayReward = "Du har f\229et 15.000 erfaringspoints. "
gameforge.subquest_19._30_select = "Jeg finder en til dig. "
gameforge.subquest_19._40_say = "Alt er st\248vet! Jeg har brug for en fjer kost. Kan[ENTER]du hj\230lp mig? "
gameforge.subquest_19._50_say = "Det er et stykke tid siden, men jeg tror at min[ENTER]mand, m\229 han hvile i fred, lavede det af[ENTER]ulvepels.[ENTER]Host! Host![ENTER][ENTER]Kunne du m\229ske finde et ulveskind til en fattig[ENTER]gammel dame? Du kan f\229 et fra en Gr\229 ulv. Du vil[ENTER]virkelig hj\230lpe mig meget. "
gameforge.subquest_19._60_say = "\216nsker du virkelig at afbryde? "
gameforge.subquest_19._70_say = "Hovsa, det var \230rgerligt, men jeg regnede med du[ENTER]ville hj\230lpe mig. M\229ske overvejer du det en[ENTER]ekstra gang - s\229 kan du sagtens komme forbi[ENTER]igen.  "
gameforge.subquest_19._80_say = "Hvilken bel\248nning kan du forvente fra en gammel,[ENTER]fattig dame?  "
gameforge.subquest_19._90_say = "Det er ikke nemt at f\229 fat i s\229dan en ulvepels,[ENTER]men jeg vil pr\248ve. For jeg vil jo n\229r alt kommer[ENTER]til alt gerne blive en stor helt en dag! "
gameforge.subquest_20 = {}
gameforge.subquest_20._100_say = "Vil du afbryde s\248gningen? "
gameforge.subquest_20._10_targetVid = "Hj\230lp Ah-Yu! "
gameforge.subquest_20._110_say = "Det er i orden. Kom igen, n\229r du har[ENTER]tid.  "
gameforge.subquest_20._120_say = "Du er en bangebuks.[ENTER]Du ville nok alligevel l\248be v\230k, hvis du m\248der de[ENTER]vilde! Farvel.  "
gameforge.subquest_20._130_say = "Tak du fordi du hjalp mig. Det er tre spyd. "
gameforge.subquest_20._140_sendLetter = "Spyddene "
gameforge.subquest_20._150_targetVid = "Ah-Yu: "
gameforge.subquest_20._160_sayTitle = "De 3 spyd "
gameforge.subquest_20._170_say = "Du har fundet alle 3 spyd tilh\248rende Ah-Yus[ENTER]\230gtemanden. G\229 nu tilbage til Ah-Yu. "
gameforge.subquest_20._180_sayTitle = "S\248g spydene! "
gameforge.subquest_20._190_say = "Vild infanterist, vild hellig, vild bueskytte og[ENTER]vild general: De har alle spyd. S\248g efter[ENTER]\230gtemandens spyd iblandt deres. "
gameforge.subquest_20._200_sayReward = "Du skal finde 3 spyd og bringe dem tilbage til[ENTER]Ah-Yu.[ENTER](Antal spyd: %s ) "
gameforge.subquest_20._20_npcChat = "Erindringer om \230gtemanden "
gameforge.subquest_20._210_npcChat = "Hvor kan jeg finde spydene? "
gameforge.subquest_20._220_say = "Det er meget sandsynligt at de vilde har min[ENTER]mands spyd. Hvem ved, forh\229bentligt har de ikke[ENTER]solgt det. Det er meget gode spyd.[ENTER][ENTER]Forts\230tter du med at lede efter dem? "
gameforge.subquest_20._230_select = "Ja, jeg vil forts\230tte med at s\248ge. "
gameforge.subquest_20._240_say = "Er du en kujon! Jeg g\229r ud fra at jeg ikke kan[ENTER]g\248re noget ved det. Jeg er n\248d til at g\229 og lede[ENTER]selv.[ENTER][ENTER]\216nsker du virkelig at afbryde s\248gningen? "
gameforge.subquest_20._250_select = "Ja, det er sandt "
gameforge.subquest_20._260_say = "Jeg ville g\248re det selv, men min baby beh\248ver[ENTER]mig. Kom tilbage n\229r du har fundet spydene! "
gameforge.subquest_20._270_say = "Du har opgivet jagten efter Ah-Yus \230gtemands spyd. "
gameforge.subquest_20._280_say = "Mange tak. Jeg er sikker p\229 du vil finde dem[ENTER]snart! "
gameforge.subquest_20._290_npcChat = "Aflever \230gtemandens spyd "
gameforge.subquest_20._300_sayTitle = "Ah-Yu: "
gameforge.subquest_20._30_say = "Ohh, gr\230d venligst ikke elskede. Mor har ogs\229[ENTER]bekymringer. Hvis du forts\230tter med at gr\230de som[ENTER]dette, vil ingen af os v\230re i stand til at falde[ENTER]ned. Stop venligst med at gr\230de. "
gameforge.subquest_20._310_say = "Du har fundet en, det var fantastisk! Men kan du[ENTER]lede efter de andre to ogs\229? De h\248re sammen. Det[ENTER]ser ogs\229 meget bedre ud n\229r de alle h\230nger p\229[ENTER]v\230gen sammen.... Mange tak. "
gameforge.subquest_20._320_select = "Jeg pr\248ver igen "
gameforge.subquest_20._330_select = "Jeg opgiver. "
gameforge.subquest_20._340_say = "Du har opgivet jagten efter Ah-Yus \230gtemands spyd. "
gameforge.subquest_20._350_say = "Tak for ikke at give op! "
gameforge.subquest_20._360_say = "Ohh, der er de![ENTER]Jeg er meget taknemmelig, tusind tak![ENTER]Det er ikke mange Yang, men tag[ENTER]dem.  "
gameforge.subquest_20._370_sayReward = "Du modtog 300.000 erfaringspoint.[ENTER]Du modtog 20.000 Yang. "
gameforge.subquest_20._40_say = "Ohh, du virker lidt nede i tiden. Du er normalt[ENTER]s\229 glad! Er der sket noget? "
gameforge.subquest_20._50_say = "Min mand plejede at holde \248je med mig, og sikre[ENTER]sig at ingen ting slemt skete med mig. Men s\229[ENTER]d\248de han i krigen. Det eneste jeg har tilbage[ENTER]efter ham er vores barn og hans spyd. "
gameforge.subquest_20._60_say = "Mens jeg var p\229 arbejde, stjal nogen spydene.[ENTER]Naboerne siger det var de vilde. Jeg kan ikke[ENTER]selv lede efter dem p\229 grund af babyen. "
gameforge.subquest_20._70_say = "Kan du bringe spydene tilbage til mig? Jeg er[ENTER]sikker p\229 at Savages har dem. "
gameforge.subquest_20._80_select = "Jeg vil lede efter dem "
gameforge.subquest_20._90_select = "Jeg har ikke tid "
gameforge.subquest_21 = {}
