gameforge.subquest_21._120_targetVid = "G\229 til Balso "
gameforge.subquest_21._130_sayReward = "Du har fundet medicinen til Balso, der har[ENTER]inficeret sig med en ukendt sygdom hos[ENTER]pest-m\230ndene. Aflever den til Balso. "
gameforge.subquest_21._140_sayTitle = "Hent medicinen "
gameforge.subquest_21._150_say = "Under hans lange flugt, fik Balso en ukendt[ENTER]sygdom. F\229 medicinen fra pest m\230ndene ved Sohan[ENTER]bjerget. "
gameforge.subquest_21._160_npcChat = "Jeg har din medicin! "
gameforge.subquest_21._170_say = "Oh. Tak! Det er forf\230rdeligt at leve som[ENTER]flygtning. Specielt n\229r man ogs\229 bliver syg.[ENTER]Nu kan jeg ved hj\230lp af medicinen helbredes.[ENTER]Tusind tak! "
gameforge.subquest_21._180_sayTitle = "Bel\248nning: "
gameforge.subquest_21._190_sayReward = "Du har f\229et 1.900.000 erfaringspoints Du har f\229et[ENTER]30.000 Yang "
gameforge.subquest_21._20_npcChat = "Det kl\248r s\229 meget "
gameforge.subquest_21._30_sayTitle = "Forr\230deren Balso : "
gameforge.subquest_21._40_say = "M\229 jeg bede dig om en tjeneste? Som du nok[ENTER]allerede ved, er jeg generelt kendt som forr\230der[ENTER]her omkring. Mit liv er meget sv\230rt nu. Jeg[ENTER]erindre de gode tider hvor mit liv var virkelig[ENTER]godt. Men nu er det totalt modsat. Nu er jeg[ENTER]altid p\229 flugt. Dette betyder at jeg altid[ENTER]tiltr\230kker mig sygdomme. "
gameforge.subquest_21._50_say = "For et par dage siden ved Sohan bjerget blev jeg[ENTER]p\229 en eller anden m\229de blandet sammen med et par[ENTER]pest m\230nd. Heldigvis var jeg istand til at[ENTER]flygte, men jeg fangede alligevel en sygdom fra[ENTER]dem ved at r\248re deres hud. Kan du hj\230lpe mig med[ENTER]at f\229 noget medicin. Jeg g\229r ud fra at de har[ENTER]noget med dem. Jeg kan ikke lide at g\248re dette,[ENTER]men vil du ikke nok, kunne du hj\230lpe mig? "
gameforge.subquest_21._60_select = "Ja, jeg hj\230lper dig. "
gameforge.subquest_21._70_say = "\216nsker du at afbryde s\248gningen? "
gameforge.subquest_21._80_say = "N\229r ja, det sker altid for mig. Hvor end jeg ser[ENTER]hen er der folk der ikke kan lide mig. Hvis du[ENTER]\230ndre mening s\229 kom tilbage senere. "
gameforge.subquest_21._90_say = "G\229! og kom aldrig tilbage hertil igen! Det er[ENTER]altid det samme.... "
gameforge.subquest_22 = {}
gameforge.subquest_22._100_say = "Mange tak. Jeg stoler p\229 dig! Bring mig \248ksen[ENTER]tilbage hurtigt. "
gameforge.subquest_22._10_targetVid = "Den Gyldne \216kse fra Deokbae "
gameforge.subquest_22._110_targetVid = "Bes\248g Deokbae "
gameforge.subquest_22._120_sayTitle = "Fundet guld\248ksen "
gameforge.subquest_22._130_say = "Du har fundet guld\248ksen hos barbaren. Aflever den[ENTER]til Deokbae.  "
gameforge.subquest_22._140_sayTitle = "S\248g efter guld\248ksen "
gameforge.subquest_22._150_say = "Bring Deokbaes elskede guld \248kse tilbage fra de[ENTER]vilde Generaler. "
gameforge.subquest_22._160_npcChat = "Jeg har fundet din guld\248ks! "
gameforge.subquest_22._170_sayTitle = "Tr\230samleren Deokbae: "
gameforge.subquest_22._180_say = "Uden din hj\230lp ville jeg aldrig havde f\229et \248ksen[ENTER]tilbage. Tusind tak. Jeg vil v\230re mere p\229passelig[ENTER]i fremtiden og altid have den med mig. "
gameforge.subquest_22._190_sayReward = "Du f\229r 400.000 erfaringspoints "
gameforge.subquest_22._200_sayReward = "Du har modtaget 30.000 Yang. "
gameforge.subquest_22._20_npcChat = "Omkring den Gyldne \216kse... "
gameforge.subquest_22._30_sayTitle = "Tr\230samleren Deokbae: "
gameforge.subquest_22._40_say = "\197hh Nej, \197hh nej! Jeg har tabt min \248kse. M\229ske[ENTER]ved du, hvilken \248kse jeg mener? Det er den gyldne[ENTER]\248kse jeg fik fra smeden. En af de vilde stjal[ENTER]den. "
gameforge.subquest_22._50_say = "Hvis smeden finder ud af det, bliver han blive[ENTER]rasende og n\230gte at reparere mine \248kser. Det var[ENTER]ogs\229 en rigtig god \248kse. Kan du m\229ske bringe den[ENTER]tilbage? "
gameforge.subquest_22._60_select = "Frasige "
gameforge.subquest_22._70_say = "\216nsker du at afbryde s\248gningen? "
gameforge.subquest_22._80_say = "Oh... N\229r du har tid, s\229 kom forbi. "
gameforge.subquest_22._90_say = "For sv\230rt? Der kan s\229 ikke g\248res noget ved. Men[ENTER]pas p\229, overalt lurer de vilde.  "
gameforge.subquest_23 = {}
gameforge.subquest_23._100_sendLetter = "S\248g Yu-Hwan! "
gameforge.subquest_23._10_targetVid = "V\230r s\229 venlig, og s\248ge efter min storebror! "
gameforge.subquest_23._110_targetVid = "G\229 til Yu-Hwan "
gameforge.subquest_23._120_say = "Mirines storebror er forsvundet igen. Han skrev[ENTER]et brev til hende for noget tid siden, men siden[ENTER]da har hun ikke h\248rt noget fra ham. Drag til[ENTER]Yu-Hwan og sp\248rg ham om han kender noget til[ENTER]Mirines storebror. "
gameforge.subquest_23._130_npcChat = "Har du set Mirines storebror? "
gameforge.subquest_23._140_say = "Mirines bror? Jeg er bange for at jeg ikke kan[ENTER]hj\230lpe dig der. Jeg har ikke haft kontakt med ham[ENTER]for nyligt heller. Jeg kan knapt huske hvorn\229r[ENTER]jeg s\229 ham sidst. Jeg er ogs\229 bekymret.[ENTER]M\229ske er der sket ham noget? Pr\248v at sp\248rge[ENTER]j\230geren Yang-Shin. Han er altid p\229 farten og har[ENTER]m\229ske set ham. "
gameforge.subquest_23._150_sendLetter = "S\248g Yang-Shin "
gameforge.subquest_23._160_targetVid = "G\229 til j\230geren Yang-Shin "
gameforge.subquest_23._170_say = "J\230geren Yang-Shin er altid p\229 farten og har m\229ske[ENTER]set Mirines storebror. "
gameforge.subquest_23._180_npcChat = "Har du set Mirines storebror? "
gameforge.subquest_23._190_say = "Mener du Mirines storebror? Sidst jeg s\229 ham var[ENTER]han p\229 vej til Seungryong Dalen for at samle[ENTER]urter. Jeg var lidt overrasket da det er farligt[ENTER]der, men jeg t\230nkte ikke rigtigt yderligere over[ENTER]det. "
gameforge.subquest_23._200_say = "Jeg burde have stoppet ham. Hvis han ikke har[ENTER]skabt kontakt, m\229 der v\230re sket ham noget. Du m\229[ENTER]hellere drage til Seungryong Dalen og se efter[ENTER]ham. "
gameforge.subquest_23._20_npcChat = "Hvorfor gr\230der du? "
gameforge.subquest_23._210_select = "start s\248gning "
gameforge.subquest_23._220_say = "Afbryde s\248gningen?  "
gameforge.subquest_23._230_say = "Mirine var virkelig meget ked af det. Jeg kommer[ENTER]tilbage senere. "
gameforge.subquest_23._240_say = "Hvis en storebror ikke skaber kontakt i en[ENTER]periode, betyder det ikke n\248dvendigvis at der er[ENTER]sket noget med ham. Du beh\248ver ikke drage ind i[ENTER]den farlige dal, bare fordi en lille pige har[ENTER]bedt dig om det. "
gameforge.subquest_23._250_say = "Missionen er ikke s\229 ubetydelig som den virker.[ENTER]Seungryong dalen er et farligt sted.[ENTER]Men jeg lovede det, s\229 jeg vil g\248re det. "
gameforge.subquest_23._260_sendLetter = "Den Savnede Broder "
gameforge.subquest_23._270_targetVid = "S\248g efter torebroderen i Seungryong dalen "
gameforge.subquest_23._280_sayTitle = "S\248g efter Mirines broder "
gameforge.subquest_23._290_say = "Mirines bror leder efter healende urter i[ENTER]Seungryong dalen. Drag der til og se om han er[ENTER]okay. Teleporteren vil hj\230lp dig hvis du leder[ENTER]efter en genvej. "
gameforge.subquest_23._300_npcChat = "Liget! "
gameforge.subquest_23._30_say = "Du bragte mig engang et brev fra min bror, gjorde[ENTER]du ikke? Jeg var meget taknemmelig da du gjorde[ENTER]det. Desv\230rre har jeg ikke v\230ret i kontakt med[ENTER]ham siden. Min bror er stadig af sted.[ENTER]Han leder efter healende urter til mig. "
gameforge.subquest_23._310_say = "En d\248d mand l\230gger her. Han er ung og tynd og[ENTER]virker til at samlet Ginseng. Jeg er bange for at[ENTER]det m\229ske er Mirines storebror, som vi har ledt[ENTER]efter. Liget har et halsk\230de med et vedh\230ng p\229.[ENTER]Jeg vil tage det af og bringe det til Mirine. "
gameforge.subquest_23._320_sendLetter = "G\229 til Mirine "
gameforge.subquest_23._330_sayTitle = "Trist nyt "
gameforge.subquest_23._340_say = "Du har fundet et vedh\230ng p\229 et lig i Seungryong[ENTER]dalen, p\229 hvilet mirines navn er indgraveret.[ENTER]Drag til Mirine og giv hende halsk\230den og[ENTER]vedh\230nget. "
gameforge.subquest_23._350_npcChat = "Kender du denne halsk\230de? "
gameforge.subquest_23._360_say = "Oh.. Denne k\230de... Min bror plejede at b\230re den[ENTER]altid. Jeg har en magen til. Vi bar dem altid s\229[ENTER]vi kunne huske hinanden og s\229 vi kunne finde[ENTER]tilbage til hinanden. Men... Min bror er her ikke[ENTER]l\230ngere... Og kun halsk\230den har fundet vej[ENTER]tilbage. "
gameforge.subquest_23._370_say = "Min stakkels bror...[ENTER]Alt sammen p\229 grund af krigen. Min storebror[ENTER]solgte healende urter, det var det eneste der gav[ENTER]os penge. Det gav os mulighed for at k\248be mad.[ENTER]Han arbejde meget h\229rdt s\229 jeg kunne f\229 nok at[ENTER]spise. Og nu er han d\248d. Bare p\229 grund af mig... "
gameforge.subquest_23._380_say = "Du skal have et tak fordi at du har leveret mig[ENTER]det her, for nu ved jeg i det mindste hvad der er[ENTER]sket. Havde du ikke hjulpet mig, havde jeg aldrig[ENTER]fundet ud af, hvad som var sket min bror. "
gameforge.subquest_23._390_say = "Jeg vil tage mig af min brors vedh\230ng, og vil[ENTER]give dig halsk\230den som et bevis p\229 min[ENTER]taknemmelighed. Jeg er sikker p\229 at den vil blive[ENTER]brugbar. Mange tak for din hj\230lp. Jeg er sikker[ENTER]p\229 an er i himlen nu, tror du ikke? "
gameforge.subquest_23._400_sayReward = "Du har modtaget 600.000 erfaringspoints.[ENTER]Du har modtaget 35.000 Yang. "
gameforge.subquest_23._40_say = "Jeg er bekymret for ham, da jeg ikke har haft[ENTER]kontakt med ham s\229 l\230nge. Undskyld, men kunne du[ENTER]tage endnu et kig efter min bror? Yu-Hwang ved[ENTER]m\229ske noget. "
gameforge.subquest_23._50_select = "Frasige "
gameforge.subquest_23._60_say = "Vil du afbryde s\248gningen? "
gameforge.subquest_23._70_say = "Ohh...[ENTER]Jeg venter her. M\229ske senere? Vil du ikke nok? "
gameforge.subquest_23._80_say = "Jeg har ikke tide![ENTER]Held og lykke til din bror. "
gameforge.subquest_23._90_say = "At hj\230lpe den fattige pige er meget venligt, men[ENTER]heller ikke et stort arbejde. s\229[ENTER]afsted!  "
gameforge.subquest_24 = {}
gameforge.subquest_24._100_say = "Vil du afslutte denne mission? "
gameforge.subquest_24._10_targetVid = "Yu-Rangs riskage "
gameforge.subquest_24._110_say = "Hvis du har tid senere, s\229 kom venligst forbi[ENTER]igen. Jeg ved ikke, hvordan vi skal overleve uden[ENTER]at s\230lge riskagerne. "
gameforge.subquest_24._120_say = "Alting drejer sig om de rige mennesker som[ENTER]kastede Yang ud af vinduet som om der ikke var[ENTER]noget i morgen. Vi ved ikke engang om vi vil have[ENTER]mad p\229 bordet i morgen! G\229 din vej! "
gameforge.subquest_24._130_say = "Tak! Du er meget venlig.[ENTER]Jeg venter, indtil du kommer igen. "
gameforge.subquest_24._140_sendLetter = "Den Stj\229lne Ris Kage "
gameforge.subquest_24._150_say = "Hent Yu-Rangs riskage ved edderkopperne i[ENTER]\248rkenen. Hvis du ikke er hurtig nok spiser[ENTER]edderkopperne riskagen, eller de vil blive[ENTER]ekstremt t\248rre ind i den varme sol. Skynd dig! "
gameforge.subquest_24._160_sayReward = "Dr\230b baby edderkopperne i Yongbi \248rkenen. "
gameforge.subquest_24._170_npcChat = "Omkring din stj\229lne Riskage... "
gameforge.subquest_24._180_say = "Hvad, spiste edderkopperne riskagen? ohh nej![ENTER]Eller var de t\248rret ud?! Sig venligst ikke at alt[ENTER]er tabt! "
gameforge.subquest_24._190_select = "Nej, alt er i orden. "
gameforge.subquest_24._200_select = "Jeg opgiver. "
gameforge.subquest_24._20_npcChat = "Dine stj\229lne riskager... "
gameforge.subquest_24._210_say = "Kan du m\229ske alligevel g\248re det? Riskagerne er[ENTER]meget vigtige for mig. Jeg beder dig.[ENTER][ENTER]\216nsker du at opgive opgaven med at finde Yu-Rangs[ENTER]riskager i \248rkenen? "
gameforge.subquest_24._220_select = "Jeg pr\248ver igen, "
gameforge.subquest_24._230_select = "Desv\230rre, det er for sv\230rt. "
gameforge.subquest_24._240_say = "Jeg kan ikke tro det. Hvem kan nu hj\230lpe os? "
gameforge.subquest_24._250_say = "V\230r s\229 venlig![ENTER]Hj\230lp mig! "
gameforge.subquest_24._260_say = "S\229 du vil forts\230tte s\248gningen? Mange tak! Fors\248g[ENTER]venligst at finde riskagerne s\229 hurtigt som[ENTER]muligt. "
gameforge.subquest_24._270_say = "Nej, det er for sent.[ENTER]Selv n\229r du finder den, er den nok allerede[ENTER]t\248rret ind og kan ikke s\230lges[ENTER]vidre...  "
gameforge.subquest_24._280_say = "Du kigger p\229 jorden og ser kagerester, som[ENTER]edderkopperne har efterladt. Desv\230rre er de alle[ENTER]t\248rret ind. "
gameforge.subquest_24._290_sayReward = "Du har brugt for meget tid p\229 at lede efter[ENTER]kagen. Opgaven mislykkes. "
gameforge.subquest_24._300_sendLetter = "G\229 tilbage til Yu-Rang "
gameforge.subquest_24._30_say = "Hej, hvordan har din mor det?  "
gameforge.subquest_24._310_targetVid = "G\229 tilbage til Yu-Rang "
gameforge.subquest_24._320_say = "Du har redet Yu-Rangs riskage fra edderkopperne i[ENTER]sidste \248jeblik. Bring dem hende. "
gameforge.subquest_24._330_npcChat = "Du er heldig. Her er din riskage. "
gameforge.subquest_24._340_say = "Du er virkelig fantastisk! Jeg ved ikke, hvad jeg[ENTER]skal sige. Nu kan jeg s\230lge den p\229 markedet[ENTER]imorgen. Tusind tak! "
gameforge.subquest_24._350_sayReward = "Du har modtaget 900.000 erfaringspoint. "
gameforge.subquest_24._360_sayReward = "Du f\229r 25.000 Yang "
gameforge.subquest_24._40_say = "Oh, hun har det bedre.  "
gameforge.subquest_24._50_say = "Det ser ud til, at du har problemer?[ENTER]Hvad er der i vejen?  "
gameforge.subquest_24._60_say = "Jeg s\230lger til dagligt riskager, men i dag skete[ENTER]der noget forf\230rdeligt. Gigantiske edderkopper[ENTER]dukkede op og stjal dem fra mig. Det var[ENTER]skr\230kslagen og bek\230mpede dem ikke. Nu har jeg[ENTER]ikke nogen riskager tilbage at s\230lge. Men hvordan[ENTER]skal jeg overleve? Min familie har ikke anden[ENTER]indkomst... "
gameforge.subquest_24._70_select = "Jeg vil finde den for dig "
gameforge.subquest_24._80_select = "Desv\230rre har jeg ikke tid "
gameforge.subquest_24._90_sayTitle = "Sp\248rgsm\229l: "
gameforge.subquest_25 = {}
gameforge.subquest_25._100_npcChat = "Hvad kan du lide? "
gameforge.subquest_25._10_targetVid = "Huahn-So "
gameforge.subquest_25._110_say = "N\229, lige siden jeg mistede min mand i krigen, har[ENTER]jeg v\230ret meget ensom. Hm? Hvad der kunne[ENTER]forbedre hum\248ret? N\229, min mand plejede at bringe[ENTER]mig Blomster. "
gameforge.subquest_25._120_say = "Der var nogle blomster, der vokser ret langt v\230k[ENTER]fra vores landsby. Selv om det var farligt,[ENTER]hentede han de Blomster til mig.[ENTER]Jeg kan ikke holde ud at se de blomster mere[ENTER]fordi min mand er d\248d.[ENTER]Men p\229 dage som disse savner jeg ham s\229 meget.[ENTER]\197h, hvad sagde jeg lige? Det var meget upassende.[ENTER]Glem venligst, hvad jeg lige har sagt. "
gameforge.subquest_25._130_qSetTitle = "Tilbage til Huahn-So "
gameforge.subquest_25._140_makequestbutton = "Tilbage til Huahn-So "
gameforge.subquest_25._150_targetVid = "Huahn-So "
gameforge.subquest_25._160_say = "Ariyoung mangler den blomst hendes mand altid[ENTER]bragte hende. G\229 til Huahn-So og fort\230lle ham om[ENTER]det. "
gameforge.subquest_25._170_npcChat = "Gaven til Ariyoung... "
gameforge.subquest_25._180_say = "S\229, hvad kan Ariyoung lide? Du har ikke fortalt[ENTER]hende noget om mig, vel? Hmm, hun kan lide en[ENTER]blomst, som hendes mand, altid bragte hende?[ENTER]Det er temmelig langt v\230k fra landsbyen.[ENTER]Det bliver sv\230rt for mig at komme dertil. Og der[ENTER]kunne v\230re monstre der som tigere. "
gameforge.subquest_25._190_say = "Lige netop! Hvorfor hj\230lper du mig ikke? Hvorfor[ENTER]henter du ikke blomsten for mig?[ENTER]Det ville v\230re en stor hj\230lp for os begge.[ENTER]Hvad? Det er ikke en del af aftalen?[ENTER]Kom nu, ser du ikke hvor h\229rdt jeg fors\248ger at[ENTER]vinde hendes k\230rlighed? Bare hj\230lp mig! Jeg vil[ENTER]bel\248nne dig med masser af Yang! "
gameforge.subquest_25._200_select = "Afvise "
gameforge.subquest_25._20_npcChat = "Oh, min k\230reste Ariyoung "
gameforge.subquest_25._210_say = "Vil du opgive missionen? "
gameforge.subquest_25._220_say = "Arg... Hvordan skal jeg f\229 fat i blomsterne?[ENTER]V\230r venlig at komme tilbage, hvis du ombestemmer[ENTER]dig. "
gameforge.subquest_25._230_say = "Har du aldrig elsket nogen?[ENTER]Ved du ikke, hvad jeg f\248ler for Ariyoung?...[ENTER]Oh Ariyoung... "
gameforge.subquest_25._240_say = "Mange tak![ENTER]Bring mig disse blomster. "
gameforge.subquest_25._250_qSetTitle = "Hent blomsterne "
gameforge.subquest_25._260_targetVid = "Blomster "
gameforge.subquest_25._270_sayTitle = "Blomster til Ariyoung "
gameforge.subquest_25._280_say = "For at hj\230lpe Huahn-So med at fort\230lle Ariyoung[ENTER]hvordan han f\248ler, er du n\248dt til at hente de[ENTER]specielle blomster.[ENTER]Blomsterne kan findes i hj\248rnet af kortet i den[ENTER]f\248rste landsby. "
gameforge.subquest_25._290_npcChat = "Jeg har ikke fundet nogen Blomster. "
gameforge.subquest_25._300_say = "Det er da forf\230rdeligt![ENTER]Jeg ville fort\230lle hende om mine f\248lelser. Det er[ENTER]meget sv\230rt at f\229 hendes k\230rlighed.[ENTER]Min k\230reste Ariyoung... "
gameforge.subquest_25._30_say = "Kender du Lady Ariyoung? N\229, hun er ... nej,[ENTER]godt, hun var gift. Hendes mand d\248de for et par[ENTER]\229r tilbage og siden da har hun boet alene. Hun[ENTER]har en meget imponerende personlighed og hun er[ENTER]stadig en meget smuk kvinde. Hun blev gift meget[ENTER]ung, og jeg kom for sent.... "
gameforge.subquest_25._310_select = "Jeg forts\230tter med at pr\248ve det "
gameforge.subquest_25._320_select = "Jeg stopper "
gameforge.subquest_25._330_say = "Vil du afslutte denne mission? "
gameforge.subquest_25._340_say = "Oh...[ENTER]Hvis du alligevel vil hj\230lpe, s\229 kom forbi...[ENTER]Jeg venter her.. "
gameforge.subquest_25._350_say = "Vil min k\230rlighed ende p\229 den m\229de?[ENTER]Ariyoung... "
gameforge.subquest_25._360_say = "Mange tak. Du er nok ogs\229 forelsket, hvis du kan[ENTER]forst\229, hvad jeg f\248ler for Ariyoung. "
gameforge.subquest_25._370_npcChat = "Ariyoungs ynglingsblomster "
gameforge.subquest_25._380_say = "Disse blomster ligner dem, som Ariyoung beskrev.[ENTER]Jeg har t\230nkt mig at tage nogle. "
gameforge.subquest_25._390_qSetTitle = "Tilbage til Huahn-So "
gameforge.subquest_25._400_say = "Jeg har fundet Ariyoung foretrukne blomster og[ENTER]har plukket nogle. Jeg vil tage dem til Huahn-So[ENTER]s\229 han kan bekende sin k\230rlighed til Ariyoung. "
gameforge.subquest_25._40_say = "Men hendes mand blev dr\230bt i krigen, derfor er[ENTER]hun en ung enke.[ENTER]Selvom hun stadig er gift, \248nsker jeg at hun f\229r[ENTER]af vide, hvad jeg f\248ler!![ENTER]Jeg ved godt, at jeg forlanger rimelig meget, men[ENTER]vil du ikke v\230re s\229 venlig, og[ENTER]hj\230lpe?  "
gameforge.subquest_25._410_npcChat = "Her er Ariyoung foretrukne blomster. "
gameforge.subquest_25._420_say = "\197h, det er de Blomster? Nu kan jeg fort\230lle[ENTER]Ariyoung hvordan jeg f\248ler for hende! Tror du,[ENTER]det er for tidligt til det? Oh, det g\248r ikke[ENTER]noget hvis det er for tidligt. Jeg er n\248dt til at[ENTER]fort\230lle hende det ellers vil jeg briste.[ENTER]Her er din bel\248nning og mange tak. "
gameforge.subquest_25._430_sayReward = "Du f\229r 400.000 erfaringspoints "
gameforge.subquest_25._440_sayReward = "Du f\229r 12.000 Yang "
