gameforge.subquest_26._130_targetVid = "Ok-gu "
gameforge.subquest_26._140_sayTitle = "G\229 til Octavio "
gameforge.subquest_26._150_say = "Butiksindehaveren har givet dig et godt tips:[ENTER]Fr\248l\229rsuppe, er et fantastisk l\230gemiddel imod[ENTER]svaghed og tr\230tte knogler. Sp\248rg Octavio om han[ENTER]kan lave denne suppe. "
gameforge.subquest_26._160_npcChat = "Fr\248l\229rsuppe? "
gameforge.subquest_26._170_say = "Fr\248l\229rsuppen... Rigtig, den har jeg lavet engang.[ENTER]Men det er fortid nu. Dengang var jeg ikke bange[ENTER]for monstere, s\229 jeg kunne nemt f\229 fat i fr\248l\229r. "
gameforge.subquest_26._180_say = "Men nu... Er jeg gammel og tr\230t. Med suppen kunne[ENTER]jeg f\229 min energi tilbage, men fr\248er er ikke[ENTER]nemme at sl\229 ihjel. Hvis du kan levere mig nogle[ENTER]fr\248l\229r til suppen, vil jeg tilberede[ENTER]verdensbedste fr\248l\229rsuppe til os! "
