gameforge.subquest_26._290_sayTitle = "Dr\230b tre fr\248ledere "
gameforge.subquest_26._300_say = "Octavio har brug for fr\248l\229r til sin fr\248l\229rsuppe.[ENTER]Du kan finde dem ved at jage tr\230fr\248ledere i Hwang[ENTER]templet. "
gameforge.subquest_26._30_sayTitle = "Lagerforvalter: "
gameforge.subquest_26._310_npcChat = "Det kan jeg ikke g\248re nu "
gameforge.subquest_26._320_say = "Hvad er der i vejen med dig?[ENTER]Da jeg var ung, kunne jeg levere 10 fr\248l\229r hver[ENTER]dag! "
gameforge.subquest_26._330_select = "Pr\248v igen "
gameforge.subquest_26._340_say = "Er du allerede udmattet?[ENTER]Hvorfor tager du ikke en pause og pr\248ver igen[ENTER]senere? "
gameforge.subquest_26._350_say = "Jeg kunne godt bruge fr\248l\229rsuppen... Men det[ENTER]kommer ikke til at ske. En skam. Farvel! "
gameforge.subquest_26._360_say = "S\229 st\229 da ikke bare her men g\229! Vandet koger[ENTER]allerede og alting er klar! "
gameforge.subquest_26._370_targetVid = "G\229 til Octavio "
gameforge.subquest_26._380_say = "Se det er hvad jeg kalder et fr\248l\229r! De plejede[ENTER]at v\230re mindre, men jeg er sikker p\229 at dette[ENTER]kommer til at smage godt ogs\229. Vent et \248jeblik...[ENTER]Det dufter allerede temmelig godt. En smule mere[ENTER]salt... Rigtigt! Her er din potion. Hahaha, nu[ENTER]har jeg energi nok til en hel uges arbejde. "
gameforge.subquest_26._390_say = "Fort\230l ikke nogen om det. Specielt ikke[ENTER]butiksejeren. Han kan lide og snakke, hvis[ENTER]kvaliteten af suppen bliver kendt, vil jeg ikke[ENTER]have et minuts fred, alle vil konstant komme[ENTER]hertil for at smage min suppe. "
gameforge.subquest_26._400_sayReward = "Du modtager 5.000.000 erfaringspoint. "
gameforge.subquest_26._40_say = "Jeg har ikke haft det s\229 godt p\229 det sidste. Min[ENTER]krop er ikke hvad den var engang. Da jeg var[ENTER]yngre, kunne jeg arbejde indtil natten, hver dag[ENTER]i ugen, og samtidig drikke alkohol. Nu er det for[ENTER]meget arbejde bare at komme op om morgenen. Jeg[ENTER]har brug for en stor portion hj\230lpende[ENTER]fr\248l\229rsuppe for at f\229 min energi tilbage. "
gameforge.subquest_26._410_sayReward = "Du har modtaget 50,000 Yang. "
gameforge.subquest_26._50_say = "Ved du ikke hvad fr\248l\229rsuppe er? N\229r du drikker[ENTER]en sk\229l af det, vil du v\229gne op med det samme[ENTER]fuld af energi. S\229 kan du arbejde en hel uge i[ENTER]tr\230k, uden at blive tr\230t![ENTER]Octavio plejede at lave denne suppe, men af en[ENTER]eller anden grund stoppede han for kort tid siden[ENTER]med at lave den. "
gameforge.subquest_26._60_select = "Jeg g\229r til Octavio. "
gameforge.subquest_26._70_select = "Jeg har travlt. "
gameforge.subquest_26._80_say = "Vil du afslutte denne mission? "
gameforge.subquest_26._90_say = "Okay, n\229r du har travlt, s\229 kom igen, hvis du f\229r[ENTER]tid tilovers. "
gameforge.subquest_27 = {}
gameforge.subquest_27._100_say = "Han skulle v\230re skamfuld over at kalde sig selv[ENTER]for far! Hvis jeg finder ham, s\229 gud n\229de og[ENTER]tr\248ste hans sj\230l![ENTER]Tro mig, jeg overdriver ikke. Sp\248rg de andre i[ENTER]landsbyen, de vil v\230re enige med mig. "
