gameforge.subquest_27._140_npcChat = "Hvad er der med Soon? "
gameforge.subquest_27._150_say = "I g\229r kom han forbi og spurgte om den hemmelige[ENTER]tempel bog. Han havde ingen Yang med sig, s\229 han[ENTER]kiggede bare p\229 den. Det m\229 v\230re meget vigtigt[ENTER]for ham hvis han fors\248mmer familien for den.[ENTER]Hvorfor er han s\229 interesseret i den? "
gameforge.subquest_27._160_sayTitle = "Handelsdame: "
gameforge.subquest_27._170_say = "Jeg synes det er synd for Aranyo. Hun giftede sig[ENTER]nok ikke Soon for at skulle arbejde dag og nat.[ENTER]Jeg er sikker p\229 at hun ikke havde regnet med at[ENTER]hun skal fors\248rge familien alene. Du burde tale[ENTER]med ham. Hvem ved m\229ske indser han endelig hvad[ENTER]han g\248r forkert. "
