gameforge.subquest_27._190_qSetTitle = "G\229 til Soon "
gameforge.subquest_27._200_targetVid = "Igen Soon "
gameforge.subquest_27._20_npcChat = "Gl\230den ved at l\230se. "
gameforge.subquest_27._210_say = "G\229 til Soon[ENTER]G\229 til Soon og sp\248rg om Tempel-bogen. "
gameforge.subquest_27._220_npcChat = "Hvad er den hemmelige tempel bog? "
gameforge.subquest_27._230_say = "Ved du hvad, jeg har l\230st alle b\248ger i hele[ENTER]verden. For nyligt, har jeg h\248rt om en hemmelig[ENTER]tempel bog. Rygterne siger at bogen indeholder[ENTER]M\248rkets Tempels hemmelighed. Den forklare ogs\229[ENTER]hvordan du bliver en helgen. "
gameforge.subquest_27._240_say = "Jeg \248nsker at l\230se denne bog.[ENTER]Kunne du f\229 fat i den?[ENTER]Hvis du kan det, f\229r du ogs\229 noget for det. Selv[ENTER]hvis jeg bliver n\248d til at s\230lge mit[ENTER]hus.  "
