gameforge.subquest_27._270_say = "Vil du afslutte denne mission? "
gameforge.subquest_27._280_say = "Kom s\229, kan du ikke hj\230lpe mig?[ENTER]Hvis du ikke g\248r det nu, s\229 m\229ske senere?[ENTER]Jeg venter p\229 dig. "
gameforge.subquest_27._290_say = "Du vil virkelig ikke hj\230lpe mig?[ENTER]Du tr\230nger til ferie, ik\180?![ENTER]Dokumentet er meget vigtigt..[ENTER]Hvad skal jeg bare g\248re..[ENTER]Forhelvede ogs\229... "
gameforge.subquest_27._300_say = "Tak, jeg venter p\229 dig.  "
gameforge.subquest_27._30_say = "Kan du lide at l\230se lige s\229 meget som jeg kan?[ENTER]Ord som bliver til s\230tninger, for endelig at[ENTER]blive forenet i en bog. Hvor vidunderligt! Og den[ENTER]rene gl\230de ved at skrive en bog, s\229 andre[ENTER]mennesker kan l\230se den! Det bliver ikke bedre end[ENTER]det! "
