gameforge.subquest_27._400_sayReward = "Du modtager 850.000 erfaringspoint. "
gameforge.subquest_27._40_say = "Livet pulsere imellem siderne p\229 denne bog![ENTER]Ung viden og gammel visdom bor her![ENTER]Forestil dig hvor dyster mit liv ville v\230re uden[ENTER]b\248ger... Uheldigvis... Forst\229r min kone ikke[ENTER]dette. Kunne du pr\248ve at overbevise hende om at[ENTER]det er en god ting? "
gameforge.subquest_27._410_sayReward = "Du har modtaget 20.000 Yang. "
gameforge.subquest_27._420_say = "Hey...[ENTER]Du har ikke f\229et det?[ENTER]N\229r du tager imod en opgave burde du ogs\229[ENTER]afslutte den. S\229 afsted! "
