gameforge.subquest_32._210_say = "Vidunderligt, mange tak skal du have! Hils Ah-yu[ENTER]fra mig og pas p\229 ikke at kr\248lle hendes t\248j p\229[ENTER]vejen! Jeg vil vente p\229 dig her. "
gameforge.subquest_32._220_sayTitle = "Ariyoung: "
gameforge.subquest_32._230_say = "N\229r du kommer tilbage fra nabo landsbyen vil jeg[ENTER]v\230re f\230rdig med din sytr\229d. Nu har du ikke glemt[ENTER]at tage Ah-Yus t\248j med dig, har du? Hun vil[ENTER]bebrejde mig for det. "
gameforge.subquest_32._240_say = "Er Ah-Yu tilfreds med t\248jet?[ENTER]S\229 er det en forn\248jelse at arbejde s\229 h\229rdt.[ENTER]Her er din sytr\229d.[ENTER]Det er en stabil tr\229d, som kan bruges til[ENTER]adskillige ting.  "
gameforge.subquest_32._250_say = "Jeg har allerede givet dig sytr\229d. Har du mistet[ENTER]det? "
gameforge.subquest_32._260_npcChat = "Ariyoung sender dig dette t\248j. "
gameforge.subquest_32._270_sayTitle = "Ah-Yu: "
gameforge.subquest_32._280_say = "Ohh, hvor dejligt. Det var virkelig hurtigt. Du[ENTER]skal dyrke gamle venskaber, b\248r du ikke? Vi[ENTER]hj\230lper tit hinanden...[ENTER]Mange tak for at du har bragt t\248jet til mig.[ENTER]Hils venligst Ariyoung fra mig. "
gameforge.subquest_32._290_npcChat = "Jeg har brug for et smykke. "
gameforge.subquest_32._300_say = "Du s\248ger smykker?[ENTER]Jeg kan give dig et, hvis du hj\230lper mig. I[ENTER]\248jeblikket arbejder jeg p\229 en speciel medicin[ENTER]imod smerte, men jeg skal bruge en ingrediens: En[ENTER]tigerlever. De er meget sv\230re at f\229.[ENTER]Jeg har brug for 100 Tigerlevere. "
gameforge.subquest_32._30_say = "Det er ikke let for os omrejsende handelsm\230nd i[ENTER]disse krigstider. De har brug for varer alle[ENTER]steder, men eftersp\248rgslen \230ndres s\229 hurtigt at[ENTER]jeg aldrig ved om jeg har de rigtige ting at[ENTER]tilbyde. For ikke at n\230vne de lange ture igennem[ENTER]vildmarken, hvor alle monsterene l\230gger og venter[ENTER]for ligegyldige g\229ende.[ENTER]Vil du ikke tjene et par Yang? Jeg kunne godt[ENTER]bruge lidt hj\230lp. "
gameforge.subquest_32._310_say = "Jeg har ogs\229 brug for medicinske planter men du[ENTER]vil ogs\229 f\229 disse fra Tigerne. De elsker at rulle[ENTER]sig i dem, da de elsker duften. Jeg vil give dig[ENTER]et smykke for urterne og for tigerleveren. "
gameforge.subquest_32._320_say = "Jagt tigere, eller hvide tigere.  "
gameforge.subquest_32._330_say = "Hvad siger du? Kan vi lave en aftale? "
gameforge.subquest_32._340_say = "Er min opgave for sv\230r for dig? Det kan jeg ikke[ENTER]forestille mig! Kom og bes\248g mig igen, n\229r du har[ENTER]skiftet mening. "
gameforge.subquest_32._350_say = "Du kommer hele denne lange vej for k\248bmanden og[ENTER]s\229 giver du op? Som du \248nsker...[ENTER]Hav en god dag. "
gameforge.subquest_32._360_say = "Meget godt. Det kommer til at hj\230lpe os begge,[ENTER]g\248r det ikke? Mange tak, og held og lykke! "
gameforge.subquest_32._370_npcChat = "F\229r jeg mit smykke nu? "
gameforge.subquest_32._380_say = "Lad mig se... 100 tigerlevere og de medicinske[ENTER]urter, det var alt. Mange tak![ENTER]V\230rsgo, du har har virkelig fortjent dette[ENTER]smykke. Ses! "
gameforge.subquest_32._390_qSetTitle = "Tilbage til handelsmanden "
gameforge.subquest_32._400_targetVid = "Tilbage til handelsmanden "
gameforge.subquest_32._40_say = "I \248jeblikket er halskeder lavet af Ork kindt\230nder[ENTER]virkelig efterspurgte. Ork kindt\230nder er store og[ENTER]h\229rde og er gode til at lave visse former for[ENTER]smykker.[ENTER]Ogs\229 soldater synes om Stolte ork troldm\230nds[ENTER]kindt\230nder som lykke bringer. Kunne du skaffe[ENTER]disse kindt\230nder til mig? 100 Kindt\230nder skulle[ENTER]v\230re nok til en start. "
gameforge.subquest_32._410_sayReward = "Tilbage til handelsmanden "
gameforge.subquest_32._420_sayReward = "Du har endelig alle materialerne til halsk\230den.[ENTER]Bring dem til handelsmanden. "
gameforge.subquest_32._430_npcChat = "Jeg har alle materialer "
gameforge.subquest_32._440_sayTitle = "Handelsmand: "
gameforge.subquest_32._450_say = "Har du fundet alle materialerne? Lad mig se...[ENTER]Ja, det hele er der virkelig. Takket v\230re din[ENTER]hj\230lp kan jeg udvide mit udvalg, det er godt. Her[ENTER]er din andel. Hav det godt.[ENTER]Kom her folk! Her er noget for alle! "
gameforge.subquest_32._460_sayReward = "Du har modtaget 1.100.000 erfaringspoint "
gameforge.subquest_32._470_sayReward = "Du f\229r et guld armb\229nd, en guld halsk\230de og en[ENTER]guld \248rering. "
gameforge.subquest_32._480_say = "Hmm, jeg er ked af det, men noget mangler. Jeg[ENTER]har ikke brug for mangelfulde leveringer. Vil du[ENTER]fortsat fors\248ge? "
gameforge.subquest_32._490_say = "Vil du afslutte denne mission? "
gameforge.subquest_32._500_say = "Tak fordi du ikke giver op s\229 let.[ENTER]Lykken er med dem som pr\248ver! Jeg venter her p\229[ENTER]dig. "
gameforge.subquest_32._50_say = "Jeg skal ogs\229 bruge et smykke og sytr\229d. Den ene[ENTER]kan du f\229 fra handelsdamen, den anden f\229r du fra[ENTER]Ariyoung. Det er ikke s\229 nemt at f\229 s\229 mange[ENTER]ting, men at s\230lge halsk\230der er en god forretning[ENTER]og du f\229r en fin bel\248nning for materialerne. Hvad[ENTER]syntes du? Lyder det ikke interessant? "
gameforge.subquest_32._510_say = "Er opgaven for sv\230r? I det mindste har du pr\248vet.[ENTER]Jeg vil lade dig det vide hvis jeg en dag har en[ENTER]lettere opgave til dig. Farvel! "
gameforge.subquest_32._520_say = "Ja, vil du pr\248ve igen? Tak. Jeg vil vente p\229 dig. "
gameforge.subquest_32._60_say = "Vil du afslutte denne mission? "
gameforge.subquest_32._70_say = "Har du travlt? Jeg har forst\229else for det. Men[ENTER]kom venligst tilbage n\229r du har tid. "
gameforge.subquest_32._80_say = "Ohh k\230re, hvordan skal jeg f\230rdigg\248re alle mine[ENTER]opgaver? Vi ses! "
gameforge.subquest_32._90_say = "Dejligt. Jeg vil vente her p\229 dig. "
gameforge.subquest_33 = {}
gameforge.subquest_33._100_sayTitle = "Skattekort fundet "
gameforge.subquest_33._10_targetVid = "G\229 til bogormen. "
gameforge.subquest_33._110_say = "Du har jaget dyre guderne uden for landsbyen og[ENTER]fandt alle 4 dele af skattekortet.[ENTER]Aflevere dem til Soon. "
gameforge.subquest_33._120_sayTitle = "Jag dyreguderne "
gameforge.subquest_33._130_say = "Saml alle 4 dele af skattekortet, ved at nedl\230gge[ENTER]dyreguderne Lykos, Scrofa, Bera og Tigris. "
gameforge.subquest_33._140_sayReward = "(Skattekort dele fundet : %s ) "
gameforge.subquest_33._150_sendLetter = "Skattekortet "
gameforge.subquest_33._160_sayTitle = "Alle dele af skattekortet fundet "
gameforge.subquest_33._170_say = "G\229 tilbage til Soon og fort\230l, at du har fundet[ENTER]alle dele af skattekortet.  "
gameforge.subquest_33._175_npcChat = "Jeg har f\229et alle kort delene. "
gameforge.subquest_33._180_say = "Oh! Fantastisk! Alle fire stykker sammen ... Jeg[ENTER]ville ikke have dr\248mt om det! Nu har jeg brug for[ENTER]at s\230tte dem sammen for at f\229 hele kortet ...[ENTER]Fint ... "
gameforge.subquest_33._190_say = "Hmm ... Underligt. Kortet siger, at skatten er[ENTER]skjult i sten n\230r den gamle mand. Jeg kan ikke[ENTER]forestille mig, at det er rigtigt. Det ville have[ENTER]v\230ret fundet nu. Sikke et barnlig trick! \216nsker[ENTER]du at se alligevel, eller skal jeg bare br\230nde[ENTER]kortet? "
gameforge.subquest_33._200_select = "Jeg kigge p\229 det. "
gameforge.subquest_33._20_npcChat = "Om skattekortet... "
gameforge.subquest_33._210_select = "Br\230nd det. "
gameforge.subquest_33._220_say = "Er du sikker p\229 du ikke har brug for kortet mere? "
gameforge.subquest_33._230_say = "Sikke et s\248rgeligt eventyr![ENTER]Jeg er ked af, at jeg sendte dig ud for at s\248ge[ENTER]efter disse kort stykker. Jeg vil br\230nde dem nu,[ENTER]s\229 ingen ellers falder for dem. Alligevel mange[ENTER]tak. Farvel. "
gameforge.subquest_33._240_say = "Hvorfor t\248ver du? Du har allerede samlet[ENTER]stykkerne af kortet. S\229 kan du g\229 og se efter.[ENTER]Her, tag kortet! "
gameforge.subquest_33._250_say = "Som du vil. Jeg ville blive virkelig overrasket,[ENTER]hvis du virkelig finder noget, men stadig, jeg[ENTER]\248nsker dig held og lykke! Tag kortet! "
gameforge.subquest_33._260_say = "Kortet er opdelt i fire dele. Vi har brug for[ENTER]alle fire dele til at s\230tte dem sammen igen! "
gameforge.subquest_33._270_select = "Pr\248v igen "
gameforge.subquest_33._280_say = "Du opgiver? Okay.. Farvel. "
gameforge.subquest_33._290_say = "Som forventet er du motiveret. Jeg stoler p\229 dig! "
gameforge.subquest_33._300_targetVid = "Stenen ved den gamle mand "
gameforge.subquest_33._30_say = "Hey du...[ENTER]Jeg har fundet informationer i gamle tekster, der[ENTER]siger at der findes et hemmeligt skattekort i[ENTER]denne landsby... Kender du de dyreguder udenfor[ENTER]byen? Hundeguden, Bj\248rneguden, Tigerguden og[ENTER]Svineguden.  "
gameforge.subquest_33._310_sayTitle = "S\248g skatten "
gameforge.subquest_33._320_say = "Hmm, under den gamle mands sten...[ENTER]Ingen id\233. M\229ske skulle jeg sp\248rge den gamle[ENTER]mand. Hvorfor er han s\229 langt v\230k? Pokkers. "
gameforge.subquest_33._330_sayTitle = "Gammel mand: "
gameforge.subquest_33._340_say = "Hvad s\248ger du efter? En skat? Haha, s\229 skal du[ENTER]lede l\230nge! Vis mig kortet ... Hmmm. Jeg tror,[ENTER]det er derovre. Held og lykke, hihi ... "
gameforge.subquest_33._350_say = "Dette m\229 v\230re stedet. Hej ho![ENTER]Pokkers, gulvet ser ud til at v\230re ganske sv\230rt.[ENTER]Hmm ...[ENTER][ENTER]Hej jeg kan se en boks! "
gameforge.subquest_33._360_sendLetter = "Skatten findes! "
gameforge.subquest_33._370_sayTitle = "Tilbage til Soon "
gameforge.subquest_33._380_say = "Du gravede det sted Dyreskattekortet viste og[ENTER]fandt virkelig en skattekiste! G\229 til Soon og[ENTER]fort\230l ham om det uventede resultat. "
gameforge.subquest_33._390_npcChat = "Jeg har fundet skatten! "
gameforge.subquest_33._400_say = "Oh! Dette er en overraskelse! Lad os se ...[ENTER]Forbl\248ffende.[ENTER]Det er pr\230cis s\229dan skatten er beskrevet i de[ENTER]gamle tekster. Nu skal jeg bare finde ud af[ENTER]hvordan man \229bner den. Men det er ikke dit[ENTER]problem. Tak! Her, tag dette som et tegn p\229 min[ENTER]taknemmelighed! "
gameforge.subquest_33._40_say = "Et gammel eventyr siger, at disse fire[ENTER]guddommelige monstre opdelte kortet i fire dele[ENTER]og beskytter disse omr\229der. Jeg er ikke sikker[ENTER]p\229, om det er rigtigt. Kunne du kontrollere, det[ENTER]for mig? Oh v\230r rar denne usikkerhed er ved at[ENTER]sl\229 mig ihjel ... Jeg beder dig, kan du hj\230lpe[ENTER]mig! "
gameforge.subquest_33._410_sayReward = "Du f\229r 1.400.000 erfaringspoints "
gameforge.subquest_33._420_sayReward = "Du f\229r 25.000 Yang "
gameforge.subquest_33._430_sayReward = "Du f\229r \197ndens maskehjelm +1. "
gameforge.subquest_33._440_sayReward = "Du f\229r Slots hjelm +1. "
gameforge.subquest_33._450_sayReward = "Du f\229r St\229l h\230tte +1. "
gameforge.subquest_33._460_sayReward = "Du f\229r Sollysets hat +1. "
gameforge.subquest_33._470_say = "N\229, hvor er han? \216nsker du at g\248re nar af mig?![ENTER]Du har ikke rigtig fundet ham, har du? "
gameforge.subquest_33._50_say = "Du er ikke interesseret i gamle skattekort? Du er[ENTER]m\230rkelig ... Jeg har t\230nkt mig at forts\230tte med[ENTER]at kigge efter spor i disse tekster. Kom tilbage,[ENTER]hvis du \230ndrer mening. "
gameforge.subquest_33._60_say = "Du kan ikke lide den slags eventyr, hva?[ENTER]Hvordan skal jeg bare f\229 fat i kortdelene...?[ENTER]Men okay.. Farvel. "
gameforge.subquest_33._70_say = "Du er en sand ven. Jeg tror, at du vil finde dem. "
gameforge.subquest_33._80_sendLetter = "Skattekortet fra bogormen "
gameforge.subquest_33._90_targetVid = "G\229 til bogormen "
gameforge.subquest_34 = {}
gameforge.subquest_34._100_say = "Kaptajnen har stadig problemer med at f\229 Sort[ENTER]Vind Banden under kontrol. Dr\230b Generalerne af[ENTER]Sort Vind Banden Jak-To, To-Su og Gu-Ryung.[ENTER]M\229ske er de rolige bagefter. "
gameforge.subquest_34._10_npcChat = "Hvad laver Sort Vind Banden? "
gameforge.subquest_34._110_say = "Generalerne blev dr\230bt! "
gameforge.subquest_34._120_select = "Ja. Pr\248v igen "
gameforge.subquest_34._130_say = "Vil du afslutte denne mission? "
gameforge.subquest_34._140_say = "At k\230mpe er ikke nemt, at vinde er endnu sv\230rere.[ENTER]Is\230r hvis du k\230mper mod Generalerne. Pr\248v igen. "
gameforge.subquest_34._150_say = "Som n\230vnt er det en meget st\230rk klan.[ENTER]P\229 gensyn "
gameforge.subquest_34._160_say = "Du er modig! Jeg tror du kan vinde over[ENTER]sortvind-klanen! "
gameforge.subquest_34._170_targetVid = "Rapportere til kaptajnen "
gameforge.subquest_34._180_say = "G\229 tilbage til kaptajnen og fort\230l at du har[ENTER]dr\230bt generalen.  "
gameforge.subquest_34._185_npcChat = "Jeg har dr\230bt Generalerne! "
gameforge.subquest_34._190_say = "Hmm ... Du besejrede Generalerne. Godt. Sort Vind[ENTER]Banden var begyndt at give os alle hovedpine, men[ENTER]takke v\230re din hj\230lp, vi vil v\230re i stand til at[ENTER]besejre dem nu. Uden Generalerne, vil det v\230re[ENTER]nemt. Her er en bel\248nning til dig.[ENTER]Jeg h\229ber snart at se dig igen! "
gameforge.subquest_34._200_sayReward = "Du modtager 1.000.000 erfaringspoint. "
gameforge.subquest_34._20_sayTitle = "Kaptajn "
gameforge.subquest_34._210_sayReward = "Du modtager en sprogring. "
gameforge.subquest_34._30_say = "Selvom du har skadet sortvind-klanen en del,[ENTER]giver de ikke op.[ENTER]Istedet for at v\230re rolige, g\229r de amok.[ENTER]Hvis vi skal besejre dem, skal vi dr\230be sortvinds[ENTER]generalerne.  "
gameforge.subquest_34._40_say = "N\229r Generalerne er besejret, er de \248vrige[ENTER]medlemmer ikke noget problem. Det bliver h\229rdt[ENTER]arbejde, men vi er n\248dt til at besejre Sort Vind[ENTER]Generalerne Jak-To, To-Su og Gu-Ryung. Hvis vi[ENTER]besejre dem, beh\248ver vi ikke bekymre os om Sort[ENTER]Vind Banden mere. OK, s\229 held og lykke, jeg vil[ENTER]bede for din sejr. "
gameforge.subquest_34._50_say = "Vil du afslutte denne mission? "
gameforge.subquest_34._60_say = "Hmm... N\229r du er klar, bes\248g mig.[ENTER]Der findes f\229 uddannede folk som dig. "
gameforge.subquest_34._70_say = "Du kan ikke klare det..[ENTER]Hvordan skal vi ellers vinde over sortvinds[ENTER]klanen...? "
gameforge.subquest_34._80_say = "Jeg vidste, jeg kunne stole p\229 dig! N\229r[ENTER]Generalerne er dr\230bt, vil medlemmerne af Sortvind[ENTER]Banden ikke v\230re et problem l\230ngere. Held og[ENTER]lykke! "
gameforge.subquest_34._90_sendLetter = "Dr\230b Sortvind Generalerne "
gameforge.subquest_36 = {}
gameforge.subquest_36._100_sayTitle = "Af sted for at finde stald drengen "
gameforge.subquest_36._10_targetVid = "Yonah: "
gameforge.subquest_36._110_say = "Du har samlet 10 stakke h\248. Bring dem til[ENTER]stalddrengen s\229 han kan fodre hestene. "
gameforge.subquest_36._120_sayTitle = "H\248 til staldene "
gameforge.subquest_36._130_say = "Der er en mad opbevaring i staldenen. Find 10[ENTER]stakke h\248 og bring dem til stald drengen inden[ENTER]hestene sulter! Du kan f\229 h\248 p\229 jagten. "
gameforge.subquest_36._140_npcChat = "Har du brug for H\248? "
gameforge.subquest_36._150_say = "Du kom her fordi Yonah har sendt dig? Jeg har[ENTER]h\248rt s\229 meget om dig. Ohh, alle vores heste ender[ENTER]med at sulte. Vi er n\248d til at rede dem. Hj\230lp[ENTER]mig med at f\229 H\248 til hestene! "
gameforge.subquest_36._160_say = "Et l\248fte er et l\248fte. Jeg \248nsker m\229ske ogs\229 at[ENTER]ride p\229 en hest senere. Jeg har absolut brug for[ENTER]at finde noget h\248! "
gameforge.subquest_36._170_say = "Jeg er ked af det. Jeg har ledt, men det er[ENTER]simpelthen umuligt at finde noget h\248. "
gameforge.subquest_36._180_say = "Jeg ved at det ikke er s\248dt af mig at sp\248rge dig[ENTER]om du vil g\248re mit arbejde, men jeg h\229ber stadig[ENTER]du vil g\248re det. Vil du pr\248ve igen? Jeg kender en[ENTER]meget vigtig person i et andet kongerige. Hvis du[ENTER]hj\230lper mig, vil jeg sp\248rge ham om han kan g\248re[ENTER]noget for dig. "
gameforge.subquest_36._190_select = "Pr\248v igen "
gameforge.subquest_36._200_say = "Jeg hj\230lper dig. Jeg har ikke styrken til at[ENTER]klare det. "
gameforge.subquest_36._20_npcChat = "Vores Stalde Har Problemer "
gameforge.subquest_36._210_say = "Jeg har ikke nok energi, selvom jeg virkelig[ENTER]gerne ville hj\230lpe dig. Men jeg er ikke st\230rk[ENTER]nok. "
gameforge.subquest_36._220_npcChat = "Jeg har h\248 til hestene. "
gameforge.subquest_36._230_say = "Har du fundet h\248et? Ohh, tak. Vi havde ikke nok[ENTER]mad til hestene, det fortalte jeg til Yonah. Han[ENTER]er en af mine gode venner. Jeg havde en ide, han[ENTER]ville sp\248rge omkring og se om nogen ville hj\230lpe.[ENTER]Men jeg troede ikke det vil l\248se sig s\229 hurtigt.[ENTER]Se bare hvor entusiastiske hestene spiser! "
gameforge.subquest_36._240_sayReward = "Du f\229r 1.800.000 erfaringspoints. "
gameforge.subquest_36._250_sendLetter = "Tilbage til Yonah "
gameforge.subquest_36._260_sayTitle = "Tilbage til Yonah "
gameforge.subquest_36._270_say = "Du bragte 10 h\248 stakke til de sultne heste til[ENTER]stald drengen. Returner til Yonah og fort\230l ham[ENTER]om din succes. "
gameforge.subquest_36._280_npcChat = "Der er blevet taget h\229nd om hestene! "
gameforge.subquest_36._290_say = "Hey du er tilbage![ENTER]Det var sikkert et h\229rdt job at samle s\229 meget[ENTER]h\248. Mange tak for ikke at opgive! Her er en lille[ENTER]gave til dig. "
gameforge.subquest_36._300_sayReward = "Du har modtaget en missionsbog. "
gameforge.subquest_36._30_say = "Hej, jeg har et sp\248rgsm\229l til dig! Jeg ved godt[ENTER]at du ikke er ansvarligt for stalden, men i den[ENTER]sidste tid har der v\230ret adskillige problemer og[ENTER]kunne godt bruge din hj\230lp. Hestene har haft en[ENTER]masse arbejde under krigen, men selv en st\230rk[ENTER]voksen hest har dens begr\230nsninger. "
gameforge.subquest_36._40_say = "Der findes mange heste, og ikke nok foder. Mange[ENTER]af dem d\248r. Kunne du venligst finde noget mad til[ENTER]hestene s\229 de kan f\229 deres energi tilbage? Jeg[ENTER]ved ikke hvem jeg ellers kan sp\248rge. Indsamle 10[ENTER]h\248 stakke, og bring dem til stalddrengen. Han[ENTER]kender allerede til problemet. Bare fort\230l ham at[ENTER]jeg har sendt dig. "
gameforge.subquest_36._50_select = "Jeg drager afsted med det samme! "
gameforge.subquest_36._60_select = "Nej, det er et simpel job. "
gameforge.subquest_36._70_say = "I nutiden findes der flere og flere folk som[ENTER]\248nsker at have en hest. Men ingen har overvejet[ENTER]kendsgerningen om at vi er ved at l\248be t\248r for[ENTER]foder til hestene. De sulter i staldene. Hvis du[ENTER]\230ndre mening, s\229 kom tilbage. "
gameforge.subquest_36._80_say = "Ahh.. Vores heste lider under[ENTER]underern\230ring....  "
gameforge.subquest_36._90_say = "Jeg ved godt du har travlt og jeg p\229skynder din[ENTER]hj\230lp. Heste er virkelig vigtige nu tildags.[ENTER]Derfor har vi ogs\229 virkelig brug for h\248et. "
gameforge.subquest_37 = {}
gameforge.subquest_37._100_say = "Yonah g\248r sit bedste for at producere nyt[ENTER]porcel\230n men g\248r ingen fremskridt med sine[ENTER]eksperimenter. G\229 til Uriel den l\230rde og sp\248rg[ENTER]ham om han ved noget om Celadon Porcel\230n. "
gameforge.subquest_37._10_targetVid = "Hemmeligheden omkring Celadon Porcel\230net "
gameforge.subquest_37._110_npcChat = "Kender du Celadon Porcel\230n? "
gameforge.subquest_37._120_sayTitle = "Uriel: "
gameforge.subquest_37._130_say = "Celadon Porcel\230n? N\229, jeg ved en masse om[ENTER]historie og videnskab, men jeg er ikke rigtig[ENTER]interesseret i kunst. Det er derfor, jeg er bange[ENTER]for jeg kan ikke fort\230lle dig noget om Celadon[ENTER]Porcel\230n. Men m\229ske Soon ved noget? Han er ikke[ENTER]s\230rlig popul\230r, men han l\230ser en masse b\248ger. Han[ENTER]ved m\229ske noget om det. "
gameforge.subquest_37._140_makequestbutton = "G\229 til Soon "
gameforge.subquest_37._150_targetVid = "G\229 til Soon "
gameforge.subquest_37._160_say = "Desv\230rre ved Uriel ikke noget om Celadon[ENTER]Porcel\230n. Men Soon bogormen l\230ser en masse i hans[ENTER]b\248ger. G\229 hen til ham og sp\248rge om han ved noget[ENTER]om hvordan det er lavet. "
gameforge.subquest_37._170_sayTitle = "Soon: "
gameforge.subquest_37._180_say = "Hvad vil du? Forstyr mig ikke, n\229r jeg l\230ser![ENTER]Huh? Celadon Porcel\230n? Selvf\248lgelig ved jeg[ENTER]noget, om det. Jeg har l\230st n\230sten et dusin b\248ger[ENTER]om p\229g\230ldende emne alene. Hvorfor? Godt de ikke[ENTER]kalder mig 'bogorm' for ingenting, du ved! Jeg[ENTER]kan forst\229 alt, hvad der er blevet skrevet i[ENTER]b\248ger! "
gameforge.subquest_37._190_say = "Jeg kan til hver en tid skrive hvordan man laver[ENTER]Celadon porcel\230n, men hvorfor skulle jeg det?[ENTER]Hmm. Alts\229, vent, jeg har en ide: Jeg har bedt[ENTER]handelsmanden i den n\230ste by efter en bog som jeg[ENTER]stadig mangler, men jeg har ikke tid til at tage[ENTER]derhen. Hent den for mig, s\229 vil jeg hj\230lpe dig[ENTER]med porcel\230net. Afsted med dig! "
gameforge.subquest_37._200_makequestbutton = "Afsted til handelsmanden "
gameforge.subquest_37._20_sayTitle = "Yonah: "
gameforge.subquest_37._210_targetVid = "G\229 til handelsmanden "
gameforge.subquest_37._220_say = "Bogormen Soon kender alt til Celadon porcel\230n.[ENTER]Han vil ikke dele sin viden uden at f\229 noget[ENTER]igen. Tag til handelsmanen og hent den bog som[ENTER]Soon har bestilt. "
gameforge.subquest_37._230_npcChat = "Soon sende mig... "
gameforge.subquest_37._240_say = "Hey, du kom tilbage for at hj\230lpe mig igen? Ahh.[ENTER]Du \248nsker, bogen til Soon. Jeg ville snart have[ENTER]v\230ret inde i byen alligevel, men han er meget[ENTER]ut\229lmodig og beder andre om at hente det fo ham.[ENTER]Hmm. Her er det. Jeg forst\229r ikke, hvad det er[ENTER]Soon kan lide ved en stak papirer. Det er meget[ENTER]mere vigtigt hurtigt at tjene Yang! "
gameforge.subquest_37._250_qSetTitle = "G\229 tilbage til Soon "
gameforge.subquest_37._260_targetVid = "G\229 tilbage til Soon "
gameforge.subquest_37._270_say = "Du har f\229et Soons bog fra handelsmanden. G\229[ENTER]tilbage til Soon og giv ham bogen s\229 fort\230ller[ENTER]han dig hvordan man laver Celadon porcel\230n. "
gameforge.subquest_37._280_npcChat = "Jeg har bogen. "
gameforge.subquest_37._290_say = "Yay! Jeg har endelig f\229et den nye bog! Mange tak.[ENTER]Der er ikke mange b\248ger, jeg ikke har l\230st ...[ENTER]Jeg har skrevet ned, hvad der er vigtigt omkring[ENTER]det at lave Celadon Porcel\230n. Hold dig til mine[ENTER]noter, og du vil producere fantastiske porcel\230n.[ENTER]Og nu er det tid for mig at l\230se den nye bog.[ENTER]Farvel. "
gameforge.subquest_37._300_makequestbutton = "Tilbage til Yonah "
gameforge.subquest_37._30_say = "Hmm ... Det her er ikke godt. Og heller ikke[ENTER]denne her ... Oh, hej! Kig her: Jeg producerer[ENTER]porcel\230n non-stop, men det meste af det bryder[ENTER]sammen med det samme. Jeg tror jeg har brug for[ENTER]en ny type af banebrydende porcel\230n ... "
gameforge.subquest_37._310_targetVid = "Aflever noterne til Yonah "
gameforge.subquest_37._320_say = "Soon har holdt sit l\248fte og nedskrevet hvordan[ENTER]man br\230nder Celadon Porcel\230n. Tage det til Yonah. "
gameforge.subquest_37._330_say = "Ooh![ENTER]Alt om produktionen af Celadon Porcel\230n er[ENTER]skrevet her. Med hj\230lp fra disse notater kommer[ENTER]jeg endelig med i historieb\248gerne som en mester i[ENTER]kunsth\229ndv\230rk. Tak for din hj\230lp. Jeg vil v\230re i[ENTER]stand til at vise dig mit bedste keramiske[ENTER]arbejde snart! Du kan regne med mig! Jeg har[ENTER]t\230nkt mig at producere s\229danne fantastiske[ENTER]Celadon Porcel\230n, at det vil overleve i[ENTER]\229rhundreder. "
gameforge.subquest_37._340_sayReward = "Du har modtaget 2,500,000 erfaringspoint. "
gameforge.subquest_37._350_sayReward = "Du har modtaget 35.000 Yang. "
gameforge.subquest_37._360_sayReward = "Du f\229r jade sko +3 "
gameforge.subquest_37._40_say = "Jeg vil afpr\248ve en ny metode...[ENTER]Seladon-porcel\230n er sv\230rt at fremstille, derfor[ENTER]kankun f\229 personer det.[ENTER]Men jeg har brug for det, s\229 jeg kan danne[ENTER]kunstv\230rker![ENTER]I hvert fald...[ENTER]Ja, den l\230rte Uriel kunne vide noget om det![ENTER]G\229 til den l\230rte Uriel og sp\248rg om fremstilling[ENTER]af Seladon-porcel\230n, han kan sikkert hj\230lpe[ENTER]dig!  "
gameforge.subquest_37._50_say = "Vil du afslutte denne mission? "
gameforge.subquest_37._60_say = "Hm, jeg tror du har for travlt? Husk at komme[ENTER]tilbage, hvis du har noget tid til overs. "
gameforge.subquest_37._70_say = "Jeg vil fremstille det bedste porcel\230n..[ENTER]Aha... Det forst\229r jeg -[ENTER]farvel...  "
gameforge.subquest_37._80_say = "Tak. Uriel ved hvad der skal g\248res. Vi ses snart! "
gameforge.subquest_37._90_targetVid = "Lad os g\229 til Uriel "
gameforge.subquest_38 = {}
gameforge.subquest_38._100_say = "J\230geren Yang-Shin og hans dekorerede buer, som er[ENTER]et familie arvestykke, er blevet stj\229let fra ham.[ENTER]Drag til Sangsun Dong og tag den dekorerede bue[ENTER]med tilbage fra de tyvagtige aber. "
gameforge.subquest_38._10_targetVid = "J\230gerens Skat "
gameforge.subquest_38._110_sendLetter = "Dekoreret bue fundet. "
gameforge.subquest_38._120_targetVid = "G\229 til j\230geren Yang-Shin. "
gameforge.subquest_38._125_say = "Du har fundet J\230gerens dekorerede bue. Bring den[ENTER]tilbage til Yang-Shin. "
gameforge.subquest_38._130_npcChat = "Her er din bue.. "
gameforge.subquest_38._140_say = "Wow, det er! Min bue, yay! Min \230re er blevet[ENTER]genoprettet. Phew. Jeg har lidt lige siden den[ENTER]blev v\230k... Jeg er virkelig taknemmelig for din[ENTER]hj\230lp. Det er en \230re for mig at give dig dette.[ENTER]Det ser m\229ske ikke ud af meget, men det er fra[ENTER]hjertet s\229 tag den. Mange tak, jeg kan nu[ENTER]forts\230tte mit liv i fred! "
gameforge.subquest_38._150_sayReward = "Du f\229r 1.500.000 erfaringspoints. "
gameforge.subquest_38._160_sayReward = "Du har modtaget 35.000 Yang. "
gameforge.subquest_38._170_sayReward = "Du har modtaget en Tapperhedens kappe. "
gameforge.subquest_38._180_say = "Du har fundet min bue? Men hvor er den? Har du[ENTER]mistet den igen? "
gameforge.subquest_38._190_select = "Ja, jeg vil forts\230tte med at s\248ge. "
gameforge.subquest_38._200_say = "S\229 m\229 det v\230re s\229dan.[ENTER]Pas p\229 dig selv. "
gameforge.subquest_38._20_say = "Hey, kunne du lige lutte til mig et sekund? Som[ENTER]du kan se er jeg j\230ger; Min familie har jaget i[ENTER]generationer. Vi er alle j\230gere, en familie med[ENTER]utrolig meget \230re. Men jeg har lavet en stor[ENTER]fejl, som ender med at bringe mig i skam foran[ENTER]hele min familie. "
gameforge.subquest_38._210_say = "Vil du pr\248ve igen? Mange tak.[ENTER]Med dine evner, burde du v\230re i stand til at g\248re[ENTER]det. "
gameforge.subquest_38._30_say = "Det er omkring en overd\229dig dekoreret bue, som[ENTER]blev stj\229let af aberne for et stykke tid siden.[ENTER]Jeg var p\229 jagt i Abegrotten, jeg var kun[ENTER]uopm\230rksom et \248jeblik - de udnyttede situationen[ENTER]og stjal den fra mig. "
gameforge.subquest_38._40_say = "Jeg har aldrig v\230ret inde i Sangsun Dong dybet,[ENTER]s\229 jeg kan ikke finde rundet der, og har brug for[ENTER]din hj\230lp. Et par lokale fortalte mig at du var[ENTER]meget talentfuld. Det er derfor jeg har spurgt[ENTER]dig om denne tjeneste. Jeg kan ikke m\248de mine[ENTER]forf\230dre uden min dekorerede bue. "
gameforge.subquest_38._50_sayTitle = "Yang-Shin: "
gameforge.subquest_38._60_say = "Oh, jeg skal hurtig have den tilbage...[ENTER]V\230r venlig og kom igen, n\229r du har tid.[ENTER]Lev vel.  "
gameforge.subquest_38._70_say = "Okay...[ENTER]Pas p\229 p\229 dine rejser. "
gameforge.subquest_38._80_say = "Du kan nemt finde det, det er en rigt udsmykket[ENTER]bue. Jeg vil give dig en storsl\229et bel\248nning for[ENTER]det! "
gameforge.subquest_38._90_sayTitle = "Se efter den Overd\229dige Dekorerede bue "
gameforge.subquest_39 = {}
gameforge.subquest_39._100_sayTitle = "Forr\230deren Balsos tilstand "
gameforge.subquest_39._10_targetVid = "Levering til Forr\230deren Balso "
gameforge.subquest_39._110_say = "Forr\230deren Balsos helbred er blevet forv\230rret.[ENTER]Drag til Baek-Go og sp\248rg hvordan vi kan hj\230lpe[ENTER]Balso. "
gameforge.subquest_39._120_makequestbutton = "G\229 til Baek-Go. "
gameforge.subquest_39._130_qSetTitle = "G\229 til Baek-Go. "
gameforge.subquest_39._140_targetVid = "Afsted til Baek-Go "
gameforge.subquest_39._150_npcChat = "Jeg har en pationt... "
gameforge.subquest_39._160_sayTitle = "Baek-Go: "
gameforge.subquest_39._170_say = "Ohh, det er dig. Hvordan har du det? Du behandler[ENTER]en syg patient? Fort\230l mig hvad der er i vejen[ENTER]med ham... Hmm... Og hvad medicin har han taget?[ENTER]Hvad?! Ingen undren at han f\229r det v\230rre! Denne[ENTER]medicin er totalt uegnet! "
gameforge.subquest_39._180_say = "Han er heldig han stadig er i live! Det er meget[ENTER]farligt at give en syg person en forkert[ENTER]behandling! Men jeg ved hvad der vil hj\230lpe ham.[ENTER]Der er en bestemt urt der befrir kroppen for gift[ENTER]og vil genopbygge helbredet.[ENTER]Dog er s\248gningen efter den meget farlig. "
gameforge.subquest_39._190_say = "S\229 vidt jeg ved gror urten kun i Sangsung Dong.[ENTER]Men den bliver altid h\248stet til Abeherren som[ENTER]elsker at spise den. Du er n\248d til at dr\230be ham[ENTER]for at f\229 den.[ENTER]Jeg kan lave den rigtige medicin hvis du bringer[ENTER]mig urten. "
gameforge.subquest_39._200_select = "Ok, jeg henter den. "
gameforge.subquest_39._20_npcChat = "Omkring din medicin... "
gameforge.subquest_39._210_select = "Det kan jeg ikke "
gameforge.subquest_39._220_say = "Vil du afslutte denne mission? "
gameforge.subquest_39._230_select = "Ja "
gameforge.subquest_39._240_say = "N\229, kom igen n\229r du har tid.[ENTER]Mange mennesker er syge, men kun f\229, s\248ger efter[ENTER]medicin.  "
gameforge.subquest_39._250_say = "Hmm, s\229dan er det desv\230rre. Det er en skam at du[ENTER]ikke har mod nok. Hvordan mon alt dette ender... "
gameforge.subquest_39._260_say = "Ohh, tak! Det kommer til at v\230re h\229rdt arbejde.[ENTER]Men du vil hj\230lpe et antal mennesker! "
gameforge.subquest_39._270_makequestbutton = "Urter fra abeherren "
gameforge.subquest_39._280_targetVid = "G\229 tilbage til Baek-Go "
gameforge.subquest_39._290_sayTitle = "Fundet urter fra den h\229rde abe "
gameforge.subquest_39._300_say = "Du har taget urterne fra den h\229rde abe fra[ENTER]abeherren. Bring dem til Baek-Go, s\229 han kan lave[ENTER]medicinen til Balso. "
gameforge.subquest_39._30_say = "Mange tak for at bringe mig medicinen sidste[ENTER]gang. Men der er et problem... Medicinen har[ENTER]mistet sin effekt. Jeg tror den er blevet d\229rlig.[ENTER]*host* - Jeg har desperat brug for behandling. "
gameforge.subquest_39._310_sayTitle = "F\229 fat i urterne fra Sangsun Dong "
gameforge.subquest_39._320_say = "Beak-Go kan lave medicinen til forr\230deren Balsos[ENTER]sygdom. Han har brug for urterne fra de sv\230re[ENTER]aber for dette. Du kan f\229 dem fra abeherren i den[ENTER]sv\230re abegrotte. "
gameforge.subquest_39._330_npcChat = "Urter fra den h\229rde abe... "
gameforge.subquest_39._340_say = "Det virker som om at sygdommen er ved at sprede[ENTER]sig til en epidemi, men vi kender ikke grunden.[ENTER]Men hvor om alting er, har den akademiske[ENTER]organisation fortalt os at en kur er mulig med[ENTER]abe urter. Hvad er der i vejen? Har du allerede[ENTER]fundet urterne? "
gameforge.subquest_39._350_select = "Ikke endnu. Men snart! "
gameforge.subquest_39._360_select = "Jeg kan ikke f\229 fat i de urter... "
gameforge.subquest_39._370_say = "\216nsker du virkelig at opgive? Hmm, jeg formoder[ENTER]ikke du kan g\248re ret meget mere end det. Hvad[ENTER]skal jeg g\248re? Disse urter kunne v\230re en virkelig[ENTER]velsignelse... "
gameforge.subquest_39._380_select = "Jeg kan ikke g\248re det. "
gameforge.subquest_39._390_select = "Jeg vil hj\230lpe! "
gameforge.subquest_39._400_say = "Aberne er for st\230rke for mig. Jeg kan ikke komme[ENTER]til urterne. Undskyld. "
gameforge.subquest_39._40_say = "Jeg ved, at der i n\230ste by bor en doktor. Kan du[ENTER]bes\248ge ham og forklare min tilstand? S\229 han[ENTER]fort\230lle dig, hvordan jeg kan helbredes? Som du[ENTER]selv kan se, er jeg ikke selv i stand til at g\229[ENTER]til byen. Jeg er stadig meget taknemmelig da du[ENTER]hjalp mig sidst og jeg vil selvf\248lgelig ogs\229 give[ENTER]dig en bel\248nning denne gang[ENTER]ogs\229.  "
gameforge.subquest_39._410_say = "Du n\230gter at hj\230lpe folk som lider fra en mystisk[ENTER]og forf\230rdelig sygdom. Kom ud af mit syn. "
gameforge.subquest_39._420_say = "Du har ret. Nogen er n\248d til at finde disse[ENTER]urter, ellers vil alle disse mennesker lide[ENTER]skr\230kkeligt. Jeg vil tage h\229nd om det. "
gameforge.subquest_39._430_say = "Okay s\229. Skynd dig! "
gameforge.subquest_39._440_say = "Det har virkelig lykkes dig at finde urter fra de[ENTER]h\229rde aber! Jeg h\229ber de virkelig kan heale denne[ENTER]mystiske sygdom. Vent et \248jeblik, jeg vil hurtigt[ENTER]lave medicinen nu. "
gameforge.subquest_39._450_sayTitle = "Baek-Go: "
gameforge.subquest_39._460_say = "Her er medicinen. Skynd dig til patienten og giv[ENTER]den til ham. S\229 skulle han f\229 det bedre snart.[ENTER]Fort\230l ham ogs\229, at det er bedre at sp\248rge[ENTER]doktoren hvilken medicin der er rigtig. "
gameforge.subquest_39._470_makequestbutton = "Aflever medicinen til Balso "
gameforge.subquest_39._480_targetVid = "Du giver forr\230deren Balso sin medicin "
gameforge.subquest_39._490_sayTitle = "Forr\230der Balsos medicin "
gameforge.subquest_39._500_say = "Baek-Go har lavet medicinen fra urterne fra de[ENTER]h\229rde aber som kan kurere mange sj\230ldne sygdomme.[ENTER]Bring det til forr\230deren Balso i nabo landsbyen. "
gameforge.subquest_39._50_say = "Vil du opgive missionen? "
gameforge.subquest_39._510_npcChat = "Her er medicinen "
gameforge.subquest_39._520_say = "Bringer du mig den nye medicin? Har der v\230ret[ENTER]nogen fremskridt i den medicinske forskning?[ENTER]Undskyld jeg har besv\230ret dig. Jeg burde have[ENTER]spurgt en l\230ge efter r\229d fra begyndelsen af. Dog[ENTER]er jeg n\248d til at acceptere det, jeg er n\248d til[ENTER]at tage denne medicin nu. "
gameforge.subquest_39._530_say = "Tusind tak for at du hj\230lp mig ud af klemmen.[ENTER]Jeg har ikke mange venner. Her, jeg ved det ikke[ENTER]er meget, men det kommer fra hjertet. Acceptere[ENTER]det venligst. Hvis jeg nogensinde kommer mig, vil[ENTER]jeg aldrig glemme dig. "
gameforge.subquest_39._540_sayReward = "Du modtager 4.000.000 erfaringspoint. "
gameforge.subquest_39._550_sayReward = "Du modtager 65.000 Yang. "
gameforge.subquest_39._60_say = "N\229r du ved, hvordan jeg skal behandles, m\248des vi[ENTER]igen. "
gameforge.subquest_39._70_sayTitle = "Forr\230deren Balso : "
gameforge.subquest_39._80_say = "Bliver jeg n\248d til at leve s\229dan, til mit livets[ENTER]ende...?[ENTER]Vi ses... "
gameforge.subquest_39._90_say = "Tak... V\230r forsigtigt. "
gameforge.subquest_40 = {}
gameforge.subquest_40._100_say = "Jeg viste jeg kunne stole p\229 dig! Det er et sv\230rt[ENTER]job, men jeg er sikker p\229 at du kan klare det.[ENTER]Held og lykke! "
gameforge.subquest_40._10_targetVid = "Underst\248ttende Krigs Enhed "
gameforge.subquest_40._110_targetVid = "G\229 tilbage til kaptajnen "
gameforge.subquest_40._120_say = "Du har samlet alle 5000 pilespidser.[ENTER]Bring dem til kaptajnen. "
gameforge.subquest_40._130_say = "H\230ren har problemer med at f\229 flere pile. Dr\230b[ENTER]pestbueskytter ved Sohan bjerget og tag deres[ENTER]pilespidser til kaptajnen. 5.000 er nok. "
gameforge.subquest_40._140_npcChat = "Omkring pilespidserne... "
gameforge.subquest_40._150_say = "Disse pestbueskytter har en bestemt sygdom, som[ENTER]har spredt sig p\229 tv\230rs af kontinentet. Ikke[ENTER]engang vores l\230ger kan forklare det.[ENTER]Pilespidserne er stadig normale i \248jeblikket, men[ENTER]de bliver mere og mere giftige. "
gameforge.subquest_40._160_select = "Jeg vil forts\230tte. "
gameforge.subquest_40._170_say = "Vil du afslutte denne mission? "
gameforge.subquest_40._180_say = "Du er bange for sygdommen. Fald til ro, og kom[ENTER]igen. "
gameforge.subquest_40._190_say = "Er du sikker p\229 du vil give op??[ENTER]Hmm, m\229sker er opgaven bare for sv\230rt.[ENTER]Jeg sp\248rger en anden..[ENTER]Ok... Tag resten og forsvind "
gameforge.subquest_40._200_say = "Jeg kan se det..[ENTER]Du opgiver ikke, vel?[ENTER]S\229 afsted. "
gameforge.subquest_40._20_say = "Giv agt krigere! Som du kan se, er antallet af[ENTER]angreb fra vores fjender steget hver dag. Vi har[ENTER]ogs\229 modtaget alarmerne informationer fra[ENTER]Yu-Hwan. For at g\248re en lang historie kort: Vi[ENTER]har ikke nok pile! "
gameforge.subquest_40._210_npcChat = "Her er 5.000 pilespidser! "
gameforge.subquest_40._220_say = "Fantastisk arbejde! Nu kan vi forberede angrebet.[ENTER]Nu vil jeg give ordren til at lave pilene med det[ENTER]samme. Det var en virkelig god hold indsats. Jeg[ENTER]h\229ber vi kan regne med dig senere. "
gameforge.subquest_40._230_say = "Her er din bel\248nning. N\230ste gang jeg har et[ENTER]vigtigt job, vil du v\230re den f\248rste jeg sender[ENTER]bud efter.[ENTER]Alt det bedste og vi ses snart! "
gameforge.subquest_40._240_sayReward = "Du har modtaget 4.500.000 erfaringspoint. "
gameforge.subquest_40._250_sayReward = "Du har modtaget 50,000 Yang. "
gameforge.subquest_40._260_sayReward = "Du har modtaget 3 x Kritisk angreb.[ENTER]Du har modtaget 3 x Gennemborende angreb. "
gameforge.subquest_40._30_say = "Bueskytter er en vigtigt strategisk faktor i[ENTER]krigsf\248relse. S\229 snart fjenderne er inden for[ENTER]r\230kkevide skal vores bueskytter skyde mod dem. P\229[ENTER]den m\229de kan vi enten jage dem v\230k med det samme[ENTER]eller i det mindste reducere deres antal. Men[ENTER]hvis der er for mange angribere p\229 kort tid er vi[ENTER]snart l\248bet t\248r for pile. "
gameforge.subquest_40._40_say = "Det er grunden til at jeg har brug for dig! Drag[ENTER]til Sohan bjerget og dr\230b pestbueskytter for at[ENTER]f\229 deres pilehoveder. De pilehoveder er giftige[ENTER]men deres effekt vil hj\230lpe os med at besejre[ENTER]fjenden. Vi har brug for 5.000 pilespidser. Hvad[ENTER]siger du? "
gameforge.subquest_40._50_select = "Jeg acceptere. "
gameforge.subquest_40._60_select = "Det er h\229rdt for mig. "
gameforge.subquest_40._70_say = "Vil du afslutte denne mission? "
gameforge.subquest_40._80_say = "Er der for langt til Sohan bjerget for dig? T\230nk[ENTER]over det. Missionen er af stor vigtighed. "
gameforge.subquest_40._90_say = "Hmm, er du bange for pest-bueskytterne?![ENTER]Jeg har vel overvurderet din styrke.[ENTER]S\229 er der intet h\229b for os mere.  "
gameforge.subquest_41 = {}
gameforge.subquest_41._015_npcChat = "Hvad l\230ser du? "
gameforge.subquest_41._100_say = "Du har samlet alle 100 Edderkops \248je til[ENTER]Octavio's nye opskrift. Aflever dem hurtigt til[ENTER]ham. "
gameforge.subquest_41._10_targetVid = "Specielle Edderkops \216jne "
gameforge.subquest_41._110_sayTitle = "Hent Edderkops \248je "
gameforge.subquest_41._120_say = "Octavio \248nsker at afpr\248ve sin nye opskrift kaldet[ENTER]'Edderkops \248je special'. For at g\248re det han har[ENTER]brug for 100 Edderkops \248je fra Edderkopperne i[ENTER]Yongbi \248rkenen. "
gameforge.subquest_41._130_targetVid = "Tilbage til Octavio "
gameforge.subquest_41._140_npcChat = "Jeg har Edderkops \248je. "
gameforge.subquest_41._150_sayTitle = "Octavio: "
gameforge.subquest_41._160_say = "Vis mig dem. N\248jagtig hundrede \248je, meget godt.[ENTER]N\229, lad os se ...[ENTER]Mmhhh, f\230rdig! Har du ogs\229 lyst til at pr\248ve? Se[ENTER]ikke s\229 forf\230rdet ud. Det dr\230ber dig ikke. "
gameforge.subquest_41._170_say = "Hmm, hmm... Sikke en oplevelse! Meget n\230rende,[ENTER]ikke alt for s\248d.... utroligt smag! Jeg vidste[ENTER]det var umagen v\230rd. Jeg kunne aldrig har gjort[ENTER]det uden dig. Mange tak for din hj\230lp! "
gameforge.subquest_41._180_sayReward = "Du har modtaget 2,100,000 erfaringspoints. "
gameforge.subquest_41._190_say = "Hvad snakker du om? Der er ikke ethundrede \248je,[ENTER]kan jeg fort\230lle, uden at t\230lle dem![ENTER]Hent venligst nogle flere. "
gameforge.subquest_41._200_say = "Jeg vil gerne koge det...[ENTER]N\229, men pyt. Vi ses og pas godt p\229 dig selv. "
gameforge.subquest_41._20_say = "Hey, hvordan har du det? Jeg l\230ser bare en[ENTER]madlavningsbog, som Soon meget venligt gav mig.[ENTER]Jeg fandt en meget interessant opskrift kaldet[ENTER]'Edderkops \248je special' i den.[ENTER]Jeg har aldrig set noget lignende f\248r! Har du?[ENTER]Det m\229 v\230re en s\230rlig ret fra et andet land. "
gameforge.subquest_41._210_say = "Tak fordi du ikke lod mig i stikken.[ENTER]Du er meget venlig! "
gameforge.subquest_41._30_say = "Jeg vil virkelig gerne pr\248ve denne ret, men[ENTER]hvordan skal jeg formodes at f\229 fat i Edderkops[ENTER]\248je? Jeg har virkelig brug for din hj\230lp igen![ENTER]V\230r venlig og hent Edderkops \248je fra[ENTER]Edderkopperne i Yongbi \248rkenen. "
gameforge.subquest_41._40_say = "Vil du g\248re det for mig? Jeg vil virkelig v\230re[ENTER]meget taknemmelig. For at pr\248ve denne opskrift[ENTER]har jeg brug for hundrede \248je for at f\229 en[ENTER]rimelig portion st\248rrelse. Jeg er virkelig sp\230ndt[ENTER]... "
gameforge.subquest_41._50_say = "Vil du afslutte denne mission? "
gameforge.subquest_41._60_say = "Jeg vil absolut koge den opskrift, s\229 hvis du vil[ENTER]g\248re mig den tjeneste kom og bes\248g[ENTER]mig!.  "
gameforge.subquest_41._70_say = "Hm... Hvor f\229r jeg s\229 de \248jne fra...[ENTER]Ok, farvel. "
gameforge.subquest_41._80_say = "Tak. Jeg vidste du ville hj\230lpe mig. Du f\229r ogs\229[ENTER]serveret en dejlig ret.  "
gameforge.subquest_41._90_sayTitle = "Tilbage til Octavio "
gameforge.subquest_42 = {}
gameforge.subquest_42._100_say = "Jeg er ked af at h\248re det. Jeg h\248re s\229 mange[ENTER]stemmer fra d\248de mennesker, som ikke bare kan[ENTER]hvile i fred. Vi er virkelig n\248d til at hj\230lpe[ENTER]dem. Jeg vil sp\248rge en anden. Farvel. "
gameforge.subquest_42._10_targetVid = "Lad De D\248de Hvile "
gameforge.subquest_42._110_say = "Hvor modig af dig. Jeg er sikker p\229 at tapre unge[ENTER]krigere som dig selv vil snart drage til Nirvana[ENTER]med din hj\230lp. "
gameforge.subquest_42._120_say = "Skr\230kkelige krige dr\230ber alt for ofte unge m\230nd,[ENTER]og det bliver flere og flere. Det er krigere som[ENTER]k\230mper i front for deres familie og deres land i[ENTER]forreste r\230kke. Men efter deres d\248d, kan nogen af[ENTER]dem bare ikke forts\230tte til Nirvana og forbliver[ENTER]i vores verden. "
gameforge.subquest_42._130_say = "Jeg h\248rte, at de stolte m\248rke oberst i Hwang[ENTER]tempelet har et tempelt\248rkl\230det og tempelbogen.[ENTER]Hj\230lp mig og mine kammerater med at berolige dem[ENTER]som er d\248de for deres land. "
gameforge.subquest_42._140_sayTitle = "Returner til Dragekrafts l\230ren "
gameforge.subquest_42._150_say = "Du har fundet et tempel t\248rkl\230de og en tempel[ENTER]l\230re. Bring dem til Dragekraft l\230ren, s\229 Shamaner[ENTER]kan udf\248re deres ritual og berolige de d\248de. "
gameforge.subquest_42._160_sayTitle = "Hent tempel-halst\248rkl\230det og tempelbogen "
gameforge.subquest_42._170_say = "Shamanerne har brug for et Tempelt\248rkl\230de og en[ENTER]Tempell\230re til en ceremoni der kan berolige[ENTER]\229nderne af de soldater som er d\248de under krigen.[ENTER]Dr\230b den Stolte M\248rke Oberst i Hwang templet for[ENTER]at f\229 de rituelle genstande. "
gameforge.subquest_42._180_npcChat = "Du har fundet halst\248rkl\230det og bogen "
gameforge.subquest_42._190_say = "Det var dejligt. Nu kan vi berolige de dr\230bte[ENTER]soldater. De gjorde deres bedste, nu kan de hvile[ENTER]i fred. Lad mig give dig en bel\248nning for denne[ENTER]noble bedrift. "
gameforge.subquest_42._200_sayReward = "Du har modtaget 1.700.000 erfaringspoints. "
gameforge.subquest_42._20_sayTitle = "Dragemagtens l\230rer: "
gameforge.subquest_42._210_sayReward = "Du har modtaget 30.000 Yang. "
gameforge.subquest_42._220_sayReward = "Du har modtaget 3 diamanter. "
gameforge.subquest_42._230_say = "Det var dejligt. Nu kan vi berolige de dr\230bte[ENTER]soldater. De gjorde deres bedste, nu kan de hvile[ENTER]i fred. Lad mig give dig en bel\248nning for denne[ENTER]noble bedrift. "
gameforge.subquest_42._30_say = "Skr\230kkelige krige dr\230ber alt for ofte unge m\230nd,[ENTER]og det bliver flere og flere. Det er krigere som[ENTER]k\230mper i front for deres familie og deres land i[ENTER]forreste r\230kke. Men efter deres d\248d, kan nogen af[ENTER]dem bare ikke forts\230tte til Nirvana og forbliver[ENTER]i vores verden. "
gameforge.subquest_42._40_say = "Der fort\230lles, at soldaterne blev resistente mod[ENTER]d\248den under krigen. De troede, at de stadig[ENTER]skulle forsvare deres land.[ENTER]Vores shaman \248nsker at holde en ceremoni for at[ENTER]berolige \229nderne. For at g\248re dette, har vi brug[ENTER]for et specielt Tempelt\248rkl\230de og en tempelbog,[ENTER]som er sv\230re at finde i disse dage. Kunne du[ENTER]finde begge dele til os? "
gameforge.subquest_42._50_say = "Jeg h\248rte, at de stolte m\248rke oberst i Hwang[ENTER]tempelet har et tempelt\248rkl\230det og tempelbogen.[ENTER]Hj\230lp mig og mine kammerater med at berolige dem[ENTER]som er d\248de for deres land. "
gameforge.subquest_42._60_select = "Jeg vil hj\230lpe dig. "
gameforge.subquest_42._70_select = "Vil du afbryde missionen? "
gameforge.subquest_42._80_say = "Vil du afslutte denne mission? "
gameforge.subquest_42._90_say = "Hj\230lp os med at berolige deres sj\230le, s\229 de kan[ENTER]hvile i fred. Jeg venter p\229 din hj\230lp her. "
gameforge.subquest_44 = {}
gameforge.subquest_44._100_sendLetter = "Edderkoppen med Klokken "
gameforge.subquest_44._10_targetVid = "Edderkoppen "
gameforge.subquest_44._110_say = "Taurean siger at han hang en klokke p\229 en[ENTER]edderkop. Nu vil Yu-Rang vide om hans ven virkeli[ENTER]er s\229 tapper som han siger.[ENTER]S\248g efter edderkoppen i \248rkenen. "
gameforge.subquest_44._120_say = "Har du fundet edderkoppen med klokken? Nej? Du[ENTER]vil sikkert aldrig finde den. Taurean er en kujon[ENTER]og vil bare vise sig. "
gameforge.subquest_44._130_sendLetter = "Kan ikke finde klokken "
gameforge.subquest_44._140_sayTitle = "Mange edderkopper, ingen klokke "
gameforge.subquest_44._150_say = "Du har dr\230b nogle edderkopper men har ikke fundet[ENTER]en klokke. Du kan ikke lede for evigt. Det vil[ENTER]sikkert v\230re bedst at g\229 til Taurean og sp\248rge[ENTER]ham om sandheden. "
gameforge.subquest_44._160_sendLetter = "Find Taurean "
gameforge.subquest_44._170_targetVid = "Sp\248rg Taurean om klokken "
gameforge.subquest_44._180_say = "Det er usandsynligt at Taurean var tapper nok til[ENTER]at putte klokken p\229 en edderkop. Det er bedst at[ENTER]sp\248rge ham direkte om sandheden. "
gameforge.subquest_44._190_npcChat = "Fort\230l mig om dit v\230dem\229l med Yu-Rang... "
gameforge.subquest_44._200_say = "Kender du til v\230ddem\229let med Yu-Rang? Hun tror[ENTER]mig ikke, og tror ikke at jeg gjorde det. Hun[ENTER]tror at jeg ville falde d\248d om hvis bare jeg s\229[ENTER]en gigantisk edderkop. "
gameforge.subquest_44._20_npcChat = "En edderkpop med en klokke...? "
gameforge.subquest_44._210_say = "For at v\230re \230rlig... Hun har ret. Jeg var ikke[ENTER]tapper nok til at fort\230lle hende det, da jeg er[ENTER]for stolt. "
gameforge.subquest_44._220_say = "Men du ser meget st\230rk ud! Kan du ikke putte en[ENTER]klokke p\229 en baby edderkop for mig, og sige det[ENTER]var mig? Vil du ikke nok. Ellers vil de g\248re nar[ENTER]af mig resten af mit liv. "
gameforge.subquest_44._230_say = "Vil du afslutte denne mission? "
gameforge.subquest_44._240_say = "Du vil ikke g\248re det? Men du fort\230ller ikke[ENTER]Yu-Rang sandheden?[ENTER]Vil du ikke nok hj\230lpe mig. Kom tilbage n\229r du[ENTER]har tid til mig! "
gameforge.subquest_44._250_say = "Nu vil Yu-Rang aldrig tale med mig igen![ENTER]Eller bare grine af mig... "
gameforge.subquest_44._260_say = "Ah! Jeg havde ret! Jeg viste du var lige s\229 s\248d[ENTER]som du ser ud. Held og lykke! "
gameforge.subquest_44._270_sendLetter = "G\229 tilbage til Yu-Rang "
gameforge.subquest_44._280_say = "G\229 tilbage til Yu-Rang og fort\230l om Taureans[ENTER]l\248gnhistorie.  "
gameforge.subquest_44._290_npcChat = "Yu-Rang er meget skuffet over dig. "
gameforge.subquest_44._300_say = "Har du fortalt hende det?![ENTER]Jeg kan ikke forst\229 at hun ikke \248nsker at v\230re[ENTER]min ven mere. Men det g\248r mig meget ked. Jeg[ENTER]h\229ber at jeg kan \230ndre hendes holdning engang.[ENTER]M\229ske kan jeg finde p\229 noget virkelig rart til[ENTER]hende... "
gameforge.subquest_44._30_say = "Hey, kunne du g\248re mig en tjeneste? Min ven[ENTER]Taurean er meget sur fordi jeg kaldte ham en[ENTER]kujon. Han siger han faktisk er meget tapper, og[ENTER]vi v\230dede om om han kunne h\230nge en klokke om[ENTER]halsen p\229 en Baby edderkop. Han har ogs\229 fortalt[ENTER]mig at han allerede har gjort det, men jeg tror[ENTER]ikke p\229 ham. "
gameforge.subquest_44._310_npcChat = "Taurean l\248g. "
gameforge.subquest_44._320_say = "Hans historie var ikke sand?[ENTER]Hmm, jeg er ikke rigtig sur over at han l\248g.[ENTER]Ingen kan lide at tabe ansigt.[ENTER]Men han kunne i det mindste havde fors\248gt at g\248re[ENTER]g\248re det sandt! Jeg \248nsker ikke at v\230re venner[ENTER]med s\229dan en kujon mere. "
gameforge.subquest_44._330_sayReward = "Yu-Rang giver dig en bel\248nning for din \230rlighed. "
gameforge.subquest_44._340_sayReward = "Du har modtaget 30.000 Yang. "
gameforge.subquest_44._350_sayReward = "Du har modtaget 350.000 erfaringspoints. "
gameforge.subquest_44._360_sendLetter = "Klokke til edderkoppen "
gameforge.subquest_44._370_say = "G\229 til \248rkenen og fang en Baby edderkop og fors\248g[ENTER]at h\230nge Taureans klokke p\229 en af dem. "
gameforge.subquest_44._380_npcChat = "Omkring klokken... "
gameforge.subquest_44._390_say = "Har du h\230ngt klokken omkring en edderkop endnu?[ENTER]S\229 g\248r det venligst snart. Og v\230r sikker p\229 at[ENTER]Yu-Rang ikke ser dig! "
gameforge.subquest_44._400_sendLetter = "Gjort! "
gameforge.subquest_44._40_say = "Jeg ved jeg burde stole p\229 mine venner, men jeg[ENTER]vil vide om han virkelig gjorde det. Det er for[ENTER]farligt for mig i \248rkenen. Du ser meget st\230rk ud.[ENTER]Du kunne let g\248re det. Kunne du tage et kig for[ENTER]mig? "
gameforge.subquest_44._410_say = "Det var meget sv\230rt, men du klarede endelig at[ENTER]h\230nge en klokke om en baby edderkop. Drag nu til[ENTER]Yu-Rang og fort\230l hende at Taurean gjorde det. "
gameforge.subquest_44._420_npcChat = "Klokken er blevet h\230ngt p\229 en edderkop. "
gameforge.subquest_44._430_say = "Har du gjort det? Det er fantastisk![ENTER]S\229 fort\230l det hurtigt til Yu-Rang s\229 hun endelig[ENTER]tror p\229 mig! "
gameforge.subquest_44._440_npcChat = "Taurean har fortalt sandheden. "
gameforge.subquest_44._450_say = "Engang til? Har du virkelig fundet en edderkop[ENTER]med en klokke? S\229 gjorde Taurean det virkelig.[ENTER]Jeg havde ikke troet det var muligt. M\229ske vil[ENTER]han alligevel blive en rigtig mand en dag. Tak[ENTER]for at have tjekket det for mig. Her er din[ENTER]bel\248nning for din hj\230lp. "
gameforge.subquest_44._460_sendLetter = "G\229 tilbage til Taurean "
gameforge.subquest_44._470_targetVid = "G\229 tilbage til Taurean "
gameforge.subquest_44._480_say = "Du har fortalt Yu-Rang at hendes ven virkelig[ENTER]hang klokken p\229 en baby edderkop.[ENTER]G\229 nu tilbage til Tauran og fort\230l ham omkring[ENTER]det succesfulde bedrag. "
gameforge.subquest_44._490_npcChat = "Yu-Rang troede p\229 dig. "
gameforge.subquest_44._500_say = "Tusind tak. Nu foragter Yu-Rang mig ikke. Det vil[ENTER]for altid v\230re vores hemmelighed. Lov mig det?[ENTER]Ses snart! "
gameforge.subquest_44._50_select = "Acceptere. "
gameforge.subquest_44._510_sayReward = "Taurean giver dig en bel\248nning for at hj\230lpe med[ENTER]hans l\248gn: Du har modtaget 30.000 Yang. "
gameforge.subquest_44._520_sayReward = "Du har modtaget 700.000 erfaringspoints. "
gameforge.subquest_44._60_say = "Vil du opgive missionen? "
gameforge.subquest_44._70_say = "Hvorfor ikke? Du er bange?[ENTER]Bes\248g mig, n\229r du skifter mening. "
gameforge.subquest_44._80_say = "Ahh, er du bange?[ENTER]Men du er meget st\248rre og st\230rkere end mig! Haha,[ENTER]du er en kujon! S\229 er jeg n\248d til at sp\248rge en[ENTER]anden. "
gameforge.subquest_44._90_say = "Edderkopper lever i \248rkenen. Du er st\230rk. Jeg er[ENTER]sikker p\229 du kan g\248re det. Held og lykke! "
