gameforge.subquest_45._100_sayTitle = "Skaf den hemmelige information "
gameforge.subquest_45._10_npcChat = "Sagen omkring M\248rkets tempel "
gameforge.subquest_45._110_say = "Du har tempelbogen, tempel-halst\248rkl\230det og[ENTER]overs\230ttelserne af forbandelses bogen. Aflever[ENTER]dem til Soon.  "
gameforge.subquest_45._120_say = "Hvis du hj\230lper Soon, bogormen, kan han forts\230tte[ENTER]sin forskning omkring m\248rkets tempel. Han kan dog[ENTER]kun g\248re dette hvis han f\229r fat i f\248lgende ting:[ENTER]Tempelbogen, Tempelt\248rkl\230det og en overs\230ttelse[ENTER]af besv\230rgelsesbogen. F\229 fat i disse ting og[ENTER]bring dem til Soon. Du vil finde dem i Hwang[ENTER]Templet i Seungryong Dalen. "
gameforge.subquest_45._130_npcChat = "Tingene fra M\248rkets tempel. "
gameforge.subquest_45._140_say = "Ahh, du har dem! Mange tak.[ENTER]Omkring det hemmelige folk i templet, well, det[ENTER]er rimelig simpelt: De er farlige folk. Men du[ENTER]har l\230rt det den h\229rde vej. De virker ogs\229 til at[ENTER]tjene de onde guder. Jeg har ingen detaljer, men[ENTER]jeg formoder at de planl\230gger noget virkelig[ENTER]skidt. "
gameforge.subquest_45._150_say = "Nu hvor jeg har nogle af deres hellige ting vil[ENTER]jeg forh\229bentlig finde ud af mere. Bedst at[ENTER]starte med Tempelbogen.[ENTER]Lad os se... Hmm... Aha...[ENTER]Hvorfor bliver du h\230ngene her? Har du ikke bedre[ENTER]ting at tage dig til? "
gameforge.subquest_45._160_sayReward = "Du f\229r 7.000.000 erfaringspints. "
gameforge.subquest_45._170_sayReward = "Du har modtaget 70.000 Yang. "
gameforge.subquest_45._180_sayReward = "Du har modtaget leder bogen. "
gameforge.subquest_45._190_say = "N\229... Det er dig...[ENTER]Du har dem ikke?[ENTER]Skynd dig, n\229r du tager imod en opgave![ENTER]Afsted, hop hop!! "
gameforge.subquest_45._200_select = "Pr\248v igen "
gameforge.subquest_45._20_say = "Der foreg\229r noget inde i m\248rkets tempel. Jeg tror[ENTER]der er farlige v\230sner der inde, som studere antik[ENTER]magi.[ENTER]M\248rkets tempels hemmelighed er sv\230rd at forst\229,[ENTER]selv for mig. Men jeg er sikker p\229 at disse[ENTER]menneskers dagsorden er mere end mist\230nkelig. Jeg[ENTER]er n\248d til at finde ud af mere om dem! "
gameforge.subquest_45._210_say = "S\229 er jeg n\248d til at sp\248rge en st\230rkere helt.[ENTER]Farvel. "
gameforge.subquest_45._220_say = "Mange tak.[ENTER]Jeg h\229ber du er mere succesfuld denne gang! "
gameforge.subquest_45._30_say = "Jeg har brug for flere informationer til mine[ENTER]studier. Jeg tror at tempelbogen, tempelt\248rkl\230det[ENTER]og overs\230ttelsen af besv\230rgelsesbogen vil v\230re[ENTER]meget hj\230lpsomme. Kan du bringe mig disse ting.[ENTER]Jeg vil v\230re meget taknemmelig![ENTER]Og h\230ng ikke for l\230nge, jeg har brug for dem[ENTER]snart! "
gameforge.subquest_45._40_select = "Jeg er p\229 vej. "
gameforge.subquest_45._50_say = "Vil du tage imod opgaven? "
gameforge.subquest_45._60_say = "Jeg sp\248rger om din hj\230lp! Hvis du har for travlt[ENTER]s\229 kom tilbage senere. M\229ske har du mere tid der.[ENTER]Jeg vil vente p\229 dig. "
gameforge.subquest_45._70_say = "Jeg spurgte om din hj\230lp og du vender bare ryggen[ENTER]til mig?[ENTER]Ohh, well jeg har ikke brug for dig alligevel...[ENTER]Forsvind! "
gameforge.subquest_45._80_say = "Tak! "
