gameforge.subquest_46._150_targetVid = "Hemmelighederne om det Lysegr\248nne Porcel\230n "
gameforge.subquest_46._160_npcChat = "Jeg har fundet alt materialet. "
gameforge.subquest_46._170_say = "Du har gjort det! Tusind tak! Med den rigtige[ENTER]teknik og de rigtige materialer kan jeg producere[ENTER]vidunderligt lysegr\248nt porcel\230n. Indtjeningen jeg[ENTER]f\229r fra det vil v\230re en velsignelse for min pung.[ENTER]Her er din bel\248nning. Du har fortjent den. Jeg[ENTER]vil starte med at producere porcel\230n med det[ENTER]samme! "
