gameforge.subquest_46._190_sayReward = "Du har modtaget 30.000 Yang. "
gameforge.subquest_46._20_say = "Hej eventyrer. Bragte du mig ikke Soons noter om[ENTER]at lave Celadon porcel\230n for nyligt? Jeg har et[ENTER]problem... Selv om jeg kender teknikken, kan jeg[ENTER]ikke fremstille \230gte Celadon porcel\230n.[ENTER]Det er sikkert fordi jeg bruger mine normale[ENTER]ingredienserne i stedet for materialerne skrevet[ENTER]i noten som er sv\230re at f\229. "
gameforge.subquest_46._30_say = "Jeg har brug for fint \248rken sand, krystalmalm og[ENTER]abeblod. Hvis du blander disse og tilf\248jer dem[ENTER]til ler bliver det virkelig h\229rde n\229r det[ENTER]br\230ndes. Glasuren vil ogs\229 f\229 den typiske[ENTER]lysegr\248nne farve s\229, som ligner jade. Denne farve[ENTER]er meget popul\230r hos kunderne og jeg har virkelig[ENTER]brug for at s\230lge mere! "
gameforge.subquest_46._40_say = "Du f\229r \248rken sandet fra \248rkenbanditterne, du kan[ENTER]f\229 krystalmalm fra krystalminerne og for at f\229[ENTER]abeblod, skal du dr\230be aber i Sangsung Dong. Kan[ENTER]du f\229 fat i disse materialer for mig? Jeg ved,[ENTER]det vil ikke blive let, men jeg vil bel\248nne dig[ENTER]gener\248st. "
