gameforge.subquest_47._240_say = "Ja du har ret! Nu forst\229r jeg det ogs\229. Jeg er[ENTER]stolt af dig. Du er en af vores bedste soldater![ENTER]Denne s\230tning er helt sikkert et aftalt kodeord.[ENTER]Det betyder at Yu-Hwan har opdaget fjendens[ENTER]spioner og vi er n\248d til at handle imod dem. Jeg[ENTER]vil give de n\248dvendige ordre med det samme. "
gameforge.subquest_47._250_sayReward = "Du har modtaget 2.300.000 erfaringspoints. "
gameforge.subquest_47._260_say = "Du vil finde ud af det. Kom tilbage n\229r du er[ENTER]klar! "
gameforge.subquest_47._270_say = "Hmm, det siger mig ingen ting. Hvad mente han med[ENTER]det. Jeg tror ikke det er rigtigt. T\230nk igen. "
gameforge.subquest_47._280_select = "Jeg pr\248ver igen "
gameforge.subquest_47._290_select = "Jeg opgiver. "
gameforge.subquest_47._300_say = "S\229? Hvad betyder beskeden? "
gameforge.subquest_47._301_answer_correct = "Fjender sigtet i horisonten "
gameforge.subquest_47._302_answer_wrong = "Venner set i horisonten "
gameforge.subquest_47._303_answer_wrong = "Fjende set i horisonten "
gameforge.subquest_47._304_answer_wrong = "Falske venner hj\230lper ikke "
gameforge.subquest_47._305_answer_dontknow = "Ved det ikke "
gameforge.subquest_47._30_say = "GIV AGT![ENTER]Ahh, det er dig. Det er godt at du er her![ENTER]Jeg har modtaget nogle informationer fra Yu-Hwan.[ENTER]Hun har som altid skrevet det i hemmeligt skrift.[ENTER]Det tager mig \229r at dekryptere det. Og det er n\248d[ENTER]til at blive taget h\229nd om hurtigt. Sidste gang[ENTER]lykkedes det dig at g\248re det ret hurtigt. Vil du[ENTER]venligst hj\230lpe mig igen? "
gameforge.subquest_47._310_say = "Ja du har ret! Nu forst\229r jeg det ogs\229. Jeg er[ENTER]stolt af dig. Du er en af vores bedste soldater![ENTER]Denne s\230tning er helt sikkert et aftalt kodeord.[ENTER]Det betyder at Yu-Hwan har opdaget fjendens[ENTER]spioner og vi er n\248d til at handle imod dem. Jeg[ENTER]vil give de n\248dvendige ordre med det samme. "
gameforge.subquest_47._320_sayReward = "Du har modtaget 20.000 Yang. "
gameforge.subquest_47._330_say = "Du vil finde ud af det. Kom tilbage n\229r du er[ENTER]klar! "
gameforge.subquest_47._40_say = "Vil du opgive missionen? "
gameforge.subquest_47._50_say = "Men.. sidste gang har du klaret det.[ENTER]Hvad overvejer du nu?[ENTER]T\230nk dig om engang merel. "
gameforge.subquest_47._60_say = "Jeg ved, hvad du mener..[ENTER]Du vil ikke arbejde sammen med os l\230ngere, ikke[ENTER]sandt? Det er en skam. Der er ikke mange tapre[ENTER]krigere. "
gameforge.subquest_47._70_say = "Ja da! Du er min redning. Se p\229 denne kode. Tjek[ENTER]den n\248je ud! "
gameforge.subquest_47._80_say = "njefedr[ENTER]tstgie[ENTER]i[ENTER]onoerisnth[ENTER][ENTER]Kan du dekryptere det? "
gameforge.subquest_47._90_say = "Hvordan g\229r det?[ENTER]Kan du finde ud af det?  "
gameforge.subquest_48 = {}
gameforge.subquest_48._100_sayTitle = "S\248g efter spionen "
gameforge.subquest_48._10_npcChat = "Find Spionen "
gameforge.subquest_48._110_say = "En af disse spioner lever som Fisker i omr\229det[ENTER]Pyungmo i Jinno riget. Pr\248v diskret at komme i[ENTER]kontakt med ham og aflevere hans rapport til[ENTER]Kaptajnen. "
gameforge.subquest_48._120_say = "En af disse spioner lever som Fisker i omr\229det[ENTER]Yongan i Shinsoo riget.[ENTER]Pr\248v diskret at komme i kontakt med ham og[ENTER]aflevere hans rapport til Kaptajnen. "
gameforge.subquest_48._130_say = "En af disse spioner lever som Fisker i omr\229det[ENTER]Joan i Chunjo riget. Pr\248v diskret at komme i[ENTER]kontakt med ham og aflevere hans rapport til[ENTER]Kaptajnen. "
gameforge.subquest_48._140_npcChat = "Hvad har du gang i "
gameforge.subquest_48._150_say = "Psst, v\230r stille! Du skr\230mmer alle fiskene! Hvad[ENTER]vil du overhoved her? Som du r\229ber og skriger er[ENTER]du nok n\230ppe kommet for at[ENTER]fiske.  "
gameforge.subquest_48._160_say = "Ah! Jeg forst\229r! Jeg har ventet i lang tid p\229[ENTER]dig. Du er sent p\229 den. Det var ikke nemt at f\229[ENTER]de informationer uden at blive opdaget. Du skal[ENTER]vide, at der overalt lurer fjender og venter p\229[ENTER]at man beg\229r en fejl.  "
gameforge.subquest_48._170_say = "Vi b\248r ikke blive set for meget sammen.[ENTER]Efter alt, \248nsker vi ikke at nogen opdager os.[ENTER]Her er dokumenterne. Tag nu straks afsted og[ENTER]aflevere dem direkte til Kaptajnen. "
gameforge.subquest_48._180_say = "Ah - et sekund! Jeg har en lille gave til dig.[ENTER]Og nu afsted. Farvel! "
gameforge.subquest_48._190_sayReward = "Du er nysgerrig og \229bner pakken for at se, hvad[ENTER]spionen har givet dig. "
gameforge.subquest_48._200_say = "Smart! Grillet rudskalle! Den spion m\229 virkelig[ENTER]vide noget om fiskning. "
gameforge.subquest_48._20_say = "Slap af, soldat![ENTER]Da alle vores nabolande er fjender, er det[ENTER]vigtigt at have venner der, som kan spionere og[ENTER]hj\230lper os med at indsamle oplysninger, s\229 vi kan[ENTER]forberede eventuelle angreb. Det er yderst[ENTER]vigtigt, at disse spioners d\230kke aldrig bliver[ENTER]afsl\248ret. "
gameforge.subquest_48._210_sayReward = "Du har f\229et 3 stegte rudskaller "
gameforge.subquest_48._220_sendLetter = "G\229 tilbage til kaptajnen "
gameforge.subquest_48._230_targetVid = "Kaptajnen "
gameforge.subquest_48._240_say = "Den farlige rejse til Pyungmoo i Jinno Rige var[ENTER]en succes: Du har modtaget rapporten fra spionen,[ENTER]der er forkl\230dt som fisker. Tag nu tilbage til[ENTER]dit rige og hurtig aflevere oplysningerne til[ENTER]Kaptajnen. "
gameforge.subquest_48._250_say = "Den farlige rejse til Yongan i Shinsoo Rige var[ENTER]en succes: Du har modtaget rapporten fra spionen,[ENTER]der er forkl\230dt som fisker. Tag nu tilbage til[ENTER]dit rige og hurtig aflevere oplysningerne til[ENTER]Kaptajnen. "
gameforge.subquest_48._260_say = "Den farlige rejse til Joan i Chunjo Rige var en[ENTER]succes: Du har modtaget rapporten fra spionen,[ENTER]der er forkl\230dt som fisker. Tag nu tilbage til[ENTER]dit rige og hurtig aflevere oplysningerne til[ENTER]Kaptajnen. "
gameforge.subquest_48._270_npcChat = "Missionen lykkedes! "
gameforge.subquest_48._280_say = "Er det disse dokumenter? Storartet! Tak. Nu, hvor[ENTER]vi kender vores fjenders planer, kan vi forberede[ENTER]os p\229 at forsvarer os selv. Du har gjort riget en[ENTER]stor tjeneste! "
gameforge.subquest_48._290_sayReward = "Du har modtaget 5,500,000 erfaringspoints. "
gameforge.subquest_48._300_sayReward = "Du har modtaget 50,000 Yang. "
gameforge.subquest_48._30_say = "Du kender sikkert, Yu-Hwan musikeren, g\248r du[ENTER]ikke? Han er ogs\229 en spion og arbejder for os.[ENTER]Men en spion alene er ikke nok, s\229 har vi flere[ENTER]over hele verden. En af dem udgiver sig for at[ENTER]v\230re fisker i den f\248rste landsby. "
gameforge.subquest_48._40_say = "Da jeg ikke kan komme direkte i kontakt med ham,[ENTER]uden at \248del\230gge hans d\230kning, har jeg brug for[ENTER]hj\230lp fra nogle frygtl\248se soldater. Ja, jeg mener[ENTER]dig! G\229 venligst til den fisker og hent hans[ENTER]seneste rapport. Det er meget vigtigt for vores[ENTER]Riges sikkerhed! "
gameforge.subquest_48._50_say = "Vil du afslutte denne mission? "
gameforge.subquest_48._60_say = "Du \248nsker at forberede dig selv f\248rst? Okay, s\229[ENTER]kom tilbage senere. Jeg vil vente p\229 dig. Men[ENTER]skynd dig, jeg har brug for denne rapport! "
gameforge.subquest_48._70_say = "Hvad er der galt med dig? Sidste gang, gjorde du[ENTER]et fantastisk arbejde for os! Og nu vil du bare[ENTER]opgive dit land? Men der er intet, jeg kan g\248re[ENTER]ved det. Farvel. "
gameforge.subquest_48._80_say = "Jeg vidste, jeg kunne stole p\229 dig. Held og[ENTER]lykke, og v\230r forsigtig! "
gameforge.subquest_48._90_makequestbutton = "M\248d spionen "
gameforge.subquest_49 = {}
gameforge.subquest_49._100_sayTitle = "Hvad er Bingsu?! "
gameforge.subquest_49._10_targetVid = "Bingsu? "
gameforge.subquest_49._110_say = "Taurean har haft et sk\230nderi med Harang fordi han[ENTER]ikke tror p\229 at du kan lave is om sommeren. Drag[ENTER]til Harang og sp\248rg hende hvad hun ved om Bingsu. "
gameforge.subquest_49._120_qSetTitle = "Sp\248rg Harang "
gameforge.subquest_49._130_targetVid = "Sp\248rg Harang "
gameforge.subquest_49._140_npcChat = "Hvad er Bingsu?! "
gameforge.subquest_49._150_say = "Ham Taurean lader ogs\229 som om han ved alting. Han[ENTER]kender ikke engang Bingsu! Hvordan kan du ikke[ENTER]kende til noget s\229 l\230kkert?[ENTER]Ved ud heller ikke hvad Bingsu er?? Well, du m\229[ENTER]hellere g\229 til Octavio i nabo landsbyen. Han er[ENTER]en ber\248mt kok og kender en masse gode opskrifter.[ENTER]Han lavede engang Bingsu til mig.... mmmmh. Han[ENTER]vil bevise for dig at jeg har ret! "
gameforge.subquest_49._160_makequestbutton = "G\229 til Octavio "
gameforge.subquest_49._170_say = "Taurean vil vide, hvad Bingsu er. G\229 til[ENTER]restaurant ejeren Octavio. Jeg er sikker p\229 han[ENTER]kan hj\230lpe dig. "
gameforge.subquest_49._180_npcChat = "Ved du hvad Bingsu er? "
gameforge.subquest_49._190_say = "Bingsu? Selvf\248lgelig, ved jeg det. Alle gode[ENTER]kokke ved hvordan man laver Bingsu! For det[ENTER]f\248rste skal du have fint knust is. S\229 putter du[ENTER]sukker, tyndt hakket riskage i, og til sidste[ENTER]frisk frugt til dekorering. "
gameforge.subquest_49._200_say = "Hvorfor sp\248rger du? Fordi Taurean og Harang[ENTER]sk\230ndes? Det er jo ikke noget nyt. Men Harang har[ENTER]ret. Specielt p\229 en varm sommerdag er Bingsu en[ENTER]eftertragtet ret.[ENTER]Taurean er en god dreng, ogs\229 n\229r han er lidt[ENTER]ener\229dig. Hvis du bringer mig ingredienserne, s\229[ENTER]laver jeg noget Bingsu til ham. "
gameforge.subquest_49._20_npcChat = "Bingsu? "
gameforge.subquest_49._210_say = "Vil du byde Taurean p\229 Bingsu. Hvad tror du? Kan[ENTER]du finde Is fra Sohan bjerget? "
gameforge.subquest_49._220_say = "Vil du opgive missionen? "
gameforge.subquest_49._230_say = "Kan du ikke lide is? eller er du allerede m\230t??[ENTER]Det er til Taureanm s\229 t\230nk venligst over det[ENTER]igen. "
gameforge.subquest_49._240_say = "Synd. Taurean bliver meget skuffet.[ENTER]Ses. "
gameforge.subquest_49._250_say = "Rigtigt godt. Jeg skal bruge isklumperne fra[ENTER]fortryllet is der er p\229 bjerget Sohan. Aflever 50[ENTER]stykker, s\229 kan jeg lave noget dejligt Bingsu. "
gameforge.subquest_49._260_targetVid = "G\229 til Octavio "
gameforge.subquest_49._270_say = "%s[ENTER]Du har isklumperne til Taureans Bingsu.[ENTER]Bringe dem til Octavio. "
gameforge.subquest_49._275_say = "Find isklumperne "
gameforge.subquest_49._280_say = "Octavio har sagt ja til at lave Bingsu til[ENTER]Taurean, men han har brug for is til at g\248re det.[ENTER]Dr\230b Fortryllet Is p\229 Bjerg Sohan og indsaml 50[ENTER]Isklumper. Bringe dem til Octavio bagefter. "
gameforge.subquest_49._285_say = "S\248g efter is "
gameforge.subquest_49._290_npcChat = "Her jeg har isklumperne med. "
gameforge.subquest_49._300_say = "Ahh meget godt! Den sv\230reste del ved Bingsu[ENTER]fremstilling er nu gjort. Nu skal jeg bare[ENTER]tilf\248je lidt sukker... Og noget frugt... V\230rsgo![ENTER]En is til Taurean. Bring ham den nu, s\229 vil han[ENTER]snart glemme sin vrede. "
gameforge.subquest_49._30_sayTitle = "Taurean: "
gameforge.subquest_49._310_say = "Beklager, men det er ikke nok. Du er n\248d til at[ENTER]finde mere, ellers vil det bare blive en[ENTER]lillebitte potion! "
gameforge.subquest_49._320_select = "Ja. Pr\248v igen "
gameforge.subquest_49._330_say = "Jeg ved der er langt og monsterene er st\230rke.[ENTER]Hvis det er for sv\230rt for dig er der ikke noget[ENTER]at g\248re ved et. Ses. "
gameforge.subquest_49._340_say = "Pr\248v igen. Med dit mod og udholdenhed kan du[ENTER]klare det! "
gameforge.subquest_49._350_targetVid = "Bingsu? "
gameforge.subquest_49._360_say = "Det er gjort: Octvio har lavet Bingsu ud af is[ENTER]fra Sohan bjerget. Skynd dig tilbage til Taurean[ENTER]inden det smelter. "
gameforge.subquest_49._370_npcChat = "V\230rsgo! Bingsu! "
gameforge.subquest_49._380_say = "Er det Bingsu? Det smager virkelig godt. Dejligt[ENTER]og koldt. Jeg har aldrig smagt noget lignende[ENTER]f\248r, tak! S\229 har Harang ret. Jeg er n\248d til at[ENTER]give hende en undskyldning... "
gameforge.subquest_49._390_sayReward = "Du har modtaget 6.000.000 erfaringspoints. "
gameforge.subquest_49._400_sayReward = "Du har modtaget 70.000 Yang. "
gameforge.subquest_49._40_say = "I dag havde jeg en strid med Harang.[ENTER]Bare han dog....[ENTER]Han p\229st\229r, at der findes noget dejligt, der[ENTER]best\229r af nogle sm\229 isklumper. Det kaldes Bingsu. "
gameforge.subquest_49._410_sayReward = "Du har modtaget krigsgudens skriftrulle. "
gameforge.subquest_49._420_say = "Bingsu for mig?[ENTER]Hvem havde regnet med det? "
gameforge.subquest_49._430_say = "Ohh k\230re, jeg har totalt glemt det! Hmm, skal jeg[ENTER]fortsat fors\248ge? Eller b\248r jeg hellere lade det[ENTER]v\230re? "
gameforge.subquest_49._440_select = "Ja, jeg forts\230tter "
gameforge.subquest_49._450_select = "Jeg opgiver. "
gameforge.subquest_49._460_say = "Jeg kan ikke klare det.[ENTER]Desv\230rre.  "
gameforge.subquest_49._50_say = "S\229dan noget er kun muligt om vinteren n\229r det er[ENTER]virkelig koldt. Men hun bliver ved med at p\229st\229[ENTER]det virker. Kan du finde ud af om man ogs\229 kan[ENTER]lave Bingsu om sommeren? Hvis noget s\229dan ellers[ENTER]findes... "
gameforge.subquest_49._60_say = "Jeg er sikker p\229 at Bingsu er l\230kkert! Er du[ENTER]sikker p\229 du aldrig vil hj\230lpe mig med at lave[ENTER]det? "
gameforge.subquest_49._70_say = "Hvis du vil g\248re det senere, s\229 sig til. "
gameforge.subquest_49._80_say = "Jeg ville s\229 gerne smage Bingsu...[ENTER]Men du har ret. Harang vil sikkert bare vise at[ENTER]Bingsu ikke eksistere. Farvel. "
gameforge.subquest_49._90_say = "Tak for din hj\230lp. Lad mig vide om du finder ud[ENTER]af noget. S\229 kan jeg fort\230lle denne Harang min[ENTER]mening! "
