gameforge.training_mount = {}
gameforge.training_mount._01_say = "Jeg er ked af det, men du har ikke den n\248dvendige[ENTER]ride erfaring for at forbedre din hest. Du skal[ENTER]mindst have Krigs Hest License. "
gameforge.training_mount._02_say = "Beklager, men uden de rigtige dokumenter kan jeg[ENTER]ikke g\248re noget for dig. Fors\248g ikke at snyde mig[ENTER]igen, ellers vil du betale for det. "
gameforge.training_mount._03_say = "Hvor er dit Ride Segl? Jeg kan ikke forbedre[ENTER]noget uden dette Segl.[ENTER]Tjek bag den roterende m\248nt.[ENTER]Du kan finde et Certifikat der som du kan bytte[ENTER]til et Ride Segl. "
gameforge.training_mount._04_say = "Jeg \248nsker at ride p\229 en ny Ganger! "
gameforge.training_mount._05_say = "Hey! Du rider stadig p\229 en hest?! Virkelig? Du[ENTER]ved vel, at vi kan t\230mme vilde dyr i disse dage[ENTER]ikke? "
gameforge.training_mount._06_say = "At tr\230ne tamme vilde dyr til kamp, du b\248r absolut[ENTER]have en god Ride f\230rdighed.[ENTER]Oven i dette, skal du ogs\229 bruge f\248lgende emner:[ENTER]Rulle af Udvikling, for at forbedre din ganger[ENTER]til en vild ganger og Rulle af Mutation, for at[ENTER]g\248re den til en tapper ganger. "
gameforge.training_mount._07_say = "Hvis du har sp\248rgsm\229l, kan du altid bes\248ge mig[ENTER]igen. Jeg vil hj\230lpe dig s\229 meget som jeg kan. "
gameforge.training_mount._08_say = "Jeg vil gerne forbedre min ganger! "
gameforge.training_mount._09_say = "S\229 du \248nsker at forbedre din ganger? Ved du[ENTER]hvordan det virker? OK, vil jeg forklare det for[ENTER]dig. "
gameforge.training_mount._10_say = "For at forbedre din ganger til en vild ganger er[ENTER]du n\248dt til at g\229 p\229 jagt efter en Rulle af[ENTER]Udvikling. Find Rulle af Mutation, s\229 du kan[ENTER]tr\230ne vilde dyr til at blive en tapper ganger. De[ENTER]siger at de er skjult i et fjernt befolket land[ENTER]med farlige giganter! "
gameforge.training_mount._11_say = "Bring mig disse ruller, og jeg vil forbedre din[ENTER]ganger. Du har dem m\229ske allerede p\229 dig ? "
gameforge.training_mount._12_say = "Ja, jeg vil gerne forbedre min ganger! "
gameforge.training_mount._13_say = "Nej, ikke lige nu. "
gameforge.training_mount._14_say = "Ah du har en af rullerne med dig. Hvilke en af[ENTER]dem er det s\229 ?[ENTER]Rulle af Udvikling lader dig tr\230ne et uerfaren[ENTER]ungt dyr til krig.[ENTER]Rulle af Mutation lader dig tr\230ne en ganger til[ENTER]en tapper ganger. "
gameforge.training_mount._15_2_say = "Jeg har bragt dig en Rulle af Mutation. "
gameforge.training_mount._15_say = "Jeg har bragt dig en Rulle af Udvikling. "
gameforge.training_mount._16_say = "Jeg har ikke nogle af Rullerne p\229 mig. "
gameforge.training_mount._17_say = "Ah, se - Rulle af Udvikling! OK, lad mig tage et[ENTER]kig p\229 dit Ganger Segl. Nogle mennesker har[ENTER]fors\248gt at f\229 mig til at acceptere[ENTER]forfalskninger! Jeg vil tjekke dens \230gthed f\248rst.[ENTER]Giv mig det her. (Tr\230k Seglet over p\229[ENTER]stalddrengen.) "
gameforge.training_mount._18_say = "En Rulle af Mutation! Indtil nu har jeg bare h\248rt[ENTER]historier. Jeg har faktisk aldrig holdt en i mine[ENTER]h\230nder. Vis mig dit Ganger Segl, derefter vil jeg[ENTER]bytte den til en mere kraftfuld en, n\229r jeg har[ENTER]kontrolleres dens \230gthed. (Tr\230k Seglet over p\229[ENTER]stalddrengen.) "
gameforge.training_mount._19_say = "S\229 snart du har fundet en af skriftrullerne, s\229[ENTER]kom tilbage til mig. Jeg vil derefter v\230re i[ENTER]stand til at udveksle dit gamle Ganger Segl for[ENTER]en mere kraftfuld en. "
gameforge.training_mount._20_say = "Dit Ganger segl har afgjort set bedre dage.[ENTER]H\230ng p\229, jeg vil bytte den til en ny. V\230r venlig[ENTER]at tage det. Nu kan du tilkalde din vilde Ganger.[ENTER]Kom tilbage til mig, hvis du tilf\230ldigvis finder[ENTER]en Rulle af Mutation. Jeg vil bruge den til at[ENTER]give dig en endnu st\230rkere Ganger Segl. "
gameforge.training_mount._21_say = "Det er det Ganger segl, som du fik af mig for et[ENTER]stykke tid siden. Det er allerede temmelig slidt.[ENTER]Giv mig den tilbage og jeg vil skabe dig et[ENTER]Ganger segl, der er endnu mere kraftfuld! "
gameforge.training_mount._22_say = "Dette Segl giver dig mulighed for at tilkalde din[ENTER]tr\230nede ganger. Dens v\230rdi er uvurderlig! "
gameforge.training_mount._23_say = "Kan jeg bruge Heste f\230rdigheder? "
gameforge.training_mount._24_say = "Du \248nsker at bruge nogle heste f\230rdigheder?[ENTER]Du er temmelig kr\230vende! Selv om jeg ogs\229 dr\248mmer[ENTER]om dem ... meget vel.[ENTER]For at l\230re dem skal du f\248lge et par bestemmelser. "
gameforge.training_mount._25_say = "F\248rste ting f\248rst, du er n\248dt til at beherske[ENTER]ridning, ellers vil du bringe dig selv i alvorlig[ENTER]fare. Oven i det, har du brug for at din ganger[ENTER]er kamp-klar, da den f\248rst derefter er klar til[ENTER]at g\248re brug af hest f\230rdigheder. "
gameforge.training_mount._26_say = "Er din ganger klar til at l\230re hest f\230rdigheder?[ENTER]Jeg vil ikke v\230re i stand til at tillade tr\230ning[ENTER]hvis den ikke er det. Hvad vil du g\248re? "
gameforge.training_mount._27_say = "Jeg forst\229r. Jeg vil nu vurdere din styrke og[ENTER]Ride f\230rdighed. Vent et \248jeblik. "
gameforge.training_mount._28_say = "Hmm ... st\230rk rygrad, god Ride f\230rdighed og din[ENTER]ganger er meget opsat p\229 kamp. Du kan bruge hest[ENTER]f\230rdigheder. "
gameforge.training_mount._29_say = "Nu kan din ganger bruge heste f\230rdigheder.[ENTER]Hvis du f\229r en ny ganger, vil den ogs\229 v\230re n\248dt[ENTER]til at l\230re f\230rdighederne. I det tilf\230lde kommer[ENTER]du bare tilbage til mig. "
gameforge.training_mount._30_say = "Kom nu, Jeg har allerede fortalt dig, at det er[ENTER]farligt hvis du ikke kan ride. Vend tilbage til[ENTER]mig, n\229r du ved hvordan. "
gameforge.training_mount._31_say = "Jeg er bange for at din ganger ikke er helt klar[ENTER]endnu. Vend tilbage til mig, n\229r den viser mere[ENTER]vilje til kamp. "
gameforge.training_mount._32_say = "Kunne du m\229ske klatre ned fra din ganger mens vi[ENTER]taler? Jeg har en stiv nakke, og det er temmelig[ENTER]tr\230ttende, at skulle kigge op p\229 dig hele tiden. "
gameforge.training_mount._33_say = "Du har ikke have den rette ride licens til at[ENTER]forbedre din ganger. Du skal mindst have Krigs[ENTER]Hest licens for at tr\230ne en vild ganger. For at[ENTER]t\230mme en tapper ganger, du skal have Milit\230r Hest[ENTER]licens. "
gameforge.training_mount._34_say = "Jeg kan se at du har en Energi Snack. Denne[ENTER]v\230rdifulde l\230geurt vil give din Ganger ren energi[ENTER]- det vil forl\230nge dens levetid med et antal af[ENTER]dage. Hvad skal jeg g\248re? Vil du have mig til at[ENTER]forl\230nge levetiden p\229 din Ganger, eller \248nsker du[ENTER]at forbedre den? "
gameforge.training_mount._35_select_1 = "Forl\230ng "
gameforge.training_mount._35_select_2 = "Forbedre "
gameforge.training_mount._36_select_1 = "7 dage "
gameforge.training_mount._36_select_2 = "15 dage "
gameforge.training_mount._36_select_3 = "30 dage "
gameforge.training_mount._36_select_4 = "Rulle af Mutation + 200k Yang "
gameforge.training_mount._37_say = "Desv\230rre du har ikke har de n\248dvendige Energi[ENTER]Snack for den \248nskede varighed. Men jeg er sikker[ENTER]p\229 at du vil finde det i afsnittet bag den[ENTER]roterende m\248nt! "
gameforge.training_mount._38_say = "Rulle af Mutation indeholder en stor magt! Den[ENTER]kan forl\230nge levetiden p\229 din Tapre Ganger op til[ENTER]fire dage. Et fors\248g vil koste dig 200.000 Yang.[ENTER]Din Ganger skal v\230re udk\248rt, og have mindre end[ENTER]en dag tilbage at leve i, for at g\248re fors\248get.[ENTER]Selvf\248lgelig vil lidt held ogs\229 hj\230lpe en del p\229[ENTER]processen! Skulle fors\248get fejle, vil jeg[ENTER]anbefale dig at fodre den med en Energi Snack. De[ENTER]kan findes bag den roterende m\248nt. "
gameforge.training_mount._39_say = "Din Ganger er stadig for st\230rk. Rulle af Mutation[ENTER]vil ikke have nogen virkning her. Kom tilbage n\229r[ENTER]den har mindre end en dag tilbage at leve i. "
gameforge.training_mount._40_say = "Desv\230rre kan jeg ikke hj\230lpe dig. Enten har du[ENTER]ikke en Rulle af Mutation, eller ogs\229 har du[ENTER]mindre end 200.000 Yang. "
gameforge.upgrade_refine_scroll = {}
gameforge.upgrade_refine_scroll._100_say = "Dit fors\248g p\229 at fremstille dokumentet er[ENTER]mislykket, da du ikke havde alle[ENTER]materialer.  "
gameforge.upgrade_refine_scroll._10_npcChat = "Fremstil krigsgudens dokument "
gameforge.upgrade_refine_scroll._110_npcChat = "Dragens dokument "
gameforge.upgrade_refine_scroll._120_say = "Dragens dokument \248ger din chance for succes, n\229r[ENTER]du forbedre en genstand. Selv hvis det fejler,[ENTER]vil genstandens level kun blive reduceret med en.[ENTER]Dette er en mystisk genstand, som kan ses som en[ENTER]slags opgraderings velsignelses dokument. "
gameforge.upgrade_refine_scroll._130_say = "For at fremstille det, har du brug for Magisk[ENTER]jernmalm. "
gameforge.upgrade_refine_scroll._140_sayItem = "Magisk jernmalm "
gameforge.upgrade_refine_scroll._150_say = "For at fremstille det, har man brug for et[ENTER]velsignelses dokument "
gameforge.upgrade_refine_scroll._160_say = "Har du alle genstande der kr\230ves?[ENTER]Vil du fremstille det?[ENTER]Hvis du har et velsignelses dokument og magisk[ENTER]jernmalm, kan det dannes til Dragens[ENTER]dokument.  "
gameforge.upgrade_refine_scroll._170_say = "Du har produceret drage rullen! Det er virkelig[ENTER]meget lettere at producere Dragerullen hvis du[ENTER]bruger magisk jernmalm. Det kan jeg lide! "
gameforge.upgrade_refine_scroll._180_say = "Dit fors\248g p\229 at fremstille dokumentet er[ENTER]mislykket, da du ikke havde alle[ENTER]materialer.  "
gameforge.upgrade_refine_scroll._190_npcChat = "Fremstil smede h\229ndbogen "
gameforge.upgrade_refine_scroll._200_say = "Har ud h\248rt at stenene kaldes smedens sten?[ENTER]\197benbart er stenene lavet af blod og sved fra en[ENTER]smed. Hvis du bringer mig smede stenene og en[ENTER]velsignelses rulle, vil jeg lave en h\229ndbog til[ENTER]dig som er givet videre i min familie i[ENTER]generationer. Den har en lignende funktion som[ENTER]dragerullen, men har en h\248jere succes rate. "
gameforge.upgrade_refine_scroll._20_say = "Disse mystiske krigsruller forbedre +0 til +3[ENTER]genstande og har en 100% succes rate. Dog virker[ENTER]de ikke p\229 genstande med +4 eller over. "
gameforge.upgrade_refine_scroll._210_say = "For at fremstille det, kr\230ves det en af smedens[ENTER]sten.  "
gameforge.upgrade_refine_scroll._220_sayItem = "Smedens sten "
gameforge.upgrade_refine_scroll._230_say = "For at fremstille det, skal du bruge et[ENTER]velsignelses dokument. "
gameforge.upgrade_refine_scroll._240_say = "Har du alle de n\248dvendige genstande? S\229 \248nsker du[ENTER]at jeg skal lave en h\229ndbog til dig som er givet[ENTER]videre i min familie i generationer? "
gameforge.upgrade_refine_scroll._250_say = "Jeg har produceret en smede h\229ndbog til dig![ENTER]Nu har du den antikke viden fra et helt smede[ENTER]dynasti. Brug det klogt! Ha, ha, ha! "
gameforge.upgrade_refine_scroll._260_sayItem = "Smede h\229ndbog "
gameforge.upgrade_refine_scroll._270_say = "Jeg kan ikke lave Smedens h\229ndbog fordi du ikke[ENTER]har alle materialerne. "
gameforge.upgrade_refine_scroll._30_say = "For at fremstille det, kr\230ves der Magisk[ENTER]kobbermalm. "
gameforge.upgrade_refine_scroll._40_sayItem = "Magisk kobbermalm "
gameforge.upgrade_refine_scroll._50_say = "Du skal yderligere bruge et velsignelses dokument. "
gameforge.upgrade_refine_scroll._60_sayItem = "Velsignelses dokument "
gameforge.upgrade_refine_scroll._70_say = "Har du alle de n\248dvendige genstande? Du har[ENTER]stadig brug for endnu 200.000 Yang. Hvis du har[ENTER]en velsignelses rulle, noget magisk kobbermalm og[ENTER]200.000 Yang, kan du producere krigsrullen.[ENTER]\216nsker du at producere rullen? "
gameforge.upgrade_refine_scroll._80_say = "Du har succesfuldt produceret rullen! Det er[ENTER]virkelig meget lettere at producere krigsrullen[ENTER]hvis du har magisk kobbermalm! Det kan jeg lide![ENTER]Ha, ha, ha! "
gameforge.upgrade_refine_scroll._90_sayItem = "Krigsgudens dokument "
gameforge.warehouse = {}
gameforge.warehouse._100_say = "Velkommen! Ved du hvad guldbare er til for? Hvis[ENTER]du b\230re rundt p\229 Yang, er det som at sige: Dr\230b[ENTER]mig venligst nu![ENTER]Det er derfor jeg bytter folks Yang til guldbare[ENTER]og opbevare det for dem. "
gameforge.warehouse._10_npcChat = "Jeg vil bruge lageret? "
gameforge.warehouse._110_say = "Ok, s\229 jeg forlanger lidt mere end en guldbar er[ENTER]v\230rd. Men s\229dan en aftale er stadig fair, er den[ENTER]ikke? Der er ingen grund til at f\248le du er blevet[ENTER]snydt. Som du ved er det meget farligt der ude. "
gameforge.warehouse._120_npcChat = "\197ben item-shop lageret "
gameforge.warehouse._130_say = "Hmm..[ENTER]Vores miner er n\230sten alle tomme.[ENTER]Det er meget sv\230rt at finde guld eller s\248lv.[ENTER]S\229l\230nge vi ikke finder nye \229re, findes der ikke[ENTER]noget guld eller s\248lv.  "
gameforge.warehouse._140_say = "Velkommen! S\229 du vil se dit Itemshop lager?[ENTER]Hvorfor kommer du s\229 til mig? Tag bare et kig i[ENTER]dit inventar, der er en direkte adgang der. "
gameforge.warehouse._150_say = "F\229 adgang til Itemshop lageret n\229r som helst du[ENTER]\248nsker ved at klikke p\229 dette symbol. Hvis du[ENTER]ikke har \230ndret den, s\229 er koden 000000. "
gameforge.warehouse._20_sayTitle = "Lagerforvalter: "
gameforge.warehouse._30_say = "\216nsker du at bruge lageret?[ENTER]For at benytte lageret skal du betale lidt. Jeg[ENTER]er idag i godt hum\248r og tilbyder, at du kan bruge[ENTER]mit lager for 500 Yang. Hvad siger du til det?[ENTER]Det da billigt, hva\180? Ha, ha, ha!  "
gameforge.warehouse._40_say = "Hvad? Du har ikke nok Yang?[ENTER]S\229 kom igen, n\229r du har nok Yang.  "
gameforge.warehouse._50_say = "Dit lager er \229bnet.[ENTER]Hvis du vil bruge det, snak bare med mig.[ENTER]Startkodeordet for dit lager er "
gameforge.warehouse._60_sayReward = "000000 "
gameforge.warehouse._70_say = "Du b\248r \230ndre det af sikkerhedsgrunde.[ENTER][ENTER]Du synes m\229ske at 45 bokse ikke er nok. Men hvem[ENTER]ved, m\229ske vil jeg give dig mere plads hvis vi[ENTER]kommer godt ud af det med hinanden. "
gameforge.warehouse._80_say = "N\229, jeg tvinger ikke nogen. Hvis du ikke har lyst[ENTER]til det, kom tilbage senere. "
gameforge.warehouse._90_npcChat = "\197ben lageret "
